INSERT INTO verses (goi, conical, edition_id, version, language_subtag, book, chapter, verse, testament, verse_text) VALUES
(1, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 1, 'NT', 'βιβλος γενεσεως ιησου χριστου υιου δαβιδ υιου αβρααμ'),
(2, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 2, 'NT', 'αβρααμ εγεννησεν τον ισαακ ισαακ δε εγεννησεν τον ιακωβ ιακωβ δε εγεννησεν τον ιουδαν και τους αδελφους αυτου'),
(3, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 3, 'NT', 'ιουδας δε εγεννησεν τον φαρες και τον ζαρα εκ της θαμαρ φαρες δε εγεννησεν τον εσρωμ εσρωμ δε εγεννησεν τον αραμ'),
(4, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 4, 'NT', 'αραμ δε εγεννησεν τον αμιναδαβ αμιναδαβ δε εγεννησεν τον ναασσων ναασσων δε εγεννησεν τον σαλμων'),
(5, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 5, 'NT', 'σαλμων δε εγεννησεν τον βοοζ εκ της ραχαβ βοοζ δε εγεννησεν τον ωβηδ εκ της ρουθ ωβηδ δε εγεννησεν τον ιεσσαι'),
(6, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 6, 'NT', 'ιεσσαι δε εγεννησεν τον δαβιδ τον βασιλεα δαβιδ δε ο βασιλευς εγεννησεν τον σολομωντα εκ της του ουριου'),
(7, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 7, 'NT', 'σολομων δε εγεννησεν τον ροβοαμ ροβοαμ δε εγεννησεν τον αβια αβια δε εγεννησεν τον ασα'),
(8, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 8, 'NT', 'ασα δε εγεννησεν τον ιωσαφατ ιωσαφατ δε εγεννησεν τον ιωραμ ιωραμ δε εγεννησεν τον οζιαν'),
(9, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 9, 'NT', 'οζιας δε εγεννησεν τον ιωαθαμ ιωαθαμ δε εγεννησεν τον αχαζ αχαζ δε εγεννησεν τον εζεκιαν'),
(10, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 10, 'NT', 'εζεκιας δε εγεννησεν τον μανασση μανασσης δε εγεννησεν τον αμων αμων δε εγεννησεν τον ιωσιαν'),
(11, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 11, 'NT', 'ιωσιας δε εγεννησεν τον ιεχονιαν και τους αδελφους αυτου επι της μετοικεσιας βαβυλωνος'),
(12, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 12, 'NT', 'μετα δε την μετοικεσιαν βαβυλωνος ιεχονιας εγεννησεν τον σαλαθιηλ σαλαθιηλ δε εγεννησεν τον ζοροβαβελ'),
(13, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 13, 'NT', 'ζοροβαβελ δε εγεννησεν τον αβιουδ αβιουδ δε εγεννησεν τον ελιακειμ ελιακειμ δε εγεννησεν τον αζωρ'),
(14, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 14, 'NT', 'αζωρ δε εγεννησεν τον σαδωκ σαδωκ δε εγεννησεν τον αχειμ αχειμ δε εγεννησεν τον ελιουδ'),
(15, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 15, 'NT', 'ελιουδ δε εγεννησεν τον ελεαζαρ ελεαζαρ δε εγεννησεν τον ματθαν ματθαν δε εγεννησεν τον ιακωβ'),
(16, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 16, 'NT', 'ιακωβ δε εγεννησεν τον ιωσηφ τον ανδρα μαριας εξ ης εγεννηθη ιησους ο λεγομενος χριστος'),
(17, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 17, 'NT', 'πασαι ουν αι γενεαι απο αβρααμ εως δαβιδ γενεαι δεκατεσσαρες και απο δαβιδ εως της μετοικεσιας βαβυλωνος γενεαι δεκατεσσαρες και απο της μετοικεσιας βαβυλωνος εως του χριστου γενεαι δεκατεσσαρες'),
(18, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 18, 'NT', 'του δε ιησου χριστου η γεννησις ουτως ην μνηστευθεισης γαρ της μητρος αυτου μαριας τω ιωσηφ πριν η συνελθειν αυτους ευρεθη εν γαστρι εχουσα εκ πνευματος αγιου'),
(19, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 19, 'NT', 'ιωσηφ δε ο ανηρ αυτης δικαιος ων και μη θελων αυτην παραδειγματισαι εβουληθη λαθρα απολυσαι αυτην'),
(20, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 20, 'NT', 'ταυτα δε αυτου ενθυμηθεντος ιδου αγγελος κυριου κατ οναρ εφανη αυτω λεγων ιωσηφ υιος δαβιδ μη φοβηθης παραλαβειν μαριαμ την γυναικα σου το γαρ εν αυτη γεννηθεν εκ πνευματος εστιν αγιου'),
(21, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 21, 'NT', 'τεξεται δε υιον και καλεσεις το ονομα αυτου ιησουν αυτος γαρ σωσει τον λαον αυτου απο των αμαρτιων αυτων'),
(22, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 22, 'NT', 'τουτο δε ολον γεγονεν ινα πληρωθη το ρηθεν υπο του κυριου δια του προφητου λεγοντος'),
(23, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 23, 'NT', 'ιδου η παρθενος εν γαστρι εξει και τεξεται υιον και καλεσουσιν το ονομα αυτου εμμανουηλ ο εστιν μεθερμηνευομενον μεθ ημων ο θεος'),
(24, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 24, 'NT', 'διεγερθεις δε ο ιωσηφ απο του υπνου εποιησεν ως προσεταξεν αυτω ο αγγελος κυριου και παρελαβεν την γυναικα αυτου'),
(25, 40, 'TR1550', 'TR1550', 'el', 'MAT', 1, 25, 'NT', 'και ουκ εγινωσκεν αυτην εως ου ετεκεν τον υιον αυτης τον πρωτοτοκον και εκαλεσεν το ονομα αυτου ιησουν'),
(26, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 1, 'NT', 'του δε ιησου γεννηθεντος εν βηθλεεμ της ιουδαιας εν ημεραις ηρωδου του βασιλεως ιδου μαγοι απο ανατολων παρεγενοντο εις ιεροσολυμα'),
(27, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 2, 'NT', 'λεγοντες που εστιν ο τεχθεις βασιλευς των ιουδαιων ειδομεν γαρ αυτου τον αστερα εν τη ανατολη και ηλθομεν προσκυνησαι αυτω'),
(28, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 3, 'NT', 'ακουσας δε ηρωδης ο βασιλευς εταραχθη και πασα ιεροσολυμα μετ αυτου'),
(29, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 4, 'NT', 'και συναγαγων παντας τους αρχιερεις και γραμματεις του λαου επυνθανετο παρ αυτων που ο χριστος γενναται'),
(30, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 5, 'NT', 'οι δε ειπον αυτω εν βηθλεεμ της ιουδαιας ουτως γαρ γεγραπται δια του προφητου'),
(31, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 6, 'NT', 'και συ βηθλεεμ γη ιουδα ουδαμως ελαχιστη ει εν τοις ηγεμοσιν ιουδα εκ σου γαρ εξελευσεται ηγουμενος οστις ποιμανει τον λαον μου τον ισραηλ'),
(32, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 7, 'NT', 'τοτε ηρωδης λαθρα καλεσας τους μαγους ηκριβωσεν παρ αυτων τον χρονον του φαινομενου αστερος'),
(33, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 8, 'NT', 'και πεμψας αυτους εις βηθλεεμ ειπεν πορευθεντες ακριβως εξετασατε περι του παιδιου επαν δε ευρητε απαγγειλατε μοι οπως καγω ελθων προσκυνησω αυτω'),
(34, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 9, 'NT', 'οι δε ακουσαντες του βασιλεως επορευθησαν και ιδου ο αστηρ ον ειδον εν τη ανατολη προηγεν αυτους εως ελθων εστη επανω ου ην το παιδιον'),
(35, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 10, 'NT', 'ιδοντες δε τον αστερα εχαρησαν χαραν μεγαλην σφοδρα'),
(36, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 11, 'NT', 'και ελθοντες εις την οικιαν ευρον το παιδιον μετα μαριας της μητρος αυτου και πεσοντες προσεκυνησαν αυτω και ανοιξαντες τους θησαυρους αυτων προσηνεγκαν αυτω δωρα χρυσον και λιβανον και σμυρναν'),
(37, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 12, 'NT', 'και χρηματισθεντες κατ οναρ μη ανακαμψαι προς ηρωδην δι αλλης οδου ανεχωρησαν εις την χωραν αυτων'),
(38, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 13, 'NT', 'αναχωρησαντων δε αυτων ιδου αγγελος κυριου φαινεται κατ οναρ τω ιωσηφ λεγων εγερθεις παραλαβε το παιδιον και την μητερα αυτου και φευγε εις αιγυπτον και ισθι εκει εως αν ειπω σοι μελλει γαρ ηρωδης ζητειν το παιδιον του απολεσαι αυτο'),
(39, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 14, 'NT', 'ο δε εγερθεις παρελαβεν το παιδιον και την μητερα αυτου νυκτος και ανεχωρησεν εις αιγυπτον'),
(40, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 15, 'NT', 'και ην εκει εως της τελευτης ηρωδου ινα πληρωθη το ρηθεν υπο του κυριου δια του προφητου λεγοντος εξ αιγυπτου εκαλεσα τον υιον μου'),
(41, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 16, 'NT', 'τοτε ηρωδης ιδων οτι ενεπαιχθη υπο των μαγων εθυμωθη λιαν και αποστειλας ανειλεν παντας τους παιδας τους εν βηθλεεμ και εν πασιν τοις οριοις αυτης απο διετους και κατωτερω κατα τον χρονον ον ηκριβωσεν παρα των μαγων'),
(42, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 17, 'NT', 'τοτε επληρωθη το ρηθεν υπο ιερεμιου του προφητου λεγοντος'),
(43, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 18, 'NT', 'φωνη εν ραμα ηκουσθη θρηνος και κλαυθμος και οδυρμος πολυς ραχηλ κλαιουσα τα τεκνα αυτης και ουκ ηθελεν παρακληθηναι οτι ουκ εισιν'),
(44, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 19, 'NT', 'τελευτησαντος δε του ηρωδου ιδου αγγελος κυριου κατ οναρ φαινεται τω ιωσηφ εν αιγυπτω'),
(45, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 20, 'NT', 'λεγων εγερθεις παραλαβε το παιδιον και την μητερα αυτου και πορευου εις γην ισραηλ τεθνηκασιν γαρ οι ζητουντες την ψυχην του παιδιου'),
(46, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 21, 'NT', 'ο δε εγερθεις παρελαβεν το παιδιον και την μητερα αυτου και ηλθεν εις γην ισραηλ'),
(47, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 22, 'NT', 'ακουσας δε οτι αρχελαος βασιλευει επι της ιουδαιας αντι ηρωδου του πατρος αυτου εφοβηθη εκει απελθειν χρηματισθεις δε κατ οναρ ανεχωρησεν εις τα μερη της γαλιλαιας'),
(48, 40, 'TR1550', 'TR1550', 'el', 'MAT', 2, 23, 'NT', 'και ελθων κατωκησεν εις πολιν λεγομενην ναζαρετ οπως πληρωθη το ρηθεν δια των προφητων οτι ναζωραιος κληθησεται'),
(49, 40, 'TR1550', 'TR1550', 'el', 'MAT', 3, 1, 'NT', 'εν δε ταις ημεραις εκειναις παραγινεται ιωαννης ο βαπτιστης κηρυσσων εν τη ερημω της ιουδαιας'),
(50, 40, 'TR1550', 'TR1550', 'el', 'MAT', 3, 2, 'NT', 'και λεγων μετανοειτε ηγγικεν γαρ η βασιλεια των ουρανων'),
(51, 40, 'TR1550', 'TR1550', 'el', 'MAT', 3, 3, 'NT', 'ουτος γαρ εστιν ο ρηθεις υπο ησαιου του προφητου λεγοντος φωνη βοωντος εν τη ερημω ετοιμασατε την οδον κυριου ευθειας ποιειτε τας τριβους αυτου'),
(52, 40, 'TR1550', 'TR1550', 'el', 'MAT', 3, 4, 'NT', 'αυτος δε ο ιωαννης ειχεν το ενδυμα αυτου απο τριχων καμηλου και ζωνην δερματινην περι την οσφυν αυτου η δε τροφη αυτου ην ακριδες και μελι αγριον'),
(53, 40, 'TR1550', 'TR1550', 'el', 'MAT', 3, 5, 'NT', 'τοτε εξεπορευετο προς αυτον ιεροσολυμα και πασα η ιουδαια και πασα η περιχωρος του ιορδανου'),
(54, 40, 'TR1550', 'TR1550', 'el', 'MAT', 3, 6, 'NT', 'και εβαπτιζοντο εν τω ιορδανη υπ αυτου εξομολογουμενοι τας αμαρτιας αυτων'),
(55, 40, 'TR1550', 'TR1550', 'el', 'MAT', 3, 7, 'NT', 'ιδων δε πολλους των φαρισαιων και σαδδουκαιων ερχομενους επι το βαπτισμα αυτου ειπεν αυτοις γεννηματα εχιδνων τις υπεδειξεν υμιν φυγειν απο της μελλουσης οργης'),
(56, 40, 'TR1550', 'TR1550', 'el', 'MAT', 3, 8, 'NT', 'ποιησατε ουν καρπους αξιους της μετανοιας'),
(57, 40, 'TR1550', 'TR1550', 'el', 'MAT', 3, 9, 'NT', 'και μη δοξητε λεγειν εν εαυτοις πατερα εχομεν τον αβρααμ λεγω γαρ υμιν οτι δυναται ο θεος εκ των λιθων τουτων εγειραι τεκνα τω αβρααμ'),
(58, 40, 'TR1550', 'TR1550', 'el', 'MAT', 3, 10, 'NT', 'ηδη δε και η αξινη προς την ριζαν των δενδρων κειται παν ουν δενδρον μη ποιουν καρπον καλον εκκοπτεται και εις πυρ βαλλεται'),
(59, 40, 'TR1550', 'TR1550', 'el', 'MAT', 3, 11, 'NT', 'εγω μεν βαπτιζω υμας εν υδατι εις μετανοιαν ο δε οπισω μου ερχομενος ισχυροτερος μου εστιν ου ουκ ειμι ικανος τα υποδηματα βαστασαι αυτος υμας βαπτισει εν πνευματι αγιω και πυρι'),
(60, 40, 'TR1550', 'TR1550', 'el', 'MAT', 3, 12, 'NT', 'ου το πτυον εν τη χειρι αυτου και διακαθαριει την αλωνα αυτου και συναξει τον σιτον αυτου εις την αποθηκην το δε αχυρον κατακαυσει πυρι ασβεστω'),
(61, 40, 'TR1550', 'TR1550', 'el', 'MAT', 3, 13, 'NT', 'τοτε παραγινεται ο ιησους απο της γαλιλαιας επι τον ιορδανην προς τον ιωαννην του βαπτισθηναι υπ αυτου'),
(62, 40, 'TR1550', 'TR1550', 'el', 'MAT', 3, 14, 'NT', 'ο δε ιωαννης διεκωλυεν αυτον λεγων εγω χρειαν εχω υπο σου βαπτισθηναι και συ ερχη προς με'),
(63, 40, 'TR1550', 'TR1550', 'el', 'MAT', 3, 15, 'NT', 'αποκριθεις δε ο ιησους ειπεν προς αυτον αφες αρτι ουτως γαρ πρεπον εστιν ημιν πληρωσαι πασαν δικαιοσυνην τοτε αφιησιν αυτον'),
(64, 40, 'TR1550', 'TR1550', 'el', 'MAT', 3, 16, 'NT', 'και βαπτισθεις ο ιησους ανεβη ευθυς απο του υδατος και ιδου ανεωχθησαν αυτω οι ουρανοι και ειδεν το πνευμα του θεου καταβαινον ωσει περιστεραν και ερχομενον επ αυτον'),
(65, 40, 'TR1550', 'TR1550', 'el', 'MAT', 3, 17, 'NT', 'και ιδου φωνη εκ των ουρανων λεγουσα ουτος εστιν ο υιος μου ο αγαπητος εν ω ευδοκησα'),
(66, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 1, 'NT', 'τοτε ο ιησους ανηχθη εις την ερημον υπο του πνευματος πειρασθηναι υπο του διαβολου'),
(67, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 2, 'NT', 'και νηστευσας ημερας τεσσαρακοντα και νυκτας τεσσαρακοντα υστερον επεινασεν'),
(68, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 3, 'NT', 'και προσελθων αυτω ο πειραζων ειπεν ει υιος ει του θεου ειπε ινα οι λιθοι ουτοι αρτοι γενωνται'),
(69, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 4, 'NT', 'ο δε αποκριθεις ειπεν γεγραπται ουκ επ αρτω μονω ζησεται ανθρωπος αλλ επι παντι ρηματι εκπορευομενω δια στοματος θεου'),
(70, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 5, 'NT', 'τοτε παραλαμβανει αυτον ο διαβολος εις την αγιαν πολιν και ιστησιν αυτον επι το πτερυγιον του ιερου'),
(71, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 6, 'NT', 'και λεγει αυτω ει υιος ει του θεου βαλε σεαυτον κατω γεγραπται γαρ οτι τοις αγγελοις αυτου εντελειται περι σου και επι χειρων αρουσιν σε μηποτε προσκοψης προς λιθον τον ποδα σου'),
(72, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 7, 'NT', 'εφη αυτω ο ιησους παλιν γεγραπται ουκ εκπειρασεις κυριον τον θεον σου'),
(73, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 8, 'NT', 'παλιν παραλαμβανει αυτον ο διαβολος εις ορος υψηλον λιαν και δεικνυσιν αυτω πασας τας βασιλειας του κοσμου και την δοξαν αυτων'),
(74, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 9, 'NT', 'και λεγει αυτω ταυτα παντα σοι δωσω εαν πεσων προσκυνησης μοι'),
(75, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 10, 'NT', 'τοτε λεγει αυτω ο ιησους υπαγε σατανα γεγραπται γαρ κυριον τον θεον σου προσκυνησεις και αυτω μονω λατρευσεις'),
(76, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 11, 'NT', 'τοτε αφιησιν αυτον ο διαβολος και ιδου αγγελοι προσηλθον και διηκονουν αυτω'),
(77, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 12, 'NT', 'ακουσας δε ο ιησους οτι ιωαννης παρεδοθη ανεχωρησεν εις την γαλιλαιαν'),
(78, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 13, 'NT', 'και καταλιπων την ναζαρετ ελθων κατωκησεν εις καπερναουμ την παραθαλασσιαν εν οριοις ζαβουλων και νεφθαλειμ'),
(79, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 14, 'NT', 'ινα πληρωθη το ρηθεν δια ησαιου του προφητου λεγοντος'),
(80, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 15, 'NT', 'γη ζαβουλων και γη νεφθαλειμ οδον θαλασσης περαν του ιορδανου γαλιλαια των εθνων'),
(81, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 16, 'NT', 'ο λαος ο καθημενος εν σκοτει ειδε φως μεγα και τοις καθημενοις εν χωρα και σκια θανατου φως ανετειλεν αυτοις'),
(82, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 17, 'NT', 'απο τοτε ηρξατο ο ιησους κηρυσσειν και λεγειν μετανοειτε ηγγικεν γαρ η βασιλεια των ουρανων'),
(83, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 18, 'NT', 'περιπατων δε ο ιησους παρα την θαλασσαν της γαλιλαιας ειδεν δυο αδελφους σιμωνα τον λεγομενον πετρον και ανδρεαν τον αδελφον αυτου βαλλοντας αμφιβληστρον εις την θαλασσαν ησαν γαρ αλιεις'),
(84, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 19, 'NT', 'και λεγει αυτοις δευτε οπισω μου και ποιησω υμας αλιεις ανθρωπων'),
(85, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 20, 'NT', 'οι δε ευθεως αφεντες τα δικτυα ηκολουθησαν αυτω'),
(86, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 21, 'NT', 'και προβας εκειθεν ειδεν αλλους δυο αδελφους ιακωβον τον του ζεβεδαιου και ιωαννην τον αδελφον αυτου εν τω πλοιω μετα ζεβεδαιου του πατρος αυτων καταρτιζοντας τα δικτυα αυτων και εκαλεσεν αυτους'),
(87, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 22, 'NT', 'οι δε ευθεως αφεντες το πλοιον και τον πατερα αυτων ηκολουθησαν αυτω'),
(88, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 23, 'NT', 'και περιηγεν ολην την γαλιλαιαν ο ιησους διδασκων εν ταις συναγωγαις αυτων και κηρυσσων το ευαγγελιον της βασιλειας και θεραπευων πασαν νοσον και πασαν μαλακιαν εν τω λαω'),
(89, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 24, 'NT', 'και απηλθεν η ακοη αυτου εις ολην την συριαν και προσηνεγκαν αυτω παντας τους κακως εχοντας ποικιλαις νοσοις και βασανοις συνεχομενους και δαιμονιζομενους και σεληνιαζομενους και παραλυτικους και εθεραπευσεν αυτους'),
(90, 40, 'TR1550', 'TR1550', 'el', 'MAT', 4, 25, 'NT', 'και ηκολουθησαν αυτω οχλοι πολλοι απο της γαλιλαιας και δεκαπολεως και ιεροσολυμων και ιουδαιας και περαν του ιορδανου'),
(91, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 1, 'NT', 'ιδων δε τους οχλους ανεβη εις το ορος και καθισαντος αυτου προσηλθον αυτω οι μαθηται αυτου'),
(92, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 2, 'NT', 'και ανοιξας το στομα αυτου εδιδασκεν αυτους λεγων'),
(93, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 3, 'NT', 'μακαριοι οι πτωχοι τω πνευματι οτι αυτων εστιν η βασιλεια των ουρανων'),
(94, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 4, 'NT', 'μακαριοι οι πενθουντες οτι αυτοι παρακληθησονται'),
(95, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 5, 'NT', 'μακαριοι οι πραεις οτι αυτοι κληρονομησουσιν την γην'),
(96, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 6, 'NT', 'μακαριοι οι πεινωντες και διψωντες την δικαιοσυνην οτι αυτοι χορτασθησονται'),
(97, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 7, 'NT', 'μακαριοι οι ελεημονες οτι αυτοι ελεηθησονται'),
(98, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 8, 'NT', 'μακαριοι οι καθαροι τη καρδια οτι αυτοι τον θεον οψονται'),
(99, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 9, 'NT', 'μακαριοι οι ειρηνοποιοι οτι αυτοι υιοι θεου κληθησονται'),
(100, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 10, 'NT', 'μακαριοι οι δεδιωγμενοι ενεκεν δικαιοσυνης οτι αυτων εστιν η βασιλεια των ουρανων'),
(101, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 11, 'NT', 'μακαριοι εστε οταν ονειδισωσιν υμας και διωξωσιν και ειπωσιν παν πονηρον ρημα καθ υμων ψευδομενοι ενεκεν εμου'),
(102, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 12, 'NT', 'χαιρετε και αγαλλιασθε οτι ο μισθος υμων πολυς εν τοις ουρανοις ουτως γαρ εδιωξαν τους προφητας τους προ υμων'),
(103, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 13, 'NT', 'υμεις εστε το αλας της γης εαν δε το αλας μωρανθη εν τινι αλισθησεται εις ουδεν ισχυει ετι ει μη βληθηναι εξω και καταπατεισθαι υπο των ανθρωπων'),
(104, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 14, 'NT', 'υμεις εστε το φως του κοσμου ου δυναται πολις κρυβηναι επανω ορους κειμενη'),
(105, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 15, 'NT', 'ουδε καιουσιν λυχνον και τιθεασιν αυτον υπο τον μοδιον αλλ επι την λυχνιαν και λαμπει πασιν τοις εν τη οικια'),
(106, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 16, 'NT', 'ουτως λαμψατω το φως υμων εμπροσθεν των ανθρωπων οπως ιδωσιν υμων τα καλα εργα και δοξασωσιν τον πατερα υμων τον εν τοις ουρανοις'),
(107, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 17, 'NT', 'μη νομισητε οτι ηλθον καταλυσαι τον νομον η τους προφητας ουκ ηλθον καταλυσαι αλλα πληρωσαι'),
(108, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 18, 'NT', 'αμην γαρ λεγω υμιν εως αν παρελθη ο ουρανος και η γη ιωτα εν η μια κεραια ου μη παρελθη απο του νομου εως αν παντα γενηται'),
(109, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 19, 'NT', 'ος εαν ουν λυση μιαν των εντολων τουτων των ελαχιστων και διδαξη ουτως τους ανθρωπους ελαχιστος κληθησεται εν τη βασιλεια των ουρανων ος δ αν ποιηση και διδαξη ουτος μεγας κληθησεται εν τη βασιλεια των ουρανων'),
(110, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 20, 'NT', 'λεγω γαρ υμιν οτι εαν μη περισσευση η δικαιοσυνη υμων πλειον των γραμματεων και φαρισαιων ου μη εισελθητε εις την βασιλειαν των ουρανων'),
(111, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 21, 'NT', 'ηκουσατε οτι ερρεθη τοις αρχαιοις ου φονευσεις ος δ αν φονευση ενοχος εσται τη κρισει'),
(112, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 22, 'NT', 'εγω δε λεγω υμιν οτι πας ο οργιζομενος τω αδελφω αυτου εικη ενοχος εσται τη κρισει ος δ αν ειπη τω αδελφω αυτου ρακα ενοχος εσται τω συνεδριω ος δ αν ειπη μωρε ενοχος εσται εις την γεενναν του πυρος'),
(113, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 23, 'NT', 'εαν ουν προσφερης το δωρον σου επι το θυσιαστηριον κακει μνησθης οτι ο αδελφος σου εχει τι κατα σου'),
(114, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 24, 'NT', 'αφες εκει το δωρον σου εμπροσθεν του θυσιαστηριου και υπαγε πρωτον διαλλαγηθι τω αδελφω σου και τοτε ελθων προσφερε το δωρον σου'),
(115, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 25, 'NT', 'ισθι ευνοων τω αντιδικω σου ταχυ εως οτου ει εν τη οδω μετ αυτου μηποτε σε παραδω ο αντιδικος τω κριτη και ο κριτης σε παραδω τω υπηρετη και εις φυλακην βληθηση'),
(116, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 26, 'NT', 'αμην λεγω σοι ου μη εξελθης εκειθεν εως αν αποδως τον εσχατον κοδραντην'),
(117, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 27, 'NT', 'ηκουσατε οτι ερρεθη τοις αρχαιοις ου μοιχευσεις'),
(118, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 28, 'NT', 'εγω δε λεγω υμιν οτι πας ο βλεπων γυναικα προς το επιθυμησαι αυτης ηδη εμοιχευσεν αυτην εν τη καρδια αυτου'),
(119, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 29, 'NT', 'ει δε ο οφθαλμος σου ο δεξιος σκανδαλιζει σε εξελε αυτον και βαλε απο σου συμφερει γαρ σοι ινα αποληται εν των μελων σου και μη ολον το σωμα σου βληθη εις γεενναν'),
(120, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 30, 'NT', 'και ει η δεξια σου χειρ σκανδαλιζει σε εκκοψον αυτην και βαλε απο σου συμφερει γαρ σοι ινα αποληται εν των μελων σου και μη ολον το σωμα σου βληθη εις γεενναν'),
(121, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 31, 'NT', 'ερρεθη δε οτι ος αν απολυση την γυναικα αυτου δοτω αυτη αποστασιον'),
(122, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 32, 'NT', 'εγω δε λεγω υμιν οτι ος αν απολυση την γυναικα αυτου παρεκτος λογου πορνειας ποιει αυτην μοιχασθαι και ος εαν απολελυμενην γαμηση μοιχαται'),
(123, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 33, 'NT', 'παλιν ηκουσατε οτι ερρεθη τοις αρχαιοις ουκ επιορκησεις αποδωσεις δε τω κυριω τους ορκους σου'),
(124, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 34, 'NT', 'εγω δε λεγω υμιν μη ομοσαι ολως μητε εν τω ουρανω οτι θρονος εστιν του θεου'),
(125, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 35, 'NT', 'μητε εν τη γη οτι υποποδιον εστιν των ποδων αυτου μητε εις ιεροσολυμα οτι πολις εστιν του μεγαλου βασιλεως'),
(126, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 36, 'NT', 'μητε εν τη κεφαλη σου ομοσης οτι ου δυνασαι μιαν τριχα λευκην η μελαιναν ποιησαι'),
(127, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 37, 'NT', 'εστω δε ο λογος υμων ναι ναι ου ου το δε περισσον τουτων εκ του πονηρου εστιν'),
(128, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 38, 'NT', 'ηκουσατε οτι ερρεθη οφθαλμον αντι οφθαλμου και οδοντα αντι οδοντος'),
(129, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 39, 'NT', 'εγω δε λεγω υμιν μη αντιστηναι τω πονηρω αλλ οστις σε ραπισει επι την δεξιαν σου σιαγονα στρεψον αυτω και την αλλην'),
(130, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 40, 'NT', 'και τω θελοντι σοι κριθηναι και τον χιτωνα σου λαβειν αφες αυτω και το ιματιον'),
(131, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 41, 'NT', 'και οστις σε αγγαρευσει μιλιον εν υπαγε μετ αυτου δυο'),
(132, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 42, 'NT', 'τω αιτουντι σε διδου και τον θελοντα απο σου δανεισασθαι μη αποστραφης'),
(133, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 43, 'NT', 'ηκουσατε οτι ερρεθη αγαπησεις τον πλησιον σου και μισησεις τον εχθρον σου'),
(134, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 44, 'NT', 'εγω δε λεγω υμιν αγαπατε τους εχθρους υμων ευλογειτε τους καταρωμενους υμας καλως ποιειτε τους μισουντας υμας και προσευχεσθε υπερ των επηρεαζοντων υμας και διωκοντων υμας'),
(135, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 45, 'NT', 'οπως γενησθε υιοι του πατρος υμων του εν ουρανοις οτι τον ηλιον αυτου ανατελλει επι πονηρους και αγαθους και βρεχει επι δικαιους και αδικους'),
(136, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 46, 'NT', 'εαν γαρ αγαπησητε τους αγαπωντας υμας τινα μισθον εχετε ουχι και οι τελωναι το αυτο ποιουσιν'),
(137, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 47, 'NT', 'και εαν ασπασησθε τους αδελφους υμων μονον τι περισσον ποιειτε ουχι και οι τελωναι ουτως ποιουσιν'),
(138, 40, 'TR1550', 'TR1550', 'el', 'MAT', 5, 48, 'NT', 'εσεσθε ουν υμεις τελειοι ωσπερ ο πατηρ υμων ο εν τοις ουρανοις τελειος εστιν'),
(139, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 1, 'NT', 'προσεχετε την ελεημοσυνην υμων μη ποιειν εμπροσθεν των ανθρωπων προς το θεαθηναι αυτοις ει δε μηγε μισθον ουκ εχετε παρα τω πατρι υμων τω εν τοις ουρανοις'),
(140, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 2, 'NT', 'οταν ουν ποιης ελεημοσυνην μη σαλπισης εμπροσθεν σου ωσπερ οι υποκριται ποιουσιν εν ταις συναγωγαις και εν ταις ρυμαις οπως δοξασθωσιν υπο των ανθρωπων αμην λεγω υμιν απεχουσιν τον μισθον αυτων'),
(141, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 3, 'NT', 'σου δε ποιουντος ελεημοσυνην μη γνωτω η αριστερα σου τι ποιει η δεξια σου'),
(142, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 4, 'NT', 'οπως η σου η ελεημοσυνη εν τω κρυπτω και ο πατηρ σου ο βλεπων εν τω κρυπτω αυτος αποδωσει σοι εν τω φανερω'),
(143, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 5, 'NT', 'και οταν προσευχη ουκ εση ωσπερ οι υποκριται οτι φιλουσιν εν ταις συναγωγαις και εν ταις γωνιαις των πλατειων εστωτες προσευχεσθαι οπως αν φανωσιν τοις ανθρωποις αμην λεγω υμιν οτι απεχουσιν τον μισθον αυτων'),
(144, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 6, 'NT', 'συ δε οταν προσευχη εισελθε εις το ταμιειον σου και κλεισας την θυραν σου προσευξαι τω πατρι σου τω εν τω κρυπτω και ο πατηρ σου ο βλεπων εν τω κρυπτω αποδωσει σοι εν τω φανερω'),
(145, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 7, 'NT', 'προσευχομενοι δε μη βαττολογησητε ωσπερ οι εθνικοι δοκουσιν γαρ οτι εν τη πολυλογια αυτων εισακουσθησονται'),
(146, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 8, 'NT', 'μη ουν ομοιωθητε αυτοις οιδεν γαρ ο πατηρ υμων ων χρειαν εχετε προ του υμας αιτησαι αυτον'),
(147, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 9, 'NT', 'ουτως ουν προσευχεσθε υμεις πατερ ημων ο εν τοις ουρανοις αγιασθητω το ονομα σου'),
(148, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 10, 'NT', 'ελθετω η βασιλεια σου γενηθητω το θελημα σου ως εν ουρανω και επι της γης'),
(149, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 11, 'NT', 'τον αρτον ημων τον επιουσιον δος ημιν σημερον'),
(150, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 12, 'NT', 'και αφες ημιν τα οφειληματα ημων ως και ημεις αφιεμεν τοις οφειλεταις ημων'),
(151, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 13, 'NT', 'και μη εισενεγκης ημας εις πειρασμον αλλα ρυσαι ημας απο του πονηρου οτι σου εστιν η βασιλεια και η δυναμις και η δοξα εις τους αιωνας αμην'),
(152, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 14, 'NT', 'εαν γαρ αφητε τοις ανθρωποις τα παραπτωματα αυτων αφησει και υμιν ο πατηρ υμων ο ουρανιος'),
(153, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 15, 'NT', 'εαν δε μη αφητε τοις ανθρωποις τα παραπτωματα αυτων ουδε ο πατηρ υμων αφησει τα παραπτωματα υμων'),
(154, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 16, 'NT', 'οταν δε νηστευητε μη γινεσθε ωσπερ οι υποκριται σκυθρωποι αφανιζουσιν γαρ τα προσωπα αυτων οπως φανωσιν τοις ανθρωποις νηστευοντες αμην λεγω υμιν οτι απεχουσιν τον μισθον αυτων'),
(155, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 17, 'NT', 'συ δε νηστευων αλειψαι σου την κεφαλην και το προσωπον σου νιψαι'),
(156, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 18, 'NT', 'οπως μη φανης τοις ανθρωποις νηστευων αλλα τω πατρι σου τω εν τω κρυπτω και ο πατηρ σου ο βλεπων εν τω κρυπτω αποδωσει σοι εν τω φανερω'),
(157, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 19, 'NT', 'μη θησαυριζετε υμιν θησαυρους επι της γης οπου σης και βρωσις αφανιζει και οπου κλεπται διορυσσουσιν και κλεπτουσιν'),
(158, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 20, 'NT', 'θησαυριζετε δε υμιν θησαυρους εν ουρανω οπου ουτε σης ουτε βρωσις αφανιζει και οπου κλεπται ου διορυσσουσιν ουδε κλεπτουσιν'),
(159, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 21, 'NT', 'οπου γαρ εστιν ο θησαυρος υμων εκει εσται και η καρδια υμων'),
(160, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 22, 'NT', 'ο λυχνος του σωματος εστιν ο οφθαλμος εαν ουν ο οφθαλμος σου απλους η ολον το σωμα σου φωτεινον εσται'),
(161, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 23, 'NT', 'εαν δε ο οφθαλμος σου πονηρος η ολον το σωμα σου σκοτεινον εσται ει ουν το φως το εν σοι σκοτος εστιν το σκοτος ποσον'),
(162, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 24, 'NT', 'ουδεις δυναται δυσι κυριοις δουλευειν η γαρ τον ενα μισησει και τον ετερον αγαπησει η ενος ανθεξεται και του ετερου καταφρονησει ου δυνασθε θεω δουλευειν και μαμμωνα'),
(163, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 25, 'NT', 'δια τουτο λεγω υμιν μη μεριμνατε τη ψυχη υμων τι φαγητε και τι πιητε μηδε τω σωματι υμων τι ενδυσησθε ουχι η ψυχη πλειον εστιν της τροφης και το σωμα του ενδυματος'),
(164, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 26, 'NT', 'εμβλεψατε εις τα πετεινα του ουρανου οτι ου σπειρουσιν ουδε θεριζουσιν ουδε συναγουσιν εις αποθηκας και ο πατηρ υμων ο ουρανιος τρεφει αυτα ουχ υμεις μαλλον διαφερετε αυτων'),
(165, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 27, 'NT', 'τις δε εξ υμων μεριμνων δυναται προσθειναι επι την ηλικιαν αυτου πηχυν ενα'),
(166, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 28, 'NT', 'και περι ενδυματος τι μεριμνατε καταμαθετε τα κρινα του αγρου πως αυξανει ου κοπια ουδε νηθει'),
(167, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 29, 'NT', 'λεγω δε υμιν οτι ουδε σολομων εν παση τη δοξη αυτου περιεβαλετο ως εν τουτων'),
(168, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 30, 'NT', 'ει δε τον χορτον του αγρου σημερον οντα και αυριον εις κλιβανον βαλλομενον ο θεος ουτως αμφιεννυσιν ου πολλω μαλλον υμας ολιγοπιστοι'),
(169, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 31, 'NT', 'μη ουν μεριμνησητε λεγοντες τι φαγωμεν η τι πιωμεν η τι περιβαλωμεθα'),
(170, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 32, 'NT', 'παντα γαρ ταυτα τα εθνη επιζητει οιδεν γαρ ο πατηρ υμων ο ουρανιος οτι χρηζετε τουτων απαντων'),
(171, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 33, 'NT', 'ζητειτε δε πρωτον την βασιλειαν του θεου και την δικαιοσυνην αυτου και ταυτα παντα προστεθησεται υμιν'),
(172, 40, 'TR1550', 'TR1550', 'el', 'MAT', 6, 34, 'NT', 'μη ουν μεριμνησητε εις την αυριον η γαρ αυριον μεριμνησει τα εαυτης αρκετον τη ημερα η κακια αυτης'),
(173, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 1, 'NT', 'μη κρινετε ινα μη κριθητε'),
(174, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 2, 'NT', 'εν ω γαρ κριματι κρινετε κριθησεσθε και εν ω μετρω μετρειτε αντιμετρηθησεται υμιν'),
(175, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 3, 'NT', 'τι δε βλεπεις το καρφος το εν τω οφθαλμω του αδελφου σου την δε εν τω σω οφθαλμω δοκον ου κατανοεις'),
(176, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 4, 'NT', 'η πως ερεις τω αδελφω σου αφες εκβαλω το καρφος απο του οφθαλμου σου και ιδου η δοκος εν τω οφθαλμω σου'),
(177, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 5, 'NT', 'υποκριτα εκβαλε πρωτον την δοκον εκ του οφθαλμου σου και τοτε διαβλεψεις εκβαλειν το καρφος εκ του οφθαλμου του αδελφου σου'),
(178, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 6, 'NT', 'μη δωτε το αγιον τοις κυσιν μηδε βαλητε τους μαργαριτας υμων εμπροσθεν των χοιρων μηποτε καταπατησωσιν αυτους εν τοις ποσιν αυτων και στραφεντες ρηξωσιν υμας'),
(179, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 7, 'NT', 'αιτειτε και δοθησεται υμιν ζητειτε και ευρησετε κρουετε και ανοιγησεται υμιν'),
(180, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 8, 'NT', 'πας γαρ ο αιτων λαμβανει και ο ζητων ευρισκει και τω κρουοντι ανοιγησεται'),
(181, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 9, 'NT', 'η τις εστιν εξ υμων ανθρωπος ον εαν αιτηση ο υιος αυτου αρτον μη λιθον επιδωσει αυτω'),
(182, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 10, 'NT', 'και εαν ιχθυν αιτηση μη οφιν επιδωσει αυτω'),
(183, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 11, 'NT', 'ει ουν υμεις πονηροι οντες οιδατε δοματα αγαθα διδοναι τοις τεκνοις υμων ποσω μαλλον ο πατηρ υμων ο εν τοις ουρανοις δωσει αγαθα τοις αιτουσιν αυτον'),
(184, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 12, 'NT', 'παντα ουν οσα αν θελητε ινα ποιωσιν υμιν οι ανθρωποι ουτως και υμεις ποιειτε αυτοις ουτος γαρ εστιν ο νομος και οι προφηται'),
(185, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 13, 'NT', 'εισελθετε δια της στενης πυλης οτι πλατεια η πυλη και ευρυχωρος η οδος η απαγουσα εις την απωλειαν και πολλοι εισιν οι εισερχομενοι δι αυτης'),
(186, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 14, 'NT', 'οτι στενη η πυλη και τεθλιμμενη η οδος η απαγουσα εις την ζωην και ολιγοι εισιν οι ευρισκοντες αυτην'),
(187, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 15, 'NT', 'προσεχετε δε απο των ψευδοπροφητων οιτινες ερχονται προς υμας εν ενδυμασιν προβατων εσωθεν δε εισιν λυκοι αρπαγες'),
(188, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 16, 'NT', 'απο των καρπων αυτων επιγνωσεσθε αυτους μητι συλλεγουσιν απο ακανθων σταφυλην η απο τριβολων συκα'),
(189, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 17, 'NT', 'ουτως παν δενδρον αγαθον καρπους καλους ποιει το δε σαπρον δενδρον καρπους πονηρους ποιει'),
(190, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 18, 'NT', 'ου δυναται δενδρον αγαθον καρπους πονηρους ποιειν ουδε δενδρον σαπρον καρπους καλους ποιειν'),
(191, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 19, 'NT', 'παν δενδρον μη ποιουν καρπον καλον εκκοπτεται και εις πυρ βαλλεται'),
(192, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 20, 'NT', 'αραγε απο των καρπων αυτων επιγνωσεσθε αυτους'),
(193, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 21, 'NT', 'ου πας ο λεγων μοι κυριε κυριε εισελευσεται εις την βασιλειαν των ουρανων αλλ ο ποιων το θελημα του πατρος μου του εν ουρανοις'),
(194, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 22, 'NT', 'πολλοι ερουσιν μοι εν εκεινη τη ημερα κυριε κυριε ου τω σω ονοματι προεφητευσαμεν και τω σω ονοματι δαιμονια εξεβαλομεν και τω σω ονοματι δυναμεις πολλας εποιησαμεν'),
(195, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 23, 'NT', 'και τοτε ομολογησω αυτοις οτι ουδεποτε εγνων υμας αποχωρειτε απ εμου οι εργαζομενοι την ανομιαν'),
(196, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 24, 'NT', 'πας ουν οστις ακουει μου τους λογους τουτους και ποιει αυτους ομοιωσω αυτον ανδρι φρονιμω οστις ωκοδομησεν την οικιαν αυτου επι την πετραν'),
(197, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 25, 'NT', 'και κατεβη η βροχη και ηλθον οι ποταμοι και επνευσαν οι ανεμοι και προσεπεσον τη οικια εκεινη και ουκ επεσεν τεθεμελιωτο γαρ επι την πετραν'),
(198, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 26, 'NT', 'και πας ο ακουων μου τους λογους τουτους και μη ποιων αυτους ομοιωθησεται ανδρι μωρω οστις ωκοδομησεν την οικιαν αυτου επι την αμμον'),
(199, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 27, 'NT', 'και κατεβη η βροχη και ηλθον οι ποταμοι και επνευσαν οι ανεμοι και προσεκοψαν τη οικια εκεινη και επεσεν και ην η πτωσις αυτης μεγαλη'),
(200, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 28, 'NT', 'και εγενετο οτε συνετελεσεν ο ιησους τους λογους τουτους εξεπλησσοντο οι οχλοι επι τη διδαχη αυτου'),
(201, 40, 'TR1550', 'TR1550', 'el', 'MAT', 7, 29, 'NT', 'ην γαρ διδασκων αυτους ως εξουσιαν εχων και ουχ ως οι γραμματεις'),
(202, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 1, 'NT', 'καταβαντι δε αυτω απο του ορους ηκολουθησαν αυτω οχλοι πολλοι'),
(203, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 2, 'NT', 'και ιδου λεπρος ελθων προσεκυνει αυτω λεγων κυριε εαν θελης δυνασαι με καθαρισαι'),
(204, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 3, 'NT', 'και εκτεινας την χειρα ηψατο αυτου ο ιησους λεγων θελω καθαρισθητι και ευθεως εκαθαρισθη αυτου η λεπρα'),
(205, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 4, 'NT', 'και λεγει αυτω ο ιησους ορα μηδενι ειπης αλλ υπαγε σεαυτον δειξον τω ιερει και προσενεγκε το δωρον ο προσεταξεν μωσης εις μαρτυριον αυτοις'),
(206, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 5, 'NT', 'εισελθοντι δε τω ιησου εις καπερναουμ προσηλθεν αυτω εκατονταρχος παρακαλων αυτον'),
(207, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 6, 'NT', 'και λεγων κυριε ο παις μου βεβληται εν τη οικια παραλυτικος δεινως βασανιζομενος'),
(208, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 7, 'NT', 'και λεγει αυτω ο ιησους εγω ελθων θεραπευσω αυτον'),
(209, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 8, 'NT', 'και αποκριθεις ο εκατονταρχος εφη κυριε ουκ ειμι ικανος ινα μου υπο την στεγην εισελθης αλλα μονον ειπε λογον και ιαθησεται ο παις μου'),
(210, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 9, 'NT', 'και γαρ εγω ανθρωπος ειμι υπο εξουσιαν εχων υπ εμαυτον στρατιωτας και λεγω τουτω πορευθητι και πορευεται και αλλω ερχου και ερχεται και τω δουλω μου ποιησον τουτο και ποιει'),
(211, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 10, 'NT', 'ακουσας δε ο ιησους εθαυμασεν και ειπεν τοις ακολουθουσιν αμην λεγω υμιν ουδε εν τω ισραηλ τοσαυτην πιστιν ευρον'),
(212, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 11, 'NT', 'λεγω δε υμιν οτι πολλοι απο ανατολων και δυσμων ηξουσιν και ανακλιθησονται μετα αβρααμ και ισαακ και ιακωβ εν τη βασιλεια των ουρανων'),
(213, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 12, 'NT', 'οι δε υιοι της βασιλειας εκβληθησονται εις το σκοτος το εξωτερον εκει εσται ο κλαυθμος και ο βρυγμος των οδοντων'),
(214, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 13, 'NT', 'και ειπεν ο ιησους τω εκατονταρχω υπαγε και ως επιστευσας γενηθητω σοι και ιαθη ο παις αυτου εν τη ωρα εκεινη'),
(215, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 14, 'NT', 'και ελθων ο ιησους εις την οικιαν πετρου ειδεν την πενθεραν αυτου βεβλημενην και πυρεσσουσαν'),
(216, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 15, 'NT', 'και ηψατο της χειρος αυτης και αφηκεν αυτην ο πυρετος και ηγερθη και διηκονει αυτοις'),
(217, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 16, 'NT', 'οψιας δε γενομενης προσηνεγκαν αυτω δαιμονιζομενους πολλους και εξεβαλεν τα πνευματα λογω και παντας τους κακως εχοντας εθεραπευσεν'),
(218, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 17, 'NT', 'οπως πληρωθη το ρηθεν δια ησαιου του προφητου λεγοντος αυτος τας ασθενειας ημων ελαβεν και τας νοσους εβαστασεν'),
(219, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 18, 'NT', 'ιδων δε ο ιησους πολλους οχλους περι αυτον εκελευσεν απελθειν εις το περαν'),
(220, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 19, 'NT', 'και προσελθων εις γραμματευς ειπεν αυτω διδασκαλε ακολουθησω σοι οπου εαν απερχη'),
(221, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 20, 'NT', 'και λεγει αυτω ο ιησους αι αλωπεκες φωλεους εχουσιν και τα πετεινα του ουρανου κατασκηνωσεις ο δε υιος του ανθρωπου ουκ εχει που την κεφαλην κλινη'),
(222, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 21, 'NT', 'ετερος δε των μαθητων αυτου ειπεν αυτω κυριε επιτρεψον μοι πρωτον απελθειν και θαψαι τον πατερα μου'),
(223, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 22, 'NT', 'ο δε ιησους ειπεν αυτω ακολουθει μοι και αφες τους νεκρους θαψαι τους εαυτων νεκρους'),
(224, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 23, 'NT', 'και εμβαντι αυτω εις το πλοιον ηκολουθησαν αυτω οι μαθηται αυτου'),
(225, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 24, 'NT', 'και ιδου σεισμος μεγας εγενετο εν τη θαλασση ωστε το πλοιον καλυπτεσθαι υπο των κυματων αυτος δε εκαθευδεν'),
(226, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 25, 'NT', 'και προσελθοντες οι μαθηται αυτου ηγειραν αυτον λεγοντες κυριε σωσον ημας απολλυμεθα'),
(227, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 26, 'NT', 'και λεγει αυτοις τι δειλοι εστε ολιγοπιστοι τοτε εγερθεις επετιμησεν τοις ανεμοις και τη θαλασση και εγενετο γαληνη μεγαλη'),
(228, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 27, 'NT', 'οι δε ανθρωποι εθαυμασαν λεγοντες ποταπος εστιν ουτος οτι και οι ανεμοι και η θαλασσα υπακουουσιν αυτω'),
(229, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 28, 'NT', 'και ελθοντι αυτω εις το περαν εις την χωραν των γεργεσηνων υπηντησαν αυτω δυο δαιμονιζομενοι εκ των μνημειων εξερχομενοι χαλεποι λιαν ωστε μη ισχυειν τινα παρελθειν δια της οδου εκεινης'),
(230, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 29, 'NT', 'και ιδου εκραξαν λεγοντες τι ημιν και σοι ιησου υιε του θεου ηλθες ωδε προ καιρου βασανισαι ημας'),
(231, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 30, 'NT', 'ην δε μακραν απ αυτων αγελη χοιρων πολλων βοσκομενη'),
(232, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 31, 'NT', 'οι δε δαιμονες παρεκαλουν αυτον λεγοντες ει εκβαλλεις ημας επιτρεψον ημιν απελθειν εις την αγελην των χοιρων'),
(233, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 32, 'NT', 'και ειπεν αυτοις υπαγετε οι δε εξελθοντες απηλθον εις την αγελην των χοιρων και ιδου ωρμησεν πασα η αγελη των χοιρων κατα του κρημνου εις την θαλασσαν και απεθανον εν τοις υδασιν'),
(234, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 33, 'NT', 'οι δε βοσκοντες εφυγον και απελθοντες εις την πολιν απηγγειλαν παντα και τα των δαιμονιζομενων'),
(235, 40, 'TR1550', 'TR1550', 'el', 'MAT', 8, 34, 'NT', 'και ιδου πασα η πολις εξηλθεν εις συναντησιν τω ιησου και ιδοντες αυτον παρεκαλεσαν οπως μεταβη απο των οριων αυτων'),
(236, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 1, 'NT', 'και εμβας εις το πλοιον διεπερασεν και ηλθεν εις την ιδιαν πολιν'),
(237, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 2, 'NT', 'και ιδου προσεφερον αυτω παραλυτικον επι κλινης βεβλημενον και ιδων ο ιησους την πιστιν αυτων ειπεν τω παραλυτικω θαρσει τεκνον αφεωνται σοι αι αμαρτιαι σου'),
(238, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 3, 'NT', 'και ιδου τινες των γραμματεων ειπον εν εαυτοις ουτος βλασφημει'),
(239, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 4, 'NT', 'και ιδων ο ιησους τας ενθυμησεις αυτων ειπεν ινα τι υμεις ενθυμεισθε πονηρα εν ταις καρδιαις υμων'),
(240, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 5, 'NT', 'τι γαρ εστιν ευκοπωτερον ειπειν αφεωνται σοι αι αμαρτιαι η ειπειν εγειραι και περιπατει'),
(241, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 6, 'NT', 'ινα δε ειδητε οτι εξουσιαν εχει ο υιος του ανθρωπου επι της γης αφιεναι αμαρτιας τοτε λεγει τω παραλυτικω εγερθεις αρον σου την κλινην και υπαγε εις τον οικον σου'),
(242, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 7, 'NT', 'και εγερθεις απηλθεν εις τον οικον αυτου'),
(243, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 8, 'NT', 'ιδοντες δε οι οχλοι εθαυμασαν και εδοξασαν τον θεον τον δοντα εξουσιαν τοιαυτην τοις ανθρωποις'),
(244, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 9, 'NT', 'και παραγων ο ιησους εκειθεν ειδεν ανθρωπον καθημενον επι το τελωνιον ματθαιον λεγομενον και λεγει αυτω ακολουθει μοι και αναστας ηκολουθησεν αυτω'),
(245, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 10, 'NT', 'και εγενετο αυτου ανακειμενου εν τη οικια και ιδου πολλοι τελωναι και αμαρτωλοι ελθοντες συνανεκειντο τω ιησου και τοις μαθηταις αυτου'),
(246, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 11, 'NT', 'και ιδοντες οι φαρισαιοι ειπον τοις μαθηταις αυτου δια τι μετα των τελωνων και αμαρτωλων εσθιει ο διδασκαλος υμων'),
(247, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 12, 'NT', 'ο δε ιησους ακουσας ειπεν αυτοις ου χρειαν εχουσιν οι ισχυοντες ιατρου αλλ οι κακως εχοντες'),
(248, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 13, 'NT', 'πορευθεντες δε μαθετε τι εστιν ελεον θελω και ου θυσιαν ου γαρ ηλθον καλεσαι δικαιους αλλ αμαρτωλους εις μετανοιαν'),
(249, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 14, 'NT', 'τοτε προσερχονται αυτω οι μαθηται ιωαννου λεγοντες δια τι ημεις και οι φαρισαιοι νηστευομεν πολλα οι δε μαθηται σου ου νηστευουσιν'),
(250, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 15, 'NT', 'και ειπεν αυτοις ο ιησους μη δυνανται οι υιοι του νυμφωνος πενθειν εφ οσον μετ αυτων εστιν ο νυμφιος ελευσονται δε ημεραι οταν απαρθη απ αυτων ο νυμφιος και τοτε νηστευσουσιν'),
(251, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 16, 'NT', 'ουδεις δε επιβαλλει επιβλημα ρακους αγναφου επι ιματιω παλαιω αιρει γαρ το πληρωμα αυτου απο του ιματιου και χειρον σχισμα γινεται'),
(252, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 17, 'NT', 'ουδε βαλλουσιν οινον νεον εις ασκους παλαιους ει δε μηγε ρηγνυνται οι ασκοι και ο οινος εκχειται και οι ασκοι απολουνται αλλα βαλλουσιν οινον νεον εις ασκους καινους και αμφοτερα συντηρουνται'),
(253, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 18, 'NT', 'ταυτα αυτου λαλουντος αυτοις ιδου αρχων ελθων προσεκυνει αυτω λεγων οτι η θυγατηρ μου αρτι ετελευτησεν αλλα ελθων επιθες την χειρα σου επ αυτην και ζησεται'),
(254, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 19, 'NT', 'και εγερθεις ο ιησους ηκολουθησεν αυτω και οι μαθηται αυτου'),
(255, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 20, 'NT', 'και ιδου γυνη αιμορροουσα δωδεκα ετη προσελθουσα οπισθεν ηψατο του κρασπεδου του ιματιου αυτου'),
(256, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 21, 'NT', 'ελεγεν γαρ εν εαυτη εαν μονον αψωμαι του ιματιου αυτου σωθησομαι'),
(257, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 22, 'NT', 'ο δε ιησους επιστραφεις και ιδων αυτην ειπεν θαρσει θυγατερ η πιστις σου σεσωκεν σε και εσωθη η γυνη απο της ωρας εκεινης'),
(258, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 23, 'NT', 'και ελθων ο ιησους εις την οικιαν του αρχοντος και ιδων τους αυλητας και τον οχλον θορυβουμενον'),
(259, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 24, 'NT', 'λεγει αυτοις αναχωρειτε ου γαρ απεθανεν το κορασιον αλλα καθευδει και κατεγελων αυτου'),
(260, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 25, 'NT', 'οτε δε εξεβληθη ο οχλος εισελθων εκρατησεν της χειρος αυτης και ηγερθη το κορασιον'),
(261, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 26, 'NT', 'και εξηλθεν η φημη αυτη εις ολην την γην εκεινην'),
(262, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 27, 'NT', 'και παραγοντι εκειθεν τω ιησου ηκολουθησαν αυτω δυο τυφλοι κραζοντες και λεγοντες ελεησον ημας υιε δαβιδ'),
(263, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 28, 'NT', 'ελθοντι δε εις την οικιαν προσηλθον αυτω οι τυφλοι και λεγει αυτοις ο ιησους πιστευετε οτι δυναμαι τουτο ποιησαι λεγουσιν αυτω ναι κυριε'),
(264, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 29, 'NT', 'τοτε ηψατο των οφθαλμων αυτων λεγων κατα την πιστιν υμων γενηθητω υμιν'),
(265, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 30, 'NT', 'και ανεωχθησαν αυτων οι οφθαλμοι και ενεβριμησατο αυτοις ο ιησους λεγων ορατε μηδεις γινωσκετω'),
(266, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 31, 'NT', 'οι δε εξελθοντες διεφημισαν αυτον εν ολη τη γη εκεινη'),
(267, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 32, 'NT', 'αυτων δε εξερχομενων ιδου προσηνεγκαν αυτω ανθρωπον κωφον δαιμονιζομενον'),
(268, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 33, 'NT', 'και εκβληθεντος του δαιμονιου ελαλησεν ο κωφος και εθαυμασαν οι οχλοι λεγοντες οτι ουδεποτε εφανη ουτως εν τω ισραηλ'),
(269, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 34, 'NT', 'οι δε φαρισαιοι ελεγον εν τω αρχοντι των δαιμονιων εκβαλλει τα δαιμονια'),
(270, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 35, 'NT', 'και περιηγεν ο ιησους τας πολεις πασας και τας κωμας διδασκων εν ταις συναγωγαις αυτων και κηρυσσων το ευαγγελιον της βασιλειας και θεραπευων πασαν νοσον και πασαν μαλακιαν εν τω λαω'),
(271, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 36, 'NT', 'ιδων δε τους οχλους εσπλαγχνισθη περι αυτων οτι ησαν εκλελυμενοι και ερριμμενοι ωσει προβατα μη εχοντα ποιμενα'),
(272, 40, 'TR1550', 'TR1550', 'el', 'MAT', 9, 37, 'NT', 'τοτε λεγει τοις μαθηταις αυτου ο μεν θερισμος πολυς οι δε εργαται ολιγοι'),
