(274, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 1, 'NT', 'και προσκαλεσαμενος τους δωδεκα μαθητας αυτου εδωκεν αυτοις εξουσιαν πνευματων ακαθαρτων ωστε εκβαλλειν αυτα και θεραπευειν πασαν νοσον και πασαν μαλακιαν'),
(275, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 2, 'NT', 'των δε δωδεκα αποστολων τα ονοματα εστιν ταυτα πρωτος σιμων ο λεγομενος πετρος και ανδρεας ο αδελφος αυτου ιακωβος ο του ζεβεδαιου και ιωαννης ο αδελφος αυτου'),
(276, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 3, 'NT', 'φιλιππος και βαρθολομαιος θωμας και ματθαιος ο τελωνης ιακωβος ο του αλφαιου και λεββαιος ο επικληθεις θαδδαιος'),
(277, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 4, 'NT', 'σιμων ο κανανιτης και ιουδας ισκαριωτης ο και παραδους αυτον'),
(278, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 5, 'NT', 'τουτους τους δωδεκα απεστειλεν ο ιησους παραγγειλας αυτοις λεγων εις οδον εθνων μη απελθητε και εις πολιν σαμαρειτων μη εισελθητε'),
(279, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 6, 'NT', 'πορευεσθε δε μαλλον προς τα προβατα τα απολωλοτα οικου ισραηλ'),
(280, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 7, 'NT', 'πορευομενοι δε κηρυσσετε λεγοντες οτι ηγγικεν η βασιλεια των ουρανων'),
(281, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 8, 'NT', 'ασθενουντας θεραπευετε λεπρους καθαριζετε νεκρους εγειρετε δαιμονια εκβαλλετε δωρεαν ελαβετε δωρεαν δοτε'),
(282, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 9, 'NT', 'μη κτησησθε χρυσον μηδε αργυρον μηδε χαλκον εις τας ζωνας υμων'),
(283, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 10, 'NT', 'μη πηραν εις οδον μηδε δυο χιτωνας μηδε υποδηματα μηδε ραβδον αξιος γαρ ο εργατης της τροφης αυτου εστιν'),
(284, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 11, 'NT', 'εις ην δ αν πολιν η κωμην εισελθητε εξετασατε τις εν αυτη αξιος εστιν κακει μεινατε εως αν εξελθητε'),
(285, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 12, 'NT', 'εισερχομενοι δε εις την οικιαν ασπασασθε αυτην'),
(286, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 13, 'NT', 'και εαν μεν η η οικια αξια ελθετω η ειρηνη υμων επ αυτην εαν δε μη η αξια η ειρηνη υμων προς υμας επιστραφητω'),
(287, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 14, 'NT', 'και ος εαν μη δεξηται υμας μηδε ακουση τους λογους υμων εξερχομενοι της οικιας η της πολεως εκεινης εκτιναξατε τον κονιορτον των ποδων υμων'),
(288, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 15, 'NT', 'αμην λεγω υμιν ανεκτοτερον εσται γη σοδομων και γομορρων εν ημερα κρισεως η τη πολει εκεινη'),
(289, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 16, 'NT', 'ιδου εγω αποστελλω υμας ως προβατα εν μεσω λυκων γινεσθε ουν φρονιμοι ως οι οφεις και ακεραιοι ως αι περιστεραι'),
(290, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 17, 'NT', 'προσεχετε δε απο των ανθρωπων παραδωσουσιν γαρ υμας εις συνεδρια και εν ταις συναγωγαις αυτων μαστιγωσουσιν υμας'),
(291, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 18, 'NT', 'και επι ηγεμονας δε και βασιλεις αχθησεσθε ενεκεν εμου εις μαρτυριον αυτοις και τοις εθνεσιν'),
(292, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 19, 'NT', 'οταν δε παραδιδωσιν υμας μη μεριμνησητε πως η τι λαλησητε δοθησεται γαρ υμιν εν εκεινη τη ωρα τι λαλησετε'),
(293, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 20, 'NT', 'ου γαρ υμεις εστε οι λαλουντες αλλα το πνευμα του πατρος υμων το λαλουν εν υμιν'),
(294, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 21, 'NT', 'παραδωσει δε αδελφος αδελφον εις θανατον και πατηρ τεκνον και επαναστησονται τεκνα επι γονεις και θανατωσουσιν αυτους'),
(295, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 22, 'NT', 'και εσεσθε μισουμενοι υπο παντων δια το ονομα μου ο δε υπομεινας εις τελος ουτος σωθησεται'),
(296, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 23, 'NT', 'οταν δε διωκωσιν υμας εν τη πολει ταυτη φευγετε εις την αλλην αμην γαρ λεγω υμιν ου μη τελεσητε τας πολεις του ισραηλ εως αν ελθη ο υιος του ανθρωπου'),
(297, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 24, 'NT', 'ουκ εστιν μαθητης υπερ τον διδασκαλον ουδε δουλος υπερ τον κυριον αυτου'),
(298, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 25, 'NT', 'αρκετον τω μαθητη ινα γενηται ως ο διδασκαλος αυτου και ο δουλος ως ο κυριος αυτου ει τον οικοδεσποτην βεελζεβουλ εκαλεσαν ποσω μαλλον τους οικιακους αυτου'),
(299, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 26, 'NT', 'μη ουν φοβηθητε αυτους ουδεν γαρ εστιν κεκαλυμμενον ο ουκ αποκαλυφθησεται και κρυπτον ο ου γνωσθησεται'),
(300, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 27, 'NT', 'ο λεγω υμιν εν τη σκοτια ειπατε εν τω φωτι και ο εις το ους ακουετε κηρυξατε επι των δωματων'),
(301, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 28, 'NT', 'και μη φοβηθητε απο των αποκτεινοντων το σωμα την δε ψυχην μη δυναμενων αποκτειναι φοβηθητε δε μαλλον τον δυναμενον και ψυχην και σωμα απολεσαι εν γεεννη'),
(302, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 29, 'NT', 'ουχι δυο στρουθια ασσαριου πωλειται και εν εξ αυτων ου πεσειται επι την γην ανευ του πατρος υμων'),
(303, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 30, 'NT', 'υμων δε και αι τριχες της κεφαλης πασαι ηριθμημεναι εισιν'),
