(305, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 32, 'NT', 'πας ουν οστις ομολογησει εν εμοι εμπροσθεν των ανθρωπων ομολογησω καγω εν αυτω εμπροσθεν του πατρος μου του εν ουρανοις'),
(306, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 33, 'NT', 'οστις δ αν αρνησηται με εμπροσθεν των ανθρωπων αρνησομαι αυτον καγω εμπροσθεν του πατρος μου του εν ουρανοις'),
(307, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 34, 'NT', 'μη νομισητε οτι ηλθον βαλειν ειρηνην επι την γην ουκ ηλθον βαλειν ειρηνην αλλα μαχαιραν'),
(308, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 35, 'NT', 'ηλθον γαρ διχασαι ανθρωπον κατα του πατρος αυτου και θυγατερα κατα της μητρος αυτης και νυμφην κατα της πενθερας αυτης'),
(309, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 36, 'NT', 'και εχθροι του ανθρωπου οι οικιακοι αυτου'),
(310, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 37, 'NT', 'ο φιλων πατερα η μητερα υπερ εμε ουκ εστιν μου αξιος και ο φιλων υιον η θυγατερα υπερ εμε ουκ εστιν μου αξιος'),
(311, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 38, 'NT', 'και ος ου λαμβανει τον σταυρον αυτου και ακολουθει οπισω μου ουκ εστιν μου αξιος'),
(312, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 39, 'NT', 'ο ευρων την ψυχην αυτου απολεσει αυτην και ο απολεσας την ψυχην αυτου ενεκεν εμου ευρησει αυτην'),
(313, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 40, 'NT', 'ο δεχομενος υμας εμε δεχεται και ο εμε δεχομενος δεχεται τον αποστειλαντα με'),
(314, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 41, 'NT', 'ο δεχομενος προφητην εις ονομα προφητου μισθον προφητου ληψεται και ο δεχομενος δικαιον εις ονομα δικαιου μισθον δικαιου ληψεται'),
(315, 40, 'TR1550', 'TR1550', 'el', 'MAT', 10, 42, 'NT', 'και ος εαν ποτιση ενα των μικρων τουτων ποτηριον ψυχρου μονον εις ονομα μαθητου αμην λεγω υμιν ου μη απολεση τον μισθον αυτου'),
(316, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 1, 'NT', 'και εγενετο οτε ετελεσεν ο ιησους διατασσων τοις δωδεκα μαθηταις αυτου μετεβη εκειθεν του διδασκειν και κηρυσσειν εν ταις πολεσιν αυτων'),
(317, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 2, 'NT', 'ο δε ιωαννης ακουσας εν τω δεσμωτηριω τα εργα του χριστου πεμψας δυο των μαθητων αυτου'),
(318, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 3, 'NT', 'ειπεν αυτω συ ει ο ερχομενος η ετερον προσδοκωμεν'),
(319, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 4, 'NT', 'και αποκριθεις ο ιησους ειπεν αυτοις πορευθεντες απαγγειλατε ιωαννη α ακουετε και βλεπετε'),
(320, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 5, 'NT', 'τυφλοι αναβλεπουσιν και χωλοι περιπατουσιν λεπροι καθαριζονται και κωφοι ακουουσιν νεκροι εγειρονται και πτωχοι ευαγγελιζονται'),
(321, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 6, 'NT', 'και μακαριος εστιν ος εαν μη σκανδαλισθη εν εμοι'),
(322, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 7, 'NT', 'τουτων δε πορευομενων ηρξατο ο ιησους λεγειν τοις οχλοις περι ιωαννου τι εξηλθετε εις την ερημον θεασασθαι καλαμον υπο ανεμου σαλευομενον'),
(323, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 8, 'NT', 'αλλα τι εξηλθετε ιδειν ανθρωπον εν μαλακοις ιματιοις ημφιεσμενον ιδου οι τα μαλακα φορουντες εν τοις οικοις των βασιλεων εισιν'),
(324, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 9, 'NT', 'αλλα τι εξηλθετε ιδειν προφητην ναι λεγω υμιν και περισσοτερον προφητου'),
(325, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 10, 'NT', 'ουτος γαρ εστιν περι ου γεγραπται ιδου εγω αποστελλω τον αγγελον μου προ προσωπου σου ος κατασκευασει την οδον σου εμπροσθεν σου'),
(326, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 11, 'NT', 'αμην λεγω υμιν ουκ εγηγερται εν γεννητοις γυναικων μειζων ιωαννου του βαπτιστου ο δε μικροτερος εν τη βασιλεια των ουρανων μειζων αυτου εστιν'),
(327, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 12, 'NT', 'απο δε των ημερων ιωαννου του βαπτιστου εως αρτι η βασιλεια των ουρανων βιαζεται και βιασται αρπαζουσιν αυτην'),
(328, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 13, 'NT', 'παντες γαρ οι προφηται και ο νομος εως ιωαννου προεφητευσαν'),
(329, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 14, 'NT', 'και ει θελετε δεξασθαι αυτος εστιν ηλιας ο μελλων ερχεσθαι'),
(330, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 15, 'NT', 'ο εχων ωτα ακουειν ακουετω'),
(331, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 16, 'NT', 'τινι δε ομοιωσω την γενεαν ταυτην ομοια εστιν παιδαριοις εν αγοραις καθημενοις και προσφωνουσιν τοις εταιροις αυτων'),
(332, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 17, 'NT', 'και λεγουσιν ηυλησαμεν υμιν και ουκ ωρχησασθε εθρηνησαμεν υμιν και ουκ εκοψασθε'),
(333, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 18, 'NT', 'ηλθεν γαρ ιωαννης μητε εσθιων μητε πινων και λεγουσιν δαιμονιον εχει'),
(334, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 19, 'NT', 'ηλθεν ο υιος του ανθρωπου εσθιων και πινων και λεγουσιν ιδου ανθρωπος φαγος και οινοποτης τελωνων φιλος και αμαρτωλων και εδικαιωθη η σοφια απο των τεκνων αυτης'),
(335, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 20, 'NT', 'τοτε ηρξατο ονειδιζειν τας πολεις εν αις εγενοντο αι πλεισται δυναμεις αυτου οτι ου μετενοησαν'),
(336, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 21, 'NT', 'ουαι σοι χοραζιν ουαι σοι βηθσαιδαν οτι ει εν τυρω και σιδωνι εγενοντο αι δυναμεις αι γενομεναι εν υμιν παλαι αν εν σακκω και σποδω μετενοησαν'),
(337, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 22, 'NT', 'πλην λεγω υμιν τυρω και σιδωνι ανεκτοτερον εσται εν ημερα κρισεως η υμιν'),
(338, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 23, 'NT', 'και συ καπερναουμ η εως του ουρανου υψωθεισα εως αδου καταβιβασθηση οτι ει εν σοδομοις εγενοντο αι δυναμεις αι γενομεναι εν σοι εμειναν αν μεχρι της σημερον'),
(339, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 24, 'NT', 'πλην λεγω υμιν οτι γη σοδομων ανεκτοτερον εσται εν ημερα κρισεως η σοι'),
(340, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 25, 'NT', 'εν εκεινω τω καιρω αποκριθεις ο ιησους ειπεν εξομολογουμαι σοι πατερ κυριε του ουρανου και της γης οτι απεκρυψας ταυτα απο σοφων και συνετων και απεκαλυψας αυτα νηπιοις'),
(341, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 26, 'NT', 'ναι ο πατηρ οτι ουτως εγενετο ευδοκια εμπροσθεν σου'),
(342, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 27, 'NT', 'παντα μοι παρεδοθη υπο του πατρος μου και ουδεις επιγινωσκει τον υιον ει μη ο πατηρ ουδε τον πατερα τις επιγινωσκει ει μη ο υιος και ω εαν βουληται ο υιος αποκαλυψαι'),
(343, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 28, 'NT', 'δευτε προς με παντες οι κοπιωντες και πεφορτισμενοι καγω αναπαυσω υμας'),
(344, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 29, 'NT', 'αρατε τον ζυγον μου εφ υμας και μαθετε απ εμου οτι πραος ειμι και ταπεινος τη καρδια και ευρησετε αναπαυσιν ταις ψυχαις υμων'),
(345, 40, 'TR1550', 'TR1550', 'el', 'MAT', 11, 30, 'NT', 'ο γαρ ζυγος μου χρηστος και το φορτιον μου ελαφρον εστιν'),
(346, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 1, 'NT', 'εν εκεινω τω καιρω επορευθη ο ιησους τοις σαββασιν δια των σποριμων οι δε μαθηται αυτου επεινασαν και ηρξαντο τιλλειν σταχυας και εσθιειν'),
(347, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 2, 'NT', 'οι δε φαρισαιοι ιδοντες ειπον αυτω ιδου οι μαθηται σου ποιουσιν ο ουκ εξεστιν ποιειν εν σαββατω'),
(348, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 3, 'NT', 'ο δε ειπεν αυτοις ουκ ανεγνωτε τι εποιησεν δαβιδ οτε επεινασεν αυτος και οι μετ αυτου'),
(349, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 4, 'NT', 'πως εισηλθεν εις τον οικον του θεου και τους αρτους της προθεσεως εφαγεν ους ουκ εξον ην αυτω φαγειν ουδε τοις μετ αυτου ει μη τοις ιερευσιν μονοις'),
(350, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 5, 'NT', 'η ουκ ανεγνωτε εν τω νομω οτι τοις σαββασιν οι ιερεις εν τω ιερω το σαββατον βεβηλουσιν και αναιτιοι εισιν'),
(351, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 6, 'NT', 'λεγω δε υμιν οτι του ιερου μειζων εστιν ωδε'),
(352, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 7, 'NT', 'ει δε εγνωκειτε τι εστιν ελεον θελω και ου θυσιαν ουκ αν κατεδικασατε τους αναιτιους'),
(353, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 8, 'NT', 'κυριος γαρ εστιν και του σαββατου ο υιος του ανθρωπου'),
(354, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 9, 'NT', 'και μεταβας εκειθεν ηλθεν εις την συναγωγην αυτων'),
(355, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 10, 'NT', 'και ιδου ανθρωπος ην την χειρα εχων ξηραν και επηρωτησαν αυτον λεγοντες ει εξεστιν τοις σαββασιν θεραπευειν ινα κατηγορησωσιν αυτου'),
(356, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 11, 'NT', 'ο δε ειπεν αυτοις τις εσται εξ υμων ανθρωπος ος εξει προβατον εν και εαν εμπεση τουτο τοις σαββασιν εις βοθυνον ουχι κρατησει αυτο και εγερει'),
(357, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 12, 'NT', 'ποσω ουν διαφερει ανθρωπος προβατου ωστε εξεστιν τοις σαββασιν καλως ποιειν'),
(358, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 13, 'NT', 'τοτε λεγει τω ανθρωπω εκτεινον την χειρα σου και εξετεινεν και αποκατεσταθη υγιης ως η αλλη'),
(359, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 14, 'NT', 'οι δε φαρισαιοι συμβουλιον ελαβον κατ αυτου εξελθοντες οπως αυτον απολεσωσιν'),
(360, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 15, 'NT', 'ο δε ιησους γνους ανεχωρησεν εκειθεν και ηκολουθησαν αυτω οχλοι πολλοι και εθεραπευσεν αυτους παντας'),
(361, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 16, 'NT', 'και επετιμησεν αυτοις ινα μη φανερον αυτον ποιησωσιν'),
(362, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 17, 'NT', 'οπως πληρωθη το ρηθεν δια ησαιου του προφητου λεγοντος'),
(363, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 18, 'NT', 'ιδου ο παις μου ον ηρετισα ο αγαπητος μου εις ον ευδοκησεν η ψυχη μου θησω το πνευμα μου επ αυτον και κρισιν τοις εθνεσιν απαγγελει'),
(364, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 19, 'NT', 'ουκ ερισει ουδε κραυγασει ουδε ακουσει τις εν ταις πλατειαις την φωνην αυτου'),
(365, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 20, 'NT', 'καλαμον συντετριμμενον ου κατεαξει και λινον τυφομενον ου σβεσει εως αν εκβαλη εις νικος την κρισιν'),
(366, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 21, 'NT', 'και εν τω ονοματι αυτου εθνη ελπιουσιν'),
(367, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 22, 'NT', 'τοτε προσηνεχθη αυτω δαιμονιζομενος τυφλος και κωφος και εθεραπευσεν αυτον ωστε τον τυφλον και κωφον και λαλειν και βλεπειν'),
(368, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 23, 'NT', 'και εξισταντο παντες οι οχλοι και ελεγον μητι ουτος εστιν ο υιος δαβιδ'),
(369, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 24, 'NT', 'οι δε φαρισαιοι ακουσαντες ειπον ουτος ουκ εκβαλλει τα δαιμονια ει μη εν τω βεελζεβουλ αρχοντι των δαιμονιων'),
(370, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 25, 'NT', 'ειδως δε ο ιησους τας ενθυμησεις αυτων ειπεν αυτοις πασα βασιλεια μερισθεισα καθ εαυτης ερημουται και πασα πολις η οικια μερισθεισα καθ εαυτης ου σταθησεται'),
(371, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 26, 'NT', 'και ει ο σατανας τον σαταναν εκβαλλει εφ εαυτον εμερισθη πως ουν σταθησεται η βασιλεια αυτου'),
(372, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 27, 'NT', 'και ει εγω εν βεελζεβουλ εκβαλλω τα δαιμονια οι υιοι υμων εν τινι εκβαλλουσιν δια τουτο αυτοι υμων εσονται κριται'),
(373, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 28, 'NT', 'ει δε εγω εν πνευματι θεου εκβαλλω τα δαιμονια αρα εφθασεν εφ υμας η βασιλεια του θεου'),
(374, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 29, 'NT', 'η πως δυναται τις εισελθειν εις την οικιαν του ισχυρου και τα σκευη αυτου διαρπασαι εαν μη πρωτον δηση τον ισχυρον και τοτε την οικιαν αυτου διαρπασει'),
(375, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 30, 'NT', 'ο μη ων μετ εμου κατ εμου εστιν και ο μη συναγων μετ εμου σκορπιζει'),
(376, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 31, 'NT', 'δια τουτο λεγω υμιν πασα αμαρτια και βλασφημια αφεθησεται τοις ανθρωποις η δε του πνευματος βλασφημια ουκ αφεθησεται τοις ανθρωποις'),
(377, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 32, 'NT', 'και ος αν ειπη λογον κατα του υιου του ανθρωπου αφεθησεται αυτω ος δ αν ειπη κατα του πνευματος του αγιου ουκ αφεθησεται αυτω ουτε εν τουτω τω αιωνι ουτε εν τω μελλοντι'),
(378, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 33, 'NT', 'η ποιησατε το δενδρον καλον και τον καρπον αυτου καλον η ποιησατε το δενδρον σαπρον και τον καρπον αυτου σαπρον εκ γαρ του καρπου το δενδρον γινωσκεται'),
(379, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 34, 'NT', 'γεννηματα εχιδνων πως δυνασθε αγαθα λαλειν πονηροι οντες εκ γαρ του περισσευματος της καρδιας το στομα λαλει'),
(380, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 35, 'NT', 'ο αγαθος ανθρωπος εκ του αγαθου θησαυρου της καρδιας εκβαλλει τα αγαθα και ο πονηρος ανθρωπος εκ του πονηρου θησαυρου εκβαλλει πονηρα'),
(381, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 36, 'NT', 'λεγω δε υμιν οτι παν ρημα αργον ο εαν λαλησωσιν οι ανθρωποι αποδωσουσιν περι αυτου λογον εν ημερα κρισεως'),
(382, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 37, 'NT', 'εκ γαρ των λογων σου δικαιωθηση και εκ των λογων σου καταδικασθηση'),
(383, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 38, 'NT', 'τοτε απεκριθησαν τινες των γραμματεων και φαρισαιων λεγοντες διδασκαλε θελομεν απο σου σημειον ιδειν'),
(384, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 39, 'NT', 'ο δε αποκριθεις ειπεν αυτοις γενεα πονηρα και μοιχαλις σημειον επιζητει και σημειον ου δοθησεται αυτη ει μη το σημειον ιωνα του προφητου'),
(385, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 40, 'NT', 'ωσπερ γαρ ην ιωνας εν τη κοιλια του κητους τρεις ημερας και τρεις νυκτας ουτως εσται ο υιος του ανθρωπου εν τη καρδια της γης τρεις ημερας και τρεις νυκτας'),
(386, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 41, 'NT', 'ανδρες νινευιται αναστησονται εν τη κρισει μετα της γενεας ταυτης και κατακρινουσιν αυτην οτι μετενοησαν εις το κηρυγμα ιωνα και ιδου πλειον ιωνα ωδε'),
(387, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 42, 'NT', 'βασιλισσα νοτου εγερθησεται εν τη κρισει μετα της γενεας ταυτης και κατακρινει αυτην οτι ηλθεν εκ των περατων της γης ακουσαι την σοφιαν σολομωντος και ιδου πλειον σολομωντος ωδε'),
(388, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 43, 'NT', 'οταν δε το ακαθαρτον πνευμα εξελθη απο του ανθρωπου διερχεται δι ανυδρων τοπων ζητουν αναπαυσιν και ουχ ευρισκει'),
(389, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 44, 'NT', 'τοτε λεγει επιστρεψω εις τον οικον μου οθεν εξηλθον και ελθον ευρισκει σχολαζοντα σεσαρωμενον και κεκοσμημενον'),
(390, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 45, 'NT', 'τοτε πορευεται και παραλαμβανει μεθ εαυτου επτα ετερα πνευματα πονηροτερα εαυτου και εισελθοντα κατοικει εκει και γινεται τα εσχατα του ανθρωπου εκεινου χειρονα των πρωτων ουτως εσται και τη γενεα ταυτη τη πονηρα'),
(391, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 46, 'NT', 'ετι δε αυτου λαλουντος τοις οχλοις ιδου η μητηρ και οι αδελφοι αυτου ειστηκεισαν εξω ζητουντες αυτω λαλησαι'),
(392, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 47, 'NT', 'ειπεν δε τις αυτω ιδου η μητηρ σου και οι αδελφοι σου εξω εστηκασιν ζητουντες σοι λαλησαι'),
(393, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 48, 'NT', 'ο δε αποκριθεις ειπεν τω ειποντι αυτω τις εστιν η μητηρ μου και τινες εισιν οι αδελφοι μου'),
(394, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 49, 'NT', 'και εκτεινας την χειρα αυτου επι τους μαθητας αυτου ειπεν ιδου η μητηρ μου και οι αδελφοι μου'),
(395, 40, 'TR1550', 'TR1550', 'el', 'MAT', 12, 50, 'NT', 'οστις γαρ αν ποιηση το θελημα του πατρος μου του εν ουρανοις αυτος μου αδελφος και αδελφη και μητηρ εστιν'),
(396, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 1, 'NT', 'εν δε τη ημερα εκεινη εξελθων ο ιησους απο της οικιας εκαθητο παρα την θαλασσαν'),
(397, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 2, 'NT', 'και συνηχθησαν προς αυτον οχλοι πολλοι ωστε αυτον εις το πλοιον εμβαντα καθησθαι και πας ο οχλος επι τον αιγιαλον ειστηκει'),
(398, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 3, 'NT', 'και ελαλησεν αυτοις πολλα εν παραβολαις λεγων ιδου εξηλθεν ο σπειρων του σπειρειν'),
(399, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 4, 'NT', 'και εν τω σπειρειν αυτον α μεν επεσεν παρα την οδον και ηλθεν τα πετεινα και κατεφαγεν αυτα'),
(400, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 5, 'NT', 'αλλα δε επεσεν επι τα πετρωδη οπου ουκ ειχεν γην πολλην και ευθεως εξανετειλεν δια το μη εχειν βαθος γης'),
(401, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 6, 'NT', 'ηλιου δε ανατειλαντος εκαυματισθη και δια το μη εχειν ριζαν εξηρανθη'),
(402, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 7, 'NT', 'αλλα δε επεσεν επι τας ακανθας και ανεβησαν αι ακανθαι και απεπνιξαν αυτα'),
(403, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 8, 'NT', 'αλλα δε επεσεν επι την γην την καλην και εδιδου καρπον ο μεν εκατον ο δε εξηκοντα ο δε τριακοντα'),
(404, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 9, 'NT', 'ο εχων ωτα ακουειν ακουετω'),
(405, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 10, 'NT', 'και προσελθοντες οι μαθηται ειπον αυτω δια τι εν παραβολαις λαλεις αυτοις'),
(406, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 11, 'NT', 'ο δε αποκριθεις ειπεν αυτοις οτι υμιν δεδοται γνωναι τα μυστηρια της βασιλειας των ουρανων εκεινοις δε ου δεδοται'),
(407, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 12, 'NT', 'οστις γαρ εχει δοθησεται αυτω και περισσευθησεται οστις δε ουκ εχει και ο εχει αρθησεται απ αυτου'),
(408, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 13, 'NT', 'δια τουτο εν παραβολαις αυτοις λαλω οτι βλεποντες ου βλεπουσιν και ακουοντες ουκ ακουουσιν ουδε συνιουσιν'),
(409, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 14, 'NT', 'και αναπληρουται επ αυτοις η προφητεια ησαιου η λεγουσα ακοη ακουσετε και ου μη συνητε και βλεποντες βλεψετε και ου μη ιδητε'),
(410, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 15, 'NT', 'επαχυνθη γαρ η καρδια του λαου τουτου και τοις ωσιν βαρεως ηκουσαν και τους οφθαλμους αυτων εκαμμυσαν μηποτε ιδωσιν τοις οφθαλμοις και τοις ωσιν ακουσωσιν και τη καρδια συνωσιν και επιστρεψωσιν και ιασωμαι αυτους'),
(411, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 16, 'NT', 'υμων δε μακαριοι οι οφθαλμοι οτι βλεπουσιν και τα ωτα υμων οτι ακουει'),
(412, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 17, 'NT', 'αμην γαρ λεγω υμιν οτι πολλοι προφηται και δικαιοι επεθυμησαν ιδειν α βλεπετε και ουκ ειδον και ακουσαι α ακουετε και ουκ ηκουσαν'),
(413, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 18, 'NT', 'υμεις ουν ακουσατε την παραβολην του σπειροντος'),
(414, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 19, 'NT', 'παντος ακουοντος τον λογον της βασιλειας και μη συνιεντος ερχεται ο πονηρος και αρπαζει το εσπαρμενον εν τη καρδια αυτου ουτος εστιν ο παρα την οδον σπαρεις'),
(415, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 20, 'NT', 'ο δε επι τα πετρωδη σπαρεις ουτος εστιν ο τον λογον ακουων και ευθυς μετα χαρας λαμβανων αυτον'),
(416, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 21, 'NT', 'ουκ εχει δε ριζαν εν εαυτω αλλα προσκαιρος εστιν γενομενης δε θλιψεως η διωγμου δια τον λογον ευθυς σκανδαλιζεται'),
(417, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 22, 'NT', 'ο δε εις τας ακανθας σπαρεις ουτος εστιν ο τον λογον ακουων και η μεριμνα του αιωνος τουτου και η απατη του πλουτου συμπνιγει τον λογον και ακαρπος γινεται'),
(418, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 23, 'NT', 'ο δε επι την γην την καλην σπαρεις ουτος εστιν ο τον λογον ακουων και συνιων ος δη καρποφορει και ποιει ο μεν εκατον ο δε εξηκοντα ο δε τριακοντα'),
(419, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 24, 'NT', 'αλλην παραβολην παρεθηκεν αυτοις λεγων ωμοιωθη η βασιλεια των ουρανων ανθρωπω σπειροντι καλον σπερμα εν τω αγρω αυτου'),
(420, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 25, 'NT', 'εν δε τω καθευδειν τους ανθρωπους ηλθεν αυτου ο εχθρος και εσπειρεν ζιζανια ανα μεσον του σιτου και απηλθεν'),
(421, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 26, 'NT', 'οτε δε εβλαστησεν ο χορτος και καρπον εποιησεν τοτε εφανη και τα ζιζανια'),
(422, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 27, 'NT', 'προσελθοντες δε οι δουλοι του οικοδεσποτου ειπον αυτω κυριε ουχι καλον σπερμα εσπειρας εν τω σω αγρω ποθεν ουν εχει τα ζιζανια'),
(423, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 28, 'NT', 'ο δε εφη αυτοις εχθρος ανθρωπος τουτο εποιησεν οι δε δουλοι ειπον αυτω θελεις ουν απελθοντες συλλεξωμεν αυτα'),
(424, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 29, 'NT', 'ο δε εφη ου μηποτε συλλεγοντες τα ζιζανια εκριζωσητε αμα αυτοις τον σιτον'),
(425, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 30, 'NT', 'αφετε συναυξανεσθαι αμφοτερα μεχρι του θερισμου και εν τω καιρω του θερισμου ερω τοις θερισταις συλλεξατε πρωτον τα ζιζανια και δησατε αυτα εις δεσμας προς το κατακαυσαι αυτα τον δε σιτον συναγαγετε εις την αποθηκην μου'),
(426, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 31, 'NT', 'αλλην παραβολην παρεθηκεν αυτοις λεγων ομοια εστιν η βασιλεια των ουρανων κοκκω σιναπεως ον λαβων ανθρωπος εσπειρεν εν τω αγρω αυτου'),
(427, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 32, 'NT', 'ο μικροτερον μεν εστιν παντων των σπερματων οταν δε αυξηθη μειζον των λαχανων εστιν και γινεται δενδρον ωστε ελθειν τα πετεινα του ουρανου και κατασκηνουν εν τοις κλαδοις αυτου'),
(428, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 33, 'NT', 'αλλην παραβολην ελαλησεν αυτοις ομοια εστιν η βασιλεια των ουρανων ζυμη ην λαβουσα γυνη ενεκρυψεν εις αλευρου σατα τρια εως ου εζυμωθη ολον'),
(429, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 34, 'NT', 'ταυτα παντα ελαλησεν ο ιησους εν παραβολαις τοις οχλοις και χωρις παραβολης ουκ ελαλει αυτοις'),
(430, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 35, 'NT', 'οπως πληρωθη το ρηθεν δια του προφητου λεγοντος ανοιξω εν παραβολαις το στομα μου ερευξομαι κεκρυμμενα απο καταβολης κοσμου'),
(431, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 36, 'NT', 'τοτε αφεις τους οχλους ηλθεν εις την οικιαν ο ιησους και προσηλθον αυτω οι μαθηται αυτου λεγοντες φρασον ημιν την παραβολην των ζιζανιων του αγρου'),
(432, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 37, 'NT', 'ο δε αποκριθεις ειπεν αυτοις ο σπειρων το καλον σπερμα εστιν ο υιος του ανθρωπου'),
(433, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 38, 'NT', 'ο δε αγρος εστιν ο κοσμος το δε καλον σπερμα ουτοι εισιν οι υιοι της βασιλειας τα δε ζιζανια εισιν οι υιοι του πονηρου'),
(434, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 39, 'NT', 'ο δε εχθρος ο σπειρας αυτα εστιν ο διαβολος ο δε θερισμος συντελεια του αιωνος εστιν οι δε θερισται αγγελοι εισιν'),
(435, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 40, 'NT', 'ωσπερ ουν συλλεγεται τα ζιζανια και πυρι κατακαιεται ουτως εσται εν τη συντελεια του αιωνος τουτου'),
(436, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 41, 'NT', 'αποστελει ο υιος του ανθρωπου τους αγγελους αυτου και συλλεξουσιν εκ της βασιλειας αυτου παντα τα σκανδαλα και τους ποιουντας την ανομιαν'),
(437, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 42, 'NT', 'και βαλουσιν αυτους εις την καμινον του πυρος εκει εσται ο κλαυθμος και ο βρυγμος των οδοντων'),
(438, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 43, 'NT', 'τοτε οι δικαιοι εκλαμψουσιν ως ο ηλιος εν τη βασιλεια του πατρος αυτων ο εχων ωτα ακουειν ακουετω'),
(439, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 44, 'NT', 'παλιν ομοια εστιν η βασιλεια των ουρανων θησαυρω κεκρυμμενω εν τω αγρω ον ευρων ανθρωπος εκρυψεν και απο της χαρας αυτου υπαγει και παντα οσα εχει πωλει και αγοραζει τον αγρον εκεινον'),
(440, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 45, 'NT', 'παλιν ομοια εστιν η βασιλεια των ουρανων ανθρωπω εμπορω ζητουντι καλους μαργαριτας'),
(441, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 46, 'NT', 'ος ευρων ενα πολυτιμον μαργαριτην απελθων πεπρακεν παντα οσα ειχεν και ηγορασεν αυτον'),
(442, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 47, 'NT', 'παλιν ομοια εστιν η βασιλεια των ουρανων σαγηνη βληθειση εις την θαλασσαν και εκ παντος γενους συναγαγουση'),
(443, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 48, 'NT', 'ην οτε επληρωθη αναβιβασαντες επι τον αιγιαλον και καθισαντες συνελεξαν τα καλα εις αγγεια τα δε σαπρα εξω εβαλον'),
(444, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 49, 'NT', 'ουτως εσται εν τη συντελεια του αιωνος εξελευσονται οι αγγελοι και αφοριουσιν τους πονηρους εκ μεσου των δικαιων'),
(445, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 50, 'NT', 'και βαλουσιν αυτους εις την καμινον του πυρος εκει εσται ο κλαυθμος και ο βρυγμος των οδοντων'),
(446, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 51, 'NT', 'λεγει αυτοις ο ιησους συνηκατε ταυτα παντα λεγουσιν αυτω ναι κυριε'),
(447, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 52, 'NT', 'ο δε ειπεν αυτοις δια τουτο πας γραμματευς μαθητευθεις εις την βασιλειαν των ουρανων ομοιος εστιν ανθρωπω οικοδεσποτη οστις εκβαλλει εκ του θησαυρου αυτου καινα και παλαια'),
(448, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 53, 'NT', 'και εγενετο οτε ετελεσεν ο ιησους τας παραβολας ταυτας μετηρεν εκειθεν'),
(449, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 54, 'NT', 'και ελθων εις την πατριδα αυτου εδιδασκεν αυτους εν τη συναγωγη αυτων ωστε εκπληττεσθαι αυτους και λεγειν ποθεν τουτω η σοφια αυτη και αι δυναμεις'),
(450, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 55, 'NT', 'ουχ ουτος εστιν ο του τεκτονος υιος ουχι η μητηρ αυτου λεγεται μαριαμ και οι αδελφοι αυτου ιακωβος και ιωσης και σιμων και ιουδας'),
(451, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 56, 'NT', 'και αι αδελφαι αυτου ουχι πασαι προς ημας εισιν ποθεν ουν τουτω ταυτα παντα'),
(452, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 57, 'NT', 'και εσκανδαλιζοντο εν αυτω ο δε ιησους ειπεν αυτοις ουκ εστιν προφητης ατιμος ει μη εν τη πατριδι αυτου και εν τη οικια αυτου'),
(453, 40, 'TR1550', 'TR1550', 'el', 'MAT', 13, 58, 'NT', 'και ουκ εποιησεν εκει δυναμεις πολλας δια την απιστιαν αυτων'),
(454, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 1, 'NT', 'εν εκεινω τω καιρω ηκουσεν ηρωδης ο τετραρχης την ακοην ιησου'),
(455, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 2, 'NT', 'και ειπεν τοις παισιν αυτου ουτος εστιν ιωαννης ο βαπτιστης αυτος ηγερθη απο των νεκρων και δια τουτο αι δυναμεις ενεργουσιν εν αυτω'),
(456, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 3, 'NT', 'ο γαρ ηρωδης κρατησας τον ιωαννην εδησεν αυτον και εθετο εν φυλακη δια ηρωδιαδα την γυναικα φιλιππου του αδελφου αυτου'),
(457, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 4, 'NT', 'ελεγεν γαρ αυτω ο ιωαννης ουκ εξεστιν σοι εχειν αυτην'),
(458, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 5, 'NT', 'και θελων αυτον αποκτειναι εφοβηθη τον οχλον οτι ως προφητην αυτον ειχον'),
(459, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 6, 'NT', 'γενεσιων δε αγομενων του ηρωδου ωρχησατο η θυγατηρ της ηρωδιαδος εν τω μεσω και ηρεσεν τω ηρωδη'),
(460, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 7, 'NT', 'οθεν μεθ ορκου ωμολογησεν αυτη δουναι ο εαν αιτησηται'),
(461, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 8, 'NT', 'η δε προβιβασθεισα υπο της μητρος αυτης δος μοι φησιν ωδε επι πινακι την κεφαλην ιωαννου του βαπτιστου'),
(462, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 9, 'NT', 'και ελυπηθη ο βασιλευς δια δε τους ορκους και τους συνανακειμενους εκελευσεν δοθηναι'),
(463, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 10, 'NT', 'και πεμψας απεκεφαλισεν τον ιωαννην εν τη φυλακη'),
(464, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 11, 'NT', 'και ηνεχθη η κεφαλη αυτου επι πινακι και εδοθη τω κορασιω και ηνεγκεν τη μητρι αυτης'),
(465, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 12, 'NT', 'και προσελθοντες οι μαθηται αυτου ηραν το σωμα και εθαψαν αυτο και ελθοντες απηγγειλαν τω ιησου'),
(466, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 13, 'NT', 'και ακουσας ο ιησους ανεχωρησεν εκειθεν εν πλοιω εις ερημον τοπον κατ ιδιαν και ακουσαντες οι οχλοι ηκολουθησαν αυτω πεζη απο των πολεων'),
(467, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 14, 'NT', 'και εξελθων ο ιησους ειδεν πολυν οχλον και εσπλαγχνισθη επ αυτους και εθεραπευσεν τους αρρωστους αυτων'),
(468, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 15, 'NT', 'οψιας δε γενομενης προσηλθον αυτω οι μαθηται αυτου λεγοντες ερημος εστιν ο τοπος και η ωρα ηδη παρηλθεν απολυσον τους οχλους ινα απελθοντες εις τας κωμας αγορασωσιν εαυτοις βρωματα'),
(469, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 16, 'NT', 'ο δε ιησους ειπεν αυτοις ου χρειαν εχουσιν απελθειν δοτε αυτοις υμεις φαγειν'),
(470, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 17, 'NT', 'οι δε λεγουσιν αυτω ουκ εχομεν ωδε ει μη πεντε αρτους και δυο ιχθυας'),
(471, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 18, 'NT', 'ο δε ειπεν φερετε μοι αυτους ωδε'),
(472, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 19, 'NT', 'και κελευσας τους οχλους ανακλιθηναι επι τους χορτους και λαβων τους πεντε αρτους και τους δυο ιχθυας αναβλεψας εις τον ουρανον ευλογησεν και κλασας εδωκεν τοις μαθηταις τους αρτους οι δε μαθηται τοις οχλοις'),
(473, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 20, 'NT', 'και εφαγον παντες και εχορτασθησαν και ηραν το περισσευον των κλασματων δωδεκα κοφινους πληρεις'),
(474, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 21, 'NT', 'οι δε εσθιοντες ησαν ανδρες ωσει πεντακισχιλιοι χωρις γυναικων και παιδιων'),
(475, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 22, 'NT', 'και ευθεως ηναγκασεν ο ιησους τους μαθητας αυτου εμβηναι εις το πλοιον και προαγειν αυτον εις το περαν εως ου απολυση τους οχλους'),
(476, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 23, 'NT', 'και απολυσας τους οχλους ανεβη εις το ορος κατ ιδιαν προσευξασθαι οψιας δε γενομενης μονος ην εκει'),
(477, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 24, 'NT', 'το δε πλοιον ηδη μεσον της θαλασσης ην βασανιζομενον υπο των κυματων ην γαρ εναντιος ο ανεμος'),
(478, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 25, 'NT', 'τεταρτη δε φυλακη της νυκτος απηλθεν προς αυτους ο ιησους περιπατων επι της θαλασσης'),
(479, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 26, 'NT', 'και ιδοντες αυτον οι μαθηται επι την θαλασσαν περιπατουντα εταραχθησαν λεγοντες οτι φαντασμα εστιν και απο του φοβου εκραξαν'),
(480, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 27, 'NT', 'ευθεως δε ελαλησεν αυτοις ο ιησους λεγων θαρσειτε εγω ειμι μη φοβεισθε'),
(481, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 28, 'NT', 'αποκριθεις δε αυτω ο πετρος ειπεν κυριε ει συ ει κελευσον με προς σε ελθειν επι τα υδατα'),
(482, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 29, 'NT', 'ο δε ειπεν ελθε και καταβας απο του πλοιου ο πετρος περιεπατησεν επι τα υδατα ελθειν προς τον ιησουν'),
(483, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 30, 'NT', 'βλεπων δε τον ανεμον ισχυρον εφοβηθη και αρξαμενος καταποντιζεσθαι εκραξεν λεγων κυριε σωσον με'),
(484, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 31, 'NT', 'ευθεως δε ο ιησους εκτεινας την χειρα επελαβετο αυτου και λεγει αυτω ολιγοπιστε εις τι εδιστασας'),
(485, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 32, 'NT', 'και εμβαντων αυτων εις το πλοιον εκοπασεν ο ανεμος'),
(486, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 33, 'NT', 'οι δε εν τω πλοιω ελθοντες προσεκυνησαν αυτω λεγοντες αληθως θεου υιος ει'),
(487, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 34, 'NT', 'και διαπερασαντες ηλθον εις την γην γεννησαρετ'),
(488, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 35, 'NT', 'και επιγνοντες αυτον οι ανδρες του τοπου εκεινου απεστειλαν εις ολην την περιχωρον εκεινην και προσηνεγκαν αυτω παντας τους κακως εχοντας'),
(489, 40, 'TR1550', 'TR1550', 'el', 'MAT', 14, 36, 'NT', 'και παρεκαλουν αυτον ινα μονον αψωνται του κρασπεδου του ιματιου αυτου και οσοι ηψαντο διεσωθησαν'),
(490, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 1, 'NT', 'τοτε προσερχονται τω ιησου οι απο ιεροσολυμων γραμματεις και φαρισαιοι λεγοντες'),
(491, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 2, 'NT', 'δια τι οι μαθηται σου παραβαινουσιν την παραδοσιν των πρεσβυτερων ου γαρ νιπτονται τας χειρας αυτων οταν αρτον εσθιωσιν'),
(492, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 3, 'NT', 'ο δε αποκριθεις ειπεν αυτοις δια τι και υμεις παραβαινετε την εντολην του θεου δια την παραδοσιν υμων'),
(493, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 4, 'NT', 'ο γαρ θεος ενετειλατο λεγων τιμα τον πατερα σου και την μητερα και ο κακολογων πατερα η μητερα θανατω τελευτατω'),
(494, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 5, 'NT', 'υμεις δε λεγετε ος αν ειπη τω πατρι η τη μητρι δωρον ο εαν εξ εμου ωφεληθης και ου μη τιμηση τον πατερα αυτου η την μητερα αυτου'),
(495, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 6, 'NT', 'και ηκυρωσατε την εντολην του θεου δια την παραδοσιν υμων'),
(496, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 7, 'NT', 'υποκριται καλως προεφητευσεν περι υμων ησαιας λεγων'),
(497, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 8, 'NT', 'εγγιζει μοι ο λαος ουτος τω στοματι αυτων και τοις χειλεσιν με τιμα η δε καρδια αυτων πορρω απεχει απ εμου'),
(498, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 9, 'NT', 'ματην δε σεβονται με διδασκοντες διδασκαλιας ενταλματα ανθρωπων'),
(499, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 10, 'NT', 'και προσκαλεσαμενος τον οχλον ειπεν αυτοις ακουετε και συνιετε'),
(500, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 11, 'NT', 'ου το εισερχομενον εις το στομα κοινοι τον ανθρωπον αλλα το εκπορευομενον εκ του στοματος τουτο κοινοι τον ανθρωπον'),
(501, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 12, 'NT', 'τοτε προσελθοντες οι μαθηται αυτου ειπον αυτω οιδας οτι οι φαρισαιοι ακουσαντες τον λογον εσκανδαλισθησαν'),
(502, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 13, 'NT', 'ο δε αποκριθεις ειπεν πασα φυτεια ην ουκ εφυτευσεν ο πατηρ μου ο ουρανιος εκριζωθησεται'),
(503, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 14, 'NT', 'αφετε αυτους οδηγοι εισιν τυφλοι τυφλων τυφλος δε τυφλον εαν οδηγη αμφοτεροι εις βοθυνον πεσουνται'),
(504, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 15, 'NT', 'αποκριθεις δε ο πετρος ειπεν αυτω φρασον ημιν την παραβολην ταυτην'),
(505, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 16, 'NT', 'ο δε ιησους ειπεν ακμην και υμεις ασυνετοι εστε'),
(506, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 17, 'NT', 'ουπω νοειτε οτι παν το εισπορευομενον εις το στομα εις την κοιλιαν χωρει και εις αφεδρωνα εκβαλλεται'),
(507, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 18, 'NT', 'τα δε εκπορευομενα εκ του στοματος εκ της καρδιας εξερχεται κακεινα κοινοι τον ανθρωπον'),
(508, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 19, 'NT', 'εκ γαρ της καρδιας εξερχονται διαλογισμοι πονηροι φονοι μοιχειαι πορνειαι κλοπαι ψευδομαρτυριαι βλασφημιαι'),
(509, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 20, 'NT', 'ταυτα εστιν τα κοινουντα τον ανθρωπον το δε ανιπτοις χερσιν φαγειν ου κοινοι τον ανθρωπον'),
(510, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 21, 'NT', 'και εξελθων εκειθεν ο ιησους ανεχωρησεν εις τα μερη τυρου και σιδωνος'),
(511, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 22, 'NT', 'και ιδου γυνη χαναναια απο των οριων εκεινων εξελθουσα εκραυγασεν αυτω λεγουσα ελεησον με κυριε υιε δαβιδ η θυγατηρ μου κακως δαιμονιζεται'),
(512, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 23, 'NT', 'ο δε ουκ απεκριθη αυτη λογον και προσελθοντες οι μαθηται αυτου ηρωτων αυτον λεγοντες απολυσον αυτην οτι κραζει οπισθεν ημων'),
(513, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 24, 'NT', 'ο δε αποκριθεις ειπεν ουκ απεσταλην ει μη εις τα προβατα τα απολωλοτα οικου ισραηλ'),
(514, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 25, 'NT', 'η δε ελθουσα προσεκυνει αυτω λεγουσα κυριε βοηθει μοι'),
(515, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 26, 'NT', 'ο δε αποκριθεις ειπεν ουκ εστιν καλον λαβειν τον αρτον των τεκνων και βαλειν τοις κυναριοις'),
(516, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 27, 'NT', 'η δε ειπεν ναι κυριε και γαρ τα κυναρια εσθιει απο των ψιχιων των πιπτοντων απο της τραπεζης των κυριων αυτων'),
(517, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 28, 'NT', 'τοτε αποκριθεις ο ιησους ειπεν αυτη ω γυναι μεγαλη σου η πιστις γενηθητω σοι ως θελεις και ιαθη η θυγατηρ αυτης απο της ωρας εκεινης'),
(518, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 29, 'NT', 'και μεταβας εκειθεν ο ιησους ηλθεν παρα την θαλασσαν της γαλιλαιας και αναβας εις το ορος εκαθητο εκει'),
(519, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 30, 'NT', 'και προσηλθον αυτω οχλοι πολλοι εχοντες μεθ εαυτων χωλους τυφλους κωφους κυλλους και ετερους πολλους και ερριψαν αυτους παρα τους ποδας του ιησου και εθεραπευσεν αυτους'),
(520, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 31, 'NT', 'ωστε τους οχλους θαυμασαι βλεποντας κωφους λαλουντας κυλλους υγιεις χωλους περιπατουντας και τυφλους βλεποντας και εδοξασαν τον θεον ισραηλ'),
(521, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 32, 'NT', 'ο δε ιησους προσκαλεσαμενος τους μαθητας αυτου ειπεν σπλαγχνιζομαι επι τον οχλον οτι ηδη ημερας τρεις προσμενουσιν μοι και ουκ εχουσιν τι φαγωσιν και απολυσαι αυτους νηστεις ου θελω μηποτε εκλυθωσιν εν τη οδω'),
(522, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 33, 'NT', 'και λεγουσιν αυτω οι μαθηται αυτου ποθεν ημιν εν ερημια αρτοι τοσουτοι ωστε χορτασαι οχλον τοσουτον'),
(523, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 34, 'NT', 'και λεγει αυτοις ο ιησους ποσους αρτους εχετε οι δε ειπον επτα και ολιγα ιχθυδια'),
