(528, 40, 'TR1550', 'TR1550', 'el', 'MAT', 15, 39, 'NT', 'και απολυσας τους οχλους ενεβη εις το πλοιον και ηλθεν εις τα ορια μαγδαλα'),
(529, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 1, 'NT', 'και προσελθοντες οι φαρισαιοι και σαδδουκαιοι πειραζοντες επηρωτησαν αυτον σημειον εκ του ουρανου επιδειξαι αυτοις'),
(530, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 2, 'NT', 'ο δε αποκριθεις ειπεν αυτοις οψιας γενομενης λεγετε ευδια πυρραζει γαρ ο ουρανος'),
(531, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 3, 'NT', 'και πρωι σημερον χειμων πυρραζει γαρ στυγναζων ο ουρανος υποκριται το μεν προσωπον του ουρανου γινωσκετε διακρινειν τα δε σημεια των καιρων ου δυνασθε'),
(532, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 4, 'NT', 'γενεα πονηρα και μοιχαλις σημειον επιζητει και σημειον ου δοθησεται αυτη ει μη το σημειον ιωνα του προφητου και καταλιπων αυτους απηλθεν'),
(533, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 5, 'NT', 'και ελθοντες οι μαθηται αυτου εις το περαν επελαθοντο αρτους λαβειν'),
(534, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 6, 'NT', 'ο δε ιησους ειπεν αυτοις ορατε και προσεχετε απο της ζυμης των φαρισαιων και σαδδουκαιων'),
