(539, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 11, 'NT', 'πως ου νοειτε οτι ου περι αρτου ειπον υμιν προσεχειν απο της ζυμης των φαρισαιων και σαδδουκαιων'),
(540, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 12, 'NT', 'τοτε συνηκαν οτι ουκ ειπεν προσεχειν απο της ζυμης του αρτου αλλ απο της διδαχης των φαρισαιων και σαδδουκαιων'),
(541, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 13, 'NT', 'ελθων δε ο ιησους εις τα μερη καισαρειας της φιλιππου ηρωτα τους μαθητας αυτου λεγων τινα με λεγουσιν οι ανθρωποι ειναι τον υιον του ανθρωπου'),
(542, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 14, 'NT', 'οι δε ειπον οι μεν ιωαννην τον βαπτιστην αλλοι δε ηλιαν ετεροι δε ιερεμιαν η ενα των προφητων'),
(543, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 15, 'NT', 'λεγει αυτοις υμεις δε τινα με λεγετε ειναι'),
(544, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 16, 'NT', 'αποκριθεις δε σιμων πετρος ειπεν συ ει ο χριστος ο υιος του θεου του ζωντος'),
(545, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 17, 'NT', 'και αποκριθεις ο ιησους ειπεν αυτω μακαριος ει σιμων βαρ ιωνα οτι σαρξ και αιμα ουκ απεκαλυψεν σοι αλλ ο πατηρ μου ο εν τοις ουρανοις'),
(546, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 18, 'NT', 'καγω δε σοι λεγω οτι συ ει πετρος και επι ταυτη τη πετρα οικοδομησω μου την εκκλησιαν και πυλαι αδου ου κατισχυσουσιν αυτης'),
(547, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 19, 'NT', 'και δωσω σοι τας κλεις της βασιλειας των ουρανων και ο εαν δησης επι της γης εσται δεδεμενον εν τοις ουρανοις και ο εαν λυσης επι της γης εσται λελυμενον εν τοις ουρανοις'),
(548, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 20, 'NT', 'τοτε διεστειλατο τοις μαθηταις αυτου ινα μηδενι ειπωσιν οτι αυτος εστιν ιησους ο χριστος'),
(549, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 21, 'NT', 'απο τοτε ηρξατο ο ιησους δεικνυειν τοις μαθηταις αυτου οτι δει αυτον απελθειν εις ιεροσολυμα και πολλα παθειν απο των πρεσβυτερων και αρχιερεων και γραμματεων και αποκτανθηναι και τη τριτη ημερα εγερθηναι'),
(550, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 22, 'NT', 'και προσλαβομενος αυτον ο πετρος ηρξατο επιτιμαν αυτω λεγων ιλεως σοι κυριε ου μη εσται σοι τουτο'),
(551, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 23, 'NT', 'ο δε στραφεις ειπεν τω πετρω υπαγε οπισω μου σατανα σκανδαλον μου ει οτι ου φρονεις τα του θεου αλλα τα των ανθρωπων'),
(552, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 24, 'NT', 'τοτε ο ιησους ειπεν τοις μαθηταις αυτου ει τις θελει οπισω μου ελθειν απαρνησασθω εαυτον και αρατω τον σταυρον αυτου και ακολουθειτω μοι'),
(553, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 25, 'NT', 'ος γαρ αν θελη την ψυχην αυτου σωσαι απολεσει αυτην ος δ αν απολεση την ψυχην αυτου ενεκεν εμου ευρησει αυτην'),
(554, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 26, 'NT', 'τι γαρ ωφελειται ανθρωπος εαν τον κοσμον ολον κερδηση την δε ψυχην αυτου ζημιωθη η τι δωσει ανθρωπος ανταλλαγμα της ψυχης αυτου'),
(555, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 27, 'NT', 'μελλει γαρ ο υιος του ανθρωπου ερχεσθαι εν τη δοξη του πατρος αυτου μετα των αγγελων αυτου και τοτε αποδωσει εκαστω κατα την πραξιν αυτου'),
(556, 40, 'TR1550', 'TR1550', 'el', 'MAT', 16, 28, 'NT', 'αμην λεγω υμιν εισιν τινες των ωδε εστηκοτων οιτινες ου μη γευσωνται θανατου εως αν ιδωσιν τον υιον του ανθρωπου ερχομενον εν τη βασιλεια αυτου'),
(557, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 1, 'NT', 'και μεθ ημερας εξ παραλαμβανει ο ιησους τον πετρον και ιακωβον και ιωαννην τον αδελφον αυτου και αναφερει αυτους εις ορος υψηλον κατ ιδιαν'),
(558, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 2, 'NT', 'και μετεμορφωθη εμπροσθεν αυτων και ελαμψεν το προσωπον αυτου ως ο ηλιος τα δε ιματια αυτου εγενετο λευκα ως το φως'),
(559, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 3, 'NT', 'και ιδου ωφθησαν αυτοις μωσης και ηλιας μετ αυτου συλλαλουντες'),
(560, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 4, 'NT', 'αποκριθεις δε ο πετρος ειπεν τω ιησου κυριε καλον εστιν ημας ωδε ειναι ει θελεις ποιησωμεν ωδε τρεις σκηνας σοι μιαν και μωση μιαν και μιαν ηλια'),
(561, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 5, 'NT', 'ετι αυτου λαλουντος ιδου νεφελη φωτεινη επεσκιασεν αυτους και ιδου φωνη εκ της νεφελης λεγουσα ουτος εστιν ο υιος μου ο αγαπητος εν ω ευδοκησα αυτου ακουετε'),
(562, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 6, 'NT', 'και ακουσαντες οι μαθηται επεσον επι προσωπον αυτων και εφοβηθησαν σφοδρα'),
(563, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 7, 'NT', 'και προσελθων ο ιησους ηψατο αυτων και ειπεν εγερθητε και μη φοβεισθε'),
(564, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 8, 'NT', 'επαραντες δε τους οφθαλμους αυτων ουδενα ειδον ει μη τον ιησουν μονον'),
(565, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 9, 'NT', 'και καταβαινοντων αυτων απο του ορους ενετειλατο αυτοις ο ιησους λεγων μηδενι ειπητε το οραμα εως ου ο υιος του ανθρωπου εκ νεκρων αναστη'),
(566, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 10, 'NT', 'και επηρωτησαν αυτον οι μαθηται αυτου λεγοντες τι ουν οι γραμματεις λεγουσιν οτι ηλιαν δει ελθειν πρωτον'),
(567, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 11, 'NT', 'ο δε ιησους αποκριθεις ειπεν αυτοις ηλιας μεν ερχεται πρωτον και αποκαταστησει παντα'),
(568, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 12, 'NT', 'λεγω δε υμιν οτι ηλιας ηδη ηλθεν και ουκ επεγνωσαν αυτον αλλ εποιησαν εν αυτω οσα ηθελησαν ουτως και ο υιος του ανθρωπου μελλει πασχειν υπ αυτων'),
