(570, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 14, 'NT', 'και ελθοντων αυτων προς τον οχλον προσηλθεν αυτω ανθρωπος γονυπετων αυτω'),
(571, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 15, 'NT', 'και λεγων κυριε ελεησον μου τον υιον οτι σεληνιαζεται και κακως πασχει πολλακις γαρ πιπτει εις το πυρ και πολλακις εις το υδωρ'),
(572, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 16, 'NT', 'και προσηνεγκα αυτον τοις μαθηταις σου και ουκ ηδυνηθησαν αυτον θεραπευσαι'),
(573, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 17, 'NT', 'αποκριθεις δε ο ιησους ειπεν ω γενεα απιστος και διεστραμμενη εως ποτε εσομαι μεθ υμων εως ποτε ανεξομαι υμων φερετε μοι αυτον ωδε'),
(574, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 18, 'NT', 'και επετιμησεν αυτω ο ιησους και εξηλθεν απ αυτου το δαιμονιον και εθεραπευθη ο παις απο της ωρας εκεινης'),
(575, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 19, 'NT', 'τοτε προσελθοντες οι μαθηται τω ιησου κατ ιδιαν ειπον δια τι ημεις ουκ ηδυνηθημεν εκβαλειν αυτο'),
(576, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 20, 'NT', 'ο δε ιησους ειπεν αυτοις δια την απιστιαν υμων αμην γαρ λεγω υμιν εαν εχητε πιστιν ως κοκκον σιναπεως ερειτε τω ορει τουτω μεταβηθι εντευθεν εκει και μεταβησεται και ουδεν αδυνατησει υμιν'),
(577, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 21, 'NT', 'τουτο δε το γενος ουκ εκπορευεται ει μη εν προσευχη και νηστεια'),
(578, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 22, 'NT', 'αναστρεφομενων δε αυτων εν τη γαλιλαια ειπεν αυτοις ο ιησους μελλει ο υιος του ανθρωπου παραδιδοσθαι εις χειρας ανθρωπων'),
(579, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 23, 'NT', 'και αποκτενουσιν αυτον και τη τριτη ημερα εγερθησεται και ελυπηθησαν σφοδρα'),
(580, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 24, 'NT', 'ελθοντων δε αυτων εις καπερναουμ προσηλθον οι τα διδραχμα λαμβανοντες τω πετρω και ειπον ο διδασκαλος υμων ου τελει τα διδραχμα'),
(581, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 25, 'NT', 'λεγει ναι και οτε εισηλθεν εις την οικιαν προεφθασεν αυτον ο ιησους λεγων τι σοι δοκει σιμων οι βασιλεις της γης απο τινων λαμβανουσιν τελη η κηνσον απο των υιων αυτων η απο των αλλοτριων'),
(582, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 26, 'NT', 'λεγει αυτω ο πετρος απο των αλλοτριων εφη αυτω ο ιησους αραγε ελευθεροι εισιν οι υιοι'),
(583, 40, 'TR1550', 'TR1550', 'el', 'MAT', 17, 27, 'NT', 'ινα δε μη σκανδαλισωμεν αυτους πορευθεις εις την θαλασσαν βαλε αγκιστρον και τον αναβαντα πρωτον ιχθυν αρον και ανοιξας το στομα αυτου ευρησεις στατηρα εκεινον λαβων δος αυτοις αντι εμου και σου'),
(584, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 1, 'NT', 'εν εκεινη τη ωρα προσηλθον οι μαθηται τω ιησου λεγοντες τις αρα μειζων εστιν εν τη βασιλεια των ουρανων'),
(585, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 2, 'NT', 'και προσκαλεσαμενος ο ιησους παιδιον εστησεν αυτο εν μεσω αυτων'),
(586, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 3, 'NT', 'και ειπεν αμην λεγω υμιν εαν μη στραφητε και γενησθε ως τα παιδια ου μη εισελθητε εις την βασιλειαν των ουρανων'),
(587, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 4, 'NT', 'οστις ουν ταπεινωση εαυτον ως το παιδιον τουτο ουτος εστιν ο μειζων εν τη βασιλεια των ουρανων'),
(588, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 5, 'NT', 'και ος εαν δεξηται παιδιον τοιουτον εν επι τω ονοματι μου εμε δεχεται'),
(589, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 6, 'NT', 'ος δ αν σκανδαλιση ενα των μικρων τουτων των πιστευοντων εις εμε συμφερει αυτω ινα κρεμασθη μυλος ονικος επι τον τραχηλον αυτου και καταποντισθη εν τω πελαγει της θαλασσης'),
(590, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 7, 'NT', 'ουαι τω κοσμω απο των σκανδαλων αναγκη γαρ εστιν ελθειν τα σκανδαλα πλην ουαι τω ανθρωπω εκεινω δι ου το σκανδαλον ερχεται'),
(591, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 8, 'NT', 'ει δε η χειρ σου η ο πους σου σκανδαλιζει σε εκκοψον αυτα και βαλε απο σου καλον σοι εστιν εισελθειν εις την ζωην χωλον η κυλλον η δυο χειρας η δυο ποδας εχοντα βληθηναι εις το πυρ το αιωνιον'),
(592, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 9, 'NT', 'και ει ο οφθαλμος σου σκανδαλιζει σε εξελε αυτον και βαλε απο σου καλον σοι εστιν μονοφθαλμον εις την ζωην εισελθειν η δυο οφθαλμους εχοντα βληθηναι εις την γεενναν του πυρος'),
(593, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 10, 'NT', 'ορατε μη καταφρονησητε ενος των μικρων τουτων λεγω γαρ υμιν οτι οι αγγελοι αυτων εν ουρανοις δια παντος βλεπουσιν το προσωπον του πατρος μου του εν ουρανοις'),
(594, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 11, 'NT', 'ηλθεν γαρ ο υιος του ανθρωπου σωσαι το απολωλος'),
(595, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 12, 'NT', 'τι υμιν δοκει εαν γενηται τινι ανθρωπω εκατον προβατα και πλανηθη εν εξ αυτων ουχι αφεις τα εννενηκονταεννεα επι τα ορη πορευθεις ζητει το πλανωμενον'),
(596, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 13, 'NT', 'και εαν γενηται ευρειν αυτο αμην λεγω υμιν οτι χαιρει επ αυτω μαλλον η επι τοις εννενηκονταεννεα τοις μη πεπλανημενοις'),
(597, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 14, 'NT', 'ουτως ουκ εστιν θελημα εμπροσθεν του πατρος υμων του εν ουρανοις ινα αποληται εις των μικρων τουτων'),
(598, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 15, 'NT', 'εαν δε αμαρτηση εις σε ο αδελφος σου υπαγε και ελεγξον αυτον μεταξυ σου και αυτου μονου εαν σου ακουση εκερδησας τον αδελφον σου'),
(599, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 16, 'NT', 'εαν δε μη ακουση παραλαβε μετα σου ετι ενα η δυο ινα επι στοματος δυο μαρτυρων η τριων σταθη παν ρημα'),
(600, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 17, 'NT', 'εαν δε παρακουση αυτων ειπε τη εκκλησια εαν δε και της εκκλησιας παρακουση εστω σοι ωσπερ ο εθνικος και ο τελωνης'),
(601, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 18, 'NT', 'αμην λεγω υμιν οσα εαν δησητε επι της γης εσται δεδεμενα εν τω ουρανω και οσα εαν λυσητε επι της γης εσται λελυμενα εν τω ουρανω'),
(602, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 19, 'NT', 'παλιν λεγω υμιν οτι εαν δυο υμων συμφωνησωσιν επι της γης περι παντος πραγματος ου εαν αιτησωνται γενησεται αυτοις παρα του πατρος μου του εν ουρανοις'),
(603, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 20, 'NT', 'ου γαρ εισιν δυο η τρεις συνηγμενοι εις το εμον ονομα εκει ειμι εν μεσω αυτων'),
(604, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 21, 'NT', 'τοτε προσελθων αυτω ο πετρος ειπεν κυριε ποσακις αμαρτησει εις εμε ο αδελφος μου και αφησω αυτω εως επτακις'),
(605, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 22, 'NT', 'λεγει αυτω ο ιησους ου λεγω σοι εως επτακις αλλ εως εβδομηκοντακις επτα'),
(606, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 23, 'NT', 'δια τουτο ωμοιωθη η βασιλεια των ουρανων ανθρωπω βασιλει ος ηθελησεν συναραι λογον μετα των δουλων αυτου'),
(607, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 24, 'NT', 'αρξαμενου δε αυτου συναιρειν προσηνεχθη αυτω εις οφειλετης μυριων ταλαντων'),
(608, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 25, 'NT', 'μη εχοντος δε αυτου αποδουναι εκελευσεν αυτον ο κυριος αυτου πραθηναι και την γυναικα αυτου και τα τεκνα και παντα οσα ειχεν και αποδοθηναι'),
(609, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 26, 'NT', 'πεσων ουν ο δουλος προσεκυνει αυτω λεγων κυριε μακροθυμησον επ εμοι και παντα σοι αποδωσω'),
(610, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 27, 'NT', 'σπλαγχνισθεις δε ο κυριος του δουλου εκεινου απελυσεν αυτον και το δανειον αφηκεν αυτω'),
(611, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 28, 'NT', 'εξελθων δε ο δουλος εκεινος ευρεν ενα των συνδουλων αυτου ος ωφειλεν αυτω εκατον δηναρια και κρατησας αυτον επνιγεν λεγων αποδος μοι ο τι οφειλεις'),
(612, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 29, 'NT', 'πεσων ουν ο συνδουλος αυτου εις τους ποδας αυτου παρεκαλει αυτον λεγων μακροθυμησον επ εμοι και παντα αποδωσω σοι'),
(613, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 30, 'NT', 'ο δε ουκ ηθελεν αλλα απελθων εβαλεν αυτον εις φυλακην εως ου αποδω το οφειλομενον'),
(614, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 31, 'NT', 'ιδοντες δε οι συνδουλοι αυτου τα γενομενα ελυπηθησαν σφοδρα και ελθοντες διεσαφησαν τω κυριω αυτων παντα τα γενομενα'),
(615, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 32, 'NT', 'τοτε προσκαλεσαμενος αυτον ο κυριος αυτου λεγει αυτω δουλε πονηρε πασαν την οφειλην εκεινην αφηκα σοι επει παρεκαλεσας με'),
(616, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 33, 'NT', 'ουκ εδει και σε ελεησαι τον συνδουλον σου ως και εγω σε ηλεησα'),
(617, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 34, 'NT', 'και οργισθεις ο κυριος αυτου παρεδωκεν αυτον τοις βασανισταις εως ου αποδω παν το οφειλομενον αυτω'),
(618, 40, 'TR1550', 'TR1550', 'el', 'MAT', 18, 35, 'NT', 'ουτως και ο πατηρ μου ο επουρανιος ποιησει υμιν εαν μη αφητε εκαστος τω αδελφω αυτου απο των καρδιων υμων τα παραπτωματα αυτων'),
(619, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 1, 'NT', 'και εγενετο οτε ετελεσεν ο ιησους τους λογους τουτους μετηρεν απο της γαλιλαιας και ηλθεν εις τα ορια της ιουδαιας περαν του ιορδανου'),
(620, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 2, 'NT', 'και ηκολουθησαν αυτω οχλοι πολλοι και εθεραπευσεν αυτους εκει'),
(621, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 3, 'NT', 'και προσηλθον αυτω οι φαρισαιοι πειραζοντες αυτον και λεγοντες αυτω ει εξεστιν ανθρωπω απολυσαι την γυναικα αυτου κατα πασαν αιτιαν'),
(622, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 4, 'NT', 'ο δε αποκριθεις ειπεν αυτοις ουκ ανεγνωτε οτι ο ποιησας απ αρχης αρσεν και θηλυ εποιησεν αυτους'),
(623, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 5, 'NT', 'και ειπεν ενεκεν τουτου καταλειψει ανθρωπος τον πατερα και την μητερα και προσκολληθησεται τη γυναικι αυτου και εσονται οι δυο εις σαρκα μιαν'),
(624, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 6, 'NT', 'ωστε ουκετι εισιν δυο αλλα σαρξ μια ο ουν ο θεος συνεζευξεν ανθρωπος μη χωριζετω'),
(625, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 7, 'NT', 'λεγουσιν αυτω τι ουν μωσης ενετειλατο δουναι βιβλιον αποστασιου και απολυσαι αυτην'),
(626, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 8, 'NT', 'λεγει αυτοις οτι μωσης προς την σκληροκαρδιαν υμων επετρεψεν υμιν απολυσαι τας γυναικας υμων απ αρχης δε ου γεγονεν ουτως'),
(627, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 9, 'NT', 'λεγω δε υμιν οτι ος αν απολυση την γυναικα αυτου ει μη επι πορνεια και γαμηση αλλην μοιχαται και ο απολελυμενην γαμησας μοιχαται'),
(628, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 10, 'NT', 'λεγουσιν αυτω οι μαθηται αυτου ει ουτως εστιν η αιτια του ανθρωπου μετα της γυναικος ου συμφερει γαμησαι'),
(629, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 11, 'NT', 'ο δε ειπεν αυτοις ου παντες χωρουσιν τον λογον τουτον αλλ οις δεδοται'),
(630, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 12, 'NT', 'εισιν γαρ ευνουχοι οιτινες εκ κοιλιας μητρος εγεννηθησαν ουτως και εισιν ευνουχοι οιτινες ευνουχισθησαν υπο των ανθρωπων και εισιν ευνουχοι οιτινες ευνουχισαν εαυτους δια την βασιλειαν των ουρανων ο δυναμενος χωρειν χωρειτω'),
(631, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 13, 'NT', 'τοτε προσηνεχθη αυτω παιδια ινα τας χειρας επιθη αυτοις και προσευξηται οι δε μαθηται επετιμησαν αυτοις'),
(632, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 14, 'NT', 'ο δε ιησους ειπεν αφετε τα παιδια και μη κωλυετε αυτα ελθειν προς με των γαρ τοιουτων εστιν η βασιλεια των ουρανων'),
(633, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 15, 'NT', 'και επιθεις αυτοις τας χειρας επορευθη εκειθεν'),
(634, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 16, 'NT', 'και ιδου εις προσελθων ειπεν αυτω διδασκαλε αγαθε τι αγαθον ποιησω ινα εχω ζωην αιωνιον'),
(635, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 17, 'NT', 'ο δε ειπεν αυτω τι με λεγεις αγαθον ουδεις αγαθος ει μη εις ο θεος ει δε θελεις εισελθειν εις την ζωην τηρησον τας εντολας'),
(636, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 18, 'NT', 'λεγει αυτω ποιας ο δε ιησους ειπεν το ου φονευσεις ου μοιχευσεις ου κλεψεις ου ψευδομαρτυρησεις'),
(637, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 19, 'NT', 'τιμα τον πατερα σου και την μητερα και αγαπησεις τον πλησιον σου ως σεαυτον'),
(638, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 20, 'NT', 'λεγει αυτω ο νεανισκος παντα ταυτα εφυλαξαμην εκ νεοτητος μου τι ετι υστερω'),
(639, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 21, 'NT', 'εφη αυτω ο ιησους ει θελεις τελειος ειναι υπαγε πωλησον σου τα υπαρχοντα και δος πτωχοις και εξεις θησαυρον εν ουρανω και δευρο ακολουθει μοι'),
(640, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 22, 'NT', 'ακουσας δε ο νεανισκος τον λογον απηλθεν λυπουμενος ην γαρ εχων κτηματα πολλα'),
(641, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 23, 'NT', 'ο δε ιησους ειπεν τοις μαθηταις αυτου αμην λεγω υμιν οτι δυσκολως πλουσιος εισελευσεται εις την βασιλειαν των ουρανων'),
(642, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 24, 'NT', 'παλιν δε λεγω υμιν ευκοπωτερον εστιν καμηλον δια τρυπηματος ραφιδος διελθειν η πλουσιον εις την βασιλειαν του θεου εισελθειν'),
(643, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 25, 'NT', 'ακουσαντες δε οι μαθηται αυτου εξεπλησσοντο σφοδρα λεγοντες τις αρα δυναται σωθηναι'),
(644, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 26, 'NT', 'εμβλεψας δε ο ιησους ειπεν αυτοις παρα ανθρωποις τουτο αδυνατον εστιν παρα δε θεω παντα δυνατα εστιν'),
(645, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 27, 'NT', 'τοτε αποκριθεις ο πετρος ειπεν αυτω ιδου ημεις αφηκαμεν παντα και ηκολουθησαμεν σοι τι αρα εσται ημιν'),
(646, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 28, 'NT', 'ο δε ιησους ειπεν αυτοις αμην λεγω υμιν οτι υμεις οι ακολουθησαντες μοι εν τη παλιγγενεσια οταν καθιση ο υιος του ανθρωπου επι θρονου δοξης αυτου καθισεσθε και υμεις επι δωδεκα θρονους κρινοντες τας δωδεκα φυλας του ισραηλ'),
(647, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 29, 'NT', 'και πας ος αφηκεν οικιας η αδελφους η αδελφας η πατερα η μητερα η γυναικα η τεκνα η αγρους ενεκεν του ονοματος μου εκατονταπλασιονα ληψεται και ζωην αιωνιον κληρονομησει'),
(648, 40, 'TR1550', 'TR1550', 'el', 'MAT', 19, 30, 'NT', 'πολλοι δε εσονται πρωτοι εσχατοι και εσχατοι πρωτοι'),
(649, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 1, 'NT', 'ομοια γαρ εστιν η βασιλεια των ουρανων ανθρωπω οικοδεσποτη οστις εξηλθεν αμα πρωι μισθωσασθαι εργατας εις τον αμπελωνα αυτου'),
(650, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 2, 'NT', 'συμφωνησας δε μετα των εργατων εκ δηναριου την ημεραν απεστειλεν αυτους εις τον αμπελωνα αυτου'),
(651, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 3, 'NT', 'και εξελθων περι την τριτην ωραν ειδεν αλλους εστωτας εν τη αγορα αργους'),
(652, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 4, 'NT', 'κακεινοις ειπεν υπαγετε και υμεις εις τον αμπελωνα και ο εαν η δικαιον δωσω υμιν'),
(653, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 5, 'NT', 'οι δε απηλθον παλιν εξελθων περι εκτην και εννατην ωραν εποιησεν ωσαυτως'),
(654, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 6, 'NT', 'περι δε την ενδεκατην ωραν εξελθων ευρεν αλλους εστωτας αργους και λεγει αυτοις τι ωδε εστηκατε ολην την ημεραν αργοι'),
(655, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 7, 'NT', 'λεγουσιν αυτω οτι ουδεις ημας εμισθωσατο λεγει αυτοις υπαγετε και υμεις εις τον αμπελωνα και ο εαν η δικαιον ληψεσθε'),
(656, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 8, 'NT', 'οψιας δε γενομενης λεγει ο κυριος του αμπελωνος τω επιτροπω αυτου καλεσον τους εργατας και αποδος αυτοις τον μισθον αρξαμενος απο των εσχατων εως των πρωτων'),
(657, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 9, 'NT', 'και ελθοντες οι περι την ενδεκατην ωραν ελαβον ανα δηναριον'),
(658, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 10, 'NT', 'ελθοντες δε οι πρωτοι ενομισαν οτι πλειονα ληψονται και ελαβον και αυτοι ανα δηναριον'),
(659, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 11, 'NT', 'λαβοντες δε εγογγυζον κατα του οικοδεσποτου'),
(660, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 12, 'NT', 'λεγοντες οτι ουτοι οι εσχατοι μιαν ωραν εποιησαν και ισους ημιν αυτους εποιησας τοις βαστασασιν το βαρος της ημερας και τον καυσωνα'),
(661, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 13, 'NT', 'ο δε αποκριθεις ειπεν ενι αυτων εταιρε ουκ αδικω σε ουχι δηναριου συνεφωνησας μοι'),
(662, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 14, 'NT', 'αρον το σον και υπαγε θελω δε τουτω τω εσχατω δουναι ως και σοι'),
(663, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 15, 'NT', 'η ουκ εξεστιν μοι ποιησαι ο θελω εν τοις εμοις ει ο οφθαλμος σου πονηρος εστιν οτι εγω αγαθος ειμι'),
(664, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 16, 'NT', 'ουτως εσονται οι εσχατοι πρωτοι και οι πρωτοι εσχατοι πολλοι γαρ εισιν κλητοι ολιγοι δε εκλεκτοι'),
(665, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 17, 'NT', 'και αναβαινων ο ιησους εις ιεροσολυμα παρελαβεν τους δωδεκα μαθητας κατ ιδιαν εν τη οδω και ειπεν αυτοις'),
(666, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 18, 'NT', 'ιδου αναβαινομεν εις ιεροσολυμα και ο υιος του ανθρωπου παραδοθησεται τοις αρχιερευσιν και γραμματευσιν και κατακρινουσιν αυτον θανατω'),
(667, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 19, 'NT', 'και παραδωσουσιν αυτον τοις εθνεσιν εις το εμπαιξαι και μαστιγωσαι και σταυρωσαι και τη τριτη ημερα αναστησεται'),
(668, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 20, 'NT', 'τοτε προσηλθεν αυτω η μητηρ των υιων ζεβεδαιου μετα των υιων αυτης προσκυνουσα και αιτουσα τι παρ αυτου'),
(669, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 21, 'NT', 'ο δε ειπεν αυτη τι θελεις λεγει αυτω ειπε ινα καθισωσιν ουτοι οι δυο υιοι μου εις εκ δεξιων σου και εις εξ ευωνυμων εν τη βασιλεια σου'),
(670, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 22, 'NT', 'αποκριθεις δε ο ιησους ειπεν ουκ οιδατε τι αιτεισθε δυνασθε πιειν το ποτηριον ο εγω μελλω πινειν και το βαπτισμα ο εγω βαπτιζομαι βαπτισθηναι λεγουσιν αυτω δυναμεθα'),
(671, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 23, 'NT', 'και λεγει αυτοις το μεν ποτηριον μου πιεσθε και το βαπτισμα ο εγω βαπτιζομαι βαπτισθησεσθε το δε καθισαι εκ δεξιων μου και εξ ευωνυμων μου ουκ εστιν εμον δουναι αλλ οις ητοιμασται υπο του πατρος μου'),
(672, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 24, 'NT', 'και ακουσαντες οι δεκα ηγανακτησαν περι των δυο αδελφων'),
(673, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 25, 'NT', 'ο δε ιησους προσκαλεσαμενος αυτους ειπεν οιδατε οτι οι αρχοντες των εθνων κατακυριευουσιν αυτων και οι μεγαλοι κατεξουσιαζουσιν αυτων'),
(674, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 26, 'NT', 'ουχ ουτως δε εσται εν υμιν αλλ ος εαν θελη εν υμιν μεγας γενεσθαι εστω υμων διακονος'),
(675, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 27, 'NT', 'και ος εαν θελη εν υμιν ειναι πρωτος εστω υμων δουλος'),
(676, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 28, 'NT', 'ωσπερ ο υιος του ανθρωπου ουκ ηλθεν διακονηθηναι αλλα διακονησαι και δουναι την ψυχην αυτου λυτρον αντι πολλων'),
(677, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 29, 'NT', 'και εκπορευομενων αυτων απο ιεριχω ηκολουθησεν αυτω οχλος πολυς'),
(678, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 30, 'NT', 'και ιδου δυο τυφλοι καθημενοι παρα την οδον ακουσαντες οτι ιησους παραγει εκραξαν λεγοντες ελεησον ημας κυριε υιος δαβιδ'),
(679, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 31, 'NT', 'ο δε οχλος επετιμησεν αυτοις ινα σιωπησωσιν οι δε μειζον εκραζον λεγοντες ελεησον ημας κυριε υιος δαβιδ'),
(680, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 32, 'NT', 'και στας ο ιησους εφωνησεν αυτους και ειπεν τι θελετε ποιησω υμιν'),
(681, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 33, 'NT', 'λεγουσιν αυτω κυριε ινα ανοιχθωσιν ημων οι οφθαλμοι'),
(682, 40, 'TR1550', 'TR1550', 'el', 'MAT', 20, 34, 'NT', 'σπλαγχνισθεις δε ο ιησους ηψατο των οφθαλμων αυτων και ευθεως ανεβλεψαν αυτων οι οφθαλμοι και ηκολουθησαν αυτω'),
(683, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 1, 'NT', 'και οτε ηγγισαν εις ιεροσολυμα και ηλθον εις βηθφαγη προς το ορος των ελαιων τοτε ο ιησους απεστειλεν δυο μαθητας'),
(684, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 2, 'NT', 'λεγων αυτοις πορευθητε εις την κωμην την απεναντι υμων και ευθεως ευρησετε ονον δεδεμενην και πωλον μετ αυτης λυσαντες αγαγετε μοι'),
(685, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 3, 'NT', 'και εαν τις υμιν ειπη τι ερειτε οτι ο κυριος αυτων χρειαν εχει ευθεως δε αποστελει αυτους'),
(686, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 4, 'NT', 'τουτο δε ολον γεγονεν ινα πληρωθη το ρηθεν δια του προφητου λεγοντος'),
(687, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 5, 'NT', 'ειπατε τη θυγατρι σιων ιδου ο βασιλευς σου ερχεται σοι πραυς και επιβεβηκως επι ονον και πωλον υιον υποζυγιου'),
(688, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 6, 'NT', 'πορευθεντες δε οι μαθηται και ποιησαντες καθως προσεταξεν αυτοις ο ιησους'),
(689, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 7, 'NT', 'ηγαγον την ονον και τον πωλον και επεθηκαν επανω αυτων τα ιματια αυτων και επεκαθισεν επανω αυτων'),
(690, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 8, 'NT', 'ο δε πλειστος οχλος εστρωσαν εαυτων τα ιματια εν τη οδω αλλοι δε εκοπτον κλαδους απο των δενδρων και εστρωννυον εν τη οδω'),
(691, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 9, 'NT', 'οι δε οχλοι οι προαγοντες και οι ακολουθουντες εκραζον λεγοντες ωσαννα τω υιω δαβιδ ευλογημενος ο ερχομενος εν ονοματι κυριου ωσαννα εν τοις υψιστοις'),
(692, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 10, 'NT', 'και εισελθοντος αυτου εις ιεροσολυμα εσεισθη πασα η πολις λεγουσα τις εστιν ουτος'),
(693, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 11, 'NT', 'οι δε οχλοι ελεγον ουτος εστιν ιησους ο προφητης ο απο ναζαρετ της γαλιλαιας'),
(694, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 12, 'NT', 'και εισηλθεν ο ιησους εις το ιερον του θεου και εξεβαλεν παντας τους πωλουντας και αγοραζοντας εν τω ιερω και τας τραπεζας των κολλυβιστων κατεστρεψεν και τας καθεδρας των πωλουντων τας περιστερας'),
(695, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 13, 'NT', 'και λεγει αυτοις γεγραπται ο οικος μου οικος προσευχης κληθησεται υμεις δε αυτον εποιησατε σπηλαιον ληστων'),
(696, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 14, 'NT', 'και προσηλθον αυτω τυφλοι και χωλοι εν τω ιερω και εθεραπευσεν αυτους'),
(697, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 15, 'NT', 'ιδοντες δε οι αρχιερεις και οι γραμματεις τα θαυμασια α εποιησεν και τους παιδας κραζοντας εν τω ιερω και λεγοντας ωσαννα τω υιω δαβιδ ηγανακτησαν'),
(698, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 16, 'NT', 'και ειπον αυτω ακουεις τι ουτοι λεγουσιν ο δε ιησους λεγει αυτοις ναι ουδεποτε ανεγνωτε οτι εκ στοματος νηπιων και θηλαζοντων κατηρτισω αινον'),
(699, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 17, 'NT', 'και καταλιπων αυτους εξηλθεν εξω της πολεως εις βηθανιαν και ηυλισθη εκει'),
(700, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 18, 'NT', 'πρωιας δε επαναγων εις την πολιν επεινασεν'),
(701, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 19, 'NT', 'και ιδων συκην μιαν επι της οδου ηλθεν επ αυτην και ουδεν ευρεν εν αυτη ει μη φυλλα μονον και λεγει αυτη μηκετι εκ σου καρπος γενηται εις τον αιωνα και εξηρανθη παραχρημα η συκη'),
(702, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 20, 'NT', 'και ιδοντες οι μαθηται εθαυμασαν λεγοντες πως παραχρημα εξηρανθη η συκη'),
(703, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 21, 'NT', 'αποκριθεις δε ο ιησους ειπεν αυτοις αμην λεγω υμιν εαν εχητε πιστιν και μη διακριθητε ου μονον το της συκης ποιησετε αλλα καν τω ορει τουτω ειπητε αρθητι και βληθητι εις την θαλασσαν γενησεται'),
(704, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 22, 'NT', 'και παντα οσα αν αιτησητε εν τη προσευχη πιστευοντες ληψεσθε'),
(705, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 23, 'NT', 'και ελθοντι αυτω εις το ιερον προσηλθον αυτω διδασκοντι οι αρχιερεις και οι πρεσβυτεροι του λαου λεγοντες εν ποια εξουσια ταυτα ποιεις και τις σοι εδωκεν την εξουσιαν ταυτην'),
(706, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 24, 'NT', 'αποκριθεις δε ο ιησους ειπεν αυτοις ερωτησω υμας καγω λογον ενα ον εαν ειπητε μοι καγω υμιν ερω εν ποια εξουσια ταυτα ποιω'),
(707, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 25, 'NT', 'το βαπτισμα ιωαννου ποθεν ην εξ ουρανου η εξ ανθρωπων οι δε διελογιζοντο παρ εαυτοις λεγοντες εαν ειπωμεν εξ ουρανου ερει ημιν δια τι ουν ουκ επιστευσατε αυτω'),
(708, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 26, 'NT', 'εαν δε ειπωμεν εξ ανθρωπων φοβουμεθα τον οχλον παντες γαρ εχουσιν τον ιωαννην ως προφητην'),
(709, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 27, 'NT', 'και αποκριθεντες τω ιησου ειπον ουκ οιδαμεν εφη αυτοις και αυτος ουδε εγω λεγω υμιν εν ποια εξουσια ταυτα ποιω'),
(710, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 28, 'NT', 'τι δε υμιν δοκει ανθρωπος ειχεν τεκνα δυο και προσελθων τω πρωτω ειπεν τεκνον υπαγε σημερον εργαζου εν τω αμπελωνι μου'),
(711, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 29, 'NT', 'ο δε αποκριθεις ειπεν ου θελω υστερον δε μεταμεληθεις απηλθεν'),
(712, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 30, 'NT', 'και προσελθων τω δευτερω ειπεν ωσαυτως ο δε αποκριθεις ειπεν εγω κυριε και ουκ απηλθεν'),
(713, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 31, 'NT', 'τις εκ των δυο εποιησεν το θελημα του πατρος λεγουσιν αυτω ο πρωτος λεγει αυτοις ο ιησους αμην λεγω υμιν οτι οι τελωναι και αι πορναι προαγουσιν υμας εις την βασιλειαν του θεου'),
(714, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 32, 'NT', 'ηλθεν γαρ προς υμας ιωαννης εν οδω δικαιοσυνης και ουκ επιστευσατε αυτω οι δε τελωναι και αι πορναι επιστευσαν αυτω υμεις δε ιδοντες ου μετεμεληθητε υστερον του πιστευσαι αυτω'),
(715, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 33, 'NT', 'αλλην παραβολην ακουσατε ανθρωπος τις ην οικοδεσποτης οστις εφυτευσεν αμπελωνα και φραγμον αυτω περιεθηκεν και ωρυξεν εν αυτω ληνον και ωκοδομησεν πυργον και εξεδοτο αυτον γεωργοις και απεδημησεν'),
(716, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 34, 'NT', 'οτε δε ηγγισεν ο καιρος των καρπων απεστειλεν τους δουλους αυτου προς τους γεωργους λαβειν τους καρπους αυτου'),
(717, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 35, 'NT', 'και λαβοντες οι γεωργοι τους δουλους αυτου ον μεν εδειραν ον δε απεκτειναν ον δε ελιθοβολησαν'),
(718, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 36, 'NT', 'παλιν απεστειλεν αλλους δουλους πλειονας των πρωτων και εποιησαν αυτοις ωσαυτως'),
(719, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 37, 'NT', 'υστερον δε απεστειλεν προς αυτους τον υιον αυτου λεγων εντραπησονται τον υιον μου'),
(720, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 38, 'NT', 'οι δε γεωργοι ιδοντες τον υιον ειπον εν εαυτοις ουτος εστιν ο κληρονομος δευτε αποκτεινωμεν αυτον και κατασχωμεν την κληρονομιαν αυτου'),
(721, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 39, 'NT', 'και λαβοντες αυτον εξεβαλον εξω του αμπελωνος και απεκτειναν'),
(722, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 40, 'NT', 'οταν ουν ελθη ο κυριος του αμπελωνος τι ποιησει τοις γεωργοις εκεινοις'),
(723, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 41, 'NT', 'λεγουσιν αυτω κακους κακως απολεσει αυτους και τον αμπελωνα εκδοσεται αλλοις γεωργοις οιτινες αποδωσουσιν αυτω τους καρπους εν τοις καιροις αυτων'),
(724, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 42, 'NT', 'λεγει αυτοις ο ιησους ουδεποτε ανεγνωτε εν ταις γραφαις λιθον ον απεδοκιμασαν οι οικοδομουντες ουτος εγενηθη εις κεφαλην γωνιας παρα κυριου εγενετο αυτη και εστιν θαυμαστη εν οφθαλμοις ημων'),
(725, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 43, 'NT', 'δια τουτο λεγω υμιν οτι αρθησεται αφ υμων η βασιλεια του θεου και δοθησεται εθνει ποιουντι τους καρπους αυτης'),
(726, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 44, 'NT', 'και ο πεσων επι τον λιθον τουτον συνθλασθησεται εφ ον δ αν πεση λικμησει αυτον'),
(727, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 45, 'NT', 'και ακουσαντες οι αρχιερεις και οι φαρισαιοι τας παραβολας αυτου εγνωσαν οτι περι αυτων λεγει'),
(728, 40, 'TR1550', 'TR1550', 'el', 'MAT', 21, 46, 'NT', 'και ζητουντες αυτον κρατησαι εφοβηθησαν τους οχλους επειδη ως προφητην αυτον ειχον'),
(729, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 1, 'NT', 'και αποκριθεις ο ιησους παλιν ειπεν αυτοις εν παραβολαις λεγων'),
(730, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 2, 'NT', 'ωμοιωθη η βασιλεια των ουρανων ανθρωπω βασιλει οστις εποιησεν γαμους τω υιω αυτου'),
(731, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 3, 'NT', 'και απεστειλεν τους δουλους αυτου καλεσαι τους κεκλημενους εις τους γαμους και ουκ ηθελον ελθειν'),
(732, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 4, 'NT', 'παλιν απεστειλεν αλλους δουλους λεγων ειπατε τοις κεκλημενοις ιδου το αριστον μου ητοιμασα οι ταυροι μου και τα σιτιστα τεθυμενα και παντα ετοιμα δευτε εις τους γαμους'),
(733, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 5, 'NT', 'οι δε αμελησαντες απηλθον ο μεν εις τον ιδιον αγρον ο δε εις την εμποριαν αυτου'),
(734, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 6, 'NT', 'οι δε λοιποι κρατησαντες τους δουλους αυτου υβρισαν και απεκτειναν'),
(735, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 7, 'NT', 'ακουσας δε ο βασιλευς ωργισθη και πεμψας τα στρατευματα αυτου απωλεσεν τους φονεις εκεινους και την πολιν αυτων ενεπρησεν'),
(736, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 8, 'NT', 'τοτε λεγει τοις δουλοις αυτου ο μεν γαμος ετοιμος εστιν οι δε κεκλημενοι ουκ ησαν αξιοι'),
(737, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 9, 'NT', 'πορευεσθε ουν επι τας διεξοδους των οδων και οσους αν ευρητε καλεσατε εις τους γαμους'),
(738, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 10, 'NT', 'και εξελθοντες οι δουλοι εκεινοι εις τας οδους συνηγαγον παντας οσους ευρον πονηρους τε και αγαθους και επλησθη ο γαμος ανακειμενων'),
(739, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 11, 'NT', 'εισελθων δε ο βασιλευς θεασασθαι τους ανακειμενους ειδεν εκει ανθρωπον ουκ ενδεδυμενον ενδυμα γαμου'),
(740, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 12, 'NT', 'και λεγει αυτω εταιρε πως εισηλθες ωδε μη εχων ενδυμα γαμου ο δε εφιμωθη'),
(741, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 13, 'NT', 'τοτε ειπεν ο βασιλευς τοις διακονοις δησαντες αυτου ποδας και χειρας αρατε αυτον και εκβαλετε εις το σκοτος το εξωτερον εκει εσται ο κλαυθμος και ο βρυγμος των οδοντων'),
(742, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 14, 'NT', 'πολλοι γαρ εισιν κλητοι ολιγοι δε εκλεκτοι'),
(743, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 15, 'NT', 'τοτε πορευθεντες οι φαρισαιοι συμβουλιον ελαβον οπως αυτον παγιδευσωσιν εν λογω'),
(744, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 16, 'NT', 'και αποστελλουσιν αυτω τους μαθητας αυτων μετα των ηρωδιανων λεγοντες διδασκαλε οιδαμεν οτι αληθης ει και την οδον του θεου εν αληθεια διδασκεις και ου μελει σοι περι ουδενος ου γαρ βλεπεις εις προσωπον ανθρωπων'),
(745, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 17, 'NT', 'ειπε ουν ημιν τι σοι δοκει εξεστιν δουναι κηνσον καισαρι η ου'),
(746, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 18, 'NT', 'γνους δε ο ιησους την πονηριαν αυτων ειπεν τι με πειραζετε υποκριται'),
(747, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 19, 'NT', 'επιδειξατε μοι το νομισμα του κηνσου οι δε προσηνεγκαν αυτω δηναριον'),
(748, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 20, 'NT', 'και λεγει αυτοις τινος η εικων αυτη και η επιγραφη'),
(749, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 21, 'NT', 'λεγουσιν αυτω καισαρος τοτε λεγει αυτοις αποδοτε ουν τα καισαρος καισαρι και τα του θεου τω θεω'),
(750, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 22, 'NT', 'και ακουσαντες εθαυμασαν και αφεντες αυτον απηλθον'),
(751, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 23, 'NT', 'εν εκεινη τη ημερα προσηλθον αυτω σαδδουκαιοι οι λεγοντες μη ειναι αναστασιν και επηρωτησαν αυτον'),
(752, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 24, 'NT', 'λεγοντες διδασκαλε μωσης ειπεν εαν τις αποθανη μη εχων τεκνα επιγαμβρευσει ο αδελφος αυτου την γυναικα αυτου και αναστησει σπερμα τω αδελφω αυτου'),
(753, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 25, 'NT', 'ησαν δε παρ ημιν επτα αδελφοι και ο πρωτος γαμησας ετελευτησεν και μη εχων σπερμα αφηκεν την γυναικα αυτου τω αδελφω αυτου'),
(754, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 26, 'NT', 'ομοιως και ο δευτερος και ο τριτος εως των επτα'),
(755, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 27, 'NT', 'υστερον δε παντων απεθανεν και η γυνη'),
(756, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 28, 'NT', 'εν τη ουν αναστασει τινος των επτα εσται γυνη παντες γαρ εσχον αυτην'),
(757, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 29, 'NT', 'αποκριθεις δε ο ιησους ειπεν αυτοις πλανασθε μη ειδοτες τας γραφας μηδε την δυναμιν του θεου'),
(758, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 30, 'NT', 'εν γαρ τη αναστασει ουτε γαμουσιν ουτε εκγαμιζονται αλλ ως αγγελοι του θεου εν ουρανω εισιν'),
(759, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 31, 'NT', 'περι δε της αναστασεως των νεκρων ουκ ανεγνωτε το ρηθεν υμιν υπο του θεου λεγοντος'),
(760, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 32, 'NT', 'εγω ειμι ο θεος αβρααμ και ο θεος ισαακ και ο θεος ιακωβ ουκ εστιν ο θεος θεος νεκρων αλλα ζωντων'),
(761, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 33, 'NT', 'και ακουσαντες οι οχλοι εξεπλησσοντο επι τη διδαχη αυτου'),
(762, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 34, 'NT', 'οι δε φαρισαιοι ακουσαντες οτι εφιμωσεν τους σαδδουκαιους συνηχθησαν επι το αυτο'),
(763, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 35, 'NT', 'και επηρωτησεν εις εξ αυτων νομικος πειραζων αυτον και λεγων'),
(764, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 36, 'NT', 'διδασκαλε ποια εντολη μεγαλη εν τω νομω'),
(765, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 37, 'NT', 'ο δε ιησους ειπεν αυτω αγαπησεις κυριον τον θεον σου εν ολη τη καρδια σου και εν ολη τη ψυχη σου και εν ολη τη διανοια σου'),
(766, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 38, 'NT', 'αυτη εστιν πρωτη και μεγαλη εντολη'),
(767, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 39, 'NT', 'δευτερα δε ομοια αυτη αγαπησεις τον πλησιον σου ως σεαυτον'),
(768, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 40, 'NT', 'εν ταυταις ταις δυσιν εντολαις ολος ο νομος και οι προφηται κρεμανται'),
(769, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 41, 'NT', 'συνηγμενων δε των φαρισαιων επηρωτησεν αυτους ο ιησους'),
(770, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 42, 'NT', 'λεγων τι υμιν δοκει περι του χριστου τινος υιος εστιν λεγουσιν αυτω του δαβιδ'),
(771, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 43, 'NT', 'λεγει αυτοις πως ουν δαβιδ εν πνευματι κυριον αυτον καλει λεγων'),
(772, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 44, 'NT', 'ειπεν ο κυριος τω κυριω μου καθου εκ δεξιων μου εως αν θω τους εχθρους σου υποποδιον των ποδων σου'),
(773, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 45, 'NT', 'ει ουν δαβιδ καλει αυτον κυριον πως υιος αυτου εστιν'),
(774, 40, 'TR1550', 'TR1550', 'el', 'MAT', 22, 46, 'NT', 'και ουδεις εδυνατο αυτω αποκριθηναι λογον ουδε ετολμησεν τις απ εκεινης της ημερας επερωτησαι αυτον ουκετι'),
(775, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 1, 'NT', 'τοτε ο ιησους ελαλησεν τοις οχλοις και τοις μαθηταις αυτου'),
(776, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 2, 'NT', 'λεγων επι της μωσεως καθεδρας εκαθισαν οι γραμματεις και οι φαρισαιοι'),
(777, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 3, 'NT', 'παντα ουν οσα αν ειπωσιν υμιν τηρειν τηρειτε και ποιειτε κατα δε τα εργα αυτων μη ποιειτε λεγουσιν γαρ και ου ποιουσιν'),
(778, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 4, 'NT', 'δεσμευουσιν γαρ φορτια βαρεα και δυσβαστακτα και επιτιθεασιν επι τους ωμους των ανθρωπων τω δε δακτυλω αυτων ου θελουσιν κινησαι αυτα'),
(779, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 5, 'NT', 'παντα δε τα εργα αυτων ποιουσιν προς το θεαθηναι τοις ανθρωποις πλατυνουσιν δε τα φυλακτηρια αυτων και μεγαλυνουσιν τα κρασπεδα των ιματιων αυτων'),
(780, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 6, 'NT', 'φιλουσιν τε την πρωτοκλισιαν εν τοις δειπνοις και τας πρωτοκαθεδριας εν ταις συναγωγαις'),
(781, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 7, 'NT', 'και τους ασπασμους εν ταις αγοραις και καλεισθαι υπο των ανθρωπων ραββι ραββι'),
(782, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 8, 'NT', 'υμεις δε μη κληθητε ραββι εις γαρ εστιν υμων ο καθηγητης ο χριστος παντες δε υμεις αδελφοι εστε'),
(783, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 9, 'NT', 'και πατερα μη καλεσητε υμων επι της γης εις γαρ εστιν ο πατηρ υμων ο εν τοις ουρανοις'),
(784, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 10, 'NT', 'μηδε κληθητε καθηγηται εις γαρ υμων εστιν ο καθηγητης ο χριστος'),
(785, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 11, 'NT', 'ο δε μειζων υμων εσται υμων διακονος'),
(786, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 12, 'NT', 'οστις δε υψωσει εαυτον ταπεινωθησεται και οστις ταπεινωσει εαυτον υψωθησεται'),
(787, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 13, 'NT', 'ουαι δε υμιν γραμματεις και φαρισαιοι υποκριται οτι κατεσθιετε τας οικιας των χηρων και προφασει μακρα προσευχομενοι δια τουτο ληψεσθε περισσοτερον κριμα'),
(788, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 14, 'NT', 'ουαι υμιν γραμματεις και φαρισαιοι υποκριται οτι κλειετε την βασιλειαν των ουρανων εμπροσθεν των ανθρωπων υμεις γαρ ουκ εισερχεσθε ουδε τους εισερχομενους αφιετε εισελθειν'),
(789, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 15, 'NT', 'ουαι υμιν γραμματεις και φαρισαιοι υποκριται οτι περιαγετε την θαλασσαν και την ξηραν ποιησαι ενα προσηλυτον και οταν γενηται ποιειτε αυτον υιον γεεννης διπλοτερον υμων'),
(790, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 16, 'NT', 'ουαι υμιν οδηγοι τυφλοι οι λεγοντες ος αν ομοση εν τω ναω ουδεν εστιν ος δ αν ομοση εν τω χρυσω του ναου οφειλει'),
(791, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 17, 'NT', 'μωροι και τυφλοι τις γαρ μειζων εστιν ο χρυσος η ο ναος ο αγιαζων τον χρυσον'),
(792, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 18, 'NT', 'και ος εαν ομοση εν τω θυσιαστηριω ουδεν εστιν ος δ αν ομοση εν τω δωρω τω επανω αυτου οφειλει'),
(793, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 19, 'NT', 'μωροι και τυφλοι τι γαρ μειζον το δωρον η το θυσιαστηριον το αγιαζον το δωρον'),
(794, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 20, 'NT', 'ο ουν ομοσας εν τω θυσιαστηριω ομνυει εν αυτω και εν πασιν τοις επανω αυτου'),
(795, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 21, 'NT', 'και ο ομοσας εν τω ναω ομνυει εν αυτω και εν τω κατοικουντι αυτον'),
(796, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 22, 'NT', 'και ο ομοσας εν τω ουρανω ομνυει εν τω θρονω του θεου και εν τω καθημενω επανω αυτου'),
(797, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 23, 'NT', 'ουαι υμιν γραμματεις και φαρισαιοι υποκριται οτι αποδεκατουτε το ηδυοσμον και το ανηθον και το κυμινον και αφηκατε τα βαρυτερα του νομου την κρισιν και τον ελεον και την πιστιν ταυτα εδει ποιησαι κακεινα μη αφιεναι'),
(798, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 24, 'NT', 'οδηγοι τυφλοι οι διυλιζοντες τον κωνωπα την δε καμηλον καταπινοντες'),
(799, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 25, 'NT', 'ουαι υμιν γραμματεις και φαρισαιοι υποκριται οτι καθαριζετε το εξωθεν του ποτηριου και της παροψιδος εσωθεν δε γεμουσιν εξ αρπαγης και ακρασιας'),
(800, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 26, 'NT', 'φαρισαιε τυφλε καθαρισον πρωτον το εντος του ποτηριου και της παροψιδος ινα γενηται και το εκτος αυτων καθαρον'),
(801, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 27, 'NT', 'ουαι υμιν γραμματεις και φαρισαιοι υποκριται οτι παρομοιαζετε ταφοις κεκονιαμενοις οιτινες εξωθεν μεν φαινονται ωραιοι εσωθεν δε γεμουσιν οστεων νεκρων και πασης ακαθαρσιας'),
(802, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 28, 'NT', 'ουτως και υμεις εξωθεν μεν φαινεσθε τοις ανθρωποις δικαιοι εσωθεν δε μεστοι εστε υποκρισεως και ανομιας'),
(803, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 29, 'NT', 'ουαι υμιν γραμματεις και φαρισαιοι υποκριται οτι οικοδομειτε τους ταφους των προφητων και κοσμειτε τα μνημεια των δικαιων'),
(804, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 30, 'NT', 'και λεγετε ει ημεν εν ταις ημεραις των πατερων ημων ουκ αν ημεν κοινωνοι αυτων εν τω αιματι των προφητων'),
(805, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 31, 'NT', 'ωστε μαρτυρειτε εαυτοις οτι υιοι εστε των φονευσαντων τους προφητας'),
(806, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 32, 'NT', 'και υμεις πληρωσατε το μετρον των πατερων υμων'),
(807, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 33, 'NT', 'οφεις γεννηματα εχιδνων πως φυγητε απο της κρισεως της γεεννης'),
(808, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 34, 'NT', 'δια τουτο ιδου εγω αποστελλω προς υμας προφητας και σοφους και γραμματεις και εξ αυτων αποκτενειτε και σταυρωσετε και εξ αυτων μαστιγωσετε εν ταις συναγωγαις υμων και διωξετε απο πολεως εις πολιν'),
(809, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 35, 'NT', 'οπως ελθη εφ υμας παν αιμα δικαιον εκχυνομενον επι της γης απο του αιματος αβελ του δικαιου εως του αιματος ζαχαριου υιου βαραχιου ον εφονευσατε μεταξυ του ναου και του θυσιαστηριου'),
(810, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 36, 'NT', 'αμην λεγω υμιν ηξει ταυτα παντα επι την γενεαν ταυτην'),
(811, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 37, 'NT', 'ιερουσαλημ ιερουσαλημ η αποκτεινουσα τους προφητας και λιθοβολουσα τους απεσταλμενους προς αυτην ποσακις ηθελησα επισυναγαγειν τα τεκνα σου ον τροπον επισυναγει ορνις τα νοσσια εαυτης υπο τας πτερυγας και ουκ ηθελησατε'),
(812, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 38, 'NT', 'ιδου αφιεται υμιν ο οικος υμων ερημος'),
(813, 40, 'TR1550', 'TR1550', 'el', 'MAT', 23, 39, 'NT', 'λεγω γαρ υμιν ου μη με ιδητε απ αρτι εως αν ειπητε ευλογημενος ο ερχομενος εν ονοματι κυριου'),
(814, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 1, 'NT', 'και εξελθων ο ιησους επορευετο απο του ιερου και προσηλθον οι μαθηται αυτου επιδειξαι αυτω τας οικοδομας του ιερου'),
(815, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 2, 'NT', 'ο δε ιησους ειπεν αυτοις ου βλεπετε παντα ταυτα αμην λεγω υμιν ου μη αφεθη ωδε λιθος επι λιθον ος ου μη καταλυθησεται'),
(816, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 3, 'NT', 'καθημενου δε αυτου επι του ορους των ελαιων προσηλθον αυτω οι μαθηται κατ ιδιαν λεγοντες ειπε ημιν ποτε ταυτα εσται και τι το σημειον της σης παρουσιας και της συντελειας του αιωνος'),
(817, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 4, 'NT', 'και αποκριθεις ο ιησους ειπεν αυτοις βλεπετε μη τις υμας πλανηση'),
(818, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 5, 'NT', 'πολλοι γαρ ελευσονται επι τω ονοματι μου λεγοντες εγω ειμι ο χριστος και πολλους πλανησουσιν'),
(819, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 6, 'NT', 'μελλησετε δε ακουειν πολεμους και ακοας πολεμων ορατε μη θροεισθε δει γαρ παντα γενεσθαι αλλ ουπω εστιν το τελος'),
(820, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 7, 'NT', 'εγερθησεται γαρ εθνος επι εθνος και βασιλεια επι βασιλειαν και εσονται λιμοι και λοιμοι και σεισμοι κατα τοπους'),
(821, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 8, 'NT', 'παντα δε ταυτα αρχη ωδινων'),
(822, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 9, 'NT', 'τοτε παραδωσουσιν υμας εις θλιψιν και αποκτενουσιν υμας και εσεσθε μισουμενοι υπο παντων των εθνων δια το ονομα μου'),
(823, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 10, 'NT', 'και τοτε σκανδαλισθησονται πολλοι και αλληλους παραδωσουσιν και μισησουσιν αλληλους'),
(824, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 11, 'NT', 'και πολλοι ψευδοπροφηται εγερθησονται και πλανησουσιν πολλους'),
(825, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 12, 'NT', 'και δια το πληθυνθηναι την ανομιαν ψυγησεται η αγαπη των πολλων'),
(826, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 13, 'NT', 'ο δε υπομεινας εις τελος ουτος σωθησεται'),
(827, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 14, 'NT', 'και κηρυχθησεται τουτο το ευαγγελιον της βασιλειας εν ολη τη οικουμενη εις μαρτυριον πασιν τοις εθνεσιν και τοτε ηξει το τελος'),
(828, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 15, 'NT', 'οταν ουν ιδητε το βδελυγμα της ερημωσεως το ρηθεν δια δανιηλ του προφητου εστος εν τοπω αγιω ο αναγινωσκων νοειτω'),
(829, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 16, 'NT', 'τοτε οι εν τη ιουδαια φευγετωσαν επι τα ορη'),
(830, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 17, 'NT', 'ο επι του δωματος μη καταβαινετω αραι τι εκ της οικιας αυτου'),
(831, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 18, 'NT', 'και ο εν τω αγρω μη επιστρεψατω οπισω αραι τα ιματια αυτου'),
(832, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 19, 'NT', 'ουαι δε ταις εν γαστρι εχουσαις και ταις θηλαζουσαις εν εκειναις ταις ημεραις'),
(833, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 20, 'NT', 'προσευχεσθε δε ινα μη γενηται η φυγη υμων χειμωνος μηδε εν σαββατω'),
(834, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 21, 'NT', 'εσται γαρ τοτε θλιψις μεγαλη οια ου γεγονεν απ αρχης κοσμου εως του νυν ουδ ου μη γενηται'),
(835, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 22, 'NT', 'και ει μη εκολοβωθησαν αι ημεραι εκειναι ουκ αν εσωθη πασα σαρξ δια δε τους εκλεκτους κολοβωθησονται αι ημεραι εκειναι'),
(836, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 23, 'NT', 'τοτε εαν τις υμιν ειπη ιδου ωδε ο χριστος η ωδε μη πιστευσητε'),
(837, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 24, 'NT', 'εγερθησονται γαρ ψευδοχριστοι και ψευδοπροφηται και δωσουσιν σημεια μεγαλα και τερατα ωστε πλανησαι ει δυνατον και τους εκλεκτους'),
(838, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 25, 'NT', 'ιδου προειρηκα υμιν'),
(839, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 26, 'NT', 'εαν ουν ειπωσιν υμιν ιδου εν τη ερημω εστιν μη εξελθητε ιδου εν τοις ταμειοις μη πιστευσητε'),
(840, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 27, 'NT', 'ωσπερ γαρ η αστραπη εξερχεται απο ανατολων και φαινεται εως δυσμων ουτως εσται και η παρουσια του υιου του ανθρωπου'),
(841, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 28, 'NT', 'οπου γαρ εαν η το πτωμα εκει συναχθησονται οι αετοι'),
(842, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 29, 'NT', 'ευθεως δε μετα την θλιψιν των ημερων εκεινων ο ηλιος σκοτισθησεται και η σεληνη ου δωσει το φεγγος αυτης και οι αστερες πεσουνται απο του ουρανου και αι δυναμεις των ουρανων σαλευθησονται'),
(843, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 30, 'NT', 'και τοτε φανησεται το σημειον του υιου του ανθρωπου εν τω ουρανω και τοτε κοψονται πασαι αι φυλαι της γης και οψονται τον υιον του ανθρωπου ερχομενον επι των νεφελων του ουρανου μετα δυναμεως και δοξης πολλης'),
(844, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 31, 'NT', 'και αποστελει τους αγγελους αυτου μετα σαλπιγγος φωνης μεγαλης και επισυναξουσιν τους εκλεκτους αυτου εκ των τεσσαρων ανεμων απ ακρων ουρανων εως ακρων αυτων'),
(845, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 32, 'NT', 'απο δε της συκης μαθετε την παραβολην οταν ηδη ο κλαδος αυτης γενηται απαλος και τα φυλλα εκφυη γινωσκετε οτι εγγυς το θερος'),
(846, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 33, 'NT', 'ουτως και υμεις οταν ιδητε παντα ταυτα γινωσκετε οτι εγγυς εστιν επι θυραις'),
(847, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 34, 'NT', 'αμην λεγω υμιν ου μη παρελθη η γενεα αυτη εως αν παντα ταυτα γενηται'),
(848, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 35, 'NT', 'ο ουρανος και η γη παρελευσονται οι δε λογοι μου ου μη παρελθωσιν'),
(849, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 36, 'NT', 'περι δε της ημερας εκεινης και της ωρας ουδεις οιδεν ουδε οι αγγελοι των ουρανων ει μη ο πατηρ μου μονος'),
(850, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 37, 'NT', 'ωσπερ δε αι ημεραι του νωε ουτως εσται και η παρουσια του υιου του ανθρωπου'),
(851, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 38, 'NT', 'ωσπερ γαρ ησαν εν ταις ημεραις ταις προ του κατακλυσμου τρωγοντες και πινοντες γαμουντες και εκγαμιζοντες αχρι ης ημερας εισηλθεν νωε εις την κιβωτον'),
(852, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 39, 'NT', 'και ουκ εγνωσαν εως ηλθεν ο κατακλυσμος και ηρεν απαντας ουτως εσται και η παρουσια του υιου του ανθρωπου'),
(853, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 40, 'NT', 'τοτε δυο εσονται εν τω αγρω ο εις παραλαμβανεται και ο εις αφιεται'),
(854, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 41, 'NT', 'δυο αληθουσαι εν τω μυλωνι μια παραλαμβανεται και μια αφιεται'),
(855, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 42, 'NT', 'γρηγορειτε ουν οτι ουκ οιδατε ποια ωρα ο κυριος υμων ερχεται'),
(856, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 43, 'NT', 'εκεινο δε γινωσκετε οτι ει ηδει ο οικοδεσποτης ποια φυλακη ο κλεπτης ερχεται εγρηγορησεν αν και ουκ αν ειασεν διορυγηναι την οικιαν αυτου'),
(857, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 44, 'NT', 'δια τουτο και υμεις γινεσθε ετοιμοι οτι η ωρα ου δοκειτε ο υιος του ανθρωπου ερχεται'),
(858, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 45, 'NT', 'τις αρα εστιν ο πιστος δουλος και φρονιμος ον κατεστησεν ο κυριος αυτου επι της θεραπειας αυτου του διδοναι αυτοις την τροφην εν καιρω'),
(859, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 46, 'NT', 'μακαριος ο δουλος εκεινος ον ελθων ο κυριος αυτου ευρησει ποιουντα ουτως'),
(860, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 47, 'NT', 'αμην λεγω υμιν οτι επι πασιν τοις υπαρχουσιν αυτου καταστησει αυτον'),
(861, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 48, 'NT', 'εαν δε ειπη ο κακος δουλος εκεινος εν τη καρδια αυτου χρονιζει ο κυριος μου ελθειν'),
(862, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 49, 'NT', 'και αρξηται τυπτειν τους συνδουλους εσθιειν δε και πινειν μετα των μεθυοντων'),
(863, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 50, 'NT', 'ηξει ο κυριος του δουλου εκεινου εν ημερα η ου προσδοκα και εν ωρα η ου γινωσκει'),
(864, 40, 'TR1550', 'TR1550', 'el', 'MAT', 24, 51, 'NT', 'και διχοτομησει αυτον και το μερος αυτου μετα των υποκριτων θησει εκει εσται ο κλαυθμος και ο βρυγμος των οδοντων'),
(865, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 1, 'NT', 'τοτε ομοιωθησεται η βασιλεια των ουρανων δεκα παρθενοις αιτινες λαβουσαι τας λαμπαδας αυτων εξηλθον εις απαντησιν του νυμφιου'),
(866, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 2, 'NT', 'πεντε δε ησαν εξ αυτων φρονιμοι και αι πεντε μωραι'),
(867, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 3, 'NT', 'αιτινες μωραι λαβουσαι τας λαμπαδας εαυτων ουκ ελαβον μεθ εαυτων ελαιον'),
(868, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 4, 'NT', 'αι δε φρονιμοι ελαβον ελαιον εν τοις αγγειοις αυτων μετα των λαμπαδων αυτων'),
(869, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 5, 'NT', 'χρονιζοντος δε του νυμφιου ενυσταξαν πασαι και εκαθευδον'),
(870, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 6, 'NT', 'μεσης δε νυκτος κραυγη γεγονεν ιδου ο νυμφιος ερχεται εξερχεσθε εις απαντησιν αυτου'),
(871, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 7, 'NT', 'τοτε ηγερθησαν πασαι αι παρθενοι εκειναι και εκοσμησαν τας λαμπαδας αυτων'),
(872, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 8, 'NT', 'αι δε μωραι ταις φρονιμοις ειπον δοτε ημιν εκ του ελαιου υμων οτι αι λαμπαδες ημων σβεννυνται'),
(873, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 9, 'NT', 'απεκριθησαν δε αι φρονιμοι λεγουσαι μηποτε ουκ αρκεση ημιν και υμιν πορευεσθε δε μαλλον προς τους πωλουντας και αγορασατε εαυταις'),
(874, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 10, 'NT', 'απερχομενων δε αυτων αγορασαι ηλθεν ο νυμφιος και αι ετοιμοι εισηλθον μετ αυτου εις τους γαμους και εκλεισθη η θυρα'),
(875, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 11, 'NT', 'υστερον δε ερχονται και αι λοιπαι παρθενοι λεγουσαι κυριε κυριε ανοιξον ημιν'),
(876, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 12, 'NT', 'ο δε αποκριθεις ειπεν αμην λεγω υμιν ουκ οιδα υμας'),
(877, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 13, 'NT', 'γρηγορειτε ουν οτι ουκ οιδατε την ημεραν ουδε την ωραν εν η ο υιος του ανθρωπου ερχεται'),
(878, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 14, 'NT', 'ωσπερ γαρ ανθρωπος αποδημων εκαλεσεν τους ιδιους δουλους και παρεδωκεν αυτοις τα υπαρχοντα αυτου'),
(879, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 15, 'NT', 'και ω μεν εδωκεν πεντε ταλαντα ω δε δυο ω δε εν εκαστω κατα την ιδιαν δυναμιν και απεδημησεν ευθεως'),
(880, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 16, 'NT', 'πορευθεις δε ο τα πεντε ταλαντα λαβων ειργασατο εν αυτοις και εποιησεν αλλα πεντε ταλαντα'),
(881, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 17, 'NT', 'ωσαυτως και ο τα δυο εκερδησεν και αυτος αλλα δυο'),
(882, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 18, 'NT', 'ο δε το εν λαβων απελθων ωρυξεν εν τη γη και απεκρυψεν το αργυριον του κυριου αυτου'),
(883, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 19, 'NT', 'μετα δε χρονον πολυν ερχεται ο κυριος των δουλων εκεινων και συναιρει μετ αυτων λογον'),
(884, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 20, 'NT', 'και προσελθων ο τα πεντε ταλαντα λαβων προσηνεγκεν αλλα πεντε ταλαντα λεγων κυριε πεντε ταλαντα μοι παρεδωκας ιδε αλλα πεντε ταλαντα εκερδησα επ αυτοις'),
(885, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 21, 'NT', 'εφη δε αυτω ο κυριος αυτου ευ δουλε αγαθε και πιστε επι ολιγα ης πιστος επι πολλων σε καταστησω εισελθε εις την χαραν του κυριου σου'),
(886, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 22, 'NT', 'προσελθων δε και ο τα δυο ταλαντα λαβων ειπεν κυριε δυο ταλαντα μοι παρεδωκας ιδε αλλα δυο ταλαντα εκερδησα επ αυτοις'),
(887, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 23, 'NT', 'εφη αυτω ο κυριος αυτου ευ δουλε αγαθε και πιστε επι ολιγα ης πιστος επι πολλων σε καταστησω εισελθε εις την χαραν του κυριου σου'),
(888, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 24, 'NT', 'προσελθων δε και ο το εν ταλαντον ειληφως ειπεν κυριε εγνων σε οτι σκληρος ει ανθρωπος θεριζων οπου ουκ εσπειρας και συναγων οθεν ου διεσκορπισας'),
(889, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 25, 'NT', 'και φοβηθεις απελθων εκρυψα το ταλαντον σου εν τη γη ιδε εχεις το σον'),
(890, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 26, 'NT', 'αποκριθεις δε ο κυριος αυτου ειπεν αυτω πονηρε δουλε και οκνηρε ηδεις οτι θεριζω οπου ουκ εσπειρα και συναγω οθεν ου διεσκορπισα'),
(891, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 27, 'NT', 'εδει ουν σε βαλειν το αργυριον μου τοις τραπεζιταις και ελθων εγω εκομισαμην αν το εμον συν τοκω'),
(892, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 28, 'NT', 'αρατε ουν απ αυτου το ταλαντον και δοτε τω εχοντι τα δεκα ταλαντα'),
(893, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 29, 'NT', 'τω γαρ εχοντι παντι δοθησεται και περισσευθησεται απο δε του μη εχοντος και ο εχει αρθησεται απ αυτου'),
(894, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 30, 'NT', 'και τον αχρειον δουλον εκβαλλετε εις το σκοτος το εξωτερον εκει εσται ο κλαυθμος και ο βρυγμος των οδοντων'),
(895, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 31, 'NT', 'οταν δε ελθη ο υιος του ανθρωπου εν τη δοξη αυτου και παντες οι αγιοι αγγελοι μετ αυτου τοτε καθισει επι θρονου δοξης αυτου'),
(896, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 32, 'NT', 'και συναχθησεται εμπροσθεν αυτου παντα τα εθνη και αφοριει αυτους απ αλληλων ωσπερ ο ποιμην αφοριζει τα προβατα απο των εριφων'),
(897, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 33, 'NT', 'και στησει τα μεν προβατα εκ δεξιων αυτου τα δε εριφια εξ ευωνυμων'),
(898, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 34, 'NT', 'τοτε ερει ο βασιλευς τοις εκ δεξιων αυτου δευτε οι ευλογημενοι του πατρος μου κληρονομησατε την ητοιμασμενην υμιν βασιλειαν απο καταβολης κοσμου'),
(899, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 35, 'NT', 'επεινασα γαρ και εδωκατε μοι φαγειν εδιψησα και εποτισατε με ξενος ημην και συνηγαγετε με'),
(900, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 36, 'NT', 'γυμνος και περιεβαλετε με ησθενησα και επεσκεψασθε με εν φυλακη ημην και ηλθετε προς με'),
(901, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 37, 'NT', 'τοτε αποκριθησονται αυτω οι δικαιοι λεγοντες κυριε ποτε σε ειδομεν πεινωντα και εθρεψαμεν η διψωντα και εποτισαμεν'),
(902, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 38, 'NT', 'ποτε δε σε ειδομεν ξενον και συνηγαγομεν η γυμνον και περιεβαλομεν'),
(903, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 39, 'NT', 'ποτε δε σε ειδομεν ασθενη η εν φυλακη και ηλθομεν προς σε'),
(904, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 40, 'NT', 'και αποκριθεις ο βασιλευς ερει αυτοις αμην λεγω υμιν εφ οσον εποιησατε ενι τουτων των αδελφων μου των ελαχιστων εμοι εποιησατε'),
(905, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 41, 'NT', 'τοτε ερει και τοις εξ ευωνυμων πορευεσθε απ εμου οι κατηραμενοι εις το πυρ το αιωνιον το ητοιμασμενον τω διαβολω και τοις αγγελοις αυτου'),
(906, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 42, 'NT', 'επεινασα γαρ και ουκ εδωκατε μοι φαγειν εδιψησα και ουκ εποτισατε με'),
(907, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 43, 'NT', 'ξενος ημην και ου συνηγαγετε με γυμνος και ου περιεβαλετε με ασθενης και εν φυλακη και ουκ επεσκεψασθε με'),
(908, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 44, 'NT', 'τοτε αποκριθησονται αυτω και αυτοι λεγοντες κυριε ποτε σε ειδομεν πεινωντα η διψωντα η ξενον η γυμνον η ασθενη η εν φυλακη και ου διηκονησαμεν σοι'),
(909, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 45, 'NT', 'τοτε αποκριθησεται αυτοις λεγων αμην λεγω υμιν εφ οσον ουκ εποιησατε ενι τουτων των ελαχιστων ουδε εμοι εποιησατε'),
(910, 40, 'TR1550', 'TR1550', 'el', 'MAT', 25, 46, 'NT', 'και απελευσονται ουτοι εις κολασιν αιωνιον οι δε δικαιοι εις ζωην αιωνιον'),
(911, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 1, 'NT', 'και εγενετο οτε ετελεσεν ο ιησους παντας τους λογους τουτους ειπεν τοις μαθηταις αυτου'),
(912, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 2, 'NT', 'οιδατε οτι μετα δυο ημερας το πασχα γινεται και ο υιος του ανθρωπου παραδιδοται εις το σταυρωθηναι'),
(913, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 3, 'NT', 'τοτε συνηχθησαν οι αρχιερεις και οι γραμματεις και οι πρεσβυτεροι του λαου εις την αυλην του αρχιερεως του λεγομενου καιαφα'),
(914, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 4, 'NT', 'και συνεβουλευσαντο ινα τον ιησουν κρατησωσιν δολω και αποκτεινωσιν'),
(915, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 5, 'NT', 'ελεγον δε μη εν τη εορτη ινα μη θορυβος γενηται εν τω λαω'),
(916, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 6, 'NT', 'του δε ιησου γενομενου εν βηθανια εν οικια σιμωνος του λεπρου'),
(917, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 7, 'NT', 'προσηλθεν αυτω γυνη αλαβαστρον μυρου εχουσα βαρυτιμου και κατεχεεν επι την κεφαλην αυτου ανακειμενου'),
(918, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 8, 'NT', 'ιδοντες δε οι μαθηται αυτου ηγανακτησαν λεγοντες εις τι η απωλεια αυτη'),
(919, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 9, 'NT', 'ηδυνατο γαρ τουτο το μυρον πραθηναι πολλου και δοθηναι πτωχοις'),
(920, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 10, 'NT', 'γνους δε ο ιησους ειπεν αυτοις τι κοπους παρεχετε τη γυναικι εργον γαρ καλον ειργασατο εις εμε'),
(921, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 11, 'NT', 'παντοτε γαρ τους πτωχους εχετε μεθ εαυτων εμε δε ου παντοτε εχετε'),
(922, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 12, 'NT', 'βαλουσα γαρ αυτη το μυρον τουτο επι του σωματος μου προς το ενταφιασαι με εποιησεν'),
(923, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 13, 'NT', 'αμην λεγω υμιν οπου εαν κηρυχθη το ευαγγελιον τουτο εν ολω τω κοσμω λαληθησεται και ο εποιησεν αυτη εις μνημοσυνον αυτης'),
(924, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 14, 'NT', 'τοτε πορευθεις εις των δωδεκα ο λεγομενος ιουδας ισκαριωτης προς τους αρχιερεις'),
(925, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 15, 'NT', 'ειπεν τι θελετε μοι δουναι καγω υμιν παραδωσω αυτον οι δε εστησαν αυτω τριακοντα αργυρια'),
(926, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 16, 'NT', 'και απο τοτε εζητει ευκαιριαν ινα αυτον παραδω'),
(927, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 17, 'NT', 'τη δε πρωτη των αζυμων προσηλθον οι μαθηται τω ιησου λεγοντες αυτω που θελεις ετοιμασωμεν σοι φαγειν το πασχα'),
(928, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 18, 'NT', 'ο δε ειπεν υπαγετε εις την πολιν προς τον δεινα και ειπατε αυτω ο διδασκαλος λεγει ο καιρος μου εγγυς εστιν προς σε ποιω το πασχα μετα των μαθητων μου'),
(929, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 19, 'NT', 'και εποιησαν οι μαθηται ως συνεταξεν αυτοις ο ιησους και ητοιμασαν το πασχα'),
(930, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 20, 'NT', 'οψιας δε γενομενης ανεκειτο μετα των δωδεκα'),
(931, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 21, 'NT', 'και εσθιοντων αυτων ειπεν αμην λεγω υμιν οτι εις εξ υμων παραδωσει με'),
(932, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 22, 'NT', 'και λυπουμενοι σφοδρα ηρξαντο λεγειν αυτω εκαστος αυτων μητι εγω ειμι κυριε'),
(933, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 23, 'NT', 'ο δε αποκριθεις ειπεν ο εμβαψας μετ εμου εν τω τρυβλιω την χειρα ουτος με παραδωσει'),
(934, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 24, 'NT', 'ο μεν υιος του ανθρωπου υπαγει καθως γεγραπται περι αυτου ουαι δε τω ανθρωπω εκεινω δι ου ο υιος του ανθρωπου παραδιδοται καλον ην αυτω ει ουκ εγεννηθη ο ανθρωπος εκεινος'),
(935, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 25, 'NT', 'αποκριθεις δε ιουδας ο παραδιδους αυτον ειπεν μητι εγω ειμι ραββι λεγει αυτω συ ειπας'),
(936, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 26, 'NT', 'εσθιοντων δε αυτων λαβων ο ιησους τον αρτον και ευλογησας εκλασεν και εδιδου τοις μαθηταις και ειπεν λαβετε φαγετε τουτο εστιν το σωμα μου'),
(937, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 27, 'NT', 'και λαβων το ποτηριον και ευχαριστησας εδωκεν αυτοις λεγων πιετε εξ αυτου παντες'),
(938, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 28, 'NT', 'τουτο γαρ εστιν το αιμα μου το της καινης διαθηκης το περι πολλων εκχυνομενον εις αφεσιν αμαρτιων'),
(939, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 29, 'NT', 'λεγω δε υμιν οτι ου μη πιω απ αρτι εκ τουτου του γεννηματος της αμπελου εως της ημερας εκεινης οταν αυτο πινω μεθ υμων καινον εν τη βασιλεια του πατρος μου'),
(940, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 30, 'NT', 'και υμνησαντες εξηλθον εις το ορος των ελαιων'),
(941, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 31, 'NT', 'τοτε λεγει αυτοις ο ιησους παντες υμεις σκανδαλισθησεσθε εν εμοι εν τη νυκτι ταυτη γεγραπται γαρ παταξω τον ποιμενα και διασκορπισθησεται τα προβατα της ποιμνης'),
(942, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 32, 'NT', 'μετα δε το εγερθηναι με προαξω υμας εις την γαλιλαιαν'),
(943, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 33, 'NT', 'αποκριθεις δε ο πετρος ειπεν αυτω ει και παντες σκανδαλισθησονται εν σοι εγω ουδεποτε σκανδαλισθησομαι'),
(944, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 34, 'NT', 'εφη αυτω ο ιησους αμην λεγω σοι οτι εν ταυτη τη νυκτι πριν αλεκτορα φωνησαι τρις απαρνηση με'),
(945, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 35, 'NT', 'λεγει αυτω ο πετρος καν δεη με συν σοι αποθανειν ου μη σε απαρνησομαι ομοιως και παντες οι μαθηται ειπον'),
(946, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 36, 'NT', 'τοτε ερχεται μετ αυτων ο ιησους εις χωριον λεγομενον γεθσημανη και λεγει τοις μαθηταις καθισατε αυτου εως ου απελθων προσευξωμαι εκει'),
(947, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 37, 'NT', 'και παραλαβων τον πετρον και τους δυο υιους ζεβεδαιου ηρξατο λυπεισθαι και αδημονειν'),
(948, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 38, 'NT', 'τοτε λεγει αυτοις περιλυπος εστιν η ψυχη μου εως θανατου μεινατε ωδε και γρηγορειτε μετ εμου'),
(949, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 39, 'NT', 'και προελθων μικρον επεσεν επι προσωπον αυτου προσευχομενος και λεγων πατερ μου ει δυνατον εστιν παρελθετω απ εμου το ποτηριον τουτο πλην ουχ ως εγω θελω αλλ ως συ'),
(950, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 40, 'NT', 'και ερχεται προς τους μαθητας και ευρισκει αυτους καθευδοντας και λεγει τω πετρω ουτως ουκ ισχυσατε μιαν ωραν γρηγορησαι μετ εμου'),
(951, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 41, 'NT', 'γρηγορειτε και προσευχεσθε ινα μη εισελθητε εις πειρασμον το μεν πνευμα προθυμον η δε σαρξ ασθενης'),
(952, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 42, 'NT', 'παλιν εκ δευτερου απελθων προσηυξατο λεγων πατερ μου ει ου δυναται τουτο το ποτηριον παρελθειν απ εμου εαν μη αυτο πιω γενηθητω το θελημα σου'),
(953, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 43, 'NT', 'και ελθων ευρισκει αυτους παλιν καθευδοντας ησαν γαρ αυτων οι οφθαλμοι βεβαρημενοι'),
(954, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 44, 'NT', 'και αφεις αυτους απελθων παλιν προσηυξατο εκ τριτου τον αυτον λογον ειπων'),
(955, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 45, 'NT', 'τοτε ερχεται προς τους μαθητας αυτου και λεγει αυτοις καθευδετε το λοιπον και αναπαυεσθε ιδου ηγγικεν η ωρα και ο υιος του ανθρωπου παραδιδοται εις χειρας αμαρτωλων'),
(956, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 46, 'NT', 'εγειρεσθε αγωμεν ιδου ηγγικεν ο παραδιδους με'),
(957, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 47, 'NT', 'και ετι αυτου λαλουντος ιδου ιουδας εις των δωδεκα ηλθεν και μετ αυτου οχλος πολυς μετα μαχαιρων και ξυλων απο των αρχιερεων και πρεσβυτερων του λαου'),
(958, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 48, 'NT', 'ο δε παραδιδους αυτον εδωκεν αυτοις σημειον λεγων ον αν φιλησω αυτος εστιν κρατησατε αυτον'),
(959, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 49, 'NT', 'και ευθεως προσελθων τω ιησου ειπεν χαιρε ραββι και κατεφιλησεν αυτον'),
(960, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 50, 'NT', 'ο δε ιησους ειπεν αυτω εταιρε εφ ω παρει τοτε προσελθοντες επεβαλον τας χειρας επι τον ιησουν και εκρατησαν αυτον'),
(961, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 51, 'NT', 'και ιδου εις των μετα ιησου εκτεινας την χειρα απεσπασεν την μαχαιραν αυτου και παταξας τον δουλον του αρχιερεως αφειλεν αυτου το ωτιον'),
(962, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 52, 'NT', 'τοτε λεγει αυτω ο ιησους αποστρεψον σου την μαχαιραν εις τον τοπον αυτης παντες γαρ οι λαβοντες μαχαιραν εν μαχαιρα απολουνται'),
(963, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 53, 'NT', 'η δοκεις οτι ου δυναμαι αρτι παρακαλεσαι τον πατερα μου και παραστησει μοι πλειους η δωδεκα λεγεωνας αγγελων'),
(964, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 54, 'NT', 'πως ουν πληρωθωσιν αι γραφαι οτι ουτως δει γενεσθαι'),
(965, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 55, 'NT', 'εν εκεινη τη ωρα ειπεν ο ιησους τοις οχλοις ως επι ληστην εξηλθετε μετα μαχαιρων και ξυλων συλλαβειν με καθ ημεραν προς υμας εκαθεζομην διδασκων εν τω ιερω και ουκ εκρατησατε με'),
(966, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 56, 'NT', 'τουτο δε ολον γεγονεν ινα πληρωθωσιν αι γραφαι των προφητων τοτε οι μαθηται παντες αφεντες αυτον εφυγον'),
(967, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 57, 'NT', 'οι δε κρατησαντες τον ιησουν απηγαγον προς καιαφαν τον αρχιερεα οπου οι γραμματεις και οι πρεσβυτεροι συνηχθησαν'),
(968, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 58, 'NT', 'ο δε πετρος ηκολουθει αυτω απο μακροθεν εως της αυλης του αρχιερεως και εισελθων εσω εκαθητο μετα των υπηρετων ιδειν το τελος'),
(969, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 59, 'NT', 'οι δε αρχιερεις και οι πρεσβυτεροι και το συνεδριον ολον εζητουν ψευδομαρτυριαν κατα του ιησου οπως αυτον θανατωσωσιν'),
(970, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 60, 'NT', 'και ουχ ευρον και πολλων ψευδομαρτυρων προσελθοντων ουχ ευρον'),
(971, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 61, 'NT', 'υστερον δε προσελθοντες δυο ψευδομαρτυρες ειπον ουτος εφη δυναμαι καταλυσαι τον ναον του θεου και δια τριων ημερων οικοδομησαι αυτον'),
(972, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 62, 'NT', 'και αναστας ο αρχιερευς ειπεν αυτω ουδεν αποκρινη τι ουτοι σου καταμαρτυρουσιν'),
(973, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 63, 'NT', 'ο δε ιησους εσιωπα και αποκριθεις ο αρχιερευς ειπεν αυτω εξορκιζω σε κατα του θεου του ζωντος ινα ημιν ειπης ει συ ει ο χριστος ο υιος του θεου'),
(974, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 64, 'NT', 'λεγει αυτω ο ιησους συ ειπας πλην λεγω υμιν απ αρτι οψεσθε τον υιον του ανθρωπου καθημενον εκ δεξιων της δυναμεως και ερχομενον επι των νεφελων του ουρανου'),
(975, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 65, 'NT', 'τοτε ο αρχιερευς διερρηξεν τα ιματια αυτου λεγων οτι εβλασφημησεν τι ετι χρειαν εχομεν μαρτυρων ιδε νυν ηκουσατε την βλασφημιαν αυτου'),
(976, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 66, 'NT', 'τι υμιν δοκει οι δε αποκριθεντες ειπον ενοχος θανατου εστιν'),
(977, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 67, 'NT', 'τοτε ενεπτυσαν εις το προσωπον αυτου και εκολαφισαν αυτον οι δε ερραπισαν'),
(978, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 68, 'NT', 'λεγοντες προφητευσον ημιν χριστε τις εστιν ο παισας σε'),
(979, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 69, 'NT', 'ο δε πετρος εξω εκαθητο εν τη αυλη και προσηλθεν αυτω μια παιδισκη λεγουσα και συ ησθα μετα ιησου του γαλιλαιου'),
(980, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 70, 'NT', 'ο δε ηρνησατο εμπροσθεν παντων λεγων ουκ οιδα τι λεγεις'),
(981, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 71, 'NT', 'εξελθοντα δε αυτον εις τον πυλωνα ειδεν αυτον αλλη και λεγει τοις εκει και ουτος ην μετα ιησου του ναζωραιου'),
(982, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 72, 'NT', 'και παλιν ηρνησατο μεθ ορκου οτι ουκ οιδα τον ανθρωπον'),
(983, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 73, 'NT', 'μετα μικρον δε προσελθοντες οι εστωτες ειπον τω πετρω αληθως και συ εξ αυτων ει και γαρ η λαλια σου δηλον σε ποιει'),
(984, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 74, 'NT', 'τοτε ηρξατο καταναθεματιζειν και ομνυειν οτι ουκ οιδα τον ανθρωπον και ευθεως αλεκτωρ εφωνησεν'),
(985, 40, 'TR1550', 'TR1550', 'el', 'MAT', 26, 75, 'NT', 'και εμνησθη ο πετρος του ρηματος του ιησου ειρηκοτος αυτω οτι πριν αλεκτορα φωνησαι τρις απαρνηση με και εξελθων εξω εκλαυσεν πικρως'),
(986, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 1, 'NT', 'πρωιας δε γενομενης συμβουλιον ελαβον παντες οι αρχιερεις και οι πρεσβυτεροι του λαου κατα του ιησου ωστε θανατωσαι αυτον'),
(987, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 2, 'NT', 'και δησαντες αυτον απηγαγον και παρεδωκαν αυτον ποντιω πιλατω τω ηγεμονι'),
(988, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 3, 'NT', 'τοτε ιδων ιουδας ο παραδιδους αυτον οτι κατεκριθη μεταμεληθεις απεστρεψεν τα τριακοντα αργυρια τοις αρχιερευσιν και τοις πρεσβυτεροις'),
(989, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 4, 'NT', 'λεγων ημαρτον παραδους αιμα αθωον οι δε ειπον τι προς ημας συ οψει'),
(990, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 5, 'NT', 'και ριψας τα αργυρια εν τω ναω ανεχωρησεν και απελθων απηγξατο'),
(991, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 6, 'NT', 'οι δε αρχιερεις λαβοντες τα αργυρια ειπον ουκ εξεστιν βαλειν αυτα εις τον κορβαναν επει τιμη αιματος εστιν'),
(992, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 7, 'NT', 'συμβουλιον δε λαβοντες ηγορασαν εξ αυτων τον αγρον του κεραμεως εις ταφην τοις ξενοις'),
(993, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 8, 'NT', 'διο εκληθη ο αγρος εκεινος αγρος αιματος εως της σημερον'),
(994, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 9, 'NT', 'τοτε επληρωθη το ρηθεν δια ιερεμιου του προφητου λεγοντος και ελαβον τα τριακοντα αργυρια την τιμην του τετιμημενου ον ετιμησαντο απο υιων ισραηλ'),
(995, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 10, 'NT', 'και εδωκαν αυτα εις τον αγρον του κεραμεως καθα συνεταξεν μοι κυριος'),
(996, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 11, 'NT', 'ο δε ιησους εστη εμπροσθεν του ηγεμονος και επηρωτησεν αυτον ο ηγεμων λεγων συ ει ο βασιλευς των ιουδαιων ο δε ιησους εφη αυτω συ λεγεις'),
(997, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 12, 'NT', 'και εν τω κατηγορεισθαι αυτον υπο των αρχιερεων και των πρεσβυτερων ουδεν απεκρινατο'),
(998, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 13, 'NT', 'τοτε λεγει αυτω ο πιλατος ουκ ακουεις ποσα σου καταμαρτυρουσιν'),
(999, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 14, 'NT', 'και ουκ απεκριθη αυτω προς ουδε εν ρημα ωστε θαυμαζειν τον ηγεμονα λιαν'),
(1000, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 15, 'NT', 'κατα δε εορτην ειωθει ο ηγεμων απολυειν ενα τω οχλω δεσμιον ον ηθελον'),
(1001, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 16, 'NT', 'ειχον δε τοτε δεσμιον επισημον λεγομενον βαραββαν'),
(1002, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 17, 'NT', 'συνηγμενων ουν αυτων ειπεν αυτοις ο πιλατος τινα θελετε απολυσω υμιν βαραββαν η ιησουν τον λεγομενον χριστον'),
(1003, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 18, 'NT', 'ηδει γαρ οτι δια φθονον παρεδωκαν αυτον'),
(1004, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 19, 'NT', 'καθημενου δε αυτου επι του βηματος απεστειλεν προς αυτον η γυνη αυτου λεγουσα μηδεν σοι και τω δικαιω εκεινω πολλα γαρ επαθον σημερον κατ οναρ δι αυτον'),
(1005, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 20, 'NT', 'οι δε αρχιερεις και οι πρεσβυτεροι επεισαν τους οχλους ινα αιτησωνται τον βαραββαν τον δε ιησουν απολεσωσιν'),
(1006, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 21, 'NT', 'αποκριθεις δε ο ηγεμων ειπεν αυτοις τινα θελετε απο των δυο απολυσω υμιν οι δε ειπον βαραββαν'),
(1007, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 22, 'NT', 'λεγει αυτοις ο πιλατος τι ουν ποιησω ιησουν τον λεγομενον χριστον λεγουσιν αυτω παντες σταυρωθητω'),
(1008, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 23, 'NT', 'ο δε ηγεμων εφη τι γαρ κακον εποιησεν οι δε περισσως εκραζον λεγοντες σταυρωθητω'),
(1009, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 24, 'NT', 'ιδων δε ο πιλατος οτι ουδεν ωφελει αλλα μαλλον θορυβος γινεται λαβων υδωρ απενιψατο τας χειρας απεναντι του οχλου λεγων αθωος ειμι απο του αιματος του δικαιου τουτου υμεις οψεσθε'),
(1010, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 25, 'NT', 'και αποκριθεις πας ο λαος ειπεν το αιμα αυτου εφ ημας και επι τα τεκνα ημων'),
(1011, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 26, 'NT', 'τοτε απελυσεν αυτοις τον βαραββαν τον δε ιησουν φραγελλωσας παρεδωκεν ινα σταυρωθη'),
(1012, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 27, 'NT', 'τοτε οι στρατιωται του ηγεμονος παραλαβοντες τον ιησουν εις το πραιτωριον συνηγαγον επ αυτον ολην την σπειραν'),
(1013, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 28, 'NT', 'και εκδυσαντες αυτον περιεθηκαν αυτω χλαμυδα κοκκινην'),
(1014, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 29, 'NT', 'και πλεξαντες στεφανον εξ ακανθων επεθηκαν επι την κεφαλην αυτου και καλαμον επι την δεξιαν αυτου και γονυπετησαντες εμπροσθεν αυτου ενεπαιζον αυτω λεγοντες χαιρε ο βασιλευς των ιουδαιων'),
(1015, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 30, 'NT', 'και εμπτυσαντες εις αυτον ελαβον τον καλαμον και ετυπτον εις την κεφαλην αυτου'),
(1016, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 31, 'NT', 'και οτε ενεπαιξαν αυτω εξεδυσαν αυτον την χλαμυδα και ενεδυσαν αυτον τα ιματια αυτου και απηγαγον αυτον εις το σταυρωσαι'),
(1017, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 32, 'NT', 'εξερχομενοι δε ευρον ανθρωπον κυρηναιον ονοματι σιμωνα τουτον ηγγαρευσαν ινα αρη τον σταυρον αυτου'),
