(1020, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 35, 'NT', 'σταυρωσαντες δε αυτον διεμερισαντο τα ιματια αυτου βαλλοντες κληρον ινα πληρωθη το ρηθεν υπο του προφητου διεμερισαντο τα ιματια μου εαυτοις και επι τον ιματισμον μου εβαλον κληρον'),
(1021, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 36, 'NT', 'και καθημενοι ετηρουν αυτον εκει'),
(1022, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 37, 'NT', 'και επεθηκαν επανω της κεφαλης αυτου την αιτιαν αυτου γεγραμμενην ουτος εστιν ιησους ο βασιλευς των ιουδαιων'),
(1023, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 38, 'NT', 'τοτε σταυρουνται συν αυτω δυο λησται εις εκ δεξιων και εις εξ ευωνυμων'),
