(1026, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 41, 'NT', 'ομοιως δε και οι αρχιερεις εμπαιζοντες μετα των γραμματεων και πρεσβυτερων ελεγον'),
(1027, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 42, 'NT', 'αλλους εσωσεν εαυτον ου δυναται σωσαι ει βασιλευς ισραηλ εστιν καταβατω νυν απο του σταυρου και πιστευσομεν αυτω'),
(1028, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 43, 'NT', 'πεποιθεν επι τον θεον ρυσασθω νυν αυτον ει θελει αυτον ειπεν γαρ οτι θεου ειμι υιος'),
(1029, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 44, 'NT', 'το δ αυτο και οι λησται οι συσταυρωθεντες αυτω ωνειδιζον αυτω'),
(1030, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 45, 'NT', 'απο δε εκτης ωρας σκοτος εγενετο επι πασαν την γην εως ωρας εννατης'),
(1031, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 46, 'NT', 'περι δε την εννατην ωραν ανεβοησεν ο ιησους φωνη μεγαλη λεγων ηλι ηλι λαμα σαβαχθανι τουτ εστιν θεε μου θεε μου ινα τι με εγκατελιπες'),
(1032, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 47, 'NT', 'τινες δε των εκει εστωτων ακουσαντες ελεγον οτι ηλιαν φωνει ουτος'),
(1033, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 48, 'NT', 'και ευθεως δραμων εις εξ αυτων και λαβων σπογγον πλησας τε οξους και περιθεις καλαμω εποτιζεν αυτον'),
(1034, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 49, 'NT', 'οι δε λοιποι ελεγον αφες ιδωμεν ει ερχεται ηλιας σωσων αυτον'),
(1035, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 50, 'NT', 'ο δε ιησους παλιν κραξας φωνη μεγαλη αφηκεν το πνευμα'),
(1036, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 51, 'NT', 'και ιδου το καταπετασμα του ναου εσχισθη εις δυο απο ανωθεν εως κατω και η γη εσεισθη και αι πετραι εσχισθησαν'),
