(1038, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 53, 'NT', 'και εξελθοντες εκ των μνημειων μετα την εγερσιν αυτου εισηλθον εις την αγιαν πολιν και ενεφανισθησαν πολλοις'),
(1039, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 54, 'NT', 'ο δε εκατονταρχος και οι μετ αυτου τηρουντες τον ιησουν ιδοντες τον σεισμον και τα γενομενα εφοβηθησαν σφοδρα λεγοντες αληθως θεου υιος ην ουτος'),
(1040, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 55, 'NT', 'ησαν δε εκει γυναικες πολλαι απο μακροθεν θεωρουσαι αιτινες ηκολουθησαν τω ιησου απο της γαλιλαιας διακονουσαι αυτω'),
(1041, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 56, 'NT', 'εν αις ην μαρια η μαγδαληνη και μαρια η του ιακωβου και ιωση μητηρ και η μητηρ των υιων ζεβεδαιου'),
(1042, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 57, 'NT', 'οψιας δε γενομενης ηλθεν ανθρωπος πλουσιος απο αριμαθαιας τουνομα ιωσηφ ος και αυτος εμαθητευσεν τω ιησου'),
(1043, 40, 'TR1550', 'TR1550', 'el', 'MAT', 27, 58, 'NT', 'ουτος προσελθων τω πιλατω ητησατο το σωμα του ιησου τοτε ο πιλατος εκελευσεν αποδοθηναι το σωμα'),
