(1303, 41, 'TR1550', 'TR1550', 'el', 'MRK', 6, 40, 'NT', 'και ανεπεσον πρασιαι πρασιαι ανα εκατον και ανα πεντηκοντα'),
(1304, 41, 'TR1550', 'TR1550', 'el', 'MRK', 6, 41, 'NT', 'και λαβων τους πεντε αρτους και τους δυο ιχθυας αναβλεψας εις τον ουρανον ευλογησεν και κατεκλασεν τους αρτους και εδιδου τοις μαθηταις αυτου ινα παραθωσιν αυτοις και τους δυο ιχθυας εμερισεν πασιν'),
(1305, 41, 'TR1550', 'TR1550', 'el', 'MRK', 6, 42, 'NT', 'και εφαγον παντες και εχορτασθησαν'),
(1306, 41, 'TR1550', 'TR1550', 'el', 'MRK', 6, 43, 'NT', 'και ηραν κλασματων δωδεκα κοφινους πληρεις και απο των ιχθυων'),
(1307, 41, 'TR1550', 'TR1550', 'el', 'MRK', 6, 44, 'NT', 'και ησαν οι φαγοντες τους αρτους ωσει πεντακισχιλιοι ανδρες'),
(1308, 41, 'TR1550', 'TR1550', 'el', 'MRK', 6, 45, 'NT', 'και ευθεως ηναγκασεν τους μαθητας αυτου εμβηναι εις το πλοιον και προαγειν εις το περαν προς βηθσαιδαν εως αυτος απολυση τον οχλον'),
(1309, 41, 'TR1550', 'TR1550', 'el', 'MRK', 6, 46, 'NT', 'και αποταξαμενος αυτοις απηλθεν εις το ορος προσευξασθαι'),
(1310, 41, 'TR1550', 'TR1550', 'el', 'MRK', 6, 47, 'NT', 'και οψιας γενομενης ην το πλοιον εν μεσω της θαλασσης και αυτος μονος επι της γης'),
(1311, 41, 'TR1550', 'TR1550', 'el', 'MRK', 6, 48, 'NT', 'και ειδεν αυτους βασανιζομενους εν τω ελαυνειν ην γαρ ο ανεμος εναντιος αυτοις και περι τεταρτην φυλακην της νυκτος ερχεται προς αυτους περιπατων επι της θαλασσης και ηθελεν παρελθειν αυτους'),
(1312, 41, 'TR1550', 'TR1550', 'el', 'MRK', 6, 49, 'NT', 'οι δε ιδοντες αυτον περιπατουντα επι της θαλασσης εδοξαν φαντασμα ειναι και ανεκραξαν'),
(1313, 41, 'TR1550', 'TR1550', 'el', 'MRK', 6, 50, 'NT', 'παντες γαρ αυτον ειδον και εταραχθησαν και ευθεως ελαλησεν μετ αυτων και λεγει αυτοις θαρσειτε εγω ειμι μη φοβεισθε'),
(1314, 41, 'TR1550', 'TR1550', 'el', 'MRK', 6, 51, 'NT', 'και ανεβη προς αυτους εις το πλοιον και εκοπασεν ο ανεμος και λιαν εκ περισσου εν εαυτοις εξισταντο και εθαυμαζον'),
(1315, 41, 'TR1550', 'TR1550', 'el', 'MRK', 6, 52, 'NT', 'ου γαρ συνηκαν επι τοις αρτοις ην γαρ η καρδια αυτων πεπωρωμενη'),
(1316, 41, 'TR1550', 'TR1550', 'el', 'MRK', 6, 53, 'NT', 'και διαπερασαντες ηλθον επι την γην γενησαρετ και προσωρμισθησαν'),
(1317, 41, 'TR1550', 'TR1550', 'el', 'MRK', 6, 54, 'NT', 'και εξελθοντων αυτων εκ του πλοιου ευθεως επιγνοντες αυτον'),
(1318, 41, 'TR1550', 'TR1550', 'el', 'MRK', 6, 55, 'NT', 'περιδραμοντες ολην την περιχωρον εκεινην ηρξαντο επι τοις κραββατοις τους κακως εχοντας περιφερειν οπου ηκουον οτι εκει εστιν'),
(1319, 41, 'TR1550', 'TR1550', 'el', 'MRK', 6, 56, 'NT', 'και οπου αν εισεπορευετο εις κωμας η πολεις η αγρους εν ταις αγοραις ετιθουν τους ασθενουντας και παρεκαλουν αυτον ινα καν του κρασπεδου του ιματιου αυτου αψωνται και οσοι αν ηπτοντο αυτου εσωζοντο'),
(1320, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 1, 'NT', 'και συναγονται προς αυτον οι φαρισαιοι και τινες των γραμματεων ελθοντες απο ιεροσολυμων'),
(1321, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 2, 'NT', 'και ιδοντες τινας των μαθητων αυτου κοιναις χερσιν τουτ εστιν ανιπτοις εσθιοντας αρτους εμεμψαντο'),
(1322, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 3, 'NT', 'οι γαρ φαρισαιοι και παντες οι ιουδαιοι εαν μη πυγμη νιψωνται τας χειρας ουκ εσθιουσιν κρατουντες την παραδοσιν των πρεσβυτερων'),
(1323, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 4, 'NT', 'και απο αγορας εαν μη βαπτισωνται ουκ εσθιουσιν και αλλα πολλα εστιν α παρελαβον κρατειν βαπτισμους ποτηριων και ξεστων και χαλκιων και κλινων'),
(1324, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 5, 'NT', 'επειτα επερωτωσιν αυτον οι φαρισαιοι και οι γραμματεις δια τι οι μαθηται σου ου περιπατουσιν κατα την παραδοσιν των πρεσβυτερων αλλα ανιπτοις χερσιν εσθιουσιν τον αρτον'),
(1325, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 6, 'NT', 'ο δε αποκριθεις ειπεν αυτοις οτι καλως προεφητευσεν ησαιας περι υμων των υποκριτων ως γεγραπται ουτος ο λαος τοις χειλεσιν με τιμα η δε καρδια αυτων πορρω απεχει απ εμου'),
(1326, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 7, 'NT', 'ματην δε σεβονται με διδασκοντες διδασκαλιας ενταλματα ανθρωπων'),
(1327, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 8, 'NT', 'αφεντες γαρ την εντολην του θεου κρατειτε την παραδοσιν των ανθρωπων βαπτισμους ξεστων και ποτηριων και αλλα παρομοια τοιαυτα πολλα ποιειτε'),
(1328, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 9, 'NT', 'και ελεγεν αυτοις καλως αθετειτε την εντολην του θεου ινα την παραδοσιν υμων τηρησητε'),
(1329, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 10, 'NT', 'μωσης γαρ ειπεν τιμα τον πατερα σου και την μητερα σου και ο κακολογων πατερα η μητερα θανατω τελευτατω'),
(1330, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 11, 'NT', 'υμεις δε λεγετε εαν ειπη ανθρωπος τω πατρι η τη μητρι κορβαν ο εστιν δωρον ο εαν εξ εμου ωφεληθης'),
(1331, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 12, 'NT', 'και ουκετι αφιετε αυτον ουδεν ποιησαι τω πατρι αυτου η τη μητρι αυτου'),
(1332, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 13, 'NT', 'ακυρουντες τον λογον του θεου τη παραδοσει υμων η παρεδωκατε και παρομοια τοιαυτα πολλα ποιειτε'),
(1333, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 14, 'NT', 'και προσκαλεσαμενος παντα τον οχλον ελεγεν αυτοις ακουετε μου παντες και συνιετε'),
(1334, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 15, 'NT', 'ουδεν εστιν εξωθεν του ανθρωπου εισπορευομενον εις αυτον ο δυναται αυτον κοινωσαι αλλα τα εκπορευομενα απ αυτου εκεινα εστιν τα κοινουντα τον ανθρωπον'),
(1335, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 16, 'NT', 'ει τις εχει ωτα ακουειν ακουετω'),
(1336, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 17, 'NT', 'και οτε εισηλθεν εις οικον απο του οχλου επηρωτων αυτον οι μαθηται αυτου περι της παραβολης'),
(1337, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 18, 'NT', 'και λεγει αυτοις ουτως και υμεις ασυνετοι εστε ου νοειτε οτι παν το εξωθεν εισπορευομενον εις τον ανθρωπον ου δυναται αυτον κοινωσαι'),
(1338, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 19, 'NT', 'οτι ουκ εισπορευεται αυτου εις την καρδιαν αλλ εις την κοιλιαν και εις τον αφεδρωνα εκπορευεται καθαριζον παντα τα βρωματα'),
(1339, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 20, 'NT', 'ελεγεν δε οτι το εκ του ανθρωπου εκπορευομενον εκεινο κοινοι τον ανθρωπον'),
(1340, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 21, 'NT', 'εσωθεν γαρ εκ της καρδιας των ανθρωπων οι διαλογισμοι οι κακοι εκπορευονται μοιχειαι πορνειαι φονοι'),
(1341, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 22, 'NT', 'κλοπαι πλεονεξιαι πονηριαι δολος ασελγεια οφθαλμος πονηρος βλασφημια υπερηφανια αφροσυνη'),
(1342, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 23, 'NT', 'παντα ταυτα τα πονηρα εσωθεν εκπορευεται και κοινοι τον ανθρωπον'),
(1343, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 24, 'NT', 'και εκειθεν αναστας απηλθεν εις τα μεθορια τυρου και σιδωνος και εισελθων εις την οικιαν ουδενα ηθελεν γνωναι και ουκ ηδυνηθη λαθειν'),
(1344, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 25, 'NT', 'ακουσασα γαρ γυνη περι αυτου ης ειχεν το θυγατριον αυτης πνευμα ακαθαρτον ελθουσα προσεπεσεν προς τους ποδας αυτου'),
(1345, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 26, 'NT', 'ην δε η γυνη ελληνις συροφοινισσα τω γενει και ηρωτα αυτον ινα το δαιμονιον εκβαλλη εκ της θυγατρος αυτης'),
(1346, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 27, 'NT', 'ο δε ιησους ειπεν αυτη αφες πρωτον χορτασθηναι τα τεκνα ου γαρ καλον εστιν λαβειν τον αρτον των τεκνων και βαλειν τοις κυναριοις'),
(1347, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 28, 'NT', 'η δε απεκριθη και λεγει αυτω ναι κυριε και γαρ τα κυναρια υποκατω της τραπεζης εσθιει απο των ψιχιων των παιδιων'),
(1348, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 29, 'NT', 'και ειπεν αυτη δια τουτον τον λογον υπαγε εξεληλυθεν το δαιμονιον εκ της θυγατρος σου'),
(1349, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 30, 'NT', 'και απελθουσα εις τον οικον αυτης ευρεν το δαιμονιον εξεληλυθος και την θυγατερα βεβλημενην επι της κλινης'),
(1350, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 31, 'NT', 'και παλιν εξελθων εκ των οριων τυρου και σιδωνος ηλθεν προς την θαλασσαν της γαλιλαιας ανα μεσον των οριων δεκαπολεως'),
(1351, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 32, 'NT', 'και φερουσιν αυτω κωφον μογιλαλον και παρακαλουσιν αυτον ινα επιθη αυτω την χειρα'),
(1352, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 33, 'NT', 'και απολαβομενος αυτον απο του οχλου κατ ιδιαν εβαλεν τους δακτυλους αυτου εις τα ωτα αυτου και πτυσας ηψατο της γλωσσης αυτου'),
(1353, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 34, 'NT', 'και αναβλεψας εις τον ουρανον εστεναξεν και λεγει αυτω εφφαθα ο εστιν διανοιχθητι'),
(1354, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 35, 'NT', 'και ευθεως διηνοιχθησαν αυτου αι ακοαι και ελυθη ο δεσμος της γλωσσης αυτου και ελαλει ορθως'),
(1355, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 36, 'NT', 'και διεστειλατο αυτοις ινα μηδενι ειπωσιν οσον δε αυτος αυτοις διεστελλετο μαλλον περισσοτερον εκηρυσσον'),
(1356, 41, 'TR1550', 'TR1550', 'el', 'MRK', 7, 37, 'NT', 'και υπερπερισσως εξεπλησσοντο λεγοντες καλως παντα πεποιηκεν και τους κωφους ποιει ακουειν και τους αλαλους λαλειν'),
(1357, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 1, 'NT', 'εν εκειναις ταις ημεραις παμπολλου οχλου οντος και μη εχοντων τι φαγωσιν προσκαλεσαμενος ο ιησους τους μαθητας αυτου λεγει αυτοις'),
(1358, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 2, 'NT', 'σπλαγχνιζομαι επι τον οχλον οτι ηδη ημερας τρεις προσμενουσιν μοι και ουκ εχουσιν τι φαγωσιν'),
(1359, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 3, 'NT', 'και εαν απολυσω αυτους νηστεις εις οικον αυτων εκλυθησονται εν τη οδω τινες γαρ αυτων μακροθεν ηκασιν'),
(1360, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 4, 'NT', 'και απεκριθησαν αυτω οι μαθηται αυτου ποθεν τουτους δυνησεται τις ωδε χορτασαι αρτων επ ερημιας'),
(1361, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 5, 'NT', 'και επηρωτα αυτους ποσους εχετε αρτους οι δε ειπον επτα'),
(1362, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 6, 'NT', 'και παρηγγειλεν τω οχλω αναπεσειν επι της γης και λαβων τους επτα αρτους ευχαριστησας εκλασεν και εδιδου τοις μαθηταις αυτου ινα παραθωσιν και παρεθηκαν τω οχλω'),
(1363, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 7, 'NT', 'και ειχον ιχθυδια ολιγα και ευλογησας ειπεν παραθειναι και αυτα'),
(1364, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 8, 'NT', 'εφαγον δε και εχορτασθησαν και ηραν περισσευματα κλασματων επτα σπυριδας'),
(1365, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 9, 'NT', 'ησαν δε οι φαγοντες ως τετρακισχιλιοι και απελυσεν αυτους'),
(1366, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 10, 'NT', 'και ευθεως εμβας εις το πλοιον μετα των μαθητων αυτου ηλθεν εις τα μερη δαλμανουθα'),
(1367, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 11, 'NT', 'και εξηλθον οι φαρισαιοι και ηρξαντο συζητειν αυτω ζητουντες παρ αυτου σημειον απο του ουρανου πειραζοντες αυτον'),
(1368, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 12, 'NT', 'και αναστεναξας τω πνευματι αυτου λεγει τι η γενεα αυτη σημειον επιζητει αμην λεγω υμιν ει δοθησεται τη γενεα ταυτη σημειον'),
(1369, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 13, 'NT', 'και αφεις αυτους εμβας παλιν εις το πλοιον απηλθεν εις το περαν'),
(1370, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 14, 'NT', 'και επελαθοντο λαβειν αρτους και ει μη ενα αρτον ουκ ειχον μεθ εαυτων εν τω πλοιω'),
(1371, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 15, 'NT', 'και διεστελλετο αυτοις λεγων ορατε βλεπετε απο της ζυμης των φαρισαιων και της ζυμης ηρωδου'),
(1372, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 16, 'NT', 'και διελογιζοντο προς αλληλους λεγοντες οτι αρτους ουκ εχομεν'),
(1373, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 17, 'NT', 'και γνους ο ιησους λεγει αυτοις τι διαλογιζεσθε οτι αρτους ουκ εχετε ουπω νοειτε ουδε συνιετε ετι πεπωρωμενην εχετε την καρδιαν υμων'),
(1374, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 18, 'NT', 'οφθαλμους εχοντες ου βλεπετε και ωτα εχοντες ουκ ακουετε και ου μνημονευετε'),
(1375, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 19, 'NT', 'οτε τους πεντε αρτους εκλασα εις τους πεντακισχιλιους ποσους κοφινους πληρεις κλασματων ηρατε λεγουσιν αυτω δωδεκα'),
(1376, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 20, 'NT', 'οτε δε τους επτα εις τους τετρακισχιλιους ποσων σπυριδων πληρωματα κλασματων ηρατε οι δε ειπον επτα'),
(1377, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 21, 'NT', 'και ελεγεν αυτοις πως ου συνιετε'),
(1378, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 22, 'NT', 'και ερχεται εις βηθσαιδαν και φερουσιν αυτω τυφλον και παρακαλουσιν αυτον ινα αυτου αψηται'),
(1379, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 23, 'NT', 'και επιλαβομενος της χειρος του τυφλου εξηγαγεν αυτον εξω της κωμης και πτυσας εις τα ομματα αυτου επιθεις τας χειρας αυτω επηρωτα αυτον ει τι βλεπει'),
(1380, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 24, 'NT', 'και αναβλεψας ελεγεν βλεπω τους ανθρωπους οτι ως δενδρα ορω περιπατουντας'),
(1381, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 25, 'NT', 'ειτα παλιν επεθηκεν τας χειρας επι τους οφθαλμους αυτου και εποιησεν αυτον αναβλεψαι και αποκατεσταθη και ενεβλεψεν τηλαυγως απαντας'),
(1382, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 26, 'NT', 'και απεστειλεν αυτον εις τον οικον αυτου λεγων μηδε εις την κωμην εισελθης μηδε ειπης τινι εν τη κωμη'),
(1383, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 27, 'NT', 'και εξηλθεν ο ιησους και οι μαθηται αυτου εις τας κωμας καισαρειας της φιλιππου και εν τη οδω επηρωτα τους μαθητας αυτου λεγων αυτοις τινα με λεγουσιν οι ανθρωποι ειναι'),
(1384, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 28, 'NT', 'οι δε απεκριθησαν ιωαννην τον βαπτιστην και αλλοι ηλιαν αλλοι δε ενα των προφητων'),
(1385, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 29, 'NT', 'και αυτος λεγει αυτοις υμεις δε τινα με λεγετε ειναι αποκριθεις δε ο πετρος λεγει αυτω συ ει ο χριστος'),
(1386, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 30, 'NT', 'και επετιμησεν αυτοις ινα μηδενι λεγωσιν περι αυτου'),
(1387, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 31, 'NT', 'και ηρξατο διδασκειν αυτους οτι δει τον υιον του ανθρωπου πολλα παθειν και αποδοκιμασθηναι απο των πρεσβυτερων και αρχιερεων και γραμματεων και αποκτανθηναι και μετα τρεις ημερας αναστηναι'),
(1388, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 32, 'NT', 'και παρρησια τον λογον ελαλει και προσλαβομενος αυτον ο πετρος ηρξατο επιτιμαν αυτω'),
(1389, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 33, 'NT', 'ο δε επιστραφεις και ιδων τους μαθητας αυτου επετιμησεν τω πετρω λεγων υπαγε οπισω μου σατανα οτι ου φρονεις τα του θεου αλλα τα των ανθρωπων'),
(1390, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 34, 'NT', 'και προσκαλεσαμενος τον οχλον συν τοις μαθηταις αυτου ειπεν αυτοις οστις θελει οπισω μου ελθειν απαρνησασθω εαυτον και αρατω τον σταυρον αυτου και ακολουθειτω μοι'),
(1391, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 35, 'NT', 'ος γαρ αν θελη την ψυχην αυτου σωσαι απολεσει αυτην ος δ αν απολεση την ψυχην αυτου ενεκεν εμου και του ευαγγελιου ουτος σωσει αυτην'),
(1392, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 36, 'NT', 'τι γαρ ωφελησει ανθρωπον εαν κερδηση τον κοσμον ολον και ζημιωθη την ψυχην αυτου'),
(1393, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 37, 'NT', 'η τι δωσει ανθρωπος ανταλλαγμα της ψυχης αυτου'),
(1394, 41, 'TR1550', 'TR1550', 'el', 'MRK', 8, 38, 'NT', 'ος γαρ αν επαισχυνθη με και τους εμους λογους εν τη γενεα ταυτη τη μοιχαλιδι και αμαρτωλω και ο υιος του ανθρωπου επαισχυνθησεται αυτον οταν ελθη εν τη δοξη του πατρος αυτου μετα των αγγελων των αγιων'),
(1395, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 1, 'NT', 'και ελεγεν αυτοις αμην λεγω υμιν οτι εισιν τινες των ωδε εστηκοτων οιτινες ου μη γευσωνται θανατου εως αν ιδωσιν την βασιλειαν του θεου εληλυθυιαν εν δυναμει'),
(1396, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 2, 'NT', 'και μεθ ημερας εξ παραλαμβανει ο ιησους τον πετρον και τον ιακωβον και τον ιωαννην και αναφερει αυτους εις ορος υψηλον κατ ιδιαν μονους και μετεμορφωθη εμπροσθεν αυτων'),
(1397, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 3, 'NT', 'και τα ιματια αυτου εγενετο στιλβοντα λευκα λιαν ως χιων οια γναφευς επι της γης ου δυναται λευκαναι'),
(1398, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 4, 'NT', 'και ωφθη αυτοις ηλιας συν μωσει και ησαν συλλαλουντες τω ιησου'),
(1399, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 5, 'NT', 'και αποκριθεις ο πετρος λεγει τω ιησου ραββι καλον εστιν ημας ωδε ειναι και ποιησωμεν σκηνας τρεις σοι μιαν και μωσει μιαν και ηλια μιαν'),
(1400, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 6, 'NT', 'ου γαρ ηδει τι λαληση ησαν γαρ εκφοβοι'),
(1401, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 7, 'NT', 'και εγενετο νεφελη επισκιαζουσα αυτοις και ηλθεν φωνη εκ της νεφελης λεγουσα ουτος εστιν ο υιος μου ο αγαπητος αυτου ακουετε'),
(1402, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 8, 'NT', 'και εξαπινα περιβλεψαμενοι ουκετι ουδενα ειδον αλλα τον ιησουν μονον μεθ εαυτων'),
(1403, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 9, 'NT', 'καταβαινοντων δε αυτων απο του ορους διεστειλατο αυτοις ινα μηδενι διηγησωνται α ειδον ει μη οταν ο υιος του ανθρωπου εκ νεκρων αναστη'),
(1404, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 10, 'NT', 'και τον λογον εκρατησαν προς εαυτους συζητουντες τι εστιν το εκ νεκρων αναστηναι'),
(1405, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 11, 'NT', 'και επηρωτων αυτον λεγοντες οτι λεγουσιν οι γραμματεις οτι ηλιαν δει ελθειν πρωτον'),
(1406, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 12, 'NT', 'ο δε αποκριθεις ειπεν αυτοις ηλιας μεν ελθων πρωτον αποκαθιστα παντα και πως γεγραπται επι τον υιον του ανθρωπου ινα πολλα παθη και εξουδενωθη'),
(1407, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 13, 'NT', 'αλλα λεγω υμιν οτι και ηλιας εληλυθεν και εποιησαν αυτω οσα ηθελησαν καθως γεγραπται επ αυτον'),
(1408, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 14, 'NT', 'και ελθων προς τους μαθητας ειδεν οχλον πολυν περι αυτους και γραμματεις συζητουντας αυτοις'),
(1409, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 15, 'NT', 'και ευθεως πας ο οχλος ιδων αυτον εξεθαμβηθη και προστρεχοντες ησπαζοντο αυτον'),
(1410, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 16, 'NT', 'και επηρωτησεν τους γραμματεις τι συζητειτε προς αυτους'),
(1411, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 17, 'NT', 'και αποκριθεις εις εκ του οχλου ειπεν διδασκαλε ηνεγκα τον υιον μου προς σε εχοντα πνευμα αλαλον'),
(1412, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 18, 'NT', 'και οπου αν αυτον καταλαβη ρησσει αυτον και αφριζει και τριζει τους οδοντας αυτου και ξηραινεται και ειπον τοις μαθηταις σου ινα αυτο εκβαλωσιν και ουκ ισχυσαν'),
(1413, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 19, 'NT', 'ο δε αποκριθεις αυτω λεγει ω γενεα απιστος εως ποτε προς υμας εσομαι εως ποτε ανεξομαι υμων φερετε αυτον προς με'),
(1414, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 20, 'NT', 'και ηνεγκαν αυτον προς αυτον και ιδων αυτον ευθεως το πνευμα εσπαραξεν αυτον και πεσων επι της γης εκυλιετο αφριζων'),
(1415, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 21, 'NT', 'και επηρωτησεν τον πατερα αυτου ποσος χρονος εστιν ως τουτο γεγονεν αυτω ο δε ειπεν παιδιοθεν'),
(1416, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 22, 'NT', 'και πολλακις αυτον και εις πυρ εβαλεν και εις υδατα ινα απολεση αυτον αλλ ει τι δυνασαι βοηθησον ημιν σπλαγχνισθεις εφ ημας'),
(1417, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 23, 'NT', 'ο δε ιησους ειπεν αυτω το ει δυνασαι πιστευσαι παντα δυνατα τω πιστευοντι'),
(1418, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 24, 'NT', 'και ευθεως κραξας ο πατηρ του παιδιου μετα δακρυων ελεγεν πιστευω κυριε βοηθει μου τη απιστια'),
(1419, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 25, 'NT', 'ιδων δε ο ιησους οτι επισυντρεχει οχλος επετιμησεν τω πνευματι τω ακαθαρτω λεγων αυτω το πνευμα το αλαλον και κωφον εγω σοι επιτασσω εξελθε εξ αυτου και μηκετι εισελθης εις αυτον'),
(1420, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 26, 'NT', 'και κραξαν και πολλα σπαραξαν αυτον εξηλθεν και εγενετο ωσει νεκρος ωστε πολλους λεγειν οτι απεθανεν'),
(1421, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 27, 'NT', 'ο δε ιησους κρατησας αυτον της χειρος ηγειρεν αυτον και ανεστη'),
(1422, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 28, 'NT', 'και εισελθοντα αυτον εις οικον οι μαθηται αυτου επηρωτων αυτον κατ ιδιαν οτι ημεις ουκ ηδυνηθημεν εκβαλειν αυτο'),
(1423, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 29, 'NT', 'και ειπεν αυτοις τουτο το γενος εν ουδενι δυναται εξελθειν ει μη εν προσευχη και νηστεια'),
(1424, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 30, 'NT', 'και εκειθεν εξελθοντες παρεπορευοντο δια της γαλιλαιας και ουκ ηθελεν ινα τις γνω'),
(1425, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 31, 'NT', 'εδιδασκεν γαρ τους μαθητας αυτου και ελεγεν αυτοις οτι ο υιος του ανθρωπου παραδιδοται εις χειρας ανθρωπων και αποκτενουσιν αυτον και αποκτανθεις τη τριτη ημερα αναστησεται'),
(1426, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 32, 'NT', 'οι δε ηγνοουν το ρημα και εφοβουντο αυτον επερωτησαι'),
(1427, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 33, 'NT', 'και ηλθεν εις καπερναουμ και εν τη οικια γενομενος επηρωτα αυτους τι εν τη οδω προς εαυτους διελογιζεσθε'),
(1428, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 34, 'NT', 'οι δε εσιωπων προς αλληλους γαρ διελεχθησαν εν τη οδω τις μειζων'),
(1429, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 35, 'NT', 'και καθισας εφωνησεν τους δωδεκα και λεγει αυτοις ει τις θελει πρωτος ειναι εσται παντων εσχατος και παντων διακονος'),
(1430, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 36, 'NT', 'και λαβων παιδιον εστησεν αυτο εν μεσω αυτων και εναγκαλισαμενος αυτο ειπεν αυτοις'),
(1431, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 37, 'NT', 'ος εαν εν των τοιουτων παιδιων δεξηται επι τω ονοματι μου εμε δεχεται και ος εαν εμε δεξηται ουκ εμε δεχεται αλλα τον αποστειλαντα με'),
(1432, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 38, 'NT', 'απεκριθη δε αυτω ο ιωαννης λεγων διδασκαλε ειδομεν τινα τω ονοματι σου εκβαλλοντα δαιμονια ος ουκ ακολουθει ημιν και εκωλυσαμεν αυτον οτι ουκ ακολουθει ημιν'),
(1433, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 39, 'NT', 'ο δε ιησους ειπεν μη κωλυετε αυτον ουδεις γαρ εστιν ος ποιησει δυναμιν επι τω ονοματι μου και δυνησεται ταχυ κακολογησαι με'),
(1434, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 40, 'NT', 'ος γαρ ουκ εστιν καθ υμων υπερ υμων εστιν'),
(1435, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 41, 'NT', 'ος γαρ αν ποτιση υμας ποτηριον υδατος εν τω ονοματι μου οτι χριστου εστε αμην λεγω υμιν ου μη απολεση τον μισθον αυτου'),
(1436, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 42, 'NT', 'και ος αν σκανδαλιση ενα των μικρων των πιστευοντων εις εμε καλον εστιν αυτω μαλλον ει περικειται λιθος μυλικος περι τον τραχηλον αυτου και βεβληται εις την θαλασσαν'),
(1437, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 43, 'NT', 'και εαν σκανδαλιζη σε η χειρ σου αποκοψον αυτην καλον σοι εστιν κυλλον εις την ζωην εισελθειν η τας δυο χειρας εχοντα απελθειν εις την γεενναν εις το πυρ το ασβεστον'),
(1438, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 44, 'NT', 'οπου ο σκωληξ αυτων ου τελευτα και το πυρ ου σβεννυται'),
(1439, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 45, 'NT', 'και εαν ο πους σου σκανδαλιζη σε αποκοψον αυτον καλον εστιν σοι εισελθειν εις την ζωην χωλον η τους δυο ποδας εχοντα βληθηναι εις την γεενναν εις το πυρ το ασβεστον'),
(1440, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 46, 'NT', 'οπου ο σκωληξ αυτων ου τελευτα και το πυρ ου σβεννυται'),
(1441, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 47, 'NT', 'και εαν ο οφθαλμος σου σκανδαλιζη σε εκβαλε αυτον καλον σοι εστιν μονοφθαλμον εισελθειν εις την βασιλειαν του θεου η δυο οφθαλμους εχοντα βληθηναι εις την γεενναν του πυρος'),
(1442, 41, 'TR1550', 'TR1550', 'el', 'MRK', 9, 48, 'NT', 'οπου ο σκωληξ αυτων ου τελευτα και το πυρ ου σβεννυται'),
