(1462, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 18, 'NT', 'ο δε ιησους ειπεν αυτω τι με λεγεις αγαθον ουδεις αγαθος ει μη εις ο θεος'),
(1463, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 19, 'NT', 'τας εντολας οιδας μη μοιχευσης μη φονευσης μη κλεψης μη ψευδομαρτυρησης μη αποστερησης τιμα τον πατερα σου και την μητερα'),
(1464, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 20, 'NT', 'ο δε αποκριθεις ειπεν αυτω διδασκαλε ταυτα παντα εφυλαξαμην εκ νεοτητος μου'),
(1465, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 21, 'NT', 'ο δε ιησους εμβλεψας αυτω ηγαπησεν αυτον και ειπεν αυτω εν σοι υστερει υπαγε οσα εχεις πωλησον και δος τοις πτωχοις και εξεις θησαυρον εν ουρανω και δευρο ακολουθει μοι αρας τον σταυρον'),
(1466, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 22, 'NT', 'ο δε στυγνασας επι τω λογω απηλθεν λυπουμενος ην γαρ εχων κτηματα πολλα'),
(1467, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 23, 'NT', 'και περιβλεψαμενος ο ιησους λεγει τοις μαθηταις αυτου πως δυσκολως οι τα χρηματα εχοντες εις την βασιλειαν του θεου εισελευσονται'),
(1468, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 24, 'NT', 'οι δε μαθηται εθαμβουντο επι τοις λογοις αυτου ο δε ιησους παλιν αποκριθεις λεγει αυτοις τεκνα πως δυσκολον εστιν τους πεποιθοτας επι τοις χρημασιν εις την βασιλειαν του θεου εισελθειν'),
(1469, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 25, 'NT', 'ευκοπωτερον εστιν καμηλον δια της τρυμαλιας της ραφιδος εισελθειν η πλουσιον εις την βασιλειαν του θεου εισελθειν'),
(1470, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 26, 'NT', 'οι δε περισσως εξεπλησσοντο λεγοντες προς εαυτους και τις δυναται σωθηναι'),
(1471, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 27, 'NT', 'εμβλεψας δε αυτοις ο ιησους λεγει παρα ανθρωποις αδυνατον αλλ ου παρα τω θεω παντα γαρ δυνατα εστιν παρα τω θεω'),
(1472, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 28, 'NT', 'και ηρξατο ο πετρος λεγειν αυτω ιδου ημεις αφηκαμεν παντα και ηκολουθησαμεν σοι'),
(1473, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 29, 'NT', 'αποκριθεις δε ο ιησους ειπεν αμην λεγω υμιν ουδεις εστιν ος αφηκεν οικιαν η αδελφους η αδελφας η πατερα η μητερα η γυναικα η τεκνα η αγρους ενεκεν εμου και του ευαγγελιου'),
(1474, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 30, 'NT', 'εαν μη λαβη εκατονταπλασιονα νυν εν τω καιρω τουτω οικιας και αδελφους και αδελφας και μητερας και τεκνα και αγρους μετα διωγμων και εν τω αιωνι τω ερχομενω ζωην αιωνιον'),
(1475, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 31, 'NT', 'πολλοι δε εσονται πρωτοι εσχατοι και οι εσχατοι πρωτοι'),
(1476, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 32, 'NT', 'ησαν δε εν τη οδω αναβαινοντες εις ιεροσολυμα και ην προαγων αυτους ο ιησους και εθαμβουντο και ακολουθουντες εφοβουντο και παραλαβων παλιν τους δωδεκα ηρξατο αυτοις λεγειν τα μελλοντα αυτω συμβαινειν'),
(1477, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 33, 'NT', 'οτι ιδου αναβαινομεν εις ιεροσολυμα και ο υιος του ανθρωπου παραδοθησεται τοις αρχιερευσιν και τοις γραμματευσιν και κατακρινουσιν αυτον θανατω και παραδωσουσιν αυτον τοις εθνεσιν'),
(1478, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 34, 'NT', 'και εμπαιξουσιν αυτω και μαστιγωσουσιν αυτον και εμπτυσουσιν αυτω και αποκτενουσιν αυτον και τη τριτη ημερα αναστησεται'),
(1479, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 35, 'NT', 'και προσπορευονται αυτω ιακωβος και ιωαννης οι υιοι ζεβεδαιου λεγοντες διδασκαλε θελομεν ινα ο εαν αιτησωμεν ποιησης ημιν'),
(1480, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 36, 'NT', 'ο δε ειπεν αυτοις τι θελετε ποιησαι με υμιν'),
(1481, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 37, 'NT', 'οι δε ειπον αυτω δος ημιν ινα εις εκ δεξιων σου και εις εξ ευωνυμων σου καθισωμεν εν τη δοξη σου'),
(1482, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 38, 'NT', 'ο δε ιησους ειπεν αυτοις ουκ οιδατε τι αιτεισθε δυνασθε πιειν το ποτηριον ο εγω πινω και το βαπτισμα ο εγω βαπτιζομαι βαπτισθηναι'),
(1483, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 39, 'NT', 'οι δε ειπον αυτω δυναμεθα ο δε ιησους ειπεν αυτοις το μεν ποτηριον ο εγω πινω πιεσθε και το βαπτισμα ο εγω βαπτιζομαι βαπτισθησεσθε'),
(1484, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 40, 'NT', 'το δε καθισαι εκ δεξιων μου και εξ ευωνυμων μου ουκ εστιν εμον δουναι αλλ οις ητοιμασται'),
(1485, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 41, 'NT', 'και ακουσαντες οι δεκα ηρξαντο αγανακτειν περι ιακωβου και ιωαννου'),
(1486, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 42, 'NT', 'ο δε ιησους προσκαλεσαμενος αυτους λεγει αυτοις οιδατε οτι οι δοκουντες αρχειν των εθνων κατακυριευουσιν αυτων και οι μεγαλοι αυτων κατεξουσιαζουσιν αυτων'),
(1487, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 43, 'NT', 'ουχ ουτως δε εσται εν υμιν αλλ ος εαν θελη γενεσθαι μεγας εν υμιν εσται διακονος υμων'),
(1488, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 44, 'NT', 'και ος αν θελη υμων γενεσθαι πρωτος εσται παντων δουλος'),
(1489, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 45, 'NT', 'και γαρ ο υιος του ανθρωπου ουκ ηλθεν διακονηθηναι αλλα διακονησαι και δουναι την ψυχην αυτου λυτρον αντι πολλων'),
(1490, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 46, 'NT', 'και ερχονται εις ιεριχω και εκπορευομενου αυτου απο ιεριχω και των μαθητων αυτου και οχλου ικανου υιος τιμαιου βαρτιμαιος ο τυφλος εκαθητο παρα την οδον προσαιτων'),
(1491, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 47, 'NT', 'και ακουσας οτι ιησους ο ναζωραιος εστιν ηρξατο κραζειν και λεγειν ο υιος δαβιδ ιησου ελεησον με'),
(1492, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 48, 'NT', 'και επετιμων αυτω πολλοι ινα σιωπηση ο δε πολλω μαλλον εκραζεν υιε δαβιδ ελεησον με'),
(1493, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 49, 'NT', 'και στας ο ιησους ειπεν αυτον φωνηθηναι και φωνουσιν τον τυφλον λεγοντες αυτω θαρσει εγειραι φωνει σε'),
(1494, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 50, 'NT', 'ο δε αποβαλων το ιματιον αυτου αναστας ηλθεν προς τον ιησουν'),
(1495, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 51, 'NT', 'και αποκριθεις λεγει αυτω ο ιησους τι θελεις ποιησω σοι ο δε τυφλος ειπεν αυτω ραββονι ινα αναβλεψω'),
(1496, 41, 'TR1550', 'TR1550', 'el', 'MRK', 10, 52, 'NT', 'ο δε ιησους ειπεν αυτω υπαγε η πιστις σου σεσωκεν σε και ευθεως ανεβλεψεν και ηκολουθει τω ιησου εν τη οδω'),
(1497, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 1, 'NT', 'και οτε εγγιζουσιν εις ιερουσαλημ εις βηθφαγη και βηθανιαν προς το ορος των ελαιων αποστελλει δυο των μαθητων αυτου'),
(1498, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 2, 'NT', 'και λεγει αυτοις υπαγετε εις την κωμην την κατεναντι υμων και ευθεως εισπορευομενοι εις αυτην ευρησετε πωλον δεδεμενον εφ ον ουδεις ανθρωπων κεκαθικεν λυσαντες αυτον αγαγετε'),
(1499, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 3, 'NT', 'και εαν τις υμιν ειπη τι ποιειτε τουτο ειπατε οτι ο κυριος αυτου χρειαν εχει και ευθεως αυτον αποστελει ωδε'),
(1500, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 4, 'NT', 'απηλθον δε και ευρον τον πωλον δεδεμενον προς την θυραν εξω επι του αμφοδου και λυουσιν αυτον'),
(1501, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 5, 'NT', 'και τινες των εκει εστηκοτων ελεγον αυτοις τι ποιειτε λυοντες τον πωλον'),
(1502, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 6, 'NT', 'οι δε ειπον αυτοις καθως ενετειλατο ο ιησους και αφηκαν αυτους'),
(1503, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 7, 'NT', 'και ηγαγον τον πωλον προς τον ιησουν και επεβαλον αυτω τα ιματια αυτων και εκαθισεν επ αυτω'),
(1504, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 8, 'NT', 'πολλοι δε τα ιματια αυτων εστρωσαν εις την οδον αλλοι δε στοιβαδας εκοπτον εκ των δενδρων και εστρωννυον εις την οδον'),
(1505, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 9, 'NT', 'και οι προαγοντες και οι ακολουθουντες εκραζον λεγοντες ωσαννα ευλογημενος ο ερχομενος εν ονοματι κυριου'),
(1506, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 10, 'NT', 'ευλογημενη η ερχομενη βασιλεια εν ονοματι κυριου του πατρος ημων δαβιδ ωσαννα εν τοις υψιστοις'),
(1507, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 11, 'NT', 'και εισηλθεν εις ιεροσολυμα ο ιησους και εις το ιερον και περιβλεψαμενος παντα οψιας ηδη ουσης της ωρας εξηλθεν εις βηθανιαν μετα των δωδεκα'),
(1508, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 12, 'NT', 'και τη επαυριον εξελθοντων αυτων απο βηθανιας επεινασεν'),
(1509, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 13, 'NT', 'και ιδων συκην μακροθεν εχουσαν φυλλα ηλθεν ει αρα ευρησει τι εν αυτη και ελθων επ αυτην ουδεν ευρεν ει μη φυλλα ου γαρ ην καιρος συκων'),
(1510, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 14, 'NT', 'και αποκριθεις ο ιησους ειπεν αυτη μηκετι εκ σου εις τον αιωνα μηδεις καρπον φαγοι και ηκουον οι μαθηται αυτου'),
(1511, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 15, 'NT', 'και ερχονται εις ιεροσολυμα και εισελθων ο ιησους εις το ιερον ηρξατο εκβαλλειν τους πωλουντας και αγοραζοντας εν τω ιερω και τας τραπεζας των κολλυβιστων και τας καθεδρας των πωλουντων τας περιστερας κατεστρεψεν'),
(1512, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 16, 'NT', 'και ουκ ηφιεν ινα τις διενεγκη σκευος δια του ιερου'),
(1513, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 17, 'NT', 'και εδιδασκεν λεγων αυτοις ου γεγραπται οτι ο οικος μου οικος προσευχης κληθησεται πασιν τοις εθνεσιν υμεις δε εποιησατε αυτον σπηλαιον ληστων'),
(1514, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 18, 'NT', 'και ηκουσαν οι γραμματεις και οι αρχιερεις και εζητουν πως αυτον απολεσουσιν εφοβουντο γαρ αυτον οτι πας ο οχλος εξεπλησσετο επι τη διδαχη αυτου'),
(1515, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 19, 'NT', 'και οτε οψε εγενετο εξεπορευετο εξω της πολεως'),
(1516, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 20, 'NT', 'και πρωι παραπορευομενοι ειδον την συκην εξηραμμενην εκ ριζων'),
(1517, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 21, 'NT', 'και αναμνησθεις ο πετρος λεγει αυτω ραββι ιδε η συκη ην κατηρασω εξηρανται'),
(1518, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 22, 'NT', 'και αποκριθεις ιησους λεγει αυτοις εχετε πιστιν θεου'),
(1519, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 23, 'NT', 'αμην γαρ λεγω υμιν οτι ος αν ειπη τω ορει τουτω αρθητι και βληθητι εις την θαλασσαν και μη διακριθη εν τη καρδια αυτου αλλα πιστευση οτι α λεγει γινεται εσται αυτω ο εαν ειπη'),
(1520, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 24, 'NT', 'δια τουτο λεγω υμιν παντα οσα αν προσευχομενοι αιτεισθε πιστευετε οτι λαμβανετε και εσται υμιν'),
(1521, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 25, 'NT', 'και οταν στηκητε προσευχομενοι αφιετε ει τι εχετε κατα τινος ινα και ο πατηρ υμων ο εν τοις ουρανοις αφη υμιν τα παραπτωματα υμων'),
(1522, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 26, 'NT', 'ει δε υμεις ουκ αφιετε ουδε ο πατηρ υμων ο εν τοις ουρανοις αφησει τα παραπτωματα υμων'),
(1523, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 27, 'NT', 'και ερχονται παλιν εις ιεροσολυμα και εν τω ιερω περιπατουντος αυτου ερχονται προς αυτον οι αρχιερεις και οι γραμματεις και οι πρεσβυτεροι'),
(1524, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 28, 'NT', 'και λεγουσιν αυτω εν ποια εξουσια ταυτα ποιεις και τις σοι την εξουσιαν ταυτην εδωκεν ινα ταυτα ποιης'),
(1525, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 29, 'NT', 'ο δε ιησους αποκριθεις ειπεν αυτοις επερωτησω υμας καγω ενα λογον και αποκριθητε μοι και ερω υμιν εν ποια εξουσια ταυτα ποιω'),
(1526, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 30, 'NT', 'το βαπτισμα ιωαννου εξ ουρανου ην η εξ ανθρωπων αποκριθητε μοι'),
(1527, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 31, 'NT', 'και ελογιζοντο προς εαυτους λεγοντες εαν ειπωμεν εξ ουρανου ερει δια τι ουν ουκ επιστευσατε αυτω'),
(1528, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 32, 'NT', 'αλλ εαν ειπωμεν εξ ανθρωπων εφοβουντο τον λαον απαντες γαρ ειχον τον ιωαννην οτι οντως προφητης ην'),
(1529, 41, 'TR1550', 'TR1550', 'el', 'MRK', 11, 33, 'NT', 'και αποκριθεντες λεγουσιν τω ιησου ουκ οιδαμεν και ο ιησους αποκριθεις λεγει αυτοις ουδε εγω λεγω υμιν εν ποια εξουσια ταυτα ποιω'),
(1530, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 1, 'NT', 'και ηρξατο αυτοις εν παραβολαις λεγειν αμπελωνα εφυτευσεν ανθρωπος και περιεθηκεν φραγμον και ωρυξεν υποληνιον και ωκοδομησεν πυργον και εξεδοτο αυτον γεωργοις και απεδημησεν'),
(1531, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 2, 'NT', 'και απεστειλεν προς τους γεωργους τω καιρω δουλον ινα παρα των γεωργων λαβη απο του καρπου του αμπελωνος'),
(1532, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 3, 'NT', 'οι δε λαβοντες αυτον εδειραν και απεστειλαν κενον'),
(1533, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 4, 'NT', 'και παλιν απεστειλεν προς αυτους αλλον δουλον κακεινον λιθοβολησαντες εκεφαλαιωσαν και απεστειλαν ητιμωμενον'),
(1534, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 5, 'NT', 'και παλιν αλλον απεστειλεν κακεινον απεκτειναν και πολλους αλλους τους μεν δεροντες τους δε αποκτεινοντες'),
(1535, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 6, 'NT', 'ετι ουν ενα υιον εχων αγαπητον αυτου απεστειλεν και αυτον προς αυτους εσχατον λεγων οτι εντραπησονται τον υιον μου'),
(1536, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 7, 'NT', 'εκεινοι δε οι γεωργοι ειπον προς εαυτους οτι ουτος εστιν ο κληρονομος δευτε αποκτεινωμεν αυτον και ημων εσται η κληρονομια'),
(1537, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 8, 'NT', 'και λαβοντες αυτον απεκτειναν και εξεβαλον εξω του αμπελωνος'),
(1538, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 9, 'NT', 'τι ουν ποιησει ο κυριος του αμπελωνος ελευσεται και απολεσει τους γεωργους και δωσει τον αμπελωνα αλλοις'),
(1539, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 10, 'NT', 'ουδε την γραφην ταυτην ανεγνωτε λιθον ον απεδοκιμασαν οι οικοδομουντες ουτος εγενηθη εις κεφαλην γωνιας'),
(1540, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 11, 'NT', 'παρα κυριου εγενετο αυτη και εστιν θαυμαστη εν οφθαλμοις ημων'),
(1541, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 12, 'NT', 'και εζητουν αυτον κρατησαι και εφοβηθησαν τον οχλον εγνωσαν γαρ οτι προς αυτους την παραβολην ειπεν και αφεντες αυτον απηλθον'),
(1542, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 13, 'NT', 'και αποστελλουσιν προς αυτον τινας των φαρισαιων και των ηρωδιανων ινα αυτον αγρευσωσιν λογω'),
(1543, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 14, 'NT', 'οι δε ελθοντες λεγουσιν αυτω διδασκαλε οιδαμεν οτι αληθης ει και ου μελει σοι περι ουδενος ου γαρ βλεπεις εις προσωπον ανθρωπων αλλ επ αληθειας την οδον του θεου διδασκεις εξεστιν κηνσον καισαρι δουναι η ου'),
(1544, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 15, 'NT', 'δωμεν η μη δωμεν ο δε ειδως αυτων την υποκρισιν ειπεν αυτοις τι με πειραζετε φερετε μοι δηναριον ινα ιδω'),
(1545, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 16, 'NT', 'οι δε ηνεγκαν και λεγει αυτοις τινος η εικων αυτη και η επιγραφη οι δε ειπον αυτω καισαρος'),
(1546, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 17, 'NT', 'και αποκριθεις ο ιησους ειπεν αυτοις αποδοτε τα καισαρος καισαρι και τα του θεου τω θεω και εθαυμασαν επ αυτω'),
(1547, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 18, 'NT', 'και ερχονται σαδδουκαιοι προς αυτον οιτινες λεγουσιν αναστασιν μη ειναι και επηρωτησαν αυτον λεγοντες'),
(1548, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 19, 'NT', 'διδασκαλε μωσης εγραψεν ημιν οτι εαν τινος αδελφος αποθανη και καταλιπη γυναικα και τεκνα μη αφη ινα λαβη ο αδελφος αυτου την γυναικα αυτου και εξαναστηση σπερμα τω αδελφω αυτου'),
(1549, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 20, 'NT', 'επτα αδελφοι ησαν και ο πρωτος ελαβεν γυναικα και αποθνησκων ουκ αφηκεν σπερμα'),
(1550, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 21, 'NT', 'και ο δευτερος ελαβεν αυτην και απεθανεν και ουδε αυτος αφηκεν σπερμα και ο τριτος ωσαυτως'),
(1551, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 22, 'NT', 'και ελαβον αυτην οι επτα και ουκ αφηκαν σπερμα εσχατη παντων απεθανεν και η γυνη'),
(1552, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 23, 'NT', 'εν τη ουν αναστασει οταν αναστωσιν τινος αυτων εσται γυνη οι γαρ επτα εσχον αυτην γυναικα'),
(1553, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 24, 'NT', 'και αποκριθεις ο ιησους ειπεν αυτοις ου δια τουτο πλανασθε μη ειδοτες τας γραφας μηδε την δυναμιν του θεου'),
(1554, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 25, 'NT', 'οταν γαρ εκ νεκρων αναστωσιν ουτε γαμουσιν ουτε γαμισκονται αλλ εισιν ως αγγελοι οι εν τοις ουρανοις'),
(1555, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 26, 'NT', 'περι δε των νεκρων οτι εγειρονται ουκ ανεγνωτε εν τη βιβλω μωσεως επι της βατου ως ειπεν αυτω ο θεος λεγων εγω ο θεος αβρααμ και ο θεος ισαακ και ο θεος ιακωβ'),
(1556, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 27, 'NT', 'ουκ εστιν ο θεος νεκρων αλλα θεος ζωντων υμεις ουν πολυ πλανασθε'),
(1557, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 28, 'NT', 'και προσελθων εις των γραμματεων ακουσας αυτων συζητουντων ειδως οτι καλως αυτοις απεκριθη επηρωτησεν αυτον ποια εστιν πρωτη πασων εντολη'),
(1558, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 29, 'NT', 'ο δε ιησους απεκριθη αυτω οτι πρωτη πασων των εντολων ακουε ισραηλ κυριος ο θεος ημων κυριος εις εστιν'),
(1559, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 30, 'NT', 'και αγαπησεις κυριον τον θεον σου εξ ολης της καρδιας σου και εξ ολης της ψυχης σου και εξ ολης της διανοιας σου και εξ ολης της ισχυος σου αυτη πρωτη εντολη'),
(1560, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 31, 'NT', 'και δευτερα ομοια αυτη αγαπησεις τον πλησιον σου ως σεαυτον μειζων τουτων αλλη εντολη ουκ εστιν'),
(1561, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 32, 'NT', 'και ειπεν αυτω ο γραμματευς καλως διδασκαλε επ αληθειας ειπας οτι εις εστιν θεος και ουκ εστιν αλλος πλην αυτου'),
(1562, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 33, 'NT', 'και το αγαπαν αυτον εξ ολης της καρδιας και εξ ολης της συνεσεως και εξ ολης της ψυχης και εξ ολης της ισχυος και το αγαπαν τον πλησιον ως εαυτον πλειον εστιν παντων των ολοκαυτωματων και των θυσιων'),
(1563, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 34, 'NT', 'και ο ιησους ιδων αυτον οτι νουνεχως απεκριθη ειπεν αυτω ου μακραν ει απο της βασιλειας του θεου και ουδεις ουκετι ετολμα αυτον επερωτησαι'),
(1564, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 35, 'NT', 'και αποκριθεις ο ιησους ελεγεν διδασκων εν τω ιερω πως λεγουσιν οι γραμματεις οτι ο χριστος υιος εστιν δαβιδ'),
(1565, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 36, 'NT', 'αυτος γαρ δαβιδ ειπεν εν τω πνευματι τω αγιω ειπεν ο κυριος τω κυριω μου καθου εκ δεξιων μου εως αν θω τους εχθρους σου υποποδιον των ποδων σου'),
(1566, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 37, 'NT', 'αυτος ουν δαβιδ λεγει αυτον κυριον και ποθεν υιος αυτου εστιν και ο πολυς οχλος ηκουεν αυτου ηδεως'),
(1567, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 38, 'NT', 'και ελεγεν αυτοις εν τη διδαχη αυτου βλεπετε απο των γραμματεων των θελοντων εν στολαις περιπατειν και ασπασμους εν ταις αγοραις'),
(1568, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 39, 'NT', 'και πρωτοκαθεδριας εν ταις συναγωγαις και πρωτοκλισιας εν τοις δειπνοις'),
(1569, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 40, 'NT', 'οι κατεσθιοντες τας οικιας των χηρων και προφασει μακρα προσευχομενοι ουτοι ληψονται περισσοτερον κριμα'),
(1570, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 41, 'NT', 'και καθισας ο ιησους κατεναντι του γαζοφυλακιου εθεωρει πως ο οχλος βαλλει χαλκον εις το γαζοφυλακιον και πολλοι πλουσιοι εβαλλον πολλα'),
(1571, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 42, 'NT', 'και ελθουσα μια χηρα πτωχη εβαλεν λεπτα δυο ο εστιν κοδραντης'),
(1572, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 43, 'NT', 'και προσκαλεσαμενος τους μαθητας αυτου λεγει αυτοις αμην λεγω υμιν οτι η χηρα αυτη η πτωχη πλειον παντων βεβληκεν των βαλοντων εις το γαζοφυλακιον'),
(1573, 41, 'TR1550', 'TR1550', 'el', 'MRK', 12, 44, 'NT', 'παντες γαρ εκ του περισσευοντος αυτοις εβαλον αυτη δε εκ της υστερησεως αυτης παντα οσα ειχεν εβαλεν ολον τον βιον αυτης'),
(1574, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 1, 'NT', 'και εκπορευομενου αυτου εκ του ιερου λεγει αυτω εις των μαθητων αυτου διδασκαλε ιδε ποταποι λιθοι και ποταπαι οικοδομαι'),
(1575, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 2, 'NT', 'και ο ιησους αποκριθεις ειπεν αυτω βλεπεις ταυτας τας μεγαλας οικοδομας ου μη αφεθη λιθος επι λιθω ος ου μη καταλυθη'),
(1576, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 3, 'NT', 'και καθημενου αυτου εις το ορος των ελαιων κατεναντι του ιερου επηρωτων αυτον κατ ιδιαν πετρος και ιακωβος και ιωαννης και ανδρεας'),
(1577, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 4, 'NT', 'ειπε ημιν ποτε ταυτα εσται και τι το σημειον οταν μελλη παντα ταυτα συντελεισθαι'),
(1578, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 5, 'NT', 'ο δε ιησους αποκριθεις αυτοις ηρξατο λεγειν βλεπετε μη τις υμας πλανηση'),
(1579, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 6, 'NT', 'πολλοι γαρ ελευσονται επι τω ονοματι μου λεγοντες οτι εγω ειμι και πολλους πλανησουσιν'),
(1580, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 7, 'NT', 'οταν δε ακουσητε πολεμους και ακοας πολεμων μη θροεισθε δει γαρ γενεσθαι αλλ ουπω το τελος'),
(1581, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 8, 'NT', 'εγερθησεται γαρ εθνος επι εθνος και βασιλεια επι βασιλειαν και εσονται σεισμοι κατα τοπους και εσονται λιμοι και ταραχαι αρχαι ωδινων ταυτα'),
(1582, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 9, 'NT', 'βλεπετε δε υμεις εαυτους παραδωσουσιν γαρ υμας εις συνεδρια και εις συναγωγας δαρησεσθε και επι ηγεμονων και βασιλεων σταθησεσθε ενεκεν εμου εις μαρτυριον αυτοις'),
(1583, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 10, 'NT', 'και εις παντα τα εθνη δει πρωτον κηρυχθηναι το ευαγγελιον'),
(1584, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 11, 'NT', 'οταν δε αγαγωσιν υμας παραδιδοντες μη προμεριμνατε τι λαλησητε μηδε μελετατε αλλ ο εαν δοθη υμιν εν εκεινη τη ωρα τουτο λαλειτε ου γαρ εστε υμεις οι λαλουντες αλλα το πνευμα το αγιον'),
(1585, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 12, 'NT', 'παραδωσει δε αδελφος αδελφον εις θανατον και πατηρ τεκνον και επαναστησονται τεκνα επι γονεις και θανατωσουσιν αυτους'),
(1586, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 13, 'NT', 'και εσεσθε μισουμενοι υπο παντων δια το ονομα μου ο δε υπομεινας εις τελος ουτος σωθησεται'),
(1587, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 14, 'NT', 'οταν δε ιδητε το βδελυγμα της ερημωσεως το ρηθεν υπο δανιηλ του προφητου εστος οπου ου δει ο αναγινωσκων νοειτω τοτε οι εν τη ιουδαια φευγετωσαν εις τα ορη'),
(1588, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 15, 'NT', 'ο δε επι του δωματος μη καταβατω εις την οικιαν μηδε εισελθετω αραι τι εκ της οικιας αυτου'),
(1589, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 16, 'NT', 'και ο εις τον αγρον ων μη επιστρεψατω εις τα οπισω αραι το ιματιον αυτου'),
(1590, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 17, 'NT', 'ουαι δε ταις εν γαστρι εχουσαις και ταις θηλαζουσαις εν εκειναις ταις ημεραις'),
(1591, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 18, 'NT', 'προσευχεσθε δε ινα μη γενηται η φυγη υμων χειμωνος'),
(1592, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 19, 'NT', 'εσονται γαρ αι ημεραι εκειναι θλιψις οια ου γεγονεν τοιαυτη απ αρχης κτισεως ης εκτισεν ο θεος εως του νυν και ου μη γενηται'),
(1593, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 20, 'NT', 'και ει μη κυριος εκολοβωσεν τας ημερας ουκ αν εσωθη πασα σαρξ αλλα δια τους εκλεκτους ους εξελεξατο εκολοβωσεν τας ημερας'),
(1594, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 21, 'NT', 'και τοτε εαν τις υμιν ειπη ιδου ωδε ο χριστος η ιδου εκει μη πιστευσητε'),
(1595, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 22, 'NT', 'εγερθησονται γαρ ψευδοχριστοι και ψευδοπροφηται και δωσουσιν σημεια και τερατα προς το αποπλαναν ει δυνατον και τους εκλεκτους'),
(1596, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 23, 'NT', 'υμεις δε βλεπετε ιδου προειρηκα υμιν παντα'),
(1597, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 24, 'NT', 'αλλ εν εκειναις ταις ημεραις μετα την θλιψιν εκεινην ο ηλιος σκοτισθησεται και η σεληνη ου δωσει το φεγγος αυτης'),
(1598, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 25, 'NT', 'και οι αστερες του ουρανου εσονται εκπιπτοντες και αι δυναμεις αι εν τοις ουρανοις σαλευθησονται'),
(1599, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 26, 'NT', 'και τοτε οψονται τον υιον του ανθρωπου ερχομενον εν νεφελαις μετα δυναμεως πολλης και δοξης'),
(1600, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 27, 'NT', 'και τοτε αποστελει τους αγγελους αυτου και επισυναξει τους εκλεκτους αυτου εκ των τεσσαρων ανεμων απ ακρου γης εως ακρου ουρανου'),
(1601, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 28, 'NT', 'απο δε της συκης μαθετε την παραβολην οταν αυτης ηδη ο κλαδος απαλος γενηται και εκφυη τα φυλλα γινωσκετε οτι εγγυς το θερος εστιν'),
(1602, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 29, 'NT', 'ουτως και υμεις οταν ταυτα ιδητε γινομενα γινωσκετε οτι εγγυς εστιν επι θυραις'),
(1603, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 30, 'NT', 'αμην λεγω υμιν οτι ου μη παρελθη η γενεα αυτη μεχρις ου παντα ταυτα γενηται'),
(1604, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 31, 'NT', 'ο ουρανος και η γη παρελευσονται οι δε λογοι μου ου μη παρελθωσιν'),
(1605, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 32, 'NT', 'περι δε της ημερας εκεινης και της ωρας ουδεις οιδεν ουδε οι αγγελοι οι εν ουρανω ουδε ο υιος ει μη ο πατηρ'),
(1606, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 33, 'NT', 'βλεπετε αγρυπνειτε και προσευχεσθε ουκ οιδατε γαρ ποτε ο καιρος εστιν'),
(1607, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 34, 'NT', 'ως ανθρωπος αποδημος αφεις την οικιαν αυτου και δους τοις δουλοις αυτου την εξουσιαν και εκαστω το εργον αυτου και τω θυρωρω ενετειλατο ινα γρηγορη'),
(1608, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 35, 'NT', 'γρηγορειτε ουν ουκ οιδατε γαρ ποτε ο κυριος της οικιας ερχεται οψε η μεσονυκτιου η αλεκτοροφωνιας η πρωι'),
(1609, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 36, 'NT', 'μη ελθων εξαιφνης ευρη υμας καθευδοντας'),
(1610, 41, 'TR1550', 'TR1550', 'el', 'MRK', 13, 37, 'NT', 'α δε υμιν λεγω πασιν λεγω γρηγορειτε'),
(1611, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 1, 'NT', 'ην δε το πασχα και τα αζυμα μετα δυο ημερας και εζητουν οι αρχιερεις και οι γραμματεις πως αυτον εν δολω κρατησαντες αποκτεινωσιν'),
(1612, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 2, 'NT', 'ελεγον δε μη εν τη εορτη μηποτε θορυβος εσται του λαου'),
(1613, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 3, 'NT', 'και οντος αυτου εν βηθανια εν τη οικια σιμωνος του λεπρου κατακειμενου αυτου ηλθεν γυνη εχουσα αλαβαστρον μυρου ναρδου πιστικης πολυτελους και συντριψασα το αλαβαστρον κατεχεεν αυτου κατα της κεφαλης'),
(1614, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 4, 'NT', 'ησαν δε τινες αγανακτουντες προς εαυτους και λεγοντες εις τι η απωλεια αυτη του μυρου γεγονεν'),
(1615, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 5, 'NT', 'ηδυνατο γαρ τουτο πραθηναι επανω τριακοσιων δηναριων και δοθηναι τοις πτωχοις και ενεβριμωντο αυτη'),
(1616, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 6, 'NT', 'ο δε ιησους ειπεν αφετε αυτην τι αυτη κοπους παρεχετε καλον εργον ειργασατο εις εμε'),
(1617, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 7, 'NT', 'παντοτε γαρ τους πτωχους εχετε μεθ εαυτων και οταν θελητε δυνασθε αυτους ευ ποιησαι εμε δε ου παντοτε εχετε'),
(1618, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 8, 'NT', 'ο ειχεν αυτη εποιησεν προελαβεν μυρισαι μου το σωμα εις τον ενταφιασμον'),
(1619, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 9, 'NT', 'αμην λεγω υμιν οπου αν κηρυχθη το ευαγγελιον τουτο εις ολον τον κοσμον και ο εποιησεν αυτη λαληθησεται εις μνημοσυνον αυτης'),
(1620, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 10, 'NT', 'και ο ιουδας ο ισκαριωτης εις των δωδεκα απηλθεν προς τους αρχιερεις ινα παραδω αυτον αυτοις'),
(1621, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 11, 'NT', 'οι δε ακουσαντες εχαρησαν και επηγγειλαντο αυτω αργυριον δουναι και εζητει πως ευκαιρως αυτον παραδω'),
(1622, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 12, 'NT', 'και τη πρωτη ημερα των αζυμων οτε το πασχα εθυον λεγουσιν αυτω οι μαθηται αυτου που θελεις απελθοντες ετοιμασωμεν ινα φαγης το πασχα'),
(1623, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 13, 'NT', 'και αποστελλει δυο των μαθητων αυτου και λεγει αυτοις υπαγετε εις την πολιν και απαντησει υμιν ανθρωπος κεραμιον υδατος βασταζων ακολουθησατε αυτω'),
(1624, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 14, 'NT', 'και οπου εαν εισελθη ειπατε τω οικοδεσποτη οτι ο διδασκαλος λεγει που εστιν το καταλυμα οπου το πασχα μετα των μαθητων μου φαγω'),
(1625, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 15, 'NT', 'και αυτος υμιν δειξει ανωγεον μεγα εστρωμενον ετοιμον εκει ετοιμασατε ημιν'),
(1626, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 16, 'NT', 'και εξηλθον οι μαθηται αυτου και ηλθον εις την πολιν και ευρον καθως ειπεν αυτοις και ητοιμασαν το πασχα'),
(1627, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 17, 'NT', 'και οψιας γενομενης ερχεται μετα των δωδεκα'),
(1628, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 18, 'NT', 'και ανακειμενων αυτων και εσθιοντων ειπεν ο ιησους αμην λεγω υμιν οτι εις εξ υμων παραδωσει με ο εσθιων μετ εμου'),
(1629, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 19, 'NT', 'οι δε ηρξαντο λυπεισθαι και λεγειν αυτω εις καθ εις μητι εγω και αλλος μητι εγω'),
(1630, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 20, 'NT', 'ο δε αποκριθεις ειπεν αυτοις εις εκ των δωδεκα ο εμβαπτομενος μετ εμου εις το τρυβλιον'),
(1631, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 21, 'NT', 'ο μεν υιος του ανθρωπου υπαγει καθως γεγραπται περι αυτου ουαι δε τω ανθρωπω εκεινω δι ου ο υιος του ανθρωπου παραδιδοται καλον ην αυτω ει ουκ εγεννηθη ο ανθρωπος εκεινος'),
(1632, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 22, 'NT', 'και εσθιοντων αυτων λαβων ο ιησους αρτον ευλογησας εκλασεν και εδωκεν αυτοις και ειπεν λαβετε φαγετε τουτο εστιν το σωμα μου'),
(1633, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 23, 'NT', 'και λαβων το ποτηριον ευχαριστησας εδωκεν αυτοις και επιον εξ αυτου παντες'),
(1634, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 24, 'NT', 'και ειπεν αυτοις τουτο εστιν το αιμα μου το της καινης διαθηκης το περι πολλων εκχυνομενον'),
(1635, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 25, 'NT', 'αμην λεγω υμιν οτι ουκετι ου μη πιω εκ του γεννηματος της αμπελου εως της ημερας εκεινης οταν αυτο πινω καινον εν τη βασιλεια του θεου'),
(1636, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 26, 'NT', 'και υμνησαντες εξηλθον εις το ορος των ελαιων'),
(1637, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 27, 'NT', 'και λεγει αυτοις ο ιησους οτι παντες σκανδαλισθησεσθε εν εμοι εν τη νυκτι ταυτη οτι γεγραπται παταξω τον ποιμενα και διασκορπισθησεται τα προβατα'),
(1638, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 28, 'NT', 'αλλα μετα το εγερθηναι με προαξω υμας εις την γαλιλαιαν'),
(1639, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 29, 'NT', 'ο δε πετρος εφη αυτω και ει παντες σκανδαλισθησονται αλλ ουκ εγω'),
(1640, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 30, 'NT', 'και λεγει αυτω ο ιησους αμην λεγω σοι οτι σημερον εν τη νυκτι ταυτη πριν η δις αλεκτορα φωνησαι τρις απαρνηση με'),
(1641, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 31, 'NT', 'ο δε εκ περισσου ελεγεν μαλλον εαν με δεη συναποθανειν σοι ου μη σε απαρνησομαι ωσαυτως δε και παντες ελεγον'),
(1642, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 32, 'NT', 'και ερχονται εις χωριον ου το ονομα γεθσημανη και λεγει τοις μαθηταις αυτου καθισατε ωδε εως προσευξωμαι'),
(1643, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 33, 'NT', 'και παραλαμβανει τον πετρον και τον ιακωβον και ιωαννην μεθ εαυτου και ηρξατο εκθαμβεισθαι και αδημονειν'),
(1644, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 34, 'NT', 'και λεγει αυτοις περιλυπος εστιν η ψυχη μου εως θανατου μεινατε ωδε και γρηγορειτε'),
(1645, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 35, 'NT', 'και προελθων μικρον επεσεν επι της γης και προσηυχετο ινα ει δυνατον εστιν παρελθη απ αυτου η ωρα'),
(1646, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 36, 'NT', 'και ελεγεν αββα ο πατηρ παντα δυνατα σοι παρενεγκε το ποτηριον απ εμου τουτο αλλ ου τι εγω θελω αλλα τι συ'),
(1647, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 37, 'NT', 'και ερχεται και ευρισκει αυτους καθευδοντας και λεγει τω πετρω σιμων καθευδεις ουκ ισχυσας μιαν ωραν γρηγορησαι'),
(1648, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 38, 'NT', 'γρηγορειτε και προσευχεσθε ινα μη εισελθητε εις πειρασμον το μεν πνευμα προθυμον η δε σαρξ ασθενης'),
(1649, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 39, 'NT', 'και παλιν απελθων προσηυξατο τον αυτον λογον ειπων'),
(1650, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 40, 'NT', 'και υποστρεψας ευρεν αυτους παλιν καθευδοντας ησαν γαρ οι οφθαλμοι αυτων βεβαρημενοι και ουκ ηδεισαν τι αυτω αποκριθωσιν'),
(1651, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 41, 'NT', 'και ερχεται το τριτον και λεγει αυτοις καθευδετε το λοιπον και αναπαυεσθε απεχει ηλθεν η ωρα ιδου παραδιδοται ο υιος του ανθρωπου εις τας χειρας των αμαρτωλων'),
(1652, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 42, 'NT', 'εγειρεσθε αγωμεν ιδου ο παραδιδους με ηγγικεν'),
(1653, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 43, 'NT', 'και ευθεως ετι αυτου λαλουντος παραγινεται ιουδας εις ων των δωδεκα και μετ αυτου οχλος πολυς μετα μαχαιρων και ξυλων παρα των αρχιερεων και των γραμματεων και των πρεσβυτερων'),
(1654, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 44, 'NT', 'δεδωκει δε ο παραδιδους αυτον συσσημον αυτοις λεγων ον αν φιλησω αυτος εστιν κρατησατε αυτον και απαγαγετε ασφαλως'),
(1655, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 45, 'NT', 'και ελθων ευθεως προσελθων αυτω λεγει ραββι ραββι και κατεφιλησεν αυτον'),
(1656, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 46, 'NT', 'οι δε επεβαλον επ αυτον τας χειρας αυτων και εκρατησαν αυτον'),
(1657, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 47, 'NT', 'εις δε τις των παρεστηκοτων σπασαμενος την μαχαιραν επαισεν τον δουλον του αρχιερεως και αφειλεν αυτου το ωτιον'),
(1658, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 48, 'NT', 'και αποκριθεις ο ιησους ειπεν αυτοις ως επι ληστην εξηλθετε μετα μαχαιρων και ξυλων συλλαβειν με'),
(1659, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 49, 'NT', 'καθ ημεραν ημην προς υμας εν τω ιερω διδασκων και ουκ εκρατησατε με αλλ ινα πληρωθωσιν αι γραφαι'),
(1660, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 50, 'NT', 'και αφεντες αυτον παντες εφυγον'),
(1661, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 51, 'NT', 'και εις τις νεανισκος ηκολουθει αυτω περιβεβλημενος σινδονα επι γυμνου και κρατουσιν αυτον οι νεανισκοι'),
(1662, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 52, 'NT', 'ο δε καταλιπων την σινδονα γυμνος εφυγεν απ αυτων'),
(1663, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 53, 'NT', 'και απηγαγον τον ιησουν προς τον αρχιερεα και συνερχονται αυτω παντες οι αρχιερεις και οι πρεσβυτεροι και οι γραμματεις'),
(1664, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 54, 'NT', 'και ο πετρος απο μακροθεν ηκολουθησεν αυτω εως εσω εις την αυλην του αρχιερεως και ην συγκαθημενος μετα των υπηρετων και θερμαινομενος προς το φως'),
(1665, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 55, 'NT', 'οι δε αρχιερεις και ολον το συνεδριον εζητουν κατα του ιησου μαρτυριαν εις το θανατωσαι αυτον και ουχ ευρισκον'),
(1666, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 56, 'NT', 'πολλοι γαρ εψευδομαρτυρουν κατ αυτου και ισαι αι μαρτυριαι ουκ ησαν'),
(1667, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 57, 'NT', 'και τινες ανασταντες εψευδομαρτυρουν κατ αυτου λεγοντες'),
(1668, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 58, 'NT', 'οτι ημεις ηκουσαμεν αυτου λεγοντος οτι εγω καταλυσω τον ναον τουτον τον χειροποιητον και δια τριων ημερων αλλον αχειροποιητον οικοδομησω'),
(1669, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 59, 'NT', 'και ουδε ουτως ιση ην η μαρτυρια αυτων'),
(1670, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 60, 'NT', 'και αναστας ο αρχιερευς εις το μεσον επηρωτησεν τον ιησουν λεγων ουκ αποκρινη ουδεν τι ουτοι σου καταμαρτυρουσιν'),
(1671, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 61, 'NT', 'ο δε εσιωπα και ουδεν απεκρινατο παλιν ο αρχιερευς επηρωτα αυτον και λεγει αυτω συ ει ο χριστος ο υιος του ευλογητου'),
(1672, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 62, 'NT', 'ο δε ιησους ειπεν εγω ειμι και οψεσθε τον υιον του ανθρωπου καθημενον εκ δεξιων της δυναμεως και ερχομενον μετα των νεφελων του ουρανου'),
(1673, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 63, 'NT', 'ο δε αρχιερευς διαρρηξας τους χιτωνας αυτου λεγει τι ετι χρειαν εχομεν μαρτυρων'),
(1674, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 64, 'NT', 'ηκουσατε της βλασφημιας τι υμιν φαινεται οι δε παντες κατεκριναν αυτον ειναι ενοχον θανατου'),
(1675, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 65, 'NT', 'και ηρξαντο τινες εμπτυειν αυτω και περικαλυπτειν το προσωπον αυτου και κολαφιζειν αυτον και λεγειν αυτω προφητευσον και οι υπηρεται ραπισμασιν αυτον εβαλλον'),
(1676, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 66, 'NT', 'και οντος του πετρου εν τη αυλη κατω ερχεται μια των παιδισκων του αρχιερεως'),
(1677, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 67, 'NT', 'και ιδουσα τον πετρον θερμαινομενον εμβλεψασα αυτω λεγει και συ μετα του ναζαρηνου ιησου ησθα'),
(1678, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 68, 'NT', 'ο δε ηρνησατο λεγων ουκ οιδα ουδε επισταμαι τι συ λεγεις και εξηλθεν εξω εις το προαυλιον και αλεκτωρ εφωνησεν'),
(1679, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 69, 'NT', 'και η παιδισκη ιδουσα αυτον παλιν ηρξατο λεγειν τοις παρεστηκοσιν οτι ουτος εξ αυτων εστιν'),
(1680, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 70, 'NT', 'ο δε παλιν ηρνειτο και μετα μικρον παλιν οι παρεστωτες ελεγον τω πετρω αληθως εξ αυτων ει και γαρ γαλιλαιος ει και η λαλια σου ομοιαζει'),
(1681, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 71, 'NT', 'ο δε ηρξατο αναθεματιζειν και ομνυειν οτι ουκ οιδα τον ανθρωπον τουτον ον λεγετε'),
(1682, 41, 'TR1550', 'TR1550', 'el', 'MRK', 14, 72, 'NT', 'και εκ δευτερου αλεκτωρ εφωνησεν και ανεμνησθη ο πετρος του ρηματος ου ειπεν αυτω ο ιησους οτι πριν αλεκτορα φωνησαι δις απαρνηση με τρις και επιβαλων εκλαιεν'),
(1683, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 1, 'NT', 'και ευθεως επι το πρωι συμβουλιον ποιησαντες οι αρχιερεις μετα των πρεσβυτερων και γραμματεων και ολον το συνεδριον δησαντες τον ιησουν απηνεγκαν και παρεδωκαν τω πιλατω'),
(1684, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 2, 'NT', 'και επηρωτησεν αυτον ο πιλατος συ ει ο βασιλευς των ιουδαιων ο δε αποκριθεις ειπεν αυτω συ λεγεις'),
(1685, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 3, 'NT', 'και κατηγορουν αυτου οι αρχιερεις πολλα'),
(1686, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 4, 'NT', 'ο δε πιλατος παλιν επηρωτησεν αυτον λεγων ουκ αποκρινη ουδεν ιδε ποσα σου καταμαρτυρουσιν'),
(1687, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 5, 'NT', 'ο δε ιησους ουκετι ουδεν απεκριθη ωστε θαυμαζειν τον πιλατον'),
(1688, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 6, 'NT', 'κατα δε εορτην απελυεν αυτοις ενα δεσμιον ονπερ ητουντο'),
(1689, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 7, 'NT', 'ην δε ο λεγομενος βαραββας μετα των συστασιαστων δεδεμενος οιτινες εν τη στασει φονον πεποιηκεισαν'),
(1690, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 8, 'NT', 'και αναβοησας ο οχλος ηρξατο αιτεισθαι καθως αει εποιει αυτοις'),
(1691, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 9, 'NT', 'ο δε πιλατος απεκριθη αυτοις λεγων θελετε απολυσω υμιν τον βασιλεα των ιουδαιων'),
(1692, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 10, 'NT', 'εγινωσκεν γαρ οτι δια φθονον παραδεδωκεισαν αυτον οι αρχιερεις'),
(1693, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 11, 'NT', 'οι δε αρχιερεις ανεσεισαν τον οχλον ινα μαλλον τον βαραββαν απολυση αυτοις'),
(1694, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 12, 'NT', 'ο δε πιλατος αποκριθεις παλιν ειπεν αυτοις τι ουν θελετε ποιησω ον λεγετε βασιλεα των ιουδαιων'),
(1695, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 13, 'NT', 'οι δε παλιν εκραξαν σταυρωσον αυτον'),
(1696, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 14, 'NT', 'ο δε πιλατος ελεγεν αυτοις τι γαρ κακον εποιησεν οι δε περισσοτερως εκραξαν σταυρωσον αυτον'),
(1697, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 15, 'NT', 'ο δε πιλατος βουλομενος τω οχλω το ικανον ποιησαι απελυσεν αυτοις τον βαραββαν και παρεδωκεν τον ιησουν φραγελλωσας ινα σταυρωθη'),
(1698, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 16, 'NT', 'οι δε στρατιωται απηγαγον αυτον εσω της αυλης ο εστιν πραιτωριον και συγκαλουσιν ολην την σπειραν'),
(1699, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 17, 'NT', 'και ενδυουσιν αυτον πορφυραν και περιτιθεασιν αυτω πλεξαντες ακανθινον στεφανον'),
(1700, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 18, 'NT', 'και ηρξαντο ασπαζεσθαι αυτον χαιρε βασιλευ των ιουδαιων'),
(1701, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 19, 'NT', 'και ετυπτον αυτου την κεφαλην καλαμω και ενεπτυον αυτω και τιθεντες τα γονατα προσεκυνουν αυτω'),
(1702, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 20, 'NT', 'και οτε ενεπαιξαν αυτω εξεδυσαν αυτον την πορφυραν και ενεδυσαν αυτον τα ιματια τα ιδια και εξαγουσιν αυτον ινα σταυρωσωσιν αυτον'),
(1703, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 21, 'NT', 'και αγγαρευουσιν παραγοντα τινα σιμωνα κυρηναιον ερχομενον απ αγρου τον πατερα αλεξανδρου και ρουφου ινα αρη τον σταυρον αυτου'),
(1704, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 22, 'NT', 'και φερουσιν αυτον επι γολγοθα τοπον ο εστιν μεθερμηνευομενον κρανιου τοπος'),
(1705, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 23, 'NT', 'και εδιδουν αυτω πιειν εσμυρνισμενον οινον ο δε ουκ ελαβεν'),
(1706, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 24, 'NT', 'και σταυρωσαντες αυτον διεμεριζον τα ιματια αυτου βαλλοντες κληρον επ αυτα τις τι αρη'),
(1707, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 25, 'NT', 'ην δε ωρα τριτη και εσταυρωσαν αυτον'),
(1708, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 26, 'NT', 'και ην η επιγραφη της αιτιας αυτου επιγεγραμμενη ο βασιλευς των ιουδαιων'),
(1709, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 27, 'NT', 'και συν αυτω σταυρουσιν δυο ληστας ενα εκ δεξιων και ενα εξ ευωνυμων αυτου'),
(1710, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 28, 'NT', 'και επληρωθη η γραφη η λεγουσα και μετα ανομων ελογισθη'),
(1711, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 29, 'NT', 'και οι παραπορευομενοι εβλασφημουν αυτον κινουντες τας κεφαλας αυτων και λεγοντες ουα ο καταλυων τον ναον και εν τρισιν ημεραις οικοδομων'),
(1712, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 30, 'NT', 'σωσον σεαυτον και καταβα απο του σταυρου'),
(1713, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 31, 'NT', 'ομοιως δε και οι αρχιερεις εμπαιζοντες προς αλληλους μετα των γραμματεων ελεγον αλλους εσωσεν εαυτον ου δυναται σωσαι'),
(1714, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 32, 'NT', 'ο χριστος ο βασιλευς του ισραηλ καταβατω νυν απο του σταυρου ινα ιδωμεν και πιστευσωμεν και οι συνεσταυρωμενοι αυτω ωνειδιζον αυτον'),
(1715, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 33, 'NT', 'γενομενης δε ωρας εκτης σκοτος εγενετο εφ ολην την γην εως ωρας εννατης'),
(1716, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 34, 'NT', 'και τη ωρα τη εννατη εβοησεν ο ιησους φωνη μεγαλη λεγων ελωι ελωι λαμμα σαβαχθανι ο εστιν μεθερμηνευομενον ο θεος μου ο θεος μου εις τι με εγκατελιπες'),
(1717, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 35, 'NT', 'και τινες των παρεστηκοτων ακουσαντες ελεγον ιδου ηλιαν φωνει'),
(1718, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 36, 'NT', 'δραμων δε εις και γεμισας σπογγον οξους περιθεις τε καλαμω εποτιζεν αυτον λεγων αφετε ιδωμεν ει ερχεται ηλιας καθελειν αυτον'),
(1719, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 37, 'NT', 'ο δε ιησους αφεις φωνην μεγαλην εξεπνευσεν'),
(1720, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 38, 'NT', 'και το καταπετασμα του ναου εσχισθη εις δυο απο ανωθεν εως κατω'),
(1721, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 39, 'NT', 'ιδων δε ο κεντυριων ο παρεστηκως εξ εναντιας αυτου οτι ουτως κραξας εξεπνευσεν ειπεν αληθως ο ανθρωπος ουτος υιος ην θεου'),
(1722, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 40, 'NT', 'ησαν δε και γυναικες απο μακροθεν θεωρουσαι εν αις ην και μαρια η μαγδαληνη και μαρια η του ιακωβου του μικρου και ιωση μητηρ και σαλωμη'),
(1723, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 41, 'NT', 'αι και οτε ην εν τη γαλιλαια ηκολουθουν αυτω και διηκονουν αυτω και αλλαι πολλαι αι συναναβασαι αυτω εις ιεροσολυμα'),
(1724, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 42, 'NT', 'και ηδη οψιας γενομενης επει ην παρασκευη ο εστιν προσαββατον'),
(1725, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 43, 'NT', 'ηλθεν ιωσηφ ο απο αριμαθαιας ευσχημων βουλευτης ος και αυτος ην προσδεχομενος την βασιλειαν του θεου τολμησας εισηλθεν προς πιλατον και ητησατο το σωμα του ιησου'),
(1726, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 44, 'NT', 'ο δε πιλατος εθαυμασεν ει ηδη τεθνηκεν και προσκαλεσαμενος τον κεντυριωνα επηρωτησεν αυτον ει παλαι απεθανεν'),
(1727, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 45, 'NT', 'και γνους απο του κεντυριωνος εδωρησατο το σωμα τω ιωσηφ'),
(1728, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 46, 'NT', 'και αγορασας σινδονα και καθελων αυτον ενειλησεν τη σινδονι και κατεθηκεν αυτον εν μνημειω ο ην λελατομημενον εκ πετρας και προσεκυλισεν λιθον επι την θυραν του μνημειου'),
(1729, 41, 'TR1550', 'TR1550', 'el', 'MRK', 15, 47, 'NT', 'η δε μαρια η μαγδαληνη και μαρια ιωση εθεωρουν που τιθεται'),
(1730, 41, 'TR1550', 'TR1550', 'el', 'MRK', 16, 1, 'NT', 'και διαγενομενου του σαββατου μαρια η μαγδαληνη και μαρια η του ιακωβου και σαλωμη ηγορασαν αρωματα ινα ελθουσαι αλειψωσιν αυτον'),
(1731, 41, 'TR1550', 'TR1550', 'el', 'MRK', 16, 2, 'NT', 'και λιαν πρωι της μιας σαββατων ερχονται επι το μνημειον ανατειλαντος του ηλιου'),
