(1997, 42, 'TR1550', 'TR1550', 'el', 'LUK', 5, 34, 'NT', 'ο δε ειπεν προς αυτους μη δυνασθε τους υιους του νυμφωνος εν ω ο νυμφιος μετ αυτων εστιν ποιησαι νηστευειν'),
(1998, 42, 'TR1550', 'TR1550', 'el', 'LUK', 5, 35, 'NT', 'ελευσονται δε ημεραι και οταν απαρθη απ αυτων ο νυμφιος τοτε νηστευσουσιν εν εκειναις ταις ημεραις'),
(1999, 42, 'TR1550', 'TR1550', 'el', 'LUK', 5, 36, 'NT', 'ελεγεν δε και παραβολην προς αυτους οτι ουδεις επιβλημα ιματιου καινου επιβαλλει επι ιματιον παλαιον ει δε μηγε και το καινον σχιζει και τω παλαιω ου συμφωνει επιβλημα το απο του καινου'),
(2000, 42, 'TR1550', 'TR1550', 'el', 'LUK', 5, 37, 'NT', 'και ουδεις βαλλει οινον νεον εις ασκους παλαιους ει δε μηγε ρηξει ο νεος οινος τους ασκους και αυτος εκχυθησεται και οι ασκοι απολουνται'),
(2001, 42, 'TR1550', 'TR1550', 'el', 'LUK', 5, 38, 'NT', 'αλλα οινον νεον εις ασκους καινους βλητεον και αμφοτεροι συντηρουνται'),
(2002, 42, 'TR1550', 'TR1550', 'el', 'LUK', 5, 39, 'NT', 'και ουδεις πιων παλαιον ευθεως θελει νεον λεγει γαρ ο παλαιος χρηστοτερος εστιν'),
(2003, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 1, 'NT', 'εγενετο δε εν σαββατω δευτεροπρωτω διαπορευεσθαι αυτον δια των σποριμων και ετιλλον οι μαθηται αυτου τους σταχυας και ησθιον ψωχοντες ταις χερσιν'),
(2004, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 2, 'NT', 'τινες δε των φαρισαιων ειπον αυτοις τι ποιειτε ο ουκ εξεστιν ποιειν εν τοις σαββασιν'),
(2005, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 3, 'NT', 'και αποκριθεις προς αυτους ειπεν ο ιησους ουδε τουτο ανεγνωτε ο εποιησεν δαβιδ οποτε επεινασεν αυτος και οι μετ αυτου οντες'),
(2006, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 4, 'NT', 'ως εισηλθεν εις τον οικον του θεου και τους αρτους της προθεσεως ελαβεν και εφαγεν και εδωκεν και τοις μετ αυτου ους ουκ εξεστιν φαγειν ει μη μονους τους ιερεις'),
(2007, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 5, 'NT', 'και ελεγεν αυτοις οτι κυριος εστιν ο υιος του ανθρωπου και του σαββατου'),
(2008, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 6, 'NT', 'εγενετο δε και εν ετερω σαββατω εισελθειν αυτον εις την συναγωγην και διδασκειν και ην εκει ανθρωπος και η χειρ αυτου η δεξια ην ξηρα'),
(2009, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 7, 'NT', 'παρετηρουν δε αυτον οι γραμματεις και οι φαρισαιοι ει εν τω σαββατω θεραπευσει ινα ευρωσιν κατηγοριαν αυτου'),
(2010, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 8, 'NT', 'αυτος δε ηδει τους διαλογισμους αυτων και ειπεν τω ανθρωπω τω ξηραν εχοντι την χειρα εγειραι και στηθι εις το μεσον ο δε αναστας εστη'),
(2011, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 9, 'NT', 'ειπεν ουν ο ιησους προς αυτους επερωτησω υμας τι εξεστιν τοις σαββασιν αγαθοποιησαι η κακοποιησαι ψυχην σωσαι η απολεσαι'),
(2012, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 10, 'NT', 'και περιβλεψαμενος παντας αυτους ειπεν τω ανθρωπω εκτεινον την χειρα σου ο δε εποιησεν ουτως και αποκατεσταθη η χειρ αυτου υγιης ως η αλλη'),
(2013, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 11, 'NT', 'αυτοι δε επλησθησαν ανοιας και διελαλουν προς αλληλους τι αν ποιησειαν τω ιησου'),
(2014, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 12, 'NT', 'εγενετο δε εν ταις ημεραις ταυταις εξηλθεν εις το ορος προσευξασθαι και ην διανυκτερευων εν τη προσευχη του θεου'),
(2015, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 13, 'NT', 'και οτε εγενετο ημερα προσεφωνησεν τους μαθητας αυτου και εκλεξαμενος απ αυτων δωδεκα ους και αποστολους ωνομασεν'),
(2016, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 14, 'NT', 'σιμωνα ον και ωνομασεν πετρον και ανδρεαν τον αδελφον αυτου ιακωβον και ιωαννην φιλιππον και βαρθολομαιον'),
(2017, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 15, 'NT', 'ματθαιον και θωμαν ιακωβον τον του αλφαιου και σιμωνα τον καλουμενον ζηλωτην'),
(2018, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 16, 'NT', 'ιουδαν ιακωβου και ιουδαν ισκαριωτην ος και εγενετο προδοτης'),
(2019, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 17, 'NT', 'και καταβας μετ αυτων εστη επι τοπου πεδινου και οχλος μαθητων αυτου και πληθος πολυ του λαου απο πασης της ιουδαιας και ιερουσαλημ και της παραλιου τυρου και σιδωνος οι ηλθον ακουσαι αυτου και ιαθηναι απο των νοσων αυτων'),
(2020, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 18, 'NT', 'και οι οχλουμενοι υπο πνευματων ακαθαρτων και εθεραπευοντο'),
(2021, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 19, 'NT', 'και πας ο οχλος εζητει απτεσθαι αυτου οτι δυναμις παρ αυτου εξηρχετο και ιατο παντας'),
(2022, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 20, 'NT', 'και αυτος επαρας τους οφθαλμους αυτου εις τους μαθητας αυτου ελεγεν μακαριοι οι πτωχοι οτι υμετερα εστιν η βασιλεια του θεου'),
(2023, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 21, 'NT', 'μακαριοι οι πεινωντες νυν οτι χορτασθησεσθε μακαριοι οι κλαιοντες νυν οτι γελασετε'),
(2024, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 22, 'NT', 'μακαριοι εστε οταν μισησωσιν υμας οι ανθρωποι και οταν αφορισωσιν υμας και ονειδισωσιν και εκβαλωσιν το ονομα υμων ως πονηρον ενεκα του υιου του ανθρωπου'),
(2025, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 23, 'NT', 'χαιρετε εν εκεινη τη ημερα και σκιρτησατε ιδου γαρ ο μισθος υμων πολυς εν τω ουρανω κατα ταυτα γαρ εποιουν τοις προφηταις οι πατερες αυτων'),
(2026, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 24, 'NT', 'πλην ουαι υμιν τοις πλουσιοις οτι απεχετε την παρακλησιν υμων'),
(2027, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 25, 'NT', 'ουαι υμιν οι εμπεπλησμενοι οτι πεινασετε ουαι υμιν οι γελωντες νυν οτι πενθησετε και κλαυσετε'),
(2028, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 26, 'NT', 'ουαι υμιν οταν καλως υμας ειπωσιν παντες οι ανθρωποι κατα ταυτα γαρ εποιουν τοις ψευδοπροφηταις οι πατερες αυτων'),
(2029, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 27, 'NT', 'αλλ υμιν λεγω τοις ακουουσιν αγαπατε τους εχθρους υμων καλως ποιειτε τοις μισουσιν υμας'),
(2030, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 28, 'NT', 'ευλογειτε τους καταρωμενους υμιν και προσευχεσθε υπερ των επηρεαζοντων υμας'),
(2031, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 29, 'NT', 'τω τυπτοντι σε επι την σιαγονα παρεχε και την αλλην και απο του αιροντος σου το ιματιον και τον χιτωνα μη κωλυσης'),
(2032, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 30, 'NT', 'παντι δε τω αιτουντι σε διδου και απο του αιροντος τα σα μη απαιτει'),
(2033, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 31, 'NT', 'και καθως θελετε ινα ποιωσιν υμιν οι ανθρωποι και υμεις ποιειτε αυτοις ομοιως'),
(2034, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 32, 'NT', 'και ει αγαπατε τους αγαπωντας υμας ποια υμιν χαρις εστιν και γαρ οι αμαρτωλοι τους αγαπωντας αυτους αγαπωσιν'),
(2035, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 33, 'NT', 'και εαν αγαθοποιητε τους αγαθοποιουντας υμας ποια υμιν χαρις εστιν και γαρ οι αμαρτωλοι το αυτο ποιουσιν'),
(2036, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 34, 'NT', 'και εαν δανειζητε παρ ων ελπιζετε απολαβειν ποια υμιν χαρις εστιν και γαρ οι αμαρτωλοι αμαρτωλοις δανειζουσιν ινα απολαβωσιν τα ισα'),
(2037, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 35, 'NT', 'πλην αγαπατε τους εχθρους υμων και αγαθοποιειτε και δανειζετε μηδεν απελπιζοντες και εσται ο μισθος υμων πολυς και εσεσθε υιοι του υψιστου οτι αυτος χρηστος εστιν επι τους αχαριστους και πονηρους'),
(2038, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 36, 'NT', 'γινεσθε ουν οικτιρμονες καθως και ο πατηρ υμων οικτιρμων εστιν'),
(2039, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 37, 'NT', 'και μη κρινετε και ου μη κριθητε μη καταδικαζετε και ου μη καταδικασθητε απολυετε και απολυθησεσθε'),
(2040, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 38, 'NT', 'διδοτε και δοθησεται υμιν μετρον καλον πεπιεσμενον και σεσαλευμενον και υπερεκχυνομενον δωσουσιν εις τον κολπον υμων τω γαρ αυτω μετρω ω μετρειτε αντιμετρηθησεται υμιν'),
(2041, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 39, 'NT', 'ειπεν δε παραβολην αυτοις μητι δυναται τυφλος τυφλον οδηγειν ουχι αμφοτεροι εις βοθυνον πεσουνται'),
(2042, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 40, 'NT', 'ουκ εστιν μαθητης υπερ τον διδασκαλον αυτου κατηρτισμενος δε πας εσται ως ο διδασκαλος αυτου'),
(2043, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 41, 'NT', 'τι δε βλεπεις το καρφος το εν τω οφθαλμω του αδελφου σου την δε δοκον την εν τω ιδιω οφθαλμω ου κατανοεις'),
(2044, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 42, 'NT', 'η πως δυνασαι λεγειν τω αδελφω σου αδελφε αφες εκβαλω το καρφος το εν τω οφθαλμω σου αυτος την εν τω οφθαλμω σου δοκον ου βλεπων υποκριτα εκβαλε πρωτον την δοκον εκ του οφθαλμου σου και τοτε διαβλεψεις εκβαλειν το καρφος το εν τω οφθαλμω του αδελφου σου'),
(2045, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 43, 'NT', 'ου γαρ εστιν δενδρον καλον ποιουν καρπον σαπρον ουδε δενδρον σαπρον ποιουν καρπον καλον'),
(2046, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 44, 'NT', 'εκαστον γαρ δενδρον εκ του ιδιου καρπου γινωσκεται ου γαρ εξ ακανθων συλλεγουσιν συκα ουδε εκ βατου τρυγωσιν σταφυλην'),
(2047, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 45, 'NT', 'ο αγαθος ανθρωπος εκ του αγαθου θησαυρου της καρδιας αυτου προφερει το αγαθον και ο πονηρος ανθρωπος εκ του πονηρου θησαυρου της καρδιας αυτου προφερει το πονηρον εκ γαρ του περισσευματος της καρδιας λαλει το στομα αυτου'),
(2048, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 46, 'NT', 'τι δε με καλειτε κυριε κυριε και ου ποιειτε α λεγω'),
(2049, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 47, 'NT', 'πας ο ερχομενος προς με και ακουων μου των λογων και ποιων αυτους υποδειξω υμιν τινι εστιν ομοιος'),
(2050, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 48, 'NT', 'ομοιος εστιν ανθρωπω οικοδομουντι οικιαν ος εσκαψεν και εβαθυνεν και εθηκεν θεμελιον επι την πετραν πλημμυρας δε γενομενης προσερρηξεν ο ποταμος τη οικια εκεινη και ουκ ισχυσεν σαλευσαι αυτην τεθεμελιωτο γαρ επι την πετραν'),
(2051, 42, 'TR1550', 'TR1550', 'el', 'LUK', 6, 49, 'NT', 'ο δε ακουσας και μη ποιησας ομοιος εστιν ανθρωπω οικοδομησαντι οικιαν επι την γην χωρις θεμελιου η προσερρηξεν ο ποταμος και ευθεως επεσεν και εγενετο το ρηγμα της οικιας εκεινης μεγα'),
(2052, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 1, 'NT', 'επει δε επληρωσεν παντα τα ρηματα αυτου εις τας ακοας του λαου εισηλθεν εις καπερναουμ'),
(2053, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 2, 'NT', 'εκατονταρχου δε τινος δουλος κακως εχων ημελλεν τελευταν ος ην αυτω εντιμος'),
(2054, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 3, 'NT', 'ακουσας δε περι του ιησου απεστειλεν προς αυτον πρεσβυτερους των ιουδαιων ερωτων αυτον οπως ελθων διασωση τον δουλον αυτου'),
(2055, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 4, 'NT', 'οι δε παραγενομενοι προς τον ιησουν παρεκαλουν αυτον σπουδαιως λεγοντες οτι αξιος εστιν ω παρεξει τουτο'),
(2056, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 5, 'NT', 'αγαπα γαρ το εθνος ημων και την συναγωγην αυτος ωκοδομησεν ημιν'),
(2057, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 6, 'NT', 'ο δε ιησους επορευετο συν αυτοις ηδη δε αυτου ου μακραν απεχοντος απο της οικιας επεμψεν προς αυτον ο εκατονταρχος φιλους λεγων αυτω κυριε μη σκυλλου ου γαρ ειμι ικανος ινα υπο την στεγην μου εισελθης'),
(2058, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 7, 'NT', 'διο ουδε εμαυτον ηξιωσα προς σε ελθειν αλλα ειπε λογω και ιαθησεται ο παις μου'),
(2059, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 8, 'NT', 'και γαρ εγω ανθρωπος ειμι υπο εξουσιαν τασσομενος εχων υπ εμαυτον στρατιωτας και λεγω τουτω πορευθητι και πορευεται και αλλω ερχου και ερχεται και τω δουλω μου ποιησον τουτο και ποιει'),
(2060, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 9, 'NT', 'ακουσας δε ταυτα ο ιησους εθαυμασεν αυτον και στραφεις τω ακολουθουντι αυτω οχλω ειπεν λεγω υμιν ουδε εν τω ισραηλ τοσαυτην πιστιν ευρον'),
(2061, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 10, 'NT', 'και υποστρεψαντες οι πεμφθεντες εις τον οικον ευρον τον ασθενουντα δουλον υγιαινοντα'),
(2062, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 11, 'NT', 'και εγενετο εν τη εξης επορευετο εις πολιν καλουμενην ναιν και συνεπορευοντο αυτω οι μαθηται αυτου ικανοι και οχλος πολυς'),
(2063, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 12, 'NT', 'ως δε ηγγισεν τη πυλη της πολεως και ιδου εξεκομιζετο τεθνηκως υιος μονογενης τη μητρι αυτου και αυτη ην χηρα και οχλος της πολεως ικανος συν αυτη'),
(2064, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 13, 'NT', 'και ιδων αυτην ο κυριος εσπλαγχνισθη επ αυτη και ειπεν αυτη μη κλαιε'),
(2065, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 14, 'NT', 'και προσελθων ηψατο της σορου οι δε βασταζοντες εστησαν και ειπεν νεανισκε σοι λεγω εγερθητι'),
(2066, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 15, 'NT', 'και ανεκαθισεν ο νεκρος και ηρξατο λαλειν και εδωκεν αυτον τη μητρι αυτου'),
(2067, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 16, 'NT', 'ελαβεν δε φοβος απαντας και εδοξαζον τον θεον λεγοντες οτι προφητης μεγας εγηγερται εν ημιν και οτι επεσκεψατο ο θεος τον λαον αυτου'),
(2068, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 17, 'NT', 'και εξηλθεν ο λογος ουτος εν ολη τη ιουδαια περι αυτου και εν παση τη περιχωρω'),
(2069, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 18, 'NT', 'και απηγγειλαν ιωαννη οι μαθηται αυτου περι παντων τουτων'),
(2070, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 19, 'NT', 'και προσκαλεσαμενος δυο τινας των μαθητων αυτου ο ιωαννης επεμψεν προς τον ιησουν λεγων συ ει ο ερχομενος η αλλον προσδοκωμεν'),
(2071, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 20, 'NT', 'παραγενομενοι δε προς αυτον οι ανδρες ειπον ιωαννης ο βαπτιστης απεσταλκεν ημας προς σε λεγων συ ει ο ερχομενος η αλλον προσδοκωμεν'),
(2072, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 21, 'NT', 'εν αυτη δε τη ωρα εθεραπευσεν πολλους απο νοσων και μαστιγων και πνευματων πονηρων και τυφλοις πολλοις εχαρισατο το βλεπειν'),
(2073, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 22, 'NT', 'και αποκριθεις ο ιησους ειπεν αυτοις πορευθεντες απαγγειλατε ιωαννη α ειδετε και ηκουσατε οτι τυφλοι αναβλεπουσιν χωλοι περιπατουσιν λεπροι καθαριζονται κωφοι ακουουσιν νεκροι εγειρονται πτωχοι ευαγγελιζονται'),
(2074, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 23, 'NT', 'και μακαριος εστιν ος εαν μη σκανδαλισθη εν εμοι'),
(2075, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 24, 'NT', 'απελθοντων δε των αγγελων ιωαννου ηρξατο λεγειν προς τους οχλους περι ιωαννου τι εξεληλυθατε εις την ερημον θεασασθαι καλαμον υπο ανεμου σαλευομενον'),
(2076, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 25, 'NT', 'αλλα τι εξεληλυθατε ιδειν ανθρωπον εν μαλακοις ιματιοις ημφιεσμενον ιδου οι εν ιματισμω ενδοξω και τρυφη υπαρχοντες εν τοις βασιλειοις εισιν'),
(2077, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 26, 'NT', 'αλλα τι εξεληλυθατε ιδειν προφητην ναι λεγω υμιν και περισσοτερον προφητου'),
(2078, 42, 'TR1550', 'TR1550', 'el', 'LUK', 7, 27, 'NT', 'ουτος εστιν περι ου γεγραπται ιδου εγω αποστελλω τον αγγελον μου προ προσωπου σου ος κατασκευασει την οδον σου εμπροσθεν σου'),
