(2238, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 19, 'NT', 'ιδου διδωμι υμιν την εξουσιαν του πατειν επανω οφεων και σκορπιων και επι πασαν την δυναμιν του εχθρου και ουδεν υμας ου μη αδικηση'),
(2239, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 20, 'NT', 'πλην εν τουτω μη χαιρετε οτι τα πνευματα υμιν υποτασσεται χαιρετε δε μαλλον οτι τα ονοματα υμων εγραφη εν τοις ουρανοις'),
(2240, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 21, 'NT', 'εν αυτη τη ωρα ηγαλλιασατο τω πνευματι ο ιησους και ειπεν εξομολογουμαι σοι πατερ κυριε του ουρανου και της γης οτι απεκρυψας ταυτα απο σοφων και συνετων και απεκαλυψας αυτα νηπιοις ναι ο πατηρ οτι ουτως εγενετο ευδοκια εμπροσθεν σου'),
(2241, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 22, 'NT', 'και στραφεις προς τους μαθητας ειπεν παντα παρεδοθη μοι υπο του πατρος μου και ουδεις γινωσκει τις εστιν ο υιος ει μη ο πατηρ και τις εστιν ο πατηρ ει μη ο υιος και ω εαν βουληται ο υιος αποκαλυψαι'),
(2242, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 23, 'NT', 'και στραφεις προς τους μαθητας κατ ιδιαν ειπεν μακαριοι οι οφθαλμοι οι βλεποντες α βλεπετε'),
(2243, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 24, 'NT', 'λεγω γαρ υμιν οτι πολλοι προφηται και βασιλεις ηθελησαν ιδειν α υμεις βλεπετε και ουκ ειδον και ακουσαι α ακουετε και ουκ ηκουσαν'),
(2244, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 25, 'NT', 'και ιδου νομικος τις ανεστη εκπειραζων αυτον και λεγων διδασκαλε τι ποιησας ζωην αιωνιον κληρονομησω'),
(2245, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 26, 'NT', 'ο δε ειπεν προς αυτον εν τω νομω τι γεγραπται πως αναγινωσκεις'),
(2246, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 27, 'NT', 'ο δε αποκριθεις ειπεν αγαπησεις κυριον τον θεον σου εξ ολης της καρδιας σου και εξ ολης της ψυχης σου και εξ ολης της ισχυος σου και εξ ολης της διανοιας σου και τον πλησιον σου ως σεαυτον'),
(2247, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 28, 'NT', 'ειπεν δε αυτω ορθως απεκριθης τουτο ποιει και ζηση'),
(2248, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 29, 'NT', 'ο δε θελων δικαιουν εαυτον ειπεν προς τον ιησουν και τις εστιν μου πλησιον'),
(2249, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 30, 'NT', 'υπολαβων δε ο ιησους ειπεν ανθρωπος τις κατεβαινεν απο ιερουσαλημ εις ιεριχω και λησταις περιεπεσεν οι και εκδυσαντες αυτον και πληγας επιθεντες απηλθον αφεντες ημιθανη τυγχανοντα'),
(2250, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 31, 'NT', 'κατα συγκυριαν δε ιερευς τις κατεβαινεν εν τη οδω εκεινη και ιδων αυτον αντιπαρηλθεν'),
(2251, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 32, 'NT', 'ομοιως δε και λευιτης γενομενος κατα τον τοπον ελθων και ιδων αντιπαρηλθεν'),
(2252, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 33, 'NT', 'σαμαρειτης δε τις οδευων ηλθεν κατ αυτον και ιδων αυτον εσπλαγχνισθη'),
(2253, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 34, 'NT', 'και προσελθων κατεδησεν τα τραυματα αυτου επιχεων ελαιον και οινον επιβιβασας δε αυτον επι το ιδιον κτηνος ηγαγεν αυτον εις πανδοχειον και επεμεληθη αυτου'),
(2254, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 35, 'NT', 'και επι την αυριον εξελθων εκβαλων δυο δηναρια εδωκεν τω πανδοχει και ειπεν αυτω επιμεληθητι αυτου και ο τι αν προσδαπανησης εγω εν τω επανερχεσθαι με αποδωσω σοι'),
(2255, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 36, 'NT', 'τις ουν τουτων των τριων δοκει σοι πλησιον γεγονεναι του εμπεσοντος εις τους ληστας'),
(2256, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 37, 'NT', 'ο δε ειπεν ο ποιησας το ελεος μετ αυτου ειπεν ουν αυτω ο ιησους πορευου και συ ποιει ομοιως'),
(2257, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 38, 'NT', 'εγενετο δε εν τω πορευεσθαι αυτους και αυτος εισηλθεν εις κωμην τινα γυνη δε τις ονοματι μαρθα υπεδεξατο αυτον εις τον οικον αυτης'),
(2258, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 39, 'NT', 'και τηδε ην αδελφη καλουμενη μαρια η και παρακαθισασα παρα τους ποδας του ιησου ηκουεν τον λογον αυτου'),
(2259, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 40, 'NT', 'η δε μαρθα περιεσπατο περι πολλην διακονιαν επιστασα δε ειπεν κυριε ου μελει σοι οτι η αδελφη μου μονην με κατελιπεν διακονειν ειπε ουν αυτη ινα μοι συναντιλαβηται'),
(2260, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 41, 'NT', 'αποκριθεις δε ειπεν αυτη ο ιησους μαρθα μαρθα μεριμνας και τυρβαζη περι πολλα'),
(2261, 42, 'TR1550', 'TR1550', 'el', 'LUK', 10, 42, 'NT', 'ενος δε εστιν χρεια μαρια δε την αγαθην μεριδα εξελεξατο ητις ουκ αφαιρεθησεται απ αυτης'),
(2262, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 1, 'NT', 'και εγενετο εν τω ειναι αυτον εν τοπω τινι προσευχομενον ως επαυσατο ειπεν τις των μαθητων αυτου προς αυτον κυριε διδαξον ημας προσευχεσθαι καθως και ιωαννης εδιδαξεν τους μαθητας αυτου'),
(2263, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 2, 'NT', 'ειπεν δε αυτοις οταν προσευχησθε λεγετε πατερ ημων ο εν τοις ουρανοις αγιασθητω το ονομα σου ελθετω η βασιλεια σου γενηθητω το θελημα σου ως εν ουρανω και επι της γης'),
(2264, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 3, 'NT', 'τον αρτον ημων τον επιουσιον διδου ημιν το καθ ημεραν'),
(2265, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 4, 'NT', 'και αφες ημιν τας αμαρτιας ημων και γαρ αυτοι αφιεμεν παντι οφειλοντι ημιν και μη εισενεγκης ημας εις πειρασμον αλλα ρυσαι ημας απο του πονηρου'),
(2266, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 5, 'NT', 'και ειπεν προς αυτους τις εξ υμων εξει φιλον και πορευσεται προς αυτον μεσονυκτιου και ειπη αυτω φιλε χρησον μοι τρεις αρτους'),
(2267, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 6, 'NT', 'επειδη φιλος μου παρεγενετο εξ οδου προς με και ουκ εχω ο παραθησω αυτω'),
(2268, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 7, 'NT', 'κακεινος εσωθεν αποκριθεις ειπη μη μοι κοπους παρεχε ηδη η θυρα κεκλεισται και τα παιδια μου μετ εμου εις την κοιτην εισιν ου δυναμαι αναστας δουναι σοι'),
(2269, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 8, 'NT', 'λεγω υμιν ει και ου δωσει αυτω αναστας δια το ειναι αυτου φιλον δια γε την αναιδειαν αυτου εγερθεις δωσει αυτω οσων χρηζει'),
(2270, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 9, 'NT', 'καγω υμιν λεγω αιτειτε και δοθησεται υμιν ζητειτε και ευρησετε κρουετε και ανοιγησεται υμιν'),
(2271, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 10, 'NT', 'πας γαρ ο αιτων λαμβανει και ο ζητων ευρισκει και τω κρουοντι ανοιγησεται'),
(2272, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 11, 'NT', 'τινα δε υμων τον πατερα αιτησει ο υιος αρτον μη λιθον επιδωσει αυτω ει και ιχθυν μη αντι ιχθυος οφιν επιδωσει αυτω'),
(2273, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 12, 'NT', 'η και εαν αιτηση ωον μη επιδωσει αυτω σκορπιον'),
(2274, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 13, 'NT', 'ει ουν υμεις πονηροι υπαρχοντες οιδατε αγαθα δοματα διδοναι τοις τεκνοις υμων ποσω μαλλον ο πατηρ ο εξ ουρανου δωσει πνευμα αγιον τοις αιτουσιν αυτον'),
(2275, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 14, 'NT', 'και ην εκβαλλων δαιμονιον και αυτο ην κωφον εγενετο δε του δαιμονιου εξελθοντος ελαλησεν ο κωφος και εθαυμασαν οι οχλοι'),
(2276, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 15, 'NT', 'τινες δε εξ αυτων ειπον εν βεελζεβουλ αρχοντι των δαιμονιων εκβαλλει τα δαιμονια'),
(2277, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 16, 'NT', 'ετεροι δε πειραζοντες σημειον παρ αυτου εζητουν εξ ουρανου'),
(2278, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 17, 'NT', 'αυτος δε ειδως αυτων τα διανοηματα ειπεν αυτοις πασα βασιλεια εφ εαυτην διαμερισθεισα ερημουται και οικος επι οικον πιπτει'),
(2279, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 18, 'NT', 'ει δε και ο σατανας εφ εαυτον διεμερισθη πως σταθησεται η βασιλεια αυτου οτι λεγετε εν βεελζεβουλ εκβαλλειν με τα δαιμονια'),
(2280, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 19, 'NT', 'ει δε εγω εν βεελζεβουλ εκβαλλω τα δαιμονια οι υιοι υμων εν τινι εκβαλλουσιν δια τουτο κριται υμων αυτοι εσονται'),
(2281, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 20, 'NT', 'ει δε εν δακτυλω θεου εκβαλλω τα δαιμονια αρα εφθασεν εφ υμας η βασιλεια του θεου'),
(2282, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 21, 'NT', 'οταν ο ισχυρος καθωπλισμενος φυλασση την εαυτου αυλην εν ειρηνη εστιν τα υπαρχοντα αυτου'),
(2283, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 22, 'NT', 'επαν δε ο ισχυροτερος αυτου επελθων νικηση αυτον την πανοπλιαν αυτου αιρει εφ η επεποιθει και τα σκυλα αυτου διαδιδωσιν'),
(2284, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 23, 'NT', 'ο μη ων μετ εμου κατ εμου εστιν και ο μη συναγων μετ εμου σκορπιζει'),
(2285, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 24, 'NT', 'οταν το ακαθαρτον πνευμα εξελθη απο του ανθρωπου διερχεται δι ανυδρων τοπων ζητουν αναπαυσιν και μη ευρισκον λεγει υποστρεψω εις τον οικον μου οθεν εξηλθον'),
(2286, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 25, 'NT', 'και ελθον ευρισκει σεσαρωμενον και κεκοσμημενον'),
(2287, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 26, 'NT', 'τοτε πορευεται και παραλαμβανει επτα ετερα πνευματα πονηροτερα εαυτου και εισελθοντα κατοικει εκει και γινεται τα εσχατα του ανθρωπου εκεινου χειρονα των πρωτων'),
(2288, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 27, 'NT', 'εγενετο δε εν τω λεγειν αυτον ταυτα επαρασα τις γυνη φωνην εκ του οχλου ειπεν αυτω μακαρια η κοιλια η βαστασασα σε και μαστοι ους εθηλασας'),
(2289, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 28, 'NT', 'αυτος δε ειπεν μενουνγε μακαριοι οι ακουοντες τον λογον του θεου και φυλασσοντες αυτον'),
(2290, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 29, 'NT', 'των δε οχλων επαθροιζομενων ηρξατο λεγειν η γενεα αυτη πονηρα εστιν σημειον επιζητει και σημειον ου δοθησεται αυτη ει μη το σημειον ιωνα του προφητου'),
(2291, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 30, 'NT', 'καθως γαρ εγενετο ιωνας σημειον τοις νινευιταις ουτως εσται και ο υιος του ανθρωπου τη γενεα ταυτη'),
(2292, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 31, 'NT', 'βασιλισσα νοτου εγερθησεται εν τη κρισει μετα των ανδρων της γενεας ταυτης και κατακρινει αυτους οτι ηλθεν εκ των περατων της γης ακουσαι την σοφιαν σολομωντος και ιδου πλειον σολομωντος ωδε'),
(2293, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 32, 'NT', 'ανδρες νινευι αναστησονται εν τη κρισει μετα της γενεας ταυτης και κατακρινουσιν αυτην οτι μετενοησαν εις το κηρυγμα ιωνα και ιδου πλειον ιωνα ωδε'),
(2294, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 33, 'NT', 'ουδεις δε λυχνον αψας εις κρυπτον τιθησιν ουδε υπο τον μοδιον αλλ επι την λυχνιαν ινα οι εισπορευομενοι το φεγγος βλεπωσιν'),
(2295, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 34, 'NT', 'ο λυχνος του σωματος εστιν ο οφθαλμος οταν ουν ο οφθαλμος σου απλους η και ολον το σωμα σου φωτεινον εστιν επαν δε πονηρος η και το σωμα σου σκοτεινον'),
(2296, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 35, 'NT', 'σκοπει ουν μη το φως το εν σοι σκοτος εστιν'),
(2297, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 36, 'NT', 'ει ουν το σωμα σου ολον φωτεινον μη εχον τι μερος σκοτεινον εσται φωτεινον ολον ως οταν ο λυχνος τη αστραπη φωτιζη σε'),
(2298, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 37, 'NT', 'εν δε τω λαλησαι ηρωτα αυτον φαρισαιος τις οπως αριστηση παρ αυτω εισελθων δε ανεπεσεν'),
(2299, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 38, 'NT', 'ο δε φαρισαιος ιδων εθαυμασεν οτι ου πρωτον εβαπτισθη προ του αριστου'),
(2300, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 39, 'NT', 'ειπεν δε ο κυριος προς αυτον νυν υμεις οι φαρισαιοι το εξωθεν του ποτηριου και του πινακος καθαριζετε το δε εσωθεν υμων γεμει αρπαγης και πονηριας'),
(2301, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 40, 'NT', 'αφρονες ουχ ο ποιησας το εξωθεν και το εσωθεν εποιησεν'),
(2302, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 41, 'NT', 'πλην τα ενοντα δοτε ελεημοσυνην και ιδου παντα καθαρα υμιν εστιν'),
(2303, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 42, 'NT', 'αλλ ουαι υμιν τοις φαρισαιοις οτι αποδεκατουτε το ηδυοσμον και το πηγανον και παν λαχανον και παρερχεσθε την κρισιν και την αγαπην του θεου ταυτα εδει ποιησαι κακεινα μη αφιεναι'),
(2304, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 43, 'NT', 'ουαι υμιν τοις φαρισαιοις οτι αγαπατε την πρωτοκαθεδριαν εν ταις συναγωγαις και τους ασπασμους εν ταις αγοραις'),
(2305, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 44, 'NT', 'ουαι υμιν γραμματεις και φαρισαιοι υποκριται οτι εστε ως τα μνημεια τα αδηλα και οι ανθρωποι οι περιπατουντες επανω ουκ οιδασιν'),
(2306, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 45, 'NT', 'αποκριθεις δε τις των νομικων λεγει αυτω διδασκαλε ταυτα λεγων και ημας υβριζεις'),
(2307, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 46, 'NT', 'ο δε ειπεν και υμιν τοις νομικοις ουαι οτι φορτιζετε τους ανθρωπους φορτια δυσβαστακτα και αυτοι ενι των δακτυλων υμων ου προσψαυετε τοις φορτιοις'),
(2308, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 47, 'NT', 'ουαι υμιν οτι οικοδομειτε τα μνημεια των προφητων οι δε πατερες υμων απεκτειναν αυτους'),
(2309, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 48, 'NT', 'αρα μαρτυρειτε και συνευδοκειτε τοις εργοις των πατερων υμων οτι αυτοι μεν απεκτειναν αυτους υμεις δε οικοδομειτε αυτων τα μνημεια'),
(2310, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 49, 'NT', 'δια τουτο και η σοφια του θεου ειπεν αποστελω εις αυτους προφητας και αποστολους και εξ αυτων αποκτενουσιν και εκδιωξουσιν'),
(2311, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 50, 'NT', 'ινα εκζητηθη το αιμα παντων των προφητων το εκχυνομενον απο καταβολης κοσμου απο της γενεας ταυτης'),
(2312, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 51, 'NT', 'απο του αιματος αβελ εως του αιματος ζαχαριου του απολομενου μεταξυ του θυσιαστηριου και του οικου ναι λεγω υμιν εκζητηθησεται απο της γενεας ταυτης'),
(2313, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 52, 'NT', 'ουαι υμιν τοις νομικοις οτι ηρατε την κλειδα της γνωσεως αυτοι ουκ εισηλθετε και τους εισερχομενους εκωλυσατε'),
(2314, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 53, 'NT', 'λεγοντος δε αυτου ταυτα προς αυτους ηρξαντο οι γραμματεις και οι φαρισαιοι δεινως ενεχειν και αποστοματιζειν αυτον περι πλειονων'),
(2315, 42, 'TR1550', 'TR1550', 'el', 'LUK', 11, 54, 'NT', 'ενεδρευοντες αυτον και ζητουντες θηρευσαι τι εκ του στοματος αυτου ινα κατηγορησωσιν αυτου'),
(2316, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 1, 'NT', 'εν οις επισυναχθεισων των μυριαδων του οχλου ωστε καταπατειν αλληλους ηρξατο λεγειν προς τους μαθητας αυτου πρωτον προσεχετε εαυτοις απο της ζυμης των φαρισαιων ητις εστιν υποκρισις'),
(2317, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 2, 'NT', 'ουδεν δε συγκεκαλυμμενον εστιν ο ουκ αποκαλυφθησεται και κρυπτον ο ου γνωσθησεται'),
(2318, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 3, 'NT', 'ανθ ων οσα εν τη σκοτια ειπατε εν τω φωτι ακουσθησεται και ο προς το ους ελαλησατε εν τοις ταμειοις κηρυχθησεται επι των δωματων'),
(2319, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 4, 'NT', 'λεγω δε υμιν τοις φιλοις μου μη φοβηθητε απο των αποκτεινοντων το σωμα και μετα ταυτα μη εχοντων περισσοτερον τι ποιησαι'),
(2320, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 5, 'NT', 'υποδειξω δε υμιν τινα φοβηθητε φοβηθητε τον μετα το αποκτειναι εξουσιαν εχοντα εμβαλειν εις την γεενναν ναι λεγω υμιν τουτον φοβηθητε'),
(2321, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 6, 'NT', 'ουχι πεντε στρουθια πωλειται ασσαριων δυο και εν εξ αυτων ουκ εστιν επιλελησμενον ενωπιον του θεου'),
(2322, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 7, 'NT', 'αλλα και αι τριχες της κεφαλης υμων πασαι ηριθμηνται μη ουν φοβεισθε πολλων στρουθιων διαφερετε'),
(2323, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 8, 'NT', 'λεγω δε υμιν πας ος αν ομολογηση εν εμοι εμπροσθεν των ανθρωπων και ο υιος του ανθρωπου ομολογησει εν αυτω εμπροσθεν των αγγελων του θεου'),
(2324, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 9, 'NT', 'ο δε αρνησαμενος με ενωπιον των ανθρωπων απαρνηθησεται ενωπιον των αγγελων του θεου'),
(2325, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 10, 'NT', 'και πας ος ερει λογον εις τον υιον του ανθρωπου αφεθησεται αυτω τω δε εις το αγιον πνευμα βλασφημησαντι ουκ αφεθησεται'),
(2326, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 11, 'NT', 'οταν δε προσφερωσιν υμας επι τας συναγωγας και τας αρχας και τας εξουσιας μη μεριμνατε πως η τι απολογησησθε η τι ειπητε'),
(2327, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 12, 'NT', 'το γαρ αγιον πνευμα διδαξει υμας εν αυτη τη ωρα α δει ειπειν'),
(2328, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 13, 'NT', 'ειπεν δε τις αυτω εκ του οχλου διδασκαλε ειπε τω αδελφω μου μερισασθαι μετ εμου την κληρονομιαν'),
(2329, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 14, 'NT', 'ο δε ειπεν αυτω ανθρωπε τις με κατεστησεν δικαστην η μεριστην εφ υμας'),
(2330, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 15, 'NT', 'ειπεν δε προς αυτους ορατε και φυλασσεσθε απο της πλεονεξιας οτι ουκ εν τω περισσευειν τινι η ζωη αυτου εστιν εκ των υπαρχοντων αυτου'),
(2331, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 16, 'NT', 'ειπεν δε παραβολην προς αυτους λεγων ανθρωπου τινος πλουσιου ευφορησεν η χωρα'),
(2332, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 17, 'NT', 'και διελογιζετο εν εαυτω λεγων τι ποιησω οτι ουκ εχω που συναξω τους καρπους μου'),
(2333, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 18, 'NT', 'και ειπεν τουτο ποιησω καθελω μου τας αποθηκας και μειζονας οικοδομησω και συναξω εκει παντα τα γενηματα μου και τα αγαθα μου'),
(2334, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 19, 'NT', 'και ερω τη ψυχη μου ψυχη εχεις πολλα αγαθα κειμενα εις ετη πολλα αναπαυου φαγε πιε ευφραινου'),
(2335, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 20, 'NT', 'ειπεν δε αυτω ο θεος αφρων ταυτη τη νυκτι την ψυχην σου απαιτουσιν απο σου α δε ητοιμασας τινι εσται'),
(2336, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 21, 'NT', 'ουτως ο θησαυριζων εαυτω και μη εις θεον πλουτων'),
(2337, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 22, 'NT', 'ειπεν δε προς τους μαθητας αυτου δια τουτο υμιν λεγω μη μεριμνατε τη ψυχη υμων τι φαγητε μηδε τω σωματι τι ενδυσησθε'),
(2338, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 23, 'NT', 'η ψυχη πλειον εστιν της τροφης και το σωμα του ενδυματος'),
(2339, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 24, 'NT', 'κατανοησατε τους κορακας οτι ου σπειρουσιν ουδε θεριζουσιν οις ουκ εστιν ταμειον ουδε αποθηκη και ο θεος τρεφει αυτους ποσω μαλλον υμεις διαφερετε των πετεινων'),
(2340, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 25, 'NT', 'τις δε εξ υμων μεριμνων δυναται προσθειναι επι την ηλικιαν αυτου πηχυν ενα'),
(2341, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 26, 'NT', 'ει ουν ουτε ελαχιστον δυνασθε τι περι των λοιπων μεριμνατε'),
(2342, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 27, 'NT', 'κατανοησατε τα κρινα πως αυξανει ου κοπια ουδε νηθει λεγω δε υμιν ουδε σολομων εν παση τη δοξη αυτου περιεβαλετο ως εν τουτων'),
(2343, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 28, 'NT', 'ει δε τον χορτον εν τω αγρω σημερον οντα και αυριον εις κλιβανον βαλλομενον ο θεος ουτως αμφιεννυσιν ποσω μαλλον υμας ολιγοπιστοι'),
(2344, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 29, 'NT', 'και υμεις μη ζητειτε τι φαγητε η τι πιητε και μη μετεωριζεσθε'),
(2345, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 30, 'NT', 'ταυτα γαρ παντα τα εθνη του κοσμου επιζητει υμων δε ο πατηρ οιδεν οτι χρηζετε τουτων'),
(2346, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 31, 'NT', 'πλην ζητειτε την βασιλειαν του θεου και ταυτα παντα προστεθησεται υμιν'),
(2347, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 32, 'NT', 'μη φοβου το μικρον ποιμνιον οτι ευδοκησεν ο πατηρ υμων δουναι υμιν την βασιλειαν'),
(2348, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 33, 'NT', 'πωλησατε τα υπαρχοντα υμων και δοτε ελεημοσυνην ποιησατε εαυτοις βαλαντια μη παλαιουμενα θησαυρον ανεκλειπτον εν τοις ουρανοις οπου κλεπτης ουκ εγγιζει ουδε σης διαφθειρει'),
(2349, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 34, 'NT', 'οπου γαρ εστιν ο θησαυρος υμων εκει και η καρδια υμων εσται'),
(2350, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 35, 'NT', 'εστωσαν υμων αι οσφυες περιεζωσμεναι και οι λυχνοι καιομενοι'),
(2351, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 36, 'NT', 'και υμεις ομοιοι ανθρωποις προσδεχομενοις τον κυριον εαυτων ποτε αναλυσει εκ των γαμων ινα ελθοντος και κρουσαντος ευθεως ανοιξωσιν αυτω'),
(2352, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 37, 'NT', 'μακαριοι οι δουλοι εκεινοι ους ελθων ο κυριος ευρησει γρηγορουντας αμην λεγω υμιν οτι περιζωσεται και ανακλινει αυτους και παρελθων διακονησει αυτοις'),
(2353, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 38, 'NT', 'και εαν ελθη εν τη δευτερα φυλακη και εν τη τριτη φυλακη ελθη και ευρη ουτως μακαριοι εισιν οι δουλοι εκεινοι'),
(2354, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 39, 'NT', 'τουτο δε γινωσκετε οτι ει ηδει ο οικοδεσποτης ποια ωρα ο κλεπτης ερχεται εγρηγορησεν αν και ουκ αν αφηκεν διορυγηναι τον οικον αυτου'),
(2355, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 40, 'NT', 'και υμεις ουν γινεσθε ετοιμοι οτι η ωρα ου δοκειτε ο υιος του ανθρωπου ερχεται'),
(2356, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 41, 'NT', 'ειπεν δε αυτω ο πετρος κυριε προς ημας την παραβολην ταυτην λεγεις η και προς παντας'),
(2357, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 42, 'NT', 'ειπεν δε ο κυριος τις αρα εστιν ο πιστος οικονομος και φρονιμος ον καταστησει ο κυριος επι της θεραπειας αυτου του διδοναι εν καιρω το σιτομετριον'),
(2358, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 43, 'NT', 'μακαριος ο δουλος εκεινος ον ελθων ο κυριος αυτου ευρησει ποιουντα ουτως'),
(2359, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 44, 'NT', 'αληθως λεγω υμιν οτι επι πασιν τοις υπαρχουσιν αυτου καταστησει αυτον'),
(2360, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 45, 'NT', 'εαν δε ειπη ο δουλος εκεινος εν τη καρδια αυτου χρονιζει ο κυριος μου ερχεσθαι και αρξηται τυπτειν τους παιδας και τας παιδισκας εσθιειν τε και πινειν και μεθυσκεσθαι'),
(2361, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 46, 'NT', 'ηξει ο κυριος του δουλου εκεινου εν ημερα η ου προσδοκα και εν ωρα η ου γινωσκει και διχοτομησει αυτον και το μερος αυτου μετα των απιστων θησει'),
(2362, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 47, 'NT', 'εκεινος δε ο δουλος ο γνους το θελημα του κυριου εαυτου και μη ετοιμασας μηδε ποιησας προς το θελημα αυτου δαρησεται πολλας'),
(2363, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 48, 'NT', 'ο δε μη γνους ποιησας δε αξια πληγων δαρησεται ολιγας παντι δε ω εδοθη πολυ πολυ ζητηθησεται παρ αυτου και ω παρεθεντο πολυ περισσοτερον αιτησουσιν αυτον'),
(2364, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 49, 'NT', 'πυρ ηλθον βαλειν εις την γην και τι θελω ει ηδη ανηφθη'),
(2365, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 50, 'NT', 'βαπτισμα δε εχω βαπτισθηναι και πως συνεχομαι εως ου τελεσθη'),
(2366, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 51, 'NT', 'δοκειτε οτι ειρηνην παρεγενομην δουναι εν τη γη ουχι λεγω υμιν αλλ η διαμερισμον'),
(2367, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 52, 'NT', 'εσονται γαρ απο του νυν πεντε εν οικω ενι διαμεμερισμενοι τρεις επι δυσιν και δυο επι τρισιν'),
(2368, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 53, 'NT', 'διαμερισθησεται πατηρ εφ υιω και υιος επι πατρι μητηρ επι θυγατρι και θυγατηρ επι μητρι πενθερα επι την νυμφην αυτης και νυμφη επι την πενθεραν αυτης'),
(2369, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 54, 'NT', 'ελεγεν δε και τοις οχλοις οταν ιδητε την νεφελην ανατελλουσαν απο δυσμων ευθεως λεγετε ομβρος ερχεται και γινεται ουτως'),
(2370, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 55, 'NT', 'και οταν νοτον πνεοντα λεγετε οτι καυσων εσται και γινεται'),
(2371, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 56, 'NT', 'υποκριται το προσωπον της γης και του ουρανου οιδατε δοκιμαζειν τον δε καιρον τουτον πως ου δοκιμαζετε'),
(2372, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 57, 'NT', 'τι δε και αφ εαυτων ου κρινετε το δικαιον'),
(2373, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 58, 'NT', 'ως γαρ υπαγεις μετα του αντιδικου σου επ αρχοντα εν τη οδω δος εργασιαν απηλλαχθαι απ αυτου μηποτε κατασυρη σε προς τον κριτην και ο κριτης σε παραδω τω πρακτορι και ο πρακτωρ σε βαλλη εις φυλακην'),
(2374, 42, 'TR1550', 'TR1550', 'el', 'LUK', 12, 59, 'NT', 'λεγω σοι ου μη εξελθης εκειθεν εως ου και το εσχατον λεπτον αποδως'),
(2375, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 1, 'NT', 'παρησαν δε τινες εν αυτω τω καιρω απαγγελλοντες αυτω περι των γαλιλαιων ων το αιμα πιλατος εμιξεν μετα των θυσιων αυτων'),
(2376, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 2, 'NT', 'και αποκριθεις ο ιησους ειπεν αυτοις δοκειτε οτι οι γαλιλαιοι ουτοι αμαρτωλοι παρα παντας τους γαλιλαιους εγενοντο οτι τοιαυτα πεπονθασιν'),
(2377, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 3, 'NT', 'ουχι λεγω υμιν αλλ εαν μη μετανοητε παντες ωσαυτως απολεισθε'),
(2378, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 4, 'NT', 'η εκεινοι οι δεκα και οκτω εφ ους επεσεν ο πυργος εν τω σιλωαμ και απεκτεινεν αυτους δοκειτε οτι ουτοι οφειλεται εγενοντο παρα παντας ανθρωπους τους κατοικουντας εν ιερουσαλημ'),
(2379, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 5, 'NT', 'ουχι λεγω υμιν αλλ εαν μη μετανοητε παντες ομοιως απολεισθε'),
(2380, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 6, 'NT', 'ελεγεν δε ταυτην την παραβολην συκην ειχεν τις εν τω αμπελωνι αυτου πεφυτευμενην και ηλθεν καρπον ζητων εν αυτη και ουχ ευρεν'),
(2381, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 7, 'NT', 'ειπεν δε προς τον αμπελουργον ιδου τρια ετη ερχομαι ζητων καρπον εν τη συκη ταυτη και ουχ ευρισκω εκκοψον αυτην ινα τι και την γην καταργει'),
(2382, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 8, 'NT', 'ο δε αποκριθεις λεγει αυτω κυριε αφες αυτην και τουτο το ετος εως οτου σκαψω περι αυτην και βαλω κοπριαν'),
(2383, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 9, 'NT', 'καν μεν ποιηση καρπον ει δε μηγε εις το μελλον εκκοψεις αυτην'),
(2384, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 10, 'NT', 'ην δε διδασκων εν μια των συναγωγων εν τοις σαββασιν'),
(2385, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 11, 'NT', 'και ιδου γυνη ην πνευμα εχουσα ασθενειας ετη δεκα και οκτω και ην συγκυπτουσα και μη δυναμενη ανακυψαι εις το παντελες'),
(2386, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 12, 'NT', 'ιδων δε αυτην ο ιησους προσεφωνησεν και ειπεν αυτη γυναι απολελυσαι της ασθενειας σου'),
(2387, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 13, 'NT', 'και επεθηκεν αυτη τας χειρας και παραχρημα ανωρθωθη και εδοξαζεν τον θεον'),
(2388, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 14, 'NT', 'αποκριθεις δε ο αρχισυναγωγος αγανακτων οτι τω σαββατω εθεραπευσεν ο ιησους ελεγεν τω οχλω εξ ημεραι εισιν εν αις δει εργαζεσθαι εν ταυταις ουν ερχομενοι θεραπευεσθε και μη τη ημερα του σαββατου'),
(2389, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 15, 'NT', 'απεκριθη ουν αυτω ο κυριος και ειπεν υποκριτα εκαστος υμων τω σαββατω ου λυει τον βουν αυτου η τον ονον απο της φατνης και απαγαγων ποτιζει'),
(2390, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 16, 'NT', 'ταυτην δε θυγατερα αβρααμ ουσαν ην εδησεν ο σατανας ιδου δεκα και οκτω ετη ουκ εδει λυθηναι απο του δεσμου τουτου τη ημερα του σαββατου'),
(2391, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 17, 'NT', 'και ταυτα λεγοντος αυτου κατησχυνοντο παντες οι αντικειμενοι αυτω και πας ο οχλος εχαιρεν επι πασιν τοις ενδοξοις τοις γινομενοις υπ αυτου'),
(2392, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 18, 'NT', 'ελεγεν δε τινι ομοια εστιν η βασιλεια του θεου και τινι ομοιωσω αυτην'),
(2393, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 19, 'NT', 'ομοια εστιν κοκκω σιναπεως ον λαβων ανθρωπος εβαλεν εις κηπον εαυτου και ηυξησεν και εγενετο εις δενδρον μεγα και τα πετεινα του ουρανου κατεσκηνωσεν εν τοις κλαδοις αυτου'),
(2394, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 20, 'NT', 'και παλιν ειπεν τινι ομοιωσω την βασιλειαν του θεου'),
(2395, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 21, 'NT', 'ομοια εστιν ζυμη ην λαβουσα γυνη ενεκρυψεν εις αλευρου σατα τρια εως ου εζυμωθη ολον'),
(2396, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 22, 'NT', 'και διεπορευετο κατα πολεις και κωμας διδασκων και πορειαν ποιουμενος εις ιερουσαλημ'),
(2397, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 23, 'NT', 'ειπεν δε τις αυτω κυριε ει ολιγοι οι σωζομενοι ο δε ειπεν προς αυτους'),
(2398, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 24, 'NT', 'αγωνιζεσθε εισελθειν δια της στενης πυλης οτι πολλοι λεγω υμιν ζητησουσιν εισελθειν και ουκ ισχυσουσιν'),
(2399, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 25, 'NT', 'αφ ου αν εγερθη ο οικοδεσποτης και αποκλειση την θυραν και αρξησθε εξω εσταναι και κρουειν την θυραν λεγοντες κυριε κυριε ανοιξον ημιν και αποκριθεις ερει υμιν ουκ οιδα υμας ποθεν εστε'),
(2400, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 26, 'NT', 'τοτε αρξεσθε λεγειν εφαγομεν ενωπιον σου και επιομεν και εν ταις πλατειαις ημων εδιδαξας'),
(2401, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 27, 'NT', 'και ερει λεγω υμιν ουκ οιδα υμας ποθεν εστε αποστητε απ εμου παντες οι εργαται της αδικιας'),
(2402, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 28, 'NT', 'εκει εσται ο κλαυθμος και ο βρυγμος των οδοντων οταν οψησθε αβρααμ και ισαακ και ιακωβ και παντας τους προφητας εν τη βασιλεια του θεου υμας δε εκβαλλομενους εξω'),
(2403, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 29, 'NT', 'και ηξουσιν απο ανατολων και δυσμων και απο βορρα και νοτου και ανακλιθησονται εν τη βασιλεια του θεου'),
(2404, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 30, 'NT', 'και ιδου εισιν εσχατοι οι εσονται πρωτοι και εισιν πρωτοι οι εσονται εσχατοι'),
(2405, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 31, 'NT', 'εν αυτη τη ημερα προσηλθον τινες φαρισαιοι λεγοντες αυτω εξελθε και πορευου εντευθεν οτι ηρωδης θελει σε αποκτειναι'),
(2406, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 32, 'NT', 'και ειπεν αυτοις πορευθεντες ειπατε τη αλωπεκι ταυτη ιδου εκβαλλω δαιμονια και ιασεις επιτελω σημερον και αυριον και τη τριτη τελειουμαι'),
(2407, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 33, 'NT', 'πλην δει με σημερον και αυριον και τη εχομενη πορευεσθαι οτι ουκ ενδεχεται προφητην απολεσθαι εξω ιερουσαλημ'),
(2408, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 34, 'NT', 'ιερουσαλημ ιερουσαλημ η αποκτεινουσα τους προφητας και λιθοβολουσα τους απεσταλμενους προς αυτην ποσακις ηθελησα επισυναξαι τα τεκνα σου ον τροπον ορνις την εαυτης νοσσιαν υπο τας πτερυγας και ουκ ηθελησατε'),
(2409, 42, 'TR1550', 'TR1550', 'el', 'LUK', 13, 35, 'NT', 'ιδου αφιεται υμιν ο οικος υμων ερημος αμην δε λεγω υμιν οτι ου μη με ιδητε εως αν ηξη οτε ειπητε ευλογημενος ο ερχομενος εν ονοματι κυριου'),
(2410, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 1, 'NT', 'και εγενετο εν τω ελθειν αυτον εις οικον τινος των αρχοντων των φαρισαιων σαββατω φαγειν αρτον και αυτοι ησαν παρατηρουμενοι αυτον'),
(2411, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 2, 'NT', 'και ιδου ανθρωπος τις ην υδρωπικος εμπροσθεν αυτου'),
(2412, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 3, 'NT', 'και αποκριθεις ο ιησους ειπεν προς τους νομικους και φαρισαιους λεγων ει εξεστιν τω σαββατω θεραπευειν'),
(2413, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 4, 'NT', 'οι δε ησυχασαν και επιλαβομενος ιασατο αυτον και απελυσεν'),
(2414, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 5, 'NT', 'και αποκριθεις προς αυτους ειπεν τινος υμων ονος η βους εις φρεαρ εμπεσειται και ουκ ευθεως ανασπασει αυτον εν τη ημερα του σαββατου'),
(2415, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 6, 'NT', 'και ουκ ισχυσαν ανταποκριθηναι αυτω προς ταυτα'),
(2416, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 7, 'NT', 'ελεγεν δε προς τους κεκλημενους παραβολην επεχων πως τας πρωτοκλισιας εξελεγοντο λεγων προς αυτους'),
(2417, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 8, 'NT', 'οταν κληθης υπο τινος εις γαμους μη κατακλιθης εις την πρωτοκλισιαν μηποτε εντιμοτερος σου η κεκλημενος υπ αυτου'),
(2418, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 9, 'NT', 'και ελθων ο σε και αυτον καλεσας ερει σοι δος τουτω τοπον και τοτε αρξη μετ αισχυνης τον εσχατον τοπον κατεχειν'),
(2419, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 10, 'NT', 'αλλ οταν κληθης πορευθεις αναπεσον εις τον εσχατον τοπον ινα οταν ελθη ο κεκληκως σε ειπη σοι φιλε προσαναβηθι ανωτερον τοτε εσται σοι δοξα ενωπιον των συνανακειμενων σοι'),
(2420, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 11, 'NT', 'οτι πας ο υψων εαυτον ταπεινωθησεται και ο ταπεινων εαυτον υψωθησεται'),
(2421, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 12, 'NT', 'ελεγεν δε και τω κεκληκοτι αυτον οταν ποιης αριστον η δειπνον μη φωνει τους φιλους σου μηδε τους αδελφους σου μηδε τους συγγενεις σου μηδε γειτονας πλουσιους μηποτε και αυτοι σε αντικαλεσωσιν και γενηται σοι ανταποδομα'),
(2422, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 13, 'NT', 'αλλ οταν ποιης δοχην καλει πτωχους αναπηρους χωλους τυφλους'),
(2423, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 14, 'NT', 'και μακαριος εση οτι ουκ εχουσιν ανταποδουναι σοι ανταποδοθησεται γαρ σοι εν τη αναστασει των δικαιων'),
(2424, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 15, 'NT', 'ακουσας δε τις των συνανακειμενων ταυτα ειπεν αυτω μακαριος ος φαγεται αρτον εν τη βασιλεια του θεου'),
(2425, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 16, 'NT', 'ο δε ειπεν αυτω ανθρωπος τις εποιησεν δειπνον μεγα και εκαλεσεν πολλους'),
(2426, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 17, 'NT', 'και απεστειλεν τον δουλον αυτου τη ωρα του δειπνου ειπειν τοις κεκλημενοις ερχεσθε οτι ηδη ετοιμα εστιν παντα'),
(2427, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 18, 'NT', 'και ηρξαντο απο μιας παραιτεισθαι παντες ο πρωτος ειπεν αυτω αγρον ηγορασα και εχω αναγκην εξελθειν και ιδειν αυτον ερωτω σε εχε με παρητημενον'),
(2428, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 19, 'NT', 'και ετερος ειπεν ζευγη βοων ηγορασα πεντε και πορευομαι δοκιμασαι αυτα ερωτω σε εχε με παρητημενον'),
(2429, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 20, 'NT', 'και ετερος ειπεν γυναικα εγημα και δια τουτο ου δυναμαι ελθειν'),
(2430, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 21, 'NT', 'και παραγενομενος ο δουλος εκεινος απηγγειλεν τω κυριω αυτου ταυτα τοτε οργισθεις ο οικοδεσποτης ειπεν τω δουλω αυτου εξελθε ταχεως εις τας πλατειας και ρυμας της πολεως και τους πτωχους και αναπηρους και χωλους και τυφλους εισαγαγε ωδε'),
(2431, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 22, 'NT', 'και ειπεν ο δουλος κυριε γεγονεν ως επεταξας και ετι τοπος εστιν'),
(2432, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 23, 'NT', 'και ειπεν ο κυριος προς τον δουλον εξελθε εις τας οδους και φραγμους και αναγκασον εισελθειν ινα γεμισθη ο οικος μου'),
(2433, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 24, 'NT', 'λεγω γαρ υμιν οτι ουδεις των ανδρων εκεινων των κεκλημενων γευσεται μου του δειπνου'),
(2434, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 25, 'NT', 'συνεπορευοντο δε αυτω οχλοι πολλοι και στραφεις ειπεν προς αυτους'),
(2435, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 26, 'NT', 'ει τις ερχεται προς με και ου μισει τον πατερα εαυτου και την μητερα και την γυναικα και τα τεκνα και τους αδελφους και τας αδελφας ετι δε και την εαυτου ψυχην ου δυναται μου μαθητης ειναι'),
(2436, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 27, 'NT', 'και οστις ου βασταζει τον σταυρον αυτου και ερχεται οπισω μου ου δυναται μου ειναι μαθητης'),
(2437, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 28, 'NT', 'τις γαρ εξ υμων θελων πυργον οικοδομησαι ουχι πρωτον καθισας ψηφιζει την δαπανην ει εχει τα προς απαρτισμον'),
(2438, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 29, 'NT', 'ινα μηποτε θεντος αυτου θεμελιον και μη ισχυοντος εκτελεσαι παντες οι θεωρουντες αρξωνται εμπαιζειν αυτω'),
(2439, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 30, 'NT', 'λεγοντες οτι ουτος ο ανθρωπος ηρξατο οικοδομειν και ουκ ισχυσεν εκτελεσαι'),
(2440, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 31, 'NT', 'η τις βασιλευς πορευομενος συμβαλειν ετερω βασιλει εις πολεμον ουχι καθισας πρωτον βουλευεται ει δυνατος εστιν εν δεκα χιλιασιν απαντησαι τω μετα εικοσι χιλιαδων ερχομενω επ αυτον'),
(2441, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 32, 'NT', 'ει δε μηγε ετι αυτου πορρω οντος πρεσβειαν αποστειλας ερωτα τα προς ειρηνην'),
(2442, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 33, 'NT', 'ουτως ουν πας εξ υμων ος ουκ αποτασσεται πασιν τοις εαυτου υπαρχουσιν ου δυναται μου ειναι μαθητης'),
(2443, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 34, 'NT', 'καλον το αλας εαν δε το αλας μωρανθη εν τινι αρτυθησεται'),
(2444, 42, 'TR1550', 'TR1550', 'el', 'LUK', 14, 35, 'NT', 'ουτε εις γην ουτε εις κοπριαν ευθετον εστιν εξω βαλλουσιν αυτο ο εχων ωτα ακουειν ακουετω'),
(2445, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 1, 'NT', 'ησαν δε εγγιζοντες αυτω παντες οι τελωναι και οι αμαρτωλοι ακουειν αυτου'),
(2446, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 2, 'NT', 'και διεγογγυζον οι φαρισαιοι και οι γραμματεις λεγοντες οτι ουτος αμαρτωλους προσδεχεται και συνεσθιει αυτοις'),
(2447, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 3, 'NT', 'ειπεν δε προς αυτους την παραβολην ταυτην λεγων'),
(2448, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 4, 'NT', 'τις ανθρωπος εξ υμων εχων εκατον προβατα και απολεσας εν εξ αυτων ου καταλειπει τα εννενηκονταεννεα εν τη ερημω και πορευεται επι το απολωλος εως ευρη αυτο'),
(2449, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 5, 'NT', 'και ευρων επιτιθησιν επι τους ωμους εαυτου χαιρων'),
(2450, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 6, 'NT', 'και ελθων εις τον οικον συγκαλει τους φιλους και τους γειτονας λεγων αυτοις συγχαρητε μοι οτι ευρον το προβατον μου το απολωλος'),
(2451, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 7, 'NT', 'λεγω υμιν οτι ουτως χαρα εσται εν τω ουρανω επι ενι αμαρτωλω μετανοουντι η επι εννενηκονταεννεα δικαιοις οιτινες ου χρειαν εχουσιν μετανοιας'),
(2452, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 8, 'NT', 'η τις γυνη δραχμας εχουσα δεκα εαν απολεση δραχμην μιαν ουχι απτει λυχνον και σαροι την οικιαν και ζητει επιμελως εως οτου ευρη'),
(2453, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 9, 'NT', 'και ευρουσα συγκαλειται τας φιλας και τας γειτονας λεγουσα συγχαρητε μοι οτι ευρον την δραχμην ην απωλεσα'),
(2454, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 10, 'NT', 'ουτως λεγω υμιν χαρα γινεται ενωπιον των αγγελων του θεου επι ενι αμαρτωλω μετανοουντι'),
(2455, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 11, 'NT', 'ειπεν δε ανθρωπος τις ειχεν δυο υιους'),
(2456, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 12, 'NT', 'και ειπεν ο νεωτερος αυτων τω πατρι πατερ δος μοι το επιβαλλον μερος της ουσιας και διειλεν αυτοις τον βιον'),
(2457, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 13, 'NT', 'και μετ ου πολλας ημερας συναγαγων απαντα ο νεωτερος υιος απεδημησεν εις χωραν μακραν και εκει διεσκορπισεν την ουσιαν αυτου ζων ασωτως'),
(2458, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 14, 'NT', 'δαπανησαντος δε αυτου παντα εγενετο λιμος ισχυρος κατα την χωραν εκεινην και αυτος ηρξατο υστερεισθαι'),
(2459, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 15, 'NT', 'και πορευθεις εκολληθη ενι των πολιτων της χωρας εκεινης και επεμψεν αυτον εις τους αγρους αυτου βοσκειν χοιρους'),
(2460, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 16, 'NT', 'και επεθυμει γεμισαι την κοιλιαν αυτου απο των κερατιων ων ησθιον οι χοιροι και ουδεις εδιδου αυτω'),
(2461, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 17, 'NT', 'εις εαυτον δε ελθων ειπεν ποσοι μισθιοι του πατρος μου περισσευουσιν αρτων εγω δε λιμω απολλυμαι'),
(2462, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 18, 'NT', 'αναστας πορευσομαι προς τον πατερα μου και ερω αυτω πατερ ημαρτον εις τον ουρανον και ενωπιον σου'),
(2463, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 19, 'NT', 'και ουκετι ειμι αξιος κληθηναι υιος σου ποιησον με ως ενα των μισθιων σου'),
(2464, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 20, 'NT', 'και αναστας ηλθεν προς τον πατερα εαυτου ετι δε αυτου μακραν απεχοντος ειδεν αυτον ο πατηρ αυτου και εσπλαγχνισθη και δραμων επεπεσεν επι τον τραχηλον αυτου και κατεφιλησεν αυτον'),
(2465, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 21, 'NT', 'ειπεν δε αυτω ο υιος πατερ ημαρτον εις τον ουρανον και ενωπιον σου και ουκετι ειμι αξιος κληθηναι υιος σου'),
(2466, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 22, 'NT', 'ειπεν δε ο πατηρ προς τους δουλους αυτου εξενεγκατε την στολην την πρωτην και ενδυσατε αυτον και δοτε δακτυλιον εις την χειρα αυτου και υποδηματα εις τους ποδας'),
(2467, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 23, 'NT', 'και ενεγκαντες τον μοσχον τον σιτευτον θυσατε και φαγοντες ευφρανθωμεν'),
(2468, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 24, 'NT', 'οτι ουτος ο υιος μου νεκρος ην και ανεζησεν και απολωλως ην και ευρεθη και ηρξαντο ευφραινεσθαι'),
(2469, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 25, 'NT', 'ην δε ο υιος αυτου ο πρεσβυτερος εν αγρω και ως ερχομενος ηγγισεν τη οικια ηκουσεν συμφωνιας και χορων'),
(2470, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 26, 'NT', 'και προσκαλεσαμενος ενα των παιδων αυτου επυνθανετο τι ειη ταυτα'),
(2471, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 27, 'NT', 'ο δε ειπεν αυτω οτι ο αδελφος σου ηκει και εθυσεν ο πατηρ σου τον μοσχον τον σιτευτον οτι υγιαινοντα αυτον απελαβεν'),
(2472, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 28, 'NT', 'ωργισθη δε και ουκ ηθελεν εισελθειν ο ουν πατηρ αυτου εξελθων παρεκαλει αυτον'),
(2473, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 29, 'NT', 'ο δε αποκριθεις ειπεν τω πατρι ιδου τοσαυτα ετη δουλευω σοι και ουδεποτε εντολην σου παρηλθον και εμοι ουδεποτε εδωκας εριφον ινα μετα των φιλων μου ευφρανθω'),
(2474, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 30, 'NT', 'οτε δε ο υιος σου ουτος ο καταφαγων σου τον βιον μετα πορνων ηλθεν εθυσας αυτω τον μοσχον τον σιτευτον'),
(2475, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 31, 'NT', 'ο δε ειπεν αυτω τεκνον συ παντοτε μετ εμου ει και παντα τα εμα σα εστιν'),
(2476, 42, 'TR1550', 'TR1550', 'el', 'LUK', 15, 32, 'NT', 'ευφρανθηναι δε και χαρηναι εδει οτι ο αδελφος σου ουτος νεκρος ην και ανεζησεν και απολωλως ην και ευρεθη'),
(2477, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 1, 'NT', 'ελεγεν δε και προς τους μαθητας αυτου ανθρωπος τις ην πλουσιος ος ειχεν οικονομον και ουτος διεβληθη αυτω ως διασκορπιζων τα υπαρχοντα αυτου'),
(2478, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 2, 'NT', 'και φωνησας αυτον ειπεν αυτω τι τουτο ακουω περι σου αποδος τον λογον της οικονομιας σου ου γαρ δυνηση ετι οικονομειν'),
(2479, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 3, 'NT', 'ειπεν δε εν εαυτω ο οικονομος τι ποιησω οτι ο κυριος μου αφαιρειται την οικονομιαν απ εμου σκαπτειν ουκ ισχυω επαιτειν αισχυνομαι'),
(2480, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 4, 'NT', 'εγνων τι ποιησω ινα οταν μετασταθω της οικονομιας δεξωνται με εις τους οικους αυτων'),
(2481, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 5, 'NT', 'και προσκαλεσαμενος ενα εκαστον των χρεωφειλετων του κυριου εαυτου ελεγεν τω πρωτω ποσον οφειλεις τω κυριω μου'),
(2482, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 6, 'NT', 'ο δε ειπεν εκατον βατους ελαιου και ειπεν αυτω δεξαι σου το γραμμα και καθισας ταχεως γραψον πεντηκοντα'),
(2483, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 7, 'NT', 'επειτα ετερω ειπεν συ δε ποσον οφειλεις ο δε ειπεν εκατον κορους σιτου και λεγει αυτω δεξαι σου το γραμμα και γραψον ογδοηκοντα'),
(2484, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 8, 'NT', 'και επηνεσεν ο κυριος τον οικονομον της αδικιας οτι φρονιμως εποιησεν οτι οι υιοι του αιωνος τουτου φρονιμωτεροι υπερ τους υιους του φωτος εις την γενεαν την εαυτων εισιν'),
(2485, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 9, 'NT', 'καγω υμιν λεγω ποιησατε εαυτοις φιλους εκ του μαμωνα της αδικιας ινα οταν εκλιπητε δεξωνται υμας εις τας αιωνιους σκηνας'),
(2486, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 10, 'NT', 'ο πιστος εν ελαχιστω και εν πολλω πιστος εστιν και ο εν ελαχιστω αδικος και εν πολλω αδικος εστιν'),
(2487, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 11, 'NT', 'ει ουν εν τω αδικω μαμωνα πιστοι ουκ εγενεσθε το αληθινον τις υμιν πιστευσει'),
(2488, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 12, 'NT', 'και ει εν τω αλλοτριω πιστοι ουκ εγενεσθε το υμετερον τις υμιν δωσει'),
(2489, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 13, 'NT', 'ουδεις οικετης δυναται δυσι κυριοις δουλευειν η γαρ τον ενα μισησει και τον ετερον αγαπησει η ενος ανθεξεται και του ετερου καταφρονησει ου δυνασθε θεω δουλευειν και μαμωνα'),
(2490, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 14, 'NT', 'ηκουον δε ταυτα παντα και οι φαρισαιοι φιλαργυροι υπαρχοντες και εξεμυκτηριζον αυτον'),
(2491, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 15, 'NT', 'και ειπεν αυτοις υμεις εστε οι δικαιουντες εαυτους ενωπιον των ανθρωπων ο δε θεος γινωσκει τας καρδιας υμων οτι το εν ανθρωποις υψηλον βδελυγμα ενωπιον του θεου εστιν'),
(2492, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 16, 'NT', 'ο νομος και οι προφηται εως ιωαννου απο τοτε η βασιλεια του θεου ευαγγελιζεται και πας εις αυτην βιαζεται'),
(2493, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 17, 'NT', 'ευκοπωτερον δε εστιν τον ουρανον και την γην παρελθειν η του νομου μιαν κεραιαν πεσειν'),
(2494, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 18, 'NT', 'πας ο απολυων την γυναικα αυτου και γαμων ετεραν μοιχευει και πας ο απολελυμενην απο ανδρος γαμων μοιχευει'),
(2495, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 19, 'NT', 'ανθρωπος δε τις ην πλουσιος και ενεδιδυσκετο πορφυραν και βυσσον ευφραινομενος καθ ημεραν λαμπρως'),
(2496, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 20, 'NT', 'πτωχος δε τις ην ονοματι λαζαρος ος εβεβλητο προς τον πυλωνα αυτου ηλκωμενος'),
(2497, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 21, 'NT', 'και επιθυμων χορτασθηναι απο των ψιχιων των πιπτοντων απο της τραπεζης του πλουσιου αλλα και οι κυνες ερχομενοι απελειχον τα ελκη αυτου'),
(2498, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 22, 'NT', 'εγενετο δε αποθανειν τον πτωχον και απενεχθηναι αυτον υπο των αγγελων εις τον κολπον του αβρααμ απεθανεν δε και ο πλουσιος και εταφη'),
(2499, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 23, 'NT', 'και εν τω αδη επαρας τους οφθαλμους αυτου υπαρχων εν βασανοις ορα τον αβρααμ απο μακροθεν και λαζαρον εν τοις κολποις αυτου'),
(2500, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 24, 'NT', 'και αυτος φωνησας ειπεν πατερ αβρααμ ελεησον με και πεμψον λαζαρον ινα βαψη το ακρον του δακτυλου αυτου υδατος και καταψυξη την γλωσσαν μου οτι οδυνωμαι εν τη φλογι ταυτη'),
(2501, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 25, 'NT', 'ειπεν δε αβρααμ τεκνον μνησθητι οτι απελαβες συ τα αγαθα σου εν τη ζωη σου και λαζαρος ομοιως τα κακα νυν δε οδε παρακαλειται συ δε οδυνασαι'),
(2502, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 26, 'NT', 'και επι πασιν τουτοις μεταξυ ημων και υμων χασμα μεγα εστηρικται οπως οι θελοντες διαβηναι εντευθεν προς υμας μη δυνωνται μηδε οι εκειθεν προς ημας διαπερωσιν'),
(2503, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 27, 'NT', 'ειπεν δε ερωτω ουν σε πατερ ινα πεμψης αυτον εις τον οικον του πατρος μου'),
(2504, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 28, 'NT', 'εχω γαρ πεντε αδελφους οπως διαμαρτυρηται αυτοις ινα μη και αυτοι ελθωσιν εις τον τοπον τουτον της βασανου'),
(2505, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 29, 'NT', 'λεγει αυτω αβρααμ εχουσιν μωσεα και τους προφητας ακουσατωσαν αυτων'),
(2506, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 30, 'NT', 'ο δε ειπεν ουχι πατερ αβρααμ αλλ εαν τις απο νεκρων πορευθη προς αυτους μετανοησουσιν'),
(2507, 42, 'TR1550', 'TR1550', 'el', 'LUK', 16, 31, 'NT', 'ειπεν δε αυτω ει μωσεως και των προφητων ουκ ακουουσιν ουδε εαν τις εκ νεκρων αναστη πεισθησονται'),
(2508, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 1, 'NT', 'ειπεν δε προς τους μαθητας ανενδεκτον εστιν του μη ελθειν τα σκανδαλα ουαι δε δι ου ερχεται'),
(2509, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 2, 'NT', 'λυσιτελει αυτω ει μυλος ονικος περικειται περι τον τραχηλον αυτου και ερριπται εις την θαλασσαν η ινα σκανδαλιση ενα των μικρων τουτων'),
(2510, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 3, 'NT', 'προσεχετε εαυτοις εαν δε αμαρτη εις σε ο αδελφος σου επιτιμησον αυτω και εαν μετανοηση αφες αυτω'),
(2511, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 4, 'NT', 'και εαν επτακις της ημερας αμαρτη εις σε και επτακις της ημερας επιστρεψη επι σε λεγων μετανοω αφησεις αυτω'),
(2512, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 5, 'NT', 'και ειπον οι αποστολοι τω κυριω προσθες ημιν πιστιν'),
(2513, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 6, 'NT', 'ειπεν δε ο κυριος ει ειχετε πιστιν ως κοκκον σιναπεως ελεγετε αν τη συκαμινω ταυτη εκριζωθητι και φυτευθητι εν τη θαλασση και υπηκουσεν αν υμιν'),
(2514, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 7, 'NT', 'τις δε εξ υμων δουλον εχων αροτριωντα η ποιμαινοντα ος εισελθοντι εκ του αγρου ερει ευθεως παρελθων αναπεσαι'),
(2515, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 8, 'NT', 'αλλ ουχι ερει αυτω ετοιμασον τι δειπνησω και περιζωσαμενος διακονει μοι εως φαγω και πιω και μετα ταυτα φαγεσαι και πιεσαι συ'),
(2516, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 9, 'NT', 'μη χαριν εχει τω δουλω εκεινω οτι εποιησεν τα διαταχθεντα αυτω ου δοκω'),
(2517, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 10, 'NT', 'ουτως και υμεις οταν ποιησητε παντα τα διαταχθεντα υμιν λεγετε οτι δουλοι αχρειοι εσμεν οτι ο ωφειλομεν ποιησαι πεποιηκαμεν'),
(2518, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 11, 'NT', 'και εγενετο εν τω πορευεσθαι αυτον εις ιερουσαλημ και αυτος διηρχετο δια μεσου σαμαρειας και γαλιλαιας'),
(2519, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 12, 'NT', 'και εισερχομενου αυτου εις τινα κωμην απηντησαν αυτω δεκα λεπροι ανδρες οι εστησαν πορρωθεν'),
(2520, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 13, 'NT', 'και αυτοι ηραν φωνην λεγοντες ιησου επιστατα ελεησον ημας'),
(2521, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 14, 'NT', 'και ιδων ειπεν αυτοις πορευθεντες επιδειξατε εαυτους τοις ιερευσιν και εγενετο εν τω υπαγειν αυτους εκαθαρισθησαν'),
(2522, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 15, 'NT', 'εις δε εξ αυτων ιδων οτι ιαθη υπεστρεψεν μετα φωνης μεγαλης δοξαζων τον θεον'),
(2523, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 16, 'NT', 'και επεσεν επι προσωπον παρα τους ποδας αυτου ευχαριστων αυτω και αυτος ην σαμαρειτης'),
(2524, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 17, 'NT', 'αποκριθεις δε ο ιησους ειπεν ουχι οι δεκα εκαθαρισθησαν οι δε εννεα που'),
(2525, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 18, 'NT', 'ουχ ευρεθησαν υποστρεψαντες δουναι δοξαν τω θεω ει μη ο αλλογενης ουτος'),
(2526, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 19, 'NT', 'και ειπεν αυτω αναστας πορευου η πιστις σου σεσωκεν σε'),
(2527, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 20, 'NT', 'επερωτηθεις δε υπο των φαρισαιων ποτε ερχεται η βασιλεια του θεου απεκριθη αυτοις και ειπεν ουκ ερχεται η βασιλεια του θεου μετα παρατηρησεως'),
(2528, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 21, 'NT', 'ουδε ερουσιν ιδου ωδε η ιδου εκει ιδου γαρ η βασιλεια του θεου εντος υμων εστιν'),
(2529, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 22, 'NT', 'ειπεν δε προς τους μαθητας ελευσονται ημεραι οτε επιθυμησετε μιαν των ημερων του υιου του ανθρωπου ιδειν και ουκ οψεσθε'),
(2530, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 23, 'NT', 'και ερουσιν υμιν ιδου ωδε η ιδου εκει μη απελθητε μηδε διωξητε'),
(2531, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 24, 'NT', 'ωσπερ γαρ η αστραπη η αστραπτουσα εκ της υπ ουρανον εις την υπ ουρανον λαμπει ουτως εσται και ο υιος του ανθρωπου εν τη ημερα αυτου'),
(2532, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 25, 'NT', 'πρωτον δε δει αυτον πολλα παθειν και αποδοκιμασθηναι απο της γενεας ταυτης'),
(2533, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 26, 'NT', 'και καθως εγενετο εν ταις ημεραις του νωε ουτως εσται και εν ταις ημεραις του υιου του ανθρωπου'),
(2534, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 27, 'NT', 'ησθιον επινον εγαμουν εξεγαμιζοντο αχρι ης ημερας εισηλθεν νωε εις την κιβωτον και ηλθεν ο κατακλυσμος και απωλεσεν απαντας'),
(2535, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 28, 'NT', 'ομοιως και ως εγενετο εν ταις ημεραις λωτ ησθιον επινον ηγοραζον επωλουν εφυτευον ωκοδομουν'),
(2536, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 29, 'NT', 'η δε ημερα εξηλθεν λωτ απο σοδομων εβρεξεν πυρ και θειον απ ουρανου και απωλεσεν απαντας'),
(2537, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 30, 'NT', 'κατα ταυτα εσται η ημερα ο υιος του ανθρωπου αποκαλυπτεται'),
(2538, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 31, 'NT', 'εν εκεινη τη ημερα ος εσται επι του δωματος και τα σκευη αυτου εν τη οικια μη καταβατω αραι αυτα και ο εν τω αγρω ομοιως μη επιστρεψατω εις τα οπισω'),
(2539, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 32, 'NT', 'μνημονευετε της γυναικος λωτ'),
(2540, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 33, 'NT', 'ος εαν ζητηση την ψυχην αυτου σωσαι απολεσει αυτην και ος εαν απολεση αυτην ζωογονησει αυτην'),
(2541, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 34, 'NT', 'λεγω υμιν ταυτη τη νυκτι εσονται δυο επι κλινης μιας ο εις παραληφθησεται και ο ετερος αφεθησεται'),
(2542, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 35, 'NT', 'δυο εσονται αληθουσαι επι το αυτο μια παραληφθησεται και η ετερα αφεθησεται'),
(2543, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 36, 'NT', '[δυο εσονται εν τω αγρω ο εις παραληφθησεται και ο ετερος αφεθησεται]'),
(2544, 42, 'TR1550', 'TR1550', 'el', 'LUK', 17, 37, 'NT', 'και αποκριθεντες λεγουσιν αυτω που κυριε ο δε ειπεν αυτοις οπου το σωμα εκει συναχθησονται οι αετοι'),
(2545, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 1, 'NT', 'ελεγεν δε και παραβολην αυτοις προς το δειν παντοτε προσευχεσθαι και μη εκκακειν'),
(2546, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 2, 'NT', 'λεγων κριτης τις ην εν τινι πολει τον θεον μη φοβουμενος και ανθρωπον μη εντρεπομενος'),
(2547, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 3, 'NT', 'χηρα δε ην εν τη πολει εκεινη και ηρχετο προς αυτον λεγουσα εκδικησον με απο του αντιδικου μου'),
(2548, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 4, 'NT', 'και ουκ ηθελησεν επι χρονον μετα δε ταυτα ειπεν εν εαυτω ει και τον θεον ου φοβουμαι και ανθρωπον ουκ εντρεπομαι'),
(2549, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 5, 'NT', 'δια γε το παρεχειν μοι κοπον την χηραν ταυτην εκδικησω αυτην ινα μη εις τελος ερχομενη υπωπιαζη με'),
(2550, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 6, 'NT', 'ειπεν δε ο κυριος ακουσατε τι ο κριτης της αδικιας λεγει'),
(2551, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 7, 'NT', 'ο δε θεος ου μη ποιησει την εκδικησιν των εκλεκτων αυτου των βοωντων προς αυτον ημερας και νυκτος και μακροθυμων επ αυτοις'),
(2552, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 8, 'NT', 'λεγω υμιν οτι ποιησει την εκδικησιν αυτων εν ταχει πλην ο υιος του ανθρωπου ελθων αρα ευρησει την πιστιν επι της γης'),
(2553, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 9, 'NT', 'ειπεν δε και προς τινας τους πεποιθοτας εφ εαυτοις οτι εισιν δικαιοι και εξουθενουντας τους λοιπους την παραβολην ταυτην'),
(2554, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 10, 'NT', 'ανθρωποι δυο ανεβησαν εις το ιερον προσευξασθαι ο εις φαρισαιος και ο ετερος τελωνης'),
(2555, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 11, 'NT', 'ο φαρισαιος σταθεις προς εαυτον ταυτα προσηυχετο ο θεος ευχαριστω σοι οτι ουκ ειμι ωσπερ οι λοιποι των ανθρωπων αρπαγες αδικοι μοιχοι η και ως ουτος ο τελωνης'),
(2556, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 12, 'NT', 'νηστευω δις του σαββατου αποδεκατω παντα οσα κτωμαι'),
(2557, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 13, 'NT', 'και ο τελωνης μακροθεν εστως ουκ ηθελεν ουδε τους οφθαλμους εις τον ουρανον επαραι αλλ ετυπτεν εις το στηθος αυτου λεγων ο θεος ιλασθητι μοι τω αμαρτωλω'),
(2558, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 14, 'NT', 'λεγω υμιν κατεβη ουτος δεδικαιωμενος εις τον οικον αυτου η εκεινος οτι πας ο υψων εαυτον ταπεινωθησεται ο δε ταπεινων εαυτον υψωθησεται'),
(2559, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 15, 'NT', 'προσεφερον δε αυτω και τα βρεφη ινα αυτων απτηται ιδοντες δε οι μαθηται επετιμησαν αυτοις'),
(2560, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 16, 'NT', 'ο δε ιησους προσκαλεσαμενος αυτα ειπεν αφετε τα παιδια ερχεσθαι προς με και μη κωλυετε αυτα των γαρ τοιουτων εστιν η βασιλεια του θεου'),
(2561, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 17, 'NT', 'αμην λεγω υμιν ος εαν μη δεξηται την βασιλειαν του θεου ως παιδιον ου μη εισελθη εις αυτην'),
(2562, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 18, 'NT', 'και επηρωτησεν τις αυτον αρχων λεγων διδασκαλε αγαθε τι ποιησας ζωην αιωνιον κληρονομησω'),
(2563, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 19, 'NT', 'ειπεν δε αυτω ο ιησους τι με λεγεις αγαθον ουδεις αγαθος ει μη εις ο θεος'),
(2564, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 20, 'NT', 'τας εντολας οιδας μη μοιχευσης μη φονευσης μη κλεψης μη ψευδομαρτυρησης τιμα τον πατερα σου και την μητερα σου'),
(2565, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 21, 'NT', 'ο δε ειπεν ταυτα παντα εφυλαξαμην εκ νεοτητος μου'),
(2566, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 22, 'NT', 'ακουσας δε ταυτα ο ιησους ειπεν αυτω ετι εν σοι λειπει παντα οσα εχεις πωλησον και διαδος πτωχοις και εξεις θησαυρον εν ουρανω και δευρο ακολουθει μοι'),
(2567, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 23, 'NT', 'ο δε ακουσας ταυτα περιλυπος εγενετο ην γαρ πλουσιος σφοδρα'),
(2568, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 24, 'NT', 'ιδων δε αυτον ο ιησους περιλυπον γενομενον ειπεν πως δυσκολως οι τα χρηματα εχοντες εισελευσονται εις την βασιλειαν του θεου'),
(2569, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 25, 'NT', 'ευκοπωτερον γαρ εστιν καμηλον δια τρυμαλιας ραφιδος εισελθειν η πλουσιον εις την βασιλειαν του θεου εισελθειν'),
(2570, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 26, 'NT', 'ειπον δε οι ακουσαντες και τις δυναται σωθηναι'),
(2571, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 27, 'NT', 'ο δε ειπεν τα αδυνατα παρα ανθρωποις δυνατα εστιν παρα τω θεω'),
(2572, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 28, 'NT', 'ειπεν δε ο πετρος ιδου ημεις αφηκαμεν παντα και ηκολουθησαμεν σοι'),
(2573, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 29, 'NT', 'ο δε ειπεν αυτοις αμην λεγω υμιν οτι ουδεις εστιν ος αφηκεν οικιαν η γονεις η αδελφους η γυναικα η τεκνα ενεκεν της βασιλειας του θεου'),
(2574, 42, 'TR1550', 'TR1550', 'el', 'LUK', 18, 30, 'NT', 'ος ου μη απολαβη πολλαπλασιονα εν τω καιρω τουτω και εν τω αιωνι τω ερχομενω ζωην αιωνιον'),
