(2666, 42, 'TR1550', 'TR1550', 'el', 'LUK', 20, 31, 'NT', 'και ο τριτος ελαβεν αυτην ωσαυτως δε και οι επτα ου κατελιπον τεκνα και απεθανον'),
(2667, 42, 'TR1550', 'TR1550', 'el', 'LUK', 20, 32, 'NT', 'υστερον δε παντων απεθανεν και η γυνη'),
(2668, 42, 'TR1550', 'TR1550', 'el', 'LUK', 20, 33, 'NT', 'εν τη ουν αναστασει τινος αυτων γινεται γυνη οι γαρ επτα εσχον αυτην γυναικα'),
(2669, 42, 'TR1550', 'TR1550', 'el', 'LUK', 20, 34, 'NT', 'και αποκριθεις ειπεν αυτοις ο ιησους οι υιοι του αιωνος τουτου γαμουσιν και εκγαμισκονται'),
(2670, 42, 'TR1550', 'TR1550', 'el', 'LUK', 20, 35, 'NT', 'οι δε καταξιωθεντες του αιωνος εκεινου τυχειν και της αναστασεως της εκ νεκρων ουτε γαμουσιν ουτε εκγαμισκονται'),
(2671, 42, 'TR1550', 'TR1550', 'el', 'LUK', 20, 36, 'NT', 'ουτε γαρ αποθανειν ετι δυνανται ισαγγελοι γαρ εισιν και υιοι εισιν του θεου της αναστασεως υιοι οντες'),
(2672, 42, 'TR1550', 'TR1550', 'el', 'LUK', 20, 37, 'NT', 'οτι δε εγειρονται οι νεκροι και μωσης εμηνυσεν επι της βατου ως λεγει κυριον τον θεον αβρααμ και τον θεον ισαακ και τον θεον ιακωβ'),
(2673, 42, 'TR1550', 'TR1550', 'el', 'LUK', 20, 38, 'NT', 'θεος δε ουκ εστιν νεκρων αλλα ζωντων παντες γαρ αυτω ζωσιν'),
(2674, 42, 'TR1550', 'TR1550', 'el', 'LUK', 20, 39, 'NT', 'αποκριθεντες δε τινες των γραμματεων ειπον διδασκαλε καλως ειπας'),
(2675, 42, 'TR1550', 'TR1550', 'el', 'LUK', 20, 40, 'NT', 'ουκετι δε ετολμων επερωταν αυτον ουδεν'),
(2676, 42, 'TR1550', 'TR1550', 'el', 'LUK', 20, 41, 'NT', 'ειπεν δε προς αυτους πως λεγουσιν τον χριστον υιον δαβιδ ειναι'),
(2677, 42, 'TR1550', 'TR1550', 'el', 'LUK', 20, 42, 'NT', 'και αυτος δαβιδ λεγει εν βιβλω ψαλμων ειπεν ο κυριος τω κυριω μου καθου εκ δεξιων μου'),
(2678, 42, 'TR1550', 'TR1550', 'el', 'LUK', 20, 43, 'NT', 'εως αν θω τους εχθρους σου υποποδιον των ποδων σου'),
(2679, 42, 'TR1550', 'TR1550', 'el', 'LUK', 20, 44, 'NT', 'δαβιδ ουν κυριον αυτον καλει και πως υιος αυτου εστιν'),
(2680, 42, 'TR1550', 'TR1550', 'el', 'LUK', 20, 45, 'NT', 'ακουοντος δε παντος του λαου ειπεν τοις μαθηταις αυτου'),
(2681, 42, 'TR1550', 'TR1550', 'el', 'LUK', 20, 46, 'NT', 'προσεχετε απο των γραμματεων των θελοντων περιπατειν εν στολαις και φιλουντων ασπασμους εν ταις αγοραις και πρωτοκαθεδριας εν ταις συναγωγαις και πρωτοκλισιας εν τοις δειπνοις'),
(2682, 42, 'TR1550', 'TR1550', 'el', 'LUK', 20, 47, 'NT', 'οι κατεσθιουσιν τας οικιας των χηρων και προφασει μακρα προσευχονται ουτοι ληψονται περισσοτερον κριμα'),
(2683, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 1, 'NT', 'αναβλεψας δε ειδεν τους βαλλοντας τα δωρα αυτων εις το γαζοφυλακιον πλουσιους'),
(2684, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 2, 'NT', 'ειδεν δε και τινα χηραν πενιχραν βαλλουσαν εκει δυο λεπτα'),
(2685, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 3, 'NT', 'και ειπεν αληθως λεγω υμιν οτι η χηρα η πτωχη αυτη πλειον παντων εβαλεν'),
(2686, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 4, 'NT', 'απαντες γαρ ουτοι εκ του περισσευοντος αυτοις εβαλον εις τα δωρα του θεου αυτη δε εκ του υστερηματος αυτης απαντα τον βιον ον ειχεν εβαλεν'),
(2687, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 5, 'NT', 'και τινων λεγοντων περι του ιερου οτι λιθοις καλοις και αναθημασιν κεκοσμηται ειπεν'),
(2688, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 6, 'NT', 'ταυτα α θεωρειτε ελευσονται ημεραι εν αις ουκ αφεθησεται λιθος επι λιθω ος ου καταλυθησεται'),
(2689, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 7, 'NT', 'επηρωτησαν δε αυτον λεγοντες διδασκαλε ποτε ουν ταυτα εσται και τι το σημειον οταν μελλη ταυτα γινεσθαι'),
(2690, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 8, 'NT', 'ο δε ειπεν βλεπετε μη πλανηθητε πολλοι γαρ ελευσονται επι τω ονοματι μου λεγοντες οτι εγω ειμι και ο καιρος ηγγικεν μη ουν πορευθητε οπισω αυτων'),
(2691, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 9, 'NT', 'οταν δε ακουσητε πολεμους και ακαταστασιας μη πτοηθητε δει γαρ ταυτα γενεσθαι πρωτον αλλ ουκ ευθεως το τελος'),
(2692, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 10, 'NT', 'τοτε ελεγεν αυτοις εγερθησεται εθνος επι εθνος και βασιλεια επι βασιλειαν'),
(2693, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 11, 'NT', 'σεισμοι τε μεγαλοι κατα τοπους και λιμοι και λοιμοι εσονται φοβητρα τε και σημεια απ ουρανου μεγαλα εσται'),
(2694, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 12, 'NT', 'προ δε τουτων απαντων επιβαλουσιν εφ υμας τας χειρας αυτων και διωξουσιν παραδιδοντες εις συναγωγας και φυλακας αγομενους επι βασιλεις και ηγεμονας ενεκεν του ονοματος μου'),
(2695, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 13, 'NT', 'αποβησεται δε υμιν εις μαρτυριον'),
(2696, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 14, 'NT', 'θεσθε ουν εις τας καρδιας υμων μη προμελεταν απολογηθηναι'),
(2697, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 15, 'NT', 'εγω γαρ δωσω υμιν στομα και σοφιαν η ου δυνησονται αντειπειν ουδε αντιστηναι παντες οι αντικειμενοι υμιν'),
(2698, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 16, 'NT', 'παραδοθησεσθε δε και υπο γονεων και αδελφων και συγγενων και φιλων και θανατωσουσιν εξ υμων'),
(2699, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 17, 'NT', 'και εσεσθε μισουμενοι υπο παντων δια το ονομα μου'),
(2700, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 18, 'NT', 'και θριξ εκ της κεφαλης υμων ου μη αποληται'),
(2701, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 19, 'NT', 'εν τη υπομονη υμων κτησασθε τας ψυχας υμων'),
(2702, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 20, 'NT', 'οταν δε ιδητε κυκλουμενην υπο στρατοπεδων την ιερουσαλημ τοτε γνωτε οτι ηγγικεν η ερημωσις αυτης'),
(2703, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 21, 'NT', 'τοτε οι εν τη ιουδαια φευγετωσαν εις τα ορη και οι εν μεσω αυτης εκχωρειτωσαν και οι εν ταις χωραις μη εισερχεσθωσαν εις αυτην'),
(2704, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 22, 'NT', 'οτι ημεραι εκδικησεως αυται εισιν του πληρωθηναι παντα τα γεγραμμενα'),
(2705, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 23, 'NT', 'ουαι δε ταις εν γαστρι εχουσαις και ταις θηλαζουσαις εν εκειναις ταις ημεραις εσται γαρ αναγκη μεγαλη επι της γης και οργη εν τω λαω τουτω'),
(2706, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 24, 'NT', 'και πεσουνται στοματι μαχαιρας και αιχμαλωτισθησονται εις παντα τα εθνη και ιερουσαλημ εσται πατουμενη υπο εθνων αχρι πληρωθωσιν καιροι εθνων'),
(2707, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 25, 'NT', 'και εσται σημεια εν ηλιω και σεληνη και αστροις και επι της γης συνοχη εθνων εν απορια ηχουσης θαλασσης και σαλου'),
(2708, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 26, 'NT', 'αποψυχοντων ανθρωπων απο φοβου και προσδοκιας των επερχομενων τη οικουμενη αι γαρ δυναμεις των ουρανων σαλευθησονται'),
(2709, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 27, 'NT', 'και τοτε οψονται τον υιον του ανθρωπου ερχομενον εν νεφελη μετα δυναμεως και δοξης πολλης'),
(2710, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 28, 'NT', 'αρχομενων δε τουτων γινεσθαι ανακυψατε και επαρατε τας κεφαλας υμων διοτι εγγιζει η απολυτρωσις υμων'),
(2711, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 29, 'NT', 'και ειπεν παραβολην αυτοις ιδετε την συκην και παντα τα δενδρα'),
(2712, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 30, 'NT', 'οταν προβαλωσιν ηδη βλεποντες αφ εαυτων γινωσκετε οτι ηδη εγγυς το θερος εστιν'),
(2713, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 31, 'NT', 'ουτως και υμεις οταν ιδητε ταυτα γινομενα γινωσκετε οτι εγγυς εστιν η βασιλεια του θεου'),
(2714, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 32, 'NT', 'αμην λεγω υμιν οτι ου μη παρελθη η γενεα αυτη εως αν παντα γενηται'),
(2715, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 33, 'NT', 'ο ουρανος και η γη παρελευσονται οι δε λογοι μου ου μη παρελθωσιν'),
(2716, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 34, 'NT', 'προσεχετε δε εαυτοις μηποτε βαρυνθωσιν υμων αι καρδιαι εν κραιπαλη και μεθη και μεριμναις βιωτικαις και αιφνιδιος εφ υμας επιστη η ημερα εκεινη'),
(2717, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 35, 'NT', 'ως παγις γαρ επελευσεται επι παντας τους καθημενους επι προσωπον πασης της γης'),
(2718, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 36, 'NT', 'αγρυπνειτε ουν εν παντι καιρω δεομενοι ινα καταξιωθητε εκφυγειν ταυτα παντα τα μελλοντα γινεσθαι και σταθηναι εμπροσθεν του υιου του ανθρωπου'),
(2719, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 37, 'NT', 'ην δε τας ημερας εν τω ιερω διδασκων τας δε νυκτας εξερχομενος ηυλιζετο εις το ορος το καλουμενον ελαιων'),
(2720, 42, 'TR1550', 'TR1550', 'el', 'LUK', 21, 38, 'NT', 'και πας ο λαος ωρθριζεν προς αυτον εν τω ιερω ακουειν αυτου'),
(2721, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 1, 'NT', 'ηγγιζεν δε η εορτη των αζυμων η λεγομενη πασχα'),
(2722, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 2, 'NT', 'και εζητουν οι αρχιερεις και οι γραμματεις το πως ανελωσιν αυτον εφοβουντο γαρ τον λαον'),
(2723, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 3, 'NT', 'εισηλθεν δε ο σατανας εις ιουδαν τον επικαλουμενον ισκαριωτην οντα εκ του αριθμου των δωδεκα'),
(2724, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 4, 'NT', 'και απελθων συνελαλησεν τοις αρχιερευσιν και τοις στρατηγοις το πως αυτον παραδω αυτοις'),
(2725, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 5, 'NT', 'και εχαρησαν και συνεθεντο αυτω αργυριον δουναι'),
(2726, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 6, 'NT', 'και εξωμολογησεν και εζητει ευκαιριαν του παραδουναι αυτον αυτοις ατερ οχλου'),
(2727, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 7, 'NT', 'ηλθεν δε η ημερα των αζυμων εν η εδει θυεσθαι το πασχα'),
(2728, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 8, 'NT', 'και απεστειλεν πετρον και ιωαννην ειπων πορευθεντες ετοιμασατε ημιν το πασχα ινα φαγωμεν'),
(2729, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 9, 'NT', 'οι δε ειπον αυτω που θελεις ετοιμασωμεν'),
(2730, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 10, 'NT', 'ο δε ειπεν αυτοις ιδου εισελθοντων υμων εις την πολιν συναντησει υμιν ανθρωπος κεραμιον υδατος βασταζων ακολουθησατε αυτω εις την οικιαν ου εισπορευεται'),
(2731, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 11, 'NT', 'και ερειτε τω οικοδεσποτη της οικιας λεγει σοι ο διδασκαλος που εστιν το καταλυμα οπου το πασχα μετα των μαθητων μου φαγω'),
(2732, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 12, 'NT', 'κακεινος υμιν δειξει ανωγεον μεγα εστρωμενον εκει ετοιμασατε'),
(2733, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 13, 'NT', 'απελθοντες δε ευρον καθως ειρηκεν αυτοις και ητοιμασαν το πασχα'),
(2734, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 14, 'NT', 'και οτε εγενετο η ωρα ανεπεσεν και οι δωδεκα αποστολοι συν αυτω'),
(2735, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 15, 'NT', 'και ειπεν προς αυτους επιθυμια επεθυμησα τουτο το πασχα φαγειν μεθ υμων προ του με παθειν'),
(2736, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 16, 'NT', 'λεγω γαρ υμιν οτι ουκετι ου μη φαγω εξ αυτου εως οτου πληρωθη εν τη βασιλεια του θεου'),
(2737, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 17, 'NT', 'και δεξαμενος ποτηριον ευχαριστησας ειπεν λαβετε τουτο και διαμερισατε εαυτοις'),
(2738, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 18, 'NT', 'λεγω γαρ υμιν οτι ου μη πιω απο του γεννηματος της αμπελου εως οτου η βασιλεια του θεου ελθη'),
(2739, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 19, 'NT', 'και λαβων αρτον ευχαριστησας εκλασεν και εδωκεν αυτοις λεγων τουτο εστιν το σωμα μου το υπερ υμων διδομενον τουτο ποιειτε εις την εμην αναμνησιν'),
(2740, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 20, 'NT', 'ωσαυτως και το ποτηριον μετα το δειπνησαι λεγων τουτο το ποτηριον η καινη διαθηκη εν τω αιματι μου το υπερ υμων εκχυνομενον'),
(2741, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 21, 'NT', 'πλην ιδου η χειρ του παραδιδοντος με μετ εμου επι της τραπεζης'),
(2742, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 22, 'NT', 'και ο μεν υιος του ανθρωπου πορευεται κατα το ωρισμενον πλην ουαι τω ανθρωπω εκεινω δι ου παραδιδοται'),
(2743, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 23, 'NT', 'και αυτοι ηρξαντο συζητειν προς εαυτους το τις αρα ειη εξ αυτων ο τουτο μελλων πρασσειν'),
(2744, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 24, 'NT', 'εγενετο δε και φιλονεικια εν αυτοις το τις αυτων δοκει ειναι μειζων'),
(2745, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 25, 'NT', 'ο δε ειπεν αυτοις οι βασιλεις των εθνων κυριευουσιν αυτων και οι εξουσιαζοντες αυτων ευεργεται καλουνται'),
(2746, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 26, 'NT', 'υμεις δε ουχ ουτως αλλ ο μειζων εν υμιν γενεσθω ως ο νεωτερος και ο ηγουμενος ως ο διακονων'),
(2747, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 27, 'NT', 'τις γαρ μειζων ο ανακειμενος η ο διακονων ουχι ο ανακειμενος εγω δε ειμι εν μεσω υμων ως ο διακονων'),
(2748, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 28, 'NT', 'υμεις δε εστε οι διαμεμενηκοτες μετ εμου εν τοις πειρασμοις μου'),
(2749, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 29, 'NT', 'καγω διατιθεμαι υμιν καθως διεθετο μοι ο πατηρ μου βασιλειαν'),
(2750, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 30, 'NT', 'ινα εσθιητε και πινητε επι της τραπεζης μου εν τη βασιλεια μου και καθισησθε επι θρονων κρινοντες τας δωδεκα φυλας του ισραηλ'),
(2751, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 31, 'NT', 'ειπεν δε ο κυριος σιμων σιμων ιδου ο σατανας εξητησατο υμας του σινιασαι ως τον σιτον'),
(2752, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 32, 'NT', 'εγω δε εδεηθην περι σου ινα μη εκλειπη η πιστις σου και συ ποτε επιστρεψας στηριξον τους αδελφους σου'),
(2753, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 33, 'NT', 'ο δε ειπεν αυτω κυριε μετα σου ετοιμος ειμι και εις φυλακην και εις θανατον πορευεσθαι'),
(2754, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 34, 'NT', 'ο δε ειπεν λεγω σοι πετρε ου μη φωνησει σημερον αλεκτωρ πριν η τρις απαρνηση μη ειδεναι με'),
(2755, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 35, 'NT', 'και ειπεν αυτοις οτε απεστειλα υμας ατερ βαλαντιου και πηρας και υποδηματων μη τινος υστερησατε οι δε ειπον ουδενος'),
(2756, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 36, 'NT', 'ειπεν ουν αυτοις αλλα νυν ο εχων βαλαντιον αρατω ομοιως και πηραν και ο μη εχων πωλησατω το ιματιον αυτου και αγορασατω μαχαιραν'),
(2757, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 37, 'NT', 'λεγω γαρ υμιν οτι ετι τουτο το γεγραμμενον δει τελεσθηναι εν εμοι το και μετα ανομων ελογισθη και γαρ τα περι εμου τελος εχει'),
(2758, 42, 'TR1550', 'TR1550', 'el', 'LUK', 22, 38, 'NT', 'οι δε ειπον κυριε ιδου μαχαιραι ωδε δυο ο δε ειπεν αυτοις ικανον εστιν'),
