(2855, 42, 'TR1550', 'TR1550', 'el', 'LUK', 24, 8, 'NT', 'και εμνησθησαν των ρηματων αυτου'),
(2856, 42, 'TR1550', 'TR1550', 'el', 'LUK', 24, 9, 'NT', 'και υποστρεψασαι απο του μνημειου απηγγειλαν ταυτα παντα τοις ενδεκα και πασιν τοις λοιποις'),
