(2864, 42, 'TR1550', 'TR1550', 'el', 'LUK', 24, 17, 'NT', 'ειπεν δε προς αυτους τινες οι λογοι ουτοι ους αντιβαλλετε προς αλληλους περιπατουντες και εστε σκυθρωποι'),
(2865, 42, 'TR1550', 'TR1550', 'el', 'LUK', 24, 18, 'NT', 'αποκριθεις δε ο εις ω ονομα κλεοπας ειπεν προς αυτον συ μονος παροικεις εν ιερουσαλημ και ουκ εγνως τα γενομενα εν αυτη εν ταις ημεραις ταυταις'),
(2866, 42, 'TR1550', 'TR1550', 'el', 'LUK', 24, 19, 'NT', 'και ειπεν αυτοις ποια οι δε ειπον αυτω τα περι ιησου του ναζωραιου ος εγενετο ανηρ προφητης δυνατος εν εργω και λογω εναντιον του θεου και παντος του λαου'),
(2867, 42, 'TR1550', 'TR1550', 'el', 'LUK', 24, 20, 'NT', 'οπως τε παρεδωκαν αυτον οι αρχιερεις και οι αρχοντες ημων εις κριμα θανατου και εσταυρωσαν αυτον'),
(2868, 42, 'TR1550', 'TR1550', 'el', 'LUK', 24, 21, 'NT', 'ημεις δε ηλπιζομεν οτι αυτος εστιν ο μελλων λυτρουσθαι τον ισραηλ αλλα γε συν πασιν τουτοις τριτην ταυτην ημεραν αγει σημερον αφ ου ταυτα εγενετο'),
(2869, 42, 'TR1550', 'TR1550', 'el', 'LUK', 24, 22, 'NT', 'αλλα και γυναικες τινες εξ ημων εξεστησαν ημας γενομεναι ορθριαι επι το μνημειον'),
