(2941, 43, 'TR1550', 'TR1550', 'el', 'JHN', 1, 41, 'NT', 'ευρισκει ουτος πρωτος τον αδελφον τον ιδιον σιμωνα και λεγει αυτω ευρηκαμεν τον μεσσιαν ο εστιν μεθερμηνευομενον ο χριστος'),
(2942, 43, 'TR1550', 'TR1550', 'el', 'JHN', 1, 42, 'NT', 'και ηγαγεν αυτον προς τον ιησουν εμβλεψας δε αυτω ο ιησους ειπεν συ ει σιμων ο υιος ιωνα συ κληθηση κηφας ο ερμηνευεται πετρος'),
(2943, 43, 'TR1550', 'TR1550', 'el', 'JHN', 1, 43, 'NT', 'τη επαυριον ηθελησεν ο ιησους εξελθειν εις την γαλιλαιαν και ευρισκει φιλιππον και λεγει αυτω ακολουθει μοι'),
(2944, 43, 'TR1550', 'TR1550', 'el', 'JHN', 1, 44, 'NT', 'ην δε ο φιλιππος απο βηθσαιδα εκ της πολεως ανδρεου και πετρου'),
(2945, 43, 'TR1550', 'TR1550', 'el', 'JHN', 1, 45, 'NT', 'ευρισκει φιλιππος τον ναθαναηλ και λεγει αυτω ον εγραψεν μωσης εν τω νομω και οι προφηται ευρηκαμεν ιησουν τον υιον του ιωσηφ τον απο ναζαρετ'),
(2946, 43, 'TR1550', 'TR1550', 'el', 'JHN', 1, 46, 'NT', 'και ειπεν αυτω ναθαναηλ εκ ναζαρετ δυναται τι αγαθον ειναι λεγει αυτω φιλιππος ερχου και ιδε'),
(2947, 43, 'TR1550', 'TR1550', 'el', 'JHN', 1, 47, 'NT', 'ειδεν ο ιησους τον ναθαναηλ ερχομενον προς αυτον και λεγει περι αυτου ιδε αληθως ισραηλιτης εν ω δολος ουκ εστιν'),
(2948, 43, 'TR1550', 'TR1550', 'el', 'JHN', 1, 48, 'NT', 'λεγει αυτω ναθαναηλ ποθεν με γινωσκεις απεκριθη ο ιησους και ειπεν αυτω προ του σε φιλιππον φωνησαι οντα υπο την συκην ειδον σε'),
(2949, 43, 'TR1550', 'TR1550', 'el', 'JHN', 1, 49, 'NT', 'απεκριθη ναθαναηλ και λεγει αυτω ραββι συ ει ο υιος του θεου συ ει ο βασιλευς του ισραηλ'),
(2950, 43, 'TR1550', 'TR1550', 'el', 'JHN', 1, 50, 'NT', 'απεκριθη ιησους και ειπεν αυτω οτι ειπον σοι ειδον σε υποκατω της συκης πιστευεις μειζω τουτων οψει'),
(2951, 43, 'TR1550', 'TR1550', 'el', 'JHN', 1, 51, 'NT', 'και λεγει αυτω αμην αμην λεγω υμιν απ αρτι οψεσθε τον ουρανον ανεωγοτα και τους αγγελους του θεου αναβαινοντας και καταβαινοντας επι τον υιον του ανθρωπου'),
(2952, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 1, 'NT', 'και τη ημερα τη τριτη γαμος εγενετο εν κανα της γαλιλαιας και ην η μητηρ του ιησου εκει'),
(2953, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 2, 'NT', 'εκληθη δε και ο ιησους και οι μαθηται αυτου εις τον γαμον'),
(2954, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 3, 'NT', 'και υστερησαντος οινου λεγει η μητηρ του ιησου προς αυτον οινον ουκ εχουσιν'),
(2955, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 4, 'NT', 'λεγει αυτη ο ιησους τι εμοι και σοι γυναι ουπω ηκει η ωρα μου'),
(2956, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 5, 'NT', 'λεγει η μητηρ αυτου τοις διακονοις ο τι αν λεγη υμιν ποιησατε'),
(2957, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 6, 'NT', 'ησαν δε εκει υδριαι λιθιναι εξ κειμεναι κατα τον καθαρισμον των ιουδαιων χωρουσαι ανα μετρητας δυο η τρεις'),
(2958, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 7, 'NT', 'λεγει αυτοις ο ιησους γεμισατε τας υδριας υδατος και εγεμισαν αυτας εως ανω'),
