(2960, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 9, 'NT', 'ως δε εγευσατο ο αρχιτρικλινος το υδωρ οινον γεγενημενον και ουκ ηδει ποθεν εστιν οι δε διακονοι ηδεισαν οι ηντληκοτες το υδωρ φωνει τον νυμφιον ο αρχιτρικλινος'),
(2961, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 10, 'NT', 'και λεγει αυτω πας ανθρωπος πρωτον τον καλον οινον τιθησιν και οταν μεθυσθωσιν τοτε τον ελασσω συ τετηρηκας τον καλον οινον εως αρτι'),
(2962, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 11, 'NT', 'ταυτην εποιησεν την αρχην των σημειων ο ιησους εν κανα της γαλιλαιας και εφανερωσεν την δοξαν αυτου και επιστευσαν εις αυτον οι μαθηται αυτου'),
(2963, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 12, 'NT', 'μετα τουτο κατεβη εις καπερναουμ αυτος και η μητηρ αυτου και οι αδελφοι αυτου και οι μαθηται αυτου και εκει εμειναν ου πολλας ημερας'),
(2964, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 13, 'NT', 'και εγγυς ην το πασχα των ιουδαιων και ανεβη εις ιεροσολυμα ο ιησους'),
(2965, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 14, 'NT', 'και ευρεν εν τω ιερω τους πωλουντας βοας και προβατα και περιστερας και τους κερματιστας καθημενους'),
(2966, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 15, 'NT', 'και ποιησας φραγελλιον εκ σχοινιων παντας εξεβαλεν εκ του ιερου τα τε προβατα και τους βοας και των κολλυβιστων εξεχεεν το κερμα και τας τραπεζας ανεστρεψεν'),
(2967, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 16, 'NT', 'και τοις τας περιστερας πωλουσιν ειπεν αρατε ταυτα εντευθεν μη ποιειτε τον οικον του πατρος μου οικον εμποριου'),
(2968, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 17, 'NT', 'εμνησθησαν δε οι μαθηται αυτου οτι γεγραμμενον εστιν ο ζηλος του οικου σου κατεφαγεν με'),
(2969, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 18, 'NT', 'απεκριθησαν ουν οι ιουδαιοι και ειπον αυτω τι σημειον δεικνυεις ημιν οτι ταυτα ποιεις'),
(2970, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 19, 'NT', 'απεκριθη ο ιησους και ειπεν αυτοις λυσατε τον ναον τουτον και εν τρισιν ημεραις εγερω αυτον'),
(2971, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 20, 'NT', 'ειπον ουν οι ιουδαιοι τεσσαρακοντα και εξ ετεσιν ωκοδομηθη ο ναος ουτος και συ εν τρισιν ημεραις εγερεις αυτον'),
(2972, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 21, 'NT', 'εκεινος δε ελεγεν περι του ναου του σωματος αυτου'),
(2973, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 22, 'NT', 'οτε ουν ηγερθη εκ νεκρων εμνησθησαν οι μαθηται αυτου οτι τουτο ελεγεν αυτοις και επιστευσαν τη γραφη και τω λογω ω ειπεν ο ιησους'),
(2974, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 23, 'NT', 'ως δε ην εν ιεροσολυμοις εν τω πασχα εν τη εορτη πολλοι επιστευσαν εις το ονομα αυτου θεωρουντες αυτου τα σημεια α εποιει'),
(2975, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 24, 'NT', 'αυτος δε ο ιησους ουκ επιστευεν εαυτον αυτοις δια το αυτον γινωσκειν παντας'),
(2976, 43, 'TR1550', 'TR1550', 'el', 'JHN', 2, 25, 'NT', 'και οτι ου χρειαν ειχεν ινα τις μαρτυρηση περι του ανθρωπου αυτος γαρ εγινωσκεν τι ην εν τω ανθρωπω'),
(2977, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 1, 'NT', 'ην δε ανθρωπος εκ των φαρισαιων νικοδημος ονομα αυτω αρχων των ιουδαιων'),
(2978, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 2, 'NT', 'ουτος ηλθεν προς τον ιησουν νυκτος και ειπεν αυτω ραββι οιδαμεν οτι απο θεου εληλυθας διδασκαλος ουδεις γαρ ταυτα τα σημεια δυναται ποιειν α συ ποιεις εαν μη η ο θεος μετ αυτου'),
(2979, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 3, 'NT', 'απεκριθη ο ιησους και ειπεν αυτω αμην αμην λεγω σοι εαν μη τις γεννηθη ανωθεν ου δυναται ιδειν την βασιλειαν του θεου'),
(2980, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 4, 'NT', 'λεγει προς αυτον ο νικοδημος πως δυναται ανθρωπος γεννηθηναι γερων ων μη δυναται εις την κοιλιαν της μητρος αυτου δευτερον εισελθειν και γεννηθηναι'),
(2981, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 5, 'NT', 'απεκριθη ο ιησους αμην αμην λεγω σοι εαν μη τις γεννηθη εξ υδατος και πνευματος ου δυναται εισελθειν εις την βασιλειαν του θεου'),
(2982, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 6, 'NT', 'το γεγεννημενον εκ της σαρκος σαρξ εστιν και το γεγεννημενον εκ του πνευματος πνευμα εστιν'),
(2983, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 7, 'NT', 'μη θαυμασης οτι ειπον σοι δει υμας γεννηθηναι ανωθεν'),
(2984, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 8, 'NT', 'το πνευμα οπου θελει πνει και την φωνην αυτου ακουεις αλλ ουκ οιδας ποθεν ερχεται και που υπαγει ουτως εστιν πας ο γεγεννημενος εκ του πνευματος'),
(2985, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 9, 'NT', 'απεκριθη νικοδημος και ειπεν αυτω πως δυναται ταυτα γενεσθαι'),
(2986, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 10, 'NT', 'απεκριθη ο ιησους και ειπεν αυτω συ ει ο διδασκαλος του ισραηλ και ταυτα ου γινωσκεις'),
(2987, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 11, 'NT', 'αμην αμην λεγω σοι οτι ο οιδαμεν λαλουμεν και ο εωρακαμεν μαρτυρουμεν και την μαρτυριαν ημων ου λαμβανετε'),
(2988, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 12, 'NT', 'ει τα επιγεια ειπον υμιν και ου πιστευετε πως εαν ειπω υμιν τα επουρανια πιστευσετε'),
(2989, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 13, 'NT', 'και ουδεις αναβεβηκεν εις τον ουρανον ει μη ο εκ του ουρανου καταβας ο υιος του ανθρωπου ο ων εν τω ουρανω'),
(2990, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 14, 'NT', 'και καθως μωσης υψωσεν τον οφιν εν τη ερημω ουτως υψωθηναι δει τον υιον του ανθρωπου'),
(2991, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 15, 'NT', 'ινα πας ο πιστευων εις αυτον μη αποληται αλλ εχη ζωην αιωνιον'),
(2992, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 16, 'NT', 'ουτως γαρ ηγαπησεν ο θεος τον κοσμον ωστε τον υιον αυτου τον μονογενη εδωκεν ινα πας ο πιστευων εις αυτον μη αποληται αλλ εχη ζωην αιωνιον'),
(2993, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 17, 'NT', 'ου γαρ απεστειλεν ο θεος τον υιον αυτου εις τον κοσμον ινα κρινη τον κοσμον αλλ ινα σωθη ο κοσμος δι αυτου'),
(2994, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 18, 'NT', 'ο πιστευων εις αυτον ου κρινεται ο δε μη πιστευων ηδη κεκριται οτι μη πεπιστευκεν εις το ονομα του μονογενους υιου του θεου'),
(2995, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 19, 'NT', 'αυτη δε εστιν η κρισις οτι το φως εληλυθεν εις τον κοσμον και ηγαπησαν οι ανθρωποι μαλλον το σκοτος η το φως ην γαρ πονηρα αυτων τα εργα'),
(2996, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 20, 'NT', 'πας γαρ ο φαυλα πρασσων μισει το φως και ουκ ερχεται προς το φως ινα μη ελεγχθη τα εργα αυτου'),
(2997, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 21, 'NT', 'ο δε ποιων την αληθειαν ερχεται προς το φως ινα φανερωθη αυτου τα εργα οτι εν θεω εστιν ειργασμενα'),
(2998, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 22, 'NT', 'μετα ταυτα ηλθεν ο ιησους και οι μαθηται αυτου εις την ιουδαιαν γην και εκει διετριβεν μετ αυτων και εβαπτιζεν'),
(2999, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 23, 'NT', 'ην δε και ιωαννης βαπτιζων εν αινων εγγυς του σαλειμ οτι υδατα πολλα ην εκει και παρεγινοντο και εβαπτιζοντο'),
(3000, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 24, 'NT', 'ουπω γαρ ην βεβλημενος εις την φυλακην ο ιωαννης'),
