(3003, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 27, 'NT', 'απεκριθη ιωαννης και ειπεν ου δυναται ανθρωπος λαμβανειν ουδεν εαν μη η δεδομενον αυτω εκ του ουρανου'),
(3004, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 28, 'NT', 'αυτοι υμεις μοι μαρτυρειτε οτι ειπον ουκ ειμι εγω ο χριστος αλλ οτι απεσταλμενος ειμι εμπροσθεν εκεινου'),
(3005, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 29, 'NT', 'ο εχων την νυμφην νυμφιος εστιν ο δε φιλος του νυμφιου ο εστηκως και ακουων αυτου χαρα χαιρει δια την φωνην του νυμφιου αυτη ουν η χαρα η εμη πεπληρωται'),
(3006, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 30, 'NT', 'εκεινον δει αυξανειν εμε δε ελαττουσθαι'),
(3007, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 31, 'NT', 'ο ανωθεν ερχομενος επανω παντων εστιν ο ων εκ της γης εκ της γης εστιν και εκ της γης λαλει ο εκ του ουρανου ερχομενος επανω παντων εστιν'),
(3008, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 32, 'NT', 'και ο εωρακεν και ηκουσεν τουτο μαρτυρει και την μαρτυριαν αυτου ουδεις λαμβανει'),
(3009, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 33, 'NT', 'ο λαβων αυτου την μαρτυριαν εσφραγισεν οτι ο θεος αληθης εστιν'),
(3010, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 34, 'NT', 'ον γαρ απεστειλεν ο θεος τα ρηματα του θεου λαλει ου γαρ εκ μετρου διδωσιν ο θεος το πνευμα'),
(3011, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 35, 'NT', 'ο πατηρ αγαπα τον υιον και παντα δεδωκεν εν τη χειρι αυτου'),
(3012, 43, 'TR1550', 'TR1550', 'el', 'JHN', 3, 36, 'NT', 'ο πιστευων εις τον υιον εχει ζωην αιωνιον ο δε απειθων τω υιω ουκ οψεται ζωην αλλ η οργη του θεου μενει επ αυτον'),
(3013, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 1, 'NT', 'ως ουν εγνω ο κυριος οτι ηκουσαν οι φαρισαιοι οτι ιησους πλειονας μαθητας ποιει και βαπτιζει η ιωαννης'),
(3014, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 2, 'NT', 'καιτοιγε ιησους αυτος ουκ εβαπτιζεν αλλ οι μαθηται αυτου'),
(3015, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 3, 'NT', 'αφηκεν την ιουδαιαν και απηλθεν παλιν εις την γαλιλαιαν'),
(3016, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 4, 'NT', 'εδει δε αυτον διερχεσθαι δια της σαμαρειας'),
(3017, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 5, 'NT', 'ερχεται ουν εις πολιν της σαμαρειας λεγομενην συχαρ πλησιον του χωριου ο εδωκεν ιακωβ ιωσηφ τω υιω αυτου'),
(3018, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 6, 'NT', 'ην δε εκει πηγη του ιακωβ ο ουν ιησους κεκοπιακως εκ της οδοιποριας εκαθεζετο ουτως επι τη πηγη ωρα ην ωσει εκτη'),
(3019, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 7, 'NT', 'ερχεται γυνη εκ της σαμαρειας αντλησαι υδωρ λεγει αυτη ο ιησους δος μοι πιειν'),
(3020, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 8, 'NT', 'οι γαρ μαθηται αυτου απεληλυθεισαν εις την πολιν ινα τροφας αγορασωσιν'),
(3021, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 9, 'NT', 'λεγει ουν αυτω η γυνη η σαμαρειτις πως συ ιουδαιος ων παρ εμου πιειν αιτεις ουσης γυναικος σαμαρειτιδος ου γαρ συγχρωνται ιουδαιοι σαμαρειταις'),
(3022, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 10, 'NT', 'απεκριθη ιησους και ειπεν αυτη ει ηδεις την δωρεαν του θεου και τις εστιν ο λεγων σοι δος μοι πιειν συ αν ητησας αυτον και εδωκεν αν σοι υδωρ ζων'),
(3023, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 11, 'NT', 'λεγει αυτω η γυνη κυριε ουτε αντλημα εχεις και το φρεαρ εστιν βαθυ ποθεν ουν εχεις το υδωρ το ζων'),
(3024, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 12, 'NT', 'μη συ μειζων ει του πατρος ημων ιακωβ ος εδωκεν ημιν το φρεαρ και αυτος εξ αυτου επιεν και οι υιοι αυτου και τα θρεμματα αυτου'),
(3025, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 13, 'NT', 'απεκριθη ο ιησους και ειπεν αυτη πας ο πινων εκ του υδατος τουτου διψησει παλιν'),
(3026, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 14, 'NT', 'ος δ αν πιη εκ του υδατος ου εγω δωσω αυτω ου μη διψηση εις τον αιωνα αλλα το υδωρ ο δωσω αυτω γενησεται εν αυτω πηγη υδατος αλλομενου εις ζωην αιωνιον'),
(3027, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 15, 'NT', 'λεγει προς αυτον η γυνη κυριε δος μοι τουτο το υδωρ ινα μη διψω μηδε ερχωμαι ενθαδε αντλειν'),
(3028, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 16, 'NT', 'λεγει αυτη ο ιησους υπαγε φωνησον τον ανδρα σου και ελθε ενθαδε'),
(3029, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 17, 'NT', 'απεκριθη η γυνη και ειπεν ουκ εχω ανδρα λεγει αυτη ο ιησους καλως ειπας οτι ανδρα ουκ εχω'),
(3030, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 18, 'NT', 'πεντε γαρ ανδρας εσχες και νυν ον εχεις ουκ εστιν σου ανηρ τουτο αληθες ειρηκας'),
(3031, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 19, 'NT', 'λεγει αυτω η γυνη κυριε θεωρω οτι προφητης ει συ'),
(3032, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 20, 'NT', 'οι πατερες ημων εν τουτω τω ορει προσεκυνησαν και υμεις λεγετε οτι εν ιεροσολυμοις εστιν ο τοπος οπου δει προσκυνειν'),
(3033, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 21, 'NT', 'λεγει αυτη ο ιησους γυναι πιστευσον μοι οτι ερχεται ωρα οτε ουτε εν τω ορει τουτω ουτε εν ιεροσολυμοις προσκυνησετε τω πατρι'),
(3034, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 22, 'NT', 'υμεις προσκυνειτε ο ουκ οιδατε ημεις προσκυνουμεν ο οιδαμεν οτι η σωτηρια εκ των ιουδαιων εστιν'),
(3035, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 23, 'NT', 'αλλ ερχεται ωρα και νυν εστιν οτε οι αληθινοι προσκυνηται προσκυνησουσιν τω πατρι εν πνευματι και αληθεια και γαρ ο πατηρ τοιουτους ζητει τους προσκυνουντας αυτον'),
(3036, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 24, 'NT', 'πνευμα ο θεος και τους προσκυνουντας αυτον εν πνευματι και αληθεια δει προσκυνειν'),
(3037, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 25, 'NT', 'λεγει αυτω η γυνη οιδα οτι μεσσιας ερχεται ο λεγομενος χριστος οταν ελθη εκεινος αναγγελει ημιν παντα'),
(3038, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 26, 'NT', 'λεγει αυτη ο ιησους εγω ειμι ο λαλων σοι'),
(3039, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 27, 'NT', 'και επι τουτω ηλθον οι μαθηται αυτου και εθαυμασαν οτι μετα γυναικος ελαλει ουδεις μεντοι ειπεν τι ζητεις η τι λαλεις μετ αυτης'),
(3040, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 28, 'NT', 'αφηκεν ουν την υδριαν αυτης η γυνη και απηλθεν εις την πολιν και λεγει τοις ανθρωποις'),
(3041, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 29, 'NT', 'δευτε ιδετε ανθρωπον ος ειπεν μοι παντα οσα εποιησα μητι ουτος εστιν ο χριστος'),
(3042, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 30, 'NT', 'εξηλθον ουν εκ της πολεως και ηρχοντο προς αυτον'),
(3043, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 31, 'NT', 'εν δε τω μεταξυ ηρωτων αυτον οι μαθηται λεγοντες ραββι φαγε'),
(3044, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 32, 'NT', 'ο δε ειπεν αυτοις εγω βρωσιν εχω φαγειν ην υμεις ουκ οιδατε'),
(3045, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 33, 'NT', 'ελεγον ουν οι μαθηται προς αλληλους μη τις ηνεγκεν αυτω φαγειν'),
(3046, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 34, 'NT', 'λεγει αυτοις ο ιησους εμον βρωμα εστιν ινα ποιω το θελημα του πεμψαντος με και τελειωσω αυτου το εργον'),
(3047, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 35, 'NT', 'ουχ υμεις λεγετε οτι ετι τετραμηνον εστιν και ο θερισμος ερχεται ιδου λεγω υμιν επαρατε τους οφθαλμους υμων και θεασασθε τας χωρας οτι λευκαι εισιν προς θερισμον ηδη'),
(3048, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 36, 'NT', 'και ο θεριζων μισθον λαμβανει και συναγει καρπον εις ζωην αιωνιον ινα και ο σπειρων ομου χαιρη και ο θεριζων'),
(3049, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 37, 'NT', 'εν γαρ τουτω ο λογος εστιν ο αληθινος οτι αλλος εστιν ο σπειρων και αλλος ο θεριζων'),
(3050, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 38, 'NT', 'εγω απεστειλα υμας θεριζειν ο ουχ υμεις κεκοπιακατε αλλοι κεκοπιακασιν και υμεις εις τον κοπον αυτων εισεληλυθατε'),
(3051, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 39, 'NT', 'εκ δε της πολεως εκεινης πολλοι επιστευσαν εις αυτον των σαμαρειτων δια τον λογον της γυναικος μαρτυρουσης οτι ειπεν μοι παντα οσα εποιησα'),
(3052, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 40, 'NT', 'ως ουν ηλθον προς αυτον οι σαμαρειται ηρωτων αυτον μειναι παρ αυτοις και εμεινεν εκει δυο ημερας'),
(3053, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 41, 'NT', 'και πολλω πλειους επιστευσαν δια τον λογον αυτου'),
(3054, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 42, 'NT', 'τη τε γυναικι ελεγον οτι ουκετι δια την σην λαλιαν πιστευομεν αυτοι γαρ ακηκοαμεν και οιδαμεν οτι ουτος εστιν αληθως ο σωτηρ του κοσμου ο χριστος'),
(3055, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 43, 'NT', 'μετα δε τας δυο ημερας εξηλθεν εκειθεν και απηλθεν εις την γαλιλαιαν'),
(3056, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 44, 'NT', 'αυτος γαρ ο ιησους εμαρτυρησεν οτι προφητης εν τη ιδια πατριδι τιμην ουκ εχει'),
(3057, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 45, 'NT', 'οτε ουν ηλθεν εις την γαλιλαιαν εδεξαντο αυτον οι γαλιλαιοι παντα εωρακοτες α εποιησεν εν ιεροσολυμοις εν τη εορτη και αυτοι γαρ ηλθον εις την εορτην'),
(3058, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 46, 'NT', 'ηλθεν ουν ο ιησους παλιν εις την κανα της γαλιλαιας οπου εποιησεν το υδωρ οινον και ην τις βασιλικος ου ο υιος ησθενει εν καπερναουμ'),
(3059, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 47, 'NT', 'ουτος ακουσας οτι ιησους ηκει εκ της ιουδαιας εις την γαλιλαιαν απηλθεν προς αυτον και ηρωτα αυτον ινα καταβη και ιασηται αυτου τον υιον ημελλεν γαρ αποθνησκειν'),
(3060, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 48, 'NT', 'ειπεν ουν ο ιησους προς αυτον εαν μη σημεια και τερατα ιδητε ου μη πιστευσητε'),
(3061, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 49, 'NT', 'λεγει προς αυτον ο βασιλικος κυριε καταβηθι πριν αποθανειν το παιδιον μου'),
(3062, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 50, 'NT', 'λεγει αυτω ο ιησους πορευου ο υιος σου ζη και επιστευσεν ο ανθρωπος τω λογω ω ειπεν αυτω ιησους και επορευετο'),
(3063, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 51, 'NT', 'ηδη δε αυτου καταβαινοντος οι δουλοι αυτου απηντησαν αυτω και απηγγειλαν λεγοντες οτι ο παις σου ζη'),
(3064, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 52, 'NT', 'επυθετο ουν παρ αυτων την ωραν εν η κομψοτερον εσχεν και ειπον αυτω οτι χθες ωραν εβδομην αφηκεν αυτον ο πυρετος'),
(3065, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 53, 'NT', 'εγνω ουν ο πατηρ οτι εν εκεινη τη ωρα εν η ειπεν αυτω ο ιησους οτι ο υιος σου ζη και επιστευσεν αυτος και η οικια αυτου ολη'),
(3066, 43, 'TR1550', 'TR1550', 'el', 'JHN', 4, 54, 'NT', 'τουτο παλιν δευτερον σημειον εποιησεν ο ιησους ελθων εκ της ιουδαιας εις την γαλιλαιαν'),
(3067, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 1, 'NT', 'μετα ταυτα ην εορτη των ιουδαιων και ανεβη ο ιησους εις ιεροσολυμα'),
(3068, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 2, 'NT', 'εστιν δε εν τοις ιεροσολυμοις επι τη προβατικη κολυμβηθρα η επιλεγομενη εβραιστι βηθεσδα πεντε στοας εχουσα'),
(3069, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 3, 'NT', 'εν ταυταις κατεκειτο πληθος πολυ των ασθενουντων τυφλων χωλων ξηρων εκδεχομενων την του υδατος κινησιν'),
(3070, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 4, 'NT', 'αγγελος γαρ κατα καιρον κατεβαινεν εν τη κολυμβηθρα και εταρασσεν το υδωρ ο ουν πρωτος εμβας μετα την ταραχην του υδατος υγιης εγινετο ω δηποτε κατειχετο νοσηματι'),
(3071, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 5, 'NT', 'ην δε τις ανθρωπος εκει τριακονταοκτω ετη εχων εν τη ασθενεια'),
(3072, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 6, 'NT', 'τουτον ιδων ο ιησους κατακειμενον και γνους οτι πολυν ηδη χρονον εχει λεγει αυτω θελεις υγιης γενεσθαι'),
(3073, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 7, 'NT', 'απεκριθη αυτω ο ασθενων κυριε ανθρωπον ουκ εχω ινα οταν ταραχθη το υδωρ βαλλη με εις την κολυμβηθραν εν ω δε ερχομαι εγω αλλος προ εμου καταβαινει'),
(3074, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 8, 'NT', 'λεγει αυτω ο ιησους εγειραι αρον τον κραββατον σου και περιπατει'),
(3075, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 9, 'NT', 'και ευθεως εγενετο υγιης ο ανθρωπος και ηρεν τον κραββατον αυτου και περιεπατει ην δε σαββατον εν εκεινη τη ημερα'),
(3076, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 10, 'NT', 'ελεγον ουν οι ιουδαιοι τω τεθεραπευμενω σαββατον εστιν ουκ εξεστιν σοι αραι τον κραββατον'),
(3077, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 11, 'NT', 'απεκριθη αυτοις ο ποιησας με υγιη εκεινος μοι ειπεν αρον τον κραββατον σου και περιπατει'),
(3078, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 12, 'NT', 'ηρωτησαν ουν αυτον τις εστιν ο ανθρωπος ο ειπων σοι αρον τον κραββατον σου και περιπατει'),
(3079, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 13, 'NT', 'ο δε ιαθεις ουκ ηδει τις εστιν ο γαρ ιησους εξενευσεν οχλου οντος εν τω τοπω'),
(3080, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 14, 'NT', 'μετα ταυτα ευρισκει αυτον ο ιησους εν τω ιερω και ειπεν αυτω ιδε υγιης γεγονας μηκετι αμαρτανε ινα μη χειρον τι σοι γενηται'),
(3081, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 15, 'NT', 'απηλθεν ο ανθρωπος και ανηγγειλεν τοις ιουδαιοις οτι ιησους εστιν ο ποιησας αυτον υγιη'),
(3082, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 16, 'NT', 'και δια τουτο εδιωκον τον ιησουν οι ιουδαιοι και εζητουν αυτον αποκτειναι οτι ταυτα εποιει εν σαββατω'),
(3083, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 17, 'NT', 'ο δε ιησους απεκρινατο αυτοις ο πατηρ μου εως αρτι εργαζεται καγω εργαζομαι'),
(3084, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 18, 'NT', 'δια τουτο ουν μαλλον εζητουν αυτον οι ιουδαιοι αποκτειναι οτι ου μονον ελυεν το σαββατον αλλα και πατερα ιδιον ελεγεν τον θεον ισον εαυτον ποιων τω θεω'),
(3085, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 19, 'NT', 'απεκρινατο ουν ο ιησους και ειπεν αυτοις αμην αμην λεγω υμιν ου δυναται ο υιος ποιειν αφ εαυτου ουδεν εαν μη τι βλεπη τον πατερα ποιουντα α γαρ αν εκεινος ποιη ταυτα και ο υιος ομοιως ποιει'),
(3086, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 20, 'NT', 'ο γαρ πατηρ φιλει τον υιον και παντα δεικνυσιν αυτω α αυτος ποιει και μειζονα τουτων δειξει αυτω εργα ινα υμεις θαυμαζητε'),
(3087, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 21, 'NT', 'ωσπερ γαρ ο πατηρ εγειρει τους νεκρους και ζωοποιει ουτως και ο υιος ους θελει ζωοποιει'),
(3088, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 22, 'NT', 'ουδε γαρ ο πατηρ κρινει ουδενα αλλα την κρισιν πασαν δεδωκεν τω υιω'),
(3089, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 23, 'NT', 'ινα παντες τιμωσιν τον υιον καθως τιμωσιν τον πατερα ο μη τιμων τον υιον ου τιμα τον πατερα τον πεμψαντα αυτον'),
(3090, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 24, 'NT', 'αμην αμην λεγω υμιν οτι ο τον λογον μου ακουων και πιστευων τω πεμψαντι με εχει ζωην αιωνιον και εις κρισιν ουκ ερχεται αλλα μεταβεβηκεν εκ του θανατου εις την ζωην'),
(3091, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 25, 'NT', 'αμην αμην λεγω υμιν οτι ερχεται ωρα και νυν εστιν οτε οι νεκροι ακουσονται της φωνης του υιου του θεου και οι ακουσαντες ζησονται'),
(3092, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 26, 'NT', 'ωσπερ γαρ ο πατηρ εχει ζωην εν εαυτω ουτως εδωκεν και τω υιω ζωην εχειν εν εαυτω'),
(3093, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 27, 'NT', 'και εξουσιαν εδωκεν αυτω και κρισιν ποιειν οτι υιος ανθρωπου εστιν'),
(3094, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 28, 'NT', 'μη θαυμαζετε τουτο οτι ερχεται ωρα εν η παντες οι εν τοις μνημειοις ακουσονται της φωνης αυτου'),
(3095, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 29, 'NT', 'και εκπορευσονται οι τα αγαθα ποιησαντες εις αναστασιν ζωης οι δε τα φαυλα πραξαντες εις αναστασιν κρισεως'),
(3096, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 30, 'NT', 'ου δυναμαι εγω ποιειν απ εμαυτου ουδεν καθως ακουω κρινω και η κρισις η εμη δικαια εστιν οτι ου ζητω το θελημα το εμον αλλα το θελημα του πεμψαντος με πατρος'),
(3097, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 31, 'NT', 'εαν εγω μαρτυρω περι εμαυτου η μαρτυρια μου ουκ εστιν αληθης'),
(3098, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 32, 'NT', 'αλλος εστιν ο μαρτυρων περι εμου και οιδα οτι αληθης εστιν η μαρτυρια ην μαρτυρει περι εμου'),
(3099, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 33, 'NT', 'υμεις απεσταλκατε προς ιωαννην και μεμαρτυρηκεν τη αληθεια'),
(3100, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 34, 'NT', 'εγω δε ου παρα ανθρωπου την μαρτυριαν λαμβανω αλλα ταυτα λεγω ινα υμεις σωθητε'),
(3101, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 35, 'NT', 'εκεινος ην ο λυχνος ο καιομενος και φαινων υμεις δε ηθελησατε αγαλλιασθηναι προς ωραν εν τω φωτι αυτου'),
(3102, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 36, 'NT', 'εγω δε εχω την μαρτυριαν μειζω του ιωαννου τα γαρ εργα α εδωκεν μοι ο πατηρ ινα τελειωσω αυτα αυτα τα εργα α εγω ποιω μαρτυρει περι εμου οτι ο πατηρ με απεσταλκεν'),
(3103, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 37, 'NT', 'και ο πεμψας με πατηρ αυτος μεμαρτυρηκεν περι εμου ουτε φωνην αυτου ακηκοατε πωποτε ουτε ειδος αυτου εωρακατε'),
(3104, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 38, 'NT', 'και τον λογον αυτου ουκ εχετε μενοντα εν υμιν οτι ον απεστειλεν εκεινος τουτω υμεις ου πιστευετε'),
(3105, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 39, 'NT', 'ερευνατε τας γραφας οτι υμεις δοκειτε εν αυταις ζωην αιωνιον εχειν και εκειναι εισιν αι μαρτυρουσαι περι εμου'),
(3106, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 40, 'NT', 'και ου θελετε ελθειν προς με ινα ζωην εχητε'),
(3107, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 41, 'NT', 'δοξαν παρα ανθρωπων ου λαμβανω'),
(3108, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 42, 'NT', 'αλλ εγνωκα υμας οτι την αγαπην του θεου ουκ εχετε εν εαυτοις'),
(3109, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 43, 'NT', 'εγω εληλυθα εν τω ονοματι του πατρος μου και ου λαμβανετε με εαν αλλος ελθη εν τω ονοματι τω ιδιω εκεινον ληψεσθε'),
(3110, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 44, 'NT', 'πως δυνασθε υμεις πιστευσαι δοξαν παρα αλληλων λαμβανοντες και την δοξαν την παρα του μονου θεου ου ζητειτε'),
(3111, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 45, 'NT', 'μη δοκειτε οτι εγω κατηγορησω υμων προς τον πατερα εστιν ο κατηγορων υμων μωσης εις ον υμεις ηλπικατε'),
(3112, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 46, 'NT', 'ει γαρ επιστευετε μωση επιστευετε αν εμοι περι γαρ εμου εκεινος εγραψεν'),
(3113, 43, 'TR1550', 'TR1550', 'el', 'JHN', 5, 47, 'NT', 'ει δε τοις εκεινου γραμμασιν ου πιστευετε πως τοις εμοις ρημασιν πιστευσετε'),
(3114, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 1, 'NT', 'μετα ταυτα απηλθεν ο ιησους περαν της θαλασσης της γαλιλαιας της τιβεριαδος'),
(3115, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 2, 'NT', 'και ηκολουθει αυτω οχλος πολυς οτι εωρων αυτου τα σημεια α εποιει επι των ασθενουντων'),
(3116, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 3, 'NT', 'ανηλθεν δε εις το ορος ο ιησους και εκει εκαθητο μετα των μαθητων αυτου'),
(3117, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 4, 'NT', 'ην δε εγγυς το πασχα η εορτη των ιουδαιων'),
(3118, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 5, 'NT', 'επαρας ουν ο ιησους τους οφθαλμους και θεασαμενος οτι πολυς οχλος ερχεται προς αυτον λεγει προς τον φιλιππον ποθεν αγορασομεν αρτους ινα φαγωσιν ουτοι'),
(3119, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 6, 'NT', 'τουτο δε ελεγεν πειραζων αυτον αυτος γαρ ηδει τι εμελλεν ποιειν'),
(3120, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 7, 'NT', 'απεκριθη αυτω φιλιππος διακοσιων δηναριων αρτοι ουκ αρκουσιν αυτοις ινα εκαστος αυτων βραχυ τι λαβη'),
(3121, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 8, 'NT', 'λεγει αυτω εις εκ των μαθητων αυτου ανδρεας ο αδελφος σιμωνος πετρου'),
(3122, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 9, 'NT', 'εστιν παιδαριον εν ωδε ο εχει πεντε αρτους κριθινους και δυο οψαρια αλλα ταυτα τι εστιν εις τοσουτους'),
(3123, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 10, 'NT', 'ειπεν δε ο ιησους ποιησατε τους ανθρωπους αναπεσειν ην δε χορτος πολυς εν τω τοπω ανεπεσον ουν οι ανδρες τον αριθμον ωσει πεντακισχιλιοι'),
(3124, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 11, 'NT', 'ελαβεν δε τους αρτους ο ιησους και ευχαριστησας διεδωκεν τοις μαθηταις οι δε μαθηται τοις ανακειμενοις ομοιως και εκ των οψαριων οσον ηθελον'),
(3125, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 12, 'NT', 'ως δε ενεπλησθησαν λεγει τοις μαθηταις αυτου συναγαγετε τα περισσευσαντα κλασματα ινα μη τι αποληται'),
(3126, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 13, 'NT', 'συνηγαγον ουν και εγεμισαν δωδεκα κοφινους κλασματων εκ των πεντε αρτων των κριθινων α επερισσευσεν τοις βεβρωκοσιν'),
(3127, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 14, 'NT', 'οι ουν ανθρωποι ιδοντες ο εποιησεν σημειον ο ιησους ελεγον οτι ουτος εστιν αληθως ο προφητης ο ερχομενος εις τον κοσμον'),
(3128, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 15, 'NT', 'ιησους ουν γνους οτι μελλουσιν ερχεσθαι και αρπαζειν αυτον ινα ποιησωσιν αυτον βασιλεα ανεχωρησεν παλιν εις το ορος αυτος μονος'),
(3129, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 16, 'NT', 'ως δε οψια εγενετο κατεβησαν οι μαθηται αυτου επι την θαλασσαν'),
(3130, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 17, 'NT', 'και εμβαντες εις το πλοιον ηρχοντο περαν της θαλασσης εις καπερναουμ και σκοτια ηδη εγεγονει και ουκ εληλυθει προς αυτους ο ιησους'),
(3131, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 18, 'NT', 'η τε θαλασσα ανεμου μεγαλου πνεοντος διηγειρετο'),
(3132, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 19, 'NT', 'εληλακοτες ουν ως σταδιους εικοσιπεντε η τριακοντα θεωρουσιν τον ιησουν περιπατουντα επι της θαλασσης και εγγυς του πλοιου γινομενον και εφοβηθησαν'),
(3133, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 20, 'NT', 'ο δε λεγει αυτοις εγω ειμι μη φοβεισθε'),
(3134, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 21, 'NT', 'ηθελον ουν λαβειν αυτον εις το πλοιον και ευθεως το πλοιον εγενετο επι της γης εις ην υπηγον'),
(3135, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 22, 'NT', 'τη επαυριον ο οχλος ο εστηκως περαν της θαλασσης ιδων οτι πλοιαριον αλλο ουκ ην εκει ει μη εν εκεινο εις ο ενεβησαν οι μαθηται αυτου και οτι ου συνεισηλθεν τοις μαθηταις αυτου ο ιησους εις το πλοιαριον αλλα μονοι οι μαθηται αυτου απηλθον'),
(3136, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 23, 'NT', 'αλλα δε ηλθεν πλοιαρια εκ τιβεριαδος εγγυς του τοπου οπου εφαγον τον αρτον ευχαριστησαντος του κυριου'),
(3137, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 24, 'NT', 'οτε ουν ειδεν ο οχλος οτι ιησους ουκ εστιν εκει ουδε οι μαθηται αυτου ενεβησαν και αυτοι εις τα πλοια και ηλθον εις καπερναουμ ζητουντες τον ιησουν'),
(3138, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 25, 'NT', 'και ευροντες αυτον περαν της θαλασσης ειπον αυτω ραββι ποτε ωδε γεγονας'),
(3139, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 26, 'NT', 'απεκριθη αυτοις ο ιησους και ειπεν αμην αμην λεγω υμιν ζητειτε με ουχ οτι ειδετε σημεια αλλ οτι εφαγετε εκ των αρτων και εχορτασθητε'),
(3140, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 27, 'NT', 'εργαζεσθε μη την βρωσιν την απολλυμενην αλλα την βρωσιν την μενουσαν εις ζωην αιωνιον ην ο υιος του ανθρωπου υμιν δωσει τουτον γαρ ο πατηρ εσφραγισεν ο θεος'),
(3141, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 28, 'NT', 'ειπον ουν προς αυτον τι ποιουμεν ινα εργαζωμεθα τα εργα του θεου'),
(3142, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 29, 'NT', 'απεκριθη ο ιησους και ειπεν αυτοις τουτο εστιν το εργον του θεου ινα πιστευσητε εις ον απεστειλεν εκεινος'),
(3143, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 30, 'NT', 'ειπον ουν αυτω τι ουν ποιεις συ σημειον ινα ιδωμεν και πιστευσωμεν σοι τι εργαζη'),
(3144, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 31, 'NT', 'οι πατερες ημων το μαννα εφαγον εν τη ερημω καθως εστιν γεγραμμενον αρτον εκ του ουρανου εδωκεν αυτοις φαγειν'),
(3145, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 32, 'NT', 'ειπεν ουν αυτοις ο ιησους αμην αμην λεγω υμιν ου μωσης δεδωκεν υμιν τον αρτον εκ του ουρανου αλλ ο πατηρ μου διδωσιν υμιν τον αρτον εκ του ουρανου τον αληθινον'),
(3146, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 33, 'NT', 'ο γαρ αρτος του θεου εστιν ο καταβαινων εκ του ουρανου και ζωην διδους τω κοσμω'),
(3147, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 34, 'NT', 'ειπον ουν προς αυτον κυριε παντοτε δος ημιν τον αρτον τουτον'),
(3148, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 35, 'NT', 'ειπεν δε αυτοις ο ιησους εγω ειμι ο αρτος της ζωης ο ερχομενος προς με ου μη πειναση και ο πιστευων εις εμε ου μη διψηση πωποτε'),
(3149, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 36, 'NT', 'αλλ ειπον υμιν οτι και εωρακατε με και ου πιστευετε'),
(3150, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 37, 'NT', 'παν ο διδωσιν μοι ο πατηρ προς εμε ηξει και τον ερχομενον προς με ου μη εκβαλω εξω'),
(3151, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 38, 'NT', 'οτι καταβεβηκα εκ του ουρανου ουχ ινα ποιω το θελημα το εμον αλλα το θελημα του πεμψαντος με'),
(3152, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 39, 'NT', 'τουτο δε εστιν το θελημα του πεμψαντος με πατρος ινα παν ο δεδωκεν μοι μη απολεσω εξ αυτου αλλα αναστησω αυτο εν τη εσχατη ημερα'),
(3153, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 40, 'NT', 'τουτο δε εστιν το θελημα του πεμψαντος με ινα πας ο θεωρων τον υιον και πιστευων εις αυτον εχη ζωην αιωνιον και αναστησω αυτον εγω τη εσχατη ημερα'),
(3154, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 41, 'NT', 'εγογγυζον ουν οι ιουδαιοι περι αυτου οτι ειπεν εγω ειμι ο αρτος ο καταβας εκ του ουρανου'),
(3155, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 42, 'NT', 'και ελεγον ουχ ουτος εστιν ιησους ο υιος ιωσηφ ου ημεις οιδαμεν τον πατερα και την μητερα πως ουν λεγει ουτος οτι εκ του ουρανου καταβεβηκα'),
(3156, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 43, 'NT', 'απεκριθη ουν ο ιησους και ειπεν αυτοις μη γογγυζετε μετ αλληλων'),
(3157, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 44, 'NT', 'ουδεις δυναται ελθειν προς με εαν μη ο πατηρ ο πεμψας με ελκυση αυτον και εγω αναστησω αυτον τη εσχατη ημερα'),
(3158, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 45, 'NT', 'εστιν γεγραμμενον εν τοις προφηταις και εσονται παντες διδακτοι του θεου πας ουν ο ακουσας παρα του πατρος και μαθων ερχεται προς με'),
(3159, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 46, 'NT', 'ουχ οτι τον πατερα τις εωρακεν ει μη ο ων παρα του θεου ουτος εωρακεν τον πατερα'),
(3160, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 47, 'NT', 'αμην αμην λεγω υμιν ο πιστευων εις εμε εχει ζωην αιωνιον'),
(3161, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 48, 'NT', 'εγω ειμι ο αρτος της ζωης'),
(3162, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 49, 'NT', 'οι πατερες υμων εφαγον το μαννα εν τη ερημω και απεθανον'),
(3163, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 50, 'NT', 'ουτος εστιν ο αρτος ο εκ του ουρανου καταβαινων ινα τις εξ αυτου φαγη και μη αποθανη'),
(3164, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 51, 'NT', 'εγω ειμι ο αρτος ο ζων ο εκ του ουρανου καταβας εαν τις φαγη εκ τουτου του αρτου ζησεται εις τον αιωνα και ο αρτος δε ον εγω δωσω η σαρξ μου εστιν ην εγω δωσω υπερ της του κοσμου ζωης'),
(3165, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 52, 'NT', 'εμαχοντο ουν προς αλληλους οι ιουδαιοι λεγοντες πως δυναται ουτος ημιν δουναι την σαρκα φαγειν'),
(3166, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 53, 'NT', 'ειπεν ουν αυτοις ο ιησους αμην αμην λεγω υμιν εαν μη φαγητε την σαρκα του υιου του ανθρωπου και πιητε αυτου το αιμα ουκ εχετε ζωην εν εαυτοις'),
(3167, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 54, 'NT', 'ο τρωγων μου την σαρκα και πινων μου το αιμα εχει ζωην αιωνιον και εγω αναστησω αυτον τη εσχατη ημερα'),
(3168, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 55, 'NT', 'η γαρ σαρξ μου αληθως εστιν βρωσις και το αιμα μου αληθως εστιν ποσις'),
(3169, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 56, 'NT', 'ο τρωγων μου την σαρκα και πινων μου το αιμα εν εμοι μενει καγω εν αυτω'),
(3170, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 57, 'NT', 'καθως απεστειλεν με ο ζων πατηρ καγω ζω δια τον πατερα και ο τρωγων με κακεινος ζησεται δι εμε'),
(3171, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 58, 'NT', 'ουτος εστιν ο αρτος ο εκ του ουρανου καταβας ου καθως εφαγον οι πατερες υμων το μαννα και απεθανον ο τρωγων τουτον τον αρτον ζησεται εις τον αιωνα'),
(3172, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 59, 'NT', 'ταυτα ειπεν εν συναγωγη διδασκων εν καπερναουμ'),
(3173, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 60, 'NT', 'πολλοι ουν ακουσαντες εκ των μαθητων αυτου ειπον σκληρος εστιν ουτος ο λογος τις δυναται αυτου ακουειν'),
(3174, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 61, 'NT', 'ειδως δε ο ιησους εν εαυτω οτι γογγυζουσιν περι τουτου οι μαθηται αυτου ειπεν αυτοις τουτο υμας σκανδαλιζει'),
(3175, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 62, 'NT', 'εαν ουν θεωρητε τον υιον του ανθρωπου αναβαινοντα οπου ην το προτερον'),
(3176, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 63, 'NT', 'το πνευμα εστιν το ζωοποιουν η σαρξ ουκ ωφελει ουδεν τα ρηματα α εγω λαλω υμιν πνευμα εστιν και ζωη εστιν'),
(3177, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 64, 'NT', 'αλλ εισιν εξ υμων τινες οι ου πιστευουσιν ηδει γαρ εξ αρχης ο ιησους τινες εισιν οι μη πιστευοντες και τις εστιν ο παραδωσων αυτον'),
(3178, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 65, 'NT', 'και ελεγεν δια τουτο ειρηκα υμιν οτι ουδεις δυναται ελθειν προς με εαν μη η δεδομενον αυτω εκ του πατρος μου'),
(3179, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 66, 'NT', 'εκ τουτου πολλοι απηλθον των μαθητων αυτου εις τα οπισω και ουκετι μετ αυτου περιεπατουν'),
(3180, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 67, 'NT', 'ειπεν ουν ο ιησους τοις δωδεκα μη και υμεις θελετε υπαγειν'),
(3181, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 68, 'NT', 'απεκριθη ουν αυτω σιμων πετρος κυριε προς τινα απελευσομεθα ρηματα ζωης αιωνιου εχεις'),
(3182, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 69, 'NT', 'και ημεις πεπιστευκαμεν και εγνωκαμεν οτι συ ει ο χριστος ο υιος του θεου του ζωντος'),
(3183, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 70, 'NT', 'απεκριθη αυτοις ο ιησους ουκ εγω υμας τους δωδεκα εξελεξαμην και εξ υμων εις διαβολος εστιν'),
(3184, 43, 'TR1550', 'TR1550', 'el', 'JHN', 6, 71, 'NT', 'ελεγεν δε τον ιουδαν σιμωνος ισκαριωτην ουτος γαρ ημελλεν αυτον παραδιδοναι εις ων εκ των δωδεκα'),
(3185, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 1, 'NT', 'και περιεπατει ο ιησους μετα ταυτα εν τη γαλιλαια ου γαρ ηθελεν εν τη ιουδαια περιπατειν οτι εζητουν αυτον οι ιουδαιοι αποκτειναι'),
(3186, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 2, 'NT', 'ην δε εγγυς η εορτη των ιουδαιων η σκηνοπηγια'),
(3187, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 3, 'NT', 'ειπον ουν προς αυτον οι αδελφοι αυτου μεταβηθι εντευθεν και υπαγε εις την ιουδαιαν ινα και οι μαθηται σου θεωρησωσιν τα εργα σου α ποιεις'),
(3188, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 4, 'NT', 'ουδεις γαρ εν κρυπτω τι ποιει και ζητει αυτος εν παρρησια ειναι ει ταυτα ποιεις φανερωσον σεαυτον τω κοσμω'),
(3189, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 5, 'NT', 'ουδε γαρ οι αδελφοι αυτου επιστευον εις αυτον'),
(3190, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 6, 'NT', 'λεγει ουν αυτοις ο ιησους ο καιρος ο εμος ουπω παρεστιν ο δε καιρος ο υμετερος παντοτε εστιν ετοιμος'),
(3191, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 7, 'NT', 'ου δυναται ο κοσμος μισειν υμας εμε δε μισει οτι εγω μαρτυρω περι αυτου οτι τα εργα αυτου πονηρα εστιν'),
(3192, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 8, 'NT', 'υμεις αναβητε εις την εορτην ταυτην εγω ουπω αναβαινω εις την εορτην ταυτην οτι ο καιρος ο εμος ουπω πεπληρωται'),
(3193, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 9, 'NT', 'ταυτα δε ειπων αυτοις εμεινεν εν τη γαλιλαια'),
(3194, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 10, 'NT', 'ως δε ανεβησαν οι αδελφοι αυτου τοτε και αυτος ανεβη εις την εορτην ου φανερως αλλ ως εν κρυπτω'),
(3195, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 11, 'NT', 'οι ουν ιουδαιοι εζητουν αυτον εν τη εορτη και ελεγον που εστιν εκεινος'),
(3196, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 12, 'NT', 'και γογγυσμος πολυς περι αυτου ην εν τοις οχλοις οι μεν ελεγον οτι αγαθος εστιν αλλοι δε ελεγον ου αλλα πλανα τον οχλον'),
(3197, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 13, 'NT', 'ουδεις μεντοι παρρησια ελαλει περι αυτου δια τον φοβον των ιουδαιων'),
(3198, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 14, 'NT', 'ηδη δε της εορτης μεσουσης ανεβη ο ιησους εις το ιερον και εδιδασκεν'),
(3199, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 15, 'NT', 'και εθαυμαζον οι ιουδαιοι λεγοντες πως ουτος γραμματα οιδεν μη μεμαθηκως'),
(3200, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 16, 'NT', 'απεκριθη αυτοις ο ιησους και ειπεν η εμη διδαχη ουκ εστιν εμη αλλα του πεμψαντος με'),
(3201, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 17, 'NT', 'εαν τις θελη το θελημα αυτου ποιειν γνωσεται περι της διδαχης ποτερον εκ του θεου εστιν η εγω απ εμαυτου λαλω'),
(3202, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 18, 'NT', 'ο αφ εαυτου λαλων την δοξαν την ιδιαν ζητει ο δε ζητων την δοξαν του πεμψαντος αυτον ουτος αληθης εστιν και αδικια εν αυτω ουκ εστιν'),
(3203, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 19, 'NT', 'ου μωσης δεδωκεν υμιν τον νομον και ουδεις εξ υμων ποιει τον νομον τι με ζητειτε αποκτειναι'),
(3204, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 20, 'NT', 'απεκριθη ο οχλος και ειπεν δαιμονιον εχεις τις σε ζητει αποκτειναι'),
(3205, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 21, 'NT', 'απεκριθη ο ιησους και ειπεν αυτοις εν εργον εποιησα και παντες θαυμαζετε'),
(3206, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 22, 'NT', 'δια τουτο μωσης δεδωκεν υμιν την περιτομην ουχ οτι εκ του μωσεως εστιν αλλ εκ των πατερων και εν σαββατω περιτεμνετε ανθρωπον'),
(3207, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 23, 'NT', 'ει περιτομην λαμβανει ανθρωπος εν σαββατω ινα μη λυθη ο νομος μωσεως εμοι χολατε οτι ολον ανθρωπον υγιη εποιησα εν σαββατω'),
(3208, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 24, 'NT', 'μη κρινετε κατ οψιν αλλα την δικαιαν κρισιν κρινατε'),
(3209, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 25, 'NT', 'ελεγον ουν τινες εκ των ιεροσολυμιτων ουχ ουτος εστιν ον ζητουσιν αποκτειναι'),
(3210, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 26, 'NT', 'και ιδε παρρησια λαλει και ουδεν αυτω λεγουσιν μηποτε αληθως εγνωσαν οι αρχοντες οτι ουτος εστιν αληθως ο χριστος'),
(3211, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 27, 'NT', 'αλλα τουτον οιδαμεν ποθεν εστιν ο δε χριστος οταν ερχηται ουδεις γινωσκει ποθεν εστιν'),
(3212, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 28, 'NT', 'εκραξεν ουν εν τω ιερω διδασκων ο ιησους και λεγων καμε οιδατε και οιδατε ποθεν ειμι και απ εμαυτου ουκ εληλυθα αλλ εστιν αληθινος ο πεμψας με ον υμεις ουκ οιδατε'),
(3213, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 29, 'NT', 'εγω δε οιδα αυτον οτι παρ αυτου ειμι κακεινος με απεστειλεν'),
(3214, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 30, 'NT', 'εζητουν ουν αυτον πιασαι και ουδεις επεβαλεν επ αυτον την χειρα οτι ουπω εληλυθει η ωρα αυτου'),
(3215, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 31, 'NT', 'πολλοι δε εκ του οχλου επιστευσαν εις αυτον και ελεγον οτι ο χριστος οταν ελθη μητι πλειονα σημεια τουτων ποιησει ων ουτος εποιησεν'),
(3216, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 32, 'NT', 'ηκουσαν οι φαρισαιοι του οχλου γογγυζοντος περι αυτου ταυτα και απεστειλαν οι φαρισαιοι και οι αρχιερεις υπηρετας ινα πιασωσιν αυτον'),
(3217, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 33, 'NT', 'ειπεν ουν αυτοις ο ιησους ετι μικρον χρονον μεθ υμων ειμι και υπαγω προς τον πεμψαντα με'),
(3218, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 34, 'NT', 'ζητησετε με και ουχ ευρησετε και οπου ειμι εγω υμεις ου δυνασθε ελθειν'),
(3219, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 35, 'NT', 'ειπον ουν οι ιουδαιοι προς εαυτους που ουτος μελλει πορευεσθαι οτι ημεις ουχ ευρησομεν αυτον μη εις την διασποραν των ελληνων μελλει πορευεσθαι και διδασκειν τους ελληνας'),
(3220, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 36, 'NT', 'τις εστιν ουτος ο λογος ον ειπεν ζητησετε με και ουχ ευρησετε και οπου ειμι εγω υμεις ου δυνασθε ελθειν'),
(3221, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 37, 'NT', 'εν δε τη εσχατη ημερα τη μεγαλη της εορτης ειστηκει ο ιησους και εκραξεν λεγων εαν τις διψα ερχεσθω προς με και πινετω'),
(3222, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 38, 'NT', 'ο πιστευων εις εμε καθως ειπεν η γραφη ποταμοι εκ της κοιλιας αυτου ρευσουσιν υδατος ζωντος'),
(3223, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 39, 'NT', 'τουτο δε ειπεν περι του πνευματος ου εμελλον λαμβανειν οι πιστευοντες εις αυτον ουπω γαρ ην πνευμα αγιον οτι ο ιησους ουδεπω εδοξασθη'),
(3224, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 40, 'NT', 'πολλοι ουν εκ του οχλου ακουσαντες τον λογον ελεγον ουτος εστιν αληθως ο προφητης'),
(3225, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 41, 'NT', 'αλλοι ελεγον ουτος εστιν ο χριστος αλλοι δε ελεγον μη γαρ εκ της γαλιλαιας ο χριστος ερχεται'),
(3226, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 42, 'NT', 'ουχι η γραφη ειπεν οτι εκ του σπερματος δαβιδ και απο βηθλεεμ της κωμης οπου ην δαβιδ ο χριστος ερχεται'),
(3227, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 43, 'NT', 'σχισμα ουν εν τω οχλω εγενετο δι αυτον'),
(3228, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 44, 'NT', 'τινες δε ηθελον εξ αυτων πιασαι αυτον αλλ ουδεις επεβαλεν επ αυτον τας χειρας'),
(3229, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 45, 'NT', 'ηλθον ουν οι υπηρεται προς τους αρχιερεις και φαρισαιους και ειπον αυτοις εκεινοι δια τι ουκ ηγαγετε αυτον'),
(3230, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 46, 'NT', 'απεκριθησαν οι υπηρεται ουδεποτε ουτως ελαλησεν ανθρωπος ως ουτος ο ανθρωπος'),
(3231, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 47, 'NT', 'απεκριθησαν ουν αυτοις οι φαρισαιοι μη και υμεις πεπλανησθε'),
(3232, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 48, 'NT', 'μη τις εκ των αρχοντων επιστευσεν εις αυτον η εκ των φαρισαιων'),
(3233, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 49, 'NT', 'αλλ ο οχλος ουτος ο μη γινωσκων τον νομον επικαταρατοι εισιν'),
(3234, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 50, 'NT', 'λεγει νικοδημος προς αυτους ο ελθων νυκτος προς αυτον εις ων εξ αυτων'),
(3235, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 51, 'NT', 'μη ο νομος ημων κρινει τον ανθρωπον εαν μη ακουση παρ αυτου προτερον και γνω τι ποιει'),
(3236, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 52, 'NT', 'απεκριθησαν και ειπον αυτω μη και συ εκ της γαλιλαιας ει ερευνησον και ιδε οτι προφητης εκ της γαλιλαιας ουκ εγηγερται'),
(3237, 43, 'TR1550', 'TR1550', 'el', 'JHN', 7, 53, 'NT', 'και επορευθη εκαστος εις τον οικον αυτου'),
(3238, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 1, 'NT', 'ιησους δε επορευθη εις το ορος των ελαιων'),
(3239, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 2, 'NT', 'ορθρου δε παλιν παρεγενετο εις το ιερον και πας ο λαος ηρχετο προς αυτον και καθισας εδιδασκεν αυτους'),
(3240, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 3, 'NT', 'αγουσιν δε οι γραμματεις και οι φαρισαιοι προς αυτον γυναικα εν μοιχεια κατειλημμενην και στησαντες αυτην εν μεσω'),
(3241, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 4, 'NT', 'λεγουσιν αυτω διδασκαλε αυτη η γυνη κατειληφθη επαυτοφωρω μοιχευομενη'),
(3242, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 5, 'NT', 'εν δε τω νομω μωσης ημιν ενετειλατο τας τοιαυτας λιθοβολεισθαι συ ουν τι λεγεις'),
(3243, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 6, 'NT', 'τουτο δε ελεγον πειραζοντες αυτον ινα εχωσιν κατηγορειν αυτου ο δε ιησους κατω κυψας τω δακτυλω εγραφεν εις την γην'),
(3244, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 7, 'NT', 'ως δε επεμενον ερωτωντες αυτον ανακυψας ειπεν προς αυτους ο αναμαρτητος υμων πρωτος τον λιθον επ αυτη βαλετω'),
(3245, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 8, 'NT', 'και παλιν κατω κυψας εγραφεν εις την γην'),
(3246, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 9, 'NT', 'οι δε ακουσαντες και υπο της συνειδησεως ελεγχομενοι εξηρχοντο εις καθ εις αρξαμενοι απο των πρεσβυτερων εως των εσχατων και κατελειφθη μονος ο ιησους και η γυνη εν μεσω εστωσα'),
(3247, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 10, 'NT', 'ανακυψας δε ο ιησους και μηδενα θεασαμενος πλην της γυναικος ειπεν αυτη η γυνη που εισιν εκεινοι οι κατηγοροι σου ουδεις σε κατεκρινεν'),
(3248, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 11, 'NT', 'η δε ειπεν ουδεις κυριε ειπεν δε αυτη ο ιησους ουδε εγω σε κατακρινω πορευου και μηκετι αμαρτανε'),
(3249, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 12, 'NT', 'παλιν ουν ο ιησους αυτοις ελαλησεν λεγων εγω ειμι το φως του κοσμου ο ακολουθων εμοι ου μη περιπατησει εν τη σκοτια αλλ εξει το φως της ζωης'),
(3250, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 13, 'NT', 'ειπον ουν αυτω οι φαρισαιοι συ περι σεαυτου μαρτυρεις η μαρτυρια σου ουκ εστιν αληθης'),
(3251, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 14, 'NT', 'απεκριθη ιησους και ειπεν αυτοις καν εγω μαρτυρω περι εμαυτου αληθης εστιν η μαρτυρια μου οτι οιδα ποθεν ηλθον και που υπαγω υμεις δε ουκ οιδατε ποθεν ερχομαι και που υπαγω'),
(3252, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 15, 'NT', 'υμεις κατα την σαρκα κρινετε εγω ου κρινω ουδενα'),
(3253, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 16, 'NT', 'και εαν κρινω δε εγω η κρισις η εμη αληθης εστιν οτι μονος ουκ ειμι αλλ εγω και ο πεμψας με πατηρ'),
(3254, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 17, 'NT', 'και εν τω νομω δε τω υμετερω γεγραπται οτι δυο ανθρωπων η μαρτυρια αληθης εστιν'),
(3255, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 18, 'NT', 'εγω ειμι ο μαρτυρων περι εμαυτου και μαρτυρει περι εμου ο πεμψας με πατηρ'),
(3256, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 19, 'NT', 'ελεγον ουν αυτω που εστιν ο πατηρ σου απεκριθη ο ιησους ουτε εμε οιδατε ουτε τον πατερα μου ει εμε ηδειτε και τον πατερα μου ηδειτε αν'),
(3257, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 20, 'NT', 'ταυτα τα ρηματα ελαλησεν ο ιησους εν τω γαζοφυλακιω διδασκων εν τω ιερω και ουδεις επιασεν αυτον οτι ουπω εληλυθει η ωρα αυτου'),
(3258, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 21, 'NT', 'ειπεν ουν παλιν αυτοις ο ιησους εγω υπαγω και ζητησετε με και εν τη αμαρτια υμων αποθανεισθε οπου εγω υπαγω υμεις ου δυνασθε ελθειν'),
(3259, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 22, 'NT', 'ελεγον ουν οι ιουδαιοι μητι αποκτενει εαυτον οτι λεγει οπου εγω υπαγω υμεις ου δυνασθε ελθειν'),
(3260, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 23, 'NT', 'και ειπεν αυτοις υμεις εκ των κατω εστε εγω εκ των ανω ειμι υμεις εκ του κοσμου τουτου εστε εγω ουκ ειμι εκ του κοσμου τουτου'),
(3261, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 24, 'NT', 'ειπον ουν υμιν οτι αποθανεισθε εν ταις αμαρτιαις υμων εαν γαρ μη πιστευσητε οτι εγω ειμι αποθανεισθε εν ταις αμαρτιαις υμων'),
(3262, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 25, 'NT', 'ελεγον ουν αυτω συ τις ει και ειπεν αυτοις ο ιησους την αρχην ο τι και λαλω υμιν'),
(3263, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 26, 'NT', 'πολλα εχω περι υμων λαλειν και κρινειν αλλ ο πεμψας με αληθης εστιν καγω α ηκουσα παρ αυτου ταυτα λεγω εις τον κοσμον'),
(3264, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 27, 'NT', 'ουκ εγνωσαν οτι τον πατερα αυτοις ελεγεν'),
(3265, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 28, 'NT', 'ειπεν ουν αυτοις ο ιησους οταν υψωσητε τον υιον του ανθρωπου τοτε γνωσεσθε οτι εγω ειμι και απ εμαυτου ποιω ουδεν αλλα καθως εδιδαξεν με ο πατηρ μου ταυτα λαλω'),
(3266, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 29, 'NT', 'και ο πεμψας με μετ εμου εστιν ουκ αφηκεν με μονον ο πατηρ οτι εγω τα αρεστα αυτω ποιω παντοτε'),
(3267, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 30, 'NT', 'ταυτα αυτου λαλουντος πολλοι επιστευσαν εις αυτον'),
(3268, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 31, 'NT', 'ελεγεν ουν ο ιησους προς τους πεπιστευκοτας αυτω ιουδαιους εαν υμεις μεινητε εν τω λογω τω εμω αληθως μαθηται μου εστε'),
(3269, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 32, 'NT', 'και γνωσεσθε την αληθειαν και η αληθεια ελευθερωσει υμας'),
(3270, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 33, 'NT', 'απεκριθησαν αυτω σπερμα αβρααμ εσμεν και ουδενι δεδουλευκαμεν πωποτε πως συ λεγεις οτι ελευθεροι γενησεσθε'),
(3271, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 34, 'NT', 'απεκριθη αυτοις ο ιησους αμην αμην λεγω υμιν οτι πας ο ποιων την αμαρτιαν δουλος εστιν της αμαρτιας'),
(3272, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 35, 'NT', 'ο δε δουλος ου μενει εν τη οικια εις τον αιωνα ο υιος μενει εις τον αιωνα'),
(3273, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 36, 'NT', 'εαν ουν ο υιος υμας ελευθερωση οντως ελευθεροι εσεσθε'),
(3274, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 37, 'NT', 'οιδα οτι σπερμα αβρααμ εστε αλλα ζητειτε με αποκτειναι οτι ο λογος ο εμος ου χωρει εν υμιν'),
(3275, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 38, 'NT', 'εγω ο εωρακα παρα τω πατρι μου λαλω και υμεις ουν ο εωρακατε παρα τω πατρι υμων ποιειτε'),
(3276, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 39, 'NT', 'απεκριθησαν και ειπον αυτω ο πατηρ ημων αβρααμ εστιν λεγει αυτοις ο ιησους ει τεκνα του αβρααμ ητε τα εργα του αβρααμ εποιειτε αν'),
(3277, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 40, 'NT', 'νυν δε ζητειτε με αποκτειναι ανθρωπον ος την αληθειαν υμιν λελαληκα ην ηκουσα παρα του θεου τουτο αβρααμ ουκ εποιησεν'),
(3278, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 41, 'NT', 'υμεις ποιειτε τα εργα του πατρος υμων ειπον ουν αυτω ημεις εκ πορνειας ου γεγεννημεθα ενα πατερα εχομεν τον θεον'),
(3279, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 42, 'NT', 'ειπεν ουν αυτοις ο ιησους ει ο θεος πατηρ υμων ην ηγαπατε αν εμε εγω γαρ εκ του θεου εξηλθον και ηκω ουδε γαρ απ εμαυτου εληλυθα αλλ εκεινος με απεστειλεν'),
(3280, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 43, 'NT', 'δια τι την λαλιαν την εμην ου γινωσκετε οτι ου δυνασθε ακουειν τον λογον τον εμον'),
(3281, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 44, 'NT', 'υμεις εκ πατρος του διαβολου εστε και τας επιθυμιας του πατρος υμων θελετε ποιειν εκεινος ανθρωποκτονος ην απ αρχης και εν τη αληθεια ουχ εστηκεν οτι ουκ εστιν αληθεια εν αυτω οταν λαλη το ψευδος εκ των ιδιων λαλει οτι ψευστης εστιν και ο πατηρ αυτου'),
(3282, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 45, 'NT', 'εγω δε οτι την αληθειαν λεγω ου πιστευετε μοι'),
(3283, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 46, 'NT', 'τις εξ υμων ελεγχει με περι αμαρτιας ει δε αληθειαν λεγω δια τι υμεις ου πιστευετε μοι'),
(3284, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 47, 'NT', 'ο ων εκ του θεου τα ρηματα του θεου ακουει δια τουτο υμεις ουκ ακουετε οτι εκ του θεου ουκ εστε'),
(3285, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 48, 'NT', 'απεκριθησαν ουν οι ιουδαιοι και ειπον αυτω ου καλως λεγομεν ημεις οτι σαμαρειτης ει συ και δαιμονιον εχεις'),
(3286, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 49, 'NT', 'απεκριθη ιησους εγω δαιμονιον ουκ εχω αλλα τιμω τον πατερα μου και υμεις ατιμαζετε με'),
(3287, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 50, 'NT', 'εγω δε ου ζητω την δοξαν μου εστιν ο ζητων και κρινων'),
(3288, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 51, 'NT', 'αμην αμην λεγω υμιν εαν τις τον λογον τον εμον τηρηση θανατον ου μη θεωρηση εις τον αιωνα'),
(3289, 43, 'TR1550', 'TR1550', 'el', 'JHN', 8, 52, 'NT', 'ειπον ουν αυτω οι ιουδαιοι νυν εγνωκαμεν οτι δαιμονιον εχεις αβρααμ απεθανεν και οι προφηται και συ λεγεις εαν τις τον λογον μου τηρηση ου μη γευσεται θανατου εις τον αιωνα'),
