(3387, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 8, 'NT', 'λεγουσιν αυτω οι μαθηται ραββι νυν εζητουν σε λιθασαι οι ιουδαιοι και παλιν υπαγεις εκει'),
(3388, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 9, 'NT', 'απεκριθη ο ιησους ουχι δωδεκα εισιν ωραι της ημερας εαν τις περιπατη εν τη ημερα ου προσκοπτει οτι το φως του κοσμου τουτου βλεπει'),
(3389, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 10, 'NT', 'εαν δε τις περιπατη εν τη νυκτι προσκοπτει οτι το φως ουκ εστιν εν αυτω'),
(3390, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 11, 'NT', 'ταυτα ειπεν και μετα τουτο λεγει αυτοις λαζαρος ο φιλος ημων κεκοιμηται αλλα πορευομαι ινα εξυπνισω αυτον'),
(3391, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 12, 'NT', 'ειπον ουν οι μαθηται αυτου κυριε ει κεκοιμηται σωθησεται'),
(3392, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 13, 'NT', 'ειρηκει δε ο ιησους περι του θανατου αυτου εκεινοι δε εδοξαν οτι περι της κοιμησεως του υπνου λεγει'),
(3393, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 14, 'NT', 'τοτε ουν ειπεν αυτοις ο ιησους παρρησια λαζαρος απεθανεν'),
(3394, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 15, 'NT', 'και χαιρω δι υμας ινα πιστευσητε οτι ουκ ημην εκει αλλ αγωμεν προς αυτον'),
(3395, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 16, 'NT', 'ειπεν ουν θωμας ο λεγομενος διδυμος τοις συμμαθηταις αγωμεν και ημεις ινα αποθανωμεν μετ αυτου'),
(3396, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 17, 'NT', 'ελθων ουν ο ιησους ευρεν αυτον τεσσαρας ημερας ηδη εχοντα εν τω μνημειω'),
(3397, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 18, 'NT', 'ην δε η βηθανια εγγυς των ιεροσολυμων ως απο σταδιων δεκαπεντε'),
(3398, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 19, 'NT', 'και πολλοι εκ των ιουδαιων εληλυθεισαν προς τας περι μαρθαν και μαριαν ινα παραμυθησωνται αυτας περι του αδελφου αυτων'),
(3399, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 20, 'NT', 'η ουν μαρθα ως ηκουσεν οτι ο ιησους ερχεται υπηντησεν αυτω μαρια δε εν τω οικω εκαθεζετο'),
