(3410, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 31, 'NT', 'οι ουν ιουδαιοι οι οντες μετ αυτης εν τη οικια και παραμυθουμενοι αυτην ιδοντες την μαριαν οτι ταχεως ανεστη και εξηλθεν ηκολουθησαν αυτη λεγοντες οτι υπαγει εις το μνημειον ινα κλαυση εκει'),
(3411, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 32, 'NT', 'η ουν μαρια ως ηλθεν οπου ην ο ιησους ιδουσα αυτον επεσεν εις τους ποδας αυτου λεγουσα αυτω κυριε ει ης ωδε ουκ αν απεθανεν μου ο αδελφος'),
(3412, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 33, 'NT', 'ιησους ουν ως ειδεν αυτην κλαιουσαν και τους συνελθοντας αυτη ιουδαιους κλαιοντας ενεβριμησατο τω πνευματι και εταραξεν εαυτον'),
(3413, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 34, 'NT', 'και ειπεν που τεθεικατε αυτον λεγουσιν αυτω κυριε ερχου και ιδε'),
(3414, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 35, 'NT', 'εδακρυσεν ο ιησους'),
(3415, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 36, 'NT', 'ελεγον ουν οι ιουδαιοι ιδε πως εφιλει αυτον'),
(3416, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 37, 'NT', 'τινες δε εξ αυτων ειπον ουκ ηδυνατο ουτος ο ανοιξας τους οφθαλμους του τυφλου ποιησαι ινα και ουτος μη αποθανη'),
(3417, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 38, 'NT', 'ιησους ουν παλιν εμβριμωμενος εν εαυτω ερχεται εις το μνημειον ην δε σπηλαιον και λιθος επεκειτο επ αυτω'),
(3418, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 39, 'NT', 'λεγει ο ιησους αρατε τον λιθον λεγει αυτω η αδελφη του τεθνηκοτος μαρθα κυριε ηδη οζει τεταρταιος γαρ εστιν'),
(3419, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 40, 'NT', 'λεγει αυτη ο ιησους ουκ ειπον σοι οτι εαν πιστευσης οψει την δοξαν του θεου'),
(3420, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 41, 'NT', 'ηραν ουν τον λιθον ου ην ο τεθνηκως κειμενος ο δε ιησους ηρεν τους οφθαλμους ανω και ειπεν πατερ ευχαριστω σοι οτι ηκουσας μου'),
(3421, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 42, 'NT', 'εγω δε ηδειν οτι παντοτε μου ακουεις αλλα δια τον οχλον τον περιεστωτα ειπον ινα πιστευσωσιν οτι συ με απεστειλας'),
(3422, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 43, 'NT', 'και ταυτα ειπων φωνη μεγαλη εκραυγασεν λαζαρε δευρο εξω'),
(3423, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 44, 'NT', 'και εξηλθεν ο τεθνηκως δεδεμενος τους ποδας και τας χειρας κειριαις και η οψις αυτου σουδαριω περιεδεδετο λεγει αυτοις ο ιησους λυσατε αυτον και αφετε υπαγειν'),
(3424, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 45, 'NT', 'πολλοι ουν εκ των ιουδαιων οι ελθοντες προς την μαριαν και θεασαμενοι α εποιησεν ο ιησους επιστευσαν εις αυτον'),
(3425, 43, 'TR1550', 'TR1550', 'el', 'JHN', 11, 46, 'NT', 'τινες δε εξ αυτων απηλθον προς τους φαρισαιους και ειπον αυτοις α εποιησεν ο ιησους'),
