(3445, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 9, 'NT', 'εγνω ουν οχλος πολυς εκ των ιουδαιων οτι εκει εστιν και ηλθον ου δια τον ιησουν μονον αλλ ινα και τον λαζαρον ιδωσιν ον ηγειρεν εκ νεκρων'),
(3446, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 10, 'NT', 'εβουλευσαντο δε οι αρχιερεις ινα και τον λαζαρον αποκτεινωσιν'),
(3447, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 11, 'NT', 'οτι πολλοι δι αυτον υπηγον των ιουδαιων και επιστευον εις τον ιησουν'),
(3448, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 12, 'NT', 'τη επαυριον οχλος πολυς ο ελθων εις την εορτην ακουσαντες οτι ερχεται ο ιησους εις ιεροσολυμα'),
(3449, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 13, 'NT', 'ελαβον τα βαια των φοινικων και εξηλθον εις υπαντησιν αυτω και εκραζον ωσαννα ευλογημενος ο ερχομενος εν ονοματι κυριου ο βασιλευς του ισραηλ'),
(3450, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 14, 'NT', 'ευρων δε ο ιησους οναριον εκαθισεν επ αυτο καθως εστιν γεγραμμενον'),
(3451, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 15, 'NT', 'μη φοβου θυγατερ σιων ιδου ο βασιλευς σου ερχεται καθημενος επι πωλον ονου'),
(3452, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 16, 'NT', 'ταυτα δε ουκ εγνωσαν οι μαθηται αυτου το πρωτον αλλ οτε εδοξασθη ο ιησους τοτε εμνησθησαν οτι ταυτα ην επ αυτω γεγραμμενα και ταυτα εποιησαν αυτω'),
(3453, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 17, 'NT', 'εμαρτυρει ουν ο οχλος ο ων μετ αυτου οτε τον λαζαρον εφωνησεν εκ του μνημειου και ηγειρεν αυτον εκ νεκρων'),
(3454, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 18, 'NT', 'δια τουτο και υπηντησεν αυτω ο οχλος οτι ηκουσεν τουτο αυτον πεποιηκεναι το σημειον'),
