(3456, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 20, 'NT', 'ησαν δε τινες ελληνες εκ των αναβαινοντων ινα προσκυνησωσιν εν τη εορτη'),
(3457, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 21, 'NT', 'ουτοι ουν προσηλθον φιλιππω τω απο βηθσαιδα της γαλιλαιας και ηρωτων αυτον λεγοντες κυριε θελομεν τον ιησουν ιδειν'),
(3458, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 22, 'NT', 'ερχεται φιλιππος και λεγει τω ανδρεα και παλιν ανδρεας και φιλιππος λεγουσιν τω ιησου'),
(3459, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 23, 'NT', 'ο δε ιησους απεκρινατο αυτοις λεγων εληλυθεν η ωρα ινα δοξασθη ο υιος του ανθρωπου'),
(3460, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 24, 'NT', 'αμην αμην λεγω υμιν εαν μη ο κοκκος του σιτου πεσων εις την γην αποθανη αυτος μονος μενει εαν δε αποθανη πολυν καρπον φερει'),
(3461, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 25, 'NT', 'ο φιλων την ψυχην αυτου απολεσει αυτην και ο μισων την ψυχην αυτου εν τω κοσμω τουτω εις ζωην αιωνιον φυλαξει αυτην'),
(3462, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 26, 'NT', 'εαν εμοι διακονη τις εμοι ακολουθειτω και οπου ειμι εγω εκει και ο διακονος ο εμος εσται και εαν τις εμοι διακονη τιμησει αυτον ο πατηρ'),
(3463, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 27, 'NT', 'νυν η ψυχη μου τεταρακται και τι ειπω πατερ σωσον με εκ της ωρας ταυτης αλλα δια τουτο ηλθον εις την ωραν ταυτην'),
(3464, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 28, 'NT', 'πατερ δοξασον σου το ονομα ηλθεν ουν φωνη εκ του ουρανου και εδοξασα και παλιν δοξασω'),
(3465, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 29, 'NT', 'ο ουν οχλος ο εστως και ακουσας ελεγεν βροντην γεγονεναι αλλοι ελεγον αγγελος αυτω λελαληκεν'),
(3466, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 30, 'NT', 'απεκριθη ο ιησους και ειπεν ου δι εμε αυτη η φωνη γεγονεν αλλα δι υμας'),
(3467, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 31, 'NT', 'νυν κρισις εστιν του κοσμου τουτου νυν ο αρχων του κοσμου τουτου εκβληθησεται εξω'),
(3468, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 32, 'NT', 'καγω εαν υψωθω εκ της γης παντας ελκυσω προς εμαυτον'),
(3469, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 33, 'NT', 'τουτο δε ελεγεν σημαινων ποιω θανατω ημελλεν αποθνησκειν'),
(3470, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 34, 'NT', 'απεκριθη αυτω ο οχλος ημεις ηκουσαμεν εκ του νομου οτι ο χριστος μενει εις τον αιωνα και πως συ λεγεις οτι δει υψωθηναι τον υιον του ανθρωπου τις εστιν ουτος ο υιος του ανθρωπου'),
(3471, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 35, 'NT', 'ειπεν ουν αυτοις ο ιησους ετι μικρον χρονον το φως μεθ υμων εστιν περιπατειτε εως το φως εχετε ινα μη σκοτια υμας καταλαβη και ο περιπατων εν τη σκοτια ουκ οιδεν που υπαγει'),
(3472, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 36, 'NT', 'εως το φως εχετε πιστευετε εις το φως ινα υιοι φωτος γενησθε ταυτα ελαλησεν ο ιησους και απελθων εκρυβη απ αυτων'),
(3473, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 37, 'NT', 'τοσαυτα δε αυτου σημεια πεποιηκοτος εμπροσθεν αυτων ουκ επιστευον εις αυτον'),
(3474, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 38, 'NT', 'ινα ο λογος ησαιου του προφητου πληρωθη ον ειπεν κυριε τις επιστευσεν τη ακοη ημων και ο βραχιων κυριου τινι απεκαλυφθη'),
(3475, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 39, 'NT', 'δια τουτο ουκ ηδυναντο πιστευειν οτι παλιν ειπεν ησαιας'),
(3476, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 40, 'NT', 'τετυφλωκεν αυτων τους οφθαλμους και πεπωρωκεν αυτων την καρδιαν ινα μη ιδωσιν τοις οφθαλμοις και νοησωσιν τη καρδια και επιστραφωσιν και ιασωμαι αυτους'),
(3477, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 41, 'NT', 'ταυτα ειπεν ησαιας οτε ειδεν την δοξαν αυτου και ελαλησεν περι αυτου'),
(3478, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 42, 'NT', 'ομως μεντοι και εκ των αρχοντων πολλοι επιστευσαν εις αυτον αλλα δια τους φαρισαιους ουχ ωμολογουν ινα μη αποσυναγωγοι γενωνται'),
(3479, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 43, 'NT', 'ηγαπησαν γαρ την δοξαν των ανθρωπων μαλλον ηπερ την δοξαν του θεου'),
(3480, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 44, 'NT', 'ιησους δε εκραξεν και ειπεν ο πιστευων εις εμε ου πιστευει εις εμε αλλ εις τον πεμψαντα με'),
(3481, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 45, 'NT', 'και ο θεωρων εμε θεωρει τον πεμψαντα με'),
(3482, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 46, 'NT', 'εγω φως εις τον κοσμον εληλυθα ινα πας ο πιστευων εις εμε εν τη σκοτια μη μεινη'),
(3483, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 47, 'NT', 'και εαν τις μου ακουση των ρηματων και μη πιστευση εγω ου κρινω αυτον ου γαρ ηλθον ινα κρινω τον κοσμον αλλ ινα σωσω τον κοσμον'),
(3484, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 48, 'NT', 'ο αθετων εμε και μη λαμβανων τα ρηματα μου εχει τον κρινοντα αυτον ο λογος ον ελαλησα εκεινος κρινει αυτον εν τη εσχατη ημερα'),
(3485, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 49, 'NT', 'οτι εγω εξ εμαυτου ουκ ελαλησα αλλ ο πεμψας με πατηρ αυτος μοι εντολην εδωκεν τι ειπω και τι λαλησω'),
(3486, 43, 'TR1550', 'TR1550', 'el', 'JHN', 12, 50, 'NT', 'και οιδα οτι η εντολη αυτου ζωη αιωνιος εστιν α ουν λαλω εγω καθως ειρηκεν μοι ο πατηρ ουτως λαλω'),
(3487, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 1, 'NT', 'προ δε της εορτης του πασχα ειδως ο ιησους οτι εληλυθεν αυτου η ωρα ινα μεταβη εκ του κοσμου τουτου προς τον πατερα αγαπησας τους ιδιους τους εν τω κοσμω εις τελος ηγαπησεν αυτους'),
(3488, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 2, 'NT', 'και δειπνου γενομενου του διαβολου ηδη βεβληκοτος εις την καρδιαν ιουδα σιμωνος ισκαριωτου ινα αυτον παραδω'),
(3489, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 3, 'NT', 'ειδως ο ιησους οτι παντα δεδωκεν αυτω ο πατηρ εις τας χειρας και οτι απο θεου εξηλθεν και προς τον θεον υπαγει'),
(3490, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 4, 'NT', 'εγειρεται εκ του δειπνου και τιθησιν τα ιματια και λαβων λεντιον διεζωσεν εαυτον'),
(3491, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 5, 'NT', 'ειτα βαλλει υδωρ εις τον νιπτηρα και ηρξατο νιπτειν τους ποδας των μαθητων και εκμασσειν τω λεντιω ω ην διεζωσμενος'),
(3492, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 6, 'NT', 'ερχεται ουν προς σιμωνα πετρον και λεγει αυτω εκεινος κυριε συ μου νιπτεις τους ποδας'),
(3493, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 7, 'NT', 'απεκριθη ιησους και ειπεν αυτω ο εγω ποιω συ ουκ οιδας αρτι γνωση δε μετα ταυτα'),
(3494, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 8, 'NT', 'λεγει αυτω πετρος ου μη νιψης τους ποδας μου εις τον αιωνα απεκριθη αυτω ο ιησους εαν μη νιψω σε ουκ εχεις μερος μετ εμου'),
(3495, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 9, 'NT', 'λεγει αυτω σιμων πετρος κυριε μη τους ποδας μου μονον αλλα και τας χειρας και την κεφαλην'),
(3496, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 10, 'NT', 'λεγει αυτω ο ιησους ο λελουμενος ου χρειαν εχει η τους ποδας νιψασθαι αλλ εστιν καθαρος ολος και υμεις καθαροι εστε αλλ ουχι παντες'),
(3497, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 11, 'NT', 'ηδει γαρ τον παραδιδοντα αυτον δια τουτο ειπεν ουχι παντες καθαροι εστε'),
(3498, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 12, 'NT', 'οτε ουν ενιψεν τους ποδας αυτων και ελαβεν τα ιματια αυτου αναπεσων παλιν ειπεν αυτοις γινωσκετε τι πεποιηκα υμιν'),
(3499, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 13, 'NT', 'υμεις φωνειτε με ο διδασκαλος και ο κυριος και καλως λεγετε ειμι γαρ'),
(3500, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 14, 'NT', 'ει ουν εγω ενιψα υμων τους ποδας ο κυριος και ο διδασκαλος και υμεις οφειλετε αλληλων νιπτειν τους ποδας'),
(3501, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 15, 'NT', 'υποδειγμα γαρ εδωκα υμιν ινα καθως εγω εποιησα υμιν και υμεις ποιητε'),
(3502, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 16, 'NT', 'αμην αμην λεγω υμιν ουκ εστιν δουλος μειζων του κυριου αυτου ουδε αποστολος μειζων του πεμψαντος αυτον'),
(3503, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 17, 'NT', 'ει ταυτα οιδατε μακαριοι εστε εαν ποιητε αυτα'),
(3504, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 18, 'NT', 'ου περι παντων υμων λεγω εγω οιδα ους εξελεξαμην αλλ ινα η γραφη πληρωθη ο τρωγων μετ εμου τον αρτον επηρεν επ εμε την πτερναν αυτου'),
(3505, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 19, 'NT', 'απ αρτι λεγω υμιν προ του γενεσθαι ινα οταν γενηται πιστευσητε οτι εγω ειμι'),
(3506, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 20, 'NT', 'αμην αμην λεγω υμιν ο λαμβανων εαν τινα πεμψω εμε λαμβανει ο δε εμε λαμβανων λαμβανει τον πεμψαντα με'),
(3507, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 21, 'NT', 'ταυτα ειπων ο ιησους εταραχθη τω πνευματι και εμαρτυρησεν και ειπεν αμην αμην λεγω υμιν οτι εις εξ υμων παραδωσει με'),
(3508, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 22, 'NT', 'εβλεπον ουν εις αλληλους οι μαθηται απορουμενοι περι τινος λεγει'),
(3509, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 23, 'NT', 'ην δε ανακειμενος εις των μαθητων αυτου εν τω κολπω του ιησου ον ηγαπα ο ιησους'),
(3510, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 24, 'NT', 'νευει ουν τουτω σιμων πετρος πυθεσθαι τις αν ειη περι ου λεγει'),
(3511, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 25, 'NT', 'επιπεσων δε εκεινος επι το στηθος του ιησου λεγει αυτω κυριε τις εστιν'),
(3512, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 26, 'NT', 'αποκρινεται ο ιησους εκεινος εστιν ω εγω βαψας το ψωμιον επιδωσω και εμβαψας το ψωμιον διδωσιν ιουδα σιμωνος ισκαριωτη'),
(3513, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 27, 'NT', 'και μετα το ψωμιον τοτε εισηλθεν εις εκεινον ο σατανας λεγει ουν αυτω ο ιησους ο ποιεις ποιησον ταχιον'),
(3514, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 28, 'NT', 'τουτο δε ουδεις εγνω των ανακειμενων προς τι ειπεν αυτω'),
(3515, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 29, 'NT', 'τινες γαρ εδοκουν επει το γλωσσοκομον ειχεν ο ιουδας οτι λεγει αυτω ο ιησους αγορασον ων χρειαν εχομεν εις την εορτην η τοις πτωχοις ινα τι δω'),
(3516, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 30, 'NT', 'λαβων ουν το ψωμιον εκεινος ευθεως εξηλθεν ην δε νυξ'),
(3517, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 31, 'NT', 'οτε εξηλθεν λεγει ο ιησους νυν εδοξασθη ο υιος του ανθρωπου και ο θεος εδοξασθη εν αυτω'),
(3518, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 32, 'NT', 'ει ο θεος εδοξασθη εν αυτω και ο θεος δοξασει αυτον εν εαυτω και ευθυς δοξασει αυτον'),
(3519, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 33, 'NT', 'τεκνια ετι μικρον μεθ υμων ειμι ζητησετε με και καθως ειπον τοις ιουδαιοις οτι οπου υπαγω εγω υμεις ου δυνασθε ελθειν και υμιν λεγω αρτι'),
(3520, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 34, 'NT', 'εντολην καινην διδωμι υμιν ινα αγαπατε αλληλους καθως ηγαπησα υμας ινα και υμεις αγαπατε αλληλους'),
(3521, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 35, 'NT', 'εν τουτω γνωσονται παντες οτι εμοι μαθηται εστε εαν αγαπην εχητε εν αλληλοις'),
(3522, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 36, 'NT', 'λεγει αυτω σιμων πετρος κυριε που υπαγεις απεκριθη αυτω ο ιησους οπου υπαγω ου δυνασαι μοι νυν ακολουθησαι υστερον δε ακολουθησεις μοι'),
(3523, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 37, 'NT', 'λεγει αυτω ο πετρος κυριε δια τι ου δυναμαι σοι ακολουθησαι αρτι την ψυχην μου υπερ σου θησω'),
(3524, 43, 'TR1550', 'TR1550', 'el', 'JHN', 13, 38, 'NT', 'απεκριθη αυτω ο ιησους την ψυχην σου υπερ εμου θησεις αμην αμην λεγω σοι ου μη αλεκτωρ φωνησει εως ου απαρνηση με τρις'),
(3525, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 1, 'NT', 'μη ταρασσεσθω υμων η καρδια πιστευετε εις τον θεον και εις εμε πιστευετε'),
(3526, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 2, 'NT', 'εν τη οικια του πατρος μου μοναι πολλαι εισιν ει δε μη ειπον αν υμιν πορευομαι ετοιμασαι τοπον υμιν'),
(3527, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 3, 'NT', 'και εαν πορευθω και ετοιμασω υμιν τοπον παλιν ερχομαι και παραληψομαι υμας προς εμαυτον ινα οπου ειμι εγω και υμεις ητε'),
(3528, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 4, 'NT', 'και οπου εγω υπαγω οιδατε και την οδον οιδατε'),
(3529, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 5, 'NT', 'λεγει αυτω θωμας κυριε ουκ οιδαμεν που υπαγεις και πως δυναμεθα την οδον ειδεναι'),
(3530, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 6, 'NT', 'λεγει αυτω ο ιησους εγω ειμι η οδος και η αληθεια και η ζωη ουδεις ερχεται προς τον πατερα ει μη δι εμου'),
(3531, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 7, 'NT', 'ει εγνωκειτε με και τον πατερα μου εγνωκειτε αν και απ αρτι γινωσκετε αυτον και εωρακατε αυτον'),
(3532, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 8, 'NT', 'λεγει αυτω φιλιππος κυριε δειξον ημιν τον πατερα και αρκει ημιν'),
(3533, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 9, 'NT', 'λεγει αυτω ο ιησους τοσουτον χρονον μεθ υμων ειμι και ουκ εγνωκας με φιλιππε ο εωρακως εμε εωρακεν τον πατερα και πως συ λεγεις δειξον ημιν τον πατερα'),
(3534, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 10, 'NT', 'ου πιστευεις οτι εγω εν τω πατρι και ο πατηρ εν εμοι εστιν τα ρηματα α εγω λαλω υμιν απ εμαυτου ου λαλω ο δε πατηρ ο εν εμοι μενων αυτος ποιει τα εργα'),
(3535, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 11, 'NT', 'πιστευετε μοι οτι εγω εν τω πατρι και ο πατηρ εν εμοι ει δε μη δια τα εργα αυτα πιστευετε μοι'),
(3536, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 12, 'NT', 'αμην αμην λεγω υμιν ο πιστευων εις εμε τα εργα α εγω ποιω κακεινος ποιησει και μειζονα τουτων ποιησει οτι εγω προς τον πατερα μου πορευομαι'),
(3537, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 13, 'NT', 'και ο τι αν αιτησητε εν τω ονοματι μου τουτο ποιησω ινα δοξασθη ο πατηρ εν τω υιω'),
(3538, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 14, 'NT', 'εαν τι αιτησητε εν τω ονοματι μου εγω ποιησω'),
(3539, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 15, 'NT', 'εαν αγαπατε με τας εντολας τας εμας τηρησατε'),
(3540, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 16, 'NT', 'και εγω ερωτησω τον πατερα και αλλον παρακλητον δωσει υμιν ινα μενη μεθ υμων εις τον αιωνα'),
(3541, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 17, 'NT', 'το πνευμα της αληθειας ο ο κοσμος ου δυναται λαβειν οτι ου θεωρει αυτο ουδε γινωσκει αυτο υμεις δε γινωσκετε αυτο οτι παρ υμιν μενει και εν υμιν εσται'),
(3542, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 18, 'NT', 'ουκ αφησω υμας ορφανους ερχομαι προς υμας'),
(3543, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 19, 'NT', 'ετι μικρον και ο κοσμος με ουκ ετι θεωρει υμεις δε θεωρειτε με οτι εγω ζω και υμεις ζησεσθε'),
(3544, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 20, 'NT', 'εν εκεινη τη ημερα γνωσεσθε υμεις οτι εγω εν τω πατρι μου και υμεις εν εμοι καγω εν υμιν'),
(3545, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 21, 'NT', 'ο εχων τας εντολας μου και τηρων αυτας εκεινος εστιν ο αγαπων με ο δε αγαπων με αγαπηθησεται υπο του πατρος μου και εγω αγαπησω αυτον και εμφανισω αυτω εμαυτον'),
(3546, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 22, 'NT', 'λεγει αυτω ιουδας ουχ ο ισκαριωτης κυριε τι γεγονεν οτι ημιν μελλεις εμφανιζειν σεαυτον και ουχι τω κοσμω'),
(3547, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 23, 'NT', 'απεκριθη ο ιησους και ειπεν αυτω εαν τις αγαπα με τον λογον μου τηρησει και ο πατηρ μου αγαπησει αυτον και προς αυτον ελευσομεθα και μονην παρ αυτω ποιησομεν'),
(3548, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 24, 'NT', 'ο μη αγαπων με τους λογους μου ου τηρει και ο λογος ον ακουετε ουκ εστιν εμος αλλα του πεμψαντος με πατρος'),
(3549, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 25, 'NT', 'ταυτα λελαληκα υμιν παρ υμιν μενων'),
(3550, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 26, 'NT', 'ο δε παρακλητος το πνευμα το αγιον ο πεμψει ο πατηρ εν τω ονοματι μου εκεινος υμας διδαξει παντα και υπομνησει υμας παντα α ειπον υμιν'),
(3551, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 27, 'NT', 'ειρηνην αφιημι υμιν ειρηνην την εμην διδωμι υμιν ου καθως ο κοσμος διδωσιν εγω διδωμι υμιν μη ταρασσεσθω υμων η καρδια μηδε δειλιατω'),
(3552, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 28, 'NT', 'ηκουσατε οτι εγω ειπον υμιν υπαγω και ερχομαι προς υμας ει ηγαπατε με εχαρητε αν οτι ειπον πορευομαι προς τον πατερα οτι ο πατηρ μου μειζων μου εστιν'),
(3553, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 29, 'NT', 'και νυν ειρηκα υμιν πριν γενεσθαι ινα οταν γενηται πιστευσητε'),
(3554, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 30, 'NT', 'ουκ ετι πολλα λαλησω μεθ υμων ερχεται γαρ ο του κοσμου τουτου αρχων και εν εμοι ουκ εχει ουδεν'),
(3555, 43, 'TR1550', 'TR1550', 'el', 'JHN', 14, 31, 'NT', 'αλλ ινα γνω ο κοσμος οτι αγαπω τον πατερα και καθως ενετειλατο μοι ο πατηρ ουτως ποιω εγειρεσθε αγωμεν εντευθεν'),
(3556, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 1, 'NT', 'εγω ειμι η αμπελος η αληθινη και ο πατηρ μου ο γεωργος εστιν'),
(3557, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 2, 'NT', 'παν κλημα εν εμοι μη φερον καρπον αιρει αυτο και παν το καρπον φερον καθαιρει αυτο ινα πλειονα καρπον φερη'),
(3558, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 3, 'NT', 'ηδη υμεις καθαροι εστε δια τον λογον ον λελαληκα υμιν'),
(3559, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 4, 'NT', 'μεινατε εν εμοι καγω εν υμιν καθως το κλημα ου δυναται καρπον φερειν αφ εαυτου εαν μη μεινη εν τη αμπελω ουτως ουδε υμεις εαν μη εν εμοι μεινητε'),
(3560, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 5, 'NT', 'εγω ειμι η αμπελος υμεις τα κληματα ο μενων εν εμοι καγω εν αυτω ουτος φερει καρπον πολυν οτι χωρις εμου ου δυνασθε ποιειν ουδεν'),
(3561, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 6, 'NT', 'εαν μη τις μεινη εν εμοι εβληθη εξω ως το κλημα και εξηρανθη και συναγουσιν αυτα και εις πυρ βαλλουσιν και καιεται'),
(3562, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 7, 'NT', 'εαν μεινητε εν εμοι και τα ρηματα μου εν υμιν μεινη ο εαν θελητε αιτησεσθε και γενησεται υμιν'),
(3563, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 8, 'NT', 'εν τουτω εδοξασθη ο πατηρ μου ινα καρπον πολυν φερητε και γενησεσθε εμοι μαθηται'),
(3564, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 9, 'NT', 'καθως ηγαπησεν με ο πατηρ καγω ηγαπησα υμας μεινατε εν τη αγαπη τη εμη'),
(3565, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 10, 'NT', 'εαν τας εντολας μου τηρησητε μενειτε εν τη αγαπη μου καθως εγω τας εντολας του πατρος μου τετηρηκα και μενω αυτου εν τη αγαπη'),
(3566, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 11, 'NT', 'ταυτα λελαληκα υμιν ινα η χαρα η εμη εν υμιν μεινη και η χαρα υμων πληρωθη'),
(3567, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 12, 'NT', 'αυτη εστιν η εντολη η εμη ινα αγαπατε αλληλους καθως ηγαπησα υμας'),
(3568, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 13, 'NT', 'μειζονα ταυτης αγαπην ουδεις εχει ινα τις την ψυχην αυτου θη υπερ των φιλων αυτου'),
(3569, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 14, 'NT', 'υμεις φιλοι μου εστε εαν ποιητε οσα εγω εντελλομαι υμιν'),
(3570, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 15, 'NT', 'ουκετι υμας λεγω δουλους οτι ο δουλος ουκ οιδεν τι ποιει αυτου ο κυριος υμας δε ειρηκα φιλους οτι παντα α ηκουσα παρα του πατρος μου εγνωρισα υμιν'),
(3571, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 16, 'NT', 'ουχ υμεις με εξελεξασθε αλλ εγω εξελεξαμην υμας και εθηκα υμας ινα υμεις υπαγητε και καρπον φερητε και ο καρπος υμων μενη ινα ο τι αν αιτησητε τον πατερα εν τω ονοματι μου δω υμιν'),
(3572, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 17, 'NT', 'ταυτα εντελλομαι υμιν ινα αγαπατε αλληλους'),
(3573, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 18, 'NT', 'ει ο κοσμος υμας μισει γινωσκετε οτι εμε πρωτον υμων μεμισηκεν'),
(3574, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 19, 'NT', 'ει εκ του κοσμου ητε ο κοσμος αν το ιδιον εφιλει οτι δε εκ του κοσμου ουκ εστε αλλ εγω εξελεξαμην υμας εκ του κοσμου δια τουτο μισει υμας ο κοσμος'),
(3575, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 20, 'NT', 'μνημονευετε του λογου ου εγω ειπον υμιν ουκ εστιν δουλος μειζων του κυριου αυτου ει εμε εδιωξαν και υμας διωξουσιν ει τον λογον μου ετηρησαν και τον υμετερον τηρησουσιν'),
(3576, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 21, 'NT', 'αλλα ταυτα παντα ποιησουσιν υμιν δια το ονομα μου οτι ουκ οιδασιν τον πεμψαντα με'),
(3577, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 22, 'NT', 'ει μη ηλθον και ελαλησα αυτοις αμαρτιαν ουκ ειχον νυν δε προφασιν ουκ εχουσιν περι της αμαρτιας αυτων'),
(3578, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 23, 'NT', 'ο εμε μισων και τον πατερα μου μισει'),
(3579, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 24, 'NT', 'ει τα εργα μη εποιησα εν αυτοις α ουδεις αλλος πεποιηκεν αμαρτιαν ουκ ειχον νυν δε και εωρακασιν και μεμισηκασιν και εμε και τον πατερα μου'),
(3580, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 25, 'NT', 'αλλ ινα πληρωθη ο λογος ο γεγραμμενος εν τω νομω αυτων οτι εμισησαν με δωρεαν'),
(3581, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 26, 'NT', 'οταν δε ελθη ο παρακλητος ον εγω πεμψω υμιν παρα του πατρος το πνευμα της αληθειας ο παρα του πατρος εκπορευεται εκεινος μαρτυρησει περι εμου'),
(3582, 43, 'TR1550', 'TR1550', 'el', 'JHN', 15, 27, 'NT', 'και υμεις δε μαρτυρειτε οτι απ αρχης μετ εμου εστε'),
(3583, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 1, 'NT', 'ταυτα λελαληκα υμιν ινα μη σκανδαλισθητε'),
(3584, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 2, 'NT', 'αποσυναγωγους ποιησουσιν υμας αλλ ερχεται ωρα ινα πας ο αποκτεινας υμας δοξη λατρειαν προσφερειν τω θεω'),
(3585, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 3, 'NT', 'και ταυτα ποιησουσιν υμιν οτι ουκ εγνωσαν τον πατερα ουδε εμε'),
(3586, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 4, 'NT', 'αλλα ταυτα λελαληκα υμιν ινα οταν ελθη η ωρα μνημονευητε αυτων οτι εγω ειπον υμιν ταυτα δε υμιν εξ αρχης ουκ ειπον οτι μεθ υμων ημην'),
(3587, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 5, 'NT', 'νυν δε υπαγω προς τον πεμψαντα με και ουδεις εξ υμων ερωτα με που υπαγεις'),
(3588, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 6, 'NT', 'αλλ οτι ταυτα λελαληκα υμιν η λυπη πεπληρωκεν υμων την καρδιαν'),
(3589, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 7, 'NT', 'αλλ εγω την αληθειαν λεγω υμιν συμφερει υμιν ινα εγω απελθω εαν γαρ μη απελθω ο παρακλητος ουκ ελευσεται προς υμας εαν δε πορευθω πεμψω αυτον προς υμας'),
(3590, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 8, 'NT', 'και ελθων εκεινος ελεγξει τον κοσμον περι αμαρτιας και περι δικαιοσυνης και περι κρισεως'),
(3591, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 9, 'NT', 'περι αμαρτιας μεν οτι ου πιστευουσιν εις εμε'),
(3592, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 10, 'NT', 'περι δικαιοσυνης δε οτι προς τον πατερα μου υπαγω και ουκ ετι θεωρειτε με'),
(3593, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 11, 'NT', 'περι δε κρισεως οτι ο αρχων του κοσμου τουτου κεκριται'),
(3594, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 12, 'NT', 'ετι πολλα εχω λεγειν υμιν αλλ ου δυνασθε βασταζειν αρτι'),
(3595, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 13, 'NT', 'οταν δε ελθη εκεινος το πνευμα της αληθειας οδηγησει υμας εις πασαν την αληθειαν ου γαρ λαλησει αφ εαυτου αλλ οσα αν ακουση λαλησει και τα ερχομενα αναγγελει υμιν'),
(3596, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 14, 'NT', 'εκεινος εμε δοξασει οτι εκ του εμου ληψεται και αναγγελει υμιν'),
(3597, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 15, 'NT', 'παντα οσα εχει ο πατηρ εμα εστιν δια τουτο ειπον οτι εκ του εμου ληψεται και αναγγελει υμιν'),
(3598, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 16, 'NT', 'μικρον και ου θεωρειτε με και παλιν μικρον και οψεσθε με οτι εγω υπαγω προς τον πατερα'),
(3599, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 17, 'NT', 'ειπον ουν εκ των μαθητων αυτου προς αλληλους τι εστιν τουτο ο λεγει ημιν μικρον και ου θεωρειτε με και παλιν μικρον και οψεσθε με και οτι εγω υπαγω προς τον πατερα'),
(3600, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 18, 'NT', 'ελεγον ουν τουτο τι εστιν ο λεγει το μικρον ουκ οιδαμεν τι λαλει'),
(3601, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 19, 'NT', 'εγνω ουν ο ιησους οτι ηθελον αυτον ερωταν και ειπεν αυτοις περι τουτου ζητειτε μετ αλληλων οτι ειπον μικρον και ου θεωρειτε με και παλιν μικρον και οψεσθε με'),
(3602, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 20, 'NT', 'αμην αμην λεγω υμιν οτι κλαυσετε και θρηνησετε υμεις ο δε κοσμος χαρησεται υμεις δε λυπηθησεσθε αλλ η λυπη υμων εις χαραν γενησεται'),
(3603, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 21, 'NT', 'η γυνη οταν τικτη λυπην εχει οτι ηλθεν η ωρα αυτης οταν δε γεννηση το παιδιον ουκ ετι μνημονευει της θλιψεως δια την χαραν οτι εγεννηθη ανθρωπος εις τον κοσμον'),
(3604, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 22, 'NT', 'και υμεις ουν λυπην μεν νυν εχετε παλιν δε οψομαι υμας και χαρησεται υμων η καρδια και την χαραν υμων ουδεις αιρει αφ υμων'),
(3605, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 23, 'NT', 'και εν εκεινη τη ημερα εμε ουκ ερωτησετε ουδεν αμην αμην λεγω υμιν οτι οσα αν αιτησητε τον πατερα εν τω ονοματι μου δωσει υμιν'),
(3606, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 24, 'NT', 'εως αρτι ουκ ητησατε ουδεν εν τω ονοματι μου αιτειτε και ληψεσθε ινα η χαρα υμων η πεπληρωμενη'),
(3607, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 25, 'NT', 'ταυτα εν παροιμιαις λελαληκα υμιν αλλ ερχεται ωρα οτε ουκ ετι εν παροιμιαις λαλησω υμιν αλλα παρρησια περι του πατρος αναγγελω υμιν'),
(3608, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 26, 'NT', 'εν εκεινη τη ημερα εν τω ονοματι μου αιτησεσθε και ου λεγω υμιν οτι εγω ερωτησω τον πατερα περι υμων'),
(3609, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 27, 'NT', 'αυτος γαρ ο πατηρ φιλει υμας οτι υμεις εμε πεφιληκατε και πεπιστευκατε οτι εγω παρα του θεου εξηλθον'),
(3610, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 28, 'NT', 'εξηλθον παρα του πατρος και εληλυθα εις τον κοσμον παλιν αφιημι τον κοσμον και πορευομαι προς τον πατερα'),
(3611, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 29, 'NT', 'λεγουσιν αυτω οι μαθηται αυτου ιδε νυν παρρησια λαλεις και παροιμιαν ουδεμιαν λεγεις'),
(3612, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 30, 'NT', 'νυν οιδαμεν οτι οιδας παντα και ου χρειαν εχεις ινα τις σε ερωτα εν τουτω πιστευομεν οτι απο θεου εξηλθες'),
(3613, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 31, 'NT', 'απεκριθη αυτοις ο ιησους αρτι πιστευετε'),
(3614, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 32, 'NT', 'ιδου ερχεται ωρα και νυν εληλυθεν ινα σκορπισθητε εκαστος εις τα ιδια και εμε μονον αφητε και ουκ ειμι μονος οτι ο πατηρ μετ εμου εστιν'),
(3615, 43, 'TR1550', 'TR1550', 'el', 'JHN', 16, 33, 'NT', 'ταυτα λελαληκα υμιν ινα εν εμοι ειρηνην εχητε εν τω κοσμω θλιψιν εχετε αλλα θαρσειτε εγω νενικηκα τον κοσμον'),
(3616, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 1, 'NT', 'ταυτα ελαλησεν ο ιησους και επηρεν τους οφθαλμους αυτου εις τον ουρανον και ειπεν πατερ εληλυθεν η ωρα δοξασον σου τον υιον ινα και ο υιος σου δοξαση σε'),
(3617, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 2, 'NT', 'καθως εδωκας αυτω εξουσιαν πασης σαρκος ινα παν ο δεδωκας αυτω δωση αυτοις ζωην αιωνιον'),
(3618, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 3, 'NT', 'αυτη δε εστιν η αιωνιος ζωη ινα γινωσκωσιν σε τον μονον αληθινον θεον και ον απεστειλας ιησουν χριστον'),
(3619, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 4, 'NT', 'εγω σε εδοξασα επι της γης το εργον ετελειωσα ο δεδωκας μοι ινα ποιησω'),
(3620, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 5, 'NT', 'και νυν δοξασον με συ πατερ παρα σεαυτω τη δοξη η ειχον προ του τον κοσμον ειναι παρα σοι'),
(3621, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 6, 'NT', 'εφανερωσα σου το ονομα τοις ανθρωποις ους δεδωκας μοι εκ του κοσμου σοι ησαν και εμοι αυτους δεδωκας και τον λογον σου τετηρηκασιν'),
(3622, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 7, 'NT', 'νυν εγνωκαν οτι παντα οσα δεδωκας μοι παρα σου εστιν'),
(3623, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 8, 'NT', 'οτι τα ρηματα α δεδωκας μοι δεδωκα αυτοις και αυτοι ελαβον και εγνωσαν αληθως οτι παρα σου εξηλθον και επιστευσαν οτι συ με απεστειλας'),
(3624, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 9, 'NT', 'εγω περι αυτων ερωτω ου περι του κοσμου ερωτω αλλα περι ων δεδωκας μοι οτι σοι εισιν'),
(3625, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 10, 'NT', 'και τα εμα παντα σα εστιν και τα σα εμα και δεδοξασμαι εν αυτοις'),
(3626, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 11, 'NT', 'και ουκ ετι ειμι εν τω κοσμω και ουτοι εν τω κοσμω εισιν και εγω προς σε ερχομαι πατερ αγιε τηρησον αυτους εν τω ονοματι σου ους δεδωκας μοι ινα ωσιν εν καθως ημεις'),
(3627, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 12, 'NT', 'οτε ημην μετ αυτων εν τω κοσμω εγω ετηρουν αυτους εν τω ονοματι σου ους δεδωκας μοι εφυλαξα και ουδεις εξ αυτων απωλετο ει μη ο υιος της απωλειας ινα η γραφη πληρωθη'),
(3628, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 13, 'NT', 'νυν δε προς σε ερχομαι και ταυτα λαλω εν τω κοσμω ινα εχωσιν την χαραν την εμην πεπληρωμενην εν αυτοις'),
(3629, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 14, 'NT', 'εγω δεδωκα αυτοις τον λογον σου και ο κοσμος εμισησεν αυτους οτι ουκ εισιν εκ του κοσμου καθως εγω ουκ ειμι εκ του κοσμου'),
(3630, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 15, 'NT', 'ουκ ερωτω ινα αρης αυτους εκ του κοσμου αλλ ινα τηρησης αυτους εκ του πονηρου'),
(3631, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 16, 'NT', 'εκ του κοσμου ουκ εισιν καθως εγω εκ του κοσμου ουκ ειμι'),
(3632, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 17, 'NT', 'αγιασον αυτους εν τη αληθεια σου ο λογος ο σος αληθεια εστιν'),
(3633, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 18, 'NT', 'καθως εμε απεστειλας εις τον κοσμον καγω απεστειλα αυτους εις τον κοσμον'),
(3634, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 19, 'NT', 'και υπερ αυτων εγω αγιαζω εμαυτον ινα και αυτοι ωσιν ηγιασμενοι εν αληθεια'),
(3635, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 20, 'NT', 'ου περι τουτων δε ερωτω μονον αλλα και περι των πιστευσοντων δια του λογου αυτων εις εμε'),
(3636, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 21, 'NT', 'ινα παντες εν ωσιν καθως συ πατερ εν εμοι καγω εν σοι ινα και αυτοι εν ημιν εν ωσιν ινα ο κοσμος πιστευση οτι συ με απεστειλας'),
(3637, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 22, 'NT', 'και εγω την δοξαν ην δεδωκας μοι δεδωκα αυτοις ινα ωσιν εν καθως ημεις εν εσμεν'),
(3638, 43, 'TR1550', 'TR1550', 'el', 'JHN', 17, 23, 'NT', 'εγω εν αυτοις και συ εν εμοι ινα ωσιν τετελειωμενοι εις εν και ινα γινωσκη ο κοσμος οτι συ με απεστειλας και ηγαπησας αυτους καθως εμε ηγαπησας'),
