(3753, 43, 'TR1550', 'TR1550', 'el', 'JHN', 20, 30, 'NT', 'πολλα μεν ουν και αλλα σημεια εποιησεν ο ιησους ενωπιον των μαθητων αυτου α ουκ εστιν γεγραμμενα εν τω βιβλιω τουτω'),
(3754, 43, 'TR1550', 'TR1550', 'el', 'JHN', 20, 31, 'NT', 'ταυτα δε γεγραπται ινα πιστευσητε οτι ο ιησους εστιν ο χριστος ο υιος του θεου και ινα πιστευοντες ζωην εχητε εν τω ονοματι αυτου'),
(3755, 43, 'TR1550', 'TR1550', 'el', 'JHN', 21, 1, 'NT', 'μετα ταυτα εφανερωσεν εαυτον παλιν ο ιησους τοις μαθηταις επι της θαλασσης της τιβεριαδος εφανερωσεν δε ουτως'),
(3756, 43, 'TR1550', 'TR1550', 'el', 'JHN', 21, 2, 'NT', 'ησαν ομου σιμων πετρος και θωμας ο λεγομενος διδυμος και ναθαναηλ ο απο κανα της γαλιλαιας και οι του ζεβεδαιου και αλλοι εκ των μαθητων αυτου δυο'),
(3757, 43, 'TR1550', 'TR1550', 'el', 'JHN', 21, 3, 'NT', 'λεγει αυτοις σιμων πετρος υπαγω αλιευειν λεγουσιν αυτω ερχομεθα και ημεις συν σοι εξηλθον και ανεβησαν εις το πλοιον ευθυς και εν εκεινη τη νυκτι επιασαν ουδεν'),
(3758, 43, 'TR1550', 'TR1550', 'el', 'JHN', 21, 4, 'NT', 'πρωιας δε ηδη γενομενης εστη ο ιησους εις τον αιγιαλον ου μεντοι ηδεισαν οι μαθηται οτι ιησους εστιν'),
(3759, 43, 'TR1550', 'TR1550', 'el', 'JHN', 21, 5, 'NT', 'λεγει ουν αυτοις ο ιησους παιδια μη τι προσφαγιον εχετε απεκριθησαν αυτω ου'),
