(3788, 44, 'TR1550', 'TR1550', 'el', 'ACT', 1, 9, 'NT', 'και ταυτα ειπων βλεποντων αυτων επηρθη και νεφελη υπελαβεν αυτον απο των οφθαλμων αυτων'),
(3789, 44, 'TR1550', 'TR1550', 'el', 'ACT', 1, 10, 'NT', 'και ως ατενιζοντες ησαν εις τον ουρανον πορευομενου αυτου και ιδου ανδρες δυο παρειστηκεισαν αυτοις εν εσθητι λευκη'),
(3790, 44, 'TR1550', 'TR1550', 'el', 'ACT', 1, 11, 'NT', 'οι και ειπον ανδρες γαλιλαιοι τι εστηκατε εμβλεποντες εις τον ουρανον ουτος ο ιησους ο αναληφθεις αφ υμων εις τον ουρανον ουτως ελευσεται ον τροπον εθεασασθε αυτον πορευομενον εις τον ουρανον'),
(3791, 44, 'TR1550', 'TR1550', 'el', 'ACT', 1, 12, 'NT', 'τοτε υπεστρεψαν εις ιερουσαλημ απο ορους του καλουμενου ελαιωνος ο εστιν εγγυς ιερουσαλημ σαββατου εχον οδον'),
(3792, 44, 'TR1550', 'TR1550', 'el', 'ACT', 1, 13, 'NT', 'και οτε εισηλθον ανεβησαν εις το υπερωον ου ησαν καταμενοντες ο τε πετρος και ιακωβος και ιωαννης και ανδρεας φιλιππος και θωμας βαρθολομαιος και ματθαιος ιακωβος αλφαιου και σιμων ο ζηλωτης και ιουδας ιακωβου'),
(3793, 44, 'TR1550', 'TR1550', 'el', 'ACT', 1, 14, 'NT', 'ουτοι παντες ησαν προσκαρτερουντες ομοθυμαδον τη προσευχη και τη δεησει συν γυναιξιν και μαρια τη μητρι του ιησου και συν τοις αδελφοις αυτου'),
