(3894, 44, 'TR1550', 'TR1550', 'el', 'ACT', 4, 16, 'NT', 'λεγοντες τι ποιησομεν τοις ανθρωποις τουτοις οτι μεν γαρ γνωστον σημειον γεγονεν δι αυτων πασιν τοις κατοικουσιν ιερουσαλημ φανερον και ου δυναμεθα αρνησασθαι'),
(3895, 44, 'TR1550', 'TR1550', 'el', 'ACT', 4, 17, 'NT', 'αλλ ινα μη επι πλειον διανεμηθη εις τον λαον απειλη απειλησωμεθα αυτοις μηκετι λαλειν επι τω ονοματι τουτω μηδενι ανθρωπων'),
(3896, 44, 'TR1550', 'TR1550', 'el', 'ACT', 4, 18, 'NT', 'και καλεσαντες αυτους παρηγγειλαν αυτοις το καθολου μη φθεγγεσθαι μηδε διδασκειν επι τω ονοματι του ιησου'),
(3897, 44, 'TR1550', 'TR1550', 'el', 'ACT', 4, 19, 'NT', 'ο δε πετρος και ιωαννης αποκριθεντες προς αυτους ειπον ει δικαιον εστιν ενωπιον του θεου υμων ακουειν μαλλον η του θεου κρινατε'),
(3898, 44, 'TR1550', 'TR1550', 'el', 'ACT', 4, 20, 'NT', 'ου δυναμεθα γαρ ημεις α ειδομεν και ηκουσαμεν μη λαλειν'),
(3899, 44, 'TR1550', 'TR1550', 'el', 'ACT', 4, 21, 'NT', 'οι δε προσαπειλησαμενοι απελυσαν αυτους μηδεν ευρισκοντες το πως κολασωνται αυτους δια τον λαον οτι παντες εδοξαζον τον θεον επι τω γεγονοτι'),
(3900, 44, 'TR1550', 'TR1550', 'el', 'ACT', 4, 22, 'NT', 'ετων γαρ ην πλειονων τεσσαρακοντα ο ανθρωπος εφ ον εγεγονει το σημειον τουτο της ιασεως'),
