(4042, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 10, 'NT', 'ω προσειχον παντες απο μικρου εως μεγαλου λεγοντες ουτος εστιν η δυναμις του θεου η μεγαλη'),
(4043, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 11, 'NT', 'προσειχον δε αυτω δια το ικανω χρονω ταις μαγειαις εξεστακεναι αυτους'),
(4044, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 12, 'NT', 'οτε δε επιστευσαν τω φιλιππω ευαγγελιζομενω τα περι της βασιλειας του θεου και του ονοματος του ιησου χριστου εβαπτιζοντο ανδρες τε και γυναικες'),
(4045, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 13, 'NT', 'ο δε σιμων και αυτος επιστευσεν και βαπτισθεις ην προσκαρτερων τω φιλιππω θεωρων τε σημεια και δυναμεις μεγαλας γινομενας εξιστατο'),
(4046, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 14, 'NT', 'ακουσαντες δε οι εν ιεροσολυμοις αποστολοι οτι δεδεκται η σαμαρεια τον λογον του θεου απεστειλαν προς αυτους τον πετρον και ιωαννην'),
(4047, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 15, 'NT', 'οιτινες καταβαντες προσηυξαντο περι αυτων οπως λαβωσιν πνευμα αγιον'),
(4048, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 16, 'NT', 'ουπω γαρ ην επ ουδενι αυτων επιπεπτωκος μονον δε βεβαπτισμενοι υπηρχον εις το ονομα του κυριου ιησου'),
(4049, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 17, 'NT', 'τοτε επετιθουν τας χειρας επ αυτους και ελαμβανον πνευμα αγιον'),
(4050, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 18, 'NT', 'θεασαμενος δε ο σιμων οτι δια της επιθεσεως των χειρων των αποστολων διδοται το πνευμα το αγιον προσηνεγκεν αυτοις χρηματα'),
(4051, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 19, 'NT', 'λεγων δοτε καμοι την εξουσιαν ταυτην ινα ω αν επιθω τας χειρας λαμβανη πνευμα αγιον'),
(4052, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 20, 'NT', 'πετρος δε ειπεν προς αυτον το αργυριον σου συν σοι ειη εις απωλειαν οτι την δωρεαν του θεου ενομισας δια χρηματων κτασθαι'),
(4053, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 21, 'NT', 'ουκ εστιν σοι μερις ουδε κληρος εν τω λογω τουτω η γαρ καρδια σου ουκ εστιν ευθεια ενωπιον του θεου'),
(4054, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 22, 'NT', 'μετανοησον ουν απο της κακιας σου ταυτης και δεηθητι του θεου ει αρα αφεθησεται σοι η επινοια της καρδιας σου'),
(4055, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 23, 'NT', 'εις γαρ χολην πικριας και συνδεσμον αδικιας ορω σε οντα'),
(4056, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 24, 'NT', 'αποκριθεις δε ο σιμων ειπεν δεηθητε υμεις υπερ εμου προς τον κυριον οπως μηδεν επελθη επ εμε ων ειρηκατε'),
(4057, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 25, 'NT', 'οι μεν ουν διαμαρτυραμενοι και λαλησαντες τον λογον του κυριου υπεστρεψαν εις ιερουσαλημ πολλας τε κωμας των σαμαρειτων ευηγγελισαντο'),
