(4065, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 33, 'NT', 'εν τη ταπεινωσει αυτου η κρισις αυτου ηρθη την δε γενεαν αυτου τις διηγησεται οτι αιρεται απο της γης η ζωη αυτου'),
(4066, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 34, 'NT', 'αποκριθεις δε ο ευνουχος τω φιλιππω ειπεν δεομαι σου περι τινος ο προφητης λεγει τουτο περι εαυτου η περι ετερου τινος'),
(4067, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 35, 'NT', 'ανοιξας δε ο φιλιππος το στομα αυτου και αρξαμενος απο της γραφης ταυτης ευηγγελισατο αυτω τον ιησουν'),
(4068, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 36, 'NT', 'ως δε επορευοντο κατα την οδον ηλθον επι τι υδωρ και φησιν ο ευνουχος ιδου υδωρ τι κωλυει με βαπτισθηναι'),
(4069, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 37, 'NT', 'ειπεν δε ο φιλιππος ει πιστευεις εξ ολης της καρδιας εξεστιν αποκριθεις δε ειπεν πιστευω τον υιον του θεου ειναι τον ιησουν χριστον'),
(4070, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 38, 'NT', 'και εκελευσεν στηναι το αρμα και κατεβησαν αμφοτεροι εις το υδωρ ο τε φιλιππος και ο ευνουχος και εβαπτισεν αυτον'),
(4071, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 39, 'NT', 'οτε δε ανεβησαν εκ του υδατος πνευμα κυριου ηρπασεν τον φιλιππον και ουκ ειδεν αυτον ουκετι ο ευνουχος επορευετο γαρ την οδον αυτου χαιρων'),
(4072, 44, 'TR1550', 'TR1550', 'el', 'ACT', 8, 40, 'NT', 'φιλιππος δε ευρεθη εις αζωτον και διερχομενος ευηγγελιζετο τας πολεις πασας εως του ελθειν αυτον εις καισαρειαν'),
(4073, 44, 'TR1550', 'TR1550', 'el', 'ACT', 9, 1, 'NT', 'ο δε σαυλος ετι εμπνεων απειλης και φονου εις τους μαθητας του κυριου προσελθων τω αρχιερει'),
(4074, 44, 'TR1550', 'TR1550', 'el', 'ACT', 9, 2, 'NT', 'ητησατο παρ αυτου επιστολας εις δαμασκον προς τας συναγωγας οπως εαν τινας ευρη της οδου οντας ανδρας τε και γυναικας δεδεμενους αγαγη εις ιερουσαλημ'),
(4075, 44, 'TR1550', 'TR1550', 'el', 'ACT', 9, 3, 'NT', 'εν δε τω πορευεσθαι εγενετο αυτον εγγιζειν τη δαμασκω και εξαιφνης περιηστραψεν αυτον φως απο του ουρανου'),
(4076, 44, 'TR1550', 'TR1550', 'el', 'ACT', 9, 4, 'NT', 'και πεσων επι την γην ηκουσεν φωνην λεγουσαν αυτω σαουλ σαουλ τι με διωκεις'),
(4077, 44, 'TR1550', 'TR1550', 'el', 'ACT', 9, 5, 'NT', 'ειπεν δε τις ει κυριε ο δε κυριος ειπεν εγω ειμι ιησους ον συ διωκεις σκληρον σοι προς κεντρα λακτιζειν'),
(4078, 44, 'TR1550', 'TR1550', 'el', 'ACT', 9, 6, 'NT', 'τρεμων τε και θαμβων ειπεν κυριε τι με θελεις ποιησαι και ο κυριος προς αυτον αναστηθι και εισελθε εις την πολιν και λαληθησεται σοι τι σε δει ποιειν'),
(4079, 44, 'TR1550', 'TR1550', 'el', 'ACT', 9, 7, 'NT', 'οι δε ανδρες οι συνοδευοντες αυτω ειστηκεισαν εννεοι ακουοντες μεν της φωνης μηδενα δε θεωρουντες'),
