(4118, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 3, 'NT', 'ειδεν εν οραματι φανερως ωσει ωραν εννατην της ημερας αγγελον του θεου εισελθοντα προς αυτον και ειποντα αυτω κορνηλιε'),
(4119, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 4, 'NT', 'ο δε ατενισας αυτω και εμφοβος γενομενος ειπεν τι εστιν κυριε ειπεν δε αυτω αι προσευχαι σου και αι ελεημοσυναι σου ανεβησαν εις μνημοσυνον ενωπιον του θεου'),
(4120, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 5, 'NT', 'και νυν πεμψον εις ιοππην ανδρας και μεταπεμψαι σιμωνα ος επικαλειται πετρος'),
(4121, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 6, 'NT', 'ουτος ξενιζεται παρα τινι σιμωνι βυρσει ω εστιν οικια παρα θαλασσαν ουτος λαλησει σοι τι σε δει ποιειν'),
(4122, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 7, 'NT', 'ως δε απηλθεν ο αγγελος ο λαλων τω κορνηλιω φωνησας δυο των οικετων αυτου και στρατιωτην ευσεβη των προσκαρτερουντων αυτω'),
(4123, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 8, 'NT', 'και εξηγησαμενος αυτοις απαντα απεστειλεν αυτους εις την ιοππην'),
(4124, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 9, 'NT', 'τη δε επαυριον οδοιπορουντων εκεινων και τη πολει εγγιζοντων ανεβη πετρος επι το δωμα προσευξασθαι περι ωραν εκτην'),
(4125, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 10, 'NT', 'εγενετο δε προσπεινος και ηθελεν γευσασθαι παρασκευαζοντων δε εκεινων επεπεσεν επ αυτον εκστασις'),
(4126, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 11, 'NT', 'και θεωρει τον ουρανον ανεωγμενον και καταβαινον επ αυτον σκευος τι ως οθονην μεγαλην τεσσαρσιν αρχαις δεδεμενον και καθιεμενον επι της γης'),
(4127, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 12, 'NT', 'εν ω υπηρχεν παντα τα τετραποδα της γης και τα θηρια και τα ερπετα και τα πετεινα του ουρανου'),
(4128, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 13, 'NT', 'και εγενετο φωνη προς αυτον αναστας πετρε θυσον και φαγε'),
(4129, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 14, 'NT', 'ο δε πετρος ειπεν μηδαμως κυριε οτι ουδεποτε εφαγον παν κοινον η ακαθαρτον'),
(4130, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 15, 'NT', 'και φωνη παλιν εκ δευτερου προς αυτον α ο θεος εκαθαρισεν συ μη κοινου'),
(4131, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 16, 'NT', 'τουτο δε εγενετο επι τρις και παλιν ανεληφθη το σκευος εις τον ουρανον'),
(4132, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 17, 'NT', 'ως δε εν εαυτω διηπορει ο πετρος τι αν ειη το οραμα ο ειδεν και ιδου οι ανδρες οι απεσταλμενοι απο του κορνηλιου διερωτησαντες την οικιαν σιμωνος επεστησαν επι τον πυλωνα'),
(4133, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 18, 'NT', 'και φωνησαντες επυνθανοντο ει σιμων ο επικαλουμενος πετρος ενθαδε ξενιζεται'),
(4134, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 19, 'NT', 'του δε πετρου ενθυμουμενου περι του οραματος ειπεν αυτω το πνευμα ιδου ανδρες τρεις ζητουσιν σε'),
(4135, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 20, 'NT', 'αλλα αναστας καταβηθι και πορευου συν αυτοις μηδεν διακρινομενος διοτι εγω απεσταλκα αυτους'),
(4136, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 21, 'NT', 'καταβας δε πετρος προς τους ανδρας τους απεσταλμενους απο του κορνηλιου προς αυτον ειπεν ιδου εγω ειμι ον ζητειτε τις η αιτια δι ην παρεστε'),
(4137, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 22, 'NT', 'οι δε ειπον κορνηλιος εκατονταρχης ανηρ δικαιος και φοβουμενος τον θεον μαρτυρουμενος τε υπο ολου του εθνους των ιουδαιων εχρηματισθη υπο αγγελου αγιου μεταπεμψασθαι σε εις τον οικον αυτου και ακουσαι ρηματα παρα σου'),
(4138, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 23, 'NT', 'εισκαλεσαμενος ουν αυτους εξενισεν τη δε επαυριον ο πετρος εξηλθεν συν αυτοις και τινες των αδελφων των απο της ιοππης συνηλθον αυτω'),
(4139, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 24, 'NT', 'και τη επαυριον εισηλθον εις την καισαρειαν ο δε κορνηλιος ην προσδοκων αυτους συγκαλεσαμενος τους συγγενεις αυτου και τους αναγκαιους φιλους'),
(4140, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 25, 'NT', 'ως δε εγενετο εισελθειν τον πετρον συναντησας αυτω ο κορνηλιος πεσων επι τους ποδας προσεκυνησεν'),
