(4142, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 27, 'NT', 'και συνομιλων αυτω εισηλθεν και ευρισκει συνεληλυθοτας πολλους'),
(4143, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 28, 'NT', 'εφη τε προς αυτους υμεις επιστασθε ως αθεμιτον εστιν ανδρι ιουδαιω κολλασθαι η προσερχεσθαι αλλοφυλω και εμοι ο θεος εδειξεν μηδενα κοινον η ακαθαρτον λεγειν ανθρωπον'),
(4144, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 29, 'NT', 'διο και αναντιρρητως ηλθον μεταπεμφθεις πυνθανομαι ουν τινι λογω μετεπεμψασθε με'),
(4145, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 30, 'NT', 'και ο κορνηλιος εφη απο τεταρτης ημερας μεχρι ταυτης της ωρας ημην νηστευων και την εννατην ωραν προσευχομενος εν τω οικω μου και ιδου ανηρ εστη ενωπιον μου εν εσθητι λαμπρα'),
(4146, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 31, 'NT', 'και φησιν κορνηλιε εισηκουσθη σου η προσευχη και αι ελεημοσυναι σου εμνησθησαν ενωπιον του θεου'),
(4147, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 32, 'NT', 'πεμψον ουν εις ιοππην και μετακαλεσαι σιμωνα ος επικαλειται πετρος ουτος ξενιζεται εν οικια σιμωνος βυρσεως παρα θαλασσαν ος παραγενομενος λαλησει σοι'),
(4148, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 33, 'NT', 'εξαυτης ουν επεμψα προς σε συ τε καλως εποιησας παραγενομενος νυν ουν παντες ημεις ενωπιον του θεου παρεσμεν ακουσαι παντα τα προστεταγμενα σοι υπο του θεου'),
(4149, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 34, 'NT', 'ανοιξας δε πετρος το στομα ειπεν επ αληθειας καταλαμβανομαι οτι ουκ εστιν προσωποληπτης ο θεος'),
(4150, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 35, 'NT', 'αλλ εν παντι εθνει ο φοβουμενος αυτον και εργαζομενος δικαιοσυνην δεκτος αυτω εστιν'),
(4151, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 36, 'NT', 'τον λογον ον απεστειλεν τοις υιοις ισραηλ ευαγγελιζομενος ειρηνην δια ιησου χριστου ουτος εστιν παντων κυριος'),
(4152, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 37, 'NT', 'υμεις οιδατε το γενομενον ρημα καθ ολης της ιουδαιας αρξαμενον απο της γαλιλαιας μετα το βαπτισμα ο εκηρυξεν ιωαννης'),
(4153, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 38, 'NT', 'ιησουν τον απο ναζαρετ ως εχρισεν αυτον ο θεος πνευματι αγιω και δυναμει ος διηλθεν ευεργετων και ιωμενος παντας τους καταδυναστευομενους υπο του διαβολου οτι ο θεος ην μετ αυτου'),
(4154, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 39, 'NT', 'και ημεις εσμεν μαρτυρες παντων ων εποιησεν εν τε τη χωρα των ιουδαιων και εν ιερουσαλημ ον ανειλον κρεμασαντες επι ξυλου'),
(4155, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 40, 'NT', 'τουτον ο θεος ηγειρεν τη τριτη ημερα και εδωκεν αυτον εμφανη γενεσθαι'),
(4156, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 41, 'NT', 'ου παντι τω λαω αλλα μαρτυσιν τοις προκεχειροτονημενοις υπο του θεου ημιν οιτινες συνεφαγομεν και συνεπιομεν αυτω μετα το αναστηναι αυτον εκ νεκρων'),
(4157, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 42, 'NT', 'και παρηγγειλεν ημιν κηρυξαι τω λαω και διαμαρτυρασθαι οτι αυτος εστιν ο ωρισμενος υπο του θεου κριτης ζωντων και νεκρων'),
(4158, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 43, 'NT', 'τουτω παντες οι προφηται μαρτυρουσιν αφεσιν αμαρτιων λαβειν δια του ονοματος αυτου παντα τον πιστευοντα εις αυτον'),
(4159, 44, 'TR1550', 'TR1550', 'el', 'ACT', 10, 44, 'NT', 'ετι λαλουντος του πετρου τα ρηματα ταυτα επεπεσεν το πνευμα το αγιον επι παντας τους ακουοντας τον λογον'),
