(4596, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 6, 'NT', 'γνους δε ο παυλος οτι το εν μερος εστιν σαδδουκαιων το δε ετερον φαρισαιων εκραξεν εν τω συνεδριω ανδρες αδελφοι εγω φαρισαιος ειμι υιος φαρισαιου περι ελπιδος και αναστασεως νεκρων εγω κρινομαι'),
(4597, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 7, 'NT', 'τουτο δε αυτου λαλησαντος εγενετο στασις των φαρισαιων και των σαδδουκαιων και εσχισθη το πληθος'),
(4598, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 8, 'NT', 'σαδδουκαιοι μεν γαρ λεγουσιν μη ειναι αναστασιν μηδε αγγελον μητε πνευμα φαρισαιοι δε ομολογουσιν τα αμφοτερα'),
(4599, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 9, 'NT', 'εγενετο δε κραυγη μεγαλη και ανασταντες οι γραμματεις του μερους των φαρισαιων διεμαχοντο λεγοντες ουδεν κακον ευρισκομεν εν τω ανθρωπω τουτω ει δε πνευμα ελαλησεν αυτω η αγγελος μη θεομαχωμεν'),
(4600, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 10, 'NT', 'πολλης δε γενομενης στασεως ευλαβηθεις ο χιλιαρχος μη διασπασθη ο παυλος υπ αυτων εκελευσεν το στρατευμα καταβαν αρπασαι αυτον εκ μεσου αυτων αγειν τε εις την παρεμβολην'),
(4601, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 11, 'NT', 'τη δε επιουση νυκτι επιστας αυτω ο κυριος ειπεν θαρσει παυλε ως γαρ διεμαρτυρω τα περι εμου εις ιερουσαλημ ουτως σε δει και εις ρωμην μαρτυρησαι'),
(4602, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 12, 'NT', 'γενομενης δε ημερας ποιησαντες τινες των ιουδαιων συστροφην ανεθεματισαν εαυτους λεγοντες μητε φαγειν μητε πιειν εως ου αποκτεινωσιν τον παυλον'),
(4603, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 13, 'NT', 'ησαν δε πλειους τεσσαρακοντα οι ταυτην την συνωμοσιαν πεποιηκοτες'),
(4604, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 14, 'NT', 'οιτινες προσελθοντες τοις αρχιερευσιν και τοις πρεσβυτεροις ειπον αναθεματι ανεθεματισαμεν εαυτους μηδενος γευσασθαι εως ου αποκτεινωμεν τον παυλον'),
(4605, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 15, 'NT', 'νυν ουν υμεις εμφανισατε τω χιλιαρχω συν τω συνεδριω οπως αυριον αυτον καταγαγη προς υμας ως μελλοντας διαγινωσκειν ακριβεστερον τα περι αυτου ημεις δε προ του εγγισαι αυτον ετοιμοι εσμεν του ανελειν αυτον'),
(4606, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 16, 'NT', 'ακουσας δε ο υιος της αδελφης παυλου το ενεδρον παραγενομενος και εισελθων εις την παρεμβολην απηγγειλεν τω παυλω'),
(4607, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 17, 'NT', 'προσκαλεσαμενος δε ο παυλος ενα των εκατονταρχων εφη τον νεανιαν τουτον απαγαγε προς τον χιλιαρχον εχει γαρ τι απαγγειλαι αυτω'),
(4608, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 18, 'NT', 'ο μεν ουν παραλαβων αυτον ηγαγεν προς τον χιλιαρχον και φησιν ο δεσμιος παυλος προσκαλεσαμενος με ηρωτησεν τουτον τον νεανιαν αγαγειν προς σε εχοντα τι λαλησαι σοι'),
(4609, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 19, 'NT', 'επιλαβομενος δε της χειρος αυτου ο χιλιαρχος και αναχωρησας κατ ιδιαν επυνθανετο τι εστιν ο εχεις απαγγειλαι μοι'),
(4610, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 20, 'NT', 'ειπεν δε οτι οι ιουδαιοι συνεθεντο του ερωτησαι σε οπως αυριον εις το συνεδριον καταγαγης τον παυλον ως μελλοντες τι ακριβεστερον πυνθανεσθαι περι αυτου'),
(4611, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 21, 'NT', 'συ ουν μη πεισθης αυτοις ενεδρευουσιν γαρ αυτον εξ αυτων ανδρες πλειους τεσσαρακοντα οιτινες ανεθεματισαν εαυτους μητε φαγειν μητε πιειν εως ου ανελωσιν αυτον και νυν ετοιμοι εισιν προσδεχομενοι την απο σου επαγγελιαν'),
(4612, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 22, 'NT', 'ο μεν ουν χιλιαρχος απελυσεν τον νεανιαν παραγγειλας μηδενι εκλαλησαι οτι ταυτα ενεφανισας προς με'),
(4613, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 23, 'NT', 'και προσκαλεσαμενος δυο τινας των εκατονταρχων ειπεν ετοιμασατε στρατιωτας διακοσιους οπως πορευθωσιν εως καισαρειας και ιππεις εβδομηκοντα και δεξιολαβους διακοσιους απο τριτης ωρας της νυκτος'),
(4614, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 24, 'NT', 'κτηνη τε παραστησαι ινα επιβιβασαντες τον παυλον διασωσωσιν προς φηλικα τον ηγεμονα'),
(4615, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 25, 'NT', 'γραψας επιστολην περιεχουσαν τον τυπον τουτον'),
(4616, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 26, 'NT', 'κλαυδιος λυσιας τω κρατιστω ηγεμονι φηλικι χαιρειν'),
(4617, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 27, 'NT', 'τον ανδρα τουτον συλληφθεντα υπο των ιουδαιων και μελλοντα αναιρεισθαι υπ αυτων επιστας συν τω στρατευματι εξειλομην αυτον μαθων οτι ρωμαιος εστιν'),
(4618, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 28, 'NT', 'βουλομενος δε γνωναι την αιτιαν δι ην ενεκαλουν αυτω κατηγαγον αυτον εις το συνεδριον αυτων'),
(4619, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 29, 'NT', 'ον ευρον εγκαλουμενον περι ζητηματων του νομου αυτων μηδεν δε αξιον θανατου η δεσμων εγκλημα εχοντα'),
(4620, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 30, 'NT', 'μηνυθεισης δε μοι επιβουλης εις τον ανδρα μελλειν εσεσθαι υπο των ιουδαιων εξαυτης επεμψα προς σε παραγγειλας και τοις κατηγοροις λεγειν τα προς αυτον επι σου ερρωσο'),
(4621, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 31, 'NT', 'οι μεν ουν στρατιωται κατα το διατεταγμενον αυτοις αναλαβοντες τον παυλον ηγαγον δια της νυκτος εις την αντιπατριδα'),
(4622, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 32, 'NT', 'τη δε επαυριον εασαντες τους ιππεις πορευεσθαι συν αυτω υπεστρεψαν εις την παρεμβολην'),
(4623, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 33, 'NT', 'οιτινες εισελθοντες εις την καισαρειαν και αναδοντες την επιστολην τω ηγεμονι παρεστησαν και τον παυλον αυτω'),
(4624, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 34, 'NT', 'αναγνους δε ο ηγεμων και επερωτησας εκ ποιας επαρχιας εστιν και πυθομενος οτι απο κιλικιας'),
(4625, 44, 'TR1550', 'TR1550', 'el', 'ACT', 23, 35, 'NT', 'διακουσομαι σου εφη οταν και οι κατηγοροι σου παραγενωνται εκελευσεν τε αυτον εν τω πραιτωριω του ηρωδου φυλασσεσθαι'),
(4626, 44, 'TR1550', 'TR1550', 'el', 'ACT', 24, 1, 'NT', 'μετα δε πεντε ημερας κατεβη ο αρχιερευς ανανιας μετα των πρεσβυτερων και ρητορος τερτυλλου τινος οιτινες ενεφανισαν τω ηγεμονι κατα του παυλου'),
(4627, 44, 'TR1550', 'TR1550', 'el', 'ACT', 24, 2, 'NT', 'κληθεντος δε αυτου ηρξατο κατηγορειν ο τερτυλλος λεγων [24:3] πολλης ειρηνης τυγχανοντες δια σου και κατορθωματων γινομενων τω εθνει τουτω δια της σης προνοιας'),
(4628, 44, 'TR1550', 'TR1550', 'el', 'ACT', 24, 3, 'NT', 'παντη τε και πανταχου αποδεχομεθα κρατιστε φηλιξ μετα πασης ευχαριστιας'),
