(4655, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 3, 'NT', 'αιτουμενοι χαριν κατ αυτου οπως μεταπεμψηται αυτον εις ιερουσαλημ ενεδραν ποιουντες ανελειν αυτον κατα την οδον'),
(4656, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 4, 'NT', 'ο μεν ουν φηστος απεκριθη τηρεισθαι τον παυλον εν καισαρεια εαυτον δε μελλειν εν ταχει εκπορευεσθαι'),
(4657, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 5, 'NT', 'οι ουν δυνατοι εν υμιν φησιν συγκαταβαντες ει τι εστιν εν τω ανδρι τουτω κατηγορειτωσαν αυτου'),
(4658, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 6, 'NT', 'διατριψας δε εν αυτοις ημερας πλειους η δεκα καταβας εις καισαρειαν τη επαυριον καθισας επι του βηματος εκελευσεν τον παυλον αχθηναι'),
(4659, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 7, 'NT', 'παραγενομενου δε αυτου περιεστησαν οι απο ιεροσολυμων καταβεβηκοτες ιουδαιοι πολλα και βαρεα αιτιαματα φεροντες κατα του παυλου α ουκ ισχυον αποδειξαι'),
(4660, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 8, 'NT', 'απολογουμενου αυτου οτι ουτε εις τον νομον των ιουδαιων ουτε εις το ιερον ουτε εις καισαρα τι ημαρτον'),
(4661, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 9, 'NT', 'ο φηστος δε τοις ιουδαιοις θελων χαριν καταθεσθαι αποκριθεις τω παυλω ειπεν θελεις εις ιεροσολυμα αναβας εκει περι τουτων κρινεσθαι επ εμου'),
(4662, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 10, 'NT', 'ειπεν δε ο παυλος επι του βηματος καισαρος εστως ειμι ου με δει κρινεσθαι ιουδαιους ουδεν ηδικησα ως και συ καλλιον επιγινωσκεις'),
(4663, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 11, 'NT', 'ει μεν γαρ αδικω και αξιον θανατου πεπραχα τι ου παραιτουμαι το αποθανειν ει δε ουδεν εστιν ων ουτοι κατηγορουσιν μου ουδεις με δυναται αυτοις χαρισασθαι καισαρα επικαλουμαι'),
(4664, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 12, 'NT', 'τοτε ο φηστος συλλαλησας μετα του συμβουλιου απεκριθη καισαρα επικεκλησαι επι καισαρα πορευση'),
