(4666, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 14, 'NT', 'ως δε πλειους ημερας διετριβον εκει ο φηστος τω βασιλει ανεθετο τα κατα τον παυλον λεγων ανηρ τις εστιν καταλελειμμενος υπο φηλικος δεσμιος'),
(4667, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 15, 'NT', 'περι ου γενομενου μου εις ιεροσολυμα ενεφανισαν οι αρχιερεις και οι πρεσβυτεροι των ιουδαιων αιτουμενοι κατ αυτου δικην'),
(4668, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 16, 'NT', 'προς ους απεκριθην οτι ουκ εστιν εθος ρωμαιοις χαριζεσθαι τινα ανθρωπον εις απωλειαν πριν η ο κατηγορουμενος κατα προσωπον εχοι τους κατηγορους τοπον τε απολογιας λαβοι περι του εγκληματος'),
(4669, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 17, 'NT', 'συνελθοντων ουν αυτων ενθαδε αναβολην μηδεμιαν ποιησαμενος τη εξης καθισας επι του βηματος εκελευσα αχθηναι τον ανδρα'),
(4670, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 18, 'NT', 'περι ου σταθεντες οι κατηγοροι ουδεμιαν αιτιαν επεφερον ων υπενοουν εγω'),
(4671, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 19, 'NT', 'ζητηματα δε τινα περι της ιδιας δεισιδαιμονιας ειχον προς αυτον και περι τινος ιησου τεθνηκοτος ον εφασκεν ο παυλος ζην'),
(4672, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 20, 'NT', 'απορουμενος δε εγω εις την περι τουτου ζητησιν ελεγον ει βουλοιτο πορευεσθαι εις ιερουσαλημ κακει κρινεσθαι περι τουτων'),
(4673, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 21, 'NT', 'του δε παυλου επικαλεσαμενου τηρηθηναι αυτον εις την του σεβαστου διαγνωσιν εκελευσα τηρεισθαι αυτον εως ου πεμψω αυτον προς καισαρα'),
(4674, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 22, 'NT', 'αγριππας δε προς τον φηστον εφη εβουλομην και αυτος του ανθρωπου ακουσαι ο δε αυριον φησιν ακουση αυτου'),
(4675, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 23, 'NT', 'τη ουν επαυριον ελθοντος του αγριππα και της βερνικης μετα πολλης φαντασιας και εισελθοντων εις το ακροατηριον συν τε τοις χιλιαρχοις και ανδρασιν τοις κατ εξοχην ουσιν της πολεως και κελευσαντος του φηστου ηχθη ο παυλος'),
(4676, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 24, 'NT', 'και φησιν ο φηστος αγριππα βασιλευ και παντες οι συμπαροντες ημιν ανδρες θεωρειτε τουτον περι ου παν το πληθος των ιουδαιων ενετυχον μοι εν τε ιεροσολυμοις και ενθαδε επιβοωντες μη δειν ζην αυτον μηκετι'),
(4677, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 25, 'NT', 'εγω δε καταλαβομενος μηδεν αξιον θανατου αυτον πεπραχεναι και αυτου δε τουτου επικαλεσαμενου τον σεβαστον εκρινα πεμπειν αυτον'),
(4678, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 26, 'NT', 'περι ου ασφαλες τι γραψαι τω κυριω ουκ εχω διο προηγαγον αυτον εφ υμων και μαλιστα επι σου βασιλευ αγριππα οπως της ανακρισεως γενομενης σχω τι γραψαι'),
(4679, 44, 'TR1550', 'TR1550', 'el', 'ACT', 25, 27, 'NT', 'αλογον γαρ μοι δοκει πεμποντα δεσμιον μη και τας κατ αυτου αιτιας σημαναι'),
(4680, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 1, 'NT', 'αγριππας δε προς τον παυλον εφη επιτρεπεται σοι υπερ σεαυτου λεγειν τοτε ο παυλος απελογειτο εκτεινας την χειρα'),
(4681, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 2, 'NT', 'περι παντων ων εγκαλουμαι υπο ιουδαιων βασιλευ αγριππα ηγημαι εμαυτον μακαριον μελλων απολογεισθαι επι σου σημερον'),
(4682, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 3, 'NT', 'μαλιστα γνωστην οντα σε παντων των κατα ιουδαιους εθων τε και ζητηματων διο δεομαι σου μακροθυμως ακουσαι μου'),
(4683, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 4, 'NT', 'την μεν ουν βιωσιν μου την εκ νεοτητος την απ αρχης γενομενην εν τω εθνει μου εν ιεροσολυμοις ισασιν παντες οι ιουδαιοι'),
(4684, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 5, 'NT', 'προγινωσκοντες με ανωθεν εαν θελωσιν μαρτυρειν οτι κατα την ακριβεστατην αιρεσιν της ημετερας θρησκειας εζησα φαρισαιος'),
(4685, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 6, 'NT', 'και νυν επ ελπιδι της προς τους πατερας επαγγελιας γενομενης υπο του θεου εστηκα κρινομενος'),
(4686, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 7, 'NT', 'εις ην το δωδεκαφυλον ημων εν εκτενεια νυκτα και ημεραν λατρευον ελπιζει καταντησαι περι ης ελπιδος εγκαλουμαι βασιλευ αγριππα υπο των ιουδαιων'),
(4687, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 8, 'NT', 'τι απιστον κρινεται παρ υμιν ει ο θεος νεκρους εγειρει'),
