(4689, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 10, 'NT', 'ο και εποιησα εν ιεροσολυμοις και πολλους των αγιων εγω φυλακαις κατεκλεισα την παρα των αρχιερεων εξουσιαν λαβων αναιρουμενων τε αυτων κατηνεγκα ψηφον'),
(4690, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 11, 'NT', 'και κατα πασας τας συναγωγας πολλακις τιμωρων αυτους ηναγκαζον βλασφημειν περισσως τε εμμαινομενος αυτοις εδιωκον εως και εις τας εξω πολεις'),
(4691, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 12, 'NT', 'εν οις και πορευομενος εις την δαμασκον μετ εξουσιας και επιτροπης της παρα των αρχιερεων'),
(4692, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 13, 'NT', 'ημερας μεσης κατα την οδον ειδον βασιλευ ουρανοθεν υπερ την λαμπροτητα του ηλιου περιλαμψαν με φως και τους συν εμοι πορευομενους'),
(4693, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 14, 'NT', 'παντων δε καταπεσοντων ημων εις την γην ηκουσα φωνην λαλουσαν προς με και λεγουσαν τη εβραιδι διαλεκτω σαουλ σαουλ τι με διωκεις σκληρον σοι προς κεντρα λακτιζειν'),
(4694, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 15, 'NT', 'εγω δε ειπον τις ει κυριε ο δε ειπεν εγω ειμι ιησους ον συ διωκεις'),
(4695, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 16, 'NT', 'αλλα αναστηθι και στηθι επι τους ποδας σου εις τουτο γαρ ωφθην σοι προχειρισασθαι σε υπηρετην και μαρτυρα ων τε ειδες ων τε οφθησομαι σοι'),
(4696, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 17, 'NT', 'εξαιρουμενος σε εκ του λαου και των εθνων εις ους νυν σε αποστελλω'),
(4697, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 18, 'NT', 'ανοιξαι οφθαλμους αυτων του επιστρεψαι απο σκοτους εις φως και της εξουσιας του σατανα επι τον θεον του λαβειν αυτους αφεσιν αμαρτιων και κληρον εν τοις ηγιασμενοις πιστει τη εις εμε'),
(4698, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 19, 'NT', 'οθεν βασιλευ αγριππα ουκ εγενομην απειθης τη ουρανιω οπτασια'),
(4699, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 20, 'NT', 'αλλα τοις εν δαμασκω πρωτον και ιεροσολυμοις εις πασαν τε την χωραν της ιουδαιας και τοις εθνεσιν απαγγελλων μετανοειν και επιστρεφειν επι τον θεον αξια της μετανοιας εργα πρασσοντας'),
(4700, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 21, 'NT', 'ενεκα τουτων με οι ιουδαιοι συλλαβομενοι εν τω ιερω επειρωντο διαχειρισασθαι'),
(4701, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 22, 'NT', 'επικουριας ουν τυχων της παρα του θεου αχρι της ημερας ταυτης εστηκα μαρτυρουμενος μικρω τε και μεγαλω ουδεν εκτος λεγων ων τε οι προφηται ελαλησαν μελλοντων γινεσθαι και μωσης'),
(4702, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 23, 'NT', 'ει παθητος ο χριστος ει πρωτος εξ αναστασεως νεκρων φως μελλει καταγγελλειν τω λαω και τοις εθνεσιν'),
(4703, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 24, 'NT', 'ταυτα δε αυτου απολογουμενου ο φηστος μεγαλη τη φωνη εφη μαινη παυλε τα πολλα σε γραμματα εις μανιαν περιτρεπει'),
(4704, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 25, 'NT', 'ο δε ου μαινομαι φησιν κρατιστε φηστε αλλ αληθειας και σωφροσυνης ρηματα αποφθεγγομαι'),
(4705, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 26, 'NT', 'επισταται γαρ περι τουτων ο βασιλευς προς ον και παρρησιαζομενος λαλω λανθανειν γαρ αυτον τι τουτων ου πειθομαι ουδεν ου γαρ εστιν εν γωνια πεπραγμενον τουτο'),
(4706, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 27, 'NT', 'πιστευεις βασιλευ αγριππα τοις προφηταις οιδα οτι πιστευεις'),
(4707, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 28, 'NT', 'ο δε αγριππας προς τον παυλον εφη εν ολιγω με πειθεις χριστιανον γενεσθαι'),
