(4709, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 30, 'NT', 'και ταυτα ειποντος αυτου ανεστη ο βασιλευς και ο ηγεμων η τε βερνικη και οι συγκαθημενοι αυτοις'),
(4710, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 31, 'NT', 'και αναχωρησαντες ελαλουν προς αλληλους λεγοντες οτι ουδεν θανατου αξιον η δεσμων πρασσει ο ανθρωπος ουτος'),
(4711, 44, 'TR1550', 'TR1550', 'el', 'ACT', 26, 32, 'NT', 'αγριππας δε τω φηστω εφη απολελυσθαι εδυνατο ο ανθρωπος ουτος ει μη επεκεκλητο καισαρα'),
(4712, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 1, 'NT', 'ως δε εκριθη του αποπλειν ημας εις την ιταλιαν παρεδιδουν τον τε παυλον και τινας ετερους δεσμωτας εκατονταρχη ονοματι ιουλιω σπειρης σεβαστης'),
(4713, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 2, 'NT', 'επιβαντες δε πλοιω αδραμυττηνω μελλοντες πλειν τους κατα την ασιαν τοπους ανηχθημεν οντος συν ημιν αρισταρχου μακεδονος θεσσαλονικεως'),
(4714, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 3, 'NT', 'τη τε ετερα κατηχθημεν εις σιδωνα φιλανθρωπως τε ο ιουλιος τω παυλω χρησαμενος επετρεψεν προς φιλους πορευθεντα επιμελειας τυχειν'),
(4715, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 4, 'NT', 'κακειθεν αναχθεντες υπεπλευσαμεν την κυπρον δια το τους ανεμους ειναι εναντιους'),
(4716, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 5, 'NT', 'το τε πελαγος το κατα την κιλικιαν και παμφυλιαν διαπλευσαντες κατηλθομεν εις μυρα της λυκιας'),
