(4718, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 7, 'NT', 'εν ικαναις δε ημεραις βραδυπλοουντες και μολις γενομενοι κατα την κνιδον μη προσεωντος ημας του ανεμου υπεπλευσαμεν την κρητην κατα σαλμωνην'),
(4719, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 8, 'NT', 'μολις τε παραλεγομενοι αυτην ηλθομεν εις τοπον τινα καλουμενον καλους λιμενας ω εγγυς ην πολις λασαια'),
(4720, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 9, 'NT', 'ικανου δε χρονου διαγενομενου και οντος ηδη επισφαλους του πλοος δια το και την νηστειαν ηδη παρεληλυθεναι παρηνει ο παυλος'),
(4721, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 10, 'NT', 'λεγων αυτοις ανδρες θεωρω οτι μετα υβρεως και πολλης ζημιας ου μονον του φορτου και του πλοιου αλλα και των ψυχων ημων μελλειν εσεσθαι τον πλουν'),
(4722, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 11, 'NT', 'ο δε εκατονταρχος τω κυβερνητη και τω ναυκληρω επειθετο μαλλον η τοις υπο του παυλου λεγομενοις'),
(4723, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 12, 'NT', 'ανευθετου δε του λιμενος υπαρχοντος προς παραχειμασιαν οι πλειους εθεντο βουλην αναχθηναι κακειθεν ειπως δυναιντο καταντησαντες εις φοινικα παραχειμασαι λιμενα της κρητης βλεποντα κατα λιβα και κατα χωρον'),
(4724, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 13, 'NT', 'υποπνευσαντος δε νοτου δοξαντες της προθεσεως κεκρατηκεναι αραντες ασσον παρελεγοντο την κρητην'),
