(4735, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 24, 'NT', 'λεγων μη φοβου παυλε καισαρι σε δει παραστηναι και ιδου κεχαρισται σοι ο θεος παντας τους πλεοντας μετα σου'),
(4736, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 25, 'NT', 'διο ευθυμειτε ανδρες πιστευω γαρ τω θεω οτι ουτως εσται καθ ον τροπον λελαληται μοι'),
(4737, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 26, 'NT', 'εις νησον δε τινα δει ημας εκπεσειν'),
(4738, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 27, 'NT', 'ως δε τεσσαρεσκαιδεκατη νυξ εγενετο διαφερομενων ημων εν τω αδρια κατα μεσον της νυκτος υπενοουν οι ναυται προσαγειν τινα αυτοις χωραν'),
(4739, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 28, 'NT', 'και βολισαντες ευρον οργυιας εικοσι βραχυ δε διαστησαντες και παλιν βολισαντες ευρον οργυιας δεκαπεντε'),
(4740, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 29, 'NT', 'φοβουμενοι τε μηπως εις τραχεις τοπους εκπεσωσιν εκ πρυμνης ριψαντες αγκυρας τεσσαρας ηυχοντο ημεραν γενεσθαι'),
(4741, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 30, 'NT', 'των δε ναυτων ζητουντων φυγειν εκ του πλοιου και χαλασαντων την σκαφην εις την θαλασσαν προφασει ως εκ πρωρας μελλοντων αγκυρας εκτεινειν'),
(4742, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 31, 'NT', 'ειπεν ο παυλος τω εκατονταρχη και τοις στρατιωταις εαν μη ουτοι μεινωσιν εν τω πλοιω υμεις σωθηναι ου δυνασθε'),
(4743, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 32, 'NT', 'τοτε οι στρατιωται απεκοψαν τα σχοινια της σκαφης και ειασαν αυτην εκπεσειν'),
(4744, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 33, 'NT', 'αχρι δε ου εμελλεν ημερα γινεσθαι παρεκαλει ο παυλος απαντας μεταλαβειν τροφης λεγων τεσσαρεσκαιδεκατην σημερον ημεραν προσδοκωντες ασιτοι διατελειτε μηδεν προσλαβομενοι'),
(4745, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 34, 'NT', 'διο παρακαλω υμας προσλαβειν τροφης τουτο γαρ προς της υμετερας σωτηριας υπαρχει ουδενος γαρ υμων θριξ εκ της κεφαλης πεσειται'),
(4746, 44, 'TR1550', 'TR1550', 'el', 'ACT', 27, 35, 'NT', 'ειπων δε ταυτα και λαβων αρτον ευχαριστησεν τω θεω ενωπιον παντων και κλασας ηρξατο εσθιειν'),
