(5197, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 5, 'NT', 'και την κατ οικον αυτων εκκλησιαν ασπασασθε επαινετον τον αγαπητον μου ος εστιν απαρχη της αχαιας εις χριστον'),
(5198, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 6, 'NT', 'ασπασασθε μαριαμ ητις πολλα εκοπιασεν εις ημας'),
(5199, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 7, 'NT', 'ασπασασθε ανδρονικον και ιουνιαν τους συγγενεις μου και συναιχμαλωτους μου οιτινες εισιν επισημοι εν τοις αποστολοις οι και προ εμου γεγονασιν εν χριστω'),
(5200, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 8, 'NT', 'ασπασασθε αμπλιαν τον αγαπητον μου εν κυριω'),
(5201, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 9, 'NT', 'ασπασασθε ουρβανον τον συνεργον ημων εν χριστω και σταχυν τον αγαπητον μου'),
(5202, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 10, 'NT', 'ασπασασθε απελλην τον δοκιμον εν χριστω ασπασασθε τους εκ των αριστοβουλου'),
(5203, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 11, 'NT', 'ασπασασθε ηροδιωνα τον συγγενη μου ασπασασθε τους εκ των ναρκισσου τους οντας εν κυριω'),
(5204, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 12, 'NT', 'ασπασασθε τρυφαιναν και τρυφωσαν τας κοπιωσας εν κυριω ασπασασθε περσιδα την αγαπητην ητις πολλα εκοπιασεν εν κυριω'),
(5205, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 13, 'NT', 'ασπασασθε ρουφον τον εκλεκτον εν κυριω και την μητερα αυτου και εμου'),
(5206, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 14, 'NT', 'ασπασασθε ασυγκριτον φλεγοντα ερμαν πατροβαν ερμην και τους συν αυτοις αδελφους'),
(5207, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 15, 'NT', 'ασπασασθε φιλολογον και ιουλιαν νηρεα και την αδελφην αυτου και ολυμπαν και τους συν αυτοις παντας αγιους'),
(5208, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 16, 'NT', 'ασπασασθε αλληλους εν φιληματι αγιω ασπαζονται υμας αι εκκλησιαι του χριστου'),
(5209, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 17, 'NT', 'παρακαλω δε υμας αδελφοι σκοπειν τους τας διχοστασιας και τα σκανδαλα παρα την διδαχην ην υμεις εμαθετε ποιουντας και εκκλινατε απ αυτων'),
(5210, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 18, 'NT', 'οι γαρ τοιουτοι τω κυριω ημων ιησου χριστω ου δουλευουσιν αλλα τη εαυτων κοιλια και δια της χρηστολογιας και ευλογιας εξαπατωσιν τας καρδιας των ακακων'),
(5211, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 19, 'NT', 'η γαρ υμων υπακοη εις παντας αφικετο χαιρω ουν το εφ υμιν θελω δε υμας σοφους μεν ειναι εις το αγαθον ακεραιους δε εις το κακον'),
(5212, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 20, 'NT', 'ο δε θεος της ειρηνης συντριψει τον σαταναν υπο τους ποδας υμων εν ταχει η χαρις του κυριου ημων ιησου χριστου μεθ υμων'),
(5213, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 21, 'NT', 'ασπαζονται υμας τιμοθεος ο συνεργος μου και λουκιος και ιασων και σωσιπατρος οι συγγενεις μου'),
(5214, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 22, 'NT', 'ασπαζομαι υμας εγω τερτιος ο γραψας την επιστολην εν κυριω'),
(5215, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 23, 'NT', 'ασπαζεται υμας γαιος ο ξενος μου και της εκκλησιας ολης ασπαζεται υμας εραστος ο οικονομος της πολεως και κουαρτος ο αδελφος'),
(5216, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 24, 'NT', 'η χαρις του κυριου ημων ιησου χριστου μετα παντων υμων αμην'),
(5217, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 25, 'NT', 'τω δε δυναμενω υμας στηριξαι κατα το ευαγγελιον μου και το κηρυγμα ιησου χριστου κατα αποκαλυψιν μυστηριου χρονοις αιωνιοις σεσιγημενου'),
(5218, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 26, 'NT', 'φανερωθεντος δε νυν δια τε γραφων προφητικων κατ επιταγην του αιωνιου θεου εις υπακοην πιστεως εις παντα τα εθνη γνωρισθεντος'),
(5219, 45, 'TR1550', 'TR1550', 'el', 'ROM', 16, 27, 'NT', 'μονω σοφω θεω δια ιησου χριστου ω η δοξα εις τους αιωνας αμην [προς ρωμαιους εγραφη απο κορινθου δια φοιβης της διακονου της εν κεγχρεαις εκκλησιας]'),
(5220, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 1, 'NT', 'παυλος κλητος αποστολος ιησου χριστου δια θεληματος θεου και σωσθενης ο αδελφος'),
(5221, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 2, 'NT', 'τη εκκλησια του θεου τη ουση εν κορινθω ηγιασμενοις εν χριστω ιησου κλητοις αγιοις συν πασιν τοις επικαλουμενοις το ονομα του κυριου ημων ιησου χριστου εν παντι τοπω αυτων τε και ημων'),
(5222, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 3, 'NT', 'χαρις υμιν και ειρηνη απο θεου πατρος ημων και κυριου ιησου χριστου'),
(5223, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 4, 'NT', 'ευχαριστω τω θεω μου παντοτε περι υμων επι τη χαριτι του θεου τη δοθειση υμιν εν χριστω ιησου'),
(5224, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 5, 'NT', 'οτι εν παντι επλουτισθητε εν αυτω εν παντι λογω και παση γνωσει'),
(5225, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 6, 'NT', 'καθως το μαρτυριον του χριστου εβεβαιωθη εν υμιν'),
(5226, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 7, 'NT', 'ωστε υμας μη υστερεισθαι εν μηδενι χαρισματι απεκδεχομενους την αποκαλυψιν του κυριου ημων ιησου χριστου'),
(5227, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 8, 'NT', 'ος και βεβαιωσει υμας εως τελους ανεγκλητους εν τη ημερα του κυριου ημων ιησου χριστου'),
(5228, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 9, 'NT', 'πιστος ο θεος δι ου εκληθητε εις κοινωνιαν του υιου αυτου ιησου χριστου του κυριου ημων'),
(5229, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 10, 'NT', 'παρακαλω δε υμας αδελφοι δια του ονοματος του κυριου ημων ιησου χριστου ινα το αυτο λεγητε παντες και μη η εν υμιν σχισματα ητε δε κατηρτισμενοι εν τω αυτω νοι και εν τη αυτη γνωμη'),
(5230, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 11, 'NT', 'εδηλωθη γαρ μοι περι υμων αδελφοι μου υπο των χλοης οτι εριδες εν υμιν εισιν'),
(5231, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 12, 'NT', 'λεγω δε τουτο οτι εκαστος υμων λεγει εγω μεν ειμι παυλου εγω δε απολλω εγω δε κηφα εγω δε χριστου'),
(5232, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 13, 'NT', 'μεμερισται ο χριστος μη παυλος εσταυρωθη υπερ υμων η εις το ονομα παυλου εβαπτισθητε'),
(5233, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 14, 'NT', 'ευχαριστω τω θεω οτι ουδενα υμων εβαπτισα ει μη κρισπον και γαιον'),
(5234, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 15, 'NT', 'ινα μη τις ειπη οτι εις το εμον ονομα εβαπτισα'),
(5235, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 16, 'NT', 'εβαπτισα δε και τον στεφανα οικον λοιπον ουκ οιδα ει τινα αλλον εβαπτισα'),
(5236, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 17, 'NT', 'ου γαρ απεστειλεν με χριστος βαπτιζειν αλλ ευαγγελιζεσθαι ουκ εν σοφια λογου ινα μη κενωθη ο σταυρος του χριστου'),
(5237, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 18, 'NT', 'ο λογος γαρ ο του σταυρου τοις μεν απολλυμενοις μωρια εστιν τοις δε σωζομενοις ημιν δυναμις θεου εστιν'),
(5238, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 19, 'NT', 'γεγραπται γαρ απολω την σοφιαν των σοφων και την συνεσιν των συνετων αθετησω'),
(5239, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 20, 'NT', 'που σοφος που γραμματευς που συζητητης του αιωνος τουτου ουχι εμωρανεν ο θεος την σοφιαν του κοσμου τουτου'),
(5240, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 21, 'NT', 'επειδη γαρ εν τη σοφια του θεου ουκ εγνω ο κοσμος δια της σοφιας τον θεον ευδοκησεν ο θεος δια της μωριας του κηρυγματος σωσαι τους πιστευοντας'),
(5241, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 22, 'NT', 'επειδη και ιουδαιοι σημειον αιτουσιν και ελληνες σοφιαν ζητουσιν'),
(5242, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 23, 'NT', 'ημεις δε κηρυσσομεν χριστον εσταυρωμενον ιουδαιοις μεν σκανδαλον ελλησιν δε μωριαν'),
(5243, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 24, 'NT', 'αυτοις δε τοις κλητοις ιουδαιοις τε και ελλησιν χριστον θεου δυναμιν και θεου σοφιαν'),
(5244, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 25, 'NT', 'οτι το μωρον του θεου σοφωτερον των ανθρωπων εστιν και το ασθενες του θεου ισχυροτερον των ανθρωπων εστιν'),
(5245, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 26, 'NT', 'βλεπετε γαρ την κλησιν υμων αδελφοι οτι ου πολλοι σοφοι κατα σαρκα ου πολλοι δυνατοι ου πολλοι ευγενεις'),
(5246, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 27, 'NT', 'αλλα τα μωρα του κοσμου εξελεξατο ο θεος ινα τους σοφους καταισχυνη και τα ασθενη του κοσμου εξελεξατο ο θεος ινα καταισχυνη τα ισχυρα'),
(5247, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 28, 'NT', 'και τα αγενη του κοσμου και τα εξουθενημενα εξελεξατο ο θεος και τα μη οντα ινα τα οντα καταργηση'),
(5248, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 29, 'NT', 'οπως μη καυχησηται πασα σαρξ ενωπιον αυτου'),
(5249, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 30, 'NT', 'εξ αυτου δε υμεις εστε εν χριστω ιησου ος εγενηθη ημιν σοφια απο θεου δικαιοσυνη τε και αγιασμος και απολυτρωσις'),
(5250, 46, 'TR1550', 'TR1550', 'el', '1CO', 1, 31, 'NT', 'ινα καθως γεγραπται ο καυχωμενος εν κυριω καυχασθω'),
(5251, 46, 'TR1550', 'TR1550', 'el', '1CO', 2, 1, 'NT', 'καγω ελθων προς υμας αδελφοι ηλθον ου καθ υπεροχην λογου η σοφιας καταγγελλων υμιν το μαρτυριον του θεου'),
(5252, 46, 'TR1550', 'TR1550', 'el', '1CO', 2, 2, 'NT', 'ου γαρ εκρινα του ειδεναι τι εν υμιν ει μη ιησουν χριστον και τουτον εσταυρωμενον'),
(5253, 46, 'TR1550', 'TR1550', 'el', '1CO', 2, 3, 'NT', 'και εγω εν ασθενεια και εν φοβω και εν τρομω πολλω εγενομην προς υμας'),
(5254, 46, 'TR1550', 'TR1550', 'el', '1CO', 2, 4, 'NT', 'και ο λογος μου και το κηρυγμα μου ουκ εν πειθοις ανθρωπινης σοφιας λογοις αλλ εν αποδειξει πνευματος και δυναμεως'),
(5255, 46, 'TR1550', 'TR1550', 'el', '1CO', 2, 5, 'NT', 'ινα η πιστις υμων μη η εν σοφια ανθρωπων αλλ εν δυναμει θεου'),
(5256, 46, 'TR1550', 'TR1550', 'el', '1CO', 2, 6, 'NT', 'σοφιαν δε λαλουμεν εν τοις τελειοις σοφιαν δε ου του αιωνος τουτου ουδε των αρχοντων του αιωνος τουτου των καταργουμενων'),
(5257, 46, 'TR1550', 'TR1550', 'el', '1CO', 2, 7, 'NT', 'αλλα λαλουμεν σοφιαν θεου εν μυστηριω την αποκεκρυμμενην ην προωρισεν ο θεος προ των αιωνων εις δοξαν ημων'),
(5258, 46, 'TR1550', 'TR1550', 'el', '1CO', 2, 8, 'NT', 'ην ουδεις των αρχοντων του αιωνος τουτου εγνωκεν ει γαρ εγνωσαν ουκ αν τον κυριον της δοξης εσταυρωσαν'),
(5259, 46, 'TR1550', 'TR1550', 'el', '1CO', 2, 9, 'NT', 'αλλα καθως γεγραπται α οφθαλμος ουκ ειδεν και ους ουκ ηκουσεν και επι καρδιαν ανθρωπου ουκ ανεβη α ητοιμασεν ο θεος τοις αγαπωσιν αυτον'),
(5260, 46, 'TR1550', 'TR1550', 'el', '1CO', 2, 10, 'NT', 'ημιν δε ο θεος απεκαλυψεν δια του πνευματος αυτου το γαρ πνευμα παντα ερευνα και τα βαθη του θεου'),
(5261, 46, 'TR1550', 'TR1550', 'el', '1CO', 2, 11, 'NT', 'τις γαρ οιδεν ανθρωπων τα του ανθρωπου ει μη το πνευμα του ανθρωπου το εν αυτω ουτως και τα του θεου ουδεις οιδεν ει μη το πνευμα του θεου'),
(5262, 46, 'TR1550', 'TR1550', 'el', '1CO', 2, 12, 'NT', 'ημεις δε ου το πνευμα του κοσμου ελαβομεν αλλα το πνευμα το εκ του θεου ινα ειδωμεν τα υπο του θεου χαρισθεντα ημιν'),
(5263, 46, 'TR1550', 'TR1550', 'el', '1CO', 2, 13, 'NT', 'α και λαλουμεν ουκ εν διδακτοις ανθρωπινης σοφιας λογοις αλλ εν διδακτοις πνευματος αγιου πνευματικοις πνευματικα συγκρινοντες'),
(5264, 46, 'TR1550', 'TR1550', 'el', '1CO', 2, 14, 'NT', 'ψυχικος δε ανθρωπος ου δεχεται τα του πνευματος του θεου μωρια γαρ αυτω εστιν και ου δυναται γνωναι οτι πνευματικως ανακρινεται'),
(5265, 46, 'TR1550', 'TR1550', 'el', '1CO', 2, 15, 'NT', 'ο δε πνευματικος ανακρινει μεν παντα αυτος δε υπ ουδενος ανακρινεται'),
(5266, 46, 'TR1550', 'TR1550', 'el', '1CO', 2, 16, 'NT', 'τις γαρ εγνω νουν κυριου ος συμβιβασει αυτον ημεις δε νουν χριστου εχομεν'),
(5267, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 1, 'NT', 'και εγω αδελφοι ουκ ηδυνηθην λαλησαι υμιν ως πνευματικοις αλλ ως σαρκικοις ως νηπιοις εν χριστω'),
(5268, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 2, 'NT', 'γαλα υμας εποτισα και ου βρωμα ουπω γαρ ηδυνασθε αλλ ουτε ετι νυν δυνασθε'),
(5269, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 3, 'NT', 'ετι γαρ σαρκικοι εστε οπου γαρ εν υμιν ζηλος και ερις και διχοστασιαι ουχι σαρκικοι εστε και κατα ανθρωπον περιπατειτε'),
(5270, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 4, 'NT', 'οταν γαρ λεγη τις εγω μεν ειμι παυλου ετερος δε εγω απολλω ουχι σαρκικοι εστε'),
(5271, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 5, 'NT', 'τις ουν εστιν παυλος τις δε απολλως αλλ η διακονοι δι ων επιστευσατε και εκαστω ως ο κυριος εδωκεν'),
(5272, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 6, 'NT', 'εγω εφυτευσα απολλως εποτισεν αλλ ο θεος ηυξανεν'),
(5273, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 7, 'NT', 'ωστε ουτε ο φυτευων εστιν τι ουτε ο ποτιζων αλλ ο αυξανων θεος'),
(5274, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 8, 'NT', 'ο φυτευων δε και ο ποτιζων εν εισιν εκαστος δε τον ιδιον μισθον ληψεται κατα τον ιδιον κοπον'),
(5275, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 9, 'NT', 'θεου γαρ εσμεν συνεργοι θεου γεωργιον θεου οικοδομη εστε'),
(5276, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 10, 'NT', 'κατα την χαριν του θεου την δοθεισαν μοι ως σοφος αρχιτεκτων θεμελιον τεθεικα αλλος δε εποικοδομει εκαστος δε βλεπετω πως εποικοδομει'),
(5277, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 11, 'NT', 'θεμελιον γαρ αλλον ουδεις δυναται θειναι παρα τον κειμενον ος εστιν ιησους ο χριστος'),
(5278, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 12, 'NT', 'ει δε τις εποικοδομει επι τον θεμελιον τουτον χρυσον αργυρον λιθους τιμιους ξυλα χορτον καλαμην'),
(5279, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 13, 'NT', 'εκαστου το εργον φανερον γενησεται η γαρ ημερα δηλωσει οτι εν πυρι αποκαλυπτεται και εκαστου το εργον οποιον εστιν το πυρ δοκιμασει'),
(5280, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 14, 'NT', 'ει τινος το εργον μενει ο επωκοδομησεν μισθον ληψεται'),
(5281, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 15, 'NT', 'ει τινος το εργον κατακαησεται ζημιωθησεται αυτος δε σωθησεται ουτως δε ως δια πυρος'),
(5282, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 16, 'NT', 'ουκ οιδατε οτι ναος θεου εστε και το πνευμα του θεου οικει εν υμιν'),
(5283, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 17, 'NT', 'ει τις τον ναον του θεου φθειρει φθερει τουτον ο θεος ο γαρ ναος του θεου αγιος εστιν οιτινες εστε υμεις'),
(5284, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 18, 'NT', 'μηδεις εαυτον εξαπατατω ει τις δοκει σοφος ειναι εν υμιν εν τω αιωνι τουτω μωρος γενεσθω ινα γενηται σοφος'),
(5285, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 19, 'NT', 'η γαρ σοφια του κοσμου τουτου μωρια παρα τω θεω εστιν γεγραπται γαρ ο δρασσομενος τους σοφους εν τη πανουργια αυτων'),
(5286, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 20, 'NT', 'και παλιν κυριος γινωσκει τους διαλογισμους των σοφων οτι εισιν ματαιοι'),
(5287, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 21, 'NT', 'ωστε μηδεις καυχασθω εν ανθρωποις παντα γαρ υμων εστιν'),
(5288, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 22, 'NT', 'ειτε παυλος ειτε απολλως ειτε κηφας ειτε κοσμος ειτε ζωη ειτε θανατος ειτε ενεστωτα ειτε μελλοντα παντα υμων εστιν'),
(5289, 46, 'TR1550', 'TR1550', 'el', '1CO', 3, 23, 'NT', 'υμεις δε χριστου χριστος δε θεου'),
(5290, 46, 'TR1550', 'TR1550', 'el', '1CO', 4, 1, 'NT', 'ουτως ημας λογιζεσθω ανθρωπος ως υπηρετας χριστου και οικονομους μυστηριων θεου'),
(5291, 46, 'TR1550', 'TR1550', 'el', '1CO', 4, 2, 'NT', 'ο δε λοιπον ζητειται εν τοις οικονομοις ινα πιστος τις ευρεθη'),
(5292, 46, 'TR1550', 'TR1550', 'el', '1CO', 4, 3, 'NT', 'εμοι δε εις ελαχιστον εστιν ινα υφ υμων ανακριθω η υπο ανθρωπινης ημερας αλλ ουδε εμαυτον ανακρινω'),
(5293, 46, 'TR1550', 'TR1550', 'el', '1CO', 4, 4, 'NT', 'ουδεν γαρ εμαυτω συνοιδα αλλ ουκ εν τουτω δεδικαιωμαι ο δε ανακρινων με κυριος εστιν'),
(5294, 46, 'TR1550', 'TR1550', 'el', '1CO', 4, 5, 'NT', 'ωστε μη προ καιρου τι κρινετε εως αν ελθη ο κυριος ος και φωτισει τα κρυπτα του σκοτους και φανερωσει τας βουλας των καρδιων και τοτε ο επαινος γενησεται εκαστω απο του θεου'),
(5295, 46, 'TR1550', 'TR1550', 'el', '1CO', 4, 6, 'NT', 'ταυτα δε αδελφοι μετεσχηματισα εις εμαυτον και απολλω δι υμας ινα εν ημιν μαθητε το μη υπερ ο γεγραπται φρονειν ινα μη εις υπερ του ενος φυσιουσθε κατα του ετερου'),
(5296, 46, 'TR1550', 'TR1550', 'el', '1CO', 4, 7, 'NT', 'τις γαρ σε διακρινει τι δε εχεις ο ουκ ελαβες ει δε και ελαβες τι καυχασαι ως μη λαβων'),
(5297, 46, 'TR1550', 'TR1550', 'el', '1CO', 4, 8, 'NT', 'ηδη κεκορεσμενοι εστε ηδη επλουτησατε χωρις ημων εβασιλευσατε και οφελον γε εβασιλευσατε ινα και ημεις υμιν συμβασιλευσωμεν'),
(5298, 46, 'TR1550', 'TR1550', 'el', '1CO', 4, 9, 'NT', 'δοκω γαρ οτι ο θεος ημας τους αποστολους εσχατους απεδειξεν ως επιθανατιους οτι θεατρον εγενηθημεν τω κοσμω και αγγελοις και ανθρωποις'),
(5299, 46, 'TR1550', 'TR1550', 'el', '1CO', 4, 10, 'NT', 'ημεις μωροι δια χριστον υμεις δε φρονιμοι εν χριστω ημεις ασθενεις υμεις δε ισχυροι υμεις ενδοξοι ημεις δε ατιμοι'),
(5300, 46, 'TR1550', 'TR1550', 'el', '1CO', 4, 11, 'NT', 'αχρι της αρτι ωρας και πεινωμεν και διψωμεν και γυμνητευομεν και κολαφιζομεθα και αστατουμεν'),
(5301, 46, 'TR1550', 'TR1550', 'el', '1CO', 4, 12, 'NT', 'και κοπιωμεν εργαζομενοι ταις ιδιαις χερσιν λοιδορουμενοι ευλογουμεν διωκομενοι ανεχομεθα'),
(5302, 46, 'TR1550', 'TR1550', 'el', '1CO', 4, 13, 'NT', 'βλασφημουμενοι παρακαλουμεν ως περικαθαρματα του κοσμου εγενηθημεν παντων περιψημα εως αρτι'),
(5303, 46, 'TR1550', 'TR1550', 'el', '1CO', 4, 14, 'NT', 'ουκ εντρεπων υμας γραφω ταυτα αλλ ως τεκνα μου αγαπητα νουθετω'),
(5304, 46, 'TR1550', 'TR1550', 'el', '1CO', 4, 15, 'NT', 'εαν γαρ μυριους παιδαγωγους εχητε εν χριστω αλλ ου πολλους πατερας εν γαρ χριστω ιησου δια του ευαγγελιου εγω υμας εγεννησα'),
(5305, 46, 'TR1550', 'TR1550', 'el', '1CO', 4, 16, 'NT', 'παρακαλω ουν υμας μιμηται μου γινεσθε'),
(5306, 46, 'TR1550', 'TR1550', 'el', '1CO', 4, 17, 'NT', 'δια τουτο επεμψα υμιν τιμοθεον ος εστιν τεκνον μου αγαπητον και πιστον εν κυριω ος υμας αναμνησει τας οδους μου τας εν χριστω καθως πανταχου εν παση εκκλησια διδασκω'),
(5307, 46, 'TR1550', 'TR1550', 'el', '1CO', 4, 18, 'NT', 'ως μη ερχομενου δε μου προς υμας εφυσιωθησαν τινες'),
(5308, 46, 'TR1550', 'TR1550', 'el', '1CO', 4, 19, 'NT', 'ελευσομαι δε ταχεως προς υμας εαν ο κυριος θεληση και γνωσομαι ου τον λογον των πεφυσιωμενων αλλα την δυναμιν'),
(5309, 46, 'TR1550', 'TR1550', 'el', '1CO', 4, 20, 'NT', 'ου γαρ εν λογω η βασιλεια του θεου αλλ εν δυναμει'),
(5310, 46, 'TR1550', 'TR1550', 'el', '1CO', 4, 21, 'NT', 'τι θελετε εν ραβδω ελθω προς υμας η εν αγαπη πνευματι τε πραοτητος'),
(5311, 46, 'TR1550', 'TR1550', 'el', '1CO', 5, 1, 'NT', 'ολως ακουεται εν υμιν πορνεια και τοιαυτη πορνεια ητις ουδε εν τοις εθνεσιν ονομαζεται ωστε γυναικα τινα του πατρος εχειν'),
(5312, 46, 'TR1550', 'TR1550', 'el', '1CO', 5, 2, 'NT', 'και υμεις πεφυσιωμενοι εστε και ουχι μαλλον επενθησατε ινα εξαρθη εκ μεσου υμων ο το εργον τουτο ποιησας'),
(5313, 46, 'TR1550', 'TR1550', 'el', '1CO', 5, 3, 'NT', 'εγω μεν γαρ ως απων τω σωματι παρων δε τω πνευματι ηδη κεκρικα ως παρων τον ουτως τουτο κατεργασαμενον'),
(5314, 46, 'TR1550', 'TR1550', 'el', '1CO', 5, 4, 'NT', 'εν τω ονοματι του κυριου ημων ιησου χριστου συναχθεντων υμων και του εμου πνευματος συν τη δυναμει του κυριου ημων ιησου χριστου'),
(5315, 46, 'TR1550', 'TR1550', 'el', '1CO', 5, 5, 'NT', 'παραδουναι τον τοιουτον τω σατανα εις ολεθρον της σαρκος ινα το πνευμα σωθη εν τη ημερα του κυριου ιησου'),
(5316, 46, 'TR1550', 'TR1550', 'el', '1CO', 5, 6, 'NT', 'ου καλον το καυχημα υμων ουκ οιδατε οτι μικρα ζυμη ολον το φυραμα ζυμοι'),
(5317, 46, 'TR1550', 'TR1550', 'el', '1CO', 5, 7, 'NT', 'εκκαθαρατε ουν την παλαιαν ζυμην ινα ητε νεον φυραμα καθως εστε αζυμοι και γαρ το πασχα ημων υπερ ημων ετυθη χριστος'),
(5318, 46, 'TR1550', 'TR1550', 'el', '1CO', 5, 8, 'NT', 'ωστε εορταζωμεν μη εν ζυμη παλαια μηδε εν ζυμη κακιας και πονηριας αλλ εν αζυμοις ειλικρινειας και αληθειας'),
(5319, 46, 'TR1550', 'TR1550', 'el', '1CO', 5, 9, 'NT', 'εγραψα υμιν εν τη επιστολη μη συναναμιγνυσθαι πορνοις'),
(5320, 46, 'TR1550', 'TR1550', 'el', '1CO', 5, 10, 'NT', 'και ου παντως τοις πορνοις του κοσμου τουτου η τοις πλεονεκταις η αρπαξιν η ειδωλολατραις επει οφειλετε αρα εκ του κοσμου εξελθειν'),
(5321, 46, 'TR1550', 'TR1550', 'el', '1CO', 5, 11, 'NT', 'νυνι δε εγραψα υμιν μη συναναμιγνυσθαι εαν τις αδελφος ονομαζομενος η πορνος η πλεονεκτης η ειδωλολατρης η λοιδορος η μεθυσος η αρπαξ τω τοιουτω μηδε συνεσθιειν'),
(5322, 46, 'TR1550', 'TR1550', 'el', '1CO', 5, 12, 'NT', 'τι γαρ μοι και τους εξω κρινειν ουχι τους εσω υμεις κρινετε'),
(5323, 46, 'TR1550', 'TR1550', 'el', '1CO', 5, 13, 'NT', 'τους δε εξω ο θεος κρινει και εξαρειτε τον πονηρον εξ υμων αυτων'),
(5324, 46, 'TR1550', 'TR1550', 'el', '1CO', 6, 1, 'NT', 'τολμα τις υμων πραγμα εχων προς τον ετερον κρινεσθαι επι των αδικων και ουχι επι των αγιων'),
(5325, 46, 'TR1550', 'TR1550', 'el', '1CO', 6, 2, 'NT', 'ουκ οιδατε οτι οι αγιοι τον κοσμον κρινουσιν και ει εν υμιν κρινεται ο κοσμος αναξιοι εστε κριτηριων ελαχιστων'),
(5326, 46, 'TR1550', 'TR1550', 'el', '1CO', 6, 3, 'NT', 'ουκ οιδατε οτι αγγελους κρινουμεν μητι γε βιωτικα'),
(5327, 46, 'TR1550', 'TR1550', 'el', '1CO', 6, 4, 'NT', 'βιωτικα μεν ουν κριτηρια εαν εχητε τους εξουθενημενους εν τη εκκλησια τουτους καθιζετε'),
(5328, 46, 'TR1550', 'TR1550', 'el', '1CO', 6, 5, 'NT', 'προς εντροπην υμιν λεγω ουτως ουκ εστιν εν υμιν σοφος ουδε εις ος δυνησεται διακριναι ανα μεσον του αδελφου αυτου'),
(5329, 46, 'TR1550', 'TR1550', 'el', '1CO', 6, 6, 'NT', 'αλλα αδελφος μετα αδελφου κρινεται και τουτο επι απιστων'),
(5330, 46, 'TR1550', 'TR1550', 'el', '1CO', 6, 7, 'NT', 'ηδη μεν ουν ολως ηττημα εν υμιν εστιν οτι κριματα εχετε μεθ εαυτων δια τι ουχι μαλλον αδικεισθε δια τι ουχι μαλλον αποστερεισθε'),
(5331, 46, 'TR1550', 'TR1550', 'el', '1CO', 6, 8, 'NT', 'αλλα υμεις αδικειτε και αποστερειτε και ταυτα αδελφους'),
(5332, 46, 'TR1550', 'TR1550', 'el', '1CO', 6, 9, 'NT', 'η ουκ οιδατε οτι αδικοι βασιλειαν θεου ου κληρονομησουσιν μη πλανασθε ουτε πορνοι ουτε ειδωλολατραι ουτε μοιχοι ουτε μαλακοι ουτε αρσενοκοιται'),
(5333, 46, 'TR1550', 'TR1550', 'el', '1CO', 6, 10, 'NT', 'ουτε κλεπται ουτε πλεονεκται ουτε μεθυσοι ου λοιδοροι ουχ αρπαγες βασιλειαν θεου ου κληρονομησουσιν'),
(5334, 46, 'TR1550', 'TR1550', 'el', '1CO', 6, 11, 'NT', 'και ταυτα τινες ητε αλλα απελουσασθε αλλα ηγιασθητε αλλ εδικαιωθητε εν τω ονοματι του κυριου ιησου και εν τω πνευματι του θεου ημων'),
(5335, 46, 'TR1550', 'TR1550', 'el', '1CO', 6, 12, 'NT', 'παντα μοι εξεστιν αλλ ου παντα συμφερει παντα μοι εξεστιν αλλ ουκ εγω εξουσιασθησομαι υπο τινος'),
(5336, 46, 'TR1550', 'TR1550', 'el', '1CO', 6, 13, 'NT', 'τα βρωματα τη κοιλια και η κοιλια τοις βρωμασιν ο δε θεος και ταυτην και ταυτα καταργησει το δε σωμα ου τη πορνεια αλλα τω κυριω και ο κυριος τω σωματι'),
(5337, 46, 'TR1550', 'TR1550', 'el', '1CO', 6, 14, 'NT', 'ο δε θεος και τον κυριον ηγειρεν και ημας εξεγερει δια της δυναμεως αυτου'),
(5338, 46, 'TR1550', 'TR1550', 'el', '1CO', 6, 15, 'NT', 'ουκ οιδατε οτι τα σωματα υμων μελη χριστου εστιν αρας ουν τα μελη του χριστου ποιησω πορνης μελη μη γενοιτο'),
(5339, 46, 'TR1550', 'TR1550', 'el', '1CO', 6, 16, 'NT', 'η ουκ οιδατε οτι ο κολλωμενος τη πορνη εν σωμα εστιν εσονται γαρ φησιν οι δυο εις σαρκα μιαν'),
(5340, 46, 'TR1550', 'TR1550', 'el', '1CO', 6, 17, 'NT', 'ο δε κολλωμενος τω κυριω εν πνευμα εστιν'),
(5341, 46, 'TR1550', 'TR1550', 'el', '1CO', 6, 18, 'NT', 'φευγετε την πορνειαν παν αμαρτημα ο εαν ποιηση ανθρωπος εκτος του σωματος εστιν ο δε πορνευων εις το ιδιον σωμα αμαρτανει'),
(5342, 46, 'TR1550', 'TR1550', 'el', '1CO', 6, 19, 'NT', 'η ουκ οιδατε οτι το σωμα υμων ναος του εν υμιν αγιου πνευματος εστιν ου εχετε απο θεου και ουκ εστε εαυτων'),
(5343, 46, 'TR1550', 'TR1550', 'el', '1CO', 6, 20, 'NT', 'ηγορασθητε γαρ τιμης δοξασατε δη τον θεον εν τω σωματι υμων και εν τω πνευματι υμων ατινα εστιν του θεου'),
(5344, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 1, 'NT', 'περι δε ων εγραψατε μοι καλον ανθρωπω γυναικος μη απτεσθαι'),
(5345, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 2, 'NT', 'δια δε τας πορνειας εκαστος την εαυτου γυναικα εχετω και εκαστη τον ιδιον ανδρα εχετω'),
(5346, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 3, 'NT', 'τη γυναικι ο ανηρ την οφειλομενην ευνοιαν αποδιδοτω ομοιως δε και η γυνη τω ανδρι'),
(5347, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 4, 'NT', 'η γυνη του ιδιου σωματος ουκ εξουσιαζει αλλ ο ανηρ ομοιως δε και ο ανηρ του ιδιου σωματος ουκ εξουσιαζει αλλ η γυνη'),
(5348, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 5, 'NT', 'μη αποστερειτε αλληλους ει μη τι αν εκ συμφωνου προς καιρον ινα σχολαζητε τη νηστεια και τη προσευχη και παλιν επι το αυτο συνερχησθε ινα μη πειραζη υμας ο σατανας δια την ακρασιαν υμων'),
(5349, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 6, 'NT', 'τουτο δε λεγω κατα συγγνωμην ου κατ επιταγην'),
(5350, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 7, 'NT', 'θελω γαρ παντας ανθρωπους ειναι ως και εμαυτον αλλ εκαστος ιδιον χαρισμα εχει εκ θεου ος μεν ουτως ος δε ουτως'),
(5351, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 8, 'NT', 'λεγω δε τοις αγαμοις και ταις χηραις καλον αυτοις εστιν εαν μεινωσιν ως καγω'),
(5352, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 9, 'NT', 'ει δε ουκ εγκρατευονται γαμησατωσαν κρεισσον γαρ εστιν γαμησαι η πυρουσθαι'),
(5353, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 10, 'NT', 'τοις δε γεγαμηκοσιν παραγγελλω ουκ εγω αλλ ο κυριος γυναικα απο ανδρος μη χωρισθηναι'),
(5354, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 11, 'NT', 'εαν δε και χωρισθη μενετω αγαμος η τω ανδρι καταλλαγητω και ανδρα γυναικα μη αφιεναι'),
(5355, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 12, 'NT', 'τοις δε λοιποις εγω λεγω ουχ ο κυριος ει τις αδελφος γυναικα εχει απιστον και αυτη συνευδοκει οικειν μετ αυτου μη αφιετω αυτην'),
(5356, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 13, 'NT', 'και γυνη ητις εχει ανδρα απιστον και αυτος συνευδοκει οικειν μετ αυτης μη αφιετω αυτον'),
(5357, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 14, 'NT', 'ηγιασται γαρ ο ανηρ ο απιστος εν τη γυναικι και ηγιασται η γυνη η απιστος εν τω ανδρι επει αρα τα τεκνα υμων ακαθαρτα εστιν νυν δε αγια εστιν'),
(5358, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 15, 'NT', 'ει δε ο απιστος χωριζεται χωριζεσθω ου δεδουλωται ο αδελφος η η αδελφη εν τοις τοιουτοις εν δε ειρηνη κεκληκεν ημας ο θεος'),
(5359, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 16, 'NT', 'τι γαρ οιδας γυναι ει τον ανδρα σωσεις η τι οιδας ανερ ει την γυναικα σωσεις'),
(5360, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 17, 'NT', 'ει μη εκαστω ως εμερισεν ο θεος εκαστον ως κεκληκεν ο κυριος ουτως περιπατειτω και ουτως εν ταις εκκλησιαις πασαις διατασσομαι'),
(5361, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 18, 'NT', 'περιτετμημενος τις εκληθη μη επισπασθω εν ακροβυστια τις εκληθη μη περιτεμνεσθω'),
(5362, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 19, 'NT', 'η περιτομη ουδεν εστιν και η ακροβυστια ουδεν εστιν αλλα τηρησις εντολων θεου'),
(5363, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 20, 'NT', 'εκαστος εν τη κλησει η εκληθη εν ταυτη μενετω'),
(5364, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 21, 'NT', 'δουλος εκληθης μη σοι μελετω αλλ ει και δυνασαι ελευθερος γενεσθαι μαλλον χρησαι'),
(5365, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 22, 'NT', 'ο γαρ εν κυριω κληθεις δουλος απελευθερος κυριου εστιν ομοιως και ο ελευθερος κληθεις δουλος εστιν χριστου'),
(5366, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 23, 'NT', 'τιμης ηγορασθητε μη γινεσθε δουλοι ανθρωπων'),
(5367, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 24, 'NT', 'εκαστος εν ω εκληθη αδελφοι εν τουτω μενετω παρα τω θεω'),
(5368, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 25, 'NT', 'περι δε των παρθενων επιταγην κυριου ουκ εχω γνωμην δε διδωμι ως ηλεημενος υπο κυριου πιστος ειναι'),
(5369, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 26, 'NT', 'νομιζω ουν τουτο καλον υπαρχειν δια την ενεστωσαν αναγκην οτι καλον ανθρωπω το ουτως ειναι'),
(5370, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 27, 'NT', 'δεδεσαι γυναικι μη ζητει λυσιν λελυσαι απο γυναικος μη ζητει γυναικα'),
(5371, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 28, 'NT', 'εαν δε και γημης ουχ ημαρτες και εαν γημη η παρθενος ουχ ημαρτεν θλιψιν δε τη σαρκι εξουσιν οι τοιουτοι εγω δε υμων φειδομαι'),
(5372, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 29, 'NT', 'τουτο δε φημι αδελφοι ο καιρος συνεσταλμενος το λοιπον εστιν ινα και οι εχοντες γυναικας ως μη εχοντες ωσιν'),
(5373, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 30, 'NT', 'και οι κλαιοντες ως μη κλαιοντες και οι χαιροντες ως μη χαιροντες και οι αγοραζοντες ως μη κατεχοντες'),
(5374, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 31, 'NT', 'και οι χρωμενοι τω κοσμω τουτω ως μη καταχρωμενοι παραγει γαρ το σχημα του κοσμου τουτου'),
(5375, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 32, 'NT', 'θελω δε υμας αμεριμνους ειναι ο αγαμος μεριμνα τα του κυριου πως αρεσει τω κυριω'),
(5376, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 33, 'NT', 'ο δε γαμησας μεριμνα τα του κοσμου πως αρεσει τη γυναικι'),
(5377, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 34, 'NT', 'μεμερισται η γυνη και η παρθενος η αγαμος μεριμνα τα του κυριου ινα η αγια και σωματι και πνευματι η δε γαμησασα μεριμνα τα του κοσμου πως αρεσει τω ανδρι'),
(5378, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 35, 'NT', 'τουτο δε προς το υμων αυτων συμφερον λεγω ουχ ινα βροχον υμιν επιβαλω αλλα προς το ευσχημον και ευπροσεδρον τω κυριω απερισπαστως'),
(5379, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 36, 'NT', 'ει δε τις ασχημονειν επι την παρθενον αυτου νομιζει εαν η υπερακμος και ουτως οφειλει γινεσθαι ο θελει ποιειτω ουχ αμαρτανει γαμειτωσαν'),
(5380, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 37, 'NT', 'ος δε εστηκεν εδραιος εν τη καρδια μη εχων αναγκην εξουσιαν δε εχει περι του ιδιου θεληματος και τουτο κεκρικεν εν τη καρδια αυτου του τηρειν την εαυτου παρθενον καλως ποιει'),
(5381, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 38, 'NT', 'ωστε και ο εκγαμιζων καλως ποιει ο δε μη εκγαμιζων κρεισσον ποιει'),
(5382, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 39, 'NT', 'γυνη δεδεται νομω εφ οσον χρονον ζη ο ανηρ αυτης εαν δε κοιμηθη ο ανηρ αυτης ελευθερα εστιν ω θελει γαμηθηναι μονον εν κυριω'),
(5383, 46, 'TR1550', 'TR1550', 'el', '1CO', 7, 40, 'NT', 'μακαριωτερα δε εστιν εαν ουτως μεινη κατα την εμην γνωμην δοκω δε καγω πνευμα θεου εχειν'),
(5384, 46, 'TR1550', 'TR1550', 'el', '1CO', 8, 1, 'NT', 'περι δε των ειδωλοθυτων οιδαμεν οτι παντες γνωσιν εχομεν η γνωσις φυσιοι η δε αγαπη οικοδομει'),
(5385, 46, 'TR1550', 'TR1550', 'el', '1CO', 8, 2, 'NT', 'ει δε τις δοκει ειδεναι τι ουδεπω ουδεν εγνωκεν καθως δει γνωναι'),
(5386, 46, 'TR1550', 'TR1550', 'el', '1CO', 8, 3, 'NT', 'ει δε τις αγαπα τον θεον ουτος εγνωσται υπ αυτου'),
(5387, 46, 'TR1550', 'TR1550', 'el', '1CO', 8, 4, 'NT', 'περι της βρωσεως ουν των ειδωλοθυτων οιδαμεν οτι ουδεν ειδωλον εν κοσμω και οτι ουδεις θεος ετερος ει μη εις'),
(5388, 46, 'TR1550', 'TR1550', 'el', '1CO', 8, 5, 'NT', 'και γαρ ειπερ εισιν λεγομενοι θεοι ειτε εν ουρανω ειτε επι της γης ωσπερ εισιν θεοι πολλοι και κυριοι πολλοι'),
(5389, 46, 'TR1550', 'TR1550', 'el', '1CO', 8, 6, 'NT', 'αλλ ημιν εις θεος ο πατηρ εξ ου τα παντα και ημεις εις αυτον και εις κυριος ιησους χριστος δι ου τα παντα και ημεις δι αυτου'),
(5390, 46, 'TR1550', 'TR1550', 'el', '1CO', 8, 7, 'NT', 'αλλ ουκ εν πασιν η γνωσις τινες δε τη συνειδησει του ειδωλου εως αρτι ως ειδωλοθυτον εσθιουσιν και η συνειδησις αυτων ασθενης ουσα μολυνεται'),
(5391, 46, 'TR1550', 'TR1550', 'el', '1CO', 8, 8, 'NT', 'βρωμα δε ημας ου παριστησιν τω θεω ουτε γαρ εαν φαγωμεν περισσευομεν ουτε εαν μη φαγωμεν υστερουμεθα'),
(5392, 46, 'TR1550', 'TR1550', 'el', '1CO', 8, 9, 'NT', 'βλεπετε δε μηπως η εξουσια υμων αυτη προσκομμα γενηται τοις ασθενουσιν'),
(5393, 46, 'TR1550', 'TR1550', 'el', '1CO', 8, 10, 'NT', 'εαν γαρ τις ιδη σε τον εχοντα γνωσιν εν ειδωλειω κατακειμενον ουχι η συνειδησις αυτου ασθενους οντος οικοδομηθησεται εις το τα ειδωλοθυτα εσθιειν'),
(5394, 46, 'TR1550', 'TR1550', 'el', '1CO', 8, 11, 'NT', 'και απολειται ο ασθενων αδελφος επι τη ση γνωσει δι ον χριστος απεθανεν'),
(5395, 46, 'TR1550', 'TR1550', 'el', '1CO', 8, 12, 'NT', 'ουτως δε αμαρτανοντες εις τους αδελφους και τυπτοντες αυτων την συνειδησιν ασθενουσαν εις χριστον αμαρτανετε'),
(5396, 46, 'TR1550', 'TR1550', 'el', '1CO', 8, 13, 'NT', 'διοπερ ει βρωμα σκανδαλιζει τον αδελφον μου ου μη φαγω κρεα εις τον αιωνα ινα μη τον αδελφον μου σκανδαλισω'),
(5397, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 1, 'NT', 'ουκ ειμι αποστολος ουκ ειμι ελευθερος ουχι ιησουν χριστον τον κυριον ημων εωρακα ου το εργον μου υμεις εστε εν κυριω'),
(5398, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 2, 'NT', 'ει αλλοις ουκ ειμι αποστολος αλλα γε υμιν ειμι η γαρ σφραγις της εμης αποστολης υμεις εστε εν κυριω'),
(5399, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 3, 'NT', 'η εμη απολογια τοις εμε ανακρινουσιν αυτη εστιν'),
(5400, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 4, 'NT', 'μη ουκ εχομεν εξουσιαν φαγειν και πιειν'),
(5401, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 5, 'NT', 'μη ουκ εχομεν εξουσιαν αδελφην γυναικα περιαγειν ως και οι λοιποι αποστολοι και οι αδελφοι του κυριου και κηφας'),
(5402, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 6, 'NT', 'η μονος εγω και βαρναβας ουκ εχομεν εξουσιαν του μη εργαζεσθαι'),
(5403, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 7, 'NT', 'τις στρατευεται ιδιοις οψωνιοις ποτε τις φυτευει αμπελωνα και εκ του καρπου αυτου ουκ εσθιει η τις ποιμαινει ποιμνην και εκ του γαλακτος της ποιμνης ουκ εσθιει'),
(5404, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 8, 'NT', 'μη κατα ανθρωπον ταυτα λαλω η ουχι και ο νομος ταυτα λεγει'),
(5405, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 9, 'NT', 'εν γαρ τω μωσεως νομω γεγραπται ου φιμωσεις βουν αλοωντα μη των βοων μελει τω θεω'),
(5406, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 10, 'NT', 'η δι ημας παντως λεγει δι ημας γαρ εγραφη οτι επ ελπιδι οφειλει ο αροτριων αροτριαν και ο αλοων της ελπιδος αυτου μετεχειν επ ελπιδι'),
(5407, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 11, 'NT', 'ει ημεις υμιν τα πνευματικα εσπειραμεν μεγα ει ημεις υμων τα σαρκικα θερισομεν'),
(5408, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 12, 'NT', 'ει αλλοι της εξουσιας υμων μετεχουσιν ου μαλλον ημεις αλλ ουκ εχρησαμεθα τη εξουσια ταυτη αλλα παντα στεγομεν ινα μη εγκοπην τινα δωμεν τω ευαγγελιω του χριστου'),
(5409, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 13, 'NT', 'ουκ οιδατε οτι οι τα ιερα εργαζομενοι εκ του ιερου εσθιουσιν οι τω θυσιαστηριω προσεδρευοντες τω θυσιαστηριω συμμεριζονται'),
(5410, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 14, 'NT', 'ουτως και ο κυριος διεταξεν τοις το ευαγγελιον καταγγελλουσιν εκ του ευαγγελιου ζην'),
(5411, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 15, 'NT', 'εγω δε ουδενι εχρησαμην τουτων ουκ εγραψα δε ταυτα ινα ουτως γενηται εν εμοι καλον γαρ μοι μαλλον αποθανειν η το καυχημα μου ινα τις κενωση'),
(5412, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 16, 'NT', 'εαν γαρ ευαγγελιζωμαι ουκ εστιν μοι καυχημα αναγκη γαρ μοι επικειται ουαι δε μοι εστιν εαν μη ευαγγελιζωμαι'),
(5413, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 17, 'NT', 'ει γαρ εκων τουτο πρασσω μισθον εχω ει δε ακων οικονομιαν πεπιστευμαι'),
(5414, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 18, 'NT', 'τις ουν μοι εστιν ο μισθος ινα ευαγγελιζομενος αδαπανον θησω το ευαγγελιον του χριστου εις το μη καταχρησασθαι τη εξουσια μου εν τω ευαγγελιω'),
(5415, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 19, 'NT', 'ελευθερος γαρ ων εκ παντων πασιν εμαυτον εδουλωσα ινα τους πλειονας κερδησω'),
(5416, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 20, 'NT', 'και εγενομην τοις ιουδαιοις ως ιουδαιος ινα ιουδαιους κερδησω τοις υπο νομον ως υπο νομον ινα τους υπο νομον κερδησω'),
(5417, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 21, 'NT', 'τοις ανομοις ως ανομος μη ων ανομος θεω αλλ εννομος χριστω ινα κερδησω ανομους'),
(5418, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 22, 'NT', 'εγενομην τοις ασθενεσιν ως ασθενης ινα τους ασθενεις κερδησω τοις πασιν γεγονα τα παντα ινα παντως τινας σωσω'),
(5419, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 23, 'NT', 'τουτο δε ποιω δια το ευαγγελιον ινα συγκοινωνος αυτου γενωμαι'),
(5420, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 24, 'NT', 'ουκ οιδατε οτι οι εν σταδιω τρεχοντες παντες μεν τρεχουσιν εις δε λαμβανει το βραβειον ουτως τρεχετε ινα καταλαβητε'),
(5421, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 25, 'NT', 'πας δε ο αγωνιζομενος παντα εγκρατευεται εκεινοι μεν ουν ινα φθαρτον στεφανον λαβωσιν ημεις δε αφθαρτον'),
(5422, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 26, 'NT', 'εγω τοινυν ουτως τρεχω ως ουκ αδηλως ουτως πυκτευω ως ουκ αερα δερων'),
(5423, 46, 'TR1550', 'TR1550', 'el', '1CO', 9, 27, 'NT', 'αλλ υπωπιαζω μου το σωμα και δουλαγωγω μηπως αλλοις κηρυξας αυτος αδοκιμος γενωμαι'),
(5424, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 1, 'NT', 'ου θελω δε υμας αγνοειν αδελφοι οτι οι πατερες ημων παντες υπο την νεφελην ησαν και παντες δια της θαλασσης διηλθον'),
(5425, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 2, 'NT', 'και παντες εις τον μωσην εβαπτισαντο εν τη νεφελη και εν τη θαλασση'),
(5426, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 3, 'NT', 'και παντες το αυτο βρωμα πνευματικον εφαγον'),
(5427, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 4, 'NT', 'και παντες το αυτο πομα πνευματικον επιον επινον γαρ εκ πνευματικης ακολουθουσης πετρας η δε πετρα ην ο χριστος'),
(5428, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 5, 'NT', 'αλλ ουκ εν τοις πλειοσιν αυτων ευδοκησεν ο θεος κατεστρωθησαν γαρ εν τη ερημω'),
(5429, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 6, 'NT', 'ταυτα δε τυποι ημων εγενηθησαν εις το μη ειναι ημας επιθυμητας κακων καθως κακεινοι επεθυμησαν'),
(5430, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 7, 'NT', 'μηδε ειδωλολατραι γινεσθε καθως τινες αυτων ως γεγραπται εκαθισεν ο λαος φαγειν και πιειν και ανεστησαν παιζειν'),
(5431, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 8, 'NT', 'μηδε πορνευωμεν καθως τινες αυτων επορνευσαν και επεσον εν μια ημερα εικοσιτρεις χιλιαδες'),
(5432, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 9, 'NT', 'μηδε εκπειραζωμεν τον χριστον καθως και τινες αυτων επειρασαν και υπο των οφεων απωλοντο'),
(5433, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 10, 'NT', 'μηδε γογγυζετε καθως και τινες αυτων εγογγυσαν και απωλοντο υπο του ολοθρευτου'),
(5434, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 11, 'NT', 'ταυτα δε παντα τυποι συνεβαινον εκεινοις εγραφη δε προς νουθεσιαν ημων εις ους τα τελη των αιωνων κατηντησεν'),
(5435, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 12, 'NT', 'ωστε ο δοκων εσταναι βλεπετω μη πεση'),
(5436, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 13, 'NT', 'πειρασμος υμας ουκ ειληφεν ει μη ανθρωπινος πιστος δε ο θεος ος ουκ εασει υμας πειρασθηναι υπερ ο δυνασθε αλλα ποιησει συν τω πειρασμω και την εκβασιν του δυνασθαι υμας υπενεγκειν'),
(5437, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 14, 'NT', 'διοπερ αγαπητοι μου φευγετε απο της ειδωλολατρειας'),
(5438, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 15, 'NT', 'ως φρονιμοις λεγω κρινατε υμεις ο φημι'),
(5439, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 16, 'NT', 'το ποτηριον της ευλογιας ο ευλογουμεν ουχι κοινωνια του αιματος του χριστου εστιν τον αρτον ον κλωμεν ουχι κοινωνια του σωματος του χριστου εστιν'),
(5440, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 17, 'NT', 'οτι εις αρτος εν σωμα οι πολλοι εσμεν οι γαρ παντες εκ του ενος αρτου μετεχομεν'),
(5441, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 18, 'NT', 'βλεπετε τον ισραηλ κατα σαρκα ουχι οι εσθιοντες τας θυσιας κοινωνοι του θυσιαστηριου εισιν'),
(5442, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 19, 'NT', 'τι ουν φημι οτι ειδωλον τι εστιν η οτι ειδωλοθυτον τι εστιν'),
(5443, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 20, 'NT', 'αλλ οτι α θυει τα εθνη δαιμονιοις θυει και ου θεω ου θελω δε υμας κοινωνους των δαιμονιων γινεσθαι'),
(5444, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 21, 'NT', 'ου δυνασθε ποτηριον κυριου πινειν και ποτηριον δαιμονιων ου δυνασθε τραπεζης κυριου μετεχειν και τραπεζης δαιμονιων'),
(5445, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 22, 'NT', 'η παραζηλουμεν τον κυριον μη ισχυροτεροι αυτου εσμεν'),
(5446, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 23, 'NT', 'παντα μοι εξεστιν αλλ ου παντα συμφερει παντα μοι εξεστιν αλλ ου παντα οικοδομει'),
(5447, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 24, 'NT', 'μηδεις το εαυτου ζητειτω αλλα το του ετερου εκαστος'),
(5448, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 25, 'NT', 'παν το εν μακελλω πωλουμενον εσθιετε μηδεν ανακρινοντες δια την συνειδησιν'),
(5449, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 26, 'NT', 'του γαρ κυριου η γη και το πληρωμα αυτης'),
(5450, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 27, 'NT', 'ει δε τις καλει υμας των απιστων και θελετε πορευεσθαι παν το παρατιθεμενον υμιν εσθιετε μηδεν ανακρινοντες δια την συνειδησιν'),
(5451, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 28, 'NT', 'εαν δε τις υμιν ειπη τουτο ειδωλοθυτον εστιν μη εσθιετε δι εκεινον τον μηνυσαντα και την συνειδησιν του γαρ κυριου η γη και το πληρωμα αυτης'),
(5452, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 29, 'NT', 'συνειδησιν δε λεγω ουχι την εαυτου αλλα την του ετερου ινα τι γαρ η ελευθερια μου κρινεται υπο αλλης συνειδησεως'),
(5453, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 30, 'NT', 'ει δε εγω χαριτι μετεχω τι βλασφημουμαι υπερ ου εγω ευχαριστω'),
(5454, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 31, 'NT', 'ειτε ουν εσθιετε ειτε πινετε ειτε τι ποιειτε παντα εις δοξαν θεου ποιειτε'),
(5455, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 32, 'NT', 'απροσκοποι γινεσθε και ιουδαιοις και ελλησιν και τη εκκλησια του θεου'),
(5456, 46, 'TR1550', 'TR1550', 'el', '1CO', 10, 33, 'NT', 'καθως καγω παντα πασιν αρεσκω μη ζητων το εμαυτου συμφερον αλλα το των πολλων ινα σωθωσιν'),
(5457, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 1, 'NT', 'μιμηται μου γινεσθε καθως καγω χριστου'),
(5458, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 2, 'NT', 'επαινω δε υμας αδελφοι οτι παντα μου μεμνησθε και καθως παρεδωκα υμιν τας παραδοσεις κατεχετε'),
(5459, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 3, 'NT', 'θελω δε υμας ειδεναι οτι παντος ανδρος η κεφαλη ο χριστος εστιν κεφαλη δε γυναικος ο ανηρ κεφαλη δε χριστου ο θεος'),
(5460, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 4, 'NT', 'πας ανηρ προσευχομενος η προφητευων κατα κεφαλης εχων καταισχυνει την κεφαλην αυτου'),
(5461, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 5, 'NT', 'πασα δε γυνη προσευχομενη η προφητευουσα ακατακαλυπτω τη κεφαλη καταισχυνει την κεφαλην εαυτης εν γαρ εστιν και το αυτο τη εξυρημενη'),
(5462, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 6, 'NT', 'ει γαρ ου κατακαλυπτεται γυνη και κειρασθω ει δε αισχρον γυναικι το κειρασθαι η ξυρασθαι κατακαλυπτεσθω'),
(5463, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 7, 'NT', 'ανηρ μεν γαρ ουκ οφειλει κατακαλυπτεσθαι την κεφαλην εικων και δοξα θεου υπαρχων γυνη δε δοξα ανδρος εστιν'),
(5464, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 8, 'NT', 'ου γαρ εστιν ανηρ εκ γυναικος αλλα γυνη εξ ανδρος'),
(5465, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 9, 'NT', 'και γαρ ουκ εκτισθη ανηρ δια την γυναικα αλλα γυνη δια τον ανδρα'),
(5466, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 10, 'NT', 'δια τουτο οφειλει η γυνη εξουσιαν εχειν επι της κεφαλης δια τους αγγελους'),
(5467, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 11, 'NT', 'πλην ουτε ανηρ χωρις γυναικος ουτε γυνη χωρις ανδρος εν κυριω'),
(5468, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 12, 'NT', 'ωσπερ γαρ η γυνη εκ του ανδρος ουτως και ο ανηρ δια της γυναικος τα δε παντα εκ του θεου'),
(5469, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 13, 'NT', 'εν υμιν αυτοις κρινατε πρεπον εστιν γυναικα ακατακαλυπτον τω θεω προσευχεσθαι'),
(5470, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 14, 'NT', 'η ουδε αυτη η φυσις διδασκει υμας οτι ανηρ μεν εαν κομα ατιμια αυτω εστιν'),
(5471, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 15, 'NT', 'γυνη δε εαν κομα δοξα αυτη εστιν οτι η κομη αντι περιβολαιου δεδοται αυτη'),
(5472, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 16, 'NT', 'ει δε τις δοκει φιλονεικος ειναι ημεις τοιαυτην συνηθειαν ουκ εχομεν ουδε αι εκκλησιαι του θεου'),
(5473, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 17, 'NT', 'τουτο δε παραγγελλων ουκ επαινω οτι ουκ εις το κρειττον αλλ εις το ηττον συνερχεσθε'),
(5474, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 18, 'NT', 'πρωτον μεν γαρ συνερχομενων υμων εν τη εκκλησια ακουω σχισματα εν υμιν υπαρχειν και μερος τι πιστευω'),
(5475, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 19, 'NT', 'δει γαρ και αιρεσεις εν υμιν ειναι ινα οι δοκιμοι φανεροι γενωνται εν υμιν'),
(5476, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 20, 'NT', 'συνερχομενων ουν υμων επι το αυτο ουκ εστιν κυριακον δειπνον φαγειν'),
(5477, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 21, 'NT', 'εκαστος γαρ το ιδιον δειπνον προλαμβανει εν τω φαγειν και ος μεν πεινα ος δε μεθυει'),
(5478, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 22, 'NT', 'μη γαρ οικιας ουκ εχετε εις το εσθιειν και πινειν η της εκκλησιας του θεου καταφρονειτε και καταισχυνετε τους μη εχοντας τι υμιν ειπω επαινεσω υμας εν τουτω ουκ επαινω'),
(5479, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 23, 'NT', 'εγω γαρ παρελαβον απο του κυριου ο και παρεδωκα υμιν οτι ο κυριος ιησους εν τη νυκτι η παρεδιδοτο ελαβεν αρτον'),
(5480, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 24, 'NT', 'και ευχαριστησας εκλασεν και ειπεν λαβετε φαγετε τουτο μου εστιν το σωμα το υπερ υμων κλωμενον τουτο ποιειτε εις την εμην αναμνησιν'),
(5481, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 25, 'NT', 'ωσαυτως και το ποτηριον μετα το δειπνησαι λεγων τουτο το ποτηριον η καινη διαθηκη εστιν εν τω εμω αιματι τουτο ποιειτε οσακις αν πινητε εις την εμην αναμνησιν'),
(5482, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 26, 'NT', 'οσακις γαρ αν εσθιητε τον αρτον τουτον και το ποτηριον τουτο πινητε τον θανατον του κυριου καταγγελλετε αχρις ου αν ελθη'),
(5483, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 27, 'NT', 'ωστε ος αν εσθιη τον αρτον τουτον η πινη το ποτηριον του κυριου αναξιως ενοχος εσται του σωματος και αιματος του κυριου'),
(5484, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 28, 'NT', 'δοκιμαζετω δε ανθρωπος εαυτον και ουτως εκ του αρτου εσθιετω και εκ του ποτηριου πινετω'),
(5485, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 29, 'NT', 'ο γαρ εσθιων και πινων αναξιως κριμα εαυτω εσθιει και πινει μη διακρινων το σωμα του κυριου'),
(5486, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 30, 'NT', 'δια τουτο εν υμιν πολλοι ασθενεις και αρρωστοι και κοιμωνται ικανοι'),
(5487, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 31, 'NT', 'ει γαρ εαυτους διεκρινομεν ουκ αν εκρινομεθα'),
(5488, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 32, 'NT', 'κρινομενοι δε υπο κυριου παιδευομεθα ινα μη συν τω κοσμω κατακριθωμεν'),
(5489, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 33, 'NT', 'ωστε αδελφοι μου συνερχομενοι εις το φαγειν αλληλους εκδεχεσθε'),
(5490, 46, 'TR1550', 'TR1550', 'el', '1CO', 11, 34, 'NT', 'ει δε τις πεινα εν οικω εσθιετω ινα μη εις κριμα συνερχησθε τα δε λοιπα ως αν ελθω διαταξομαι'),
(5491, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 1, 'NT', 'περι δε των πνευματικων αδελφοι ου θελω υμας αγνοειν'),
(5492, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 2, 'NT', 'οιδατε οτι εθνη ητε προς τα ειδωλα τα αφωνα ως αν ηγεσθε απαγομενοι'),
(5493, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 3, 'NT', 'διο γνωριζω υμιν οτι ουδεις εν πνευματι θεου λαλων λεγει αναθεμα ιησουν και ουδεις δυναται ειπειν κυριον ιησουν ει μη εν πνευματι αγιω'),
(5494, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 4, 'NT', 'διαιρεσεις δε χαρισματων εισιν το δε αυτο πνευμα'),
(5495, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 5, 'NT', 'και διαιρεσεις διακονιων εισιν και ο αυτος κυριος'),
(5496, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 6, 'NT', 'και διαιρεσεις ενεργηματων εισιν ο δε αυτος εστιν θεος ο ενεργων τα παντα εν πασιν'),
(5497, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 7, 'NT', 'εκαστω δε διδοται η φανερωσις του πνευματος προς το συμφερον'),
(5498, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 8, 'NT', 'ω μεν γαρ δια του πνευματος διδοται λογος σοφιας αλλω δε λογος γνωσεως κατα το αυτο πνευμα'),
(5499, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 9, 'NT', 'ετερω δε πιστις εν τω αυτω πνευματι αλλω δε χαρισματα ιαματων εν τω αυτω πνευματι'),
(5500, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 10, 'NT', 'αλλω δε ενεργηματα δυναμεων αλλω δε προφητεια αλλω δε διακρισεις πνευματων ετερω δε γενη γλωσσων αλλω δε ερμηνεια γλωσσων'),
(5501, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 11, 'NT', 'παντα δε ταυτα ενεργει το εν και το αυτο πνευμα διαιρουν ιδια εκαστω καθως βουλεται'),
(5502, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 12, 'NT', 'καθαπερ γαρ το σωμα εν εστιν και μελη εχει πολλα παντα δε τα μελη του σωματος του ενος πολλα οντα εν εστιν σωμα ουτως και ο χριστος'),
(5503, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 13, 'NT', 'και γαρ εν ενι πνευματι ημεις παντες εις εν σωμα εβαπτισθημεν ειτε ιουδαιοι ειτε ελληνες ειτε δουλοι ειτε ελευθεροι και παντες εις εν πνευμα εποτισθημεν'),
(5504, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 14, 'NT', 'και γαρ το σωμα ουκ εστιν εν μελος αλλα πολλα'),
(5505, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 15, 'NT', 'εαν ειπη ο πους οτι ουκ ειμι χειρ ουκ ειμι εκ του σωματος ου παρα τουτο ουκ εστιν εκ του σωματος'),
(5506, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 16, 'NT', 'και εαν ειπη το ους οτι ουκ ειμι οφθαλμος ουκ ειμι εκ του σωματος ου παρα τουτο ουκ εστιν εκ του σωματος'),
(5507, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 17, 'NT', 'ει ολον το σωμα οφθαλμος που η ακοη ει ολον ακοη που η οσφρησις'),
(5508, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 18, 'NT', 'νυνι δε ο θεος εθετο τα μελη εν εκαστον αυτων εν τω σωματι καθως ηθελησεν'),
(5509, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 19, 'NT', 'ει δε ην τα παντα εν μελος που το σωμα'),
(5510, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 20, 'NT', 'νυν δε πολλα μεν μελη εν δε σωμα'),
(5511, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 21, 'NT', 'ου δυναται δε οφθαλμος ειπειν τη χειρι χρειαν σου ουκ εχω η παλιν η κεφαλη τοις ποσιν χρειαν υμων ουκ εχω'),
(5512, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 22, 'NT', 'αλλα πολλω μαλλον τα δοκουντα μελη του σωματος ασθενεστερα υπαρχειν αναγκαια εστιν'),
(5513, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 23, 'NT', 'και α δοκουμεν ατιμοτερα ειναι του σωματος τουτοις τιμην περισσοτεραν περιτιθεμεν και τα ασχημονα ημων ευσχημοσυνην περισσοτεραν εχει'),
(5514, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 24, 'NT', 'τα δε ευσχημονα ημων ου χρειαν εχει αλλ ο θεος συνεκερασεν το σωμα τω υστερουντι περισσοτεραν δους τιμην'),
(5515, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 25, 'NT', 'ινα μη η σχισμα εν τω σωματι αλλα το αυτο υπερ αλληλων μεριμνωσιν τα μελη'),
(5516, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 26, 'NT', 'και ειτε πασχει εν μελος συμπασχει παντα τα μελη ειτε δοξαζεται εν μελος συγχαιρει παντα τα μελη'),
(5517, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 27, 'NT', 'υμεις δε εστε σωμα χριστου και μελη εκ μερους'),
(5518, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 28, 'NT', 'και ους μεν εθετο ο θεος εν τη εκκλησια πρωτον αποστολους δευτερον προφητας τριτον διδασκαλους επειτα δυναμεις ειτα χαρισματα ιαματων αντιληψεις κυβερνησεις γενη γλωσσων'),
(5519, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 29, 'NT', 'μη παντες αποστολοι μη παντες προφηται μη παντες διδασκαλοι μη παντες δυναμεις'),
(5520, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 30, 'NT', 'μη παντες χαρισματα εχουσιν ιαματων μη παντες γλωσσαις λαλουσιν μη παντες διερμηνευουσιν'),
(5521, 46, 'TR1550', 'TR1550', 'el', '1CO', 12, 31, 'NT', 'ζηλουτε δε τα χαρισματα τα κρειττονα και ετι καθ υπερβολην οδον υμιν δεικνυμι'),
(5522, 46, 'TR1550', 'TR1550', 'el', '1CO', 13, 1, 'NT', 'εαν ταις γλωσσαις των ανθρωπων λαλω και των αγγελων αγαπην δε μη εχω γεγονα χαλκος ηχων η κυμβαλον αλαλαζον'),
(5523, 46, 'TR1550', 'TR1550', 'el', '1CO', 13, 2, 'NT', 'και εαν εχω προφητειαν και ειδω τα μυστηρια παντα και πασαν την γνωσιν και εαν εχω πασαν την πιστιν ωστε ορη μεθιστανειν αγαπην δε μη εχω ουθεν ειμι'),
(5524, 46, 'TR1550', 'TR1550', 'el', '1CO', 13, 3, 'NT', 'και εαν ψωμισω παντα τα υπαρχοντα μου και εαν παραδω το σωμα μου ινα καυθησωμαι αγαπην δε μη εχω ουδεν ωφελουμαι'),
(5525, 46, 'TR1550', 'TR1550', 'el', '1CO', 13, 4, 'NT', 'η αγαπη μακροθυμει χρηστευεται η αγαπη ου ζηλοι η αγαπη ου περπερευεται ου φυσιουται'),
(5526, 46, 'TR1550', 'TR1550', 'el', '1CO', 13, 5, 'NT', 'ουκ ασχημονει ου ζητει τα εαυτης ου παροξυνεται ου λογιζεται το κακον'),
(5527, 46, 'TR1550', 'TR1550', 'el', '1CO', 13, 6, 'NT', 'ου χαιρει επι τη αδικια συγχαιρει δε τη αληθεια'),
(5528, 46, 'TR1550', 'TR1550', 'el', '1CO', 13, 7, 'NT', 'παντα στεγει παντα πιστευει παντα ελπιζει παντα υπομενει'),
(5529, 46, 'TR1550', 'TR1550', 'el', '1CO', 13, 8, 'NT', 'η αγαπη ουδεποτε εκπιπτει ειτε δε προφητειαι καταργηθησονται ειτε γλωσσαι παυσονται ειτε γνωσις καταργηθησεται'),
(5530, 46, 'TR1550', 'TR1550', 'el', '1CO', 13, 9, 'NT', 'εκ μερους γαρ γινωσκομεν και εκ μερους προφητευομεν'),
(5531, 46, 'TR1550', 'TR1550', 'el', '1CO', 13, 10, 'NT', 'οταν δε ελθη το τελειον τοτε το εκ μερους καταργηθησεται'),
(5532, 46, 'TR1550', 'TR1550', 'el', '1CO', 13, 11, 'NT', 'οτε ημην νηπιος ως νηπιος ελαλουν ως νηπιος εφρονουν ως νηπιος ελογιζομην οτε δε γεγονα ανηρ κατηργηκα τα του νηπιου'),
(5533, 46, 'TR1550', 'TR1550', 'el', '1CO', 13, 12, 'NT', 'βλεπομεν γαρ αρτι δι εσοπτρου εν αινιγματι τοτε δε προσωπον προς προσωπον αρτι γινωσκω εκ μερους τοτε δε επιγνωσομαι καθως και επεγνωσθην'),
(5534, 46, 'TR1550', 'TR1550', 'el', '1CO', 13, 13, 'NT', 'νυνι δε μενει πιστις ελπις αγαπη τα τρια ταυτα μειζων δε τουτων η αγαπη'),
(5535, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 1, 'NT', 'διωκετε την αγαπην ζηλουτε δε τα πνευματικα μαλλον δε ινα προφητευητε'),
(5536, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 2, 'NT', 'ο γαρ λαλων γλωσση ουκ ανθρωποις λαλει αλλα τω θεω ουδεις γαρ ακουει πνευματι δε λαλει μυστηρια'),
(5537, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 3, 'NT', 'ο δε προφητευων ανθρωποις λαλει οικοδομην και παρακλησιν και παραμυθιαν'),
(5538, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 4, 'NT', 'ο λαλων γλωσση εαυτον οικοδομει ο δε προφητευων εκκλησιαν οικοδομει'),
(5539, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 5, 'NT', 'θελω δε παντας υμας λαλειν γλωσσαις μαλλον δε ινα προφητευητε μειζων γαρ ο προφητευων η ο λαλων γλωσσαις εκτος ει μη διερμηνευη ινα η εκκλησια οικοδομην λαβη'),
(5540, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 6, 'NT', 'νυνι δε αδελφοι εαν ελθω προς υμας γλωσσαις λαλων τι υμας ωφελησω εαν μη υμιν λαλησω η εν αποκαλυψει η εν γνωσει η εν προφητεια η εν διδαχη'),
(5541, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 7, 'NT', 'ομως τα αψυχα φωνην διδοντα ειτε αυλος ειτε κιθαρα εαν διαστολην τοις φθογγοις μη δω πως γνωσθησεται το αυλουμενον η το κιθαριζομενον'),
(5542, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 8, 'NT', 'και γαρ εαν αδηλον φωνην σαλπιγξ δω τις παρασκευασεται εις πολεμον'),
(5543, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 9, 'NT', 'ουτως και υμεις δια της γλωσσης εαν μη ευσημον λογον δωτε πως γνωσθησεται το λαλουμενον εσεσθε γαρ εις αερα λαλουντες'),
(5544, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 10, 'NT', 'τοσαυτα ει τυχοι γενη φωνων εστιν εν κοσμω και ουδεν αυτων αφωνον'),
(5545, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 11, 'NT', 'εαν ουν μη ειδω την δυναμιν της φωνης εσομαι τω λαλουντι βαρβαρος και ο λαλων εν εμοι βαρβαρος'),
(5546, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 12, 'NT', 'ουτως και υμεις επει ζηλωται εστε πνευματων προς την οικοδομην της εκκλησιας ζητειτε ινα περισσευητε'),
(5547, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 13, 'NT', 'διοπερ ο λαλων γλωσση προσευχεσθω ινα διερμηνευη'),
(5548, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 14, 'NT', 'εαν γαρ προσευχωμαι γλωσση το πνευμα μου προσευχεται ο δε νους μου ακαρπος εστιν'),
(5549, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 15, 'NT', 'τι ουν εστιν προσευξομαι τω πνευματι προσευξομαι δε και τω νοι ψαλω τω πνευματι ψαλω δε και τω νοι'),
(5550, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 16, 'NT', 'επει εαν ευλογησης τω πνευματι ο αναπληρων τον τοπον του ιδιωτου πως ερει το αμην επι τη ση ευχαριστια επειδη τι λεγεις ουκ οιδεν'),
(5551, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 17, 'NT', 'συ μεν γαρ καλως ευχαριστεις αλλ ο ετερος ουκ οικοδομειται'),
(5552, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 18, 'NT', 'ευχαριστω τω θεω μου παντων υμων μαλλον γλωσσαις λαλων'),
(5553, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 19, 'NT', 'αλλ εν εκκλησια θελω πεντε λογους δια του νοος μου λαλησαι ινα και αλλους κατηχησω η μυριους λογους εν γλωσση'),
(5554, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 20, 'NT', 'αδελφοι μη παιδια γινεσθε ταις φρεσιν αλλα τη κακια νηπιαζετε ταις δε φρεσιν τελειοι γινεσθε'),
(5555, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 21, 'NT', 'εν τω νομω γεγραπται οτι εν ετερογλωσσοις και εν χειλεσιν ετεροις λαλησω τω λαω τουτω και ουδ ουτως εισακουσονται μου λεγει κυριος'),
(5556, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 22, 'NT', 'ωστε αι γλωσσαι εις σημειον εισιν ου τοις πιστευουσιν αλλα τοις απιστοις η δε προφητεια ου τοις απιστοις αλλα τοις πιστευουσιν'),
(5557, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 23, 'NT', 'εαν ουν συνελθη η εκκλησια ολη επι το αυτο και παντες γλωσσαις λαλωσιν εισελθωσιν δε ιδιωται η απιστοι ουκ ερουσιν οτι μαινεσθε'),
(5558, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 24, 'NT', 'εαν δε παντες προφητευωσιν εισελθη δε τις απιστος η ιδιωτης ελεγχεται υπο παντων ανακρινεται υπο παντων'),
(5559, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 25, 'NT', 'και ουτως τα κρυπτα της καρδιας αυτου φανερα γινεται και ουτως πεσων επι προσωπον προσκυνησει τω θεω απαγγελλων οτι ο θεος οντως εν υμιν εστιν'),
(5560, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 26, 'NT', 'τι ουν εστιν αδελφοι οταν συνερχησθε εκαστος υμων ψαλμον εχει διδαχην εχει γλωσσαν εχει αποκαλυψιν εχει ερμηνειαν εχει παντα προς οικοδομην γενεσθω'),
(5561, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 27, 'NT', 'ειτε γλωσση τις λαλει κατα δυο η το πλειστον τρεις και ανα μερος και εις διερμηνευετω'),
(5562, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 28, 'NT', 'εαν δε μη η διερμηνευτης σιγατω εν εκκλησια εαυτω δε λαλειτω και τω θεω'),
(5563, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 29, 'NT', 'προφηται δε δυο η τρεις λαλειτωσαν και οι αλλοι διακρινετωσαν'),
(5564, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 30, 'NT', 'εαν δε αλλω αποκαλυφθη καθημενω ο πρωτος σιγατω'),
(5565, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 31, 'NT', 'δυνασθε γαρ καθ ενα παντες προφητευειν ινα παντες μανθανωσιν και παντες παρακαλωνται'),
(5566, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 32, 'NT', 'και πνευματα προφητων προφηταις υποτασσεται'),
(5567, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 33, 'NT', 'ου γαρ εστιν ακαταστασιας ο θεος αλλ ειρηνης ως εν πασαις ταις εκκλησιαις των αγιων'),
(5568, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 34, 'NT', 'αι γυναικες υμων εν ταις εκκλησιαις σιγατωσαν ου γαρ επιτετραπται αυταις λαλειν αλλ υποτασσεσθαι καθως και ο νομος λεγει'),
(5569, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 35, 'NT', 'ει δε τι μαθειν θελουσιν εν οικω τους ιδιους ανδρας επερωτατωσαν αισχρον γαρ εστιν γυναιξιν εν εκκλησια λαλειν'),
(5570, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 36, 'NT', 'η αφ υμων ο λογος του θεου εξηλθεν η εις υμας μονους κατηντησεν'),
(5571, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 37, 'NT', 'ει τις δοκει προφητης ειναι η πνευματικος επιγινωσκετω α γραφω υμιν οτι του κυριου εισιν εντολαι'),
(5572, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 38, 'NT', 'ει δε τις αγνοει αγνοειτω'),
(5573, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 39, 'NT', 'ωστε αδελφοι ζηλουτε το προφητευειν και το λαλειν γλωσσαις μη κωλυετε'),
(5574, 46, 'TR1550', 'TR1550', 'el', '1CO', 14, 40, 'NT', 'παντα ευσχημονως και κατα ταξιν γινεσθω'),
(5575, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 1, 'NT', 'γνωριζω δε υμιν αδελφοι το ευαγγελιον ο ευηγγελισαμην υμιν ο και παρελαβετε εν ω και εστηκατε'),
(5576, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 2, 'NT', 'δι ου και σωζεσθε τινι λογω ευηγγελισαμην υμιν ει κατεχετε εκτος ει μη εικη επιστευσατε'),
(5577, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 3, 'NT', 'παρεδωκα γαρ υμιν εν πρωτοις ο και παρελαβον οτι χριστος απεθανεν υπερ των αμαρτιων ημων κατα τας γραφας'),
(5578, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 4, 'NT', 'και οτι εταφη και οτι εγηγερται τη τριτη ημερα κατα τας γραφας'),
(5579, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 5, 'NT', 'και οτι ωφθη κηφα ειτα τοις δωδεκα'),
(5580, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 6, 'NT', 'επειτα ωφθη επανω πεντακοσιοις αδελφοις εφαπαξ εξ ων οι πλειους μενουσιν εως αρτι τινες δε και εκοιμηθησαν'),
(5581, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 7, 'NT', 'επειτα ωφθη ιακωβω ειτα τοις αποστολοις πασιν'),
(5582, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 8, 'NT', 'εσχατον δε παντων ωσπερει τω εκτρωματι ωφθη καμοι'),
(5583, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 9, 'NT', 'εγω γαρ ειμι ο ελαχιστος των αποστολων ος ουκ ειμι ικανος καλεισθαι αποστολος διοτι εδιωξα την εκκλησιαν του θεου'),
(5584, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 10, 'NT', 'χαριτι δε θεου ειμι ο ειμι και η χαρις αυτου η εις εμε ου κενη εγενηθη αλλα περισσοτερον αυτων παντων εκοπιασα ουκ εγω δε αλλ η χαρις του θεου η συν εμοι'),
(5585, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 11, 'NT', 'ειτε ουν εγω ειτε εκεινοι ουτως κηρυσσομεν και ουτως επιστευσατε'),
(5586, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 12, 'NT', 'ει δε χριστος κηρυσσεται οτι εκ νεκρων εγηγερται πως λεγουσιν τινες εν υμιν οτι αναστασις νεκρων ουκ εστιν'),
(5587, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 13, 'NT', 'ει δε αναστασις νεκρων ουκ εστιν ουδε χριστος εγηγερται'),
(5588, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 14, 'NT', 'ει δε χριστος ουκ εγηγερται κενον αρα το κηρυγμα ημων κενη δε και η πιστις υμων'),
(5589, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 15, 'NT', 'ευρισκομεθα δε και ψευδομαρτυρες του θεου οτι εμαρτυρησαμεν κατα του θεου οτι ηγειρεν τον χριστον ον ουκ ηγειρεν ειπερ αρα νεκροι ουκ εγειρονται'),
(5590, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 16, 'NT', 'ει γαρ νεκροι ουκ εγειρονται ουδε χριστος εγηγερται'),
(5591, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 17, 'NT', 'ει δε χριστος ουκ εγηγερται ματαια η πιστις υμων ετι εστε εν ταις αμαρτιαις υμων'),
(5592, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 18, 'NT', 'αρα και οι κοιμηθεντες εν χριστω απωλοντο'),
(5593, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 19, 'NT', 'ει εν τη ζωη ταυτη ηλπικοτες εσμεν εν χριστω μονον ελεεινοτεροι παντων ανθρωπων εσμεν'),
(5594, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 20, 'NT', 'νυνι δε χριστος εγηγερται εκ νεκρων απαρχη των κεκοιμημενων εγενετο'),
(5595, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 21, 'NT', 'επειδη γαρ δι ανθρωπου ο θανατος και δι ανθρωπου αναστασις νεκρων'),
(5596, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 22, 'NT', 'ωσπερ γαρ εν τω αδαμ παντες αποθνησκουσιν ουτως και εν τω χριστω παντες ζωοποιηθησονται'),
(5597, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 23, 'NT', 'εκαστος δε εν τω ιδιω ταγματι απαρχη χριστος επειτα οι χριστου εν τη παρουσια αυτου'),
(5598, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 24, 'NT', 'ειτα το τελος οταν παραδω την βασιλειαν τω θεω και πατρι οταν καταργηση πασαν αρχην και πασαν εξουσιαν και δυναμιν'),
(5599, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 25, 'NT', 'δει γαρ αυτον βασιλευειν αχρις ου αν θη παντας τους εχθρους υπο τους ποδας αυτου'),
(5600, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 26, 'NT', 'εσχατος εχθρος καταργειται ο θανατος'),
(5601, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 27, 'NT', 'παντα γαρ υπεταξεν υπο τους ποδας αυτου οταν δε ειπη οτι παντα υποτετακται δηλον οτι εκτος του υποταξαντος αυτω τα παντα'),
(5602, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 28, 'NT', 'οταν δε υποταγη αυτω τα παντα τοτε και αυτος ο υιος υποταγησεται τω υποταξαντι αυτω τα παντα ινα η ο θεος τα παντα εν πασιν'),
(5603, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 29, 'NT', 'επει τι ποιησουσιν οι βαπτιζομενοι υπερ των νεκρων ει ολως νεκροι ουκ εγειρονται τι και βαπτιζονται υπερ των νεκρων'),
(5604, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 30, 'NT', 'τι και ημεις κινδυνευομεν πασαν ωραν'),
(5605, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 31, 'NT', 'καθ ημεραν αποθνησκω νη την ημετεραν καυχησιν ην εχω εν χριστω ιησου τω κυριω ημων'),
(5606, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 32, 'NT', 'ει κατα ανθρωπον εθηριομαχησα εν εφεσω τι μοι το οφελος ει νεκροι ουκ εγειρονται φαγωμεν και πιωμεν αυριον γαρ αποθνησκομεν'),
(5607, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 33, 'NT', 'μη πλανασθε φθειρουσιν ηθη χρησθ ομιλιαι κακαι'),
(5608, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 34, 'NT', 'εκνηψατε δικαιως και μη αμαρτανετε αγνωσιαν γαρ θεου τινες εχουσιν προς εντροπην υμιν λεγω'),
(5609, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 35, 'NT', 'αλλ ερει τις πως εγειρονται οι νεκροι ποιω δε σωματι ερχονται'),
(5610, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 36, 'NT', 'αφρον συ ο σπειρεις ου ζωοποιειται εαν μη αποθανη'),
(5611, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 37, 'NT', 'και ο σπειρεις ου το σωμα το γενησομενον σπειρεις αλλα γυμνον κοκκον ει τυχοι σιτου η τινος των λοιπων'),
(5612, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 38, 'NT', 'ο δε θεος αυτω διδωσιν σωμα καθως ηθελησεν και εκαστω των σπερματων το ιδιον σωμα'),
(5613, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 39, 'NT', 'ου πασα σαρξ η αυτη σαρξ αλλα αλλη μεν σαρξ ανθρωπων αλλη δε σαρξ κτηνων αλλη δε ιχθυων αλλη δε πτηνων'),
(5614, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 40, 'NT', 'και σωματα επουρανια και σωματα επιγεια αλλ ετερα μεν η των επουρανιων δοξα ετερα δε η των επιγειων'),
(5615, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 41, 'NT', 'αλλη δοξα ηλιου και αλλη δοξα σεληνης και αλλη δοξα αστερων αστηρ γαρ αστερος διαφερει εν δοξη'),
(5616, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 42, 'NT', 'ουτως και η αναστασις των νεκρων σπειρεται εν φθορα εγειρεται εν αφθαρσια'),
(5617, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 43, 'NT', 'σπειρεται εν ατιμια εγειρεται εν δοξη σπειρεται εν ασθενεια εγειρεται εν δυναμει'),
(5618, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 44, 'NT', 'σπειρεται σωμα ψυχικον εγειρεται σωμα πνευματικον εστιν σωμα ψυχικον και εστιν σωμα πνευματικον'),
(5619, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 45, 'NT', 'ουτως και γεγραπται εγενετο ο πρωτος ανθρωπος αδαμ εις ψυχην ζωσαν ο εσχατος αδαμ εις πνευμα ζωοποιουν'),
(5620, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 46, 'NT', 'αλλ ου πρωτον το πνευματικον αλλα το ψυχικον επειτα το πνευματικον'),
(5621, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 47, 'NT', 'ο πρωτος ανθρωπος εκ γης χοικος ο δευτερος ανθρωπος ο κυριος εξ ουρανου'),
(5622, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 48, 'NT', 'οιος ο χοικος τοιουτοι και οι χοικοι και οιος ο επουρανιος τοιουτοι και οι επουρανιοι'),
(5623, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 49, 'NT', 'και καθως εφορεσαμεν την εικονα του χοικου φορεσομεν και την εικονα του επουρανιου'),
(5624, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 50, 'NT', 'τουτο δε φημι αδελφοι οτι σαρξ και αιμα βασιλειαν θεου κληρονομησαι ου δυνανται ουδε η φθορα την αφθαρσιαν κληρονομει'),
(5625, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 51, 'NT', 'ιδου μυστηριον υμιν λεγω παντες μεν ου κοιμηθησομεθα παντες δε αλλαγησομεθα'),
(5626, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 52, 'NT', 'εν ατομω εν ριπη οφθαλμου εν τη εσχατη σαλπιγγι σαλπισει γαρ και οι νεκροι εγερθησονται αφθαρτοι και ημεις αλλαγησομεθα'),
(5627, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 53, 'NT', 'δει γαρ το φθαρτον τουτο ενδυσασθαι αφθαρσιαν και το θνητον τουτο ενδυσασθαι αθανασιαν'),
(5628, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 54, 'NT', 'οταν δε το φθαρτον τουτο ενδυσηται αφθαρσιαν και το θνητον τουτο ενδυσηται αθανασιαν τοτε γενησεται ο λογος ο γεγραμμενος κατεποθη ο θανατος εις νικος'),
(5629, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 55, 'NT', 'που σου θανατε το κεντρον που σου αδη το νικος'),
(5630, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 56, 'NT', 'το δε κεντρον του θανατου η αμαρτια η δε δυναμις της αμαρτιας ο νομος'),
(5631, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 57, 'NT', 'τω δε θεω χαρις τω διδοντι ημιν το νικος δια του κυριου ημων ιησου χριστου'),
(5632, 46, 'TR1550', 'TR1550', 'el', '1CO', 15, 58, 'NT', 'ωστε αδελφοι μου αγαπητοι εδραιοι γινεσθε αμετακινητοι περισσευοντες εν τω εργω του κυριου παντοτε ειδοτες οτι ο κοπος υμων ουκ εστιν κενος εν κυριω'),
(5633, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 1, 'NT', 'περι δε της λογιας της εις τους αγιους ωσπερ διεταξα ταις εκκλησιαις της γαλατιας ουτως και υμεις ποιησατε'),
(5634, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 2, 'NT', 'κατα μιαν σαββατων εκαστος υμων παρ εαυτω τιθετω θησαυριζων ο τι αν ευοδωται ινα μη οταν ελθω τοτε λογιαι γινωνται'),
(5635, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 3, 'NT', 'οταν δε παραγενωμαι ους εαν δοκιμασητε δι επιστολων τουτους πεμψω απενεγκειν την χαριν υμων εις ιερουσαλημ'),
(5636, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 4, 'NT', 'εαν δε η αξιον του καμε πορευεσθαι συν εμοι πορευσονται'),
(5637, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 5, 'NT', 'ελευσομαι δε προς υμας οταν μακεδονιαν διελθω μακεδονιαν γαρ διερχομαι'),
(5638, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 6, 'NT', 'προς υμας δε τυχον παραμενω η και παραχειμασω ινα υμεις με προπεμψητε ου εαν πορευωμαι'),
(5639, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 7, 'NT', 'ου θελω γαρ υμας αρτι εν παροδω ιδειν ελπιζω δε χρονον τινα επιμειναι προς υμας εαν ο κυριος επιτρεπη'),
(5640, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 8, 'NT', 'επιμενω δε εν εφεσω εως της πεντηκοστης'),
(5641, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 9, 'NT', 'θυρα γαρ μοι ανεωγεν μεγαλη και ενεργης και αντικειμενοι πολλοι'),
(5642, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 10, 'NT', 'εαν δε ελθη τιμοθεος βλεπετε ινα αφοβως γενηται προς υμας το γαρ εργον κυριου εργαζεται ως και εγω'),
(5643, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 11, 'NT', 'μη τις ουν αυτον εξουθενηση προπεμψατε δε αυτον εν ειρηνη ινα ελθη προς με εκδεχομαι γαρ αυτον μετα των αδελφων'),
(5644, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 12, 'NT', 'περι δε απολλω του αδελφου πολλα παρεκαλεσα αυτον ινα ελθη προς υμας μετα των αδελφων και παντως ουκ ην θελημα ινα νυν ελθη ελευσεται δε οταν ευκαιρηση'),
(5645, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 13, 'NT', 'γρηγορειτε στηκετε εν τη πιστει ανδριζεσθε κραταιουσθε'),
(5646, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 14, 'NT', 'παντα υμων εν αγαπη γινεσθω'),
(5647, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 15, 'NT', 'παρακαλω δε υμας αδελφοι οιδατε την οικιαν στεφανα οτι εστιν απαρχη της αχαιας και εις διακονιαν τοις αγιοις εταξαν εαυτους'),
(5648, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 16, 'NT', 'ινα και υμεις υποτασσησθε τοις τοιουτοις και παντι τω συνεργουντι και κοπιωντι'),
(5649, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 17, 'NT', 'χαιρω δε επι τη παρουσια στεφανα και φουρτουνατου και αχαικου οτι το υμων υστερημα ουτοι ανεπληρωσαν'),
(5650, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 18, 'NT', 'ανεπαυσαν γαρ το εμον πνευμα και το υμων επιγινωσκετε ουν τους τοιουτους'),
(5651, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 19, 'NT', 'ασπαζονται υμας αι εκκλησιαι της ασιας ασπαζονται υμας εν κυριω πολλα ακυλας και πρισκιλλα συν τη κατ οικον αυτων εκκλησια'),
(5652, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 20, 'NT', 'ασπαζονται υμας οι αδελφοι παντες ασπασασθε αλληλους εν φιληματι αγιω'),
(5653, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 21, 'NT', 'ο ασπασμος τη εμη χειρι παυλου'),
(5654, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 22, 'NT', 'ει τις ου φιλει τον κυριον ιησουν χριστον ητω αναθεμα μαραν αθα'),
(5655, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 23, 'NT', 'η χαρις του κυριου ιησου χριστου μεθ υμων'),
(5656, 46, 'TR1550', 'TR1550', 'el', '1CO', 16, 24, 'NT', 'η αγαπη μου μετα παντων υμων εν χριστω ιησου αμην [προς κορινθιους πρωτη εγραφη απο φιλιππων δια στεφανα και φουρτουνατου και αχαικου και τιμοθεου]'),
(5657, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 1, 'NT', 'παυλος αποστολος ιησου χριστου δια θεληματος θεου και τιμοθεος ο αδελφος τη εκκλησια του θεου τη ουση εν κορινθω συν τοις αγιοις πασιν τοις ουσιν εν ολη τη αχαια'),
(5658, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 2, 'NT', 'χαρις υμιν και ειρηνη απο θεου πατρος ημων και κυριου ιησου χριστου'),
(5659, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 3, 'NT', 'ευλογητος ο θεος και πατηρ του κυριου ημων ιησου χριστου ο πατηρ των οικτιρμων και θεος πασης παρακλησεως'),
(5660, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 4, 'NT', 'ο παρακαλων ημας επι παση τη θλιψει ημων εις το δυνασθαι ημας παρακαλειν τους εν παση θλιψει δια της παρακλησεως ης παρακαλουμεθα αυτοι υπο του θεου'),
(5661, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 5, 'NT', 'οτι καθως περισσευει τα παθηματα του χριστου εις ημας ουτως δια χριστου περισσευει και η παρακλησις ημων'),
(5662, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 6, 'NT', 'ειτε δε θλιβομεθα υπερ της υμων παρακλησεως και σωτηριας της ενεργουμενης εν υπομονη των αυτων παθηματων ων και ημεις πασχομεν ειτε παρακαλουμεθα υπερ της υμων παρακλησεως και σωτηριας και η ελπις ημων βεβαια υπερ υμων'),
(5663, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 7, 'NT', 'ειδοτες οτι ωσπερ κοινωνοι εστε των παθηματων ουτως και της παρακλησεως'),
(5664, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 8, 'NT', 'ου γαρ θελομεν υμας αγνοειν αδελφοι υπερ της θλιψεως ημων της γενομενης ημιν εν τη ασια οτι καθ υπερβολην εβαρηθημεν υπερ δυναμιν ωστε εξαπορηθηναι ημας και του ζην'),
(5665, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 9, 'NT', 'αλλα αυτοι εν εαυτοις το αποκριμα του θανατου εσχηκαμεν ινα μη πεποιθοτες ωμεν εφ εαυτοις αλλ επι τω θεω τω εγειροντι τους νεκρους'),
(5666, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 10, 'NT', 'ος εκ τηλικουτου θανατου ερρυσατο ημας και ρυεται εις ον ηλπικαμεν οτι και ετι ρυσεται'),
(5667, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 11, 'NT', 'συνυπουργουντων και υμων υπερ ημων τη δεησει ινα εκ πολλων προσωπων το εις ημας χαρισμα δια πολλων ευχαριστηθη υπερ ημων'),
(5668, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 12, 'NT', 'η γαρ καυχησις ημων αυτη εστιν το μαρτυριον της συνειδησεως ημων οτι εν απλοτητι και ειλικρινεια θεου ουκ εν σοφια σαρκικη αλλ εν χαριτι θεου ανεστραφημεν εν τω κοσμω περισσοτερως δε προς υμας'),
(5669, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 13, 'NT', 'ου γαρ αλλα γραφομεν υμιν αλλ η α αναγινωσκετε η και επιγινωσκετε ελπιζω δε οτι και εως τελους επιγνωσεσθε'),
(5670, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 14, 'NT', 'καθως και επεγνωτε ημας απο μερους οτι καυχημα υμων εσμεν καθαπερ και υμεις ημων εν τη ημερα του κυριου ιησου'),
(5671, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 15, 'NT', 'και ταυτη τη πεποιθησει εβουλομην προς υμας ελθειν προτερον ινα δευτεραν χαριν εχητε'),
(5672, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 16, 'NT', 'και δι υμων διελθειν εις μακεδονιαν και παλιν απο μακεδονιας ελθειν προς υμας και υφ υμων προπεμφθηναι εις την ιουδαιαν'),
(5673, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 17, 'NT', 'τουτο ουν βουλευομενος μη τι αρα τη ελαφρια εχρησαμην η α βουλευομαι κατα σαρκα βουλευομαι ινα η παρ εμοι το ναι ναι και το ου ου'),
(5674, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 18, 'NT', 'πιστος δε ο θεος οτι ο λογος ημων ο προς υμας ουκ εγενετο ναι και ου'),
(5675, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 19, 'NT', 'ο γαρ του θεου υιος ιησους χριστος ο εν υμιν δι ημων κηρυχθεις δι εμου και σιλουανου και τιμοθεου ουκ εγενετο ναι και ου αλλα ναι εν αυτω γεγονεν'),
(5676, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 20, 'NT', 'οσαι γαρ επαγγελιαι θεου εν αυτω το ναι και εν αυτω το αμην τω θεω προς δοξαν δι ημων'),
(5677, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 21, 'NT', 'ο δε βεβαιων ημας συν υμιν εις χριστον και χρισας ημας θεος'),
(5678, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 22, 'NT', 'ο και σφραγισαμενος ημας και δους τον αρραβωνα του πνευματος εν ταις καρδιαις ημων'),
(5679, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 23, 'NT', 'εγω δε μαρτυρα τον θεον επικαλουμαι επι την εμην ψυχην οτι φειδομενος υμων ουκετι ηλθον εις κορινθον'),
(5680, 47, 'TR1550', 'TR1550', 'el', '2CO', 1, 24, 'NT', 'ουχ οτι κυριευομεν υμων της πιστεως αλλα συνεργοι εσμεν της χαρας υμων τη γαρ πιστει εστηκατε'),
(5681, 47, 'TR1550', 'TR1550', 'el', '2CO', 2, 1, 'NT', 'εκρινα δε εμαυτω τουτο το μη παλιν ελθειν εν λυπη προς υμας'),
(5682, 47, 'TR1550', 'TR1550', 'el', '2CO', 2, 2, 'NT', 'ει γαρ εγω λυπω υμας και τις εστιν ο ευφραινων με ει μη ο λυπουμενος εξ εμου'),
(5683, 47, 'TR1550', 'TR1550', 'el', '2CO', 2, 3, 'NT', 'και εγραψα υμιν τουτο αυτο ινα μη ελθων λυπην εχω αφ ων εδει με χαιρειν πεποιθως επι παντας υμας οτι η εμη χαρα παντων υμων εστιν'),
(5684, 47, 'TR1550', 'TR1550', 'el', '2CO', 2, 4, 'NT', 'εκ γαρ πολλης θλιψεως και συνοχης καρδιας εγραψα υμιν δια πολλων δακρυων ουχ ινα λυπηθητε αλλα την αγαπην ινα γνωτε ην εχω περισσοτερως εις υμας'),
(5685, 47, 'TR1550', 'TR1550', 'el', '2CO', 2, 5, 'NT', 'ει δε τις λελυπηκεν ουκ εμε λελυπηκεν αλλ απο μερους ινα μη επιβαρω παντας υμας'),
(5686, 47, 'TR1550', 'TR1550', 'el', '2CO', 2, 6, 'NT', 'ικανον τω τοιουτω η επιτιμια αυτη η υπο των πλειονων'),
(5687, 47, 'TR1550', 'TR1550', 'el', '2CO', 2, 7, 'NT', 'ωστε τουναντιον μαλλον υμας χαρισασθαι και παρακαλεσαι μηπως τη περισσοτερα λυπη καταποθη ο τοιουτος'),
(5688, 47, 'TR1550', 'TR1550', 'el', '2CO', 2, 8, 'NT', 'διο παρακαλω υμας κυρωσαι εις αυτον αγαπην'),
(5689, 47, 'TR1550', 'TR1550', 'el', '2CO', 2, 9, 'NT', 'εις τουτο γαρ και εγραψα ινα γνω την δοκιμην υμων ει εις παντα υπηκοοι εστε'),
(5690, 47, 'TR1550', 'TR1550', 'el', '2CO', 2, 10, 'NT', 'ω δε τι χαριζεσθε και εγω και γαρ εγω ει τι κεχαρισμαι ω κεχαρισμαι δι υμας εν προσωπω χριστου'),
(5691, 47, 'TR1550', 'TR1550', 'el', '2CO', 2, 11, 'NT', 'ινα μη πλεονεκτηθωμεν υπο του σατανα ου γαρ αυτου τα νοηματα αγνοουμεν'),
(5692, 47, 'TR1550', 'TR1550', 'el', '2CO', 2, 12, 'NT', 'ελθων δε εις την τρωαδα εις το ευαγγελιον του χριστου και θυρας μοι ανεωγμενης εν κυριω'),
(5693, 47, 'TR1550', 'TR1550', 'el', '2CO', 2, 13, 'NT', 'ουκ εσχηκα ανεσιν τω πνευματι μου τω μη ευρειν με τιτον τον αδελφον μου αλλα αποταξαμενος αυτοις εξηλθον εις μακεδονιαν'),
(5694, 47, 'TR1550', 'TR1550', 'el', '2CO', 2, 14, 'NT', 'τω δε θεω χαρις τω παντοτε θριαμβευοντι ημας εν τω χριστω και την οσμην της γνωσεως αυτου φανερουντι δι ημων εν παντι τοπω'),
(5695, 47, 'TR1550', 'TR1550', 'el', '2CO', 2, 15, 'NT', 'οτι χριστου ευωδια εσμεν τω θεω εν τοις σωζομενοις και εν τοις απολλυμενοις'),
(5696, 47, 'TR1550', 'TR1550', 'el', '2CO', 2, 16, 'NT', 'οις μεν οσμη θανατου εις θανατον οις δε οσμη ζωης εις ζωην και προς ταυτα τις ικανος'),
(5697, 47, 'TR1550', 'TR1550', 'el', '2CO', 2, 17, 'NT', 'ου γαρ εσμεν ως οι πολλοι καπηλευοντες τον λογον του θεου αλλ ως εξ ειλικρινειας αλλ ως εκ θεου κατενωπιον του θεου εν χριστω λαλουμεν'),
(5698, 47, 'TR1550', 'TR1550', 'el', '2CO', 3, 1, 'NT', 'αρχομεθα παλιν εαυτους συνιστανειν ει μη χρηζομεν ως τινες συστατικων επιστολων προς υμας η εξ υμων συστατικων'),
(5699, 47, 'TR1550', 'TR1550', 'el', '2CO', 3, 2, 'NT', 'η επιστολη ημων υμεις εστε εγγεγραμμενη εν ταις καρδιαις ημων γινωσκομενη και αναγινωσκομενη υπο παντων ανθρωπων'),
(5700, 47, 'TR1550', 'TR1550', 'el', '2CO', 3, 3, 'NT', 'φανερουμενοι οτι εστε επιστολη χριστου διακονηθεισα υφ ημων εγγεγραμμενη ου μελανι αλλα πνευματι θεου ζωντος ουκ εν πλαξιν λιθιναις αλλ εν πλαξιν καρδιας σαρκιναις'),
(5701, 47, 'TR1550', 'TR1550', 'el', '2CO', 3, 4, 'NT', 'πεποιθησιν δε τοιαυτην εχομεν δια του χριστου προς τον θεον'),
(5702, 47, 'TR1550', 'TR1550', 'el', '2CO', 3, 5, 'NT', 'ουχ οτι ικανοι εσμεν αφ εαυτων λογισασθαι τι ως εξ εαυτων αλλ η ικανοτης ημων εκ του θεου'),
(5703, 47, 'TR1550', 'TR1550', 'el', '2CO', 3, 6, 'NT', 'ος και ικανωσεν ημας διακονους καινης διαθηκης ου γραμματος αλλα πνευματος το γαρ γραμμα αποκτεινει το δε πνευμα ζωοποιει'),
(5704, 47, 'TR1550', 'TR1550', 'el', '2CO', 3, 7, 'NT', 'ει δε η διακονια του θανατου εν γραμμασιν εντετυπωμενη εν λιθοις εγενηθη εν δοξη ωστε μη δυνασθαι ατενισαι τους υιους ισραηλ εις το προσωπον μωσεως δια την δοξαν του προσωπου αυτου την καταργουμενην'),
(5705, 47, 'TR1550', 'TR1550', 'el', '2CO', 3, 8, 'NT', 'πως ουχι μαλλον η διακονια του πνευματος εσται εν δοξη'),
(5706, 47, 'TR1550', 'TR1550', 'el', '2CO', 3, 9, 'NT', 'ει γαρ η διακονια της κατακρισεως δοξα πολλω μαλλον περισσευει η διακονια της δικαιοσυνης εν δοξη'),
(5707, 47, 'TR1550', 'TR1550', 'el', '2CO', 3, 10, 'NT', 'και γαρ ουδε δεδοξασται το δεδοξασμενον εν τουτω τω μερει ενεκεν της υπερβαλλουσης δοξης'),
(5708, 47, 'TR1550', 'TR1550', 'el', '2CO', 3, 11, 'NT', 'ει γαρ το καταργουμενον δια δοξης πολλω μαλλον το μενον εν δοξη'),
(5709, 47, 'TR1550', 'TR1550', 'el', '2CO', 3, 12, 'NT', 'εχοντες ουν τοιαυτην ελπιδα πολλη παρρησια χρωμεθα'),
(5710, 47, 'TR1550', 'TR1550', 'el', '2CO', 3, 13, 'NT', 'και ου καθαπερ μωσης ετιθει καλυμμα επι το προσωπον εαυτου προς το μη ατενισαι τους υιους ισραηλ εις το τελος του καταργουμενου'),
(5711, 47, 'TR1550', 'TR1550', 'el', '2CO', 3, 14, 'NT', 'αλλ επωρωθη τα νοηματα αυτων αχρι γαρ της σημερον το αυτο καλυμμα επι τη αναγνωσει της παλαιας διαθηκης μενει μη ανακαλυπτομενον ο τι εν χριστω καταργειται'),
(5712, 47, 'TR1550', 'TR1550', 'el', '2CO', 3, 15, 'NT', 'αλλ εως σημερον ηνικα αναγινωσκεται μωσης καλυμμα επι την καρδιαν αυτων κειται'),
(5713, 47, 'TR1550', 'TR1550', 'el', '2CO', 3, 16, 'NT', 'ηνικα δ αν επιστρεψη προς κυριον περιαιρειται το καλυμμα'),
(5714, 47, 'TR1550', 'TR1550', 'el', '2CO', 3, 17, 'NT', 'ο δε κυριος το πνευμα εστιν ου δε το πνευμα κυριου εκει ελευθερια'),
(5715, 47, 'TR1550', 'TR1550', 'el', '2CO', 3, 18, 'NT', 'ημεις δε παντες ανακεκαλυμμενω προσωπω την δοξαν κυριου κατοπτριζομενοι την αυτην εικονα μεταμορφουμεθα απο δοξης εις δοξαν καθαπερ απο κυριου πνευματος'),
(5716, 47, 'TR1550', 'TR1550', 'el', '2CO', 4, 1, 'NT', 'δια τουτο εχοντες την διακονιαν ταυτην καθως ηλεηθημεν ουκ εκκακουμεν'),
(5717, 47, 'TR1550', 'TR1550', 'el', '2CO', 4, 2, 'NT', 'αλλ απειπαμεθα τα κρυπτα της αισχυνης μη περιπατουντες εν πανουργια μηδε δολουντες τον λογον του θεου αλλα τη φανερωσει της αληθειας συνιστωντες εαυτους προς πασαν συνειδησιν ανθρωπων ενωπιον του θεου'),
(5718, 47, 'TR1550', 'TR1550', 'el', '2CO', 4, 3, 'NT', 'ει δε και εστιν κεκαλυμμενον το ευαγγελιον ημων εν τοις απολλυμενοις εστιν κεκαλυμμενον'),
(5719, 47, 'TR1550', 'TR1550', 'el', '2CO', 4, 4, 'NT', 'εν οις ο θεος του αιωνος τουτου ετυφλωσεν τα νοηματα των απιστων εις το μη αυγασαι αυτοις τον φωτισμον του ευαγγελιου της δοξης του χριστου ος εστιν εικων του θεου'),
(5720, 47, 'TR1550', 'TR1550', 'el', '2CO', 4, 5, 'NT', 'ου γαρ εαυτους κηρυσσομεν αλλα χριστον ιησουν κυριον εαυτους δε δουλους υμων δια ιησουν'),
(5721, 47, 'TR1550', 'TR1550', 'el', '2CO', 4, 6, 'NT', 'οτι ο θεος ο ειπων εκ σκοτους φως λαμψαι ος ελαμψεν εν ταις καρδιαις ημων προς φωτισμον της γνωσεως της δοξης του θεου εν προσωπω ιησου χριστου'),
(5722, 47, 'TR1550', 'TR1550', 'el', '2CO', 4, 7, 'NT', 'εχομεν δε τον θησαυρον τουτον εν οστρακινοις σκευεσιν ινα η υπερβολη της δυναμεως η του θεου και μη εξ ημων'),
(5723, 47, 'TR1550', 'TR1550', 'el', '2CO', 4, 8, 'NT', 'εν παντι θλιβομενοι αλλ ου στενοχωρουμενοι απορουμενοι αλλ ουκ εξαπορουμενοι'),
(5724, 47, 'TR1550', 'TR1550', 'el', '2CO', 4, 9, 'NT', 'διωκομενοι αλλ ουκ εγκαταλειπομενοι καταβαλλομενοι αλλ ουκ απολλυμενοι'),
(5725, 47, 'TR1550', 'TR1550', 'el', '2CO', 4, 10, 'NT', 'παντοτε την νεκρωσιν του κυριου ιησου εν τω σωματι περιφεροντες ινα και η ζωη του ιησου εν τω σωματι ημων φανερωθη'),
(5726, 47, 'TR1550', 'TR1550', 'el', '2CO', 4, 11, 'NT', 'αει γαρ ημεις οι ζωντες εις θανατον παραδιδομεθα δια ιησουν ινα και η ζωη του ιησου φανερωθη εν τη θνητη σαρκι ημων'),
(5727, 47, 'TR1550', 'TR1550', 'el', '2CO', 4, 12, 'NT', 'ωστε ο μεν θανατος εν ημιν ενεργειται η δε ζωη εν υμιν'),
(5728, 47, 'TR1550', 'TR1550', 'el', '2CO', 4, 13, 'NT', 'εχοντες δε το αυτο πνευμα της πιστεως κατα το γεγραμμενον επιστευσα διο ελαλησα και ημεις πιστευομεν διο και λαλουμεν'),
(5729, 47, 'TR1550', 'TR1550', 'el', '2CO', 4, 14, 'NT', 'ειδοτες οτι ο εγειρας τον κυριον ιησουν και ημας δια ιησου εγερει και παραστησει συν υμιν'),
(5730, 47, 'TR1550', 'TR1550', 'el', '2CO', 4, 15, 'NT', 'τα γαρ παντα δι υμας ινα η χαρις πλεονασασα δια των πλειονων την ευχαριστιαν περισσευση εις την δοξαν του θεου'),
(5731, 47, 'TR1550', 'TR1550', 'el', '2CO', 4, 16, 'NT', 'διο ουκ εκκακουμεν αλλ ει και ο εξω ημων ανθρωπος διαφθειρεται αλλ ο εσωθεν ανακαινουται ημερα και ημερα'),
(5732, 47, 'TR1550', 'TR1550', 'el', '2CO', 4, 17, 'NT', 'το γαρ παραυτικα ελαφρον της θλιψεως ημων καθ υπερβολην εις υπερβολην αιωνιον βαρος δοξης κατεργαζεται ημιν'),
(5733, 47, 'TR1550', 'TR1550', 'el', '2CO', 4, 18, 'NT', 'μη σκοπουντων ημων τα βλεπομενα αλλα τα μη βλεπομενα τα γαρ βλεπομενα προσκαιρα τα δε μη βλεπομενα αιωνια'),
(5734, 47, 'TR1550', 'TR1550', 'el', '2CO', 5, 1, 'NT', 'οιδαμεν γαρ οτι εαν η επιγειος ημων οικια του σκηνους καταλυθη οικοδομην εκ θεου εχομεν οικιαν αχειροποιητον αιωνιον εν τοις ουρανοις'),
(5735, 47, 'TR1550', 'TR1550', 'el', '2CO', 5, 2, 'NT', 'και γαρ εν τουτω στεναζομεν το οικητηριον ημων το εξ ουρανου επενδυσασθαι επιποθουντες'),
(5736, 47, 'TR1550', 'TR1550', 'el', '2CO', 5, 3, 'NT', 'ειγε και ενδυσαμενοι ου γυμνοι ευρεθησομεθα'),
(5737, 47, 'TR1550', 'TR1550', 'el', '2CO', 5, 4, 'NT', 'και γαρ οι οντες εν τω σκηνει στεναζομεν βαρουμενοι επειδη ου θελομεν εκδυσασθαι αλλ επενδυσασθαι ινα καταποθη το θνητον υπο της ζωης'),
(5738, 47, 'TR1550', 'TR1550', 'el', '2CO', 5, 5, 'NT', 'ο δε κατεργασαμενος ημας εις αυτο τουτο θεος ο και δους ημιν τον αρραβωνα του πνευματος'),
(5739, 47, 'TR1550', 'TR1550', 'el', '2CO', 5, 6, 'NT', 'θαρρουντες ουν παντοτε και ειδοτες οτι ενδημουντες εν τω σωματι εκδημουμεν απο του κυριου'),
(5740, 47, 'TR1550', 'TR1550', 'el', '2CO', 5, 7, 'NT', 'δια πιστεως γαρ περιπατουμεν ου δια ειδους'),
(5741, 47, 'TR1550', 'TR1550', 'el', '2CO', 5, 8, 'NT', 'θαρρουμεν δε και ευδοκουμεν μαλλον εκδημησαι εκ του σωματος και ενδημησαι προς τον κυριον'),
(5742, 47, 'TR1550', 'TR1550', 'el', '2CO', 5, 9, 'NT', 'διο και φιλοτιμουμεθα ειτε ενδημουντες ειτε εκδημουντες ευαρεστοι αυτω ειναι'),
(5743, 47, 'TR1550', 'TR1550', 'el', '2CO', 5, 10, 'NT', 'τους γαρ παντας ημας φανερωθηναι δει εμπροσθεν του βηματος του χριστου ινα κομισηται εκαστος τα δια του σωματος προς α επραξεν ειτε αγαθον ειτε κακον'),
(5744, 47, 'TR1550', 'TR1550', 'el', '2CO', 5, 11, 'NT', 'ειδοτες ουν τον φοβον του κυριου ανθρωπους πειθομεν θεω δε πεφανερωμεθα ελπιζω δε και εν ταις συνειδησεσιν υμων πεφανερωσθαι'),
(5745, 47, 'TR1550', 'TR1550', 'el', '2CO', 5, 12, 'NT', 'ου γαρ παλιν εαυτους συνιστανομεν υμιν αλλα αφορμην διδοντες υμιν καυχηματος υπερ ημων ινα εχητε προς τους εν προσωπω καυχωμενους και ου καρδια'),
(5746, 47, 'TR1550', 'TR1550', 'el', '2CO', 5, 13, 'NT', 'ειτε γαρ εξεστημεν θεω ειτε σωφρονουμεν υμιν'),
(5747, 47, 'TR1550', 'TR1550', 'el', '2CO', 5, 14, 'NT', 'η γαρ αγαπη του χριστου συνεχει ημας κριναντας τουτο οτι ει εις υπερ παντων απεθανεν αρα οι παντες απεθανον'),
(5748, 47, 'TR1550', 'TR1550', 'el', '2CO', 5, 15, 'NT', 'και υπερ παντων απεθανεν ινα οι ζωντες μηκετι εαυτοις ζωσιν αλλα τω υπερ αυτων αποθανοντι και εγερθεντι'),
(5749, 47, 'TR1550', 'TR1550', 'el', '2CO', 5, 16, 'NT', 'ωστε ημεις απο του νυν ουδενα οιδαμεν κατα σαρκα ει δε και εγνωκαμεν κατα σαρκα χριστον αλλα νυν ουκετι γινωσκομεν'),
(5750, 47, 'TR1550', 'TR1550', 'el', '2CO', 5, 17, 'NT', 'ωστε ει τις εν χριστω καινη κτισις τα αρχαια παρηλθεν ιδου γεγονεν καινα τα παντα'),
(5751, 47, 'TR1550', 'TR1550', 'el', '2CO', 5, 18, 'NT', 'τα δε παντα εκ του θεου του καταλλαξαντος ημας εαυτω δια ιησου χριστου και δοντος ημιν την διακονιαν της καταλλαγης'),
(5752, 47, 'TR1550', 'TR1550', 'el', '2CO', 5, 19, 'NT', 'ως οτι θεος ην εν χριστω κοσμον καταλλασσων εαυτω μη λογιζομενος αυτοις τα παραπτωματα αυτων και θεμενος εν ημιν τον λογον της καταλλαγης'),
(5753, 47, 'TR1550', 'TR1550', 'el', '2CO', 5, 20, 'NT', 'υπερ χριστου ουν πρεσβευομεν ως του θεου παρακαλουντος δι ημων δεομεθα υπερ χριστου καταλλαγητε τω θεω'),
(5754, 47, 'TR1550', 'TR1550', 'el', '2CO', 5, 21, 'NT', 'τον γαρ μη γνοντα αμαρτιαν υπερ ημων αμαρτιαν εποιησεν ινα ημεις γινωμεθα δικαιοσυνη θεου εν αυτω'),
(5755, 47, 'TR1550', 'TR1550', 'el', '2CO', 6, 1, 'NT', 'συνεργουντες δε και παρακαλουμεν μη εις κενον την χαριν του θεου δεξασθαι υμας'),
(5756, 47, 'TR1550', 'TR1550', 'el', '2CO', 6, 2, 'NT', 'λεγει γαρ καιρω δεκτω επηκουσα σου και εν ημερα σωτηριας εβοηθησα σοι ιδου νυν καιρος ευπροσδεκτος ιδου νυν ημερα σωτηριας'),
(5757, 47, 'TR1550', 'TR1550', 'el', '2CO', 6, 3, 'NT', 'μηδεμιαν εν μηδενι διδοντες προσκοπην ινα μη μωμηθη η διακονια'),
(5758, 47, 'TR1550', 'TR1550', 'el', '2CO', 6, 4, 'NT', 'αλλ εν παντι συνιστωντες εαυτους ως θεου διακονοι εν υπομονη πολλη εν θλιψεσιν εν αναγκαις εν στενοχωριαις'),
(5759, 47, 'TR1550', 'TR1550', 'el', '2CO', 6, 5, 'NT', 'εν πληγαις εν φυλακαις εν ακαταστασιαις εν κοποις εν αγρυπνιαις εν νηστειαις'),
(5760, 47, 'TR1550', 'TR1550', 'el', '2CO', 6, 6, 'NT', 'εν αγνοτητι εν γνωσει εν μακροθυμια εν χρηστοτητι εν πνευματι αγιω εν αγαπη ανυποκριτω'),
(5761, 47, 'TR1550', 'TR1550', 'el', '2CO', 6, 7, 'NT', 'εν λογω αληθειας εν δυναμει θεου δια των οπλων της δικαιοσυνης των δεξιων και αριστερων'),
(5762, 47, 'TR1550', 'TR1550', 'el', '2CO', 6, 8, 'NT', 'δια δοξης και ατιμιας δια δυσφημιας και ευφημιας ως πλανοι και αληθεις'),
(5763, 47, 'TR1550', 'TR1550', 'el', '2CO', 6, 9, 'NT', 'ως αγνοουμενοι και επιγινωσκομενοι ως αποθνησκοντες και ιδου ζωμεν ως παιδευομενοι και μη θανατουμενοι'),
(5764, 47, 'TR1550', 'TR1550', 'el', '2CO', 6, 10, 'NT', 'ως λυπουμενοι αει δε χαιροντες ως πτωχοι πολλους δε πλουτιζοντες ως μηδεν εχοντες και παντα κατεχοντες'),
(5765, 47, 'TR1550', 'TR1550', 'el', '2CO', 6, 11, 'NT', 'το στομα ημων ανεωγεν προς υμας κορινθιοι η καρδια ημων πεπλατυνται'),
(5766, 47, 'TR1550', 'TR1550', 'el', '2CO', 6, 12, 'NT', 'ου στενοχωρεισθε εν ημιν στενοχωρεισθε δε εν τοις σπλαγχνοις υμων'),
(5767, 47, 'TR1550', 'TR1550', 'el', '2CO', 6, 13, 'NT', 'την δε αυτην αντιμισθιαν ως τεκνοις λεγω πλατυνθητε και υμεις'),
(5768, 47, 'TR1550', 'TR1550', 'el', '2CO', 6, 14, 'NT', 'μη γινεσθε ετεροζυγουντες απιστοις τις γαρ μετοχη δικαιοσυνη και ανομια τις δε κοινωνια φωτι προς σκοτος'),
(5769, 47, 'TR1550', 'TR1550', 'el', '2CO', 6, 15, 'NT', 'τις δε συμφωνησις χριστω προς βελιαρ η τις μερις πιστω μετα απιστου'),
(5770, 47, 'TR1550', 'TR1550', 'el', '2CO', 6, 16, 'NT', 'τις δε συγκαταθεσις ναω θεου μετα ειδωλων υμεις γαρ ναος θεου εστε ζωντος καθως ειπεν ο θεος οτι ενοικησω εν αυτοις και εμπεριπατησω και εσομαι αυτων θεος και αυτοι εσονται μοι λαος'),
(5771, 47, 'TR1550', 'TR1550', 'el', '2CO', 6, 17, 'NT', 'διο εξελθετε εκ μεσου αυτων και αφορισθητε λεγει κυριος και ακαθαρτου μη απτεσθε καγω εισδεξομαι υμας'),
(5772, 47, 'TR1550', 'TR1550', 'el', '2CO', 6, 18, 'NT', 'και εσομαι υμιν εις πατερα και υμεις εσεσθε μοι εις υιους και θυγατερας λεγει κυριος παντοκρατωρ'),
(5773, 47, 'TR1550', 'TR1550', 'el', '2CO', 7, 1, 'NT', 'ταυτας ουν εχοντες τας επαγγελιας αγαπητοι καθαρισωμεν εαυτους απο παντος μολυσμου σαρκος και πνευματος επιτελουντες αγιωσυνην εν φοβω θεου'),
(5774, 47, 'TR1550', 'TR1550', 'el', '2CO', 7, 2, 'NT', 'χωρησατε ημας ουδενα ηδικησαμεν ουδενα εφθειραμεν ουδενα επλεονεκτησαμεν'),
(5775, 47, 'TR1550', 'TR1550', 'el', '2CO', 7, 3, 'NT', 'ου προς κατακρισιν λεγω προειρηκα γαρ οτι εν ταις καρδιαις ημων εστε εις το συναποθανειν και συζην'),
(5776, 47, 'TR1550', 'TR1550', 'el', '2CO', 7, 4, 'NT', 'πολλη μοι παρρησια προς υμας πολλη μοι καυχησις υπερ υμων πεπληρωμαι τη παρακλησει υπερπερισσευομαι τη χαρα επι παση τη θλιψει ημων'),
(5777, 47, 'TR1550', 'TR1550', 'el', '2CO', 7, 5, 'NT', 'και γαρ ελθοντων ημων εις μακεδονιαν ουδεμιαν εσχηκεν ανεσιν η σαρξ ημων αλλ εν παντι θλιβομενοι εξωθεν μαχαι εσωθεν φοβοι'),
(5778, 47, 'TR1550', 'TR1550', 'el', '2CO', 7, 6, 'NT', 'αλλ ο παρακαλων τους ταπεινους παρεκαλεσεν ημας ο θεος εν τη παρουσια τιτου'),
(5779, 47, 'TR1550', 'TR1550', 'el', '2CO', 7, 7, 'NT', 'ου μονον δε εν τη παρουσια αυτου αλλα και εν τη παρακλησει η παρεκληθη εφ υμιν αναγγελλων ημιν την υμων επιποθησιν τον υμων οδυρμον τον υμων ζηλον υπερ εμου ωστε με μαλλον χαρηναι'),
(5780, 47, 'TR1550', 'TR1550', 'el', '2CO', 7, 8, 'NT', 'οτι ει και ελυπησα υμας εν τη επιστολη ου μεταμελομαι ει και μετεμελομην βλεπω γαρ οτι η επιστολη εκεινη ει και προς ωραν ελυπησεν υμας'),
(5781, 47, 'TR1550', 'TR1550', 'el', '2CO', 7, 9, 'NT', 'νυν χαιρω ουχ οτι ελυπηθητε αλλ οτι ελυπηθητε εις μετανοιαν ελυπηθητε γαρ κατα θεον ινα εν μηδενι ζημιωθητε εξ ημων'),
(5782, 47, 'TR1550', 'TR1550', 'el', '2CO', 7, 10, 'NT', 'η γαρ κατα θεον λυπη μετανοιαν εις σωτηριαν αμεταμελητον κατεργαζεται η δε του κοσμου λυπη θανατον κατεργαζεται'),
(5783, 47, 'TR1550', 'TR1550', 'el', '2CO', 7, 11, 'NT', 'ιδου γαρ αυτο τουτο το κατα θεον λυπηθηναι υμας ποσην κατειργασατο υμιν σπουδην αλλα απολογιαν αλλα αγανακτησιν αλλα φοβον αλλα επιποθησιν αλλα ζηλον αλλ εκδικησιν εν παντι συνεστησατε εαυτους αγνους ειναι εν τω πραγματι'),
(5784, 47, 'TR1550', 'TR1550', 'el', '2CO', 7, 12, 'NT', 'αρα ει και εγραψα υμιν ουχ εινεκεν του αδικησαντος ουδε εινεκεν του αδικηθεντος αλλ εινεκεν του φανερωθηναι την σπουδην υμων την υπερ ημων προς υμας ενωπιον του θεου'),
(5785, 47, 'TR1550', 'TR1550', 'el', '2CO', 7, 13, 'NT', 'δια τουτο παρακεκλημεθα επι τη παρακλησει υμων περισσοτερως δε μαλλον εχαρημεν επι τη χαρα τιτου οτι αναπεπαυται το πνευμα αυτου απο παντων υμων'),
(5786, 47, 'TR1550', 'TR1550', 'el', '2CO', 7, 14, 'NT', 'οτι ει τι αυτω υπερ υμων κεκαυχημαι ου κατησχυνθην αλλ ως παντα εν αληθεια ελαλησαμεν υμιν ουτως και η καυχησις ημων η επι τιτου αληθεια εγενηθη'),
(5787, 47, 'TR1550', 'TR1550', 'el', '2CO', 7, 15, 'NT', 'και τα σπλαγχνα αυτου περισσοτερως εις υμας εστιν αναμιμνησκομενου την παντων υμων υπακοην ως μετα φοβου και τρομου εδεξασθε αυτον'),
(5788, 47, 'TR1550', 'TR1550', 'el', '2CO', 7, 16, 'NT', 'χαιρω οτι εν παντι θαρρω εν υμιν'),
(5789, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 1, 'NT', 'γνωριζομεν δε υμιν αδελφοι την χαριν του θεου την δεδομενην εν ταις εκκλησιαις της μακεδονιας'),
(5790, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 2, 'NT', 'οτι εν πολλη δοκιμη θλιψεως η περισσεια της χαρας αυτων και η κατα βαθους πτωχεια αυτων επερισσευσεν εις τον πλουτον της απλοτητος αυτων'),
(5791, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 3, 'NT', 'οτι κατα δυναμιν μαρτυρω και υπερ δυναμιν αυθαιρετοι'),
(5792, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 4, 'NT', 'μετα πολλης παρακλησεως δεομενοι ημων την χαριν και την κοινωνιαν της διακονιας της εις τους αγιους δεξασθαι ημας'),
(5793, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 5, 'NT', 'και ου καθως ηλπισαμεν αλλ εαυτους εδωκαν πρωτον τω κυριω και ημιν δια θεληματος θεου'),
(5794, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 6, 'NT', 'εις το παρακαλεσαι ημας τιτον ινα καθως προενηρξατο ουτως και επιτελεση εις υμας και την χαριν ταυτην'),
(5795, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 7, 'NT', 'αλλ ωσπερ εν παντι περισσευετε πιστει και λογω και γνωσει και παση σπουδη και τη εξ υμων εν ημιν αγαπη ινα και εν ταυτη τη χαριτι περισσευητε'),
(5796, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 8, 'NT', 'ου κατ επιταγην λεγω αλλα δια της ετερων σπουδης και το της υμετερας αγαπης γνησιον δοκιμαζων'),
(5797, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 9, 'NT', 'γινωσκετε γαρ την χαριν του κυριου ημων ιησου χριστου οτι δι υμας επτωχευσεν πλουσιος ων ινα υμεις τη εκεινου πτωχεια πλουτησητε'),
(5798, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 10, 'NT', 'και γνωμην εν τουτω διδωμι τουτο γαρ υμιν συμφερει οιτινες ου μονον το ποιησαι αλλα και το θελειν προενηρξασθε απο περυσι'),
(5799, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 11, 'NT', 'νυνι δε και το ποιησαι επιτελεσατε οπως καθαπερ η προθυμια του θελειν ουτως και το επιτελεσαι εκ του εχειν'),
(5800, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 12, 'NT', 'ει γαρ η προθυμια προκειται καθο εαν εχη τις ευπροσδεκτος ου καθο ουκ εχει'),
(5801, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 13, 'NT', 'ου γαρ ινα αλλοις ανεσις υμιν δε θλιψις αλλ εξ ισοτητος εν τω νυν καιρω το υμων περισσευμα εις το εκεινων υστερημα'),
(5802, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 14, 'NT', 'ινα και το εκεινων περισσευμα γενηται εις το υμων υστερημα οπως γενηται ισοτης'),
(5803, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 15, 'NT', 'καθως γεγραπται ο το πολυ ουκ επλεονασεν και ο το ολιγον ουκ ηλαττονησεν'),
(5804, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 16, 'NT', 'χαρις δε τω θεω τω διδοντι την αυτην σπουδην υπερ υμων εν τη καρδια τιτου'),
(5805, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 17, 'NT', 'οτι την μεν παρακλησιν εδεξατο σπουδαιοτερος δε υπαρχων αυθαιρετος εξηλθεν προς υμας'),
(5806, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 18, 'NT', 'συνεπεμψαμεν δε μετ αυτου τον αδελφον ου ο επαινος εν τω ευαγγελιω δια πασων των εκκλησιων'),
(5807, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 19, 'NT', 'ου μονον δε αλλα και χειροτονηθεις υπο των εκκλησιων συνεκδημος ημων συν τη χαριτι ταυτη τη διακονουμενη υφ ημων προς την αυτου του κυριου δοξαν και προθυμιαν υμων'),
(5808, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 20, 'NT', 'στελλομενοι τουτο μη τις ημας μωμησηται εν τη αδροτητι ταυτη τη διακονουμενη υφ ημων'),
(5809, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 21, 'NT', 'προνοουμενοι καλα ου μονον ενωπιον κυριου αλλα και ενωπιον ανθρωπων'),
(5810, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 22, 'NT', 'συνεπεμψαμεν δε αυτοις τον αδελφον ημων ον εδοκιμασαμεν εν πολλοις πολλακις σπουδαιον οντα νυνι δε πολυ σπουδαιοτερον πεποιθησει πολλη τη εις υμας'),
(5811, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 23, 'NT', 'ειτε υπερ τιτου κοινωνος εμος και εις υμας συνεργος ειτε αδελφοι ημων αποστολοι εκκλησιων δοξα χριστου'),
(5812, 47, 'TR1550', 'TR1550', 'el', '2CO', 8, 24, 'NT', 'την ουν ενδειξιν της αγαπης υμων και ημων καυχησεως υπερ υμων εις αυτους ενδειξασθε και εις προσωπον των εκκλησιων'),
(5813, 47, 'TR1550', 'TR1550', 'el', '2CO', 9, 1, 'NT', 'περι μεν γαρ της διακονιας της εις τους αγιους περισσον μοι εστιν το γραφειν υμιν'),
(5814, 47, 'TR1550', 'TR1550', 'el', '2CO', 9, 2, 'NT', 'οιδα γαρ την προθυμιαν υμων ην υπερ υμων καυχωμαι μακεδοσιν οτι αχαια παρεσκευασται απο περυσι και ο εξ υμων ζηλος ηρεθισεν τους πλειονας'),
(5815, 47, 'TR1550', 'TR1550', 'el', '2CO', 9, 3, 'NT', 'επεμψα δε τους αδελφους ινα μη το καυχημα ημων το υπερ υμων κενωθη εν τω μερει τουτω ινα καθως ελεγον παρεσκευασμενοι ητε'),
(5816, 47, 'TR1550', 'TR1550', 'el', '2CO', 9, 4, 'NT', 'μηπως εαν ελθωσιν συν εμοι μακεδονες και ευρωσιν υμας απαρασκευαστους καταισχυνθωμεν ημεις ινα μη λεγωμεν υμεις εν τη υποστασει ταυτη της καυχησεως'),
