(5897, 47, 'TR1550', 'TR1550', 'el', '2CO', 12, 19, 'NT', 'παλιν δοκειτε οτι υμιν απολογουμεθα κατενωπιον του θεου εν χριστω λαλουμεν τα δε παντα αγαπητοι υπερ της υμων οικοδομης'),
(5898, 47, 'TR1550', 'TR1550', 'el', '2CO', 12, 20, 'NT', 'φοβουμαι γαρ μηπως ελθων ουχ οιους θελω ευρω υμας καγω ευρεθω υμιν οιον ου θελετε μηπως ερεις ζηλοι θυμοι εριθειαι καταλαλιαι ψιθυρισμοι φυσιωσεις ακαταστασιαι'),
(5899, 47, 'TR1550', 'TR1550', 'el', '2CO', 12, 21, 'NT', 'μη παλιν ελθοντα με ταπεινωση ο θεος μου προς υμας και πενθησω πολλους των προημαρτηκοτων και μη μετανοησαντων επι τη ακαθαρσια και πορνεια και ασελγεια η επραξαν'),
(5900, 47, 'TR1550', 'TR1550', 'el', '2CO', 13, 1, 'NT', 'τριτον τουτο ερχομαι προς υμας επι στοματος δυο μαρτυρων και τριων σταθησεται παν ρημα'),
(5901, 47, 'TR1550', 'TR1550', 'el', '2CO', 13, 2, 'NT', 'προειρηκα και προλεγω ως παρων το δευτερον και απων νυν γραφω τοις προημαρτηκοσιν και τοις λοιποις πασιν οτι εαν ελθω εις το παλιν ου φεισομαι'),
(5902, 47, 'TR1550', 'TR1550', 'el', '2CO', 13, 3, 'NT', 'επει δοκιμην ζητειτε του εν εμοι λαλουντος χριστου ος εις υμας ουκ ασθενει αλλα δυνατει εν υμιν'),
(5903, 47, 'TR1550', 'TR1550', 'el', '2CO', 13, 4, 'NT', 'και γαρ ει εσταυρωθη εξ ασθενειας αλλα ζη εκ δυναμεως θεου και γαρ ημεις ασθενουμεν εν αυτω αλλα ζησομεθα συν αυτω εκ δυναμεως θεου εις υμας'),
(5904, 47, 'TR1550', 'TR1550', 'el', '2CO', 13, 5, 'NT', 'εαυτους πειραζετε ει εστε εν τη πιστει εαυτους δοκιμαζετε η ουκ επιγινωσκετε εαυτους οτι ιησους χριστος εν υμιν εστιν ει μη τι αδοκιμοι εστε'),
(5905, 47, 'TR1550', 'TR1550', 'el', '2CO', 13, 6, 'NT', 'ελπιζω δε οτι γνωσεσθε οτι ημεις ουκ εσμεν αδοκιμοι'),
(5906, 47, 'TR1550', 'TR1550', 'el', '2CO', 13, 7, 'NT', 'ευχομαι δε προς τον θεον μη ποιησαι υμας κακον μηδεν ουχ ινα ημεις δοκιμοι φανωμεν αλλ ινα υμεις το καλον ποιητε ημεις δε ως αδοκιμοι ωμεν'),
(5907, 47, 'TR1550', 'TR1550', 'el', '2CO', 13, 8, 'NT', 'ου γαρ δυναμεθα τι κατα της αληθειας αλλ υπερ της αληθειας'),
(5908, 47, 'TR1550', 'TR1550', 'el', '2CO', 13, 9, 'NT', 'χαιρομεν γαρ οταν ημεις ασθενωμεν υμεις δε δυνατοι ητε τουτο δε και ευχομεθα την υμων καταρτισιν'),
(5909, 47, 'TR1550', 'TR1550', 'el', '2CO', 13, 10, 'NT', 'δια τουτο ταυτα απων γραφω ινα παρων μη αποτομως χρησωμαι κατα την εξουσιαν ην εδωκεν μοι ο κυριος εις οικοδομην και ουκ εις καθαιρεσιν'),
(5910, 47, 'TR1550', 'TR1550', 'el', '2CO', 13, 11, 'NT', 'λοιπον αδελφοι χαιρετε καταρτιζεσθε παρακαλεισθε το αυτο φρονειτε ειρηνευετε και ο θεος της αγαπης και ειρηνης εσται μεθ υμων'),
(5911, 47, 'TR1550', 'TR1550', 'el', '2CO', 13, 12, 'NT', 'ασπασασθε αλληλους εν αγιω φιληματι'),
(5912, 47, 'TR1550', 'TR1550', 'el', '2CO', 13, 13, 'NT', '[13:12] ασπαζονται υμας οι αγιοι παντες'),
(5913, 47, 'TR1550', 'TR1550', 'el', '2CO', 13, 14, 'NT', '[13:13] η χαρις του κυριου ιησου χριστου και η αγαπη  του θεου και η κοινωνια του αγιου πνευματος μετα παντων υμων αμην [προς κορινθιους δευτερα εγραφη απο φιλιππων της μακεδονιας δια τιτου και λουκα]'),
(5914, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 1, 'NT', 'παυλος αποστολος ουκ απ ανθρωπων ουδε δι ανθρωπου αλλα δια ιησου χριστου και θεου πατρος του εγειραντος αυτον εκ νεκρων'),
(5915, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 2, 'NT', 'και οι συν εμοι παντες αδελφοι ταις εκκλησιαις της γαλατιας'),
(5916, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 3, 'NT', 'χαρις υμιν και ειρηνη απο θεου πατρος και κυριου ημων ιησου χριστου'),
(5917, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 4, 'NT', 'του δοντος εαυτον υπερ των αμαρτιων ημων οπως εξεληται ημας εκ του ενεστωτος αιωνος πονηρου κατα το θελημα του θεου και πατρος ημων'),
(5918, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 5, 'NT', 'ω η δοξα εις τους αιωνας των αιωνων αμην'),
(5919, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 6, 'NT', 'θαυμαζω οτι ουτως ταχεως μετατιθεσθε απο του καλεσαντος υμας εν χαριτι χριστου εις ετερον ευαγγελιον'),
(5920, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 7, 'NT', 'ο ουκ εστιν αλλο ει μη τινες εισιν οι ταρασσοντες υμας και θελοντες μεταστρεψαι το ευαγγελιον του χριστου'),
(5921, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 8, 'NT', 'αλλα και εαν ημεις η αγγελος εξ ουρανου ευαγγελιζηται υμιν παρ ο ευηγγελισαμεθα υμιν αναθεμα εστω'),
(5922, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 9, 'NT', 'ως προειρηκαμεν και αρτι παλιν λεγω ει τις υμας ευαγγελιζεται παρ ο παρελαβετε αναθεμα εστω'),
(5923, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 10, 'NT', 'αρτι γαρ ανθρωπους πειθω η τον θεον η ζητω ανθρωποις αρεσκειν ει γαρ ετι ανθρωποις ηρεσκον χριστου δουλος ουκ αν ημην'),
(5924, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 11, 'NT', 'γνωριζω δε υμιν αδελφοι το ευαγγελιον το ευαγγελισθεν υπ εμου οτι ουκ εστιν κατα ανθρωπον'),
(5925, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 12, 'NT', 'ουδε γαρ εγω παρα ανθρωπου παρελαβον αυτο ουτε εδιδαχθην αλλα δι αποκαλυψεως ιησου χριστου'),
(5926, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 13, 'NT', 'ηκουσατε γαρ την εμην αναστροφην ποτε εν τω ιουδαισμω οτι καθ υπερβολην εδιωκον την εκκλησιαν του θεου και επορθουν αυτην'),
(5927, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 14, 'NT', 'και προεκοπτον εν τω ιουδαισμω υπερ πολλους συνηλικιωτας εν τω γενει μου περισσοτερως ζηλωτης υπαρχων των πατρικων μου παραδοσεων'),
(5928, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 15, 'NT', 'οτε δε ευδοκησεν ο θεος ο αφορισας με εκ κοιλιας μητρος μου και καλεσας δια της χαριτος αυτου'),
(5929, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 16, 'NT', 'αποκαλυψαι τον υιον αυτου εν εμοι ινα ευαγγελιζωμαι αυτον εν τοις εθνεσιν ευθεως ου προσανεθεμην σαρκι και αιματι'),
(5930, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 17, 'NT', 'ουδε ανηλθον εις ιεροσολυμα προς τους προ εμου αποστολους αλλ απηλθον εις αραβιαν και παλιν υπεστρεψα εις δαμασκον'),
(5931, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 18, 'NT', 'επειτα μετα ετη τρια ανηλθον εις ιεροσολυμα ιστορησαι πετρον και επεμεινα προς αυτον ημερας δεκαπεντε'),
(5932, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 19, 'NT', 'ετερον δε των αποστολων ουκ ειδον ει μη ιακωβον τον αδελφον του κυριου'),
(5933, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 20, 'NT', 'α δε γραφω υμιν ιδου ενωπιον του θεου οτι ου ψευδομαι'),
(5934, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 21, 'NT', 'επειτα ηλθον εις τα κλιματα της συριας και της κιλικιας'),
(5935, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 22, 'NT', 'ημην δε αγνοουμενος τω προσωπω ταις εκκλησιαις της ιουδαιας ταις εν χριστω'),
(5936, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 23, 'NT', 'μονον δε ακουοντες ησαν οτι ο διωκων ημας ποτε νυν ευαγγελιζεται την πιστιν ην ποτε επορθει'),
(5937, 48, 'TR1550', 'TR1550', 'el', 'GAL', 1, 24, 'NT', 'και εδοξαζον εν εμοι τον θεον'),
(5938, 48, 'TR1550', 'TR1550', 'el', 'GAL', 2, 1, 'NT', 'επειτα δια δεκατεσσαρων ετων παλιν ανεβην εις ιεροσολυμα μετα βαρναβα συμπαραλαβων και τιτον'),
(5939, 48, 'TR1550', 'TR1550', 'el', 'GAL', 2, 2, 'NT', 'ανεβην δε κατα αποκαλυψιν και ανεθεμην αυτοις το ευαγγελιον ο κηρυσσω εν τοις εθνεσιν κατ ιδιαν δε τοις δοκουσιν μηπως εις κενον τρεχω η εδραμον'),
(5940, 48, 'TR1550', 'TR1550', 'el', 'GAL', 2, 3, 'NT', 'αλλ ουδε τιτος ο συν εμοι ελλην ων ηναγκασθη περιτμηθηναι'),
(5941, 48, 'TR1550', 'TR1550', 'el', 'GAL', 2, 4, 'NT', 'δια δε τους παρεισακτους ψευδαδελφους οιτινες παρεισηλθον κατασκοπησαι την ελευθεριαν ημων ην εχομεν εν χριστω ιησου ινα ημας καταδουλωσωνται'),
(5942, 48, 'TR1550', 'TR1550', 'el', 'GAL', 2, 5, 'NT', 'οις ουδε προς ωραν ειξαμεν τη υποταγη ινα η αληθεια του ευαγγελιου διαμεινη προς υμας'),
(5943, 48, 'TR1550', 'TR1550', 'el', 'GAL', 2, 6, 'NT', 'απο δε των δοκουντων ειναι τι οποιοι ποτε ησαν ουδεν μοι διαφερει προσωπον θεος ανθρωπου ου λαμβανει εμοι γαρ οι δοκουντες ουδεν προσανεθεντο'),
(5944, 48, 'TR1550', 'TR1550', 'el', 'GAL', 2, 7, 'NT', 'αλλα τουναντιον ιδοντες οτι πεπιστευμαι το ευαγγελιον της ακροβυστιας καθως πετρος της περιτομης'),
(5945, 48, 'TR1550', 'TR1550', 'el', 'GAL', 2, 8, 'NT', 'ο γαρ ενεργησας πετρω εις αποστολην της περιτομης ενηργησεν και εμοι εις τα εθνη'),
(5946, 48, 'TR1550', 'TR1550', 'el', 'GAL', 2, 9, 'NT', 'και γνοντες την χαριν την δοθεισαν μοι ιακωβος και κηφας και ιωαννης οι δοκουντες στυλοι ειναι δεξιας εδωκαν εμοι και βαρναβα κοινωνιας ινα ημεις εις τα εθνη αυτοι δε εις την περιτομην'),
(5947, 48, 'TR1550', 'TR1550', 'el', 'GAL', 2, 10, 'NT', 'μονον των πτωχων ινα μνημονευωμεν ο και εσπουδασα αυτο τουτο ποιησαι'),
(5948, 48, 'TR1550', 'TR1550', 'el', 'GAL', 2, 11, 'NT', 'οτε δε ηλθεν πετρος εις αντιοχειαν κατα προσωπον αυτω αντεστην οτι κατεγνωσμενος ην'),
(5949, 48, 'TR1550', 'TR1550', 'el', 'GAL', 2, 12, 'NT', 'προ του γαρ ελθειν τινας απο ιακωβου μετα των εθνων συνησθιεν οτε δε ηλθον υπεστελλεν και αφωριζεν εαυτον φοβουμενος τους εκ περιτομης'),
(5950, 48, 'TR1550', 'TR1550', 'el', 'GAL', 2, 13, 'NT', 'και συνυπεκριθησαν αυτω και οι λοιποι ιουδαιοι ωστε και βαρναβας συναπηχθη αυτων τη υποκρισει'),
(5951, 48, 'TR1550', 'TR1550', 'el', 'GAL', 2, 14, 'NT', 'αλλ οτε ειδον οτι ουκ ορθοποδουσιν προς την αληθειαν του ευαγγελιου ειπον τω πετρω εμπροσθεν παντων ει συ ιουδαιος υπαρχων εθνικως ζης και ουκ ιουδαικως τι τα εθνη αναγκαζεις ιουδαιζειν'),
(5952, 48, 'TR1550', 'TR1550', 'el', 'GAL', 2, 15, 'NT', 'ημεις φυσει ιουδαιοι και ουκ εξ εθνων αμαρτωλοι'),
(5953, 48, 'TR1550', 'TR1550', 'el', 'GAL', 2, 16, 'NT', 'ειδοτες οτι ου δικαιουται ανθρωπος εξ εργων νομου εαν μη δια πιστεως ιησου χριστου και ημεις εις χριστον ιησουν επιστευσαμεν ινα δικαιωθωμεν εκ πιστεως χριστου και ουκ εξ εργων νομου διοτι ου δικαιωθησεται εξ εργων νομου πασα σαρξ'),
(5954, 48, 'TR1550', 'TR1550', 'el', 'GAL', 2, 17, 'NT', 'ει δε ζητουντες δικαιωθηναι εν χριστω ευρεθημεν και αυτοι αμαρτωλοι αρα χριστος αμαρτιας διακονος μη γενοιτο'),
(5955, 48, 'TR1550', 'TR1550', 'el', 'GAL', 2, 18, 'NT', 'ει γαρ α κατελυσα ταυτα παλιν οικοδομω παραβατην εμαυτον συνιστημι'),
(5956, 48, 'TR1550', 'TR1550', 'el', 'GAL', 2, 19, 'NT', 'εγω γαρ δια νομου νομω απεθανον ινα θεω ζησω'),
(5957, 48, 'TR1550', 'TR1550', 'el', 'GAL', 2, 20, 'NT', 'χριστω συνεσταυρωμαι ζω δε ουκετι εγω ζη δε εν εμοι χριστος ο δε νυν ζω εν σαρκι εν πιστει ζω τη του υιου του θεου του αγαπησαντος με και παραδοντος εαυτον υπερ εμου'),
(5958, 48, 'TR1550', 'TR1550', 'el', 'GAL', 2, 21, 'NT', 'ουκ αθετω την χαριν του θεου ει γαρ δια νομου δικαιοσυνη αρα χριστος δωρεαν απεθανεν'),
(5959, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 1, 'NT', 'ω ανοητοι γαλαται τις υμας εβασκανεν τη αληθεια μη πειθεσθαι οις κατ οφθαλμους ιησους χριστος προεγραφη εν υμιν εσταυρωμενος'),
(5960, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 2, 'NT', 'τουτο μονον θελω μαθειν αφ υμων εξ εργων νομου το πνευμα ελαβετε η εξ ακοης πιστεως'),
(5961, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 3, 'NT', 'ουτως ανοητοι εστε εναρξαμενοι πνευματι νυν σαρκι επιτελεισθε'),
(5962, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 4, 'NT', 'τοσαυτα επαθετε εικη ειγε και εικη'),
(5963, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 5, 'NT', 'ο ουν επιχορηγων υμιν το πνευμα και ενεργων δυναμεις εν υμιν εξ εργων νομου η εξ ακοης πιστεως'),
(5964, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 6, 'NT', 'καθως αβρααμ επιστευσεν τω θεω και ελογισθη αυτω εις δικαιοσυνην'),
(5965, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 7, 'NT', 'γινωσκετε αρα οτι οι εκ πιστεως ουτοι εισιν υιοι αβρααμ'),
(5966, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 8, 'NT', 'προιδουσα δε η γραφη οτι εκ πιστεως δικαιοι τα εθνη ο θεος προευηγγελισατο τω αβρααμ οτι ενευλογηθησονται εν σοι παντα τα εθνη'),
(5967, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 9, 'NT', 'ωστε οι εκ πιστεως ευλογουνται συν τω πιστω αβρααμ'),
(5968, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 10, 'NT', 'οσοι γαρ εξ εργων νομου εισιν υπο καταραν εισιν γεγραπται γαρ επικαταρατος πας ος ουκ εμμενει εν πασιν τοις γεγραμμενοις εν τω βιβλιω του νομου του ποιησαι αυτα'),
(5969, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 11, 'NT', 'οτι δε εν νομω ουδεις δικαιουται παρα τω θεω δηλον οτι ο δικαιος εκ πιστεως ζησεται'),
(5970, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 12, 'NT', 'ο δε νομος ουκ εστιν εκ πιστεως αλλ ο ποιησας αυτα ανθρωπος ζησεται εν αυτοις'),
(5971, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 13, 'NT', 'χριστος ημας εξηγορασεν εκ της καταρας του νομου γενομενος υπερ ημων καταρα γεγραπται γαρ επικαταρατος πας ο κρεμαμενος επι ξυλου'),
(5972, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 14, 'NT', 'ινα εις τα εθνη η ευλογια του αβρααμ γενηται εν χριστω ιησου ινα την επαγγελιαν του πνευματος λαβωμεν δια της πιστεως'),
(5973, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 15, 'NT', 'αδελφοι κατα ανθρωπον λεγω ομως ανθρωπου κεκυρωμενην διαθηκην ουδεις αθετει η επιδιατασσεται'),
(5974, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 16, 'NT', 'τω δε αβρααμ ερρηθησαν αι επαγγελιαι και τω σπερματι αυτου ου λεγει και τοις σπερμασιν ως επι πολλων αλλ ως εφ ενος και τω σπερματι σου ος εστιν χριστος'),
(5975, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 17, 'NT', 'τουτο δε λεγω διαθηκην προκεκυρωμενην υπο του θεου εις χριστον ο μετα ετη τετρακοσια και τριακοντα γεγονως νομος ουκ ακυροι εις το καταργησαι την επαγγελιαν'),
(5976, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 18, 'NT', 'ει γαρ εκ νομου η κληρονομια ουκετι εξ επαγγελιας τω δε αβρααμ δι επαγγελιας κεχαρισται ο θεος'),
(5977, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 19, 'NT', 'τι ουν ο νομος των παραβασεων χαριν προσετεθη αχρις ου ελθη το σπερμα ω επηγγελται διαταγεις δι αγγελων εν χειρι μεσιτου'),
(5978, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 20, 'NT', 'ο δε μεσιτης ενος ουκ εστιν ο δε θεος εις εστιν'),
(5979, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 21, 'NT', 'ο ουν νομος κατα των επαγγελιων του θεου μη γενοιτο ει γαρ εδοθη νομος ο δυναμενος ζωοποιησαι οντως αν εκ νομου ην η δικαιοσυνη'),
(5980, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 22, 'NT', 'αλλα συνεκλεισεν η γραφη τα παντα υπο αμαρτιαν ινα η επαγγελια εκ πιστεως ιησου χριστου δοθη τοις πιστευουσιν'),
(5981, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 23, 'NT', 'προ του δε ελθειν την πιστιν υπο νομον εφρουρουμεθα συγκεκλεισμενοι εις την μελλουσαν πιστιν αποκαλυφθηναι'),
(5982, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 24, 'NT', 'ωστε ο νομος παιδαγωγος ημων γεγονεν εις χριστον ινα εκ πιστεως δικαιωθωμεν'),
(5983, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 25, 'NT', 'ελθουσης δε της πιστεως ουκετι υπο παιδαγωγον εσμεν'),
(5984, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 26, 'NT', 'παντες γαρ υιοι θεου εστε δια της πιστεως εν χριστω ιησου'),
(5985, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 27, 'NT', 'οσοι γαρ εις χριστον εβαπτισθητε χριστον ενεδυσασθε'),
(5986, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 28, 'NT', 'ουκ ενι ιουδαιος ουδε ελλην ουκ ενι δουλος ουδε ελευθερος ουκ ενι αρσεν και θηλυ παντες γαρ υμεις εις εστε εν χριστω ιησου'),
(5987, 48, 'TR1550', 'TR1550', 'el', 'GAL', 3, 29, 'NT', 'ει δε υμεις χριστου αρα του αβρααμ σπερμα εστε και κατ επαγγελιαν κληρονομοι'),
(5988, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 1, 'NT', 'λεγω δε εφ οσον χρονον ο κληρονομος νηπιος εστιν ουδεν διαφερει δουλου κυριος παντων ων'),
(5989, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 2, 'NT', 'αλλα υπο επιτροπους εστιν και οικονομους αχρι της προθεσμιας του πατρος'),
(5990, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 3, 'NT', 'ουτως και ημεις οτε ημεν νηπιοι υπο τα στοιχεια του κοσμου ημεν δεδουλωμενοι'),
(5991, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 4, 'NT', 'οτε δε ηλθεν το πληρωμα του χρονου εξαπεστειλεν ο θεος τον υιον αυτου γενομενον εκ γυναικος γενομενον υπο νομον'),
(5992, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 5, 'NT', 'ινα τους υπο νομον εξαγοραση ινα την υιοθεσιαν απολαβωμεν'),
(5993, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 6, 'NT', 'οτι δε εστε υιοι εξαπεστειλεν ο θεος το πνευμα του υιου αυτου εις τας καρδιας υμων κραζον αββα ο πατηρ'),
(5994, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 7, 'NT', 'ωστε ουκετι ει δουλος αλλ υιος ει δε υιος και κληρονομος θεου δια χριστου'),
(5995, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 8, 'NT', 'αλλα τοτε μεν ουκ ειδοτες θεον εδουλευσατε τοις μη φυσει ουσιν θεοις'),
(5996, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 9, 'NT', 'νυν δε γνοντες θεον μαλλον δε γνωσθεντες υπο θεου πως επιστρεφετε παλιν επι τα ασθενη και πτωχα στοιχεια οις παλιν ανωθεν δουλευειν θελετε'),
(5997, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 10, 'NT', 'ημερας παρατηρεισθε και μηνας και καιρους και ενιαυτους'),
(5998, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 11, 'NT', 'φοβουμαι υμας μηπως εικη κεκοπιακα εις υμας'),
(5999, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 12, 'NT', 'γινεσθε ως εγω οτι καγω ως υμεις αδελφοι δεομαι υμων ουδεν με ηδικησατε'),
(6000, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 13, 'NT', 'οιδατε δε οτι δι ασθενειαν της σαρκος ευηγγελισαμην υμιν το προτερον'),
(6001, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 14, 'NT', 'και τον πειρασμον μου τον εν τη σαρκι μου ουκ εξουθενησατε ουδε εξεπτυσατε αλλ ως αγγελον θεου εδεξασθε με ως χριστον ιησουν'),
(6002, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 15, 'NT', 'τις ουν ην ο μακαρισμος υμων μαρτυρω γαρ υμιν οτι ει δυνατον τους οφθαλμους υμων εξορυξαντες αν εδωκατε μοι'),
(6003, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 16, 'NT', 'ωστε εχθρος υμων γεγονα αληθευων υμιν'),
(6004, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 17, 'NT', 'ζηλουσιν υμας ου καλως αλλα εκκλεισαι υμας θελουσιν ινα αυτους ζηλουτε'),
(6005, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 18, 'NT', 'καλον δε το ζηλουσθαι εν καλω παντοτε και μη μονον εν τω παρειναι με προς υμας'),
(6006, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 19, 'NT', 'τεκνια μου ους παλιν ωδινω αχρις ου μορφωθη χριστος εν υμιν'),
(6007, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 20, 'NT', 'ηθελον δε παρειναι προς υμας αρτι και αλλαξαι την φωνην μου οτι απορουμαι εν υμιν'),
(6008, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 21, 'NT', 'λεγετε μοι οι υπο νομον θελοντες ειναι τον νομον ουκ ακουετε'),
(6009, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 22, 'NT', 'γεγραπται γαρ οτι αβρααμ δυο υιους εσχεν ενα εκ της παιδισκης και ενα εκ της ελευθερας'),
(6010, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 23, 'NT', 'αλλ ο μεν εκ της παιδισκης κατα σαρκα γεγεννηται ο δε εκ της ελευθερας δια της επαγγελιας'),
(6011, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 24, 'NT', 'ατινα εστιν αλληγορουμενα αυται γαρ εισιν αι δυο διαθηκαι μια μεν απο ορους σινα εις δουλειαν γεννωσα ητις εστιν αγαρ'),
(6012, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 25, 'NT', 'το γαρ αγαρ σινα ορος εστιν εν τη αραβια συστοιχει δε τη νυν ιερουσαλημ δουλευει δε μετα των τεκνων αυτης'),
(6013, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 26, 'NT', 'η δε ανω ιερουσαλημ ελευθερα εστιν ητις εστιν μητηρ παντων ημων'),
(6014, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 27, 'NT', 'γεγραπται γαρ ευφρανθητι στειρα η ου τικτουσα ρηξον και βοησον η ουκ ωδινουσα οτι πολλα τα τεκνα της ερημου μαλλον η της εχουσης τον ανδρα'),
(6015, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 28, 'NT', 'ημεις δε αδελφοι κατα ισαακ επαγγελιας τεκνα εσμεν'),
(6016, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 29, 'NT', 'αλλ ωσπερ τοτε ο κατα σαρκα γεννηθεις εδιωκεν τον κατα πνευμα ουτως και νυν'),
(6017, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 30, 'NT', 'αλλα τι λεγει η γραφη εκβαλε την παιδισκην και τον υιον αυτης ου γαρ μη κληρονομηση ο υιος της παιδισκης μετα του υιου της ελευθερας'),
(6018, 48, 'TR1550', 'TR1550', 'el', 'GAL', 4, 31, 'NT', 'αρα αδελφοι ουκ εσμεν παιδισκης τεκνα αλλα της ελευθερας'),
(6019, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 1, 'NT', 'τη ελευθερια ουν η χριστος ημας ηλευθερωσεν στηκετε και μη παλιν ζυγω δουλειας ενεχεσθε'),
(6020, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 2, 'NT', 'ιδε εγω παυλος λεγω υμιν οτι εαν περιτεμνησθε χριστος υμας ουδεν ωφελησει'),
(6021, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 3, 'NT', 'μαρτυρομαι δε παλιν παντι ανθρωπω περιτεμνομενω οτι οφειλετης εστιν ολον τον νομον ποιησαι'),
(6022, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 4, 'NT', 'κατηργηθητε απο του χριστου οιτινες εν νομω δικαιουσθε της χαριτος εξεπεσατε'),
(6023, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 5, 'NT', 'ημεις γαρ πνευματι εκ πιστεως ελπιδα δικαιοσυνης απεκδεχομεθα'),
(6024, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 6, 'NT', 'εν γαρ χριστω ιησου ουτε περιτομη τι ισχυει ουτε ακροβυστια αλλα πιστις δι αγαπης ενεργουμενη'),
(6025, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 7, 'NT', 'ετρεχετε καλως τις υμας ανεκοψεν τη αληθεια μη πειθεσθαι'),
(6026, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 8, 'NT', 'η πεισμονη ουκ εκ του καλουντος υμας'),
(6027, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 9, 'NT', 'μικρα ζυμη ολον το φυραμα ζυμοι'),
(6028, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 10, 'NT', 'εγω πεποιθα εις υμας εν κυριω οτι ουδεν αλλο φρονησετε ο δε ταρασσων υμας βαστασει το κριμα οστις αν η'),
(6029, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 11, 'NT', 'εγω δε αδελφοι ει περιτομην ετι κηρυσσω τι ετι διωκομαι αρα κατηργηται το σκανδαλον του σταυρου'),
(6030, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 12, 'NT', 'οφελον και αποκοψονται οι αναστατουντες υμας'),
(6031, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 13, 'NT', 'υμεις γαρ επ ελευθερια εκληθητε αδελφοι μονον μη την ελευθεριαν εις αφορμην τη σαρκι αλλα δια της αγαπης δουλευετε αλληλοις'),
(6032, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 14, 'NT', 'ο γαρ πας νομος εν ενι λογω πληρουται εν τω αγαπησεις τον πλησιον σου ως εαυτον'),
(6033, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 15, 'NT', 'ει δε αλληλους δακνετε και κατεσθιετε βλεπετε μη υπο αλληλων αναλωθητε'),
(6034, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 16, 'NT', 'λεγω δε πνευματι περιπατειτε και επιθυμιαν σαρκος ου μη τελεσητε'),
(6035, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 17, 'NT', 'η γαρ σαρξ επιθυμει κατα του πνευματος το δε πνευμα κατα της σαρκος ταυτα δε αντικειται αλληλοις ινα μη α αν θελητε ταυτα ποιητε'),
(6036, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 18, 'NT', 'ει δε πνευματι αγεσθε ουκ εστε υπο νομον'),
(6037, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 19, 'NT', 'φανερα δε εστιν τα εργα της σαρκος ατινα εστιν μοιχεια πορνεια ακαθαρσια ασελγεια'),
(6038, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 20, 'NT', 'ειδωλολατρεια φαρμακεια εχθραι ερεις ζηλοι θυμοι εριθειαι διχοστασιαι αιρεσεις'),
(6039, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 21, 'NT', 'φθονοι φονοι μεθαι κωμοι και τα ομοια τουτοις α προλεγω υμιν καθως και προειπον οτι οι τα τοιαυτα πρασσοντες βασιλειαν θεου ου κληρονομησουσιν'),
(6040, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 22, 'NT', 'ο δε καρπος του πνευματος εστιν αγαπη χαρα ειρηνη μακροθυμια χρηστοτης αγαθωσυνη πιστις'),
(6041, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 23, 'NT', 'πραοτης εγκρατεια κατα των τοιουτων ουκ εστιν νομος'),
(6042, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 24, 'NT', 'οι δε του χριστου την σαρκα εσταυρωσαν συν τοις παθημασιν και ταις επιθυμιαις'),
(6043, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 25, 'NT', 'ει ζωμεν πνευματι πνευματι και στοιχωμεν'),
(6044, 48, 'TR1550', 'TR1550', 'el', 'GAL', 5, 26, 'NT', 'μη γινωμεθα κενοδοξοι αλληλους προκαλουμενοι αλληλοις φθονουντες'),
(6045, 48, 'TR1550', 'TR1550', 'el', 'GAL', 6, 1, 'NT', 'αδελφοι εαν και προληφθη ανθρωπος εν τινι παραπτωματι υμεις οι πνευματικοι καταρτιζετε τον τοιουτον εν πνευματι πραοτητος σκοπων σεαυτον μη και συ πειρασθης'),
(6046, 48, 'TR1550', 'TR1550', 'el', 'GAL', 6, 2, 'NT', 'αλληλων τα βαρη βασταζετε και ουτως αναπληρωσατε τον νομον του χριστου'),
(6047, 48, 'TR1550', 'TR1550', 'el', 'GAL', 6, 3, 'NT', 'ει γαρ δοκει τις ειναι τι μηδεν ων εαυτον φρεναπατα'),
(6048, 48, 'TR1550', 'TR1550', 'el', 'GAL', 6, 4, 'NT', 'το δε εργον εαυτου δοκιμαζετω εκαστος και τοτε εις εαυτον μονον το καυχημα εξει και ουκ εις τον ετερον'),
(6049, 48, 'TR1550', 'TR1550', 'el', 'GAL', 6, 5, 'NT', 'εκαστος γαρ το ιδιον φορτιον βαστασει'),
(6050, 48, 'TR1550', 'TR1550', 'el', 'GAL', 6, 6, 'NT', 'κοινωνειτω δε ο κατηχουμενος τον λογον τω κατηχουντι εν πασιν αγαθοις'),
(6051, 48, 'TR1550', 'TR1550', 'el', 'GAL', 6, 7, 'NT', 'μη πλανασθε θεος ου μυκτηριζεται ο γαρ εαν σπειρη ανθρωπος τουτο και θερισει'),
(6052, 48, 'TR1550', 'TR1550', 'el', 'GAL', 6, 8, 'NT', 'οτι ο σπειρων εις την σαρκα εαυτου εκ της σαρκος θερισει φθοραν ο δε σπειρων εις το πνευμα εκ του πνευματος θερισει ζωην αιωνιον'),
(6053, 48, 'TR1550', 'TR1550', 'el', 'GAL', 6, 9, 'NT', 'το δε καλον ποιουντες μη εκκακωμεν καιρω γαρ ιδιω θερισομεν μη εκλυομενοι'),
(6054, 48, 'TR1550', 'TR1550', 'el', 'GAL', 6, 10, 'NT', 'αρα ουν ως καιρον εχομεν εργαζωμεθα το αγαθον προς παντας μαλιστα δε προς τους οικειους της πιστεως'),
(6055, 48, 'TR1550', 'TR1550', 'el', 'GAL', 6, 11, 'NT', 'ιδετε πηλικοις υμιν γραμμασιν εγραψα τη εμη χειρι'),
(6056, 48, 'TR1550', 'TR1550', 'el', 'GAL', 6, 12, 'NT', 'οσοι θελουσιν ευπροσωπησαι εν σαρκι ουτοι αναγκαζουσιν υμας περιτεμνεσθαι μονον ινα μη τω σταυρω του χριστου διωκωνται'),
(6057, 48, 'TR1550', 'TR1550', 'el', 'GAL', 6, 13, 'NT', 'ουδε γαρ οι περιτεμνομενοι αυτοι νομον φυλασσουσιν αλλα θελουσιν υμας περιτεμνεσθαι ινα εν τη υμετερα σαρκι καυχησωνται'),
(6058, 48, 'TR1550', 'TR1550', 'el', 'GAL', 6, 14, 'NT', 'εμοι δε μη γενοιτο καυχασθαι ει μη εν τω σταυρω του κυριου ημων ιησου χριστου δι ου εμοι κοσμος εσταυρωται καγω τω κοσμω'),
(6059, 48, 'TR1550', 'TR1550', 'el', 'GAL', 6, 15, 'NT', 'εν γαρ χριστω ιησου ουτε περιτομη τι ισχυει ουτε ακροβυστια αλλα καινη κτισις'),
(6060, 48, 'TR1550', 'TR1550', 'el', 'GAL', 6, 16, 'NT', 'και οσοι τω κανονι τουτω στοιχησουσιν ειρηνη επ αυτους και ελεος και επι τον ισραηλ του θεου'),
(6061, 48, 'TR1550', 'TR1550', 'el', 'GAL', 6, 17, 'NT', 'του λοιπου κοπους μοι μηδεις παρεχετω εγω γαρ τα στιγματα του κυριου ιησου εν τω σωματι μου βασταζω'),
(6062, 48, 'TR1550', 'TR1550', 'el', 'GAL', 6, 18, 'NT', 'η χαρις του κυριου ημων ιησου χριστου μετα του πνευματος υμων αδελφοι αμην [προς γαλατας εγραφη απο ρωμης]'),
(6063, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 1, 'NT', 'παυλος αποστολος ιησου χριστου δια θεληματος θεου τοις αγιοις τοις ουσιν εν εφεσω και πιστοις εν χριστω ιησου'),
(6064, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 2, 'NT', 'χαρις υμιν και ειρηνη απο θεου πατρος ημων και κυριου ιησου χριστου'),
(6065, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 3, 'NT', 'ευλογητος ο θεος και πατηρ του κυριου ημων ιησου χριστου ο ευλογησας ημας εν παση ευλογια πνευματικη εν τοις επουρανιοις χριστω'),
(6066, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 4, 'NT', 'καθως εξελεξατο ημας εν αυτω προ καταβολης κοσμου ειναι ημας αγιους και αμωμους κατενωπιον αυτου εν αγαπη'),
(6067, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 5, 'NT', 'προορισας ημας εις υιοθεσιαν δια ιησου χριστου εις αυτον κατα την ευδοκιαν του θεληματος αυτου'),
(6068, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 6, 'NT', 'εις επαινον δοξης της χαριτος αυτου εν η εχαριτωσεν ημας εν τω ηγαπημενω'),
(6069, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 7, 'NT', 'εν ω εχομεν την απολυτρωσιν δια του αιματος αυτου την αφεσιν των παραπτωματων κατα τον πλουτον της χαριτος αυτου'),
(6070, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 8, 'NT', 'ης επερισσευσεν εις ημας εν παση σοφια και φρονησει'),
(6071, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 9, 'NT', 'γνωρισας ημιν το μυστηριον του θεληματος αυτου κατα την ευδοκιαν αυτου ην προεθετο εν αυτω'),
(6072, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 10, 'NT', 'εις οικονομιαν του πληρωματος των καιρων ανακεφαλαιωσασθαι τα παντα εν τω χριστω τα τε εν τοις ουρανοις και τα επι της γης'),
(6073, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 11, 'NT', 'εν αυτω εν ω και εκληρωθημεν προορισθεντες κατα προθεσιν του τα παντα ενεργουντος κατα την βουλην του θεληματος αυτου'),
(6074, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 12, 'NT', 'εις το ειναι ημας εις επαινον της δοξης αυτου τους προηλπικοτας εν τω χριστω'),
(6075, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 13, 'NT', 'εν ω και υμεις ακουσαντες τον λογον της αληθειας το ευαγγελιον της σωτηριας υμων εν ω και πιστευσαντες εσφραγισθητε τω πνευματι της επαγγελιας τω αγιω'),
(6076, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 14, 'NT', 'ος εστιν αρραβων της κληρονομιας ημων εις απολυτρωσιν της περιποιησεως εις επαινον της δοξης αυτου'),
(6077, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 15, 'NT', 'δια τουτο καγω ακουσας την καθ υμας πιστιν εν τω κυριω ιησου και την αγαπην την εις παντας τους αγιους'),
(6078, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 16, 'NT', 'ου παυομαι ευχαριστων υπερ υμων μνειαν υμων ποιουμενος επι των προσευχων μου'),
(6079, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 17, 'NT', 'ινα ο θεος του κυριου ημων ιησου χριστου ο πατηρ της δοξης δωη υμιν πνευμα σοφιας και αποκαλυψεως εν επιγνωσει αυτου'),
(6080, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 18, 'NT', 'πεφωτισμενους τους οφθαλμους της διανοιας υμων εις το ειδεναι υμας τις εστιν η ελπις της κλησεως αυτου και τις ο πλουτος της δοξης της κληρονομιας αυτου εν τοις αγιοις'),
(6081, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 19, 'NT', 'και τι το υπερβαλλον μεγεθος της δυναμεως αυτου εις ημας τους πιστευοντας κατα την ενεργειαν του κρατους της ισχυος αυτου'),
(6082, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 20, 'NT', 'ην ενηργησεν εν τω χριστω εγειρας αυτον εκ νεκρων και εκαθισεν εν δεξια αυτου εν τοις επουρανιοις'),
(6083, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 21, 'NT', 'υπερανω πασης αρχης και εξουσιας και δυναμεως και κυριοτητος και παντος ονοματος ονομαζομενου ου μονον εν τω αιωνι τουτω αλλα και εν τω μελλοντι'),
(6084, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 22, 'NT', 'και παντα υπεταξεν υπο τους ποδας αυτου και αυτον εδωκεν κεφαλην υπερ παντα τη εκκλησια'),
(6085, 49, 'TR1550', 'TR1550', 'el', 'EPH', 1, 23, 'NT', 'ητις εστιν το σωμα αυτου το πληρωμα του παντα εν πασιν πληρουμενου'),
(6086, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 1, 'NT', 'και υμας οντας νεκρους τοις παραπτωμασιν και ταις αμαρτιαις'),
(6087, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 2, 'NT', 'εν αις ποτε περιεπατησατε κατα τον αιωνα του κοσμου τουτου κατα τον αρχοντα της εξουσιας του αερος του πνευματος του νυν ενεργουντος εν τοις υιοις της απειθειας'),
(6088, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 3, 'NT', 'εν οις και ημεις παντες ανεστραφημεν ποτε εν ταις επιθυμιαις της σαρκος ημων ποιουντες τα θεληματα της σαρκος και των διανοιων και ημεν τεκνα φυσει οργης ως και οι λοιποι'),
(6089, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 4, 'NT', 'ο δε θεος πλουσιος ων εν ελεει δια την πολλην αγαπην αυτου ην ηγαπησεν ημας'),
(6090, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 5, 'NT', 'και οντας ημας νεκρους τοις παραπτωμασιν συνεζωοποιησεν τω χριστω χαριτι εστε σεσωσμενοι'),
(6091, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 6, 'NT', 'και συνηγειρεν και συνεκαθισεν εν τοις επουρανιοις εν χριστω ιησου'),
(6092, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 7, 'NT', 'ινα ενδειξηται εν τοις αιωσιν τοις επερχομενοις τον υπερβαλλοντα πλουτον της χαριτος αυτου εν χρηστοτητι εφ ημας εν χριστω ιησου'),
(6093, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 8, 'NT', 'τη γαρ χαριτι εστε σεσωσμενοι δια της πιστεως και τουτο ουκ εξ υμων θεου το δωρον'),
(6094, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 9, 'NT', 'ουκ εξ εργων ινα μη τις καυχησηται'),
(6095, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 10, 'NT', 'αυτου γαρ εσμεν ποιημα κτισθεντες εν χριστω ιησου επι εργοις αγαθοις οις προητοιμασεν ο θεος ινα εν αυτοις περιπατησωμεν'),
(6096, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 11, 'NT', 'διο μνημονευετε οτι υμεις ποτε τα εθνη εν σαρκι οι λεγομενοι ακροβυστια υπο της λεγομενης περιτομης εν σαρκι χειροποιητου'),
(6097, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 12, 'NT', 'οτι ητε εν τω καιρω εκεινω χωρις χριστου απηλλοτριωμενοι της πολιτειας του ισραηλ και ξενοι των διαθηκων της επαγγελιας ελπιδα μη εχοντες και αθεοι εν τω κοσμω'),
(6098, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 13, 'NT', 'νυνι δε εν χριστω ιησου υμεις οι ποτε οντες μακραν εγγυς εγενηθητε εν τω αιματι του χριστου'),
(6099, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 14, 'NT', 'αυτος γαρ εστιν η ειρηνη ημων ο ποιησας τα αμφοτερα εν και το μεσοτοιχον του φραγμου λυσας'),
(6100, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 15, 'NT', 'την εχθραν εν τη σαρκι αυτου τον νομον των εντολων εν δογμασιν καταργησας ινα τους δυο κτιση εν εαυτω εις ενα καινον ανθρωπον ποιων ειρηνην'),
(6101, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 16, 'NT', 'και αποκαταλλαξη τους αμφοτερους εν ενι σωματι τω θεω δια του σταυρου αποκτεινας την εχθραν εν αυτω'),
(6102, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 17, 'NT', 'και ελθων ευηγγελισατο ειρηνην υμιν τοις μακραν και τοις εγγυς'),
(6103, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 18, 'NT', 'οτι δι αυτου εχομεν την προσαγωγην οι αμφοτεροι εν ενι πνευματι προς τον πατερα'),
(6104, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 19, 'NT', 'αρα ουν ουκετι εστε ξενοι και παροικοι αλλα συμπολιται των αγιων και οικειοι του θεου'),
(6105, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 20, 'NT', 'εποικοδομηθεντες επι τω θεμελιω των αποστολων και προφητων οντος ακρογωνιαιου αυτου ιησου χριστου'),
(6106, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 21, 'NT', 'εν ω πασα η οικοδομη συναρμολογουμενη αυξει εις ναον αγιον εν κυριω'),
(6107, 49, 'TR1550', 'TR1550', 'el', 'EPH', 2, 22, 'NT', 'εν ω και υμεις συνοικοδομεισθε εις κατοικητηριον του θεου εν πνευματι'),
(6108, 49, 'TR1550', 'TR1550', 'el', 'EPH', 3, 1, 'NT', 'τουτου χαριν εγω παυλος ο δεσμιος του χριστου ιησου υπερ υμων των εθνων'),
(6109, 49, 'TR1550', 'TR1550', 'el', 'EPH', 3, 2, 'NT', 'ειγε ηκουσατε την οικονομιαν της χαριτος του θεου της δοθεισης μοι εις υμας'),
(6110, 49, 'TR1550', 'TR1550', 'el', 'EPH', 3, 3, 'NT', 'οτι κατα αποκαλυψιν εγνωρισεν μοι το μυστηριον καθως προεγραψα εν ολιγω'),
(6111, 49, 'TR1550', 'TR1550', 'el', 'EPH', 3, 4, 'NT', 'προς ο δυνασθε αναγινωσκοντες νοησαι την συνεσιν μου εν τω μυστηριω του χριστου'),
(6112, 49, 'TR1550', 'TR1550', 'el', 'EPH', 3, 5, 'NT', 'ο εν ετεραις γενεαις ουκ εγνωρισθη τοις υιοις των ανθρωπων ως νυν απεκαλυφθη τοις αγιοις αποστολοις αυτου και προφηταις εν πνευματι'),
(6113, 49, 'TR1550', 'TR1550', 'el', 'EPH', 3, 6, 'NT', 'ειναι τα εθνη συγκληρονομα και συσσωμα και συμμετοχα της επαγγελιας αυτου εν τω χριστω δια του ευαγγελιου'),
(6114, 49, 'TR1550', 'TR1550', 'el', 'EPH', 3, 7, 'NT', 'ου εγενομην διακονος κατα την δωρεαν της χαριτος του θεου την δοθεισαν μοι κατα την ενεργειαν της δυναμεως αυτου'),
(6115, 49, 'TR1550', 'TR1550', 'el', 'EPH', 3, 8, 'NT', 'εμοι τω ελαχιστοτερω παντων των αγιων εδοθη η χαρις αυτη εν τοις εθνεσιν ευαγγελισασθαι τον ανεξιχνιαστον πλουτον του χριστου'),
(6116, 49, 'TR1550', 'TR1550', 'el', 'EPH', 3, 9, 'NT', 'και φωτισαι παντας τις η κοινωνια του μυστηριου του αποκεκρυμμενου απο των αιωνων εν τω θεω τω τα παντα κτισαντι δια ιησου χριστου'),
(6117, 49, 'TR1550', 'TR1550', 'el', 'EPH', 3, 10, 'NT', 'ινα γνωρισθη νυν ταις αρχαις και ταις εξουσιαις εν τοις επουρανιοις δια της εκκλησιας η πολυποικιλος σοφια του θεου'),
(6118, 49, 'TR1550', 'TR1550', 'el', 'EPH', 3, 11, 'NT', 'κατα προθεσιν των αιωνων ην εποιησεν εν χριστω ιησου τω κυριω ημων'),
(6119, 49, 'TR1550', 'TR1550', 'el', 'EPH', 3, 12, 'NT', 'εν ω εχομεν την παρρησιαν και την προσαγωγην εν πεποιθησει δια της πιστεως αυτου'),
(6120, 49, 'TR1550', 'TR1550', 'el', 'EPH', 3, 13, 'NT', 'διο αιτουμαι μη εκκακειν εν ταις θλιψεσιν μου υπερ υμων ητις εστιν δοξα υμων'),
(6121, 49, 'TR1550', 'TR1550', 'el', 'EPH', 3, 14, 'NT', 'τουτου χαριν καμπτω τα γονατα μου προς τον πατερα του κυριου ημων ιησου χριστου'),
(6122, 49, 'TR1550', 'TR1550', 'el', 'EPH', 3, 15, 'NT', 'εξ ου πασα πατρια εν ουρανοις και επι γης ονομαζεται'),
(6123, 49, 'TR1550', 'TR1550', 'el', 'EPH', 3, 16, 'NT', 'ινα δωη υμιν κατα τον πλουτον της δοξης αυτου δυναμει κραταιωθηναι δια του πνευματος αυτου εις τον εσω ανθρωπον'),
(6124, 49, 'TR1550', 'TR1550', 'el', 'EPH', 3, 17, 'NT', 'κατοικησαι τον χριστον δια της πιστεως εν ταις καρδιαις υμων'),
(6125, 49, 'TR1550', 'TR1550', 'el', 'EPH', 3, 18, 'NT', 'εν αγαπη ερριζωμενοι και τεθεμελιωμενοι ινα εξισχυσητε καταλαβεσθαι συν πασιν τοις αγιοις τι το πλατος και μηκος και βαθος και υψος'),
(6126, 49, 'TR1550', 'TR1550', 'el', 'EPH', 3, 19, 'NT', 'γνωναι τε την υπερβαλλουσαν της γνωσεως αγαπην του χριστου ινα πληρωθητε εις παν το πληρωμα του θεου'),
(6127, 49, 'TR1550', 'TR1550', 'el', 'EPH', 3, 20, 'NT', 'τω δε δυναμενω υπερ παντα ποιησαι υπερ εκπερισσου ων αιτουμεθα η νοουμεν κατα την δυναμιν την ενεργουμενην εν ημιν'),
(6128, 49, 'TR1550', 'TR1550', 'el', 'EPH', 3, 21, 'NT', 'αυτω η δοξα εν τη εκκλησια εν χριστω ιησου εις πασας τας γενεας του αιωνος των αιωνων αμην'),
(6129, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 1, 'NT', 'παρακαλω ουν υμας εγω ο δεσμιος εν κυριω αξιως περιπατησαι της κλησεως ης εκληθητε'),
(6130, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 2, 'NT', 'μετα πασης ταπεινοφροσυνης και πραοτητος μετα μακροθυμιας ανεχομενοι αλληλων εν αγαπη'),
(6131, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 3, 'NT', 'σπουδαζοντες τηρειν την ενοτητα του πνευματος εν τω συνδεσμω της ειρηνης'),
(6132, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 4, 'NT', 'εν σωμα και εν πνευμα καθως και εκληθητε εν μια ελπιδι της κλησεως υμων'),
(6133, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 5, 'NT', 'εις κυριος μια πιστις εν βαπτισμα'),
(6134, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 6, 'NT', 'εις θεος και πατηρ παντων ο επι παντων και δια παντων και εν πασιν υμιν'),
(6135, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 7, 'NT', 'ενι δε εκαστω ημων εδοθη η χαρις κατα το μετρον της δωρεας του χριστου'),
(6136, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 8, 'NT', 'διο λεγει αναβας εις υψος ηχμαλωτευσεν αιχμαλωσιαν και εδωκεν δοματα τοις ανθρωποις'),
(6137, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 9, 'NT', 'το δε ανεβη τι εστιν ει μη οτι και κατεβη πρωτον εις τα κατωτερα μερη της γης'),
(6138, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 10, 'NT', 'ο καταβας αυτος εστιν και ο αναβας υπερανω παντων των ουρανων ινα πληρωση τα παντα'),
(6139, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 11, 'NT', 'και αυτος εδωκεν τους μεν αποστολους τους δε προφητας τους δε ευαγγελιστας τους δε ποιμενας και διδασκαλους'),
(6140, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 12, 'NT', 'προς τον καταρτισμον των αγιων εις εργον διακονιας εις οικοδομην του σωματος του χριστου'),
(6141, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 13, 'NT', 'μεχρι καταντησωμεν οι παντες εις την ενοτητα της πιστεως και της επιγνωσεως του υιου του θεου εις ανδρα τελειον εις μετρον ηλικιας του πληρωματος του χριστου'),
(6142, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 14, 'NT', 'ινα μηκετι ωμεν νηπιοι κλυδωνιζομενοι και περιφερομενοι παντι ανεμω της διδασκαλιας εν τη κυβεια των ανθρωπων εν πανουργια προς την μεθοδειαν της πλανης'),
(6143, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 15, 'NT', 'αληθευοντες δε εν αγαπη αυξησωμεν εις αυτον τα παντα ος εστιν η κεφαλη ο χριστος'),
(6144, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 16, 'NT', 'εξ ου παν το σωμα συναρμολογουμενον και συμβιβαζομενον δια πασης αφης της επιχορηγιας κατ ενεργειαν εν μετρω ενος εκαστου μερους την αυξησιν του σωματος ποιειται εις οικοδομην εαυτου εν αγαπη'),
(6145, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 17, 'NT', 'τουτο ουν λεγω και μαρτυρομαι εν κυριω μηκετι υμας περιπατειν καθως και τα λοιπα εθνη περιπατει εν ματαιοτητι του νοος αυτων'),
(6146, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 18, 'NT', 'εσκοτισμενοι τη διανοια οντες απηλλοτριωμενοι της ζωης του θεου δια την αγνοιαν την ουσαν εν αυτοις δια την πωρωσιν της καρδιας αυτων'),
(6147, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 19, 'NT', 'οιτινες απηλγηκοτες εαυτους παρεδωκαν τη ασελγεια εις εργασιαν ακαθαρσιας πασης εν πλεονεξια'),
(6148, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 20, 'NT', 'υμεις δε ουχ ουτως εμαθετε τον χριστον'),
(6149, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 21, 'NT', 'ειγε αυτον ηκουσατε και εν αυτω εδιδαχθητε καθως εστιν αληθεια εν τω ιησου'),
(6150, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 22, 'NT', 'αποθεσθαι υμας κατα την προτεραν αναστροφην τον παλαιον ανθρωπον τον φθειρομενον κατα τας επιθυμιας της απατης'),
(6151, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 23, 'NT', 'ανανεουσθαι δε τω πνευματι του νοος υμων'),
(6152, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 24, 'NT', 'και ενδυσασθαι τον καινον ανθρωπον τον κατα θεον κτισθεντα εν δικαιοσυνη και οσιοτητι της αληθειας'),
(6153, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 25, 'NT', 'διο αποθεμενοι το ψευδος λαλειτε αληθειαν εκαστος μετα του πλησιον αυτου οτι εσμεν αλληλων μελη'),
(6154, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 26, 'NT', 'οργιζεσθε και μη αμαρτανετε ο ηλιος μη επιδυετω επι τω παροργισμω υμων'),
(6155, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 27, 'NT', 'μητε διδοτε τοπον τω διαβολω'),
(6156, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 28, 'NT', 'ο κλεπτων μηκετι κλεπτετω μαλλον δε κοπιατω εργαζομενος το αγαθον ταις χερσιν ινα εχη μεταδιδοναι τω χρειαν εχοντι'),
(6157, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 29, 'NT', 'πας λογος σαπρος εκ του στοματος υμων μη εκπορευεσθω αλλ ει τις αγαθος προς οικοδομην της χρειας ινα δω χαριν τοις ακουουσιν'),
(6158, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 30, 'NT', 'και μη λυπειτε το πνευμα το αγιον του θεου εν ω εσφραγισθητε εις ημεραν απολυτρωσεως'),
(6159, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 31, 'NT', 'πασα πικρια και θυμος και οργη και κραυγη και βλασφημια αρθητω αφ υμων συν παση κακια'),
(6160, 49, 'TR1550', 'TR1550', 'el', 'EPH', 4, 32, 'NT', 'γινεσθε δε εις αλληλους χρηστοι ευσπλαγχνοι χαριζομενοι εαυτοις καθως και ο θεος εν χριστω εχαρισατο υμιν'),
(6161, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 1, 'NT', 'γινεσθε ουν μιμηται του θεου ως τεκνα αγαπητα'),
(6162, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 2, 'NT', 'και περιπατειτε εν αγαπη καθως και ο χριστος ηγαπησεν ημας και παρεδωκεν εαυτον υπερ ημων προσφοραν και θυσιαν τω θεω εις οσμην ευωδιας'),
(6163, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 3, 'NT', 'πορνεια δε και πασα ακαθαρσια η πλεονεξια μηδε ονομαζεσθω εν υμιν καθως πρεπει αγιοις'),
(6164, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 4, 'NT', 'και αισχροτης και μωρολογια η ευτραπελια τα ουκ ανηκοντα αλλα μαλλον ευχαριστια'),
(6165, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 5, 'NT', 'τουτο γαρ εστε γινωσκοντες οτι πας πορνος η ακαθαρτος η πλεονεκτης ος εστιν ειδωλολατρης ουκ εχει κληρονομιαν εν τη βασιλεια του χριστου και θεου'),
(6166, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 6, 'NT', 'μηδεις υμας απατατω κενοις λογοις δια ταυτα γαρ ερχεται η οργη του θεου επι τους υιους της απειθειας'),
(6167, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 7, 'NT', 'μη ουν γινεσθε συμμετοχοι αυτων'),
(6168, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 8, 'NT', 'ητε γαρ ποτε σκοτος νυν δε φως εν κυριω ως τεκνα φωτος περιπατειτε'),
(6169, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 9, 'NT', 'ο γαρ καρπος του πνευματος εν παση αγαθωσυνη και δικαιοσυνη και αληθεια'),
(6170, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 10, 'NT', 'δοκιμαζοντες τι εστιν ευαρεστον τω κυριω'),
(6171, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 11, 'NT', 'και μη συγκοινωνειτε τοις εργοις τοις ακαρποις του σκοτους μαλλον δε και ελεγχετε'),
(6172, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 12, 'NT', 'τα γαρ κρυφη γινομενα υπ αυτων αισχρον εστιν και λεγειν'),
(6173, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 13, 'NT', 'τα δε παντα ελεγχομενα υπο του φωτος φανερουται παν γαρ το φανερουμενον φως εστιν'),
(6174, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 14, 'NT', 'διο λεγει εγειραι ο καθευδων και αναστα εκ των νεκρων και επιφαυσει σοι ο χριστος'),
(6175, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 15, 'NT', 'βλεπετε ουν πως ακριβως περιπατειτε μη ως ασοφοι αλλ ως σοφοι'),
(6176, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 16, 'NT', 'εξαγοραζομενοι τον καιρον οτι αι ημεραι πονηραι εισιν'),
(6177, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 17, 'NT', 'δια τουτο μη γινεσθε αφρονες αλλα συνιεντες τι το θελημα του κυριου'),
(6178, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 18, 'NT', 'και μη μεθυσκεσθε οινω εν ω εστιν ασωτια αλλα πληρουσθε εν πνευματι'),
(6179, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 19, 'NT', 'λαλουντες εαυτοις ψαλμοις και υμνοις και ωδαις πνευματικαις αδοντες και ψαλλοντες εν τη καρδια υμων τω κυριω'),
(6180, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 20, 'NT', 'ευχαριστουντες παντοτε υπερ παντων εν ονοματι του κυριου ημων ιησου χριστου τω θεω και πατρι'),
(6181, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 21, 'NT', 'υποτασσομενοι αλληλοις εν φοβω θεου'),
(6182, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 22, 'NT', 'αι γυναικες τοις ιδιοις ανδρασιν υποτασσεσθε ως τω κυριω'),
(6183, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 23, 'NT', 'οτι ο ανηρ εστιν κεφαλη της γυναικος ως και ο χριστος κεφαλη της εκκλησιας και αυτος εστιν σωτηρ του σωματος'),
(6184, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 24, 'NT', 'αλλ ωσπερ η εκκλησια υποτασσεται τω χριστω ουτως και αι γυναικες τοις ιδιοις ανδρασιν εν παντι'),
(6185, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 25, 'NT', 'οι ανδρες αγαπατε τας γυναικας εαυτων καθως και ο χριστος ηγαπησεν την εκκλησιαν και εαυτον παρεδωκεν υπερ αυτης'),
(6186, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 26, 'NT', 'ινα αυτην αγιαση καθαρισας τω λουτρω του υδατος εν ρηματι'),
(6187, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 27, 'NT', 'ινα παραστηση αυτην εαυτω ενδοξον την εκκλησιαν μη εχουσαν σπιλον η ρυτιδα η τι των τοιουτων αλλ ινα η αγια και αμωμος'),
(6188, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 28, 'NT', 'ουτως οφειλουσιν οι ανδρες αγαπαν τας εαυτων γυναικας ως τα εαυτων σωματα ο αγαπων την εαυτου γυναικα εαυτον αγαπα'),
(6189, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 29, 'NT', 'ουδεις γαρ ποτε την εαυτου σαρκα εμισησεν αλλ εκτρεφει και θαλπει αυτην καθως και ο κυριος την εκκλησιαν'),
(6190, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 30, 'NT', 'οτι μελη εσμεν του σωματος αυτου εκ της σαρκος αυτου και εκ των οστεων αυτου'),
(6191, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 31, 'NT', 'αντι τουτου καταλειψει ανθρωπος τον πατερα αυτου και την μητερα και προσκολληθησεται προς την γυναικα αυτου και εσονται οι δυο εις σαρκα μιαν'),
(6192, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 32, 'NT', 'το μυστηριον τουτο μεγα εστιν εγω δε λεγω εις χριστον και εις την εκκλησιαν'),
(6193, 49, 'TR1550', 'TR1550', 'el', 'EPH', 5, 33, 'NT', 'πλην και υμεις οι καθ ενα εκαστος την εαυτου γυναικα ουτως αγαπατω ως εαυτον η δε γυνη ινα φοβηται τον ανδρα'),
(6194, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 1, 'NT', 'τα τεκνα υπακουετε τοις γονευσιν υμων εν κυριω τουτο γαρ εστιν δικαιον'),
(6195, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 2, 'NT', 'τιμα τον πατερα σου και την μητερα ητις εστιν εντολη πρωτη εν επαγγελια'),
(6196, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 3, 'NT', 'ινα ευ σοι γενηται και εση μακροχρονιος επι της γης'),
(6197, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 4, 'NT', 'και οι πατερες μη παροργιζετε τα τεκνα υμων αλλ εκτρεφετε αυτα εν παιδεια και νουθεσια κυριου'),
(6198, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 5, 'NT', 'οι δουλοι υπακουετε τοις κυριοις κατα σαρκα μετα φοβου και τρομου εν απλοτητι της καρδιας υμων ως τω χριστω'),
(6199, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 6, 'NT', 'μη κατ οφθαλμοδουλειαν ως ανθρωπαρεσκοι αλλ ως δουλοι του χριστου ποιουντες το θελημα του θεου εκ ψυχης'),
(6200, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 7, 'NT', 'μετ ευνοιας δουλευοντες τω κυριω και ουκ ανθρωποις'),
(6201, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 8, 'NT', 'ειδοτες οτι ο εαν τι εκαστος ποιηση αγαθον τουτο κομιειται παρα του κυριου ειτε δουλος ειτε ελευθερος'),
(6202, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 9, 'NT', 'και οι κυριοι τα αυτα ποιειτε προς αυτους ανιεντες την απειλην ειδοτες οτι και υμων αυτων ο κυριος εστιν εν ουρανοις και προσωποληψια ουκ εστιν παρ αυτω'),
(6203, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 10, 'NT', 'το λοιπον αδελφοι μου ενδυναμουσθε εν κυριω και εν τω κρατει της ισχυος αυτου'),
(6204, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 11, 'NT', 'ενδυσασθε την πανοπλιαν του θεου προς το δυνασθαι υμας στηναι προς τας μεθοδειας του διαβολου'),
(6205, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 12, 'NT', 'οτι ουκ εστιν ημιν η παλη προς αιμα και σαρκα αλλα προς τας αρχας προς τας εξουσιας προς τους κοσμοκρατορας του σκοτους του αιωνος τουτου προς τα πνευματικα της πονηριας εν τοις επουρανιοις'),
(6206, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 13, 'NT', 'δια τουτο αναλαβετε την πανοπλιαν του θεου ινα δυνηθητε αντιστηναι εν τη ημερα τη πονηρα και απαντα κατεργασαμενοι στηναι'),
(6207, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 14, 'NT', 'στητε ουν περιζωσαμενοι την οσφυν υμων εν αληθεια και ενδυσαμενοι τον θωρακα της δικαιοσυνης'),
(6208, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 15, 'NT', 'και υποδησαμενοι τους ποδας εν ετοιμασια του ευαγγελιου της ειρηνης'),
(6209, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 16, 'NT', 'επι πασιν αναλαβοντες τον θυρεον της πιστεως εν ω δυνησεσθε παντα τα βελη του πονηρου τα πεπυρωμενα σβεσαι'),
(6210, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 17, 'NT', 'και την περικεφαλαιαν του σωτηριου δεξασθε και την μαχαιραν του πνευματος ο εστιν ρημα θεου'),
(6211, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 18, 'NT', 'δια πασης προσευχης και δεησεως προσευχομενοι εν παντι καιρω εν πνευματι και εις αυτο τουτο αγρυπνουντες εν παση προσκαρτερησει και δεησει περι παντων των αγιων'),
(6212, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 19, 'NT', 'και υπερ εμου ινα μοι δοθειη λογος εν ανοιξει του στοματος μου εν παρρησια γνωρισαι το μυστηριον του ευαγγελιου'),
(6213, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 20, 'NT', 'υπερ ου πρεσβευω εν αλυσει ινα εν αυτω παρρησιασωμαι ως δει με λαλησαι'),
(6214, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 21, 'NT', 'ινα δε ειδητε και υμεις τα κατ εμε τι πρασσω παντα υμιν γνωρισει τυχικος ο αγαπητος αδελφος και πιστος διακονος εν κυριω'),
(6215, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 22, 'NT', 'ον επεμψα προς υμας εις αυτο τουτο ινα γνωτε τα περι ημων και παρακαλεση τας καρδιας υμων'),
(6216, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 23, 'NT', 'ειρηνη τοις αδελφοις και αγαπη μετα πιστεως απο θεου πατρος και κυριου ιησου χριστου'),
(6217, 49, 'TR1550', 'TR1550', 'el', 'EPH', 6, 24, 'NT', 'η χαρις μετα παντων των αγαπωντων τον κυριον ημων ιησουν χριστον εν αφθαρσια αμην [προς εφεσιους εγραφη απο ρωμης δια τυχικου]'),
(6218, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 1, 'NT', 'παυλος και τιμοθεος δουλοι ιησου χριστου πασιν τοις αγιοις εν χριστω ιησου τοις ουσιν εν φιλιπποις συν επισκοποις και διακονοις'),
(6219, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 2, 'NT', 'χαρις υμιν και ειρηνη απο θεου πατρος ημων και κυριου ιησου χριστου'),
(6220, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 3, 'NT', 'ευχαριστω τω θεω μου επι παση τη μνεια υμων'),
(6221, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 4, 'NT', 'παντοτε εν παση δεησει μου υπερ παντων υμων μετα χαρας την δεησιν ποιουμενος'),
(6222, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 5, 'NT', 'επι τη κοινωνια υμων εις το ευαγγελιον απο πρωτης ημερας αχρι του νυν'),
(6223, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 6, 'NT', 'πεποιθως αυτο τουτο οτι ο εναρξαμενος εν υμιν εργον αγαθον επιτελεσει αχρις ημερας ιησου χριστου'),
(6224, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 7, 'NT', 'καθως εστιν δικαιον εμοι τουτο φρονειν υπερ παντων υμων δια το εχειν με εν τη καρδια υμας εν τε τοις δεσμοις μου και τη απολογια και βεβαιωσει του ευαγγελιου συγκοινωνους μου της χαριτος παντας υμας οντας'),
(6225, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 8, 'NT', 'μαρτυς γαρ μου εστιν ο θεος ως επιποθω παντας υμας εν σπλαγχνοις ιησου χριστου'),
(6226, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 9, 'NT', 'και τουτο προσευχομαι ινα η αγαπη υμων ετι μαλλον και μαλλον περισσευη εν επιγνωσει και παση αισθησει'),
(6227, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 10, 'NT', 'εις το δοκιμαζειν υμας τα διαφεροντα ινα ητε ειλικρινεις και απροσκοποι εις ημεραν χριστου'),
(6228, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 11, 'NT', 'πεπληρωμενοι καρπων δικαιοσυνης των δια ιησου χριστου εις δοξαν και επαινον θεου'),
(6229, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 12, 'NT', 'γινωσκειν δε υμας βουλομαι αδελφοι οτι τα κατ εμε μαλλον εις προκοπην του ευαγγελιου εληλυθεν'),
(6230, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 13, 'NT', 'ωστε τους δεσμους μου φανερους εν χριστω γενεσθαι εν ολω τω πραιτωριω και τοις λοιποις πασιν'),
(6231, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 14, 'NT', 'και τους πλειονας των αδελφων εν κυριω πεποιθοτας τοις δεσμοις μου περισσοτερως τολμαν αφοβως τον λογον λαλειν'),
(6232, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 15, 'NT', 'τινες μεν και δια φθονον και εριν τινες δε και δι ευδοκιαν τον χριστον κηρυσσουσιν'),
(6233, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 16, 'NT', 'οι μεν εξ εριθειας τον χριστον καταγγελλουσιν ουχ αγνως οιομενοι θλιψιν επιφερειν τοις δεσμοις μου'),
(6234, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 17, 'NT', 'οι δε εξ αγαπης ειδοτες οτι εις απολογιαν του ευαγγελιου κειμαι'),
(6235, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 18, 'NT', 'τι γαρ πλην παντι τροπω ειτε προφασει ειτε αληθεια χριστος καταγγελλεται και εν τουτω χαιρω αλλα και χαρησομαι'),
(6236, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 19, 'NT', 'οιδα γαρ οτι τουτο μοι αποβησεται εις σωτηριαν δια της υμων δεησεως και επιχορηγιας του πνευματος ιησου χριστου'),
(6237, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 20, 'NT', 'κατα την αποκαραδοκιαν και ελπιδα μου οτι εν ουδενι αισχυνθησομαι αλλ εν παση παρρησια ως παντοτε και νυν μεγαλυνθησεται χριστος εν τω σωματι μου ειτε δια ζωης ειτε δια θανατου'),
(6238, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 21, 'NT', 'εμοι γαρ το ζην χριστος και το αποθανειν κερδος'),
(6239, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 22, 'NT', 'ει δε το ζην εν σαρκι τουτο μοι καρπος εργου και τι αιρησομαι ου γνωριζω'),
(6240, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 23, 'NT', 'συνεχομαι γαρ εκ των δυο την επιθυμιαν εχων εις το αναλυσαι και συν χριστω ειναι πολλω μαλλον κρεισσον'),
(6241, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 24, 'NT', 'το δε επιμενειν εν τη σαρκι αναγκαιοτερον δι υμας'),
(6242, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 25, 'NT', 'και τουτο πεποιθως οιδα οτι μενω και συμπαραμενω πασιν υμιν εις την υμων προκοπην και χαραν της πιστεως'),
(6243, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 26, 'NT', 'ινα το καυχημα υμων περισσευη εν χριστω ιησου εν εμοι δια της εμης παρουσιας παλιν προς υμας'),
(6244, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 27, 'NT', 'μονον αξιως του ευαγγελιου του χριστου πολιτευεσθε ινα ειτε ελθων και ιδων υμας ειτε απων ακουσω τα περι υμων οτι στηκετε εν ενι πνευματι μια ψυχη συναθλουντες τη πιστει του ευαγγελιου'),
(6245, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 28, 'NT', 'και μη πτυρομενοι εν μηδενι υπο των αντικειμενων ητις αυτοις μεν εστιν ενδειξις απωλειας υμιν δε σωτηριας και τουτο απο θεου'),
(6246, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 29, 'NT', 'οτι υμιν εχαρισθη το υπερ χριστου ου μονον το εις αυτον πιστευειν αλλα και το υπερ αυτου πασχειν'),
(6247, 50, 'TR1550', 'TR1550', 'el', 'PHP', 1, 30, 'NT', 'τον αυτον αγωνα εχοντες οιον ιδετε εν εμοι και νυν ακουετε εν εμοι'),
(6248, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 1, 'NT', 'ει τις ουν παρακλησις εν χριστω ει τι παραμυθιον αγαπης ει τις κοινωνια πνευματος ει τινα σπλαγχνα και οικτιρμοι'),
(6249, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 2, 'NT', 'πληρωσατε μου την χαραν ινα το αυτο φρονητε την αυτην αγαπην εχοντες συμψυχοι το εν φρονουντες'),
(6250, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 3, 'NT', 'μηδεν κατα εριθειαν η κενοδοξιαν αλλα τη ταπεινοφροσυνη αλληλους ηγουμενοι υπερεχοντας εαυτων'),
(6251, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 4, 'NT', 'μη τα εαυτων εκαστος σκοπειτε αλλα και τα ετερων εκαστος'),
(6252, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 5, 'NT', 'τουτο γαρ φρονεισθω εν υμιν ο και εν χριστω ιησου'),
(6253, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 6, 'NT', 'ος εν μορφη θεου υπαρχων ουχ αρπαγμον ηγησατο το ειναι ισα θεω'),
(6254, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 7, 'NT', 'αλλ εαυτον εκενωσεν μορφην δουλου λαβων εν ομοιωματι ανθρωπων γενομενος'),
(6255, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 8, 'NT', 'και σχηματι ευρεθεις ως ανθρωπος εταπεινωσεν εαυτον γενομενος υπηκοος μεχρι θανατου θανατου δε σταυρου'),
(6256, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 9, 'NT', 'διο και ο θεος αυτον υπερυψωσεν και εχαρισατο αυτω ονομα το υπερ παν ονομα'),
(6257, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 10, 'NT', 'ινα εν τω ονοματι ιησου παν γονυ καμψη επουρανιων και επιγειων και καταχθονιων'),
(6258, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 11, 'NT', 'και πασα γλωσσα εξομολογησηται οτι κυριος ιησους χριστος εις δοξαν θεου πατρος'),
(6259, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 12, 'NT', 'ωστε αγαπητοι μου καθως παντοτε υπηκουσατε μη ως εν τη παρουσια μου μονον αλλα νυν πολλω μαλλον εν τη απουσια μου μετα φοβου και τρομου την εαυτων σωτηριαν κατεργαζεσθε'),
(6260, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 13, 'NT', 'ο θεος γαρ εστιν ο ενεργων εν υμιν και το θελειν και το ενεργειν υπερ της ευδοκιας'),
(6261, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 14, 'NT', 'παντα ποιειτε χωρις γογγυσμων και διαλογισμων'),
(6262, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 15, 'NT', 'ινα γενησθε αμεμπτοι και ακεραιοι τεκνα θεου αμωμητα εν μεσω γενεας σκολιας και διεστραμμενης εν οις φαινεσθε ως φωστηρες εν κοσμω'),
(6263, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 16, 'NT', 'λογον ζωης επεχοντες εις καυχημα εμοι εις ημεραν χριστου οτι ουκ εις κενον εδραμον ουδε εις κενον εκοπιασα'),
(6264, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 17, 'NT', 'αλλ ει και σπενδομαι επι τη θυσια και λειτουργια της πιστεως υμων χαιρω και συγχαιρω πασιν υμιν'),
(6265, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 18, 'NT', 'το δ αυτο και υμεις χαιρετε και συγχαιρετε μοι'),
(6266, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 19, 'NT', 'ελπιζω δε εν κυριω ιησου τιμοθεον ταχεως πεμψαι υμιν ινα καγω ευψυχω γνους τα περι υμων'),
(6267, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 20, 'NT', 'ουδενα γαρ εχω ισοψυχον οστις γνησιως τα περι υμων μεριμνησει'),
(6268, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 21, 'NT', 'οι παντες γαρ τα εαυτων ζητουσιν ου τα του χριστου ιησου'),
(6269, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 22, 'NT', 'την δε δοκιμην αυτου γινωσκετε οτι ως πατρι τεκνον συν εμοι εδουλευσεν εις το ευαγγελιον'),
(6270, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 23, 'NT', 'τουτον μεν ουν ελπιζω πεμψαι ως αν απιδω τα περι εμε εξαυτης'),
(6271, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 24, 'NT', 'πεποιθα δε εν κυριω οτι και αυτος ταχεως ελευσομαι'),
(6272, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 25, 'NT', 'αναγκαιον δε ηγησαμην επαφροδιτον τον αδελφον και συνεργον και συστρατιωτην μου υμων δε αποστολον και λειτουργον της χρειας μου πεμψαι προς υμας'),
(6273, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 26, 'NT', 'επειδη επιποθων ην παντας υμας και αδημονων διοτι ηκουσατε οτι ησθενησεν'),
(6274, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 27, 'NT', 'και γαρ ησθενησεν παραπλησιον θανατω αλλ ο θεος αυτον ηλεησεν ουκ αυτον δε μονον αλλα και εμε ινα μη λυπην επι λυπη σχω'),
(6275, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 28, 'NT', 'σπουδαιοτερως ουν επεμψα αυτον ινα ιδοντες αυτον παλιν χαρητε καγω αλυποτερος ω'),
(6276, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 29, 'NT', 'προσδεχεσθε ουν αυτον εν κυριω μετα πασης χαρας και τους τοιουτους εντιμους εχετε'),
(6277, 50, 'TR1550', 'TR1550', 'el', 'PHP', 2, 30, 'NT', 'οτι δια το εργον του χριστου μεχρι θανατου ηγγισεν παραβουλευσαμενος τη ψυχη ινα αναπληρωση το υμων υστερημα της προς με λειτουργιας'),
(6278, 50, 'TR1550', 'TR1550', 'el', 'PHP', 3, 1, 'NT', 'το λοιπον αδελφοι μου χαιρετε εν κυριω τα αυτα γραφειν υμιν εμοι μεν ουκ οκνηρον υμιν δε ασφαλες'),
(6279, 50, 'TR1550', 'TR1550', 'el', 'PHP', 3, 2, 'NT', 'βλεπετε τους κυνας βλεπετε τους κακους εργατας βλεπετε την κατατομην'),
(6280, 50, 'TR1550', 'TR1550', 'el', 'PHP', 3, 3, 'NT', 'ημεις γαρ εσμεν η περιτομη οι πνευματι θεω λατρευοντες και καυχωμενοι εν χριστω ιησου και ουκ εν σαρκι πεποιθοτες'),
(6281, 50, 'TR1550', 'TR1550', 'el', 'PHP', 3, 4, 'NT', 'καιπερ εγω εχων πεποιθησιν και εν σαρκι ει τις δοκει αλλος πεποιθεναι εν σαρκι εγω μαλλον'),
(6282, 50, 'TR1550', 'TR1550', 'el', 'PHP', 3, 5, 'NT', 'περιτομη οκταημερος εκ γενους ισραηλ φυλης βενιαμιν εβραιος εξ εβραιων κατα νομον φαρισαιος'),
(6283, 50, 'TR1550', 'TR1550', 'el', 'PHP', 3, 6, 'NT', 'κατα ζηλον διωκων την εκκλησιαν κατα δικαιοσυνην την εν νομω γενομενος αμεμπτος'),
(6284, 50, 'TR1550', 'TR1550', 'el', 'PHP', 3, 7, 'NT', 'αλλ ατινα ην μοι κερδη ταυτα ηγημαι δια τον χριστον ζημιαν'),
(6285, 50, 'TR1550', 'TR1550', 'el', 'PHP', 3, 8, 'NT', 'αλλα μενουνγε και ηγουμαι παντα ζημιαν ειναι δια το υπερεχον της γνωσεως χριστου ιησου του κυριου μου δι ον τα παντα εζημιωθην και ηγουμαι σκυβαλα ειναι ινα χριστον κερδησω'),
(6286, 50, 'TR1550', 'TR1550', 'el', 'PHP', 3, 9, 'NT', 'και ευρεθω εν αυτω μη εχων εμην δικαιοσυνην την εκ νομου αλλα την δια πιστεως χριστου την εκ θεου δικαιοσυνην επι τη πιστει'),
(6287, 50, 'TR1550', 'TR1550', 'el', 'PHP', 3, 10, 'NT', 'του γνωναι αυτον και την δυναμιν της αναστασεως αυτου και την κοινωνιαν των παθηματων αυτου συμμορφουμενος τω θανατω αυτου'),
(6288, 50, 'TR1550', 'TR1550', 'el', 'PHP', 3, 11, 'NT', 'ει πως καταντησω εις την εξαναστασιν των νεκρων'),
(6289, 50, 'TR1550', 'TR1550', 'el', 'PHP', 3, 12, 'NT', 'ουχ οτι ηδη ελαβον η ηδη τετελειωμαι διωκω δε ει και καταλαβω εφ ω και κατεληφθην υπο του χριστου ιησου'),
(6290, 50, 'TR1550', 'TR1550', 'el', 'PHP', 3, 13, 'NT', 'αδελφοι εγω εμαυτον ου λογιζομαι κατειληφεναι εν δε τα μεν οπισω επιλανθανομενος τοις δε εμπροσθεν επεκτεινομενος'),
(6291, 50, 'TR1550', 'TR1550', 'el', 'PHP', 3, 14, 'NT', 'κατα σκοπον διωκω επι το βραβειον της ανω κλησεως του θεου εν χριστω ιησου'),
(6292, 50, 'TR1550', 'TR1550', 'el', 'PHP', 3, 15, 'NT', 'οσοι ουν τελειοι τουτο φρονωμεν και ει τι ετερως φρονειτε και τουτο ο θεος υμιν αποκαλυψει'),
(6293, 50, 'TR1550', 'TR1550', 'el', 'PHP', 3, 16, 'NT', 'πλην εις ο εφθασαμεν τω αυτω στοιχειν κανονι το αυτο φρονειν'),
(6294, 50, 'TR1550', 'TR1550', 'el', 'PHP', 3, 17, 'NT', 'συμμιμηται μου γινεσθε αδελφοι και σκοπειτε τους ουτως περιπατουντας καθως εχετε τυπον ημας'),
(6295, 50, 'TR1550', 'TR1550', 'el', 'PHP', 3, 18, 'NT', 'πολλοι γαρ περιπατουσιν ους πολλακις ελεγον υμιν νυν δε και κλαιων λεγω τους εχθρους του σταυρου του χριστου'),
(6296, 50, 'TR1550', 'TR1550', 'el', 'PHP', 3, 19, 'NT', 'ων το τελος απωλεια ων ο θεος η κοιλια και η δοξα εν τη αισχυνη αυτων οι τα επιγεια φρονουντες'),
(6297, 50, 'TR1550', 'TR1550', 'el', 'PHP', 3, 20, 'NT', 'ημων γαρ το πολιτευμα εν ουρανοις υπαρχει εξ ου και σωτηρα απεκδεχομεθα κυριον ιησουν χριστον'),
(6298, 50, 'TR1550', 'TR1550', 'el', 'PHP', 3, 21, 'NT', 'ος μετασχηματισει το σωμα της ταπεινωσεως ημων εις το γενεσθαι αυτο συμμορφον τω σωματι της δοξης αυτου κατα την ενεργειαν του δυνασθαι αυτον και υποταξαι εαυτω τα παντα'),
(6299, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 1, 'NT', 'ωστε αδελφοι μου αγαπητοι και επιποθητοι χαρα και στεφανος μου ουτως στηκετε εν κυριω αγαπητοι'),
(6300, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 2, 'NT', 'ευωδιαν παρακαλω και συντυχην παρακαλω το αυτο φρονειν εν κυριω'),
(6301, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 3, 'NT', 'και ερωτω και σε συζυγε γνησιε συλλαμβανου αυταις αιτινες εν τω ευαγγελιω συνηθλησαν μοι μετα και κλημεντος και των λοιπων συνεργων μου ων τα ονοματα εν βιβλω ζωης'),
(6302, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 4, 'NT', 'χαιρετε εν κυριω παντοτε παλιν ερω χαιρετε'),
(6303, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 5, 'NT', 'το επιεικες υμων γνωσθητω πασιν ανθρωποις ο κυριος εγγυς'),
(6304, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 6, 'NT', 'μηδεν μεριμνατε αλλ εν παντι τη προσευχη και τη δεησει μετα ευχαριστιας τα αιτηματα υμων γνωριζεσθω προς τον θεον'),
(6305, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 7, 'NT', 'και η ειρηνη του θεου η υπερεχουσα παντα νουν φρουρησει τας καρδιας υμων και τα νοηματα υμων εν χριστω ιησου'),
(6306, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 8, 'NT', 'το λοιπον αδελφοι οσα εστιν αληθη οσα σεμνα οσα δικαια οσα αγνα οσα προσφιλη οσα ευφημα ει τις αρετη και ει τις επαινος ταυτα λογιζεσθε'),
(6307, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 9, 'NT', 'α και εμαθετε και παρελαβετε και ηκουσατε και ειδετε εν εμοι ταυτα πρασσετε και ο θεος της ειρηνης εσται μεθ υμων'),
(6308, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 10, 'NT', 'εχαρην δε εν κυριω μεγαλως οτι ηδη ποτε ανεθαλετε το υπερ εμου φρονειν εφ ω και εφρονειτε ηκαιρεισθε δε'),
(6309, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 11, 'NT', 'ουχ οτι καθ υστερησιν λεγω εγω γαρ εμαθον εν οις ειμι αυταρκης ειναι'),
(6310, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 12, 'NT', 'οιδα δε ταπεινουσθαι οιδα και περισσευειν εν παντι και εν πασιν μεμυημαι και χορταζεσθαι και πειναν και περισσευειν και υστερεισθαι'),
(6311, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 13, 'NT', 'παντα ισχυω εν τω ενδυναμουντι με χριστω'),
(6312, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 14, 'NT', 'πλην καλως εποιησατε συγκοινωνησαντες μου τη θλιψει'),
(6313, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 15, 'NT', 'οιδατε δε και υμεις φιλιππησιοι οτι εν αρχη του ευαγγελιου οτε εξηλθον απο μακεδονιας ουδεμια μοι εκκλησια εκοινωνησεν εις λογον δοσεως και ληψεως ει μη υμεις μονοι'),
(6314, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 16, 'NT', 'οτι και εν θεσσαλονικη και απαξ και δις εις την χρειαν μοι επεμψατε'),
(6315, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 17, 'NT', 'ουχ οτι επιζητω το δομα αλλ επιζητω τον καρπον τον πλεοναζοντα εις λογον υμων'),
(6316, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 18, 'NT', 'απεχω δε παντα και περισσευω πεπληρωμαι δεξαμενος παρα επαφροδιτου τα παρ υμων οσμην ευωδιας θυσιαν δεκτην ευαρεστον τω θεω'),
(6317, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 19, 'NT', 'ο δε θεος μου πληρωσει πασαν χρειαν υμων κατα τον πλουτον αυτου εν δοξη εν χριστω ιησου'),
(6318, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 20, 'NT', 'τω δε θεω και πατρι ημων η δοξα εις τους αιωνας των αιωνων αμην'),
(6319, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 21, 'NT', 'ασπασασθε παντα αγιον εν χριστω ιησου ασπαζονται υμας οι συν εμοι αδελφοι'),
(6320, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 22, 'NT', 'ασπαζονται υμας παντες οι αγιοι μαλιστα δε οι εκ της καισαρος οικιας'),
(6321, 50, 'TR1550', 'TR1550', 'el', 'PHP', 4, 23, 'NT', 'η χαρις του κυριου ημων ιησου χριστου μετα παντων υμων αμην [προς φιλιππησιους εγραφη απο ρωμης δι επαφροδιτου]'),
(6322, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 1, 'NT', 'παυλος αποστολος ιησου χριστου δια θεληματος θεου και τιμοθεος ο αδελφος'),
(6323, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 2, 'NT', 'τοις εν κολασσαις αγιοις και πιστοις αδελφοις εν χριστω χαρις υμιν και ειρηνη απο θεου πατρος ημων και κυριου ιησου χριστου'),
(6324, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 3, 'NT', 'ευχαριστουμεν τω θεω και πατρι του κυριου ημων ιησου χριστου παντοτε περι υμων προσευχομενοι'),
(6325, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 4, 'NT', 'ακουσαντες την πιστιν υμων εν χριστω ιησου και την αγαπην την εις παντας τους αγιους'),
(6326, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 5, 'NT', 'δια την ελπιδα την αποκειμενην υμιν εν τοις ουρανοις ην προηκουσατε εν τω λογω της αληθειας του ευαγγελιου'),
(6327, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 6, 'NT', 'του παροντος εις υμας καθως και εν παντι τω κοσμω και εστιν καρποφορουμενον καθως και εν υμιν αφ ης ημερας ηκουσατε και επεγνωτε την χαριν του θεου εν αληθεια'),
(6328, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 7, 'NT', 'καθως και εμαθετε απο επαφρα του αγαπητου συνδουλου ημων ος εστιν πιστος υπερ υμων διακονος του χριστου'),
(6329, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 8, 'NT', 'ο και δηλωσας ημιν την υμων αγαπην εν πνευματι'),
(6330, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 9, 'NT', 'δια τουτο και ημεις αφ ης ημερας ηκουσαμεν ου παυομεθα υπερ υμων προσευχομενοι και αιτουμενοι ινα πληρωθητε την επιγνωσιν του θεληματος αυτου εν παση σοφια και συνεσει πνευματικη'),
(6331, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 10, 'NT', 'περιπατησαι υμας αξιως του κυριου εις πασαν αρεσκειαν εν παντι εργω αγαθω καρποφορουντες και αυξανομενοι εις την επιγνωσιν του θεου'),
(6332, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 11, 'NT', 'εν παση δυναμει δυναμουμενοι κατα το κρατος της δοξης αυτου εις πασαν υπομονην και μακροθυμιαν μετα χαρας'),
(6333, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 12, 'NT', 'ευχαριστουντες τω πατρι τω ικανωσαντι ημας εις την μεριδα του κληρου των αγιων εν τω φωτι'),
(6334, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 13, 'NT', 'ος ερρυσατο ημας εκ της εξουσιας του σκοτους και μετεστησεν εις την βασιλειαν του υιου της αγαπης αυτου'),
(6335, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 14, 'NT', 'εν ω εχομεν την απολυτρωσιν δια του αιματος αυτου την αφεσιν των αμαρτιων'),
(6336, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 15, 'NT', 'ος εστιν εικων του θεου του αορατου πρωτοτοκος πασης κτισεως'),
(6337, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 16, 'NT', 'οτι εν αυτω εκτισθη τα παντα τα εν τοις ουρανοις και τα επι της γης τα ορατα και τα αορατα ειτε θρονοι ειτε κυριοτητες ειτε αρχαι ειτε εξουσιαι τα παντα δι αυτου και εις αυτον εκτισται'),
(6338, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 17, 'NT', 'και αυτος εστιν προ παντων και τα παντα εν αυτω συνεστηκεν'),
(6339, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 18, 'NT', 'και αυτος εστιν η κεφαλη του σωματος της εκκλησιας ος εστιν αρχη πρωτοτοκος εκ των νεκρων ινα γενηται εν πασιν αυτος πρωτευων'),
(6340, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 19, 'NT', 'οτι εν αυτω ευδοκησεν παν το πληρωμα κατοικησαι'),
(6341, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 20, 'NT', 'και δι αυτου αποκαταλλαξαι τα παντα εις αυτον ειρηνοποιησας δια του αιματος του σταυρου αυτου δι αυτου ειτε τα επι της γης ειτε τα εν τοις ουρανοις'),
(6342, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 21, 'NT', 'και υμας ποτε οντας απηλλοτριωμενους και εχθρους τη διανοια εν τοις εργοις τοις πονηροις νυνι δε αποκατηλλαξεν'),
(6343, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 22, 'NT', 'εν τω σωματι της σαρκος αυτου δια του θανατου παραστησαι υμας αγιους και αμωμους και ανεγκλητους κατενωπιον αυτου'),
(6344, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 23, 'NT', 'ειγε επιμενετε τη πιστει τεθεμελιωμενοι και εδραιοι και μη μετακινουμενοι απο της ελπιδος του ευαγγελιου ου ηκουσατε του κηρυχθεντος εν παση τη κτισει τη υπο τον ουρανον ου εγενομην εγω παυλος διακονος'),
(6345, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 24, 'NT', 'νυν χαιρω εν τοις παθημασιν μου υπερ υμων και ανταναπληρω τα υστερηματα των θλιψεων του χριστου εν τη σαρκι μου υπερ του σωματος αυτου ο εστιν η εκκλησια'),
(6346, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 25, 'NT', 'ης εγενομην εγω διακονος κατα την οικονομιαν του θεου την δοθεισαν μοι εις υμας πληρωσαι τον λογον του θεου'),
(6347, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 26, 'NT', 'το μυστηριον το αποκεκρυμμενον απο των αιωνων και απο των γενεων νυνι δε εφανερωθη τοις αγιοις αυτου'),
(6348, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 27, 'NT', 'οις ηθελησεν ο θεος γνωρισαι τις ο πλουτος της δοξης του μυστηριου τουτου εν τοις εθνεσιν ος εστιν χριστος εν υμιν η ελπις της δοξης'),
(6349, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 28, 'NT', 'ον ημεις καταγγελλομεν νουθετουντες παντα ανθρωπον και διδασκοντες παντα ανθρωπον εν παση σοφια ινα παραστησωμεν παντα ανθρωπον τελειον εν χριστω ιησου'),
(6350, 51, 'TR1550', 'TR1550', 'el', 'COL', 1, 29, 'NT', 'εις ο και κοπιω αγωνιζομενος κατα την ενεργειαν αυτου την ενεργουμενην εν εμοι εν δυναμει'),
(6351, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 1, 'NT', 'θελω γαρ υμας ειδεναι ηλικον αγωνα εχω περι υμων και των εν λαοδικεια και οσοι ουχ εωρακασιν το προσωπον μου εν σαρκι'),
(6352, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 2, 'NT', 'ινα παρακληθωσιν αι καρδιαι αυτων συμβιβασθεντων εν αγαπη και εις παντα πλουτον της πληροφοριας της συνεσεως εις επιγνωσιν του μυστηριου του θεου και πατρος και του χριστου'),
(6353, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 3, 'NT', 'εν ω εισιν παντες οι θησαυροι της σοφιας και της γνωσεως αποκρυφοι'),
(6354, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 4, 'NT', 'τουτο δε λεγω ινα μη τις υμας παραλογιζηται εν πιθανολογια'),
(6355, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 5, 'NT', 'ει γαρ και τη σαρκι απειμι αλλα τω πνευματι συν υμιν ειμι χαιρων και βλεπων υμων την ταξιν και το στερεωμα της εις χριστον πιστεως υμων'),
(6356, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 6, 'NT', 'ως ουν παρελαβετε τον χριστον ιησουν τον κυριον εν αυτω περιπατειτε'),
(6357, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 7, 'NT', 'ερριζωμενοι και εποικοδομουμενοι εν αυτω και βεβαιουμενοι εν τη πιστει καθως εδιδαχθητε περισσευοντες εν αυτη εν ευχαριστια'),
(6358, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 8, 'NT', 'βλεπετε μη τις υμας εσται ο συλαγωγων δια της φιλοσοφιας και κενης απατης κατα την παραδοσιν των ανθρωπων κατα τα στοιχεια του κοσμου και ου κατα χριστον'),
(6359, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 9, 'NT', 'οτι εν αυτω κατοικει παν το πληρωμα της θεοτητος σωματικως'),
(6360, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 10, 'NT', 'και εστε εν αυτω πεπληρωμενοι ος εστιν η κεφαλη πασης αρχης και εξουσιας'),
(6361, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 11, 'NT', 'εν ω και περιετμηθητε περιτομη αχειροποιητω εν τη απεκδυσει του σωματος των αμαρτιων της σαρκος εν τη περιτομη του χριστου'),
(6362, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 12, 'NT', 'συνταφεντες αυτω εν τω βαπτισματι εν ω και συνηγερθητε δια της πιστεως της ενεργειας του θεου του εγειραντος αυτον εκ των νεκρων'),
(6363, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 13, 'NT', 'και υμας νεκρους οντας εν τοις παραπτωμασιν και τη ακροβυστια της σαρκος υμων συνεζωποιησεν συν αυτω χαρισαμενος ημιν παντα τα παραπτωματα'),
(6364, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 14, 'NT', 'εξαλειψας το καθ ημων χειρογραφον τοις δογμασιν ο ην υπεναντιον ημιν και αυτο ηρκεν εκ του μεσου προσηλωσας αυτο τω σταυρω'),
(6365, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 15, 'NT', 'απεκδυσαμενος τας αρχας και τας εξουσιας εδειγματισεν εν παρρησια θριαμβευσας αυτους εν αυτω'),
(6366, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 16, 'NT', 'μη ουν τις υμας κρινετω εν βρωσει η εν ποσει η εν μερει εορτης η νουμηνιας η σαββατων'),
(6367, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 17, 'NT', 'α εστιν σκια των μελλοντων το δε σωμα του χριστου'),
(6368, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 18, 'NT', 'μηδεις υμας καταβραβευετω θελων εν ταπεινοφροσυνη και θρησκεια των αγγελων α μη εωρακεν εμβατευων εικη φυσιουμενος υπο του νοος της σαρκος αυτου'),
(6369, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 19, 'NT', 'και ου κρατων την κεφαλην εξ ου παν το σωμα δια των αφων και συνδεσμων επιχορηγουμενον και συμβιβαζομενον αυξει την αυξησιν του θεου'),
(6370, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 20, 'NT', 'ει ουν απεθανετε συν τω χριστω απο των στοιχειων του κοσμου τι ως ζωντες εν κοσμω δογματιζεσθε'),
(6371, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 21, 'NT', 'μη αψη μηδε γευση μηδε θιγης'),
(6372, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 22, 'NT', 'α εστιν παντα εις φθοραν τη αποχρησει κατα τα ενταλματα και διδασκαλιας των ανθρωπων'),
(6373, 51, 'TR1550', 'TR1550', 'el', 'COL', 2, 23, 'NT', 'ατινα εστιν λογον μεν εχοντα σοφιας εν εθελοθρησκεια και ταπεινοφροσυνη και αφειδια σωματος ουκ εν τιμη τινι προς πλησμονην της σαρκος'),
(6374, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 1, 'NT', 'ει ουν συνηγερθητε τω χριστω τα ανω ζητειτε ου ο χριστος εστιν εν δεξια του θεου καθημενος'),
(6375, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 2, 'NT', 'τα ανω φρονειτε μη τα επι της γης'),
(6376, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 3, 'NT', 'απεθανετε γαρ και η ζωη υμων κεκρυπται συν τω χριστω εν τω θεω'),
(6377, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 4, 'NT', 'οταν ο χριστος φανερωθη η ζωη ημων τοτε και υμεις συν αυτω φανερωθησεσθε εν δοξη'),
(6378, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 5, 'NT', 'νεκρωσατε ουν τα μελη υμων τα επι της γης πορνειαν ακαθαρσιαν παθος επιθυμιαν κακην και την πλεονεξιαν ητις εστιν ειδωλολατρεια'),
(6379, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 6, 'NT', 'δι α ερχεται η οργη του θεου επι τους υιους της απειθειας'),
(6380, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 7, 'NT', 'εν οις και υμεις περιεπατησατε ποτε οτε εζητε εν αυτοις'),
(6381, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 8, 'NT', 'νυνι δε αποθεσθε και υμεις τα παντα οργην θυμον κακιαν βλασφημιαν αισχρολογιαν εκ του στοματος υμων'),
(6382, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 9, 'NT', 'μη ψευδεσθε εις αλληλους απεκδυσαμενοι τον παλαιον ανθρωπον συν ταις πραξεσιν αυτου'),
(6383, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 10, 'NT', 'και ενδυσαμενοι τον νεον τον ανακαινουμενον εις επιγνωσιν κατ εικονα του κτισαντος αυτον'),
(6384, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 11, 'NT', 'οπου ουκ ενι ελλην και ιουδαιος περιτομη και ακροβυστια βαρβαρος σκυθης δουλος ελευθερος αλλα τα παντα και εν πασιν χριστος'),
(6385, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 12, 'NT', 'ενδυσασθε ουν ως εκλεκτοι του θεου αγιοι και ηγαπημενοι σπλαγχνα οικτιρμων χρηστοτητα ταπεινοφροσυνην πραοτητα μακροθυμιαν'),
(6386, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 13, 'NT', 'ανεχομενοι αλληλων και χαριζομενοι εαυτοις εαν τις προς τινα εχη μομφην καθως και ο χριστος εχαρισατο υμιν ουτως και υμεις'),
(6387, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 14, 'NT', 'επι πασιν δε τουτοις την αγαπην ητις εστιν συνδεσμος της τελειοτητος'),
(6388, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 15, 'NT', 'και η ειρηνη του θεου βραβευετω εν ταις καρδιαις υμων εις ην και εκληθητε εν ενι σωματι και ευχαριστοι γινεσθε'),
(6389, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 16, 'NT', 'ο λογος του χριστου ενοικειτω εν υμιν πλουσιως εν παση σοφια διδασκοντες και νουθετουντες εαυτους ψαλμοις και υμνοις και ωδαις πνευματικαις εν χαριτι αδοντες εν τη καρδια υμων τω κυριω'),
(6390, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 17, 'NT', 'και παν ο τι αν ποιητε εν λογω η εν εργω παντα εν ονοματι κυριου ιησου ευχαριστουντες τω θεω και πατρι δι αυτου'),
(6391, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 18, 'NT', 'αι γυναικες υποτασσεσθε τοις ιδιοις ανδρασιν ως ανηκεν εν κυριω'),
(6392, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 19, 'NT', 'οι ανδρες αγαπατε τας γυναικας και μη πικραινεσθε προς αυτας'),
(6393, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 20, 'NT', 'τα τεκνα υπακουετε τοις γονευσιν κατα παντα τουτο γαρ εστιν ευαρεστον τω κυριω'),
(6394, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 21, 'NT', 'οι πατερες μη ερεθιζετε τα τεκνα υμων ινα μη αθυμωσιν'),
(6395, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 22, 'NT', 'οι δουλοι υπακουετε κατα παντα τοις κατα σαρκα κυριοις μη εν οφθαλμοδουλειαις ως ανθρωπαρεσκοι αλλ εν απλοτητι καρδιας φοβουμενοι τον θεον'),
(6396, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 23, 'NT', 'και παν ο τι εαν ποιητε εκ ψυχης εργαζεσθε ως τω κυριω και ουκ ανθρωποις'),
(6397, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 24, 'NT', 'ειδοτες οτι απο κυριου αποληψεσθε την ανταποδοσιν της κληρονομιας τω γαρ κυριω χριστω δουλευετε'),
(6398, 51, 'TR1550', 'TR1550', 'el', 'COL', 3, 25, 'NT', 'ο δε αδικων κομιειται ο ηδικησεν και ουκ εστιν προσωποληψια'),
(6399, 51, 'TR1550', 'TR1550', 'el', 'COL', 4, 1, 'NT', 'οι κυριοι το δικαιον και την ισοτητα τοις δουλοις παρεχεσθε ειδοτες οτι και υμεις εχετε κυριον εν ουρανοις'),
(6400, 51, 'TR1550', 'TR1550', 'el', 'COL', 4, 2, 'NT', 'τη προσευχη προσκαρτερειτε γρηγορουντες εν αυτη εν ευχαριστια'),
(6401, 51, 'TR1550', 'TR1550', 'el', 'COL', 4, 3, 'NT', 'προσευχομενοι αμα και περι ημων ινα ο θεος ανοιξη ημιν θυραν του λογου λαλησαι το μυστηριον του χριστου δι ο και δεδεμαι'),
(6402, 51, 'TR1550', 'TR1550', 'el', 'COL', 4, 4, 'NT', 'ινα φανερωσω αυτο ως δει με λαλησαι'),
(6403, 51, 'TR1550', 'TR1550', 'el', 'COL', 4, 5, 'NT', 'εν σοφια περιπατειτε προς τους εξω τον καιρον εξαγοραζομενοι'),
(6404, 51, 'TR1550', 'TR1550', 'el', 'COL', 4, 6, 'NT', 'ο λογος υμων παντοτε εν χαριτι αλατι ηρτυμενος ειδεναι πως δει υμας ενι εκαστω αποκρινεσθαι'),
(6405, 51, 'TR1550', 'TR1550', 'el', 'COL', 4, 7, 'NT', 'τα κατ εμε παντα γνωρισει υμιν τυχικος ο αγαπητος αδελφος και πιστος διακονος και συνδουλος εν κυριω'),
(6406, 51, 'TR1550', 'TR1550', 'el', 'COL', 4, 8, 'NT', 'ον επεμψα προς υμας εις αυτο τουτο ινα γνω τα περι υμων και παρακαλεση τας καρδιας υμων'),
(6407, 51, 'TR1550', 'TR1550', 'el', 'COL', 4, 9, 'NT', 'συν ονησιμω τω πιστω και αγαπητω αδελφω ος εστιν εξ υμων παντα υμιν γνωριουσιν τα ωδε'),
(6408, 51, 'TR1550', 'TR1550', 'el', 'COL', 4, 10, 'NT', 'ασπαζεται υμας αρισταρχος ο συναιχμαλωτος μου και μαρκος ο ανεψιος βαρναβα περι ου ελαβετε εντολας εαν ελθη προς υμας δεξασθε αυτον'),
(6409, 51, 'TR1550', 'TR1550', 'el', 'COL', 4, 11, 'NT', 'και ιησους ο λεγομενος ιουστος οι οντες εκ περιτομης ουτοι μονοι συνεργοι εις την βασιλειαν του θεου οιτινες εγενηθησαν μοι παρηγορια'),
(6410, 51, 'TR1550', 'TR1550', 'el', 'COL', 4, 12, 'NT', 'ασπαζεται υμας επαφρας ο εξ υμων δουλος χριστου παντοτε αγωνιζομενος υπερ υμων εν ταις προσευχαις ινα στητε τελειοι και πεπληρωμενοι εν παντι θεληματι του θεου'),
(6411, 51, 'TR1550', 'TR1550', 'el', 'COL', 4, 13, 'NT', 'μαρτυρω γαρ αυτω οτι εχει ζηλον πολυν υπερ υμων και των εν λαοδικεια και των εν ιεραπολει'),
(6412, 51, 'TR1550', 'TR1550', 'el', 'COL', 4, 14, 'NT', 'ασπαζεται υμας λουκας ο ιατρος ο αγαπητος και δημας'),
(6413, 51, 'TR1550', 'TR1550', 'el', 'COL', 4, 15, 'NT', 'ασπασασθε τους εν λαοδικεια αδελφους και νυμφαν και την κατ οικον αυτου εκκλησιαν'),
(6414, 51, 'TR1550', 'TR1550', 'el', 'COL', 4, 16, 'NT', 'και οταν αναγνωσθη παρ υμιν η επιστολη ποιησατε ινα και εν τη λαοδικεων εκκλησια αναγνωσθη και την εκ λαοδικειας ινα και υμεις αναγνωτε'),
(6415, 51, 'TR1550', 'TR1550', 'el', 'COL', 4, 17, 'NT', 'και ειπατε αρχιππω βλεπε την διακονιαν ην παρελαβες εν κυριω ινα αυτην πληροις'),
(6416, 51, 'TR1550', 'TR1550', 'el', 'COL', 4, 18, 'NT', 'ο ασπασμος τη εμη χειρι παυλου μνημονευετε μου των δεσμων η χαρις μεθ υμων αμην [προς κολασσαεις εγραφη απο ρωμης δια τυχικου και ονησιμου]'),
(6417, 52, 'TR1550', 'TR1550', 'el', '1TH', 1, 1, 'NT', 'παυλος και σιλουανος και τιμοθεος τη εκκλησια θεσσαλονικεων εν θεω πατρι και κυριω ιησου χριστω χαρις υμιν και ειρηνη απο θεου πατρος ημων και κυριου ιησου χριστου'),
(6418, 52, 'TR1550', 'TR1550', 'el', '1TH', 1, 2, 'NT', 'ευχαριστουμεν τω θεω παντοτε περι παντων υμων μνειαν υμων ποιουμενοι επι των προσευχων ημων'),
(6419, 52, 'TR1550', 'TR1550', 'el', '1TH', 1, 3, 'NT', 'αδιαλειπτως μνημονευοντες υμων του εργου της πιστεως και του κοπου της αγαπης και της υπομονης της ελπιδος του κυριου ημων ιησου χριστου εμπροσθεν του θεου και πατρος ημων'),
(6420, 52, 'TR1550', 'TR1550', 'el', '1TH', 1, 4, 'NT', 'ειδοτες αδελφοι ηγαπημενοι υπο θεου την εκλογην υμων'),
(6421, 52, 'TR1550', 'TR1550', 'el', '1TH', 1, 5, 'NT', 'οτι το ευαγγελιον ημων ουκ εγενηθη εις υμας εν λογω μονον αλλα και εν δυναμει και εν πνευματι αγιω και εν πληροφορια πολλη καθως οιδατε οιοι εγενηθημεν εν υμιν δι υμας'),
(6422, 52, 'TR1550', 'TR1550', 'el', '1TH', 1, 6, 'NT', 'και υμεις μιμηται ημων εγενηθητε και του κυριου δεξαμενοι τον λογον εν θλιψει πολλη μετα χαρας πνευματος αγιου'),
(6423, 52, 'TR1550', 'TR1550', 'el', '1TH', 1, 7, 'NT', 'ωστε γενεσθαι υμας τυπους πασιν τοις πιστευουσιν εν τη μακεδονια και τη αχαια'),
(6424, 52, 'TR1550', 'TR1550', 'el', '1TH', 1, 8, 'NT', 'αφ υμων γαρ εξηχηται ο λογος του κυριου ου μονον εν τη μακεδονια και αχαια αλλα και εν παντι τοπω η πιστις υμων η προς τον θεον εξεληλυθεν ωστε μη χρειαν ημας εχειν λαλειν τι'),
(6425, 52, 'TR1550', 'TR1550', 'el', '1TH', 1, 9, 'NT', 'αυτοι γαρ περι ημων απαγγελλουσιν οποιαν εισοδον εχομεν προς υμας και πως επεστρεψατε προς τον θεον απο των ειδωλων δουλευειν θεω ζωντι και αληθινω'),
(6426, 52, 'TR1550', 'TR1550', 'el', '1TH', 1, 10, 'NT', 'και αναμενειν τον υιον αυτου εκ των ουρανων ον ηγειρεν εκ νεκρων ιησουν τον ρυομενον ημας απο της οργης της ερχομενης'),
(6427, 52, 'TR1550', 'TR1550', 'el', '1TH', 2, 1, 'NT', 'αυτοι γαρ οιδατε αδελφοι την εισοδον ημων την προς υμας οτι ου κενη γεγονεν'),
(6428, 52, 'TR1550', 'TR1550', 'el', '1TH', 2, 2, 'NT', 'αλλα και προπαθοντες και υβρισθεντες καθως οιδατε εν φιλιπποις επαρρησιασαμεθα εν τω θεω ημων λαλησαι προς υμας το ευαγγελιον του θεου εν πολλω αγωνι'),
(6429, 52, 'TR1550', 'TR1550', 'el', '1TH', 2, 3, 'NT', 'η γαρ παρακλησις ημων ουκ εκ πλανης ουδε εξ ακαθαρσιας ουτε εν δολω'),
(6430, 52, 'TR1550', 'TR1550', 'el', '1TH', 2, 4, 'NT', 'αλλα καθως δεδοκιμασμεθα υπο του θεου πιστευθηναι το ευαγγελιον ουτως λαλουμεν ουχ ως ανθρωποις αρεσκοντες αλλα τω θεω τω δοκιμαζοντι τας καρδιας ημων'),
(6431, 52, 'TR1550', 'TR1550', 'el', '1TH', 2, 5, 'NT', 'ουτε γαρ ποτε εν λογω κολακειας εγενηθημεν καθως οιδατε ουτε εν προφασει πλεονεξιας θεος μαρτυς'),
(6432, 52, 'TR1550', 'TR1550', 'el', '1TH', 2, 6, 'NT', 'ουτε ζητουντες εξ ανθρωπων δοξαν ουτε αφ υμων ουτε απ αλλων δυναμενοι εν βαρει ειναι ως χριστου αποστολοι'),
(6433, 52, 'TR1550', 'TR1550', 'el', '1TH', 2, 7, 'NT', 'αλλ εγενηθημεν ηπιοι εν μεσω υμων ως αν τροφος θαλπη τα εαυτης τεκνα'),
(6434, 52, 'TR1550', 'TR1550', 'el', '1TH', 2, 8, 'NT', 'ουτως ιμειρομενοι υμων ευδοκουμεν μεταδουναι υμιν ου μονον το ευαγγελιον του θεου αλλα και τας εαυτων ψυχας διοτι αγαπητοι ημιν γεγενησθε'),
(6435, 52, 'TR1550', 'TR1550', 'el', '1TH', 2, 9, 'NT', 'μνημονευετε γαρ αδελφοι τον κοπον ημων και τον μοχθον νυκτος γαρ και ημερας εργαζομενοι προς το μη επιβαρησαι τινα υμων εκηρυξαμεν εις υμας το ευαγγελιον του θεου'),
(6436, 52, 'TR1550', 'TR1550', 'el', '1TH', 2, 10, 'NT', 'υμεις μαρτυρες και ο θεος ως οσιως και δικαιως και αμεμπτως υμιν τοις πιστευουσιν εγενηθημεν'),
(6437, 52, 'TR1550', 'TR1550', 'el', '1TH', 2, 11, 'NT', 'καθαπερ οιδατε ως ενα εκαστον υμων ως πατηρ τεκνα εαυτου παρακαλουντες υμας και παραμυθουμενοι'),
(6438, 52, 'TR1550', 'TR1550', 'el', '1TH', 2, 12, 'NT', 'και μαρτυρουμενοι εις το περιπατησαι υμας αξιως του θεου του καλουντος υμας εις την εαυτου βασιλειαν και δοξαν'),
(6439, 52, 'TR1550', 'TR1550', 'el', '1TH', 2, 13, 'NT', 'δια τουτο και ημεις ευχαριστουμεν τω θεω αδιαλειπτως οτι παραλαβοντες λογον ακοης παρ ημων του θεου εδεξασθε ου λογον ανθρωπων αλλα καθως εστιν αληθως λογον θεου ος και ενεργειται εν υμιν τοις πιστευουσιν'),
