(6497, 52, 'TR1550', 'TR1550', 'el', '1TH', 5, 20, 'NT', 'προφητειας μη εξουθενειτε'),
(6498, 52, 'TR1550', 'TR1550', 'el', '1TH', 5, 21, 'NT', 'παντα δοκιμαζετε το καλον κατεχετε'),
