(6711, 55, 'TR1550', 'TR1550', 'el', '2TI', 3, 2, 'NT', 'εσονται γαρ οι ανθρωποι φιλαυτοι φιλαργυροι αλαζονες υπερηφανοι βλασφημοι γονευσιν απειθεις αχαριστοι ανοσιοι'),
(6712, 55, 'TR1550', 'TR1550', 'el', '2TI', 3, 3, 'NT', 'αστοργοι ασπονδοι διαβολοι ακρατεις ανημεροι αφιλαγαθοι'),
