(6819, 57, 'TR1550', 'TR1550', 'el', 'PHM', 1, 25, 'NT', 'η χαρις του κυριου ημων ιησου χριστου μετα του πνευματος υμων αμην [προς φιλημονα εγραφη απο ρωμης δια ονησιμου οικετου]'),
(6820, 58, 'TR1550', 'TR1550', 'el', 'HEB', 1, 1, 'NT', 'πολυμερως και πολυτροπως παλαι ο θεος λαλησας τοις πατρασιν εν τοις προφηταις επ εσχατων των ημερων τουτων ελαλησεν ημιν εν υιω'),
(6821, 58, 'TR1550', 'TR1550', 'el', 'HEB', 1, 2, 'NT', 'ον εθηκεν κληρονομον παντων δι ου και τους αιωνας εποιησεν'),
(6822, 58, 'TR1550', 'TR1550', 'el', 'HEB', 1, 3, 'NT', 'ος ων απαυγασμα της δοξης και χαρακτηρ της υποστασεως αυτου φερων τε τα παντα τω ρηματι της δυναμεως αυτου δι εαυτου καθαρισμον ποιησαμενος των αμαρτιων ημων εκαθισεν εν δεξια της μεγαλωσυνης εν υψηλοις'),
(6823, 58, 'TR1550', 'TR1550', 'el', 'HEB', 1, 4, 'NT', 'τοσουτω κρειττων γενομενος των αγγελων οσω διαφορωτερον παρ αυτους κεκληρονομηκεν ονομα'),
(6824, 58, 'TR1550', 'TR1550', 'el', 'HEB', 1, 5, 'NT', 'τινι γαρ ειπεν ποτε των αγγελων υιος μου ει συ εγω σημερον γεγεννηκα σε και παλιν εγω εσομαι αυτω εις πατερα και αυτος εσται μοι εις υιον'),
(6825, 58, 'TR1550', 'TR1550', 'el', 'HEB', 1, 6, 'NT', 'οταν δε παλιν εισαγαγη τον πρωτοτοκον εις την οικουμενην λεγει και προσκυνησατωσαν αυτω παντες αγγελοι θεου'),
(6826, 58, 'TR1550', 'TR1550', 'el', 'HEB', 1, 7, 'NT', 'και προς μεν τους αγγελους λεγει ο ποιων τους αγγελους αυτου πνευματα και τους λειτουργους αυτου πυρος φλογα'),
(6827, 58, 'TR1550', 'TR1550', 'el', 'HEB', 1, 8, 'NT', 'προς δε τον υιον ο θρονος σου ο θεος εις τον αιωνα του αιωνος ραβδος ευθυτητος η ραβδος της βασιλειας σου'),
(6828, 58, 'TR1550', 'TR1550', 'el', 'HEB', 1, 9, 'NT', 'ηγαπησας δικαιοσυνην και εμισησας ανομιαν δια τουτο εχρισεν σε ο θεος ο θεος σου ελαιον αγαλλιασεως παρα τους μετοχους σου'),
(6829, 58, 'TR1550', 'TR1550', 'el', 'HEB', 1, 10, 'NT', 'και συ κατ αρχας κυριε την γην εθεμελιωσας και εργα των χειρων σου εισιν οι ουρανοι'),
