(6835, 58, 'TR1550', 'TR1550', 'el', 'HEB', 2, 2, 'NT', 'ει γαρ ο δι αγγελων λαληθεις λογος εγενετο βεβαιος και πασα παραβασις και παρακοη ελαβεν ενδικον μισθαποδοσιαν'),
(6836, 58, 'TR1550', 'TR1550', 'el', 'HEB', 2, 3, 'NT', 'πως ημεις εκφευξομεθα τηλικαυτης αμελησαντες σωτηριας ητις αρχην λαβουσα λαλεισθαι δια του κυριου υπο των ακουσαντων εις ημας εβεβαιωθη'),
(6837, 58, 'TR1550', 'TR1550', 'el', 'HEB', 2, 4, 'NT', 'συνεπιμαρτυρουντος του θεου σημειοις τε και τερασιν και ποικιλαις δυναμεσιν και πνευματος αγιου μερισμοις κατα την αυτου θελησιν'),
(6838, 58, 'TR1550', 'TR1550', 'el', 'HEB', 2, 5, 'NT', 'ου γαρ αγγελοις υπεταξεν την οικουμενην την μελλουσαν περι ης λαλουμεν'),
(6839, 58, 'TR1550', 'TR1550', 'el', 'HEB', 2, 6, 'NT', 'διεμαρτυρατο δε που τις λεγων τι εστιν ανθρωπος οτι μιμνησκη αυτου η υιος ανθρωπου οτι επισκεπτη αυτον'),
(6840, 58, 'TR1550', 'TR1550', 'el', 'HEB', 2, 7, 'NT', 'ηλαττωσας αυτον βραχυ τι παρ αγγελους δοξη και τιμη εστεφανωσας αυτον και κατεστησας αυτον επι τα εργα των χειρων σου'),
(6841, 58, 'TR1550', 'TR1550', 'el', 'HEB', 2, 8, 'NT', 'παντα υπεταξας υποκατω των ποδων αυτου εν γαρ τω υποταξαι αυτω τα παντα ουδεν αφηκεν αυτω ανυποτακτον νυν δε ουπω ορωμεν αυτω τα παντα υποτεταγμενα'),
(6842, 58, 'TR1550', 'TR1550', 'el', 'HEB', 2, 9, 'NT', 'τον δε βραχυ τι παρ αγγελους ηλαττωμενον βλεπομεν ιησουν δια το παθημα του θανατου δοξη και τιμη εστεφανωμενον οπως χαριτι θεου υπερ παντος γευσηται θανατου'),
(6843, 58, 'TR1550', 'TR1550', 'el', 'HEB', 2, 10, 'NT', 'επρεπεν γαρ αυτω δι ον τα παντα και δι ου τα παντα πολλους υιους εις δοξαν αγαγοντα τον αρχηγον της σωτηριας αυτων δια παθηματων τελειωσαι'),
(6844, 58, 'TR1550', 'TR1550', 'el', 'HEB', 2, 11, 'NT', 'ο τε γαρ αγιαζων και οι αγιαζομενοι εξ ενος παντες δι ην αιτιαν ουκ επαισχυνεται αδελφους αυτους καλειν'),
(6845, 58, 'TR1550', 'TR1550', 'el', 'HEB', 2, 12, 'NT', 'λεγων απαγγελω το ονομα σου τοις αδελφοις μου εν μεσω εκκλησιας υμνησω σε'),
(6846, 58, 'TR1550', 'TR1550', 'el', 'HEB', 2, 13, 'NT', 'και παλιν εγω εσομαι πεποιθως επ αυτω και παλιν ιδου εγω και τα παιδια α μοι εδωκεν ο θεος'),
