(6848, 58, 'TR1550', 'TR1550', 'el', 'HEB', 2, 15, 'NT', 'και απαλλαξη τουτους οσοι φοβω θανατου δια παντος του ζην ενοχοι ησαν δουλειας'),
(6849, 58, 'TR1550', 'TR1550', 'el', 'HEB', 2, 16, 'NT', 'ου γαρ δηπου αγγελων επιλαμβανεται αλλα σπερματος αβρααμ επιλαμβανεται'),
(6850, 58, 'TR1550', 'TR1550', 'el', 'HEB', 2, 17, 'NT', 'οθεν ωφειλεν κατα παντα τοις αδελφοις ομοιωθηναι ινα ελεημων γενηται και πιστος αρχιερευς τα προς τον θεον εις το ιλασκεσθαι τας αμαρτιας του λαου'),
(6851, 58, 'TR1550', 'TR1550', 'el', 'HEB', 2, 18, 'NT', 'εν ω γαρ πεπονθεν αυτος πειρασθεις δυναται τοις πειραζομενοις βοηθησαι'),
(6852, 58, 'TR1550', 'TR1550', 'el', 'HEB', 3, 1, 'NT', 'οθεν αδελφοι αγιοι κλησεως επουρανιου μετοχοι κατανοησατε τον αποστολον και αρχιερεα της ομολογιας ημων χριστον ιησουν'),
(6853, 58, 'TR1550', 'TR1550', 'el', 'HEB', 3, 2, 'NT', 'πιστον οντα τω ποιησαντι αυτον ως και μωσης εν ολω τω οικω αυτου'),
(6854, 58, 'TR1550', 'TR1550', 'el', 'HEB', 3, 3, 'NT', 'πλειονος γαρ δοξης ουτος παρα μωσην ηξιωται καθ οσον πλειονα τιμην εχει του οικου ο κατασκευασας αυτον'),
(6855, 58, 'TR1550', 'TR1550', 'el', 'HEB', 3, 4, 'NT', 'πας γαρ οικος κατασκευαζεται υπο τινος ο δε τα παντα κατασκευασας θεος'),
