(6870, 58, 'TR1550', 'TR1550', 'el', 'HEB', 3, 19, 'NT', 'και βλεπομεν οτι ουκ ηδυνηθησαν εισελθειν δι απιστιαν'),
(6871, 58, 'TR1550', 'TR1550', 'el', 'HEB', 4, 1, 'NT', 'φοβηθωμεν ουν μηποτε καταλειπομενης επαγγελιας εισελθειν εις την καταπαυσιν αυτου δοκη τις εξ υμων υστερηκεναι'),
(6872, 58, 'TR1550', 'TR1550', 'el', 'HEB', 4, 2, 'NT', 'και γαρ εσμεν ευηγγελισμενοι καθαπερ κακεινοι αλλ ουκ ωφελησεν ο λογος της ακοης εκεινους μη συγκεκραμενος τη πιστει τοις ακουσασιν'),
(6873, 58, 'TR1550', 'TR1550', 'el', 'HEB', 4, 3, 'NT', 'εισερχομεθα γαρ εις την καταπαυσιν οι πιστευσαντες καθως ειρηκεν ως ωμοσα εν τη οργη μου ει εισελευσονται εις την καταπαυσιν μου καιτοι των εργων απο καταβολης κοσμου γενηθεντων'),
(6874, 58, 'TR1550', 'TR1550', 'el', 'HEB', 4, 4, 'NT', 'ειρηκεν γαρ που περι της εβδομης ουτως και κατεπαυσεν ο θεος εν τη ημερα τη εβδομη απο παντων των εργων αυτου'),
(6875, 58, 'TR1550', 'TR1550', 'el', 'HEB', 4, 5, 'NT', 'και εν τουτω παλιν ει εισελευσονται εις την καταπαυσιν μου'),
(6876, 58, 'TR1550', 'TR1550', 'el', 'HEB', 4, 6, 'NT', 'επει ουν απολειπεται τινας εισελθειν εις αυτην και οι προτερον ευαγγελισθεντες ουκ εισηλθον δι απειθειαν'),
(6877, 58, 'TR1550', 'TR1550', 'el', 'HEB', 4, 7, 'NT', 'παλιν τινα οριζει ημεραν σημερον εν δαβιδ λεγων μετα τοσουτον χρονον καθως ειρηται σημερον εαν της φωνης αυτου ακουσητε μη σκληρυνητε τας καρδιας υμων'),
(6878, 58, 'TR1550', 'TR1550', 'el', 'HEB', 4, 8, 'NT', 'ει γαρ αυτους ιησους κατεπαυσεν ουκ αν περι αλλης ελαλει μετα ταυτα ημερας'),
(6879, 58, 'TR1550', 'TR1550', 'el', 'HEB', 4, 9, 'NT', 'αρα απολειπεται σαββατισμος τω λαω του θεου'),
(6880, 58, 'TR1550', 'TR1550', 'el', 'HEB', 4, 10, 'NT', 'ο γαρ εισελθων εις την καταπαυσιν αυτου και αυτος κατεπαυσεν απο των εργων αυτου ωσπερ απο των ιδιων ο θεος'),
