(6918, 58, 'TR1550', 'TR1550', 'el', 'HEB', 6, 18, 'NT', 'ινα δια δυο πραγματων αμεταθετων εν οις αδυνατον ψευσασθαι θεον ισχυραν παρακλησιν εχωμεν οι καταφυγοντες κρατησαι της προκειμενης ελπιδος'),
(6919, 58, 'TR1550', 'TR1550', 'el', 'HEB', 6, 19, 'NT', 'ην ως αγκυραν εχομεν της ψυχης ασφαλη τε και βεβαιαν και εισερχομενην εις το εσωτερον του καταπετασματος'),
(6920, 58, 'TR1550', 'TR1550', 'el', 'HEB', 6, 20, 'NT', 'οπου προδρομος υπερ ημων εισηλθεν ιησους κατα την ταξιν μελχισεδεκ αρχιερευς γενομενος εις τον αιωνα'),
(6921, 58, 'TR1550', 'TR1550', 'el', 'HEB', 7, 1, 'NT', 'ουτος γαρ ο μελχισεδεκ βασιλευς σαλημ ιερευς του θεου του υψιστου ο συναντησας αβρααμ υποστρεφοντι απο της κοπης των βασιλεων και ευλογησας αυτον'),
(6922, 58, 'TR1550', 'TR1550', 'el', 'HEB', 7, 2, 'NT', 'ω και δεκατην απο παντων εμερισεν αβρααμ πρωτον μεν ερμηνευομενος βασιλευς δικαιοσυνης επειτα δε και βασιλευς σαλημ ο εστιν βασιλευς ειρηνης'),
(6923, 58, 'TR1550', 'TR1550', 'el', 'HEB', 7, 3, 'NT', 'απατωρ αμητωρ αγενεαλογητος μητε αρχην ημερων μητε ζωης τελος εχων αφωμοιωμενος δε τω υιω του θεου μενει ιερευς εις το διηνεκες'),
(6924, 58, 'TR1550', 'TR1550', 'el', 'HEB', 7, 4, 'NT', 'θεωρειτε δε πηλικος ουτος ω και δεκατην αβρααμ εδωκεν εκ των ακροθινιων ο πατριαρχης'),
