(6946, 58, 'TR1550', 'TR1550', 'el', 'HEB', 7, 26, 'NT', 'τοιουτος γαρ ημιν επρεπεν αρχιερευς οσιος ακακος αμιαντος κεχωρισμενος απο των αμαρτωλων και υψηλοτερος των ουρανων γενομενος'),
(6947, 58, 'TR1550', 'TR1550', 'el', 'HEB', 7, 27, 'NT', 'ος ουκ εχει καθ ημεραν αναγκην ωσπερ οι αρχιερεις προτερον υπερ των ιδιων αμαρτιων θυσιας αναφερειν επειτα των του λαου τουτο γαρ εποιησεν εφαπαξ εαυτον ανενεγκας'),
(6948, 58, 'TR1550', 'TR1550', 'el', 'HEB', 7, 28, 'NT', 'ο νομος γαρ ανθρωπους καθιστησιν αρχιερεις εχοντας ασθενειαν ο λογος δε της ορκωμοσιας της μετα τον νομον υιον εις τον αιωνα τετελειωμενον'),
(6949, 58, 'TR1550', 'TR1550', 'el', 'HEB', 8, 1, 'NT', 'κεφαλαιον δε επι τοις λεγομενοις τοιουτον εχομεν αρχιερεα ος εκαθισεν εν δεξια του θρονου της μεγαλωσυνης εν τοις ουρανοις'),
(6950, 58, 'TR1550', 'TR1550', 'el', 'HEB', 8, 2, 'NT', 'των αγιων λειτουργος και της σκηνης της αληθινης ην επηξεν ο κυριος και ουκ ανθρωπος'),
(6951, 58, 'TR1550', 'TR1550', 'el', 'HEB', 8, 3, 'NT', 'πας γαρ αρχιερευς εις το προσφερειν δωρα τε και θυσιας καθισταται οθεν αναγκαιον εχειν τι και τουτον ο προσενεγκη'),
(6952, 58, 'TR1550', 'TR1550', 'el', 'HEB', 8, 4, 'NT', 'ει μεν γαρ ην επι γης ουδ αν ην ιερευς οντων των ιερεων των προσφεροντων κατα τον νομον τα δωρα'),
(6953, 58, 'TR1550', 'TR1550', 'el', 'HEB', 8, 5, 'NT', 'οιτινες υποδειγματι και σκια λατρευουσιν των επουρανιων καθως κεχρηματισται μωσης μελλων επιτελειν την σκηνην ορα γαρ φησιν ποιησης παντα κατα τον τυπον τον δειχθεντα σοι εν τω ορει'),
(6954, 58, 'TR1550', 'TR1550', 'el', 'HEB', 8, 6, 'NT', 'νυνι δε διαφορωτερας τετευχεν λειτουργιας οσω και κρειττονος εστιν διαθηκης μεσιτης ητις επι κρειττοσιν επαγγελιαις νενομοθετηται'),
(6955, 58, 'TR1550', 'TR1550', 'el', 'HEB', 8, 7, 'NT', 'ει γαρ η πρωτη εκεινη ην αμεμπτος ουκ αν δευτερας εζητειτο τοπος'),
(6956, 58, 'TR1550', 'TR1550', 'el', 'HEB', 8, 8, 'NT', 'μεμφομενος γαρ αυτοις λεγει ιδου ημεραι ερχονται λεγει κυριος και συντελεσω επι τον οικον ισραηλ και επι τον οικον ιουδα διαθηκην καινην'),
(6957, 58, 'TR1550', 'TR1550', 'el', 'HEB', 8, 9, 'NT', 'ου κατα την διαθηκην ην εποιησα τοις πατρασιν αυτων εν ημερα επιλαβομενου μου της χειρος αυτων εξαγαγειν αυτους εκ γης αιγυπτου οτι αυτοι ουκ ενεμειναν εν τη διαθηκη μου καγω ημελησα αυτων λεγει κυριος'),
(6958, 58, 'TR1550', 'TR1550', 'el', 'HEB', 8, 10, 'NT', 'οτι αυτη η διαθηκη ην διαθησομαι τω οικω ισραηλ μετα τας ημερας εκεινας λεγει κυριος διδους νομους μου εις την διανοιαν αυτων και επι καρδιας αυτων επιγραψω αυτους και εσομαι αυτοις εις θεον και αυτοι εσονται μοι εις λαον'),
(6959, 58, 'TR1550', 'TR1550', 'el', 'HEB', 8, 11, 'NT', 'και ου μη διδαξωσιν εκαστος τον πλησιον αυτου και εκαστος τον αδελφον αυτου λεγων γνωθι τον κυριον οτι παντες ειδησουσιν με απο μικρου αυτων εως μεγαλου αυτων'),
(6960, 58, 'TR1550', 'TR1550', 'el', 'HEB', 8, 12, 'NT', 'οτι ιλεως εσομαι ταις αδικιαις αυτων και των αμαρτιων αυτων και των ανομιων αυτων ου μη μνησθω ετι'),
(6961, 58, 'TR1550', 'TR1550', 'el', 'HEB', 8, 13, 'NT', 'εν τω λεγειν καινην πεπαλαιωκεν την πρωτην το δε παλαιουμενον και γηρασκον εγγυς αφανισμου'),
