(7068, 58, 'TR1550', 'TR1550', 'el', 'HEB', 11, 40, 'NT', 'του θεου περι ημων κρειττον τι προβλεψαμενου ινα μη χωρις ημων τελειωθωσιν'),
(7069, 58, 'TR1550', 'TR1550', 'el', 'HEB', 12, 1, 'NT', 'τοιγαρουν και ημεις τοσουτον εχοντες περικειμενον ημιν νεφος μαρτυρων ογκον αποθεμενοι παντα και την ευπεριστατον αμαρτιαν δι υπομονης τρεχωμεν τον προκειμενον ημιν αγωνα'),
(7070, 58, 'TR1550', 'TR1550', 'el', 'HEB', 12, 2, 'NT', 'αφορωντες εις τον της πιστεως αρχηγον και τελειωτην ιησουν ος αντι της προκειμενης αυτω χαρας υπεμεινεν σταυρον αισχυνης καταφρονησας εν δεξια τε του θρονου του θεου εκαθισεν'),
(7071, 58, 'TR1550', 'TR1550', 'el', 'HEB', 12, 3, 'NT', 'αναλογισασθε γαρ τον τοιαυτην υπομεμενηκοτα υπο των αμαρτωλων εις αυτον αντιλογιαν ινα μη καμητε ταις ψυχαις υμων εκλυομενοι'),
(7072, 58, 'TR1550', 'TR1550', 'el', 'HEB', 12, 4, 'NT', 'ουπω μεχρις αιματος αντικατεστητε προς την αμαρτιαν ανταγωνιζομενοι'),
(7073, 58, 'TR1550', 'TR1550', 'el', 'HEB', 12, 5, 'NT', 'και εκλελησθε της παρακλησεως ητις υμιν ως υιοις διαλεγεται υιε μου μη ολιγωρει παιδειας κυριου μηδε εκλυου υπ αυτου ελεγχομενος'),
(7074, 58, 'TR1550', 'TR1550', 'el', 'HEB', 12, 6, 'NT', 'ον γαρ αγαπα κυριος παιδευει μαστιγοι δε παντα υιον ον παραδεχεται'),
(7075, 58, 'TR1550', 'TR1550', 'el', 'HEB', 12, 7, 'NT', 'ει παιδειαν υπομενετε ως υιοις υμιν προσφερεται ο θεος τις γαρ εστιν υιος ον ου παιδευει πατηρ'),
(7076, 58, 'TR1550', 'TR1550', 'el', 'HEB', 12, 8, 'NT', 'ει δε χωρις εστε παιδειας ης μετοχοι γεγονασιν παντες αρα νοθοι εστε και ουχ υιοι'),
(7077, 58, 'TR1550', 'TR1550', 'el', 'HEB', 12, 9, 'NT', 'ειτα τους μεν της σαρκος ημων πατερας ειχομεν παιδευτας και ενετρεπομεθα ου πολλω μαλλον υποταγησομεθα τω πατρι των πνευματων και ζησομεν'),
(7078, 58, 'TR1550', 'TR1550', 'el', 'HEB', 12, 10, 'NT', 'οι μεν γαρ προς ολιγας ημερας κατα το δοκουν αυτοις επαιδευον ο δε επι το συμφερον εις το μεταλαβειν της αγιοτητος αυτου'),
(7079, 58, 'TR1550', 'TR1550', 'el', 'HEB', 12, 11, 'NT', 'πασα δε παιδεια προς μεν το παρον ου δοκει χαρας ειναι αλλα λυπης υστερον δε καρπον ειρηνικον τοις δι αυτης γεγυμνασμενοις αποδιδωσιν δικαιοσυνης'),
(7080, 58, 'TR1550', 'TR1550', 'el', 'HEB', 12, 12, 'NT', 'διο τας παρειμενας χειρας και τα παραλελυμενα γονατα ανορθωσατε'),
