(7096, 58, 'TR1550', 'TR1550', 'el', 'HEB', 12, 28, 'NT', 'διο βασιλειαν ασαλευτον παραλαμβανοντες εχωμεν χαριν δι ης λατρευωμεν ευαρεστως τω θεω μετα αιδους και ευλαβειας'),
(7097, 58, 'TR1550', 'TR1550', 'el', 'HEB', 12, 29, 'NT', 'και γαρ ο θεος ημων πυρ καταναλισκον'),
(7098, 58, 'TR1550', 'TR1550', 'el', 'HEB', 13, 1, 'NT', 'η φιλαδελφια μενετω'),
(7099, 58, 'TR1550', 'TR1550', 'el', 'HEB', 13, 2, 'NT', 'της φιλοξενιας μη επιλανθανεσθε δια ταυτης γαρ ελαθον τινες ξενισαντες αγγελους'),
