(7133, 59, 'TR1550', 'TR1550', 'el', 'JAS', 1, 11, 'NT', 'ανετειλεν γαρ ο ηλιος συν τω καυσωνι και εξηρανεν τον χορτον και το ανθος αυτου εξεπεσεν και η ευπρεπεια του προσωπου αυτου απωλετο ουτως και ο πλουσιος εν ταις πορειαις αυτου μαρανθησεται'),
(7134, 59, 'TR1550', 'TR1550', 'el', 'JAS', 1, 12, 'NT', 'μακαριος ανηρ ος υπομενει πειρασμον οτι δοκιμος γενομενος ληψεται τον στεφανον της ζωης ον επηγγειλατο ο κυριος τοις αγαπωσιν αυτον'),
(7135, 59, 'TR1550', 'TR1550', 'el', 'JAS', 1, 13, 'NT', 'μηδεις πειραζομενος λεγετω οτι απο του θεου πειραζομαι ο γαρ θεος απειραστος εστιν κακων πειραζει δε αυτος ουδενα'),
(7136, 59, 'TR1550', 'TR1550', 'el', 'JAS', 1, 14, 'NT', 'εκαστος δε πειραζεται υπο της ιδιας επιθυμιας εξελκομενος και δελεαζομενος'),
(7137, 59, 'TR1550', 'TR1550', 'el', 'JAS', 1, 15, 'NT', 'ειτα η επιθυμια συλλαβουσα τικτει αμαρτιαν η δε αμαρτια αποτελεσθεισα αποκυει θανατον'),
(7138, 59, 'TR1550', 'TR1550', 'el', 'JAS', 1, 16, 'NT', 'μη πλανασθε αδελφοι μου αγαπητοι'),
(7139, 59, 'TR1550', 'TR1550', 'el', 'JAS', 1, 17, 'NT', 'πασα δοσις αγαθη και παν δωρημα τελειον ανωθεν εστιν καταβαινον απο του πατρος των φωτων παρ ω ουκ ενι παραλλαγη η τροπης αποσκιασμα'),
(7140, 59, 'TR1550', 'TR1550', 'el', 'JAS', 1, 18, 'NT', 'βουληθεις απεκυησεν ημας λογω αληθειας εις το ειναι ημας απαρχην τινα των αυτου κτισματων'),
(7141, 59, 'TR1550', 'TR1550', 'el', 'JAS', 1, 19, 'NT', 'ωστε αδελφοι μου αγαπητοι εστω πας ανθρωπος ταχυς εις το ακουσαι βραδυς εις το λαλησαι βραδυς εις οργην'),
(7142, 59, 'TR1550', 'TR1550', 'el', 'JAS', 1, 20, 'NT', 'οργη γαρ ανδρος δικαιοσυνην θεου ου κατεργαζεται'),
(7143, 59, 'TR1550', 'TR1550', 'el', 'JAS', 1, 21, 'NT', 'διο αποθεμενοι πασαν ρυπαριαν και περισσειαν κακιας εν πραυτητι δεξασθε τον εμφυτον λογον τον δυναμενον σωσαι τας ψυχας υμων'),
(7144, 59, 'TR1550', 'TR1550', 'el', 'JAS', 1, 22, 'NT', 'γινεσθε δε ποιηται λογου και μη μονον ακροαται παραλογιζομενοι εαυτους'),
(7145, 59, 'TR1550', 'TR1550', 'el', 'JAS', 1, 23, 'NT', 'οτι ει τις ακροατης λογου εστιν και ου ποιητης ουτος εοικεν ανδρι κατανοουντι το προσωπον της γενεσεως αυτου εν εσοπτρω'),
(7146, 59, 'TR1550', 'TR1550', 'el', 'JAS', 1, 24, 'NT', 'κατενοησεν γαρ εαυτον και απεληλυθεν και ευθεως επελαθετο οποιος ην'),
(7147, 59, 'TR1550', 'TR1550', 'el', 'JAS', 1, 25, 'NT', 'ο δε παρακυψας εις νομον τελειον τον της ελευθεριας και παραμεινας ουτος ουκ ακροατης επιλησμονης γενομενος αλλα ποιητης εργου ουτος μακαριος εν τη ποιησει αυτου εσται'),
(7148, 59, 'TR1550', 'TR1550', 'el', 'JAS', 1, 26, 'NT', 'ει τις δοκει θρησκος ειναι εν υμιν μη χαλιναγωγων γλωσσαν αυτου αλλ απατων καρδιαν αυτου τουτου ματαιος η θρησκεια'),
(7149, 59, 'TR1550', 'TR1550', 'el', 'JAS', 1, 27, 'NT', 'θρησκεια καθαρα και αμιαντος παρα τω θεω και πατρι αυτη εστιν επισκεπτεσθαι ορφανους και χηρας εν τη θλιψει αυτων ασπιλον εαυτον τηρειν απο του κοσμου'),
(7150, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 1, 'NT', 'αδελφοι μου μη εν προσωποληψιαις εχετε την πιστιν του κυριου ημων ιησου χριστου της δοξης'),
(7151, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 2, 'NT', 'εαν γαρ εισελθη εις την συναγωγην υμων ανηρ χρυσοδακτυλιος εν εσθητι λαμπρα εισελθη δε και πτωχος εν ρυπαρα εσθητι'),
(7152, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 3, 'NT', 'και επιβλεψητε επι τον φορουντα την εσθητα την λαμπραν και ειπητε αυτω συ καθου ωδε καλως και τω πτωχω ειπητε συ στηθι εκει η καθου ωδε υπο το υποποδιον μου'),
(7153, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 4, 'NT', 'και ου διεκριθητε εν εαυτοις και εγενεσθε κριται διαλογισμων πονηρων'),
(7154, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 5, 'NT', 'ακουσατε αδελφοι μου αγαπητοι ουχ ο θεος εξελεξατο τους πτωχους του κοσμου τουτου πλουσιους εν πιστει και κληρονομους της βασιλειας ης επηγγειλατο τοις αγαπωσιν αυτον'),
(7155, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 6, 'NT', 'υμεις δε ητιμασατε τον πτωχον ουχ οι πλουσιοι καταδυναστευουσιν υμων και αυτοι ελκουσιν υμας εις κριτηρια'),
(7156, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 7, 'NT', 'ουκ αυτοι βλασφημουσιν το καλον ονομα το επικληθεν εφ υμας'),
(7157, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 8, 'NT', 'ει μεντοι νομον τελειτε βασιλικον κατα την γραφην αγαπησεις τον πλησιον σου ως σεαυτον καλως ποιειτε'),
