(7159, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 10, 'NT', 'οστις γαρ ολον τον νομον τηρησει πταισει δε εν ενι γεγονεν παντων ενοχος'),
(7160, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 11, 'NT', 'ο γαρ ειπων μη μοιχευσης ειπεν και μη φονευσης ει δε ου μοιχευσεις φονευσεις δε γεγονας παραβατης νομου'),
(7161, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 12, 'NT', 'ουτως λαλειτε και ουτως ποιειτε ως δια νομου ελευθεριας μελλοντες κρινεσθαι'),
(7162, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 13, 'NT', 'η γαρ κρισις ανιλεως τω μη ποιησαντι ελεος και κατακαυχαται ελεος κρισεως'),
(7163, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 14, 'NT', 'τι το οφελος αδελφοι μου εαν πιστιν λεγη τις εχειν εργα δε μη εχη μη δυναται η πιστις σωσαι αυτον'),
(7164, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 15, 'NT', 'εαν δε αδελφος η αδελφη γυμνοι υπαρχωσιν και λειπομενοι ωσιν της εφημερου τροφης'),
(7165, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 16, 'NT', 'ειπη δε τις αυτοις εξ υμων υπαγετε εν ειρηνη θερμαινεσθε και χορταζεσθε μη δωτε δε αυτοις τα επιτηδεια του σωματος τι το οφελος'),
(7166, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 17, 'NT', 'ουτως και η πιστις εαν μη εργα εχη νεκρα εστιν καθ εαυτην'),
(7167, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 18, 'NT', 'αλλ ερει τις συ πιστιν εχεις καγω εργα εχω δειξον μοι την πιστιν σου εκ των εργων σου καγω δειξω σοι εκ των εργων μου την πιστιν μου'),
(7168, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 19, 'NT', 'συ πιστευεις οτι ο θεος εις εστιν καλως ποιεις και τα δαιμονια πιστευουσιν και φρισσουσιν'),
(7169, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 20, 'NT', 'θελεις δε γνωναι ω ανθρωπε κενε οτι η πιστις χωρις των εργων νεκρα εστιν'),
(7170, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 21, 'NT', 'αβρααμ ο πατηρ ημων ουκ εξ εργων εδικαιωθη ανενεγκας ισαακ τον υιον αυτου επι το θυσιαστηριον'),
(7171, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 22, 'NT', 'βλεπεις οτι η πιστις συνηργει τοις εργοις αυτου και εκ των εργων η πιστις ετελειωθη'),
(7172, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 23, 'NT', 'και επληρωθη η γραφη η λεγουσα επιστευσεν δε αβρααμ τω θεω και ελογισθη αυτω εις δικαιοσυνην και φιλος θεου εκληθη'),
(7173, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 24, 'NT', 'ορατε τοινυν οτι εξ εργων δικαιουται ανθρωπος και ουκ εκ πιστεως μονον'),
(7174, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 25, 'NT', 'ομοιως δε και ρααβ η πορνη ουκ εξ εργων εδικαιωθη υποδεξαμενη τους αγγελους και ετερα οδω εκβαλουσα'),
(7175, 59, 'TR1550', 'TR1550', 'el', 'JAS', 2, 26, 'NT', 'ωσπερ γαρ το σωμα χωρις πνευματος νεκρον εστιν ουτως και η πιστις χωρις των εργων νεκρα εστιν'),
(7176, 59, 'TR1550', 'TR1550', 'el', 'JAS', 3, 1, 'NT', 'μη πολλοι διδασκαλοι γινεσθε αδελφοι μου ειδοτες οτι μειζον κριμα ληψομεθα'),
(7177, 59, 'TR1550', 'TR1550', 'el', 'JAS', 3, 2, 'NT', 'πολλα γαρ πταιομεν απαντες ει τις εν λογω ου πταιει ουτος τελειος ανηρ δυνατος χαλιναγωγησαι και ολον το σωμα'),
(7178, 59, 'TR1550', 'TR1550', 'el', 'JAS', 3, 3, 'NT', 'ιδου των ιππων τους χαλινους εις τα στοματα βαλλομεν προς το πειθεσθαι αυτους ημιν και ολον το σωμα αυτων μεταγομεν'),
(7179, 59, 'TR1550', 'TR1550', 'el', 'JAS', 3, 4, 'NT', 'ιδου και τα πλοια τηλικαυτα οντα και υπο σκληρων ανεμων ελαυνομενα μεταγεται υπο ελαχιστου πηδαλιου οπου αν η ορμη του ευθυνοντος βουληται'),
(7180, 59, 'TR1550', 'TR1550', 'el', 'JAS', 3, 5, 'NT', 'ουτως και η γλωσσα μικρον μελος εστιν και μεγαλαυχει ιδου ολιγον πυρ ηλικην υλην αναπτει'),
(7181, 59, 'TR1550', 'TR1550', 'el', 'JAS', 3, 6, 'NT', 'και η γλωσσα πυρ ο κοσμος της αδικιας ουτως η γλωσσα καθισταται εν τοις μελεσιν ημων η σπιλουσα ολον το σωμα και φλογιζουσα τον τροχον της γενεσεως και φλογιζομενη υπο της γεεννης'),
(7182, 59, 'TR1550', 'TR1550', 'el', 'JAS', 3, 7, 'NT', 'πασα γαρ φυσις θηριων τε και πετεινων ερπετων τε και εναλιων δαμαζεται και δεδαμασται τη φυσει τη ανθρωπινη'),
(7183, 59, 'TR1550', 'TR1550', 'el', 'JAS', 3, 8, 'NT', 'την δε γλωσσαν ουδεις δυναται ανθρωπων δαμασαι ακατασχετον κακον μεστη ιου θανατηφορου'),
