(7185, 59, 'TR1550', 'TR1550', 'el', 'JAS', 3, 10, 'NT', 'εκ του αυτου στοματος εξερχεται ευλογια και καταρα ου χρη αδελφοι μου ταυτα ουτως γινεσθαι'),
(7186, 59, 'TR1550', 'TR1550', 'el', 'JAS', 3, 11, 'NT', 'μητι η πηγη εκ της αυτης οπης βρυει το γλυκυ και το πικρον'),
(7187, 59, 'TR1550', 'TR1550', 'el', 'JAS', 3, 12, 'NT', 'μη δυναται αδελφοι μου συκη ελαιας ποιησαι η αμπελος συκα ουτως ουδεμια πηγη αλυκον και γλυκυ ποιησαι υδωρ'),
(7188, 59, 'TR1550', 'TR1550', 'el', 'JAS', 3, 13, 'NT', 'τις σοφος και επιστημων εν υμιν δειξατω εκ της καλης αναστροφης τα εργα αυτου εν πραυτητι σοφιας'),
(7189, 59, 'TR1550', 'TR1550', 'el', 'JAS', 3, 14, 'NT', 'ει δε ζηλον πικρον εχετε και εριθειαν εν τη καρδια υμων μη κατακαυχασθε και ψευδεσθε κατα της αληθειας'),
(7190, 59, 'TR1550', 'TR1550', 'el', 'JAS', 3, 15, 'NT', 'ουκ εστιν αυτη η σοφια ανωθεν κατερχομενη αλλ επιγειος ψυχικη δαιμονιωδης'),
(7191, 59, 'TR1550', 'TR1550', 'el', 'JAS', 3, 16, 'NT', 'οπου γαρ ζηλος και εριθεια εκει ακαταστασια και παν φαυλον πραγμα'),
(7192, 59, 'TR1550', 'TR1550', 'el', 'JAS', 3, 17, 'NT', 'η δε ανωθεν σοφια πρωτον μεν αγνη εστιν επειτα ειρηνικη επιεικης ευπειθης μεστη ελεους και καρπων αγαθων αδιακριτος και ανυποκριτος'),
(7193, 59, 'TR1550', 'TR1550', 'el', 'JAS', 3, 18, 'NT', 'καρπος δε της δικαιοσυνης εν ειρηνη σπειρεται τοις ποιουσιν ειρηνην'),
(7194, 59, 'TR1550', 'TR1550', 'el', 'JAS', 4, 1, 'NT', 'ποθεν πολεμοι και μαχαι εν υμιν ουκ εντευθεν εκ των ηδονων υμων των στρατευομενων εν τοις μελεσιν υμων'),
(7195, 59, 'TR1550', 'TR1550', 'el', 'JAS', 4, 2, 'NT', 'επιθυμειτε και ουκ εχετε φονευετε και ζηλουτε και ου δυνασθε επιτυχειν μαχεσθε και πολεμειτε ουκ εχετε δε δια το μη αιτεισθαι υμας'),
(7196, 59, 'TR1550', 'TR1550', 'el', 'JAS', 4, 3, 'NT', 'αιτειτε και ου λαμβανετε διοτι κακως αιτεισθε ινα εν ταις ηδοναις υμων δαπανησητε'),
(7197, 59, 'TR1550', 'TR1550', 'el', 'JAS', 4, 4, 'NT', 'μοιχοι και μοιχαλιδες ουκ οιδατε οτι η φιλια του κοσμου εχθρα του θεου εστιν ος αν ουν βουληθη φιλος ειναι του κοσμου εχθρος του θεου καθισταται'),
(7198, 59, 'TR1550', 'TR1550', 'el', 'JAS', 4, 5, 'NT', 'η δοκειτε οτι κενως η γραφη λεγει προς φθονον επιποθει το πνευμα ο κατωκησεν εν ημιν'),
(7199, 59, 'TR1550', 'TR1550', 'el', 'JAS', 4, 6, 'NT', 'μειζονα δε διδωσιν χαριν διο λεγει ο θεος υπερηφανοις αντιτασσεται ταπεινοις δε διδωσιν χαριν'),
(7200, 59, 'TR1550', 'TR1550', 'el', 'JAS', 4, 7, 'NT', 'υποταγητε ουν τω θεω αντιστητε τω διαβολω και φευξεται αφ υμων'),
(7201, 59, 'TR1550', 'TR1550', 'el', 'JAS', 4, 8, 'NT', 'εγγισατε τω θεω και εγγιει υμιν καθαρισατε χειρας αμαρτωλοι και αγνισατε καρδιας διψυχοι'),
(7202, 59, 'TR1550', 'TR1550', 'el', 'JAS', 4, 9, 'NT', 'ταλαιπωρησατε και πενθησατε και κλαυσατε ο γελως υμων εις πενθος μεταστραφητω και η χαρα εις κατηφειαν'),
(7203, 59, 'TR1550', 'TR1550', 'el', 'JAS', 4, 10, 'NT', 'ταπεινωθητε ενωπιον του κυριου και υψωσει υμας'),
(7204, 59, 'TR1550', 'TR1550', 'el', 'JAS', 4, 11, 'NT', 'μη καταλαλειτε αλληλων αδελφοι ο καταλαλων αδελφου και κρινων τον αδελφον αυτου καταλαλει νομου και κρινει νομον ει δε νομον κρινεις ουκ ει ποιητης νομου αλλα κριτης'),
(7205, 59, 'TR1550', 'TR1550', 'el', 'JAS', 4, 12, 'NT', 'εις εστιν ο νομοθετης ο δυναμενος σωσαι και απολεσαι συ τις ει ος κρινεις τον ετερον'),
(7206, 59, 'TR1550', 'TR1550', 'el', 'JAS', 4, 13, 'NT', 'αγε νυν οι λεγοντες σημερον και αυριον πορευσωμεθα εις τηνδε την πολιν και ποιησωμεν εκει ενιαυτον ενα και εμπορευσωμεθα και κερδησωμεν'),
(7207, 59, 'TR1550', 'TR1550', 'el', 'JAS', 4, 14, 'NT', 'οιτινες ουκ επιστασθε το της αυριον ποια γαρ η ζωη υμων ατμις γαρ εστιν η προς ολιγον φαινομενη επειτα δε αφανιζομενη'),
(7208, 59, 'TR1550', 'TR1550', 'el', 'JAS', 4, 15, 'NT', 'αντι του λεγειν υμας εαν ο κυριος θεληση και ζησωμεν και ποιησωμεν τουτο η εκεινο'),
(7209, 59, 'TR1550', 'TR1550', 'el', 'JAS', 4, 16, 'NT', 'νυν δε καυχασθε εν ταις αλαζονειαις υμων πασα καυχησις τοιαυτη πονηρα εστιν'),
(7210, 59, 'TR1550', 'TR1550', 'el', 'JAS', 4, 17, 'NT', 'ειδοτι ουν καλον ποιειν και μη ποιουντι αμαρτια αυτω εστιν'),
(7211, 59, 'TR1550', 'TR1550', 'el', 'JAS', 5, 1, 'NT', 'αγε νυν οι πλουσιοι κλαυσατε ολολυζοντες επι ταις ταλαιπωριαις υμων ταις επερχομεναις'),
(7212, 59, 'TR1550', 'TR1550', 'el', 'JAS', 5, 2, 'NT', 'ο πλουτος υμων σεσηπεν και τα ιματια υμων σητοβρωτα γεγονεν'),
(7213, 59, 'TR1550', 'TR1550', 'el', 'JAS', 5, 3, 'NT', 'ο χρυσος υμων και ο αργυρος κατιωται και ο ιος αυτων εις μαρτυριον υμιν εσται και φαγεται τας σαρκας υμων ως πυρ εθησαυρισατε εν εσχαταις ημεραις'),
(7214, 59, 'TR1550', 'TR1550', 'el', 'JAS', 5, 4, 'NT', 'ιδου ο μισθος των εργατων των αμησαντων τας χωρας υμων ο απεστερημενος αφ υμων κραζει και αι βοαι των θερισαντων εις τα ωτα κυριου σαβαωθ εισεληλυθασιν'),
(7215, 59, 'TR1550', 'TR1550', 'el', 'JAS', 5, 5, 'NT', 'ετρυφησατε επι της γης και εσπαταλησατε εθρεψατε τας καρδιας υμων ως εν ημερα σφαγης'),
(7216, 59, 'TR1550', 'TR1550', 'el', 'JAS', 5, 6, 'NT', 'κατεδικασατε εφονευσατε τον δικαιον ουκ αντιτασσεται υμιν'),
(7217, 59, 'TR1550', 'TR1550', 'el', 'JAS', 5, 7, 'NT', 'μακροθυμησατε ουν αδελφοι εως της παρουσιας του κυριου ιδου ο γεωργος εκδεχεται τον τιμιον καρπον της γης μακροθυμων επ αυτω εως αν λαβη υετον πρωιμον και οψιμον'),
(7218, 59, 'TR1550', 'TR1550', 'el', 'JAS', 5, 8, 'NT', 'μακροθυμησατε και υμεις στηριξατε τας καρδιας υμων οτι η παρουσια του κυριου ηγγικεν'),
(7219, 59, 'TR1550', 'TR1550', 'el', 'JAS', 5, 9, 'NT', 'μη στεναζετε κατ αλληλων αδελφοι ινα μη κατακριθητε ιδου κριτης προ των θυρων εστηκεν'),
(7220, 59, 'TR1550', 'TR1550', 'el', 'JAS', 5, 10, 'NT', 'υποδειγμα λαβετε της κακοπαθειας αδελφοι μου και της μακροθυμιας τους προφητας οι ελαλησαν τω ονοματι κυριου'),
(7221, 59, 'TR1550', 'TR1550', 'el', 'JAS', 5, 11, 'NT', 'ιδου μακαριζομεν τους υπομενοντας την υπομονην ιωβ ηκουσατε και το τελος κυριου ειδετε οτι πολυσπλαγχνος εστιν ο κυριος και οικτιρμων'),
(7222, 59, 'TR1550', 'TR1550', 'el', 'JAS', 5, 12, 'NT', 'προ παντων δε αδελφοι μου μη ομνυετε μητε τον ουρανον μητε την γην μητε αλλον τινα ορκον ητω δε υμων το ναι ναι και το ου ου ινα μη εις υποκρισιν πεσητε'),
(7223, 59, 'TR1550', 'TR1550', 'el', 'JAS', 5, 13, 'NT', 'κακοπαθει τις εν υμιν προσευχεσθω ευθυμει τις ψαλλετω'),
(7224, 59, 'TR1550', 'TR1550', 'el', 'JAS', 5, 14, 'NT', 'ασθενει τις εν υμιν προσκαλεσασθω τους πρεσβυτερους της εκκλησιας και προσευξασθωσαν επ αυτον αλειψαντες αυτον ελαιω εν τω ονοματι του κυριου'),
