(7381, 61, 'TR1550', 'TR1550', 'el', '2PE', 3, 3, 'NT', 'τουτο πρωτον γινωσκοντες οτι ελευσονται επ εσχατου των ημερων εμπαικται κατα τας ιδιας αυτων επιθυμιας πορευομενοι'),
(7382, 61, 'TR1550', 'TR1550', 'el', '2PE', 3, 4, 'NT', 'και λεγοντες που εστιν η επαγγελια της παρουσιας αυτου αφ ης γαρ οι πατερες εκοιμηθησαν παντα ουτως διαμενει απ αρχης κτισεως'),
(7383, 61, 'TR1550', 'TR1550', 'el', '2PE', 3, 5, 'NT', 'λανθανει γαρ αυτους τουτο θελοντας οτι ουρανοι ησαν εκπαλαι και γη εξ υδατος και δι υδατος συνεστωσα τω του θεου λογω'),
(7384, 61, 'TR1550', 'TR1550', 'el', '2PE', 3, 6, 'NT', 'δι ων ο τοτε κοσμος υδατι κατακλυσθεις απωλετο'),
(7385, 61, 'TR1550', 'TR1550', 'el', '2PE', 3, 7, 'NT', 'οι δε νυν ουρανοι και η γη αυτου λογω τεθησαυρισμενοι εισιν πυρι τηρουμενοι εις ημεραν κρισεως και απωλειας των ασεβων ανθρωπων'),
(7386, 61, 'TR1550', 'TR1550', 'el', '2PE', 3, 8, 'NT', 'εν δε τουτο μη λανθανετω υμας αγαπητοι οτι μια ημερα παρα κυριω ως χιλια ετη και χιλια ετη ως ημερα μια'),
(7387, 61, 'TR1550', 'TR1550', 'el', '2PE', 3, 9, 'NT', 'ου βραδυνει ο κυριος της επαγγελιας ως τινες βραδυτητα ηγουνται αλλα μακροθυμει εις ημας μη βουλομενος τινας απολεσθαι αλλα παντας εις μετανοιαν χωρησαι'),
(7388, 61, 'TR1550', 'TR1550', 'el', '2PE', 3, 10, 'NT', 'ηξει δε η ημερα κυριου ως κλεπτης εν νυκτι εν η οι ουρανοι ροιζηδον παρελευσονται στοιχεια δε καυσουμενα λυθησονται και γη και τα εν αυτη εργα κατακαησεται'),
(7389, 61, 'TR1550', 'TR1550', 'el', '2PE', 3, 11, 'NT', 'τουτων ουν παντων λυομενων ποταπους δει υπαρχειν υμας εν αγιαις αναστροφαις και ευσεβειαις'),
(7390, 61, 'TR1550', 'TR1550', 'el', '2PE', 3, 12, 'NT', 'προσδοκωντας και σπευδοντας την παρουσιαν της του θεου ημερας δι ην ουρανοι πυρουμενοι λυθησονται και στοιχεια καυσουμενα τηκεται'),
(7391, 61, 'TR1550', 'TR1550', 'el', '2PE', 3, 13, 'NT', 'καινους δε ουρανους και γην καινην κατα το επαγγελμα αυτου προσδοκωμεν εν οις δικαιοσυνη κατοικει'),
(7392, 61, 'TR1550', 'TR1550', 'el', '2PE', 3, 14, 'NT', 'διο αγαπητοι ταυτα προσδοκωντες σπουδασατε ασπιλοι και αμωμητοι αυτω ευρεθηναι εν ειρηνη'),
(7393, 61, 'TR1550', 'TR1550', 'el', '2PE', 3, 15, 'NT', 'και την του κυριου ημων μακροθυμιαν σωτηριαν ηγεισθε καθως και ο αγαπητος ημων αδελφος παυλος κατα την αυτω δοθεισαν σοφιαν εγραψεν υμιν'),
(7394, 61, 'TR1550', 'TR1550', 'el', '2PE', 3, 16, 'NT', 'ως και εν πασαις ταις επιστολαις λαλων εν αυταις περι τουτων εν οις εστιν δυσνοητα τινα α οι αμαθεις και αστηρικτοι στρεβλουσιν ως και τας λοιπας γραφας προς την ιδιαν αυτων απωλειαν'),
(7395, 61, 'TR1550', 'TR1550', 'el', '2PE', 3, 17, 'NT', 'υμεις ουν αγαπητοι προγινωσκοντες φυλασσεσθε ινα μη τη των αθεσμων πλανη συναπαχθεντες εκπεσητε του ιδιου στηριγμου'),
(7396, 61, 'TR1550', 'TR1550', 'el', '2PE', 3, 18, 'NT', 'αυξανετε δε εν χαριτι και γνωσει του κυριου ημων και σωτηρος ιησου χριστου αυτω η δοξα και νυν και εις ημεραν αιωνος αμην'),
(7397, 62, 'TR1550', 'TR1550', 'el', '1JN', 1, 1, 'NT', 'ο ην απ αρχης ο ακηκοαμεν ο εωρακαμεν τοις οφθαλμοις ημων ο εθεασαμεθα και αι χειρες ημων εψηλαφησαν περι του λογου της ζωης'),
(7398, 62, 'TR1550', 'TR1550', 'el', '1JN', 1, 2, 'NT', 'και η ζωη εφανερωθη και εωρακαμεν και μαρτυρουμεν και απαγγελλομεν υμιν την ζωην την αιωνιον ητις ην προς τον πατερα και εφανερωθη ημιν'),
(7399, 62, 'TR1550', 'TR1550', 'el', '1JN', 1, 3, 'NT', 'ο εωρακαμεν και ακηκοαμεν απαγγελλομεν υμιν ινα και υμεις κοινωνιαν εχητε μεθ ημων και η κοινωνια δε η ημετερα μετα του πατρος και μετα του υιου αυτου ιησου χριστου'),
(7400, 62, 'TR1550', 'TR1550', 'el', '1JN', 1, 4, 'NT', 'και ταυτα γραφομεν υμιν ινα η χαρα ημων η πεπληρωμενη'),
(7401, 62, 'TR1550', 'TR1550', 'el', '1JN', 1, 5, 'NT', 'και αυτη εστιν η επαγγελια ην ακηκοαμεν απ αυτου και αναγγελλομεν υμιν οτι ο θεος φως εστιν και σκοτια εν αυτω ουκ εστιν ουδεμια'),
(7402, 62, 'TR1550', 'TR1550', 'el', '1JN', 1, 6, 'NT', 'εαν ειπωμεν οτι κοινωνιαν εχομεν μετ αυτου και εν τω σκοτει περιπατωμεν ψευδομεθα και ου ποιουμεν την αληθειαν'),
(7403, 62, 'TR1550', 'TR1550', 'el', '1JN', 1, 7, 'NT', 'εαν δε εν τω φωτι περιπατωμεν ως αυτος εστιν εν τω φωτι κοινωνιαν εχομεν μετ αλληλων και το αιμα ιησου χριστου του υιου αυτου καθαριζει ημας απο πασης αμαρτιας'),
(7404, 62, 'TR1550', 'TR1550', 'el', '1JN', 1, 8, 'NT', 'εαν ειπωμεν οτι αμαρτιαν ουκ εχομεν εαυτους πλανωμεν και η αληθεια ουκ εστιν εν ημιν'),
(7405, 62, 'TR1550', 'TR1550', 'el', '1JN', 1, 9, 'NT', 'εαν ομολογωμεν τας αμαρτιας ημων πιστος εστιν και δικαιος ινα αφη ημιν τας αμαρτιας και καθαριση ημας απο πασης αδικιας'),
(7406, 62, 'TR1550', 'TR1550', 'el', '1JN', 1, 10, 'NT', 'εαν ειπωμεν οτι ουχ ημαρτηκαμεν ψευστην ποιουμεν αυτον και ο λογος αυτου ουκ εστιν εν ημιν'),
(7407, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 1, 'NT', 'τεκνια μου ταυτα γραφω υμιν ινα μη αμαρτητε και εαν τις αμαρτη παρακλητον εχομεν προς τον πατερα ιησουν χριστον δικαιον'),
(7408, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 2, 'NT', 'και αυτος ιλασμος εστιν περι των αμαρτιων ημων ου περι των ημετερων δε μονον αλλα και περι ολου του κοσμου'),
(7409, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 3, 'NT', 'και εν τουτω γινωσκομεν οτι εγνωκαμεν αυτον εαν τας εντολας αυτου τηρωμεν'),
(7410, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 4, 'NT', 'ο λεγων εγνωκα αυτον και τας εντολας αυτου μη τηρων ψευστης εστιν και εν τουτω η αληθεια ουκ εστιν'),
(7411, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 5, 'NT', 'ος δ αν τηρη αυτου τον λογον αληθως εν τουτω η αγαπη του θεου τετελειωται εν τουτω γινωσκομεν οτι εν αυτω εσμεν'),
(7412, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 6, 'NT', 'ο λεγων εν αυτω μενειν οφειλει καθως εκεινος περιεπατησεν και αυτος ουτως περιπατειν'),
(7413, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 7, 'NT', 'αδελφοι ουκ εντολην καινην γραφω υμιν αλλ εντολην παλαιαν ην ειχετε απ αρχης η εντολη η παλαια εστιν ο λογος ον ηκουσατε απ αρχης'),
(7414, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 8, 'NT', 'παλιν εντολην καινην γραφω υμιν ο εστιν αληθες εν αυτω και εν υμιν οτι η σκοτια παραγεται και το φως το αληθινον ηδη φαινει'),
(7415, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 9, 'NT', 'ο λεγων εν τω φωτι ειναι και τον αδελφον αυτου μισων εν τη σκοτια εστιν εως αρτι'),
(7416, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 10, 'NT', 'ο αγαπων τον αδελφον αυτου εν τω φωτι μενει και σκανδαλον εν αυτω ουκ εστιν'),
(7417, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 11, 'NT', 'ο δε μισων τον αδελφον αυτου εν τη σκοτια εστιν και εν τη σκοτια περιπατει και ουκ οιδεν που υπαγει οτι η σκοτια ετυφλωσεν τους οφθαλμους αυτου'),
(7418, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 12, 'NT', 'γραφω υμιν τεκνια οτι αφεωνται υμιν αι αμαρτιαι δια το ονομα αυτου'),
(7419, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 13, 'NT', 'γραφω υμιν πατερες οτι εγνωκατε τον απ αρχης γραφω υμιν νεανισκοι οτι νενικηκατε τον πονηρον γραφω υμιν παιδια οτι εγνωκατε τον πατερα'),
(7420, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 14, 'NT', 'εγραψα υμιν πατερες οτι εγνωκατε τον απ αρχης εγραψα υμιν νεανισκοι οτι ισχυροι εστε και ο λογος του θεου εν υμιν μενει και νενικηκατε τον πονηρον'),
(7421, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 15, 'NT', 'μη αγαπατε τον κοσμον μηδε τα εν τω κοσμω εαν τις αγαπα τον κοσμον ουκ εστιν η αγαπη του πατρος εν αυτω'),
(7422, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 16, 'NT', 'οτι παν το εν τω κοσμω η επιθυμια της σαρκος και η επιθυμια των οφθαλμων και η αλαζονεια του βιου ουκ εστιν εκ του πατρος αλλ εκ του κοσμου εστιν'),
(7423, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 17, 'NT', 'και ο κοσμος παραγεται και η επιθυμια αυτου ο δε ποιων το θελημα του θεου μενει εις τον αιωνα'),
(7424, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 18, 'NT', 'παιδια εσχατη ωρα εστιν και καθως ηκουσατε οτι ο αντιχριστος ερχεται και νυν αντιχριστοι πολλοι γεγονασιν οθεν γινωσκομεν οτι εσχατη ωρα εστιν'),
(7425, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 19, 'NT', 'εξ ημων εξηλθον αλλ ουκ ησαν εξ ημων ει γαρ ησαν εξ ημων μεμενηκεισαν αν μεθ ημων αλλ ινα φανερωθωσιν οτι ουκ εισιν παντες εξ ημων'),
(7426, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 20, 'NT', 'και υμεις χρισμα εχετε απο του αγιου και οιδατε παντα'),
(7427, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 21, 'NT', 'ουκ εγραψα υμιν οτι ουκ οιδατε την αληθειαν αλλ οτι οιδατε αυτην και οτι παν ψευδος εκ της αληθειας ουκ εστιν'),
(7428, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 22, 'NT', 'τις εστιν ο ψευστης ει μη ο αρνουμενος οτι ιησους ουκ εστιν ο χριστος ουτος εστιν ο αντιχριστος ο αρνουμενος τον πατερα και τον υιον'),
(7429, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 23, 'NT', 'πας ο αρνουμενος τον υιον ουδε τον πατερα εχει'),
(7430, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 24, 'NT', 'υμεις ουν ο ηκουσατε απ αρχης εν υμιν μενετω εαν εν υμιν μεινη ο απ αρχης ηκουσατε και υμεις εν τω υιω και εν τω πατρι μενειτε'),
(7431, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 25, 'NT', 'και αυτη εστιν η επαγγελια ην αυτος επηγγειλατο ημιν την ζωην την αιωνιον'),
(7432, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 26, 'NT', 'ταυτα εγραψα υμιν περι των πλανωντων υμας'),
(7433, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 27, 'NT', 'και υμεις το χρισμα ο ελαβετε απ αυτου εν υμιν μενει και ου χρειαν εχετε ινα τις διδασκη υμας αλλ ως το αυτο χρισμα διδασκει υμας περι παντων και αληθες εστιν και ουκ εστιν ψευδος και καθως εδιδαξεν υμας μενειτε εν αυτω'),
(7434, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 28, 'NT', 'και νυν τεκνια μενετε εν αυτω ινα οταν φανερωθη εχωμεν παρρησιαν και μη αισχυνθωμεν απ αυτου εν τη παρουσια αυτου'),
(7435, 62, 'TR1550', 'TR1550', 'el', '1JN', 2, 29, 'NT', 'εαν ειδητε οτι δικαιος εστιν γινωσκετε οτι πας ο ποιων την δικαιοσυνην εξ αυτου γεγεννηται'),
(7436, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 1, 'NT', 'ιδετε ποταπην αγαπην δεδωκεν ημιν ο πατηρ ινα τεκνα θεου κληθωμεν δια τουτο ο κοσμος ου γινωσκει ημας οτι ουκ εγνω αυτον'),
(7437, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 2, 'NT', 'αγαπητοι νυν τεκνα θεου εσμεν και ουπω εφανερωθη τι εσομεθα οιδαμεν δε οτι εαν φανερωθη ομοιοι αυτω εσομεθα οτι οψομεθα αυτον καθως εστιν'),
(7438, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 3, 'NT', 'και πας ο εχων την ελπιδα ταυτην επ αυτω αγνιζει εαυτον καθως εκεινος αγνος εστιν'),
(7439, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 4, 'NT', 'πας ο ποιων την αμαρτιαν και την ανομιαν ποιει και η αμαρτια εστιν η ανομια'),
(7440, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 5, 'NT', 'και οιδατε οτι εκεινος εφανερωθη ινα τας αμαρτιας ημων αρη και αμαρτια εν αυτω ουκ εστιν'),
(7441, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 6, 'NT', 'πας ο εν αυτω μενων ουχ αμαρτανει πας ο αμαρτανων ουχ εωρακεν αυτον ουδε εγνωκεν αυτον'),
(7442, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 7, 'NT', 'τεκνια μηδεις πλανατω υμας ο ποιων την δικαιοσυνην δικαιος εστιν καθως εκεινος δικαιος εστιν'),
(7443, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 8, 'NT', 'ο ποιων την αμαρτιαν εκ του διαβολου εστιν οτι απ αρχης ο διαβολος αμαρτανει εις τουτο εφανερωθη ο υιος του θεου ινα λυση τα εργα του διαβολου'),
(7444, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 9, 'NT', 'πας ο γεγεννημενος εκ του θεου αμαρτιαν ου ποιει οτι σπερμα αυτου εν αυτω μενει και ου δυναται αμαρτανειν οτι εκ του θεου γεγεννηται'),
(7445, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 10, 'NT', 'εν τουτω φανερα εστιν τα τεκνα του θεου και τα τεκνα του διαβολου πας ο μη ποιων δικαιοσυνην ουκ εστιν εκ του θεου και ο μη αγαπων τον αδελφον αυτου'),
(7446, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 11, 'NT', 'οτι αυτη εστιν η αγγελια ην ηκουσατε απ αρχης ινα αγαπωμεν αλληλους'),
(7447, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 12, 'NT', 'ου καθως καιν εκ του πονηρου ην και εσφαξεν τον αδελφον αυτου και χαριν τινος εσφαξεν αυτον οτι τα εργα αυτου πονηρα ην τα δε του αδελφου αυτου δικαια'),
(7448, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 13, 'NT', 'μη θαυμαζετε αδελφοι μου ει μισει υμας ο κοσμος'),
(7449, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 14, 'NT', 'ημεις οιδαμεν οτι μεταβεβηκαμεν εκ του θανατου εις την ζωην οτι αγαπωμεν τους αδελφους ο μη αγαπων τον αδελφον μενει εν τω θανατω'),
(7450, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 15, 'NT', 'πας ο μισων τον αδελφον αυτου ανθρωποκτονος εστιν και οιδατε οτι πας ανθρωποκτονος ουκ εχει ζωην αιωνιον εν αυτω μενουσαν'),
(7451, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 16, 'NT', 'εν τουτω εγνωκαμεν την αγαπην οτι εκεινος υπερ ημων την ψυχην αυτου εθηκεν και ημεις οφειλομεν υπερ των αδελφων τας ψυχας τιθεναι'),
(7452, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 17, 'NT', 'ος δ αν εχη τον βιον του κοσμου και θεωρη τον αδελφον αυτου χρειαν εχοντα και κλειση τα σπλαγχνα αυτου απ αυτου πως η αγαπη του θεου μενει εν αυτω'),
(7453, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 18, 'NT', 'τεκνια μου μη αγαπωμεν λογω μηδε γλωσση αλλ εργω και αληθεια'),
(7454, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 19, 'NT', 'και εν τουτω γινωσκομεν οτι εκ της αληθειας εσμεν και εμπροσθεν αυτου πεισομεν τας καρδιας ημων'),
(7455, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 20, 'NT', 'οτι εαν καταγινωσκη ημων η καρδια οτι μειζων εστιν ο θεος της καρδιας ημων και γινωσκει παντα'),
(7456, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 21, 'NT', 'αγαπητοι εαν η καρδια ημων μη καταγινωσκη ημων παρρησιαν εχομεν προς τον θεον'),
(7457, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 22, 'NT', 'και ο εαν αιτωμεν λαμβανομεν παρ αυτου οτι τας εντολας αυτου τηρουμεν και τα αρεστα ενωπιον αυτου ποιουμεν'),
(7458, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 23, 'NT', 'και αυτη εστιν η εντολη αυτου ινα πιστευσωμεν τω ονοματι του υιου αυτου ιησου χριστου και αγαπωμεν αλληλους καθως εδωκεν εντολην ημιν'),
(7459, 62, 'TR1550', 'TR1550', 'el', '1JN', 3, 24, 'NT', 'και ο τηρων τας εντολας αυτου εν αυτω μενει και αυτος εν αυτω και εν τουτω γινωσκομεν οτι μενει εν ημιν εκ του πνευματος ου ημιν εδωκεν'),
(7460, 62, 'TR1550', 'TR1550', 'el', '1JN', 4, 1, 'NT', 'αγαπητοι μη παντι πνευματι πιστευετε αλλα δοκιμαζετε τα πνευματα ει εκ του θεου εστιν οτι πολλοι ψευδοπροφηται εξεληλυθασιν εις τον κοσμον'),
(7461, 62, 'TR1550', 'TR1550', 'el', '1JN', 4, 2, 'NT', 'εν τουτω γινωσκετε το πνευμα του θεου παν πνευμα ο ομολογει ιησουν χριστον εν σαρκι εληλυθοτα εκ του θεου εστιν'),
